const LEXICON = {"G1": {"greek": "Α", "translit": "A", "pronunciation": "al'-fah", "derivation": "of Hebrew origin;", "definition": "the first letter of the alphabet; figuratively, only (from its use as a numeral) the first:", "kjv": "--Alpha."}, "G2": {"greek": "Ἀαρών", "translit": "Aarṓn", "pronunciation": "ah-ar-ohn'", "derivation": "of Hebrew origin ((G175));", "definition": "Aaron, the brother of Moses", "kjv": "Aaron."}, "G3": {"greek": "Ἀβαδδών", "translit": "Abaddṓn", "pronunciation": "ab-ad-dohn'", "derivation": "of Hebrew origin ((G11));", "definition": "a destroying angel", "kjv": "Abaddon."}, "G4": {"greek": "ἀβαρής", "translit": "abarḗs", "pronunciation": "ab-ar-ace'", "derivation": "from (G1) (as a negative particle) and (G922);", "definition": "weightless, i.e. (figuratively) not burdensome", "kjv": "from being burdensome."}, "G5": {"greek": "Ἀββᾶ", "translit": "Abbâ", "pronunciation": "ab-bah'", "derivation": "of Chaldee origin ((G2));", "definition": "father as a vocative", "kjv": "Abba."}, "G6": {"greek": "Ἄβελ", "translit": "Ábel", "pronunciation": "ab'-el", "derivation": "of Hebrew origin ((G1893));", "definition": "Abel, the son of Adam", "kjv": "Abel."}, "G7": {"greek": "Ἀβιά", "translit": "Abiá", "pronunciation": "ab-ee-ah'", "derivation": "of Hebrew origin ((G29));", "definition": "Abijah, the name of two Israelites", "kjv": "Abia."}, "G8": {"greek": "Ἀβιαθάρ", "translit": "Abiathár", "pronunciation": "ab-ee-ath'-ar", "derivation": "of Hebrew origin ((G54));", "definition": "Abiathar, an Israelite", "kjv": "Abiathar."}, "G9": {"greek": "Ἀβιληνή", "translit": "Abilēnḗ", "pronunciation": "ab-ee-lay-nay'", "derivation": "of foreign origin (compare (G58));", "definition": "Abilene, a region of Syria", "kjv": "Abilene."}, "G10": {"greek": "Ἀβιούδ", "translit": "Abioúd", "pronunciation": "ab-ee-ood'", "derivation": "of Hebrew origin ((G31));", "definition": "Abihud, an Israelite", "kjv": "Abiud."}, "G11": {"greek": "Ἀβραάμ", "translit": "Abraám", "pronunciation": "ab-rah-am'", "derivation": "of Hebrew origin ((G85));", "definition": "Abraham, the Hebrew patriarch", "kjv": "Abraham."}, "G12": {"greek": "ἄβυσσος", "translit": "ábyssos", "pronunciation": "ab'-us-sos", "derivation": "from (G1) (as a negative particle) and a variation of (G1037);", "definition": "depthless, i.e. (specially) (infernal) \"abyss\"", "kjv": "deep, (bottomless) pit."}, "G13": {"greek": "Ἄγαβος", "translit": "Ágabos", "pronunciation": "ag'-ab-os", "derivation": "of Hebrew origin (compare (G2285));", "definition": "Agabus, an Israelite", "kjv": "Agabus."}, "G14": {"greek": "ἀγαθοεργέω", "translit": "agathoergéō", "pronunciation": "ag-ath-er-gheh'-o", "derivation": "from (G18) and (G2041);", "definition": "to work good", "kjv": "do good."}, "G15": {"greek": "ἀγαθοποιέω", "translit": "agathopoiéō", "pronunciation": "ag-ath-op-oy-eh'-o", "derivation": "from (G17);", "definition": "to be a well-doer (as a favor or a duty)", "kjv": "(when) do good (well)."}, "G16": {"greek": "ἀγαθοποιΐα", "translit": "agathopoiḯa", "pronunciation": "ag-ath-op-oy-ee'-ah", "derivation": "from (G17);", "definition": "well-doing, i.e. virtue", "kjv": "well-doing."}, "G17": {"greek": "ἀγαθοποιός", "translit": "agathopoiós", "pronunciation": "ag-ath-op-oy-os'", "derivation": "from (G18) and (G4160);", "definition": "a well-doer, i.e. virtuous", "kjv": "them that do well."}, "G18": {"greek": "ἀγαθός", "translit": "agathós", "pronunciation": "ag-ath-os'", "derivation": "a primary word;", "definition": "\"good\" (in any sense, often as noun)", "kjv": "benefit, good(-s, things), well."}, "G19": {"greek": "ἀγαθωσύνη", "translit": "agathōsýnē", "pronunciation": "ag-ath-o-soo'-nay", "derivation": "from (G18);", "definition": "goodness, i.e. virtue or beneficence", "kjv": "goodness."}, "G20": {"greek": "ἀγαλλίασις", "translit": "agallíasis", "pronunciation": "ag-al-lee'-as-is", "derivation": "from (G21);", "definition": "exultation; specially, welcome", "kjv": "gladness, (exceeding) joy."}, "G21": {"greek": "ἀγαλλιάω", "translit": "agalliáō", "pronunciation": "ag-al-lee-ah'-o", "derivation": "from (much) and (G242);", "definition": "properly, to jump for joy, i.e. exult", "kjv": "be (exceeding) glad, with exceeding joy, rejoice (greatly)."}, "G22": {"greek": "ἄγαμος", "translit": "ágamos", "pronunciation": "ag'-am-os", "derivation": "from (G1) (as a negative particle) and (G1062);", "definition": "unmarried", "kjv": "unmarried."}, "G23": {"greek": "ἀγανακτέω", "translit": "aganaktéō", "pronunciation": "ag-an-ak-teh'-o", "derivation": "from (much) and (grief; akin to the base of (G43));", "definition": "to be greatly afflicted, i.e. (figuratively) indignant", "kjv": "be much (sore) displeased, have (be moved with, with) indignation."}, "G24": {"greek": "ἀγανάκτησις", "translit": "aganáktēsis", "pronunciation": "ag-an-ak'-tay-sis", "derivation": "from (G23);", "definition": "indignation", "kjv": "indignation."}, "G25": {"greek": "ἀγαπάω", "translit": "agapáō", "pronunciation": "ag-ap-ah'-o", "derivation": "perhaps from (much) [or compare (G5689)];", "definition": "to love (in a social or moral sense)", "kjv": "(be-)love(-ed)."}, "G26": {"greek": "ἀγάπη", "translit": "agápē", "pronunciation": "ag-ah'-pay", "derivation": "from (G25);", "definition": "love, i.e. affection or benevolence; specially (plural) a love-feast", "kjv": "(feast of) charity(-ably), dear, love."}, "G27": {"greek": "ἀγαπητός", "translit": "agapētós", "pronunciation": "ag-ap-ay-tos'", "derivation": "from (G25);", "definition": "beloved", "kjv": "(dearly, well) beloved, dear."}, "G28": {"greek": "Ἄγαρ", "translit": "Ágar", "pronunciation": "ag'-ar", "derivation": "of Hebrew origin ((G1904));", "definition": "Hagar, the concubine of Abraham", "kjv": "Hagar."}, "G29": {"greek": "ἀγγαρεύω", "translit": "angareúō", "pronunciation": "ang-ar-yew'-o", "derivation": "of foreign origin (compare (G104));", "definition": "properly, to be a courier, i.e. (by implication) to press into public service", "kjv": "compel (to go)."}, "G30": {"greek": "ἀγγεῖον", "translit": "angeîon", "pronunciation": "ang-eye'-on", "derivation": "from (a pail, perhaps as bent; compare the base of (G43));", "definition": "a receptacle", "kjv": "vessel."}, "G31": {"greek": "ἀγγελία", "translit": "angelía", "pronunciation": "ang-el-ee'-ah", "derivation": "from (G32);", "definition": "an announcement, i.e. (by implication) precept", "kjv": "message."}, "G32": {"greek": "ἄγγελος", "translit": "ángelos", "pronunciation": "ang'-el-os", "derivation": "from (probably derived from (G71);", "definition": "compare (G34)) (to bring tidings); a messenger; especially an \"angel\"; by implication, a pastor", "kjv": "angel, messenger."}, "G34": {"greek": "ἀγέλη", "translit": "agélē", "pronunciation": "ag-el'-ay", "derivation": "from (G71) (compare (G32));", "definition": "a drove", "kjv": "herd."}, "G35": {"greek": "ἀγενεαλόγητος", "translit": "agenealógētos", "pronunciation": "ag-en-eh-al-og'-ay-tos", "derivation": "from (G1) (as negative particle) and (G1075);", "definition": "unregistered as to birth", "kjv": "without descent."}, "G36": {"greek": "ἀγενής", "translit": "agenḗs", "pronunciation": "ag-en-ace'", "derivation": "from (G1) (as negative particle) and (G1085);", "definition": "properly, without kin, i.e. (of unknown descent, and by implication) ignoble", "kjv": "base things."}, "G37": {"greek": "ἁγιάζω", "translit": "hagiázō", "pronunciation": "hag-ee-ad'-zo", "derivation": "from (G40);", "definition": "to make holy, i.e. (ceremonially) purify or consecrate; (mentally) to venerate", "kjv": "hallow, be holy, sanctify."}, "G38": {"greek": "ἁγιασμός", "translit": "hagiasmós", "pronunciation": "hag-ee-as-mos'", "derivation": "from (G37);", "definition": "properly, purification, i.e. (the state) purity; concretely (by Hebraism) a purifier", "kjv": "holiness, sanctification."}, "G40": {"greek": "ἅγιος", "translit": "hágios", "pronunciation": "hag'-ee-os", "derivation": "from (an awful thing) (compare (G53), (G2282));", "definition": "sacred (physically, pure, morally blameless or religious, ceremonially, consecrated)", "kjv": "(most) holy (one, thing), saint."}, "G41": {"greek": "ἁγιότης", "translit": "hagiótēs", "pronunciation": "hag-ee-ot'-ace", "derivation": "from (G40);", "definition": "sanctity (i.e. properly, the state)", "kjv": "holiness."}, "G42": {"greek": "ἁγιωσύνη", "translit": "hagiōsýnē", "pronunciation": "hag-ee-o-soo'-nay", "derivation": "from (G40);", "definition": "sacredness (i.e. properly, the quality)", "kjv": "holiness."}, "G43": {"greek": "ἀγκάλη", "translit": "ankálē", "pronunciation": "ang-kal'-ay", "derivation": "from (a bend, \"ache\");", "definition": "an arm (as curved)", "kjv": "arm."}, "G44": {"greek": "ἄγκιστρον", "translit": "ánkistron", "pronunciation": "ang'-kis-tron", "derivation": "from the same as (G43);", "definition": "a hook (as bent)", "kjv": "hook."}, "G45": {"greek": "ἄγκυρα", "translit": "ánkyra", "pronunciation": "ang'-koo-rah", "derivation": "from the same as (G43);", "definition": "an \"anchor\" (as crooked)", "kjv": "anchor."}, "G46": {"greek": "ἄγναφος", "translit": "ágnaphos", "pronunciation": "ag'-naf-os", "derivation": "from (G1) (as a negative particle) and the same as (G1102);", "definition": "properly, unfulled, i.e. (by implication) new (cloth)", "kjv": "new."}, "G47": {"greek": "ἁγνεία", "translit": "hagneía", "pronunciation": "hag-ni'-ah", "derivation": "from (G53);", "definition": "cleanliness (the quality), i.e. (specially) chastity", "kjv": "purity."}, "G48": {"greek": "ἁγνίζω", "translit": "hagnízō", "pronunciation": "hag-nid'-zo", "derivation": "from (G53);", "definition": "to make clean, i.e. (figuratively) sanctify (ceremonially or morally)", "kjv": "purify (self)."}, "G49": {"greek": "ἁγνισμός", "translit": "hagnismós", "pronunciation": "hag-nis-mos'", "derivation": "from (G48);", "definition": "a cleansing (the act), i.e. (ceremonially) lustration", "kjv": "purification."}, "G50": {"greek": "ἀγνοέω", "translit": "agnoéō", "pronunciation": "ag-no-eh'-o", "derivation": "from (G1) (as a negative particle) and (G3539);", "definition": "not to know (through lack of information or intelligence); by implication, to ignore (through disinclination)", "kjv": "(be) ignorant(-ly), not know, not understand, unknown."}, "G51": {"greek": "ἀγνόημα", "translit": "agnóēma", "pronunciation": "ag-no'-ay-mah", "derivation": "from (G50);", "definition": "a thing ignored, i.e. shortcoming", "kjv": "error."}, "G52": {"greek": "ἄγνοια", "translit": "ágnoia", "pronunciation": "ag'-noy-ah", "derivation": "from (G50);", "definition": "ignorance (properly, the quality)", "kjv": "ignorance."}, "G53": {"greek": "ἁγνός", "translit": "hagnós", "pronunciation": "hag-nos'", "derivation": "from the same as (G40);", "definition": "properly, clean, i.e. (figuratively) innocent, modest, perfect", "kjv": "chaste, clean, pure."}, "G54": {"greek": "ἁγνότης", "translit": "hagnótēs", "pronunciation": "hag-not'-ace", "derivation": "from (G53);", "definition": "cleanness (the state), i.e. (figuratively) blamelessness", "kjv": "pureness."}, "G55": {"greek": "ἁγνῶς", "translit": "hagnōs", "pronunciation": "hag-noce'", "derivation": "adverb from (G53);", "definition": "purely, i.e. honestly", "kjv": "sincerely."}, "G56": {"greek": "ἀγνωσία", "translit": "agnōsía", "pronunciation": "ag-no-see'-ah", "derivation": "from (G1) (as negative particle) and (G1108);", "definition": "ignorance (properly, the state)", "kjv": "ignorance, not the knowledge."}, "G57": {"greek": "ἄγνωστος", "translit": "ágnōstos", "pronunciation": "ag'-noce-tos'", "derivation": "from (G1) (as negative particle) and (G1110);", "definition": "unknown", "kjv": "unknown."}, "G58": {"greek": "ἀγορά", "translit": "agorá", "pronunciation": "ag-or-ah'", "derivation": "from (to gather; probably akin to (G1453));", "definition": "properly, the town-square (as a place of public resort); by implication, a market or thoroughfare", "kjv": "market(-place), street."}, "G59": {"greek": "ἀγοράζω", "translit": "agorázō", "pronunciation": "ag-or-ad'-zo", "derivation": "from (G58);", "definition": "properly, to go to market, i.e. (by implication) to purchase; specially, to redeem", "kjv": "buy, redeem."}, "G60": {"greek": "ἀγοραῖος", "translit": "agoraîos", "pronunciation": "ag-or-ah'-yos", "derivation": "from (G58);", "definition": "relating to the market-place, i.e. forensic (times); by implication, vulgar", "kjv": "baser sort, low."}, "G61": {"greek": "ἄγρα", "translit": "ágra", "pronunciation": "ag'-rah", "derivation": "from (G71);", "definition": "(abstractly) a catching (of fish); also (concretely) a haul (of fish)", "kjv": "draught."}, "G62": {"greek": "ἀγράμματος", "translit": "agrámmatos", "pronunciation": "ag-ram-mat-os", "derivation": "from (G1) (as negative particle) and (G1121);", "definition": "unlettered, i.e. illiterate", "kjv": "unlearned."}, "G63": {"greek": "ἀγραυλέω", "translit": "agrauléō", "pronunciation": "ag-row-leh'-o", "derivation": "from (G68) and (G832) (in the sense of (G833));", "definition": "to camp out", "kjv": "abide in the field."}, "G64": {"greek": "ἀγρεύω", "translit": "agreúō", "pronunciation": "ag-rew'-o", "derivation": "from (G61);", "definition": "to hunt, i.e. (figuratively) to entrap", "kjv": "catch."}, "G65": {"greek": "ἀγριέλαιος", "translit": "agriélaios", "pronunciation": "ag-ree-el'-ah-yos", "derivation": "from (G66) and (G1636);", "definition": "an oleaster", "kjv": "olive tree (which is) wild."}, "G66": {"greek": "ἄγριος", "translit": "ágrios", "pronunciation": "ag'-ree-os", "derivation": "from (G68);", "definition": "wild (as pertaining to the country), literally (natural) or figuratively (fierce)", "kjv": "wild, raging."}, "G67": {"greek": "Ἀγρίππας", "translit": "Agríppas", "pronunciation": "ag-rip'-pas", "derivation": "apparently from (G66) and (G2462);", "definition": "wild-horse tamer; Agrippas, one of the Herods", "kjv": "Agrippa."}, "G68": {"greek": "ἀγρός", "translit": "agrós", "pronunciation": "ag-ros'", "derivation": "from (G71);", "definition": "a field (as a drive for cattle); genitive case, the country; specially, a farm, i.e. hamlet", "kjv": "country, farm, piece of ground, land."}, "G69": {"greek": "ἀγρυπνέω", "translit": "agrypnéō", "pronunciation": "ag-roop-neh'-o", "derivation": "ultimately from (G1) (as negative particle) and (G5258);", "definition": "to be sleepless, i.e. keep awake", "kjv": "watch."}, "G70": {"greek": "ἀγρυπνία", "translit": "agrypnía", "pronunciation": "ag-roop-nee'-ah", "derivation": "from (G69);", "definition": "sleeplessness, i.e. a keeping awake", "kjv": "watch."}, "G71": {"greek": "ἄγω", "translit": "ágō", "pronunciation": "ag'-o", "derivation": "a primary verb;", "definition": "properly, to lead; by implication, to bring, drive, (reflexively) go, (specially) pass (time), or (figuratively) induce", "kjv": "be, bring (forth), carry, (let) go, keep, lead away, be open."}, "G72": {"greek": "ἀγωγή", "translit": "agōgḗ", "pronunciation": "ag-o-gay'", "derivation": "reduplicated from (G71);", "definition": "a bringing up, i.e. mode of living", "kjv": "manner of life."}, "G73": {"greek": "ἀγών", "translit": "agṓn", "pronunciation": "ag-one'", "derivation": "from (G71);", "definition": "properly, a place of assembly (as if led), i.e. (by implication) a contest (held there); figuratively, an effort or anxiety", "kjv": "conflict, contention, fight, race."}, "G74": {"greek": "ἀγωνία", "translit": "agōnía", "pronunciation": "ag-o-nee'-ah", "derivation": "from (G73);", "definition": "a struggle (properly, the state), i.e. (figuratively) anguish", "kjv": "agony."}, "G75": {"greek": "ἀγωνίζομαι", "translit": "agōnízomai", "pronunciation": "ag-o-nid'-zom-ahee", "derivation": "from (G73);", "definition": "to struggle, literally (to compete for a prize), figuratively (to contend with an adversary), or genitive case (to endeavor to accomplish something)", "kjv": "fight, labor fervently, strive."}, "G76": {"greek": "Ἀδάμ", "translit": "Adám", "pronunciation": "ad-am'", "derivation": "of Hebrew origin ((G121));", "definition": "Adam, the first man; typically (of Jesus) man (as his representative)", "kjv": "Adam."}, "G77": {"greek": "ἀδάπανος", "translit": "adápanos", "pronunciation": "ad-ap'-an-os", "derivation": "from (G1) (as negative particle);", "definition": "and (G1160); costless, i.e. gratuitous", "kjv": "without expense."}, "G78": {"greek": "Ἀδδί", "translit": "Addí", "pronunciation": "ad-dee'", "derivation": "probably of Hebrew origin (compare (G5716));", "definition": "Addi, an Israelite", "kjv": "Addi."}, "G79": {"greek": "ἀδελφή", "translit": "adelphḗ", "pronunciation": "ad-el-fay'", "derivation": "feminine of (G80);", "definition": "a sister (naturally or ecclesiastically)", "kjv": "sister."}, "G80": {"greek": "ἀδελφός", "translit": "adelphós", "pronunciation": "ad-el-fos'", "derivation": "from (G1) (as a connective particle) and (the womb);", "definition": "a brother (literally or figuratively) near or remote (much like (G1))", "kjv": "brother."}, "G81": {"greek": "ἀδελφότης", "translit": "adelphótēs", "pronunciation": "ad-el-fot'-ace", "derivation": "from (G80);", "definition": "brotherhood (properly, the feeling of brotherliness), i.e. the (Christian) fraternity", "kjv": "brethren, brotherhood."}, "G82": {"greek": "ἄδηλος", "translit": "ádēlos", "pronunciation": "ad'-ay-los", "derivation": "from (G1) (as a negative particle) and (G1212);", "definition": "hidden, figuratively, indistinct", "kjv": "appear not, uncertain."}, "G83": {"greek": "ἀδηλότης", "translit": "adēlótēs", "pronunciation": "ad-ay-lot'-ace", "derivation": "from (G82);", "definition": "uncertainty", "kjv": "X uncertain."}, "G84": {"greek": "ἀδήλως", "translit": "adḗlōs", "pronunciation": "ad-ay'-loce", "derivation": "adverb from (G82);", "definition": "uncertainly", "kjv": "uncertainly."}, "G85": {"greek": "ἀδημονέω", "translit": "adēmonéō", "pronunciation": "ad-ay-mon-eh'-o", "derivation": "from a derivative of (to be sated to loathing);", "definition": "to be in distress (of mind)", "kjv": "be full of heaviness, be very heavy."}, "G86": {"greek": "ᾅδης", "translit": "háidēs", "pronunciation": "hah'-dace", "derivation": "from (G1) (as negative particle) and (G1492);", "definition": "properly, unseen, i.e. \"Hades\" or the place (state) of departed souls", "kjv": "grave, hell."}, "G87": {"greek": "ἀδιάκριτος", "translit": "adiákritos", "pronunciation": "ad-ee-ak'-ree-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G1252);", "definition": "properly, undistinguished, i.e. (actively) impartial", "kjv": "without partiality."}, "G88": {"greek": "ἀδιάλειπτος", "translit": "adiáleiptos", "pronunciation": "ad-ee-al'-ipe-tos", "derivation": "from (G1) (as a negative particle) and a derivative of a compound of (G1223) and (G3007);", "definition": "unintermitted, i.e. permanent", "kjv": "without ceasing, continual."}, "G89": {"greek": "ἀδιαλείπτως", "translit": "adialeíptōs", "pronunciation": "ad-ee-al-ipe'-toce", "derivation": "adverb from (G88);", "definition": "uninterruptedly, i.e. without omission (on an appropriate occasion)", "kjv": "without ceasing."}, "G90": {"greek": "ἀδιαφθορία", "translit": "adiaphthoría", "pronunciation": "ad-ee-af-thor-ee'-ah", "derivation": "from a derivative of a compound of (G1) (as a negative particle) and a derivative of (G1311);", "definition": "incorruptibleness, i.e. (figuratively) purity (of doctrine)", "kjv": "uncorruptness."}, "G91": {"greek": "ἀδικέω", "translit": "adikéō", "pronunciation": "ad-ee-keh'-o", "derivation": "from (G94);", "definition": "to be unjust, i.e. (actively) do wrong (morally, socially or physically)", "kjv": "hurt, injure, be an offender, be unjust, (do, suffer, take) wrong."}, "G92": {"greek": "ἀδίκημα", "translit": "adíkēma", "pronunciation": "ad-eek'-ay-mah", "derivation": "from (G91);", "definition": "a wrong done", "kjv": "evil doing, iniquity, matter of wrong."}, "G93": {"greek": "ἀδικία", "translit": "adikía", "pronunciation": "ad-ee-kee'-ah", "derivation": "from (G94);", "definition": "(legal) injustice (properly, the quality, by implication, the act); morally, wrongfulness (of character, life or act)", "kjv": "iniquity, unjust, unrighteousness, wrong."}, "G94": {"greek": "ἄδικος", "translit": "ádikos", "pronunciation": "ad'-ee-kos", "derivation": "from (G1) (as a negative particle) and (G1349);", "definition": "unjust; by extension wicked; by implication, treacherous; specially, heathen", "kjv": "unjust, unrighteous."}, "G95": {"greek": "ἀδίκως", "translit": "adíkōs", "pronunciation": "ad-ee'-koce", "derivation": "adverb from (G94);", "definition": "unjustly", "kjv": "wrongfully."}, "G96": {"greek": "ἀδόκιμος", "translit": "adókimos", "pronunciation": "ad-ok'-ee-mos", "derivation": "from (G1) (as a negative particle) and (G1384);", "definition": "unapproved, i.e. rejected; by implication, worthless (literally or morally)", "kjv": "castaway, rejected, reprobate."}, "G97": {"greek": "ἄδολος", "translit": "ádolos", "pronunciation": "ad'-ol-os", "derivation": "from (G1) (as a negative particle);", "definition": "and (G1388); undeceitful, i.e. (figuratively) unadulterated", "kjv": "sincere."}, "G98": {"greek": "Ἀδραμυττηνός", "translit": "Adramyttēnós", "pronunciation": "ad-ram-oot-tay-nos'", "derivation": "from (a place in Asia Minor);", "definition": "Adramyttene or belonging to Adramyttium", "kjv": "of Adramyttium."}, "G99": {"greek": "Ἀδρίας", "translit": "Adrías", "pronunciation": "ad-ree'-as", "derivation": "from (a place near its shore);", "definition": "the Adriatic sea (including the Ionian)", "kjv": "Adria."}, "G100": {"greek": "ἁδρότης", "translit": "hadrótēs", "pronunciation": "had-rot'-ace", "derivation": "from (stout);", "definition": "plumpness, i.e. (figuratively) liberality", "kjv": "abundance."}, "G101": {"greek": "ἀδυνατέω", "translit": "adynatéō", "pronunciation": "ad-oo-nat-eh'-o", "derivation": "from (G102);", "definition": "to be unable, i.e. (passively) impossible", "kjv": "be impossible."}, "G102": {"greek": "ἀδύνατος", "translit": "adýnatos", "pronunciation": "ad-oo'-nat-os", "derivation": "from (G1) (as a negative particle) and (G1415);", "definition": "unable, i.e. weak (literally or figuratively); passively, impossible", "kjv": "could not do, impossible, impotent, not possible, weak."}, "G103": {"greek": "ᾄδω", "translit": "áidō", "pronunciation": "ad'-o", "derivation": "a primary verb;", "definition": "to sing", "kjv": "sing."}, "G104": {"greek": "ἀεί", "translit": "aeí", "pronunciation": "ah-eye'", "derivation": "from an obsolete primary noun (apparently meaning continued duration);", "definition": "\"ever,\" by qualification regularly; by implication, earnestly", "kjv": "always, ever."}, "G105": {"greek": "ἀετός", "translit": "aetós", "pronunciation": "ah-et-os'", "derivation": "from the same as (G109);", "definition": "an eagle (from its wind-like flight)", "kjv": "eagle."}, "G106": {"greek": "ἄζυμος", "translit": "ázymos", "pronunciation": "ad'-zoo-mos", "derivation": "from (G1) (as a negative particle) and (G2219);", "definition": "unleavened, i.e. (figuratively) uncorrupted; (in the neutral plural) specially (by implication) the Passover week", "kjv": "unleavened (bread)."}, "G107": {"greek": "Ἀζώρ", "translit": "Azṓr", "pronunciation": "ad-zore'", "derivation": "of Hebrew origin (compare (G5809));", "definition": "Azor, an Israelite", "kjv": "Azor."}, "G108": {"greek": "Ἄζωτος", "translit": "Ázōtos", "pronunciation": "ad'-zo-tos", "derivation": "of Hebrew origin ((G795));", "definition": "Azotus (i.e. Ashdod), a place in Palestine", "kjv": "Azotus."}, "G109": {"greek": "ἀήρ", "translit": "aḗr", "pronunciation": "ah-ayr'", "derivation": "from (to breathe unconsciously, i.e. respire; by analogy, to blow);", "definition": "\"air\" (as naturally circumambient)", "kjv": "air."}, "G110": {"greek": "ἀθανασία", "translit": "athanasía", "pronunciation": "ath-an-as-ee'-ah", "derivation": "from a compound of (G1) (as a negative particle) and (G2288);", "definition": "deathlessness", "kjv": "immortality."}, "G111": {"greek": "ἀθέμιτος", "translit": "athémitos", "pronunciation": "ath-em'-ee-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (statute; from the base of (G5087));", "definition": "illegal; by implication, flagitious", "kjv": "abominable, unlawful thing."}, "G112": {"greek": "ἄθεος", "translit": "átheos", "pronunciation": "ath'-eh-os", "derivation": "from (G1) (as a negative particle) and (G2316);", "definition": "godless", "kjv": "without God."}, "G113": {"greek": "ἄθεσμος", "translit": "áthesmos", "pronunciation": "ath'-es-mos", "derivation": "from (G1) (as a negative particle) and a derivative of (G5087) (in the sense of enacting);", "definition": "lawless, i.e. (by implication) criminal", "kjv": "wicked."}, "G114": {"greek": "ἀθετέω", "translit": "athetéō", "pronunciation": "ath-et-eh'-o", "derivation": "from a compound of (G1) (as a negative particle) and a derivative of (G5087);", "definition": "to set aside, i.e. (by implication) to disesteem, neutralize or violate", "kjv": "cast off, despise, disannul, frustrate, bring to nought, reject."}, "G115": {"greek": "ἀθέτησις", "translit": "athétēsis", "pronunciation": "ath-et'-ay-sis", "derivation": "from (G114);", "definition": "cancellation (literally or figuratively)", "kjv": "disannulling, put away."}, "G116": {"greek": "Ἀθῆναι", "translit": "Athēnai", "pronunciation": "ath-ay-nahee", "derivation": "plural of (the goddess of wisdom, who was reputed to have founded the city);", "definition": "Athenæ, the capitol of Greece", "kjv": "Athens."}, "G117": {"greek": "Ἀθηναῖος", "translit": "Athēnaîos", "pronunciation": "ath-ay-nah'-yos", "derivation": "from (G116);", "definition": "an Athenæan or inhabitant of Athenæ", "kjv": "Athenian."}, "G118": {"greek": "ἀθλέω", "translit": "athléō", "pronunciation": "ath-leh'-o", "derivation": "from (a contest in the public lists);", "definition": "to contend in the competitive games", "kjv": "strive."}, "G119": {"greek": "ἄθλησις", "translit": "áthlēsis", "pronunciation": "ath'-lay-sis", "derivation": "from (G118);", "definition": "a struggle (figuratively)", "kjv": "fight."}, "G120": {"greek": "ἀθυμέω", "translit": "athyméō", "pronunciation": "ath-oo-meh'-o", "derivation": "from a compound of (G1) (as a negative particle) and (G2372);", "definition": "to be spiritless, i.e. disheartened", "kjv": "be dismayed."}, "G121": {"greek": "ἄθωος", "translit": "áthōos", "pronunciation": "ath'-o-os", "derivation": "from (G1) (as a negative particle) and probably a derivative of (G5087) (meaning a penalty);", "definition": "not guilty", "kjv": "innocent."}, "G122": {"greek": "αἴγειος", "translit": "aígeios", "pronunciation": "ah'-ee-ghi-os", "derivation": "from (a goat);", "definition": "belonging to a goat", "kjv": "goat."}, "G123": {"greek": "αἰγιαλός", "translit": "aigialós", "pronunciation": "ahee-ghee-al-os'", "derivation": "from (to rush) and (G251) (in the sense of the sea);", "definition": "a beach (on which the waves dash)", "kjv": "shore."}, "G124": {"greek": "Αἰγύπτιος", "translit": "Aigýptios", "pronunciation": "ahee-goop'-tee-os", "derivation": "from (G125);", "definition": "an Ægyptian or inhabitant of Ægyptus", "kjv": "Egyptian."}, "G125": {"greek": "Αἴγυπτος", "translit": "Aígyptos", "pronunciation": "ah'-ee-goop-tos", "derivation": "of uncertain derivation;", "definition": "Ægyptus, the land of the Nile", "kjv": "Egypt."}, "G126": {"greek": "ἀΐδιος", "translit": "aḯdios", "pronunciation": "ah-id'-ee-os", "derivation": "from (G104);", "definition": "everduring (forward and backward, or forward only)", "kjv": "eternal, everlasting."}, "G127": {"greek": "αἰδώς", "translit": "aidṓs", "pronunciation": "ahee-doce'", "derivation": "perhaps from (G1) (as a negative particle) and (G1492) (through the idea of downcast eyes);", "definition": "bashfulness, i.e. (towards men), modesty or (towards God) awe", "kjv": "reverence, shamefacedness."}, "G128": {"greek": "Αἰθίοψ", "translit": "Aithíops", "pronunciation": "ahee-thee'-ops", "derivation": "from (to scorch) and (the face, from (G3700));", "definition": "an Æthiopian (as a blackamoor)", "kjv": "Ethiopian."}, "G129": {"greek": "αἷμα", "translit": "haîma", "pronunciation": "hah'-ee-mah", "derivation": "of uncertain derivation;", "definition": "blood, literally (of men or animals), figuratively (the juice of grapes) or specially (the atoning blood of Christ); by implication, bloodshed, also kindred", "kjv": "blood."}, "G130": {"greek": "αἱματεκχυσία", "translit": "haimatekchysía", "pronunciation": "hahee-mat-ek-khoo-see'-ah", "derivation": "from (G129) and a derivative of (G1632);", "definition": "an effusion of blood", "kjv": "shedding of blood."}, "G131": {"greek": "αἱμοῤῥέω", "translit": "haimorrhéō", "pronunciation": "hahee-mor-hreh'-o", "derivation": "from (G129) and (G4482);", "definition": "to flow blood, i.e. have a hæmorrhage", "kjv": "diseased with an issue of blood."}, "G132": {"greek": "Αἰνέας", "translit": "Ainéas", "pronunciation": "ahee-neh'-as", "derivation": "of uncertain derivation;", "definition": "Ænĕas, an Israelite", "kjv": "Æneas."}, "G133": {"greek": "αἴνεσις", "translit": "aínesis", "pronunciation": "ah'-ee-nes-is", "derivation": "from (G134);", "definition": "a praising (the act), i.e. (specially) a thank(-offering)", "kjv": "praise."}, "G134": {"greek": "αἰνέω", "translit": "ainéō", "pronunciation": "ahee-neh'-o", "derivation": "from (G136);", "definition": "to praise (God)", "kjv": "praise."}, "G135": {"greek": "αἴνιγμα", "translit": "aínigma", "pronunciation": "ah'-ee-nig-ma", "derivation": "from a derivative of (G136) (in its primary sense);", "definition": "an obscure saying (\"enigma\"), i.e. (abstractly) obscureness", "kjv": "X darkly."}, "G136": {"greek": "αἶνος", "translit": "aînos", "pronunciation": "ah'-ee-nos", "derivation": "apparently a prime word;", "definition": "properly, a story, but used in the sense of (G1868); praise (of God)", "kjv": "praise."}, "G137": {"greek": "Αἰνών", "translit": "Ainṓn", "pronunciation": "ahee-nohn'", "derivation": "of Hebrew origin (a derivative of (G5869), place of springs);", "definition": "Ænon, a place in Palestine", "kjv": "Ænon."}, "G138": {"greek": "αἱρέομαι", "translit": "hairéomai", "pronunciation": "hahee-reh'-om-ahee", "derivation": "probably akin to (G142);", "definition": "to take for oneself, i.e. to prefer", "kjv": "choose."}, "G139": {"greek": "αἵρεσις", "translit": "haíresis", "pronunciation": "hah'-ee-res-is", "derivation": "from (G138);", "definition": "properly, a choice, i.e. (specially) a party or (abstractly) disunion", "kjv": "heresy (which is the Greek word itself), sect."}, "G140": {"greek": "αἱρετίζω", "translit": "hairetízō", "pronunciation": "hahee-ret-id'-zo", "derivation": "from a derivative of (G138);", "definition": "to make a choice", "kjv": "choose."}, "G141": {"greek": "αἱρετικός", "translit": "hairetikós", "pronunciation": "hahee-ret-ee-kos'", "derivation": "from the same as (G140);", "definition": "a schismatic", "kjv": "heretic (the Greek word itself)."}, "G142": {"greek": "αἴρω", "translit": "aírō", "pronunciation": "ah'-ee-ro", "derivation": "a primary root;", "definition": "to lift up; by implication, to take up or away; figuratively, to raise (the voice), keep in suspense (the mind), specially, to sail away (i.e. weigh anchor); by Hebraism (compare (G5375)) to expiate sin", "kjv": "away with, bear (up), carry, lift up, loose, make to doubt, put away, remove, take (away, up)."}, "G143": {"greek": "αἰσθάνομαι", "translit": "aisthánomai", "pronunciation": "ahee-sthan'-om-ahee", "derivation": "of uncertain derivation;", "definition": "to apprehend (properly, by the senses)", "kjv": "perceive."}, "G144": {"greek": "αἴσθησις", "translit": "aísthēsis", "pronunciation": "ah'-ee-sthay-sis", "derivation": "from (G143);", "definition": "perception, i.e. (figuratively) discernment", "kjv": "judgment."}, "G145": {"greek": "αἰσθητήριον", "translit": "aisthētḗrion", "pronunciation": "ahee-sthay-tay'-ree-on", "derivation": "from a derivative of (G143);", "definition": "properly, an organ of perception, i.e. (figuratively) judgment", "kjv": "senses."}, "G146": {"greek": "αἰσχροκερδής", "translit": "aischrokerdḗs", "pronunciation": "ahee-skhrok-er-dace'", "derivation": "from (G150) and (gain);", "definition": "sordid", "kjv": "given to (greedy of) filthy lucre."}, "G147": {"greek": "αἰσχροκερδῶς", "translit": "aischrokerdōs", "pronunciation": "ahee-skhrok-er-doce'", "derivation": "adverb from (G146);", "definition": "sordidly", "kjv": "for filthy lucre's sake."}, "G148": {"greek": "αἰσχρολογία", "translit": "aischrología", "pronunciation": "ahee-skhrol-og-ee'-ah", "derivation": "from (G150) and (G3056);", "definition": "vile conversation", "kjv": "filthy communication."}, "G150": {"greek": "αἰσχρός", "translit": "aischrós", "pronunciation": "ahee-skhros'", "derivation": "from the same as (G153);", "definition": "shameful, i.e. base (specially, venal)", "kjv": "filthy."}, "G151": {"greek": "αἰσχρότης", "translit": "aischrótēs", "pronunciation": "ahee-skhrot'-ace", "derivation": "from (G150);", "definition": "shamefulness, i.e. obscenity", "kjv": "filthiness."}, "G152": {"greek": "αἰσχύνη", "translit": "aischýnē", "pronunciation": "ahee-skhoo'-nay", "derivation": "from (G153);", "definition": "shame or disgrace (abstractly or concretely)", "kjv": "dishonesty, shame."}, "G153": {"greek": "αἰσχύνομαι", "translit": "aischýnomai", "pronunciation": "ahee-skhoo'-nom-ahee", "derivation": "from (disfigurement, i.e. disgrace);", "definition": "to feel shame (for oneself)", "kjv": "be ashamed."}, "G154": {"greek": "αἰτέω", "translit": "aitéō", "pronunciation": "ahee-teh'-o", "derivation": "of uncertain derivation;", "definition": "to ask (in genitive case)", "kjv": "ask, beg, call for, crave, desire, require."}, "G155": {"greek": "αἴτημα", "translit": "aítēma", "pronunciation": "ah'-ee-tay-mah", "derivation": "from (G154);", "definition": "a thing asked or (abstractly) an asking", "kjv": "petition, request, required."}, "G156": {"greek": "αἰτία", "translit": "aitía", "pronunciation": "ahee-tee'-a", "derivation": "from the same as (G154);", "definition": "a cause (as if asked for), i.e. (logical) reason (motive, matter), (legal) crime (alleged or proved)", "kjv": "accusation, case, cause, crime, fault, (wh-)ere(-fore)."}, "G157": {"greek": "αἰτίαμα", "translit": "aitíama", "pronunciation": "ahee-tee'-am-ah", "derivation": "from a derivative of (G156);", "definition": "a thing charged", "kjv": "complaint."}, "G158": {"greek": "αἴτιον", "translit": "aítion", "pronunciation": "ah'-ee-tee-on", "derivation": "neuter of (G159);", "definition": "a reason or crime (like (G156))", "kjv": "cause, fault."}, "G159": {"greek": "αἴτιος", "translit": "aítios", "pronunciation": "ah'-ee-tee-os", "derivation": "from the same as (G154);", "definition": "causative, i.e. (concretely) a causer", "kjv": "author."}, "G160": {"greek": "αἰφνίδιος", "translit": "aiphnídios", "pronunciation": "aheef-nid'-ee-os", "derivation": "from a compound of (G1) (as a negative particle) and (G5316) (compare (G1810)) (meaning non-apparent);", "definition": "unexpected, i.e. (adverbially) suddenly", "kjv": "sudden, unawares."}, "G161": {"greek": "αἰχμαλωσία", "translit": "aichmalōsía", "pronunciation": "aheekh-mal-o-see'-ah", "derivation": "from (G164);", "definition": "captivity", "kjv": "captivity."}, "G162": {"greek": "αἰχμαλωτεύω", "translit": "aichmalōteúō", "pronunciation": "aheekh-mal-o-tew'-o", "derivation": "from (G164);", "definition": "to capture (like (G163))", "kjv": "lead captive."}, "G163": {"greek": "αἰχμαλωτίζω", "translit": "aichmalōtízō", "pronunciation": "aheekh-mal-o-tid'-zo", "derivation": "from (G164);", "definition": "to make captive", "kjv": "lead away captive, bring into captivity."}, "G164": {"greek": "αἰχμάλωτος", "translit": "aichmálōtos", "pronunciation": "aheekh-mal-o-tos'", "derivation": "from (a spear) and a derivative of the same as (G259);", "definition": "properly, a prisoner of war, i.e. (genitive case) a captive", "kjv": "captive."}, "G165": {"greek": "αἰών", "translit": "aiṓn", "pronunciation": "ahee-ohn'", "derivation": "from the same as (G104);", "definition": "properly, an age; by extension, perpetuity (also past); by implication, the world; specially (Jewish) a Messianic period (present or future)", "kjv": "age, course, eternal, (for) ever(-more), (n-)ever, (beginning of the , while the) world (began, without end)."}, "G166": {"greek": "αἰώνιος", "translit": "aiṓnios", "pronunciation": "ahee-o'-nee-os", "derivation": "from (G165);", "definition": "perpetual (also used of past time, or past and future as well)", "kjv": "eternal, for ever, everlasting, world (began)."}, "G167": {"greek": "ἀκαθαρσία", "translit": "akatharsía", "pronunciation": "ak-ath-ar-see'-ah", "derivation": "from (G169);", "definition": "impurity (the quality), physically or morally", "kjv": "uncleanness."}, "G169": {"greek": "ἀκάθαρτος", "translit": "akáthartos", "pronunciation": "ak-ath'-ar-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G2508) (meaning cleansed);", "definition": "impure (ceremonially, morally (lewd) or specially, (demonic))", "kjv": "foul, unclean."}, "G170": {"greek": "ἀκαιρέομαι", "translit": "akairéomai", "pronunciation": "ak-ahee-reh'-om-ahee", "derivation": "from a compound of (G1) (as a negative particle) and (G2540) (meaning unseasonable);", "definition": "to be inopportune (for oneself), i.e. to fail of a proper occasion", "kjv": "lack opportunity."}, "G171": {"greek": "ἀκαίρως", "translit": "akaírōs", "pronunciation": "ak-ah'-ee-roce", "derivation": "adverb from the same as (G170);", "definition": "inopportunely", "kjv": "out of season."}, "G172": {"greek": "ἄκακος", "translit": "ákakos", "pronunciation": "ak'-ak-os", "derivation": "from (G1) (as a negative particle) and (G2556);", "definition": "not bad, i.e. (objectively) innocent or (subjectively) unsuspecting", "kjv": "harmless, simple."}, "G173": {"greek": "ἄκανθα", "translit": "ákantha", "pronunciation": "ak'-an-thah", "derivation": "probably from the same as (G188);", "definition": "a thorn", "kjv": "thorn."}, "G174": {"greek": "ἀκάνθινος", "translit": "akánthinos", "pronunciation": "ak-an'-thee-nos", "derivation": "from (G173);", "definition": "thorny", "kjv": "of thorns."}, "G175": {"greek": "ἄκαρπος", "translit": "ákarpos", "pronunciation": "ak'-ar-pos", "derivation": "from (G1) (as a negative particle) and (G2590);", "definition": "barren (literally or figuratively)", "kjv": "without fruit, unfruitful."}, "G176": {"greek": "ἀκατάγνωστος", "translit": "akatágnōstos", "pronunciation": "ak-at-ag'-noce-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G2607);", "definition": "unblamable", "kjv": "that cannot be condemned."}, "G177": {"greek": "ἀκατακάλυπτος", "translit": "akatakályptos", "pronunciation": "ak-at-ak-al'-oop-tos", "derivation": "from (G1) (as a negative particle) and a derivative of a compound of (G2596) and (G2572);", "definition": "unveiled", "kjv": "uncovered."}, "G178": {"greek": "ἀκατάκριτος", "translit": "akatákritos", "pronunciation": "ak-at-ak'-ree-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G2632);", "definition": "without (legal) trial", "kjv": "uncondemned."}, "G179": {"greek": "ἀκατάλυτος", "translit": "akatálytos", "pronunciation": "ak-at-al'-oo-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G2647);", "definition": "indissoluble, i.e. (figuratively) permanent", "kjv": "endless."}, "G180": {"greek": "ἀκατάπαυστος", "translit": "akatápaustos", "pronunciation": "ak-at-ap'-ow-stos", "derivation": "from (G1) (as a negative particle) and a derivative of (G2664);", "definition": "unrefraining", "kjv": "that cannot cease."}, "G181": {"greek": "ἀκαταστασία", "translit": "akatastasía", "pronunciation": "ak-at-as-tah-see'-ah", "derivation": "from (G182);", "definition": "instability, i.e. disorder", "kjv": "commotion, confusion, tumult."}, "G182": {"greek": "ἀκατάστατος", "translit": "akatástatos", "pronunciation": "ak-at-as'-tat-os", "derivation": "from (G1) (as a negative particle) and a derivative of (G2525);", "definition": "inconstant", "kjv": "unstable."}, "G184": {"greek": "Ἀκελδαμά", "translit": "Akeldamá", "pronunciation": "ak-el-dam-ah'", "derivation": "of Chaldee origin (meaning field of blood;", "definition": "corresponding to (G2506) and (G1818)); Akeldama, a place near Jerusalem", "kjv": "Aceldama."}, "G185": {"greek": "ἀκέραιος", "translit": "akéraios", "pronunciation": "ak-er'-ah-yos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G2767);", "definition": "unmixed, i.e. (figuratively) innocent", "kjv": "harmless, simple."}, "G186": {"greek": "ἀκλινής", "translit": "aklinḗs", "pronunciation": "ak-lee-nace'", "derivation": "from (G1) (as a negative particle) and (G2827);", "definition": "not leaning, i.e. (figuratively) firm", "kjv": "without wavering."}, "G187": {"greek": "ἀκμάζω", "translit": "akmázō", "pronunciation": "ak-mad'-zo", "derivation": "from the same as (G188);", "definition": "to make a point, i.e. (figuratively) mature", "kjv": "be fully ripe."}, "G188": {"greek": "ἀκμήν", "translit": "akmḗn", "pronunciation": "ak-mane'", "derivation": "accusative case of a noun (\"acme\") akin to (a point) and meaning the same;", "definition": "adverbially, just now, i.e. still", "kjv": "yet."}, "G189": {"greek": "ἀκοή", "translit": "akoḗ", "pronunciation": "ak-o-ay'", "derivation": "from (G191);", "definition": "hearing (the act, the sense or the thing heard)", "kjv": "audience, ear, fame, which ye heard, hearing, preached, report, rumor."}, "G190": {"greek": "ἀκολουθέω", "translit": "akolouthéō", "pronunciation": "ak-ol-oo-theh'-o", "derivation": "from (G1) (as a particle of union) and (a road);", "definition": "properly, to be in the same way with, i.e. to accompany (specially, as a disciple)", "kjv": "follow, reach."}, "G191": {"greek": "ἀκούω", "translit": "akoúō", "pronunciation": "ak-oo'-o", "derivation": "a primary verb;", "definition": "to hear (in various senses)", "kjv": "give (in the) audience (of), come (to the ears), (shall) hear(-er, -ken), be noised, be reported, understand."}, "G192": {"greek": "ἀκρασία", "translit": "akrasía", "pronunciation": "ak-ras-ee'-a", "derivation": "from (G193);", "definition": "want of self-restraint", "kjv": "excess, incontinency."}, "G193": {"greek": "ἀκρατής", "translit": "akratḗs", "pronunciation": "ak-rat'-ace", "derivation": "from (G1) (as a negative particle) and (G2904);", "definition": "powerless, i.e. without self-control", "kjv": "incontinent."}, "G194": {"greek": "ἄκρατος", "translit": "ákratos", "pronunciation": "ak'-rat-os", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G2767);", "definition": "undiluted", "kjv": "without mixture."}, "G195": {"greek": "ἀκρίβεια", "translit": "akríbeia", "pronunciation": "ak-ree'-bi-ah", "derivation": "from the same as (G196);", "definition": "exactness", "kjv": "perfect manner."}, "G196": {"greek": "ἀκριβέστατος", "translit": "akribéstatos", "pronunciation": "ak-ree-bes'-ta-tos", "derivation": "superlative of (a derivative of the same as (G206));", "definition": "most exact", "kjv": "most straitest."}, "G197": {"greek": "ἀκριβέστερον", "translit": "akribésteron", "pronunciation": "ak-ree-bes'-ter-on", "derivation": "neuter of the comparative of the same as (G196);", "definition": "(adverbially) more exactly", "kjv": "more perfect(-ly)."}, "G198": {"greek": "ἀκριβόω", "translit": "akribóō", "pronunciation": "ak-ree-bo'-o", "derivation": "from the same as (G196);", "definition": "to be exact, i.e. ascertain", "kjv": "enquire diligently."}, "G199": {"greek": "ἀκριβῶς", "translit": "akribōs", "pronunciation": "ak-ree-boce'", "derivation": "adverb from the same as (G196);", "definition": "exactly", "kjv": "circumspectly, diligently, perfect(-ly)."}, "G200": {"greek": "ἀκρίς", "translit": "akrís", "pronunciation": "ak-rece'", "derivation": "apparently from the same as (G206);", "definition": "a locust (as pointed, or as lighting on the top of vegetation)", "kjv": "locust."}, "G201": {"greek": "ἀκροατήριον", "translit": "akroatḗrion", "pronunciation": "ak-ro-at-ay'-ree-on", "derivation": "from (G202);", "definition": "an audience-room", "kjv": "place of hearing."}, "G202": {"greek": "ἀκροατής", "translit": "akroatḗs", "pronunciation": "ak-ro-at-ace'", "derivation": "from (to listen; apparently an intensive of (G191));", "definition": "a hearer (merely)", "kjv": "hearer."}, "G203": {"greek": "ἀκροβυστία", "translit": "akrobystía", "pronunciation": "ak-rob-oos-tee'-ah", "derivation": "from (G206) and probably a modified form of (the penis or male sexual organ);", "definition": "the prepuce; by implication, an uncircumcised (i.e. gentile, figuratively, unregenerate) state or person", "kjv": "not circumcised, uncircumcised (with (G2192)), uncircumcision."}, "G204": {"greek": "ἀκρογωνιαῖος", "translit": "akrogōniaîos", "pronunciation": "ak-rog-o-nee-ah'-yos", "derivation": "from (G206) and (G1137);", "definition": "belonging to the extreme corner", "kjv": "chief corner."}, "G205": {"greek": "ἀκροθίνιον", "translit": "akrothínion", "pronunciation": "ak-roth-in'-ee-on", "derivation": "from (G206) and (a heap);", "definition": "properly (in the plural) the top of the heap, i.e. (by implication) best of the booty", "kjv": "spoils."}, "G206": {"greek": "ἄκρον", "translit": "ákron", "pronunciation": "ak'-ron", "derivation": "neuter of an adjective probably akin to the base of (G188);", "definition": "the extremity", "kjv": "one end… other, tip, top, uttermost part."}, "G207": {"greek": "Ἀκύλας", "translit": "Akýlas", "pronunciation": "ak-oo'-las", "derivation": "probably for Latin aquila (an eagle);", "definition": "Akulas, an Israelite", "kjv": "Aquila."}, "G208": {"greek": "ἀκυρόω", "translit": "akyróō", "pronunciation": "ak-oo-ro'-o", "derivation": "from (G1) (as a negative particle) and (G2964);", "definition": "to invalidate", "kjv": "disannul, make of none effect."}, "G209": {"greek": "ἀκωλύτως", "translit": "akōlýtōs", "pronunciation": "ak-o-loo'-toce", "derivation": "adverb from a compound of (G1) (as a negative particle) and a derivative of (G2967);", "definition": "in an unhindered manner, i.e. freely", "kjv": "no man forbidding him."}, "G210": {"greek": "ἄκων", "translit": "ákōn", "pronunciation": "ak'-ohn", "derivation": "from (G1) (as a negative particle) and (G1635);", "definition": "unwilling", "kjv": "against the will."}, "G211": {"greek": "ἀλάβαστρον", "translit": "alábastron", "pronunciation": "al-ab'-as-tron", "derivation": "neuter of (of uncertain derivation), the name of a stone;", "definition": "properly, an \"alabaster\" box, i.e. (by extension) a perfume vase (of any material)", "kjv": "(alabaster) box."}, "G212": {"greek": "ἀλαζονεία", "translit": "alazoneía", "pronunciation": "al-ad-zon-i'-a", "derivation": "from (G213);", "definition": "braggadocio, i.e. (by implication) self-confidence", "kjv": "boasting, pride."}, "G213": {"greek": "ἀλαζών", "translit": "alazṓn", "pronunciation": "al-ad-zone'", "derivation": "from (vagrancy);", "definition": "braggart", "kjv": "boaster."}, "G214": {"greek": "ἀλαλάζω", "translit": "alalázō", "pronunciation": "al-al-ad'-zo", "derivation": "from ( a shout, \"halloo\");", "definition": "to vociferate, i.e. (by implication) to wail; figuratively, to clang", "kjv": "tinkle, wail."}, "G215": {"greek": "ἀλάλητος", "translit": "alálētos", "pronunciation": "al-al'-ay-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G2980);", "definition": "unspeakable", "kjv": "unutterable, which cannot be uttered."}, "G216": {"greek": "ἄλαλος", "translit": "álalos", "pronunciation": "al'-al-os", "derivation": "from (G1) (as a negative particle) and (G2980);", "definition": "mute", "kjv": "dumb."}, "G217": {"greek": "ἅλας", "translit": "hálas", "pronunciation": "hal'-as", "derivation": "from (G251);", "definition": "salt; figuratively, prudence", "kjv": "salt."}, "G218": {"greek": "ἀλείφω", "translit": "aleíphō", "pronunciation": "al-i'-fo", "derivation": "from (G1) (as particle of union) and the base of (G3045);", "definition": "to oil (with perfume)", "kjv": "anoint."}, "G219": {"greek": "ἀλεκτοροφωνία", "translit": "alektorophōnía", "pronunciation": "al-ek-tor-of-o-nee'-ah", "derivation": "from (G220) and (G5456);", "definition": "cock-crow, i.e. the third night-watch", "kjv": "cockcrowing."}, "G220": {"greek": "ἀλέκτωρ", "translit": "aléktōr", "pronunciation": "al-ek'-tore", "derivation": "from (to ward off);", "definition": "a cock or male fowl", "kjv": "cock."}, "G221": {"greek": "Ἀλεξανδρεύς", "translit": "Alexandreús", "pronunciation": "al-ex-and-reuce'", "derivation": "from (the city so called);", "definition": "an Alexandreian or inhabitant of Alexandria", "kjv": "of Alexandria, Alexandrian."}, "G222": {"greek": "Ἀλεξανδρῖνος", "translit": "Alexandrînos", "pronunciation": "al-ex-an-dree'-nos", "derivation": "from the same as (G221);", "definition": "Alexandrine, or belonging to Alexandria", "kjv": "of Alexandria."}, "G223": {"greek": "Ἀλέξανδρος", "translit": "Aléxandros", "pronunciation": "al-ex'-an-dros", "derivation": "from the same as (the first part of) (G220) and (G435);", "definition": "man-defender; Alexander, the name of three Israelites and one other man", "kjv": "Alexander."}, "G224": {"greek": "ἄλευρον", "translit": "áleuron", "pronunciation": "al'-yoo-ron", "derivation": "from (to grind);", "definition": "flour", "kjv": "meal."}, "G225": {"greek": "ἀλήθεια", "translit": "alḗtheia", "pronunciation": "al-ay'-thi-a", "derivation": "from (G227);", "definition": "truth", "kjv": "true, X truly, truth, verity."}, "G226": {"greek": "ἀληθεύω", "translit": "alētheúō", "pronunciation": "al-ayth-yoo'-o", "derivation": "from (G227);", "definition": "to be true (in doctrine and profession)", "kjv": "speak (tell) the truth."}, "G227": {"greek": "ἀληθής", "translit": "alēthḗs", "pronunciation": "al-ay-thace'", "derivation": "from (G1) (as a negative particle) and (G2990);", "definition": "true (as not concealing)", "kjv": "true, truly, truth."}, "G228": {"greek": "ἀληθινός", "translit": "alēthinós", "pronunciation": "al-ay-thee-nos'", "derivation": "from (G227);", "definition": "truthful", "kjv": "true."}, "G229": {"greek": "ἀλήθω", "translit": "alḗthō", "pronunciation": "al-ay'-tho", "derivation": "from the same as (G224);", "definition": "to grind", "kjv": "grind."}, "G230": {"greek": "ἀληθῶς", "translit": "alēthōs", "pronunciation": "al-ay-thoce'", "derivation": "adverb from (G227);", "definition": "truly", "kjv": "indeed, surely, of a surety, truly, of a (in) truth, verily, very."}, "G231": {"greek": "ἁλιεύς", "translit": "halieús", "pronunciation": "hal-ee-yoos'", "derivation": "from (G251);", "definition": "a sailor (as engaged on the salt water), i.e. (by implication) a fisher", "kjv": "fisher(-man)."}, "G232": {"greek": "ἁλιεύω", "translit": "halieúō", "pronunciation": "hal-ee-yoo'-o", "derivation": "from (G231);", "definition": "to be a fisher, i.e. (by implication) to fish", "kjv": "go a-fishing."}, "G233": {"greek": "ἁλίζω", "translit": "halízō", "pronunciation": "hal-id'-zo", "derivation": "from (G251);", "definition": "to salt", "kjv": "salt."}, "G234": {"greek": "ἀλίσγεμα", "translit": "alísgema", "pronunciation": "al-is'-ghem-ah", "derivation": "from (to soil);", "definition": "(ceremonially) defilement", "kjv": "pollution."}, "G235": {"greek": "ἀλλά", "translit": "allá", "pronunciation": "al-lah'", "derivation": "neuter plural of (G243);", "definition": "properly, other things, i.e. (adverbially) contrariwise (in many relations)", "kjv": "and, but (even), howbeit, indeed, nay, nevertheless, no, notwithstanding, save, therefore, yea, yet."}, "G236": {"greek": "ἀλλάσσω", "translit": "allássō", "pronunciation": "al-las'-so", "derivation": "from (G243);", "definition": "to make different", "kjv": "change."}, "G237": {"greek": "ἀλλαχόθεν", "translit": "allachóthen", "pronunciation": "al-lakh-oth'-en", "derivation": "from (G243);", "definition": "from elsewhere", "kjv": "some other way."}, "G238": {"greek": "ἀλληγορέω", "translit": "allēgoréō", "pronunciation": "al-lay-gor-eh'-o", "derivation": "from (G243) and (to harangue (compare (G58)));", "definition": "to allegorize", "kjv": "be an allegory (the Greek word itself)."}, "G239": {"greek": "ἀλληλουϊα", "translit": "allēlouïa", "pronunciation": "al-lay-loo'-ee-ah", "derivation": "of Hebrew origin (imperative of (G1984) and (G3050));", "definition": "praise ye Jah!, an adoring exclamation", "kjv": "alleluiah."}, "G240": {"greek": "ἀλλήλων", "translit": "allḗlōn", "pronunciation": "al-lay'-lone", "derivation": "Genitive plural from (G243) reduplicated;", "definition": "one another", "kjv": "each other, mutual, one another, (the other), (them-, your-)selves, (selves) together (sometimes with (G3326) or (G4314))."}, "G241": {"greek": "ἀλλογενής", "translit": "allogenḗs", "pronunciation": "al-log-en-ace'", "derivation": "from (G243) and (G1085);", "definition": "foreign, i.e. not a Jew", "kjv": "stranger."}, "G242": {"greek": "ἅλλομαι", "translit": "hállomai", "pronunciation": "hal'-lom-ahee", "derivation": "middle voice of apparently a primary verb;", "definition": "to jump; figuratively, to gush", "kjv": "leap, spring up."}, "G243": {"greek": "ἄλλος", "translit": "állos", "pronunciation": "al'-los", "derivation": "a primary word;", "definition": "\"else,\" i.e. different (in many applications)", "kjv": "more, one (another), (an-, some an-)other(-s, -wise)."}, "G244": {"greek": "ἀλλοτριεπίσκοπος", "translit": "allotriepískopos", "pronunciation": "al-lot-ree-ep-is'-kop-os", "derivation": "from (G245) and (G1985);", "definition": "overseeing others' affairs, i.e. a meddler (specially, in Gentile customs)", "kjv": "busybody in other men's matters."}, "G245": {"greek": "ἀλλότριος", "translit": "allótrios", "pronunciation": "al-lot'-ree-os", "derivation": "from (G243);", "definition": "another's, i.e. not one's own; by extension foreign, not akin, hostile", "kjv": "alien, (an-)other (man's, men's), strange(-r)."}, "G246": {"greek": "ἀλλόφυλος", "translit": "allóphylos", "pronunciation": "al-lof'-oo-los", "derivation": "from (G243) and (G5443);", "definition": "foreign, i.e. (specially) Gentile", "kjv": "one of another nation."}, "G247": {"greek": "ἄλλως", "translit": "állōs", "pronunciation": "al'-loce", "derivation": "adverb from (G243);", "definition": "differently", "kjv": "otherwise."}, "G248": {"greek": "ἀλοάω", "translit": "aloáō", "pronunciation": "al-o-ah'-o", "derivation": "from the same as (G257);", "definition": "to tread out grain", "kjv": "thresh, tread out the corn."}, "G249": {"greek": "ἄλογος", "translit": "álogos", "pronunciation": "al'-og-os", "derivation": "from (G1) (as a negative particle) and (G3056);", "definition": "irrational", "kjv": "brute, unreasonable."}, "G250": {"greek": "ἀλόη", "translit": "alóē", "pronunciation": "al-o-ay'", "derivation": "of foreign origin (compare (G174));", "definition": "aloes (the gum)", "kjv": "aloes."}, "G252": {"greek": "ἁλυκός", "translit": "halykós", "pronunciation": "hal-oo-kos'", "derivation": "from (G251);", "definition": "briny", "kjv": "salt."}, "G253": {"greek": "ἀλυπότερος", "translit": "alypóteros", "pronunciation": "al-oo-pot'-er-os", "derivation": "comparative of a compound of (G1) (as a negative particle) and (G3077);", "definition": "more without grief", "kjv": "less sorrowful."}, "G254": {"greek": "ἅλυσις", "translit": "hálysis", "pronunciation": "hal'-oo-sis", "derivation": "of uncertain derivation;", "definition": "a fetter or manacle", "kjv": "bonds, chain."}, "G255": {"greek": "ἀλυσιτελής", "translit": "alysitelḗs", "pronunciation": "al-oo-sit-el-ace'", "derivation": "from (G1) (as a negative particle) and the base of (G3081);", "definition": "gainless, i.e. (by implication) pernicious", "kjv": "unprofitable."}, "G256": {"greek": "Ἀλφαῖος", "translit": "Alphaîos", "pronunciation": "al-fah'-yos", "derivation": "of Hebrew origin (compare (G2501));", "definition": "Alphæus, an Israelite", "kjv": "Alpheus."}, "G257": {"greek": "ἅλων", "translit": "hálōn", "pronunciation": "hal'-ohn", "derivation": "probably from the base of (G1507);", "definition": "a threshing-floor (as rolled hard), i.e. (figuratively) the grain (and chaff, as just threshed)", "kjv": "floor."}, "G258": {"greek": "ἀλώπηξ", "translit": "alṓpēx", "pronunciation": "al-o'-pakes", "derivation": "of uncertain derivation;", "definition": "a fox, i.e. (figuratively) a cunning person", "kjv": "fox."}, "G259": {"greek": "ἅλωσις", "translit": "hálōsis", "pronunciation": "hal'-o-sis", "derivation": "from a collateral form of (G138);", "definition": "capture, be taken.", "kjv": ""}, "G260": {"greek": "ἅμα", "translit": "háma", "pronunciation": "ham'-ah", "derivation": "a primary particle;", "definition": "properly, at the \"same\" time, but freely used as a preposition or adverb denoting close association", "kjv": "also, and, together, with(-al)."}, "G261": {"greek": "ἀμαθής", "translit": "amathḗs", "pronunciation": "am-ath-ace'", "derivation": "from (G1) (as a negative particle) and (G3129);", "definition": "ignorant", "kjv": "unlearned."}, "G262": {"greek": "ἀμαράντινος", "translit": "amarántinos", "pronunciation": "am-ar-an'-tee-nos", "derivation": "from (G263);", "definition": "\"amaranthine\", i.e. (by implication) fadeless", "kjv": "that fadeth not away."}, "G263": {"greek": "ἀμάραντος", "translit": "amárantos", "pronunciation": "am-ar'-an-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G3133);", "definition": "unfading, i.e. (by implication) perpetual", "kjv": "that fadeth not away."}, "G264": {"greek": "ἁμαρτάνω", "translit": "hamartánō", "pronunciation": "ham-ar-tan'-o", "derivation": "perhaps from (G1) (as a negative particle) and the base of (G3313);", "definition": "properly, to miss the mark (and so not share in the prize), i.e. (figuratively) to err, especially (morally) to sin", "kjv": "for your faults, offend, sin, trespass."}, "G265": {"greek": "ἁμάρτημα", "translit": "hamártēma", "pronunciation": "ham-ar'-tay-mah", "derivation": "from (G264);", "definition": "a sin (properly concrete)", "kjv": "sin."}, "G266": {"greek": "ἁμαρτία", "translit": "hamartía", "pronunciation": "ham-ar-tee'-ah", "derivation": "from (G264);", "definition": "a sin (properly abstract)", "kjv": "offence, sin(-ful)."}, "G267": {"greek": "ἀμάρτυρος", "translit": "amártyros", "pronunciation": "am-ar'-too-ros", "derivation": "from (G1) (as a negative particle) and a form of (G3144);", "definition": "unattested", "kjv": "without witness."}, "G268": {"greek": "ἁμαρτωλός", "translit": "hamartōlós", "pronunciation": "ham-ar-to-los'", "derivation": "from (G264);", "definition": "sinful, i.e. a sinner", "kjv": "sinful, sinner."}, "G269": {"greek": "ἄμαχος", "translit": "ámachos", "pronunciation": "am'-akh-os", "derivation": "from (G1) (as a negative particle) and (G3163);", "definition": "peaceable", "kjv": "not a brawler."}, "G270": {"greek": "ἀμάω", "translit": "amáō", "pronunciation": "am-ah'-o", "derivation": "from (G260);", "definition": "properly, to collect, i.e. (by implication) reap", "kjv": "reap down."}, "G271": {"greek": "ἀμέθυστος", "translit": "améthystos", "pronunciation": "am-eth'-oos-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G3184);", "definition": "the \"amethyst\" (supposed to prevent intoxication)", "kjv": "amethyst."}, "G272": {"greek": "ἀμελέω", "translit": "ameléō", "pronunciation": "am-el-eh'-o", "derivation": "from (G1) (as a negative particle) and (G3199);", "definition": "to be careless of", "kjv": "make light of, neglect, be negligent, no regard."}, "G273": {"greek": "ἄμεμπτος", "translit": "ámemptos", "pronunciation": "am'-emp-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G3201);", "definition": "irreproachable", "kjv": "blameless, faultless, unblamable."}, "G274": {"greek": "ἀμέμπτως", "translit": "amémptōs", "pronunciation": "am-emp'-toce", "derivation": "adverb from (G273);", "definition": "faultlessly", "kjv": "blameless, unblamably."}, "G275": {"greek": "ἀμέριμνος", "translit": "amérimnos", "pronunciation": "am-er'-im-nos", "derivation": "from (G1) (as a negative particle) and (G3308);", "definition": "not anxious", "kjv": "without care(-fulness), secure."}, "G276": {"greek": "ἀμετάθετος", "translit": "ametáthetos", "pronunciation": "am-et-ath'-et-os", "derivation": "from (G1) (as a negative particle) and a derivative of (G3346);", "definition": "unchangeable, or (neuter as abstract) unchangeability", "kjv": "immutable(-ility)."}, "G277": {"greek": "ἀμετακίνητος", "translit": "ametakínētos", "pronunciation": "am-et-ak-in'-ay-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G3334);", "definition": "immovable", "kjv": "unmovable."}, "G278": {"greek": "ἀμεταμέλητος", "translit": "ametamélētos", "pronunciation": "am-et-am-el'-ay-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G3338);", "definition": "irrevocable", "kjv": "without repentance, not to be repented of."}, "G279": {"greek": "ἀμετανόητος", "translit": "ametanóētos", "pronunciation": "am-et-an-o'-ay-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G3340);", "definition": "unrepentant", "kjv": "impenitent."}, "G280": {"greek": "ἄμετρος", "translit": "ámetros", "pronunciation": "am'-et-ros", "derivation": "from (G1) (as a negative particle) and (G3358);", "definition": "immoderate", "kjv": "(thing) without measure."}, "G281": {"greek": "ἀμήν", "translit": "amḗn", "pronunciation": "am-ane'", "derivation": "of Hebrew origin ((G543));", "definition": "properly, firm, i.e. (figuratively) trustworthy; adverbially, surely (often as interjection, so be it)", "kjv": "amen, verily."}, "G282": {"greek": "ἀμήτωρ", "translit": "amḗtōr", "pronunciation": "am-ay'-tore", "derivation": "from (G1) (as a negative particle) and (G3384);", "definition": "motherless, i.e. of unknown maternity", "kjv": "without mother."}, "G283": {"greek": "ἀμίαντος", "translit": "amíantos", "pronunciation": "am-ee'-an-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G3392);", "definition": "unsoiled, i.e. (figuratively) pure", "kjv": "undefiled."}, "G284": {"greek": "Ἀμιναδάβ", "translit": "Aminadáb", "pronunciation": "am-ee-nad-ab'", "derivation": "of Hebrew origin ((G5992));", "definition": "Aminadab, an Israelite", "kjv": "Aminadab."}, "G285": {"greek": "ἄμμος", "translit": "ámmos", "pronunciation": "am'-mos", "derivation": "perhaps from (G260);", "definition": "sand (as heaped on the beach)", "kjv": "sand."}, "G286": {"greek": "ἀμνός", "translit": "amnós", "pronunciation": "am-nos'", "derivation": "apparently a primary word;", "definition": "a lamb", "kjv": "lamb."}, "G287": {"greek": "ἀμοιβή", "translit": "amoibḗ", "pronunciation": "am-oy-bay'", "derivation": "from (to exchange);", "definition": "requital", "kjv": "requite."}, "G288": {"greek": "ἄμπελος", "translit": "ámpelos", "pronunciation": "am'-pel-os", "derivation": "probably from the base of (G297) and that of (G257);", "definition": "a vine (as coiling about a support)", "kjv": "vine."}, "G289": {"greek": "ἀμπελουργός", "translit": "ampelourgós", "pronunciation": "am-pel-oor-gos'", "derivation": "from (G288) and (G2041);", "definition": "a vine-worker, i.e. pruner", "kjv": "vine-dresser."}, "G290": {"greek": "ἀμπελών", "translit": "ampelṓn", "pronunciation": "am-pel-ohn'", "derivation": "from (G288);", "definition": "a vineyard", "kjv": "vineyard."}, "G291": {"greek": "Ἀμπλίας", "translit": "Amplías", "pronunciation": "am-plee'-as", "derivation": "contracted for Latin ampliatus (enlarged);", "definition": "Amplias, a Roman Christian", "kjv": "Amplias."}, "G292": {"greek": "ἀμύνομαι", "translit": "amýnomai", "pronunciation": "am-oo'-nom-ahee", "derivation": "middle voice of a primary verb;", "definition": "to ward off (for oneself), i.e. protect", "kjv": "defend."}, "G293": {"greek": "ἀμφίβληστρον", "translit": "amphíblēstron", "pronunciation": "am-fib'-lace-tron", "derivation": "from a compound of the base of (G297) and (G906);", "definition": "a (fishing) net (as thrown about the fish)", "kjv": "net."}, "G294": {"greek": "ἀμφιέννυμι", "translit": "amphiénnymi", "pronunciation": "am-fee-en'-noo-mee", "derivation": "from the base of (G297) and (to invest);", "definition": "to enrobe", "kjv": "clothe."}, "G295": {"greek": "Ἀμφίπολις", "translit": "Amphípolis", "pronunciation": "am-fip'-ol-is", "derivation": "from the base of (G297) and (G4172);", "definition": "a city surrounded by a river; Amphipolis, a place in Macedonia", "kjv": "Amphipolis."}, "G296": {"greek": "ἄμφοδον", "translit": "ámphodon", "pronunciation": "am'-fod-on", "derivation": "from the base of (G297) and (G3598);", "definition": "a fork in the road", "kjv": "where two ways meet."}, "G297": {"greek": "ἀμφότερος", "translit": "amphóteros", "pronunciation": "am-fot'-er-os", "derivation": "comparative of (around);", "definition": "(in plural) both", "kjv": "both."}, "G298": {"greek": "ἀμώμητος", "translit": "amṓmētos", "pronunciation": "am-o'-may-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G3469);", "definition": "unblamable", "kjv": "blameless."}, "G299": {"greek": "ἄμωμος", "translit": "ámōmos", "pronunciation": "am'-o-mos", "derivation": "from (G1) (as a negative particle) and (G3470);", "definition": "unblemished (literally or figuratively)", "kjv": "without blame (blemish, fault, spot), faultless, unblamable."}, "G301": {"greek": "Ἀμώς", "translit": "Amṓs", "pronunciation": "am-oce'", "derivation": "of Hebrew origin ((G531));", "definition": "Amos, an Israelite", "kjv": "Amos."}, "G302": {"greek": "ἄν", "translit": "án", "pronunciation": "an", "derivation": "a primary particle, denoting a supposition, wish, possibility or uncertainty", "definition": "", "kjv": "(what-, where-, wither-, who-)soever."}, "G303": {"greek": "ἀνά", "translit": "aná", "pronunciation": "an-ah'", "derivation": "a primary preposition and adverb;", "definition": "properly, up; but (by extension) used (distributively) severally, or (locally) at (etc.)", "kjv": "and, apiece, by, each, every (man), in, through."}, "G304": {"greek": "ἀναβαθμός", "translit": "anabathmós", "pronunciation": "an-ab-ath-mos'", "derivation": "from (G305) (compare (G898));", "definition": "a stairway", "kjv": "stairs."}, "G305": {"greek": "ἀναβαίνω", "translit": "anabaínō", "pronunciation": "an-ab-ah'-ee-no", "derivation": "from (G303) and the base of (G939);", "definition": "to go up (literally or figuratively)", "kjv": "arise, ascend (up), climb (go, grow, rise, spring) up, come (up)."}, "G306": {"greek": "ἀναβάλλομαι", "translit": "anabállomai", "pronunciation": "an-ab-al'-lom-ahee", "derivation": "middle voice from (G303) and (G906);", "definition": "to put off (for oneself)", "kjv": "defer."}, "G307": {"greek": "ἀναβιβάζω", "translit": "anabibázō", "pronunciation": "an-ab-ee-bad'-zo", "derivation": "from (G303) and a derivative of the base of (G939);", "definition": "to cause to go up, i.e. haul (a net)", "kjv": "draw."}, "G308": {"greek": "ἀναβλέπω", "translit": "anablépō", "pronunciation": "an-ab-lep'-o", "derivation": "from (G303) and (G991);", "definition": "to look up; by implication, to recover sight", "kjv": "look (up), see, receive sight."}, "G309": {"greek": "ἀνάβλεψις", "translit": "anáblepsis", "pronunciation": "an-ab'-lep-sis", "derivation": "from (G308);", "definition": "restoration of sight", "kjv": "recovery of sight."}, "G310": {"greek": "ἀναβοάω", "translit": "anaboáō", "pronunciation": "an-ab-o-ah'-o", "derivation": "from (G303) and (G994);", "definition": "to halloo", "kjv": "cry (aloud, out)."}, "G311": {"greek": "ἀναβολή", "translit": "anabolḗ", "pronunciation": "an-ab-ol-ay'", "derivation": "from (G306);", "definition": "a putting off", "kjv": "delay."}, "G312": {"greek": "ἀναγγέλλω", "translit": "anangéllō", "pronunciation": "an-ang-el'-lo", "derivation": "from (G303) and the base of (G32);", "definition": "to announce (in detail)", "kjv": "declare, rehearse, report, show, speak, tell."}, "G313": {"greek": "ἀναγεννάω", "translit": "anagennáō", "pronunciation": "an-ag-en-nah'-o", "derivation": "from (G303) and (G1080);", "definition": "to beget or (by extension) bear (again)", "kjv": "beget, (bear) X (again)."}, "G314": {"greek": "ἀναγινώσκω", "translit": "anaginṓskō", "pronunciation": "an-ag-in-oce'-ko", "derivation": "from (G303) and (G1097);", "definition": "to know again, i.e. (by extension) to read", "kjv": "read."}, "G315": {"greek": "ἀναγκάζω", "translit": "anankázō", "pronunciation": "an-ang-kad'-zo", "derivation": "from (G318);", "definition": "to necessitate", "kjv": "compel, constrain."}, "G316": {"greek": "ἀναγκαῖος", "translit": "anankaîos", "pronunciation": "an-ang-kah'-yos", "derivation": "from (G318);", "definition": "necessary; by implication, close (of kin)", "kjv": "near, necessary, necessity, needful."}, "G317": {"greek": "ἀναγκαστῶς", "translit": "anankastōs", "pronunciation": "an-ang-kas-toce'", "derivation": "adverb from a derivative of (G315);", "definition": "compulsorily", "kjv": "by constraint."}, "G318": {"greek": "ἀνάγκη", "translit": "anánkē", "pronunciation": "an-ang-kay'", "derivation": "from (G303) and the base of (G43);", "definition": "constraint (literally or figuratively); by implication, distress", "kjv": "distress, must needs, (of) necessity(-sary), needeth, needful."}, "G319": {"greek": "ἀναγνωρίζομαι", "translit": "anagnōrízomai", "pronunciation": "an-ag-no-rid'-zom-ahee", "derivation": "middle voice from (G303) and (G1107);", "definition": "to make (oneself) known", "kjv": "be made known."}, "G320": {"greek": "ἀνάγνωσις", "translit": "anágnōsis", "pronunciation": "an-ag'-no-sis", "derivation": "from (G314);", "definition": "(the act of) reading", "kjv": "reading."}, "G321": {"greek": "ἀνάγω", "translit": "anágō", "pronunciation": "an-ag'-o", "derivation": "from (G303) and (G71);", "definition": "to lead up; by extension to bring out; specially, to sail away", "kjv": "bring (again, forth, up again), depart, launch (forth), lead (up), loose, offer, sail, set forth, take up."}, "G322": {"greek": "ἀναδείκνυμι", "translit": "anadeíknymi", "pronunciation": "an-ad-ike'-noo-mee", "derivation": "from (G303) and (G1166);", "definition": "to exhibit, i.e. (by implication) to indicate, appoint", "kjv": "appoint, shew."}, "G323": {"greek": "ἀνάδειξις", "translit": "anádeixis", "pronunciation": "an-ad'-ike-sis", "derivation": "from (G322);", "definition": "(the act of) exhibition", "kjv": "shewing."}, "G324": {"greek": "ἀναδέχομαι", "translit": "anadéchomai", "pronunciation": "an-ad-ekh'-om-ahee", "derivation": "from (G303) and (G1209);", "definition": "to entertain (as a guest)", "kjv": "receive."}, "G325": {"greek": "ἀναδίδωμι", "translit": "anadídōmi", "pronunciation": "an-ad-eed'-om-ee", "derivation": "from (G303) and (G1325);", "definition": "to hand over", "kjv": "deliver."}, "G326": {"greek": "ἀναζάω", "translit": "anazáō", "pronunciation": "an-ad-zah'-o", "derivation": "from (G303) and (G2198);", "definition": "to recover life (literally or figuratively)", "kjv": "(be a-)live again, revive."}, "G327": {"greek": "ἀναζητέω", "translit": "anazētéō", "pronunciation": "an-ad-zay-teh'-o", "derivation": "from (G303) and (G2212);", "definition": "to search out", "kjv": "seek."}, "G328": {"greek": "ἀναζώννυμι", "translit": "anazṓnnymi", "pronunciation": "an-ad-zone'-noo-mee", "derivation": "from (G303) and (G2224);", "definition": "to gird afresh", "kjv": "gird up."}, "G329": {"greek": "ἀναζωπυρέω", "translit": "anazōpyréō", "pronunciation": "an-ad-zo-poor-eh'-o", "derivation": "from (G303) and a compound of the base of (G2226) and (G4442);", "definition": "to re-enkindle", "kjv": "stir up."}, "G330": {"greek": "ἀναθάλλω", "translit": "anathállō", "pronunciation": "an-ath-al'-lo", "derivation": "from (G303) and (to flourish);", "definition": "to revive", "kjv": "flourish again."}, "G331": {"greek": "ἀνάθεμα", "translit": "anáthema", "pronunciation": "an-ath'-em-ah", "derivation": "from (G394);", "definition": "a (religious) ban or (concretely) excommunicated (thing or person)", "kjv": "accused, anathema, curse, X great."}, "G332": {"greek": "ἀναθεματίζω", "translit": "anathematízō", "pronunciation": "an-ath-em-at-id'-zo", "derivation": "from (G331);", "definition": "to declare or vow under penalty of execration", "kjv": "(bind under a) curse, bind with an oath."}, "G333": {"greek": "ἀναθεωρέω", "translit": "anatheōréō", "pronunciation": "an-ath-eh-o-reh'-o", "derivation": "from (G303) and (G2334);", "definition": "to look again (i.e. attentively) at (literally or figuratively)", "kjv": "behold, consider."}, "G335": {"greek": "ἀναίδεια", "translit": "anaídeia", "pronunciation": "an-ah'-ee-die-ah'", "derivation": "from a compound of (G1) (as a negative particle (compare (G427))) and (G127);", "definition": "impudence, i.e. (by implication) importunity", "kjv": "importunity."}, "G336": {"greek": "ἀναίρεσις", "translit": "anaíresis", "pronunciation": "an-ah'-ee-res-is", "derivation": "from (G337);", "definition": "(the act of) killing", "kjv": "death."}, "G337": {"greek": "ἀναιρέω", "translit": "anairéō", "pronunciation": "an-ahee-reh'-o", "derivation": "from (G303) and (the active of) (G138);", "definition": "to take up, i.e. adopt; by implication, to take away (violently), i.e. abolish, murder", "kjv": "put to death, kill, slay, take away, take up."}, "G338": {"greek": "ἀναίτιος", "translit": "anaítios", "pronunciation": "an-ah'-ee-tee-os", "derivation": "from (G1) (as a negative particle) and (G159) (in the sense of (G156));", "definition": "innocent", "kjv": "blameless, guiltless."}, "G339": {"greek": "ἀνακαθίζω", "translit": "anakathízō", "pronunciation": "an-ak-ath-id'-zo", "derivation": "from (G303) and (G2523);", "definition": "properly, to set up, i.e. (reflexively) to sit up", "kjv": "sit up."}, "G340": {"greek": "ἀνακαινίζω", "translit": "anakainízō", "pronunciation": "an-ak-ahee-nid'-zo", "derivation": "from (G303) and a derivative of (G2537);", "definition": "to restore", "kjv": "renew."}, "G341": {"greek": "ἀνακαινόω", "translit": "anakainóō", "pronunciation": "an-ak-ahee-no'-o", "derivation": "from (G303) and a derivative of (G2537);", "definition": "to renovate", "kjv": "renew."}, "G342": {"greek": "ἀνακαίνωσις", "translit": "anakaínōsis", "pronunciation": "an-ak-ah'-ee-no-sis", "derivation": "from (G341);", "definition": "renovation", "kjv": "renewing."}, "G343": {"greek": "ἀνακαλύπτω", "translit": "anakalýptō", "pronunciation": "an-ak-al-oop'-to", "derivation": "from (G303) (in the sense of reversal) and (G2572);", "definition": "to unveil", "kjv": "open, (un-)taken away."}, "G344": {"greek": "ἀνακάμπτω", "translit": "anakámptō", "pronunciation": "an-ak-amp'-to", "derivation": "from (G303) and (G2578);", "definition": "to turn back", "kjv": "(re-)turn."}, "G345": {"greek": "ἀνακεῖμαι", "translit": "anakeîmai", "pronunciation": "an-ak-i'-mahee", "derivation": "from (G303) and (G2749);", "definition": "to recline (as a corpse or at a meal)", "kjv": "guest, lean, lie, sit (down, at meat), at the table."}, "G346": {"greek": "ἀνακεφαλαίομαι", "translit": "anakephalaíomai", "pronunciation": "an-ak-ef-al-ah'-ee-om-ahee", "derivation": "from (G303) and (G2775) (in its original sense);", "definition": "to sum up", "kjv": "briefly comprehend, gather together in one."}, "G347": {"greek": "ἀνακλίνω", "translit": "anaklínō", "pronunciation": "an-ak-lee'-no", "derivation": "from (G303) and (G2827);", "definition": "to lean back", "kjv": "lay, (make) sit down."}, "G349": {"greek": "ἀνακράζω", "translit": "anakrázō", "pronunciation": "an-ak-rad'-zo", "derivation": "from (G303) and (G2896);", "definition": "to scream up (aloud)", "kjv": "cry out."}, "G350": {"greek": "ἀνακρίνω", "translit": "anakrínō", "pronunciation": "an-ak-ree'-no", "derivation": "from (G303) and (G2919);", "definition": "properly, to scrutinize, i.e. (by implication) investigate, interrogate, determine", "kjv": "ask, question, discern, examine, judge, search."}, "G351": {"greek": "ἀνάκρισις", "translit": "anákrisis", "pronunciation": "an-ak'-ree-sis", "derivation": "from (G350);", "definition": "a (judicial) investigation", "kjv": "examination."}, "G352": {"greek": "ἀνακύπτω", "translit": "anakýptō", "pronunciation": "an-ak-oop'-to", "derivation": "from (G303) (in the sense of reversal) and (G2955);", "definition": "to unbend, i.e. rise; figuratively, be elated", "kjv": "lift up, look up."}, "G353": {"greek": "ἀναλαμβάνω", "translit": "analambánō", "pronunciation": "an-al-am-ban'-o", "derivation": "from (G303) and (G2983);", "definition": "to take up", "kjv": "receive up, take (in, unto, up)."}, "G354": {"greek": "ἀνάληψις", "translit": "análēpsis", "pronunciation": "an-al'-ape-sis", "derivation": "from (G353);", "definition": "ascension", "kjv": "taking up."}, "G355": {"greek": "ἀναλίσκω", "translit": "analískō", "pronunciation": "an-al-is'-ko", "derivation": "from (G303) and a form of the alternate of (G138);", "definition": "properly, to use up, i.e. destroy", "kjv": "consume."}, "G356": {"greek": "ἀναλογία", "translit": "analogía", "pronunciation": "an-al-og-ee'-ah", "derivation": "from a compound of (G303) and (G3056);", "definition": "proportion", "kjv": "proportion."}, "G357": {"greek": "ἀναλογίζομαι", "translit": "analogízomai", "pronunciation": "an-al-og-id'-zom-ahee", "derivation": "middle voice from (G356);", "definition": "to estimate, i.e. (figuratively) contemplate", "kjv": "consider."}, "G358": {"greek": "ἄναλος", "translit": "ánalos", "pronunciation": "an'-al-os", "derivation": "from (G1) (as a negative particle) and (G251);", "definition": "saltless, i.e. insipid", "kjv": "X lose saltness."}, "G359": {"greek": "ἀνάλυσις", "translit": "análysis", "pronunciation": "an-al'-oo-sis", "derivation": "from (G360);", "definition": "departure", "kjv": "departure."}, "G360": {"greek": "ἀναλύω", "translit": "analýō", "pronunciation": "an-al-oo'-o", "derivation": "from (G303) and (G3089);", "definition": "to break up, i.e. depart (literally or figuratively)", "kjv": "depart, return."}, "G362": {"greek": "ἀναμένω", "translit": "anaménō", "pronunciation": "an-am-en'-o", "derivation": "from (G303) and (G3306);", "definition": "to await", "kjv": "wait for."}, "G363": {"greek": "ἀναμιμνήσκω", "translit": "anamimnḗskō", "pronunciation": "an-am-im-nace'-ko", "derivation": "from (G303) and (G3403);", "definition": "to remind; (reflexively) to recollect", "kjv": "call to mind, (bring to , call to, put in), remember(-brance)."}, "G364": {"greek": "ἀνάμνησις", "translit": "anámnēsis", "pronunciation": "an-am'-nay-sis", "derivation": "from (G363);", "definition": "recollection", "kjv": "remembrance (again)."}, "G365": {"greek": "ἀνανεόω", "translit": "ananeóō", "pronunciation": "an-an-neh-o'-o", "derivation": "from (G303) and a derivative of (G3501);", "definition": "to renovate, i.e. reform", "kjv": "renew."}, "G366": {"greek": "ἀνανήφω", "translit": "ananḗphō", "pronunciation": "an-an-ay'-fo", "derivation": "from (G303) and (G3525);", "definition": "to become sober again, i.e. (figuratively) regain (one's) senses", "kjv": "recover self."}, "G367": {"greek": "Ἀνανίας", "translit": "Ananías", "pronunciation": "an-an-ee'-as", "derivation": "of Hebrew origin ((G2608));", "definition": "Ananias, the name of three Israelites", "kjv": "Ananias."}, "G368": {"greek": "ἀναντίῤῥητος", "translit": "anantírrhētos", "pronunciation": "an-an-tir'-hray-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of a compound of (G473) and (G4483);", "definition": "indisputable", "kjv": "cannot be spoken against."}, "G369": {"greek": "ἀναντιῤῥήτως", "translit": "anantirrhḗtōs", "pronunciation": "an-an-tir-hray'-toce", "derivation": "adverb from (G368);", "definition": "promptly", "kjv": "without gainsaying."}, "G370": {"greek": "ἀνάξιος", "translit": "anáxios", "pronunciation": "an-ax'-ee-os", "derivation": "from (G1) (as a negative particle) and (G514);", "definition": "unfit", "kjv": "unworthy."}, "G371": {"greek": "ἀναξίως", "translit": "anaxíōs", "pronunciation": "an-ax-ee'-oce", "derivation": "adverb from (G370);", "definition": "irreverently", "kjv": "unworthily."}, "G372": {"greek": "ἀνάπαυσις", "translit": "anápausis", "pronunciation": "an-ap'-ow-sis", "derivation": "from (G373);", "definition": "intermission; by implication, recreation", "kjv": "rest."}, "G373": {"greek": "ἀναπαύω", "translit": "anapaúō", "pronunciation": "an-ap-ow'-o", "derivation": "from (G303) and (G3973);", "definition": "(reflexively) to repose (literally or figuratively (be exempt), remain); by implication, to refresh", "kjv": "take ease, refresh, (give, take) rest."}, "G374": {"greek": "ἀναπείθω", "translit": "anapeíthō", "pronunciation": "an-ap-i'-tho", "derivation": "from (G303) and (G3982);", "definition": "to incite", "kjv": "persuade."}, "G375": {"greek": "ἀναπέμπω", "translit": "anapémpō", "pronunciation": "an-ap-em'-po", "derivation": "from (G303) and (G3992);", "definition": "to send up or back", "kjv": "send (again)."}, "G376": {"greek": "ἀνάπηρος", "translit": "anápēros", "pronunciation": "an-ap'-ay-ros", "derivation": "from (G303) (in the sense of intensity) and (maimed);", "definition": "crippled", "kjv": "maimed."}, "G377": {"greek": "ἀναπίπτω", "translit": "anapíptō", "pronunciation": "an-ap-ip'-to", "derivation": "from (G303) and (G4098);", "definition": "to fall back, i.e. lie down, lean back", "kjv": "lean, sit down (to meat)."}, "G378": {"greek": "ἀναπληρόω", "translit": "anaplēróō", "pronunciation": "an-ap-lay-ro'-o", "derivation": "from (G303) and (G4137);", "definition": "to complete; by implication, to occupy, supply; figuratively, to accomplish (by coincidence ot obedience)", "kjv": "fill up, fulfill, occupy, supply."}, "G379": {"greek": "ἀναπολόγητος", "translit": "anapológētos", "pronunciation": "an-ap-ol-og'-ay-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G626);", "definition": "indefensible", "kjv": "without an excuse, inexcusable."}, "G380": {"greek": "ἀναπτύσσω", "translit": "anaptýssō", "pronunciation": "an-ap-toos'-o", "derivation": "from (G303) (in the sense of reversal) and (G4428);", "definition": "to unroll (a scroll or volume)", "kjv": "open."}, "G381": {"greek": "ἀνάπτω", "translit": "anáptō", "pronunciation": "an-ap'-to", "derivation": "from (G303) and (G681);", "definition": "to enkindle", "kjv": "kindle, light."}, "G382": {"greek": "ἀναρίθμητος", "translit": "anaríthmētos", "pronunciation": "an-ar-ith'-may-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G705);", "definition": "unnumbered, i.e. without number", "kjv": "innumerable."}, "G383": {"greek": "ἀνασείω", "translit": "anaseíō", "pronunciation": "an-as-i'-o", "derivation": "from (G303) and (G4579);", "definition": "figuratively, to excite", "kjv": "move, stir up."}, "G384": {"greek": "ἀνασκευάζω", "translit": "anaskeuázō", "pronunciation": "an-ask-yoo-ad'-zo", "derivation": "from (G303) (in the sense of reversal) and a derivative of (G4632);", "definition": "properly, to pack up (baggage), i.e. (by implication, and figuratively) to upset", "kjv": "subvert."}, "G385": {"greek": "ἀνασπάω", "translit": "anaspáō", "pronunciation": "an-as-pah'-o", "derivation": "from (G303) and (G4685);", "definition": "to take up or extricate", "kjv": "draw up, pull out."}, "G386": {"greek": "ἀνάστασις", "translit": "anástasis", "pronunciation": "an-as'-tas-is", "derivation": "from (G450);", "definition": "a standing up again, i.e. (literally) a resurrection from death (individual, genitive case or by implication, (its author)), or (figuratively) a (moral) recovery (of spiritual truth)", "kjv": "raised to life again, resurrection, rise from the dead, that should rise, rising again."}, "G387": {"greek": "ἀναστατόω", "translit": "anastatóō", "pronunciation": "an-as-tat-o'-o", "derivation": "from a derivative of (G450) (in the sense of removal);", "definition": "properly, to drive out of home, i.e. (by implication) to disturb (literally or figuratively)", "kjv": "trouble, turn upside down, make an uproar."}, "G388": {"greek": "ἀνασταυρόω", "translit": "anastauróō", "pronunciation": "an-as-tow-ro'-o", "derivation": "from (G303) and (G4717);", "definition": "to recrucify (figuratively)", "kjv": "crucify afresh."}, "G389": {"greek": "ἀναστενάζω", "translit": "anastenázō", "pronunciation": "an-as-ten-ad'-zo", "derivation": "from (G303) and (G4727);", "definition": "to sigh deeply", "kjv": "sigh deeply."}, "G390": {"greek": "ἀναστρέφω", "translit": "anastréphō", "pronunciation": "an-as-tref'-o", "derivation": "from (G303) and (G4762);", "definition": "to overturn; also to return; by implication, to busy oneself, i.e. remain, live", "kjv": "abide, behave self, have conversation, live, overthrow, pass, return, be used."}, "G391": {"greek": "ἀναστροφή", "translit": "anastrophḗ", "pronunciation": "an-as-trof-ay'", "derivation": "from (G390);", "definition": "behavior", "kjv": "conversation."}, "G392": {"greek": "ἀνατάσσομαι", "translit": "anatássomai", "pronunciation": "an-at-as'-som-ahee", "derivation": "from (G303) and the middle voice of (G5021);", "definition": "to arrange", "kjv": "set in order."}, "G393": {"greek": "ἀνατέλλω", "translit": "anatéllō", "pronunciation": "an-at-el'-lo", "derivation": "from (G303) and the base of (G5056);", "definition": "to (cause to) arise", "kjv": "(a-, make to) rise, at the rising of, spring (up), be up."}, "G394": {"greek": "ἀνατίθεμαι", "translit": "anatíthemai", "pronunciation": "an-at-ith'-em-ahee", "derivation": "from (G303) and the middle voice of (G5087);", "definition": "to set forth (for oneself), i.e propound", "kjv": "communicate, declare."}, "G395": {"greek": "ἀνατολή", "translit": "anatolḗ", "pronunciation": "an-at-ol-ay'", "derivation": "from (G393);", "definition": "a rising of light, i.e. dawn (figuratively); by implication, the east (also in plural)", "kjv": "dayspring, east, rising."}, "G396": {"greek": "ἀνατρέπω", "translit": "anatrépō", "pronunciation": "an-at-rep'-o", "derivation": "from (G303) and the base of (G5157);", "definition": "to overturn (figuratively)", "kjv": "overthrow, subvert."}, "G397": {"greek": "ἀνατρέφω", "translit": "anatréphō", "pronunciation": "an-at-ref'-o", "derivation": "from (G303) and (G5142);", "definition": "to rear (physically or mentally)", "kjv": "bring up, nourish (up)."}, "G398": {"greek": "ἀναφαίνω", "translit": "anaphaínō", "pronunciation": "an-af-ah'-ee-no", "derivation": "from (G303) and (G5316);", "definition": "to show, i.e. (reflexively) appear, or (passively) to have pointed out", "kjv": "(should) appear, discover."}, "G399": {"greek": "ἀναφέρω", "translit": "anaphérō", "pronunciation": "an-af-er'-o", "derivation": "from (G303) and (G5342);", "definition": "to take up (literally or figuratively)", "kjv": "bear, bring (carry, lead) up, offer (up)."}, "G400": {"greek": "ἀναφωνέω", "translit": "anaphōnéō", "pronunciation": "an-af-o-neh'-o", "derivation": "from (G303) and (G5455);", "definition": "to exclaim", "kjv": "speak out."}, "G401": {"greek": "ἀνάχυσις", "translit": "anáchysis", "pronunciation": "an-akh'-oo-sis", "derivation": "from a comparative of (G303) and (to pour);", "definition": "properly, effusion, i.e. (figuratively) license", "kjv": "excess."}, "G402": {"greek": "ἀναχωρέω", "translit": "anachōréō", "pronunciation": "an-akh-o-reh'-o", "derivation": "from (G303) and (G5562);", "definition": "to retire", "kjv": "depart, give place, go (turn) aside, withdraw self."}, "G403": {"greek": "ἀνάψυξις", "translit": "anápsyxis", "pronunciation": "an-aps'-ook-sis", "derivation": "from (G404);", "definition": "properly, a recovery of breath, i.e. (figuratively) revival", "kjv": "revival."}, "G404": {"greek": "ἀναψύχω", "translit": "anapsýchō", "pronunciation": "an-aps-oo'-kho", "derivation": "from (G303) and (G5594);", "definition": "properly, to cool off, i.e. (figuratively) relieve", "kjv": "refresh."}, "G405": {"greek": "ἀνδραποδιστής", "translit": "andrapodistḗs", "pronunciation": "an-drap-od-is-tace'", "derivation": "from a derivative of a compound of (G435) and (G4228);", "definition": "an enslaver (as bringing men to his feet)", "kjv": "menstealer."}, "G406": {"greek": "Ἀνδρέας", "translit": "Andréas", "pronunciation": "an-dreh'-as", "derivation": "from (G435);", "definition": "manly; Andreas, an Israelite", "kjv": "Andrew."}, "G407": {"greek": "ἀνδρίζομαι", "translit": "andrízomai", "pronunciation": "an-drid'-zom-ahee", "derivation": "middle voice from (G435);", "definition": "to act manly", "kjv": "quit like men."}, "G408": {"greek": "Ἀνδρόνικος", "translit": "Andrónikos", "pronunciation": "an-dron'-ee-kos", "derivation": "from (G435) and (G3534);", "definition": "man of victory; Andronicos, an Israelite", "kjv": "Adronicus."}, "G409": {"greek": "ἀνδροφόνος", "translit": "androphónos", "pronunciation": "an-drof-on'-os", "derivation": "from (G435) and (G5408);", "definition": "a murderer", "kjv": "manslayer."}, "G410": {"greek": "ἀνέγκλητος", "translit": "anénklētos", "pronunciation": "an-eng'-klay-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G1458);", "definition": "unaccused, i.e. (by implication) irreproachable", "kjv": "blameless."}, "G411": {"greek": "ἀνεκδιήγητος", "translit": "anekdiḗgētos", "pronunciation": "an-ek-dee-ay'-gay-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G1555);", "definition": "not expounded in full, i.e. indescribable", "kjv": "unspeakable."}, "G412": {"greek": "ἀνεκλάλητος", "translit": "aneklálētos", "pronunciation": "an-ek-lal'-ay-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G1583);", "definition": "not spoken out, i.e. (by implication) unutterable", "kjv": "unspeakable."}, "G413": {"greek": "ἀνέκλειπτος", "translit": "anékleiptos", "pronunciation": "an-ek'-lipe-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G1587);", "definition": "not left out, i.e. (by implication) inexhaustible", "kjv": "that faileth not."}, "G414": {"greek": "ἀνεκτότερος", "translit": "anektóteros", "pronunciation": "an-ek-tot'-er-os", "derivation": "comparative of a derivative of (G430);", "definition": "more endurable", "kjv": "more tolerable."}, "G415": {"greek": "ἀνελεήμων", "translit": "aneleḗmōn", "pronunciation": "an-eleh-ay'-mone", "derivation": "from (G1) (as a negative particle) and (G1655);", "definition": "merciless", "kjv": "unmerciful."}, "G416": {"greek": "ἀνεμίζω", "translit": "anemízō", "pronunciation": "an-em-id'-zo", "derivation": "from (G417);", "definition": "to toss with the wind", "kjv": "drive with the wind."}, "G417": {"greek": "ἄνεμος", "translit": "ánemos", "pronunciation": "an'-em-os", "derivation": "from the base of (G109);", "definition": "wind; (plural) by implication, (the four) quarters (of the earth)", "kjv": "wind."}, "G418": {"greek": "ἀνένδεκτος", "translit": "anéndektos", "pronunciation": "an-en'-dek-tos", "derivation": "from (G1) (as a negative particle) and a derivative of the same as (G1735);", "definition": "unadmitted, i.e. (by implication) not supposable", "kjv": "impossible."}, "G419": {"greek": "ἀνεξερεύνητος", "translit": "anexereúnētos", "pronunciation": "an-ex-er-yoo'-nay-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G1830);", "definition": "not searched out, i.e. (by implication) inscrutable", "kjv": "unsearchable."}, "G420": {"greek": "ἀνεξίκακος", "translit": "anexíkakos", "pronunciation": "an-ex-ik'-ak-os", "derivation": "from (G430) and (G2556);", "definition": "enduring of ill, i.e. forbearing", "kjv": "patient."}, "G421": {"greek": "ἀνεξιχνίαστος", "translit": "anexichníastos", "pronunciation": "an-ex-ikh-nee'-as-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of a compound of (G1537) and a derivative of (G2487);", "definition": "not tracked out, i.e. (by implication) untraceable", "kjv": "past finding out; unsearchable."}, "G422": {"greek": "ἀνεπαίσχυντος", "translit": "anepaíschyntos", "pronunciation": "an-ep-ah'-ee-skhoon-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of a compound of (G1909) and (G153);", "definition": "not ashamed, i.e. irreprehensible:", "kjv": "--that needeth not to be ashamed."}, "G423": {"greek": "ἀνεπίληπτος", "translit": "anepílēptos", "pronunciation": "an-ep-eel'-ape-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G1949);", "definition": "not arrested, i.e. (by implication) inculpable", "kjv": "blameless, unrebukeable."}, "G424": {"greek": "ἀνέρχομαι", "translit": "anérchomai", "pronunciation": "an-erkh'-om-ahee", "derivation": "from (G303) and (G2064);", "definition": "to ascend", "kjv": "go up."}, "G425": {"greek": "ἄνεσις", "translit": "ánesis", "pronunciation": "an'-es-is", "derivation": "from (G447);", "definition": "relaxation or (figuratively) relief", "kjv": "eased, liberty, rest."}, "G426": {"greek": "ἀνετάζω", "translit": "anetázō", "pronunciation": "an-et-ad'-zo", "derivation": "from (G303) and (to test);", "definition": "to investigate (judicially)", "kjv": "(should have) examined(-d)."}, "G427": {"greek": "ἄνευ", "translit": "áneu", "pronunciation": "an'-yoo", "derivation": "a primary particle;", "definition": "without", "kjv": "without."}, "G428": {"greek": "ἀνεύθετος", "translit": "aneúthetos", "pronunciation": "an-yoo'-the-tos", "derivation": "from (G1) (as a negative particle) and (G2111);", "definition": "not well set, i.e. inconvenient", "kjv": "not commodious."}, "G429": {"greek": "ἀνευρίσκω", "translit": "aneurískō", "pronunciation": "an-yoo-ris'-ko", "derivation": "from (G303) and (G2147);", "definition": "to find out", "kjv": "find."}, "G430": {"greek": "ἀνέχομαι", "translit": "anéchomai", "pronunciation": "an-ekh'-om-ahee", "derivation": "middle voice from (G303) and (G2192);", "definition": "to hold oneself up against, i.e. (figuratively) put up with", "kjv": "bear with, endure, forbear, suffer."}, "G431": {"greek": "ἀνεψιός", "translit": "anepsiós", "pronunciation": "an-eps'-ee-os", "derivation": "from (G1) (as a particle of union) and an obsolete (a brood);", "definition": "properly, akin, i.e. (specially) a cousin", "kjv": "sister's son."}, "G432": {"greek": "ἄνηθον", "translit": "ánēthon", "pronunciation": "an'-ay-thon", "derivation": "probably of foreign origin;", "definition": "dill", "kjv": "anise."}, "G433": {"greek": "ἀνήκω", "translit": "anḗkō", "pronunciation": "an-ay'-ko", "derivation": "from (G303) and (G2240);", "definition": "to attain to, i.e. (figuratively) be proper", "kjv": "convenient, be fit."}, "G434": {"greek": "ἀνήμερος", "translit": "anḗmeros", "pronunciation": "an-ay'-mer-os", "derivation": "from (G1) (as a negative particle) and (lame);", "definition": "savage", "kjv": "fierce."}, "G435": {"greek": "ἀνήρ", "translit": "anḗr", "pronunciation": "an'-ayr", "derivation": "a primary word (compare (G444));", "definition": "a man (properly as an individual male)", "kjv": "fellow, husband, man, sir."}, "G436": {"greek": "ἀνθίστημι", "translit": "anthístēmi", "pronunciation": "anth-is'-tay-mee", "derivation": "from (G473) and (G2476);", "definition": "to stand against, i.e. oppose", "kjv": "resist, withstand."}, "G437": {"greek": "ἀνθομολογέομαι", "translit": "anthomologéomai", "pronunciation": "anth-om-ol-og-eh'-om-ahee", "derivation": "from (G473) and the middle voice of (G3670);", "definition": "to confess in turn, i.e. respond in praise", "kjv": "give thanks."}, "G438": {"greek": "ἄνθος", "translit": "ánthos", "pronunciation": "anth'-os", "derivation": "a primary word;", "definition": "a blossom", "kjv": "flower."}, "G439": {"greek": "ἀνθρακιά", "translit": "anthrakiá", "pronunciation": "anth-rak-ee-ah'", "derivation": "from (G440);", "definition": "a bed of burning coals", "kjv": "fire of coals."}, "G440": {"greek": "ἄνθραξ", "translit": "ánthrax", "pronunciation": "anth'-rax", "derivation": "of uncertain derivation;", "definition": "a live coal", "kjv": "coal of fire."}, "G441": {"greek": "ἀνθρωπάρεσκος", "translit": "anthrōpáreskos", "pronunciation": "anth-ro-par'-es-kos", "derivation": "from (G444) and (G700);", "definition": "man-courting, i.e. fawning", "kjv": "men-pleaser."}, "G442": {"greek": "ἀνθρώπινος", "translit": "anthrṓpinos", "pronunciation": "anth-ro'-pee-nos", "derivation": "from (G444);", "definition": "human", "kjv": "human, common to man, man(-kind), (man-)kind, men's, after the manner of men."}, "G443": {"greek": "ἀνθρωποκτόνος", "translit": "anthrōpoktónos", "pronunciation": "anth-ro-pok-ton'-os", "derivation": "from (G444) and (to kill);", "definition": "a manslayer", "kjv": "murderer."}, "G444": {"greek": "ἄνθρωπος", "translit": "ánthrōpos", "pronunciation": "anth'-ro-pos", "derivation": "from (G435) and (the countenance; from (G3700));", "definition": "man-faced, i.e. a human being", "kjv": "certain, man."}, "G446": {"greek": "ἀνθύπατος", "translit": "anthýpatos", "pronunciation": "anth-oo'-pat-os", "derivation": "from (G473) and a superlative of (G5228);", "definition": "instead of the highest officer, i.e. (specially) a Roman proconsul", "kjv": "deputy."}, "G447": {"greek": "ἀνίημι", "translit": "aníēmi", "pronunciation": "an-ee'-ay-mee", "derivation": "from (G303) and (to send);", "definition": "to let up, i.e. (literally) slacken or (figuratively) desert, desist from", "kjv": "forbear, leave, loose."}, "G448": {"greek": "ἀνίλεως", "translit": "aníleōs", "pronunciation": "an-ee'-leh-oce", "derivation": "from (G1) (as a negative particle) and (G2436);", "definition": "inexorable", "kjv": "without mercy."}, "G449": {"greek": "ἄνιπτος", "translit": "ániptos", "pronunciation": "an'-ip-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G3538);", "definition": "without ablution", "kjv": "unwashen."}, "G450": {"greek": "ἀνίστημι", "translit": "anístēmi", "pronunciation": "an-is'-tay-mee", "derivation": "from (G303) and (G2476);", "definition": "to stand up (literal or figurative, transitive or intransitive)", "kjv": "arise, lift up, raise up (again), rise (again), stand up(-right)."}, "G451": {"greek": "Ἄννα", "translit": "Ánna", "pronunciation": "an'-nah", "derivation": "of Hebrew origin ((G2584));", "definition": "Anna, an Israelitess", "kjv": "Anna."}, "G452": {"greek": "Ἄννας", "translit": "Ánnas", "pronunciation": "an'-nas", "derivation": "of Hebrew origin ((G2608));", "definition": "Annas (i.e. (G367)), an Israelite", "kjv": "Annas."}, "G453": {"greek": "ἀνόητος", "translit": "anóētos", "pronunciation": "an-o'-ay-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G3539);", "definition": "unintelligent; by implication, sensual", "kjv": "fool(-ish), unwise."}, "G454": {"greek": "ἄνοια", "translit": "ánoia", "pronunciation": "an'-oy-ah", "derivation": "from a compound of (G1) (as a negative particle) and (G3563);", "definition": "stupidity; by implication, rage", "kjv": "folly, madness."}, "G455": {"greek": "ἀνοίγω", "translit": "anoígō", "pronunciation": "an-oy'-go", "derivation": "from (G303) and (to open);", "definition": "to open up (literally or figuratively, in various applications)", "kjv": "open."}, "G456": {"greek": "ἀνοικοδομέω", "translit": "anoikodoméō", "pronunciation": "an-oy-kod-om-eh'-o", "derivation": "from (G303) and (G3618);", "definition": "to rebuild", "kjv": "build again."}, "G457": {"greek": "ἄνοιξις", "translit": "ánoixis", "pronunciation": "an'-oix-is", "derivation": "from (G455);", "definition": "opening (throat)", "kjv": "X open."}, "G458": {"greek": "ἀνομία", "translit": "anomía", "pronunciation": "an-om-ee'-ah", "derivation": "from (G459);", "definition": "illegality, i.e. violation of law or (genitive case) wickedness", "kjv": "iniquity, X transgress(-ion of) the law, unrighteousness."}, "G459": {"greek": "ἄνομος", "translit": "ánomos", "pronunciation": "an'-om-os", "derivation": "from (G1) (as a negative particle) and (G3551);", "definition": "lawless, i.e. (negatively) not subject to (the Jewish) law; (by implication, a Gentile), or (positively) wicked", "kjv": "without law, lawless, transgressor, unlawful, wicked."}, "G460": {"greek": "ἀνόμως", "translit": "anómōs", "pronunciation": "an-om'-oce", "derivation": "adverb from (G459);", "definition": "lawlessly, i.e. (specially) not amenable to (the Jewish) law", "kjv": "without law."}, "G461": {"greek": "ἀνορθόω", "translit": "anorthóō", "pronunciation": "an-orth-o'-o", "derivation": "from (G303) and a derivative of the base of (G3717);", "definition": "to straighten up", "kjv": "lift (set) up, make straight."}, "G462": {"greek": "ἀνόσιος", "translit": "anósios", "pronunciation": "an-os'-ee-os", "derivation": "from (G1) (as a negative particle) and (G3741);", "definition": "wicked", "kjv": "unholy."}, "G463": {"greek": "ἀνοχή", "translit": "anochḗ", "pronunciation": "an-okh-ay'", "derivation": "from (G430);", "definition": "self-restraint, i.e. tolerance", "kjv": "forbearance."}, "G464": {"greek": "ἀνταγωνίζομαι", "translit": "antagōnízomai", "pronunciation": "an-tag-o-nid'-zom-ahee", "derivation": "from (G473) and (G75);", "definition": "to struggle against (figuratively) (\"antagonize\")", "kjv": "strive against."}, "G465": {"greek": "ἀντάλλαγμα", "translit": "antállagma", "pronunciation": "an-tal'-ag-mah", "derivation": "from a compound of (G473) and (G236);", "definition": "an equivalent or ransom", "kjv": "in exchange."}, "G466": {"greek": "ἀνταναπληρόω", "translit": "antanaplēróō", "pronunciation": "an-tan-ap-lay-ro'-o", "derivation": "from (G473) and (G378);", "definition": "to supplement", "kjv": "fill up."}, "G467": {"greek": "ἀνταποδίδωμι", "translit": "antapodídōmi", "pronunciation": "an-tap-od-ee'-do-mee", "derivation": "from (G473) and (G591);", "definition": "to requite (good or evil)", "kjv": "recompense, render, repay."}, "G468": {"greek": "ἀνταπόδομα", "translit": "antapódoma", "pronunciation": "an-tap-od'-om-ah", "derivation": "from (G467);", "definition": "a requital (properly, the thing)", "kjv": "recompense."}, "G469": {"greek": "ἀνταπόδοσις", "translit": "antapódosis", "pronunciation": "an-tap-od'-os-is", "derivation": "from (G467);", "definition": "requital (properly, the act)", "kjv": "reward."}, "G470": {"greek": "ἀνταποκρίνομαι", "translit": "antapokrínomai", "pronunciation": "an-tap-ok-ree'-nom-ahee", "derivation": "from (G473) and (G611);", "definition": "to contradict or dispute", "kjv": "answer again, reply against."}, "G472": {"greek": "ἀντέχομαι", "translit": "antéchomai", "pronunciation": "an-tekh'-om-ahee", "derivation": "from (G473) and the middle voice of (G2192);", "definition": "to hold oneself opposite to, i.e. (by implication) adhere to; by extension to care for", "kjv": "hold fast, hold to, support."}, "G473": {"greek": "ἀντί", "translit": "antí", "pronunciation": "an-tee'", "derivation": "a primary particle;", "definition": "opposite, i.e. instead or because of (rarely in addition to)", "kjv": "for, in the room of."}, "G474": {"greek": "ἀντιβάλλω", "translit": "antibállō", "pronunciation": "an-tee-bal'-lo", "derivation": "from (G473) and (G906);", "definition": "to bandy", "kjv": "have."}, "G475": {"greek": "ἀντιδιατίθεμαι", "translit": "antidiatíthemai", "pronunciation": "an-tee-dee-at-eeth'-em-ahee", "derivation": "from (G473) and (G1303);", "definition": "to set oneself opposite, i.e. be disputatious", "kjv": "that oppose themselves."}, "G476": {"greek": "ἀντίδικος", "translit": "antídikos", "pronunciation": "an-tid'-ee-kos", "derivation": "from (G473) and (G1349);", "definition": "an opponent (in a lawsuit); specially, Satan (as the arch-enemy)", "kjv": "adversary."}, "G477": {"greek": "ἀντίθεσις", "translit": "antíthesis", "pronunciation": "an-tith'-es-is", "derivation": "from a compound of (G473) and (G5087);", "definition": "opposition, i.e. a conflict (of theories)", "kjv": "opposition."}, "G478": {"greek": "ἀντικαθίστημι", "translit": "antikathístēmi", "pronunciation": "an-tee-kath-is'-tay-mee", "derivation": "from (G473) and (G2525);", "definition": "to set down (troops) against, i.e. withstand", "kjv": "resist."}, "G479": {"greek": "ἀντικαλέω", "translit": "antikaléō", "pronunciation": "an-tee-kal-eh'-o", "derivation": "from (G473) and (G2564);", "definition": "to invite in return", "kjv": "bid again."}, "G480": {"greek": "ἀντίκειμαι", "translit": "antíkeimai", "pronunciation": "an-tik'-i-mahee", "derivation": "from (G473) and (G2749);", "definition": "to lie opposite, i.e. be adverse (figuratively, repugnant) to", "kjv": "adversary, be contrary, oppose."}, "G481": {"greek": "ἀντικρύ", "translit": "antikrý", "pronunciation": "an-tee-kroo'", "derivation": "prolonged from (G473);", "definition": "opposite", "kjv": "over against."}, "G482": {"greek": "ἀντιλαμβάνομαι", "translit": "antilambánomai", "pronunciation": "an-tee-lam-ban'-om-ahee", "derivation": "from (G473) and the middle voice of (G2983);", "definition": "to take hold of in turn, i.e. succor; also to participate", "kjv": "help, partaker, support."}, "G483": {"greek": "ἀντιλέγω", "translit": "antilégō", "pronunciation": "an-til'-eg-o", "derivation": "from (G473) and (G3004);", "definition": "to dispute, refuse", "kjv": "answer again, contradict, deny, gainsay(-er), speak against."}, "G484": {"greek": "ἀντίληψις", "translit": "antílēpsis", "pronunciation": "an-til'-ape-sis", "derivation": "from (G482);", "definition": "relief", "kjv": "help."}, "G485": {"greek": "ἀντιλογία", "translit": "antilogía", "pronunciation": "an-tee-log-ee'-ah", "derivation": "from a derivative of (G483);", "definition": "dispute, disobedience", "kjv": "contradiction, gainsaying, strife."}, "G486": {"greek": "ἀντιλοιδορέω", "translit": "antiloidoréō", "pronunciation": "an-tee-loy-dor-eh'-o", "derivation": "from (G473) and (G3058);", "definition": "to rail in reply", "kjv": "revile again."}, "G487": {"greek": "ἀντίλυτρον", "translit": "antílytron", "pronunciation": "an-til'-oo-tron", "derivation": "from (G473) and (G3083);", "definition": "a redemption-price", "kjv": "ransom."}, "G488": {"greek": "ἀντιμετρέω", "translit": "antimetréō", "pronunciation": "an-tee-met-reh'-o", "derivation": "from (G473) and (G3354);", "definition": "to mete in return", "kjv": "measure again."}, "G489": {"greek": "ἀντιμισθία", "translit": "antimisthía", "pronunciation": "an-tee-mis-thee'-ah", "derivation": "from a compound of (G473) and (G3408);", "definition": "requital, correspondence", "kjv": "recompense."}, "G490": {"greek": "Ἀντιόχεια", "translit": "Antiócheia", "pronunciation": "an-tee-okh'-i-ah", "derivation": "from (a Syrian king);", "definition": "Antiochia, a place in Syria", "kjv": "Antioch."}, "G491": {"greek": "Ἀντιοχεύς", "translit": "Antiocheús", "pronunciation": "an-tee-okh-yoos'", "derivation": "from (G490);", "definition": "an Antiochian or inhabitant of Antiochia", "kjv": "of Antioch."}, "G492": {"greek": "ἀντιπαρέρχομαι", "translit": "antiparérchomai", "pronunciation": "an-tee-par-er'-khom-ahee", "derivation": "from (G473) and (G3928);", "definition": "to go along opposite", "kjv": "pass by on the other side."}, "G493": {"greek": "Ἀντίπας", "translit": "Antípas", "pronunciation": "an-tee'-pas", "derivation": "contracted for a compound of (G473) and a derivative of (G3962);", "definition": "Antipas, a Christian", "kjv": "Antipas."}, "G494": {"greek": "Ἀντιπατρίς", "translit": "Antipatrís", "pronunciation": "an-tip-at-rece'", "derivation": "from the same as (G493);", "definition": "Antipatris, a place in Palestine", "kjv": "Antipatris."}, "G495": {"greek": "ἀντιπέραν", "translit": "antipéran", "pronunciation": "an-tee-per'-an", "derivation": "from (G473) and (G4008);", "definition": "on the opposite side", "kjv": "over against."}, "G496": {"greek": "ἀντιπίπτω", "translit": "antipíptō", "pronunciation": "an-tee-pip'-to", "derivation": "from (G473) and (G4098) (including its alternate);", "definition": "to oppose", "kjv": "resist."}, "G497": {"greek": "ἀντιστρατεύομαι", "translit": "antistrateúomai", "pronunciation": "an-tee-strat-yoo'-om-ahee", "derivation": "from (G473) and (G4754);", "definition": "(figuratively) to attack, i.e. (by implication) destroy", "kjv": "war against."}, "G498": {"greek": "ἀντιτάσσομαι", "translit": "antitássomai", "pronunciation": "an-tee-tas'-som-ahee", "derivation": "from (G473) and the middle voice of (G5021);", "definition": "to range oneself against, i.e. oppose", "kjv": "oppose themselves, resist."}, "G499": {"greek": "ἀντίτυπον", "translit": "antítypon", "pronunciation": "an-teet'-oo-pon", "derivation": "neuter of a compound of (G473) and (G5179);", "definition": "corresponding (\"antitype\"), i.e. a representative, counterpart", "kjv": "(like) figure (whereunto)."}, "G500": {"greek": "ἀντίχριστος", "translit": "antíchristos", "pronunciation": "an-tee'-khris-tos", "derivation": "from (G473) and (G5547);", "definition": "an opponent of the Messiah", "kjv": "antichrist."}, "G501": {"greek": "ἀντλέω", "translit": "antléō", "pronunciation": "ant-leh-o", "derivation": "from (the hold of a ship);", "definition": "to bale up (properly, bilge water), i.e. dip water (with a bucket, pitcher, etc.)", "kjv": "draw (out)."}, "G502": {"greek": "ἄντλημα", "translit": "ántlēma", "pronunciation": "ant'-lay-mah", "derivation": "from (G501);", "definition": "a baling-vessel", "kjv": "thing to draw with."}, "G503": {"greek": "ἀντοφθαλμέω", "translit": "antophthalméō", "pronunciation": "ant-of-thal-meh'-o", "derivation": "from a compound of (G473) and (G3788);", "definition": "to face", "kjv": "bear up into."}, "G504": {"greek": "ἄνυδρος", "translit": "ánydros", "pronunciation": "an'-oo-dros", "derivation": "from (G1) (as a negative particle) and (G5204);", "definition": "waterless, i.e. dry", "kjv": "dry, without water."}, "G505": {"greek": "ἀνυπόκριτος", "translit": "anypókritos", "pronunciation": "an-oo-pok'-ree-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G5271);", "definition": "undissembled, i.e. sincere", "kjv": "without dissimulation (hypocrisy), unfeigned."}, "G506": {"greek": "ἀνυπότακτος", "translit": "anypótaktos", "pronunciation": "an-oo-pot'-ak-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G5293);", "definition": "unsubdued, i.e. insubordinate (in fact or temper)", "kjv": "disobedient, that is not put under, unruly."}, "G507": {"greek": "ἄνω", "translit": "ánō", "pronunciation": "an'-o", "derivation": "adverb from (G473);", "definition": "upward or on the top", "kjv": "above, brim, high, up."}, "G508": {"greek": "ἀνώγεον", "translit": "anṓgeon", "pronunciation": "an-ogue'-eh-on", "derivation": "from (G507) and (G1093);", "definition": "above the ground, i.e. (properly) the second floor of a building; used for a dome or a balcony on the upper story", "kjv": "upper room."}, "G509": {"greek": "ἄνωθεν", "translit": "ánōthen", "pronunciation": "an'-o-then", "derivation": "from (G507);", "definition": "from above; by analogy, from the first; by implication, anew", "kjv": "from above, again, from the beginning (very first), the top."}, "G510": {"greek": "ἀνωτερικός", "translit": "anōterikós", "pronunciation": "an-o-ter-ee-kos'", "derivation": "from (G511);", "definition": "superior, i.e. (locally) more remote", "kjv": "upper."}, "G511": {"greek": "ἀνώτερος", "translit": "anṓteros", "pronunciation": "an-o'-ter-os", "derivation": "comparative degree of (G507);", "definition": "upper, i.e. (neuter as adverb) to a more conspicuous place, in a former part of the book", "kjv": "above, higher."}, "G512": {"greek": "ἀνωφελής", "translit": "anōphelḗs", "pronunciation": "an-o-fel'-ace", "derivation": "from (G1) (as a negative particle) and the base of (G5624);", "definition": "useless or (neuter) inutility", "kjv": "unprofitable(-ness)."}, "G513": {"greek": "ἀξίνη", "translit": "axínē", "pronunciation": "ax-ee'-nay", "derivation": "probably from (to break;", "definition": "compare (G4486)); an axe", "kjv": "axe."}, "G514": {"greek": "ἄξιος", "translit": "áxios", "pronunciation": "ax'-ee-os", "derivation": "probably from (G71);", "definition": "deserving, comparable or suitable (as if drawing praise)", "kjv": "due reward, meet, (un-)worthy."}, "G515": {"greek": "ἀξιόω", "translit": "axióō", "pronunciation": "ax-ee-o'-o", "derivation": "from (G514);", "definition": "to deem entitled or fit", "kjv": "desire, think good, count (think) worthy."}, "G516": {"greek": "ἀξίως", "translit": "axíōs", "pronunciation": "ax-ee'-oce", "derivation": "adverb from (G514);", "definition": "appropriately", "kjv": "as becometh, after a godly sort, worthily(-thy)."}, "G517": {"greek": "ἀόρατος", "translit": "aóratos", "pronunciation": "ah-or'-at-os", "derivation": "from (G1) (as a negative particle) and (G3707);", "definition": "invisible", "kjv": "invisible (thing)."}, "G518": {"greek": "ἀπαγγέλλω", "translit": "apangéllō", "pronunciation": "ap-ang-el'-lo", "derivation": "from (G575) and the base of (G32);", "definition": "to announce", "kjv": "bring word (again), declare, report, shew (again), tell."}, "G519": {"greek": "ἀπάγχομαι", "translit": "apánchomai", "pronunciation": "ap-ang'-khom-ahee", "derivation": "from (G575) and (to choke; akin to the base of (G43));", "definition": "to strangle oneself off (i.e. to death)", "kjv": "hang himself."}, "G520": {"greek": "ἀπάγω", "translit": "apágō", "pronunciation": "ap-ag'-o", "derivation": "from (G575) and (G71);", "definition": "to take off (in various senses)", "kjv": "bring, carry away, lead (away), put to death, take away."}, "G521": {"greek": "ἀπαίδευτος", "translit": "apaídeutos", "pronunciation": "ap-ah'-ee-dyoo-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G3811);", "definition": "uninstructed, i.e. (figuratively) stupid", "kjv": "unlearned."}, "G522": {"greek": "ἀπαίρω", "translit": "apaírō", "pronunciation": "ap-ah'-ee-ro", "derivation": "from (G575) and (G142);", "definition": "to lift off, i.e. remove", "kjv": "take (away)."}, "G523": {"greek": "ἀπαιτέω", "translit": "apaitéō", "pronunciation": "ap-ah'-ee-teh-o", "derivation": "from (G575) and (G154);", "definition": "to demand back", "kjv": "ask again, require."}, "G524": {"greek": "ἀπαλγέω", "translit": "apalgéō", "pronunciation": "ap-alg-eh'-o", "derivation": "from (G575) and (to smart);", "definition": "to grieve out, i.e. become apathetic", "kjv": "be past feeling."}, "G525": {"greek": "ἀπαλλάσσω", "translit": "apallássō", "pronunciation": "ap-al-las'-so", "derivation": "from (G575) and (G236);", "definition": "to change away, i.e. release, (reflexively) remove", "kjv": "deliver, depart."}, "G526": {"greek": "ἀπαλλοτριόω", "translit": "apallotrióō", "pronunciation": "ap-al-lot-ree-o'-o", "derivation": "from (G575) and a derivative of (G245);", "definition": "to estrange away, i.e. (passively and figuratively) to be non-participant", "kjv": "alienate, be alien."}, "G527": {"greek": "ἀπαλός", "translit": "apalós", "pronunciation": "ap-al-os'", "derivation": "of uncertain derivation;", "definition": "soft", "kjv": "tender."}, "G528": {"greek": "ἀπαντάω", "translit": "apantáō", "pronunciation": "ap-an-tah'-o", "derivation": "from (G575) and a derivative of (G473);", "definition": "to meet away, i.e. encounter", "kjv": "meet."}, "G529": {"greek": "ἀπάντησις", "translit": "apántēsis", "pronunciation": "ap-an'-tay-sis", "derivation": "from (G528);", "definition": "a (friendly) encounter", "kjv": "meet."}, "G530": {"greek": "ἅπαξ", "translit": "hápax", "pronunciation": "hap'-ax", "derivation": "probably from (G537);", "definition": "one (or a single) time (numerically or conclusively)", "kjv": "once."}, "G531": {"greek": "ἀπαράβατος", "translit": "aparábatos", "pronunciation": "ap-ar-ab'-at-os", "derivation": "from (G1) (as a negative particle) and a derivative of (G3845);", "definition": "not passing away, i.e. untransferable (perpetual)", "kjv": "unchangeable."}, "G532": {"greek": "ἀπαρασκεύαστος", "translit": "aparaskeúastos", "pronunciation": "ap-ar-ask-yoo'-as-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G3903);", "definition": "unready", "kjv": "unprepared."}, "G533": {"greek": "ἀπαρνέομαι", "translit": "aparnéomai", "pronunciation": "ap-ar-neh'-om-ahee", "derivation": "from (G575) and (G720);", "definition": "to deny utterly, i.e. disown, abstain", "kjv": "deny."}, "G535": {"greek": "ἀπαρτισμός", "translit": "apartismós", "pronunciation": "ap-ar-tis-mos'", "derivation": "from a derivative of (G534);", "definition": "completion", "kjv": "finishing."}, "G536": {"greek": "ἀπαρχή", "translit": "aparchḗ", "pronunciation": "ap-ar-khay'", "derivation": "from a compound of (G575) and (G756);", "definition": "a beginning of sacrifice, i.e. the (Jewish) first-fruit (figuratively)", "kjv": "first-fruits."}, "G537": {"greek": "ἅπας", "translit": "hápas", "pronunciation": "hap'-as", "derivation": "from (G1) (as a particle of union) and (G3956);", "definition": "absolutely all or (singular) every one", "kjv": "all (things), every (one), whole."}, "G538": {"greek": "ἀπατάω", "translit": "apatáō", "pronunciation": "ap-at-ah'-o", "derivation": "of uncertain derivation;", "definition": "to cheat, i.e. delude", "kjv": "deceive."}, "G539": {"greek": "ἀπάτη", "translit": "apátē", "pronunciation": "ap-at'-ay", "derivation": "from (G538);", "definition": "delusion", "kjv": "deceit(-ful, -fulness), deceivableness(-ving)."}, "G540": {"greek": "ἀπάτωρ", "translit": "apátōr", "pronunciation": "ap-at'-ore", "derivation": "from (G1) (as a negative particle) and (G3962);", "definition": "fatherless, i.e. of unrecorded paternity", "kjv": "without father."}, "G541": {"greek": "ἀπαύγασμα", "translit": "apaúgasma", "pronunciation": "ap-ow'-gas-mah", "derivation": "from a compound of (G575) and (G826);", "definition": "an off-flash, i.e. effulgence", "kjv": "brightness."}, "G543": {"greek": "ἀπείθεια", "translit": "apeítheia", "pronunciation": "ap-i'-thi-ah", "derivation": "from (G545);", "definition": "disbelief (obstinate and rebellious)", "kjv": "disobedience, unbelief."}, "G544": {"greek": "ἀπειθέω", "translit": "apeithéō", "pronunciation": "ap-i-theh'-o", "derivation": "from (G545);", "definition": "to disbelieve (wilfully and perversely)", "kjv": "not believe, disobedient, obey not, unbelieving."}, "G545": {"greek": "ἀπειθής", "translit": "apeithḗs", "pronunciation": "ap-i-thace'", "derivation": "from (G1) (as a negative particle) and (G3982);", "definition": "unpersuadable, i.e. contumacious", "kjv": "disobedient."}, "G546": {"greek": "ἀπειλέω", "translit": "apeiléō", "pronunciation": "ap-i-leh'-o", "derivation": "of uncertain derivation;", "definition": "to menace; by implication, to forbid", "kjv": "threaten."}, "G547": {"greek": "ἀπειλή", "translit": "apeilḗ", "pronunciation": "ap-i-lay'", "derivation": "from (G546);", "definition": "a menace", "kjv": "X straitly, threatening."}, "G548": {"greek": "ἄπειμι", "translit": "ápeimi", "pronunciation": "ap'-i-mee", "derivation": "from (G575) and (G1510);", "definition": "to be away", "kjv": "be absent."}, "G550": {"greek": "ἀπειπόμην", "translit": "apeipómēn", "pronunciation": "ap-i-pom'-ane", "derivation": "reflexive past of a compound of (G575) and (G2036);", "definition": "to say off for oneself, i.e. disown", "kjv": "renounce."}, "G551": {"greek": "ἀπείραστος", "translit": "apeírastos", "pronunciation": "ap-i'-ras-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G3987);", "definition": "untried, i.e. not temptable", "kjv": "not to be tempted."}, "G552": {"greek": "ἄπειρος", "translit": "ápeiros", "pronunciation": "ap'-i-ros", "derivation": "from (G1) (as a negative particle) and (G3984);", "definition": "inexperienced, i.e. ignorant", "kjv": "unskilful."}, "G553": {"greek": "ἀπεκδέχομαι", "translit": "apekdéchomai", "pronunciation": "ap-ek-dekh'-om-ahee", "derivation": "from (G575) and (G1551);", "definition": "to expect fully", "kjv": "look (wait) for."}, "G554": {"greek": "ἀπεκδύομαι", "translit": "apekdýomai", "pronunciation": "ap-ek-doo'-om-ahee", "derivation": "middle voice from (G575) and (G1562);", "definition": "to divest wholly oneself, or (for oneself) despoil", "kjv": "put off, spoil."}, "G555": {"greek": "ἀπέκδυσις", "translit": "apékdysis", "pronunciation": "ap-ek'-doo-sis", "derivation": "from (G554);", "definition": "divestment", "kjv": "putting off."}, "G556": {"greek": "ἀπελαύνω", "translit": "apelaúnō", "pronunciation": "ap-el-ow'-no", "derivation": "from (G575) and (G1643);", "definition": "to dismiss", "kjv": "drive."}, "G557": {"greek": "ἀπελεγμός", "translit": "apelegmós", "pronunciation": "ap-el-eg-mos'", "derivation": "from a compound of (G575) and (G1651);", "definition": "refutation, i.e. (by implication) contempt", "kjv": "nought."}, "G558": {"greek": "ἀπελεύθερος", "translit": "apeleútheros", "pronunciation": "ap-el-yoo'-ther-os", "derivation": "from (G575) and (G1658);", "definition": "one freed away, i.e. a freedman", "kjv": "freeman."}, "G559": {"greek": "Ἀπελλῆς", "translit": "Apellēs", "pronunciation": "ap-el-lace'", "derivation": "of Latin origin;", "definition": "Apelles, a Christian", "kjv": "Apelles."}, "G560": {"greek": "ἀπελπίζω", "translit": "apelpízō", "pronunciation": "ap-el-pid'-zo", "derivation": "from (G575) and (G1679);", "definition": "to hope out, i.e. fully expect", "kjv": "hope for again."}, "G561": {"greek": "ἀπέναντι", "translit": "apénanti", "pronunciation": "ap-en'-an-tee", "derivation": "from (G575) and (G1725);", "definition": "from in front, i.e. opposite, before or against", "kjv": "before, contrary, over against, in the presence of."}, "G562": {"greek": "ἀπέραντος", "translit": "apérantos", "pronunciation": "ap-er'-an-tos", "derivation": "from (G1) (as a negative particle) and a secondary derivative of (G4008);", "definition": "unfinished, i.e. (by implication) interminable", "kjv": "endless."}, "G563": {"greek": "ἀπερισπάστως", "translit": "aperispástōs", "pronunciation": "ap-er-is-pas-toce'", "derivation": "adverb from a compound of (G1) (as a negative particle) and a presumed derivative of (G4049);", "definition": "undistractedly, i.e. free from (domestic) solicitude", "kjv": "without distraction."}, "G564": {"greek": "ἀπερίτμητος", "translit": "aperítmētos", "pronunciation": "ap-er-eet'-may-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G4059);", "definition": "uncircumcised (figuratively)", "kjv": "uncircumcised."}, "G565": {"greek": "ἀπέρχομαι", "translit": "apérchomai", "pronunciation": "ap-erkh'-om-ahee", "derivation": "from (G575) and (G2064);", "definition": "to go off (i.e. depart), aside (i.e. apart) or behind (i.e. follow), literally or figuratively", "kjv": "come, depart, go (aside, away, back, out, … ways), pass away, be past."}, "G568": {"greek": "ἀπέχω", "translit": "apéchō", "pronunciation": "ap-ekh'-o", "derivation": "from (G575) and (G2192);", "definition": "(actively) to have out, i.e. receive in full; (intransitively) to keep (oneself) away, i.e. be distant (literally or figuratively)", "kjv": "be, have, receive."}, "G569": {"greek": "ἀπιστέω", "translit": "apistéō", "pronunciation": "ap-is-teh'-o", "derivation": "from (G571);", "definition": "to be unbelieving, i.e. (transitively) disbelieve, or (by implication) disobey", "kjv": "believe not."}, "G570": {"greek": "ἀπιστία", "translit": "apistía", "pronunciation": "ap-is-tee'-ah", "derivation": "from (G571);", "definition": "faithlessness, i.e. (negatively) disbelief (lack of Christian faith), or (positively) unfaithfulness (disobedience)", "kjv": "unbelief."}, "G571": {"greek": "ἄπιστος", "translit": "ápistos", "pronunciation": "ap'-is-tos", "derivation": "from (G1) (as a negative particle) and (G4103);", "definition": "(actively) disbelieving, i.e. without Christian faith (specially, a heathen); (passively) untrustworthy (person), or incredible (thing)", "kjv": "that believeth not, faithless, incredible thing, infidel, unbeliever(-ing)."}, "G572": {"greek": "ἁπλότης", "translit": "haplótēs", "pronunciation": "hap-lot'-ace", "derivation": "from (G573);", "definition": "singleness, i.e. (subjectively) sincerity (without dissimulation or self-seeking), or (objectively) generosity (copious bestowal)", "kjv": "bountifulness, liberal(-ity), simplicity, singleness."}, "G573": {"greek": "ἁπλοῦς", "translit": "haploûs", "pronunciation": "hap-looce'", "derivation": "probably from (G1) (as a particle of union) and the base of (G4120);", "definition": "properly, folded together, i.e. single (figuratively, clear)", "kjv": "single."}, "G574": {"greek": "ἁπλῶς", "translit": "haplōs", "pronunciation": "hap-loce'", "derivation": "adverb from (G573) (in the objective sense of (G572));", "definition": "bountifully;", "kjv": "--liberally."}, "G575": {"greek": "ἀπό", "translit": "apó", "pronunciation": "apo'", "derivation": "a primary particle;", "definition": "\"off,\" i.e. away (from something near), in various senses (of place, time, or relation; literal or figurative)", "kjv": "(X here-)after, ago, at, because of, before, by (the space of), for(-th), from, in, (out) of, off, (up-)on(-ce), since, with."}, "G576": {"greek": "ἀποβαίνω", "translit": "apobaínō", "pronunciation": "ap-ob-ah'-ee-no", "derivation": "from (G575) and the base of (G939);", "definition": "literally, to disembark; figuratively, to eventuate", "kjv": "become, go out, turn."}, "G577": {"greek": "ἀποβάλλω", "translit": "apobállō", "pronunciation": "ap-ob-al'-lo", "derivation": "from (G575) and (G906);", "definition": "to throw off; figuratively, to lose", "kjv": "cast away."}, "G578": {"greek": "ἀποβλέπω", "translit": "apoblépō", "pronunciation": "ap-ob-lep'-o", "derivation": "from (G575) and (G991);", "definition": "to look away from everything else, i.e. (figuratively) intently regard", "kjv": "have respect."}, "G579": {"greek": "ἀπόβλητος", "translit": "apóblētos", "pronunciation": "ap-ob'-lay-tos", "derivation": "from (G577);", "definition": "cast off, i.e. (figuratively) such as to be rejected", "kjv": "be refused."}, "G580": {"greek": "ἀποβολή", "translit": "apobolḗ", "pronunciation": "ap-ob-ol-ay'", "derivation": "from (G577);", "definition": "rejection; figuratively, loss", "kjv": "casting away, loss."}, "G581": {"greek": "ἀπογενόμενος", "translit": "apogenómenos", "pronunciation": "ap-og-en-om'-en-os", "derivation": "past participle of a compound of (G575) and (G1096);", "definition": "absent, i.e. deceased (figuratively, renounced)", "kjv": "being dead."}, "G582": {"greek": "ἀπογραφή", "translit": "apographḗ", "pronunciation": "ap-og-raf-ay'", "derivation": "from (G583);", "definition": "an enrollment; by implication, an assessment", "kjv": "taxing."}, "G583": {"greek": "ἀπογράφω", "translit": "apográphō", "pronunciation": "ap-og-raf'-o", "derivation": "from (G575) and (G1125);", "definition": "to write off (a copy or list), i.e. enrol", "kjv": "tax, write."}, "G584": {"greek": "ἀποδείκνυμι", "translit": "apodeíknymi", "pronunciation": "ap-od-ike'-noo-mee", "derivation": "from (G575) and (G1166);", "definition": "to show off, i.e. exhibit; figuratively, to demonstrate, i.e. accredit", "kjv": "(ap-)prove, set forth, shew."}, "G585": {"greek": "ἀπόδειξις", "translit": "apódeixis", "pronunciation": "ap-od'-ike-sis", "derivation": "from (G584);", "definition": "manifestation", "kjv": "demonstration."}, "G586": {"greek": "ἀποδεκατόω", "translit": "apodekatóō", "pronunciation": "ap-od-ek-at-o'-o", "derivation": "from (G575) and (G1183);", "definition": "to tithe (as debtor or creditor)", "kjv": "(give, pay, take) tithe."}, "G587": {"greek": "ἀπόδεκτος", "translit": "apódektos", "pronunciation": "ap-od'-ek-tos", "derivation": "from (G588);", "definition": "accepted, i.e. agreeable", "kjv": "acceptable."}, "G588": {"greek": "ἀποδέχομαι", "translit": "apodéchomai", "pronunciation": "ap-od-ekh'-om-ahee", "derivation": "from (G575) and (G1209);", "definition": "to take fully, i.e. welcome (persons), approve (things)", "kjv": "accept, receive (gladly)."}, "G589": {"greek": "ἀποδημέω", "translit": "apodēméō", "pronunciation": "ap-od-ay-meh'-o", "derivation": "from (G590);", "definition": "to go abroad, i.e. visit a foreign land", "kjv": "go (travel) into a far country, journey."}, "G590": {"greek": "ἀπόδημος", "translit": "apódēmos", "pronunciation": "ap-od'-ay-mos", "derivation": "from (G575) and (G1218);", "definition": "absent from one's own people, i.e. a foreign traveller", "kjv": "taking a far journey."}, "G591": {"greek": "ἀποδίδωμι", "translit": "apodídōmi", "pronunciation": "ap-od-eed'-o-mee", "derivation": "from (G575) and (G1325);", "definition": "to give away, i.e. up, over, back, etc. (in various applications)", "kjv": "deliver (again), give (again), (re-)pay(-ment be made), perform, recompense, render, requite, restore, reward, sell, yield."}, "G592": {"greek": "ἀποδιορίζω", "translit": "apodiorízō", "pronunciation": "ap-od-ee-or-id'-zo", "derivation": "from (G575) and a compound of (G223) and (G3724);", "definition": "to disjoin (by a boundary, figuratively, a party)", "kjv": "separate."}, "G593": {"greek": "ἀποδοκιμάζω", "translit": "apodokimázō", "pronunciation": "ap-od-ok-ee-mad'-zo", "derivation": "from (G575) and (G1381);", "definition": "to disapprove, i.e. (by implication) to repudiate", "kjv": "disallow, reject."}, "G594": {"greek": "ἀποδοχή", "translit": "apodochḗ", "pronunciation": "ap-od-okh-ay'", "derivation": "from (G588);", "definition": "acceptance", "kjv": "acceptation."}, "G595": {"greek": "ἀπόθεσις", "translit": "apóthesis", "pronunciation": "ap-oth'-es-is", "derivation": "from (G659);", "definition": "a laying aside (literally or figuratively)", "kjv": "putting away (off)."}, "G596": {"greek": "ἀποθήκη", "translit": "apothḗkē", "pronunciation": "ap-oth-ay'-kay", "derivation": "from (G659);", "definition": "a repository, i.e. granary", "kjv": "barn, garner."}, "G597": {"greek": "ἀποθησαυρίζω", "translit": "apothēsaurízō", "pronunciation": "ap-oth-ay-sow-rid'-zo", "derivation": "from (G575) and (G2343);", "definition": "to treasure away", "kjv": "lay up in store."}, "G598": {"greek": "ἀποθλίβω", "translit": "apothlíbō", "pronunciation": "ap-oth-lee'-bo", "derivation": "from (G575) and (G2346);", "definition": "to crowd (from every side)", "kjv": "press."}, "G599": {"greek": "ἀποθνήσκω", "translit": "apothnḗskō", "pronunciation": "ap-oth-nace'-ko", "derivation": "from (G575) and (G2348);", "definition": "to die off (literally or figuratively)", "kjv": "be dead, death, die, lie a-dying, be slain (X with)."}, "G600": {"greek": "ἀποκαθίστημι", "translit": "apokathístēmi", "pronunciation": "ap-ok-ath-is'-tay-mee", "derivation": "from (G575) and (G2525);", "definition": "to reconstitute (in health, home or organization)", "kjv": "restore (again)."}, "G601": {"greek": "ἀποκαλύπτω", "translit": "apokalýptō", "pronunciation": "ap-ok-al-oop'-to", "derivation": "from (G575) and (G2572);", "definition": "to take off the cover, i.e. disclose", "kjv": "reveal."}, "G602": {"greek": "ἀποκάλυψις", "translit": "apokálypsis", "pronunciation": "ap-ok-al'-oop-sis", "derivation": "from (G601);", "definition": "disclosure", "kjv": "appearing, coming, lighten, manifestation, be revealed, revelation."}, "G603": {"greek": "ἀποκαραδοκία", "translit": "apokaradokía", "pronunciation": "ap-ok-ar-ad-ok-ee'-ah", "derivation": "from a compound of (G575) and a compound of (the head) and (G1380) (in the sense of watching);", "definition": "intense anticipation", "kjv": "earnest expectation."}, "G604": {"greek": "ἀποκαταλλάσσω", "translit": "apokatallássō", "pronunciation": "ap-ok-at-al-las'-so", "derivation": "from (G575) and (G2644);", "definition": "to reconcile fully", "kjv": "reconcile."}, "G605": {"greek": "ἀποκατάστασις", "translit": "apokatástasis", "pronunciation": "ap-ok-at-as'-tas-is", "derivation": "from (G600);", "definition": "reconstitution", "kjv": "restitution."}, "G606": {"greek": "ἀπόκειμαι", "translit": "apókeimai", "pronunciation": "ap-ok'-i-mahee", "derivation": "from (G575) and (G2749);", "definition": "to be reserved; figuratively, to await", "kjv": "be appointed, (be) laid up."}, "G607": {"greek": "ἀποκεφαλίζω", "translit": "apokephalízō", "pronunciation": "ap-ok-ef-al-id'-zo", "derivation": "from (G575) and (G2776);", "definition": "to decapitate", "kjv": "behead."}, "G608": {"greek": "ἀποκλείω", "translit": "apokleíō", "pronunciation": "ap-ok-li'-o", "derivation": "from (G575) and (G2808);", "definition": "to close fully", "kjv": "shut up."}, "G609": {"greek": "ἀποκόπτω", "translit": "apokóptō", "pronunciation": "ap-ok-op'-to", "derivation": "from (G575) and (G2875);", "definition": "to amputate; reflexively (by irony) to mutilate (the privy parts)", "kjv": "cut off."}, "G610": {"greek": "ἀπόκριμα", "translit": "apókrima", "pronunciation": "ap-ok'-ree-mah", "derivation": "from (G611) (in its original sense of judging);", "definition": "a judicial decision", "kjv": "sentence."}, "G611": {"greek": "ἀποκρίνομαι", "translit": "apokrínomai", "pronunciation": "ap-ok-ree'-nom-ahee", "derivation": "from (G575) and ;", "definition": "to conclude for oneself, i.e. (by implication) to respond; by Hebraism (compare (G6030)) to begin to speak (where an address is expected)", "kjv": "answer."}, "G612": {"greek": "ἀπόκρισις", "translit": "apókrisis", "pronunciation": "ap-ok'-ree-sis", "derivation": "from (G611);", "definition": "a response", "kjv": "answer."}, "G613": {"greek": "ἀποκρύπτω", "translit": "apokrýptō", "pronunciation": "ap-ok-roop'-to", "derivation": "from (G575) and (G2928);", "definition": "to conceal away (i.e. fully); figuratively, to keep secret", "kjv": "hide."}, "G614": {"greek": "ἀπόκρυφος", "translit": "apókryphos", "pronunciation": "ap-ok'-roo-fos", "derivation": "from (G613);", "definition": "secret; by implication, treasured", "kjv": "hid, kept secret."}, "G615": {"greek": "ἀποκτείνω", "translit": "apokteínō", "pronunciation": "ap-ok-ti'-no", "derivation": "from (G575) and (to slay);", "definition": "to kill outright; figuratively, to destroy", "kjv": "put to death, kill, slay."}, "G616": {"greek": "ἀποκυέω", "translit": "apokyéō", "pronunciation": "ap-ok-oo-eh'-o", "derivation": "from (G575) and the base of (G2949);", "definition": "to breed forth, i.e. (by transference) to generate (figuratively)", "kjv": "beget, produce."}, "G617": {"greek": "ἀποκυλίω", "translit": "apokylíō", "pronunciation": "ap-ok-oo-lee'-o", "derivation": "from (G575) and (G2947);", "definition": "to roll away", "kjv": "roll away (back)."}, "G618": {"greek": "ἀπολαμβάνω", "translit": "apolambánō", "pronunciation": "ap-ol-am-ban'-o", "derivation": "from (G575) and (G2983);", "definition": "to receive (specially, in full, or as a host); also to take aside", "kjv": "receive, take."}, "G619": {"greek": "ἀπόλαυσις", "translit": "apólausis", "pronunciation": "ap-ol'-ow-sis", "derivation": "from a comparative of (G575) and (to enjoy);", "definition": "full enjoyment", "kjv": "enjoy(-ment)."}, "G620": {"greek": "ἀπολείπω", "translit": "apoleípō", "pronunciation": "ap-ol-ipe'-o", "derivation": "from (G575) and (G3007);", "definition": "to leave behind (passively, remain); by implication, to forsake", "kjv": "leave, remain."}, "G621": {"greek": "ἀπολείχω", "translit": "apoleíchō", "pronunciation": "ap-ol-i'-kho", "derivation": "from (G575) and (to \"lick\");", "definition": "to lick clean", "kjv": "lick."}, "G622": {"greek": "ἀπόλλυμι", "translit": "apóllymi", "pronunciation": "ap-ol'-loo-mee", "derivation": "from (G575) and the base of (G3639);", "definition": "to destroy fully (reflexively, to perish, or lose), literally or figuratively", "kjv": "destroy, die, lose, mar, perish."}, "G623": {"greek": "Ἀπολλύων", "translit": "Apollýōn", "pronunciation": "ap-ol-loo'-ohn", "derivation": "active participle of (G622);", "definition": "a destroyer (i.e. Satan)", "kjv": "Apollyon."}, "G624": {"greek": "Ἀπολλωνία", "translit": "Apollōnía", "pronunciation": "ap-ol-lo-nee'-ah", "derivation": "from the pagan deity (i.e. the sun; from (G622));", "definition": "Apollonia, a place in Macedonia", "kjv": "Apollonia."}, "G625": {"greek": "Ἀπολλῶς", "translit": "Apollōs", "pronunciation": "ap-ol-loce'", "derivation": "probably from the same as (G624);", "definition": "Apollos, an Israelite", "kjv": "Apollos."}, "G626": {"greek": "ἀπολογέομαι", "translit": "apologéomai", "pronunciation": "ap-ol-og-eh'-om-ahee", "derivation": "middle voice from a compound of (G575) and (G3056);", "definition": "to give an account (legal plea) of oneself, i.e. exculpate (self)", "kjv": "answer (for self), make defence, excuse (self), speak for self."}, "G627": {"greek": "ἀπολογία", "translit": "apología", "pronunciation": "ap-ol-og-ee'-ah", "derivation": "from the same as (G626);", "definition": "a plea (\"apology\")", "kjv": "answer (for self), clearing of self, defence."}, "G628": {"greek": "ἀπολούω", "translit": "apoloúō", "pronunciation": "ap-ol-oo'-o", "derivation": "from (G575) and (G3068);", "definition": "to wash fully, i.e. (figuratively) have remitted (reflexively)", "kjv": "wash (away)."}, "G629": {"greek": "ἀπολύτρωσις", "translit": "apolýtrōsis", "pronunciation": "ap-ol-oo'-tro-sis", "derivation": "from a compound of (G575) and (G3083);", "definition": "(the act) ransom in full, i.e. (figuratively) riddance, or (specially) Christian salvation", "kjv": "deliverance, redemption."}, "G630": {"greek": "ἀπολύω", "translit": "apolýō", "pronunciation": "ap-ol-oo'-o", "derivation": "from (G575) and (G3089);", "definition": "to free fully, i.e. (literally) relieve, release, dismiss (reflexively, depart), or (figuratively) let die, pardon or (specially) divorce", "kjv": "(let) depart, dismiss, divorce, forgive, let go, loose, put (send) away, release, set at liberty."}, "G631": {"greek": "ἀπομάσσομαι", "translit": "apomássomai", "pronunciation": "ap-om-as'-som-ahee", "derivation": "middle voice from (G575) and (to squeeze, knead, smear);", "definition": "to scrape away", "kjv": "wipe off."}, "G632": {"greek": "ἀπονέμω", "translit": "aponémō", "pronunciation": "ap-on-em'-o", "derivation": "from (G575) and the base of (G3551);", "definition": "to apportion, i.e. bestow", "kjv": "give."}, "G633": {"greek": "ἀπονίπτω", "translit": "aponíptō", "pronunciation": "ap-on-ip'-to", "derivation": "from (G575) and (G3538);", "definition": "to wash off (reflexively, one's own hands symbolically)", "kjv": "wash."}, "G634": {"greek": "ἀποπίπτω", "translit": "apopíptō", "pronunciation": "ap-op-ip'-to", "derivation": "from (G575) and (G4098);", "definition": "to fall off", "kjv": "fall."}, "G635": {"greek": "ἀποπλανάω", "translit": "apoplanáō", "pronunciation": "ap-op-lan-ah'-o", "derivation": "from (G575) and (G4105);", "definition": "to lead astray (figuratively); passively, to stray (from truth)", "kjv": "err, seduce."}, "G636": {"greek": "ἀποπλέω", "translit": "apopléō", "pronunciation": "ap-op-leh'-o", "derivation": "from (G575) and (G4126);", "definition": "to set sail", "kjv": "sail away."}, "G638": {"greek": "ἀποπνίγω", "translit": "apopnígō", "pronunciation": "ap-op-nee'-go", "derivation": "from (G575) and (G4155);", "definition": "to stifle (by drowning or overgrowth)", "kjv": "choke."}, "G639": {"greek": "ἀπορέω", "translit": "aporéō", "pronunciation": "ap-or-eh'-o", "derivation": "from a compound of (G1) (as a negative particle) and the base of (G4198);", "definition": "to have no way out, i.e. be at a loss (mentally)", "kjv": "(stand in) doubt, be perplexed."}, "G640": {"greek": "ἀπορία", "translit": "aporía", "pronunciation": "ap-or-ee'-a", "derivation": "from the same as (G639);", "definition": "a (state of) quandary", "kjv": "perplexity."}, "G641": {"greek": "ἀποῤῥίπτω", "translit": "aporrhíptō", "pronunciation": "ap-or-hrip'-to", "derivation": "from (G575) and (G4496);", "definition": "to hurl off, i.e. precipitate (oneself)", "kjv": "cast."}, "G642": {"greek": "ἀπορφανίζω", "translit": "aporphanízō", "pronunciation": "ap-or-fan-id'-zo", "derivation": "from (G575) and a derivative of (G3737);", "definition": "to bereave wholly, i.e. (figuratively) separate (from intercourse)", "kjv": "take."}, "G643": {"greek": "ἀποσκευάζω", "translit": "aposkeuázō", "pronunciation": "ap-osk-yoo-ad'-zo", "derivation": "from (G575) and a derivative of (G4632);", "definition": "to pack up (one's) baggage", "kjv": "take up… carriages."}, "G644": {"greek": "ἀποσκίασμα", "translit": "aposkíasma", "pronunciation": "ap-os-kee'-as-mah", "derivation": "from a compound of (G575) and a derivative of (G4639);", "definition": "a shading off, i.e. obscuration", "kjv": "shadow."}, "G645": {"greek": "ἀποσπάω", "translit": "apospáō", "pronunciation": "ap-os-pah'-o", "derivation": "from (G575) and (G4685);", "definition": "to drag forth, i.e. (literally) unsheathe (a sword), or relatively (with a degree of force implied) retire (personally or factiously)", "kjv": "(with-)draw (away), after we were gotten from."}, "G646": {"greek": "ἀποστασία", "translit": "apostasía", "pronunciation": "ap-os-tas-ee'-ah", "derivation": "feminine of the same as (G647);", "definition": "defection from truth (properly, the state) (\"apostasy\")", "kjv": "falling away, forsake."}, "G647": {"greek": "ἀποστάσιον", "translit": "apostásion", "pronunciation": "ap-os-tas'-ee-on", "derivation": "neuter of a (presumed) adjective from a derivative of (G868);", "definition": "properly, something separative, i.e. (specially) divorce", "kjv": "(writing of) divorcement."}, "G648": {"greek": "ἀποστεγάζω", "translit": "apostegázō", "pronunciation": "ap-os-teg-ad'-zo", "derivation": "from (G575) and a derivative of (G4721);", "definition": "to unroof", "kjv": "uncover."}, "G649": {"greek": "ἀποστέλλω", "translit": "apostéllō", "pronunciation": "ap-os-tel'-lo", "derivation": "from (G575) and (G4724);", "definition": "set apart, i.e. (by implication) to send out (properly, on a mission) literally or figuratively", "kjv": "put in, send (away, forth, out), set (at liberty)."}, "G650": {"greek": "ἀποστερέω", "translit": "aposteréō", "pronunciation": "ap-os-ter-eh'-o", "derivation": "from (G575) and (to deprive);", "definition": "to despoil", "kjv": "defraud, destitute, kept back by fraud."}, "G651": {"greek": "ἀποστολή", "translit": "apostolḗ", "pronunciation": "ap-os-tol-ay'", "derivation": "from (G649);", "definition": "commission, i.e. (specially) apostolate", "kjv": "apostleship."}, "G652": {"greek": "ἀπόστολος", "translit": "apóstolos", "pronunciation": "ap-os'-tol-os", "derivation": "from (G649);", "definition": "a delegate; specially, an ambassador of the Gospel; officially a commissioner of Christ (\"apostle\") (with miraculous powers)", "kjv": "apostle, messenger, he that is sent."}, "G653": {"greek": "ἀποστοματίζω", "translit": "apostomatízō", "pronunciation": "ap-os-tom-at-id'-zo", "derivation": "from (G575) and a (presumed) derivative of (G4750);", "definition": "to speak off-hand (properly, dictate), i.e. to catechize (in an invidious manner)", "kjv": "provoke to speak."}, "G654": {"greek": "ἀποστρέφω", "translit": "apostréphō", "pronunciation": "ap-os-tref'-o", "derivation": "from (G575) and (G4762);", "definition": "to turn away or back (literally or figuratively)", "kjv": "bring again, pervert, turn away (from)."}, "G655": {"greek": "ἀποστυγέω", "translit": "apostygéō", "pronunciation": "ap-os-toog-eh'-o", "derivation": "from (G575) and the base of (G4767);", "definition": "to detest utterly", "kjv": "abhor."}, "G656": {"greek": "ἀποσυνάγωγος", "translit": "aposynágōgos", "pronunciation": "ap-os-oon-ag'-o-gos", "derivation": "from (G575) and (G4864);", "definition": "excommunicated", "kjv": "(put) out of the synagogue(-s)."}, "G657": {"greek": "ἀποτάσσομαι", "translit": "apotássomai", "pronunciation": "ap-ot-as'-som-ahee", "derivation": "middle voice from (G575) and (G5021);", "definition": "literally, to say adieu (by departing or dismissing); figuratively, to renounce", "kjv": "bid farewell, forsake, take leave, send away."}, "G658": {"greek": "ἀποτελέω", "translit": "apoteléō", "pronunciation": "ap-ot-el-eh'-o", "derivation": "from (G575) and (G5055);", "definition": "to complete entirely, i.e. consummate", "kjv": "finish."}, "G659": {"greek": "ἀποτίθημι", "translit": "apotíthēmi", "pronunciation": "ap-ot-eeth'-ay-mee", "derivation": "from (G575) and (G5087);", "definition": "to put away (literally or figuratively)", "kjv": "cast off, lay apart (aside, down), put away (off)."}, "G660": {"greek": "ἀποτινάσσω", "translit": "apotinássō", "pronunciation": "ap-ot-in-as'-so", "derivation": "from (G575) and (to jostle);", "definition": "to brush off", "kjv": "shake off."}, "G661": {"greek": "ἀποτίνω", "translit": "apotínō", "pronunciation": "ap-ot-ee'-no", "derivation": "from (G575) and (G5099);", "definition": "to pay in full", "kjv": "repay."}, "G662": {"greek": "ἀποτολμάω", "translit": "apotolmáō", "pronunciation": "ap-ot-ol-mah'-o", "derivation": "from (G575) and (G5111);", "definition": "to venture plainly", "kjv": "be very bold."}, "G663": {"greek": "ἀποτομία", "translit": "apotomía", "pronunciation": "ap-ot-om-ee'-ah", "derivation": "from the base of (G664);", "definition": "(figuratively) decisiveness, i.e. rigor", "kjv": "severity."}, "G664": {"greek": "ἀποτόμως", "translit": "apotómōs", "pronunciation": "ap-ot-om'-oce", "derivation": "adverb from a derivative of a comparative of (G575) and (to cut);", "definition": "abruptly, i.e. peremptorily", "kjv": "sharply(-ness)."}, "G665": {"greek": "ἀποτρέπω", "translit": "apotrépō", "pronunciation": "ap-ot-rep'-o", "derivation": "from (G575) and the base of (G5157);", "definition": "to deflect, i.e. (reflexively) avoid", "kjv": "turn away."}, "G666": {"greek": "ἀπουσία", "translit": "apousía", "pronunciation": "ap-oo-see'-ah", "derivation": "from the participle of (G548);", "definition": "a being away", "kjv": "absence."}, "G667": {"greek": "ἀποφέρω", "translit": "apophérō", "pronunciation": "ap-of-er'-o", "derivation": "from (G575) and (G5342);", "definition": "to bear off (literally or relatively)", "kjv": "bring, carry (away)."}, "G668": {"greek": "ἀποφεύγω", "translit": "apopheúgō", "pronunciation": "ap-of-yoo'-go", "derivation": "from (G575) and (G5343);", "definition": "(figuratively) to escape", "kjv": "escape."}, "G669": {"greek": "ἀποφθέγγομαι", "translit": "apophthéngomai", "pronunciation": "ap-of-theng'-om-ahee", "derivation": "from (G575) and (G5350);", "definition": "to enunciate plainly, i.e. declare", "kjv": "say, speak forth, utterance."}, "G670": {"greek": "ἀποφορτίζομαι", "translit": "apophortízomai", "pronunciation": "ap-of-or-tid'-zom-ahee", "derivation": "from (G575) and the middle voice of (G5412);", "definition": "to unload", "kjv": "unlade."}, "G671": {"greek": "ἀπόχρησις", "translit": "apóchrēsis", "pronunciation": "ap-okh'-ray-sis", "derivation": "from a compound of (G575) and (G5530);", "definition": "the act of using up, i.e. consumption", "kjv": "using."}, "G672": {"greek": "ἀποχωρέω", "translit": "apochōréō", "pronunciation": "ap-okh-o-reh'-o", "derivation": "from (G575) and (G5562);", "definition": "to go away", "kjv": "depart."}, "G673": {"greek": "ἀποχωρίζω", "translit": "apochōrízō", "pronunciation": "ap-okh-o-rid'-zo", "derivation": "from (G575) and (G5563);", "definition": "to rend apart; reflexively, to separate", "kjv": "depart (asunder)."}, "G674": {"greek": "ἀποψύχω", "translit": "apopsýchō", "pronunciation": "ap-ops-oo'-kho", "derivation": "from (G575) and (G5594);", "definition": "to breathe out, i.e. faint", "kjv": "hearts failing."}, "G675": {"greek": "Ἄππιος", "translit": "Áppios", "pronunciation": "ap'-pee-os", "derivation": "of Latin origin;", "definition": "(in the genitive, i.e. possessive case) of Appius, the name of a Roman", "kjv": "Appii."}, "G676": {"greek": "ἀπρόσιτος", "translit": "aprósitos", "pronunciation": "ap-ros'-ee-tos", "derivation": "from (G1) (as a negative particle) and a derivative of a comparative of (G4314) and (to go);", "definition": "inaccessible", "kjv": "which no man can approach."}, "G677": {"greek": "ἀπρόσκοπος", "translit": "apróskopos", "pronunciation": "ap-ros'-kop-os", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G4350);", "definition": "actively, inoffensive, i.e. not leading into sin; passively, faultless, i.e. not led into sin", "kjv": "none (void of, without) offence."}, "G678": {"greek": "ἀπροσωπολήπτως", "translit": "aprosōpolḗptōs", "pronunciation": "ap-ros-o-pol-ape'-tos", "derivation": "adverb from a compound of (G1) (as a negative particle) and a presumed derivative of a presumed compound of (G4383) and (G2983) (compare (G4381));", "definition": "in a way not accepting the person, i.e. impartially", "kjv": "without respect of persons."}, "G679": {"greek": "ἄπταιστος", "translit": "áptaistos", "pronunciation": "ap-tah'-ee-stos", "derivation": "from (G1) (as a negative particle) and a derivative of (G4417);", "definition": "not stumbling, i.e. (figuratively) without sin", "kjv": "from falling."}, "G680": {"greek": "ἅπτομαι", "translit": "háptomai", "pronunciation": "hap'-tom-ahee", "derivation": "reflexive of (G681);", "definition": "properly, to attach oneself to, i.e. to touch (in many implied relations)", "kjv": "touch."}, "G681": {"greek": "ἅπτω", "translit": "háptō", "pronunciation": "hap'-to", "derivation": "a primary verb;", "definition": "properly, to fasten to, i.e. (specially) to set on fire", "kjv": "kindle, light."}, "G682": {"greek": "Ἀπφία", "translit": "Apphía", "pronunciation": "ap-fee'-a", "derivation": "probably of foreign origin;", "definition": "Apphia, a woman of Collosæ", "kjv": "Apphia."}, "G683": {"greek": "ἀπωθέομαι", "translit": "apōthéomai", "pronunciation": "ap-o-theh'-om-ahee", "derivation": "from (G575) and the middle voice of or (to shove);", "definition": "to push off, figuratively, to reject", "kjv": "cast away, put away (from), thrust away (from)."}, "G684": {"greek": "ἀπώλεια", "translit": "apṓleia", "pronunciation": "ap-o'-li-a", "derivation": "from a presumed derivative of (G622);", "definition": "ruin or loss (physical, spiritual or eternal)", "kjv": "damnable(-nation), destruction, die, perdition, X perish, pernicious ways, waste."}, "G685": {"greek": "ἀρά", "translit": "ará", "pronunciation": "ar-ah'", "derivation": "probably from (G142);", "definition": "properly, prayer (as lifted to Heaven), i.e. (by implication) imprecation", "kjv": "curse."}, "G686": {"greek": "ἄρα", "translit": "ára", "pronunciation": "ar'-ah", "derivation": "probably from (G142) (through the idea of drawing a conclusion);", "definition": "a particle denoting an inference more or less decisive (as follows)", "kjv": "haply, (what) manner (of man), no doubt, perhaps, so be, then, therefore, truly, wherefore."}, "G688": {"greek": "Ἀραβία", "translit": "Arabía", "pronunciation": "ar-ab-ee'-ah", "derivation": "of Hebrew origin ((G6152));", "definition": "Arabia, a region of Asia", "kjv": "Arabia."}, "G689": {"greek": "Ἀράμ", "translit": "Arám", "pronunciation": "ar-am'", "derivation": "of Hebrew origin ((G7410));", "definition": "Aram (i.e. Ram), an Israelite", "kjv": "Aram."}, "G690": {"greek": "Ἄραψ", "translit": "Áraps", "pronunciation": "ar'-aps", "derivation": "from (G688);", "definition": "an Arab or native of Arabia", "kjv": "Arabian."}, "G691": {"greek": "ἀργέω", "translit": "argéō", "pronunciation": "arg-eh'-o", "derivation": "from (G692);", "definition": "to be idle, i.e. (figuratively) to delay", "kjv": "linger."}, "G692": {"greek": "ἀργός", "translit": "argós", "pronunciation": "ar-gos'", "derivation": "from (G1) (as a negative particle) and (G2041);", "definition": "inactive, i.e. unemployed; (by implication) lazy, useless", "kjv": "barren, idle, slow."}, "G693": {"greek": "ἀργύρεος", "translit": "argýreos", "pronunciation": "ar-goo'-reh-os", "derivation": "from (G696);", "definition": "made of silver", "kjv": "(of) silver."}, "G694": {"greek": "ἀργύριον", "translit": "argýrion", "pronunciation": "ar-goo'-ree-on", "derivation": "neuter of a presumed derivative of (G696);", "definition": "silvery, i.e. (by implication) cash; specially, a silverling (i.e. drachma or shekel)", "kjv": "money, (piece of) silver (piece)."}, "G695": {"greek": "ἀργυροκόπος", "translit": "argyrokópos", "pronunciation": "ar-goo-rok-op'-os", "derivation": "from (G696) and (G2875);", "definition": "a beater (i.e. worker) of silver", "kjv": "silversmith."}, "G696": {"greek": "ἄργυρος", "translit": "árgyros", "pronunciation": "ar'-goo-ros", "derivation": "from (shining);", "definition": "silver (the metal, in the articles or coin)", "kjv": "silver."}, "G697": {"greek": "Ἄρειος Πάγος", "translit": "Áreios Págos", "pronunciation": "ar'-i-os pag'-os", "derivation": "from (the name of the Greek deity of war) and a derivative of (G4078);", "definition": "rock of Ares, a place in Athens", "kjv": "Areopagus, Mars' Hill."}, "G698": {"greek": "Ἀρεοπαγίτης", "translit": "Areopagítēs", "pronunciation": "ar-eh-op-ag-ee'-tace", "derivation": "from (G697);", "definition": "an Areopagite or member of the court held on Mars' Hill", "kjv": "Areopagite."}, "G699": {"greek": "ἀρεσκεία", "translit": "areskeía", "pronunciation": "ar-es'-ki-ah", "derivation": "from a derivative of (G700);", "definition": "complaisance", "kjv": "pleasing."}, "G700": {"greek": "ἀρέσκω", "translit": "aréskō", "pronunciation": "ar-es'-ko", "derivation": "probably from (G142) (through the idea of exciting emotion);", "definition": "to be agreeable (or by implication, to seek to be so)", "kjv": "please."}, "G701": {"greek": "ἀρεστός", "translit": "arestós", "pronunciation": "ar-es-tos'", "derivation": "from (G700);", "definition": "agreeable; by implication, fit", "kjv": "(things that) please(-ing), reason."}, "G702": {"greek": "Ἀρέτας", "translit": "Arétas", "pronunciation": "ar-et'-as", "derivation": "of foreign origin;", "definition": "Aretas, an Arabian", "kjv": "Aretas."}, "G703": {"greek": "ἀρέτη", "translit": "arétē", "pronunciation": "ar-et'-ay", "derivation": "from the same as (G730);", "definition": "properly, manliness (valor), i.e. excellence (intrinsic or attributed)", "kjv": "praise, virtue."}, "G704": {"greek": "ἀρήν", "translit": "arḗn", "pronunciation": "ar-ane'", "derivation": "perhaps the same as (G730);", "definition": "a lamb (as a male)", "kjv": "lamb."}, "G705": {"greek": "ἀριθμέω", "translit": "arithméō", "pronunciation": "ar-ith-meh'-o", "derivation": "from (G706);", "definition": "to enumerate or count", "kjv": "number."}, "G706": {"greek": "ἀριθμός", "translit": "arithmós", "pronunciation": "ar-ith-mos'", "derivation": "from (G142);", "definition": "a number (as reckoned up)", "kjv": "number."}, "G707": {"greek": "Ἀριμαθαία", "translit": "Arimathaía", "pronunciation": "ar-ee-math-ah'-ee-ah", "derivation": "of Hebrew origin ((G7414));", "definition": "Arimathæa (or Ramah), a place in Palestine", "kjv": "Arimathæa."}, "G708": {"greek": "Ἀρίσταρχος", "translit": "Arístarchos", "pronunciation": "ar-is'-tar-khos", "derivation": "from the same as (G712) and (G757);", "definition": "best ruling; Aristarchus, a Macedonian", "kjv": "Aristarchus."}, "G709": {"greek": "ἀριστάω", "translit": "aristáō", "pronunciation": "ar-is-tah'-o", "derivation": "from (G712);", "definition": "to take the principle meal", "kjv": "dine."}, "G710": {"greek": "ἀριστερός", "translit": "aristerós", "pronunciation": "ar-is-ter-os'", "derivation": "apparently a comparative of the same as (G712);", "definition": "the left hand (as second-best)", "kjv": "left (hand)."}, "G711": {"greek": "Ἀριστόβουλος", "translit": "Aristóboulos", "pronunciation": "ar-is-tob'-oo-los", "derivation": "from the same as (G712) and (G1012);", "definition": "best counselling; Aristoboulus, a Christian", "kjv": "Aristobulus."}, "G712": {"greek": "ἄριστον", "translit": "áriston", "pronunciation": "ar'-is-ton", "derivation": "apparently neuter of a superlative from the same as (G730);", "definition": "the best meal (or breakfast; perhaps from (\"early\")), i.e. luncheon", "kjv": "dinner."}, "G713": {"greek": "ἀρκετός", "translit": "arketós", "pronunciation": "ar-ket-os'", "derivation": "from (G714);", "definition": "satisfactory", "kjv": "enough, suffice (-ient)."}, "G714": {"greek": "ἀρκέω", "translit": "arkéō", "pronunciation": "ar-keh'-o", "derivation": "apparently a primary verb (but probably akin to (G142) through the idea of raising a barrier);", "definition": "properly, to ward off, i.e. (by implication) to avail (figuratively, be satisfactory)", "kjv": "be content, be enough, suffice, be sufficient."}, "G715": {"greek": "ἄρκτος", "translit": "árktos", "pronunciation": "ark'-tos", "derivation": "probably from (G714);", "definition": "a bear (as obstructing by ferocity)", "kjv": "bear."}, "G716": {"greek": "ἅρμα", "translit": "hárma", "pronunciation": "har'-mah", "derivation": "probably from (G142) (perhaps with (G1) (as a particle of union) prefixed);", "definition": "a chariot (as raised or fitted together (compare (G719)))", "kjv": "chariot."}, "G717": {"greek": "Ἀρμαγεδδών", "translit": "Armageddṓn", "pronunciation": "ar-mag-ed-dohn'", "derivation": "of Hebrew origin ((G2022) and (G4023));", "definition": "Armageddon (or Har-Meggiddon), a symbolic name", "kjv": "Armageddon."}, "G718": {"greek": "ἁρμόζω", "translit": "harmózō", "pronunciation": "har-mod'-zo", "derivation": "from (G719);", "definition": "to joint, i.e. (figuratively) to woo (reflexively, to betroth)", "kjv": "espouse."}, "G719": {"greek": "ἁρμός", "translit": "harmós", "pronunciation": "har-mos'", "derivation": "from the same as (G716);", "definition": "an articulation (of the body)", "kjv": "joint."}, "G720": {"greek": "ἀρνέομαι", "translit": "arnéomai", "pronunciation": "ar-neh'-om-ahee", "derivation": "perhaps from (G1) (as a negative particle) and the middle voice of (G4483);", "definition": "to contradict, i.e. disavow, reject, abnegate", "kjv": "deny, refuse."}, "G721": {"greek": "ἀρνίον", "translit": "arníon", "pronunciation": "ar-nee'-on", "derivation": "diminutive from (G704);", "definition": "a lambkin", "kjv": "lamb."}, "G722": {"greek": "ἀροτριόω", "translit": "arotrióō", "pronunciation": "ar-ot-ree-o'-o", "derivation": "from (G723);", "definition": "to plow", "kjv": "plough."}, "G723": {"greek": "ἄροτρον", "translit": "árotron", "pronunciation": "ar'-ot-ron", "derivation": "from (to till);", "definition": "a plow", "kjv": "plough."}, "G724": {"greek": "ἁρπαγή", "translit": "harpagḗ", "pronunciation": "har-pag-ay'", "derivation": "from (G726);", "definition": "pillage (properly abstract)", "kjv": "extortion, ravening, spoiling."}, "G725": {"greek": "ἁρπαγμός", "translit": "harpagmós", "pronunciation": "har-pag-mos'", "derivation": "from (G726);", "definition": "plunder (properly concrete)", "kjv": "robbery."}, "G726": {"greek": "ἁρπάζω", "translit": "harpázō", "pronunciation": "har-pad'-zo", "derivation": "from a derivative of (G138);", "definition": "to seize (in various applications)", "kjv": "catch (away, up), pluck, pull, take (by force)."}, "G727": {"greek": "ἅρπαξ", "translit": "hárpax", "pronunciation": "har'-pax", "derivation": "from (G726);", "definition": "rapacious", "kjv": "extortion, ravening."}, "G728": {"greek": "ἀῤῥαβών", "translit": "arrhabṓn", "pronunciation": "ar-hrab-ohn'", "derivation": "of Hebrew origin ((G6162));", "definition": "a pledge, i.e. part of the purchase-money or property given in advance as security for the rest", "kjv": "earnest."}, "G729": {"greek": "ἄῤῥαφος", "translit": "árrhaphos", "pronunciation": "ar'-hhraf-os", "derivation": "from (G1) (as a negative particle) and a presumed derivative of the same as (G4476);", "definition": "unsewed, i.e. of a single piece", "kjv": "without seam."}, "G730": {"greek": "ἄῤῥην", "translit": "árrhēn", "pronunciation": "ar'-hrane", "derivation": "probably from (G142);", "definition": "male (as stronger for lifting)", "kjv": "male, man."}, "G731": {"greek": "ἄῤῥητος", "translit": "árrhētos", "pronunciation": "ar'-hray-tos", "derivation": "from (G1) (as a negative particle) and the same as (G4490);", "definition": "unsaid, i.e. (by implication) inexpressible", "kjv": "unspeakable."}, "G732": {"greek": "ἄῤῥωστος", "translit": "árrhōstos", "pronunciation": "ar'-hroce-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G4517);", "definition": "infirm", "kjv": "sick (folk, -ly)."}, "G733": {"greek": "ἀρσενοκοίτης", "translit": "arsenokoítēs", "pronunciation": "ar-sen-ok-oy'-tace", "derivation": "from (G730) and (G2845);", "definition": "a sodomite", "kjv": "abuser of (that defile) self with mankind."}, "G734": {"greek": "Ἀρτεμάς", "translit": "Artemás", "pronunciation": "ar-tem-as'", "derivation": "contracted from a compound of (G735) and (G1435);", "definition": "gift of Artemis; Artemas (or Artemidorus), a Christian", "kjv": "Artemas."}, "G735": {"greek": "Ἄρτεμις", "translit": "Ártemis", "pronunciation": "ar'-tem-is", "derivation": "probably from the same as (G736);", "definition": "prompt; Artemis, the name of a Grecian goddess borrowed by the Asiatics for one of their deities", "kjv": "Diana."}, "G736": {"greek": "ἀρτέμων", "translit": "artémōn", "pronunciation": "ar-tem'-ohn", "derivation": "from a derivative of (G737);", "definition": "properly, something ready (or else more remotely from (G142) (compare (G740)); something hung up), i.e. (specially) the topsail (rather foresail or jib) of a vessel", "kjv": "mainsail."}, "G737": {"greek": "ἄρτι", "translit": "árti", "pronunciation": "ar'-tee", "derivation": "adverb from a derivative of (G142) (compare (G740)) through the idea of suspension;", "definition": "just now", "kjv": "this day (hour), hence(-forth), here(-after), hither(-to), (even) now, (this) present."}, "G738": {"greek": "ἀρτιγέννητος", "translit": "artigénnētos", "pronunciation": "ar-teeg-en'-nay-tos", "derivation": "from (G737) and (G1084);", "definition": "just born, i.e. (figuratively) a young convert", "kjv": "new born."}, "G739": {"greek": "ἄρτιος", "translit": "ártios", "pronunciation": "ar'-tee-os", "derivation": "from (G737);", "definition": "fresh, i.e. (by implication) complete", "kjv": "perfect."}, "G740": {"greek": "ἄρτος", "translit": "ártos", "pronunciation": "ar'-tos", "derivation": "from (G142);", "definition": "bread (as raised) or a loaf", "kjv": "(shew-)bread, loaf."}, "G741": {"greek": "ἀρτύω", "translit": "artýō", "pronunciation": "ar-too'-o", "derivation": "from a presumed derivative of (G142);", "definition": "to prepare, i.e. spice (with stimulating condiments)", "kjv": "season."}, "G742": {"greek": "Ἀρφαξάδ", "translit": "Arphaxád", "pronunciation": "ar-fax-ad'", "derivation": "of Hebrew origin ((G775));", "definition": "Arphaxad, a post-diluvian patriarch", "kjv": "Arphaxad."}, "G743": {"greek": "ἀρχάγγελος", "translit": "archángelos", "pronunciation": "ar-khang'-el-os", "derivation": "from (G757) and (G32);", "definition": "a chief angel", "kjv": "archangel."}, "G744": {"greek": "ἀρχαῖος", "translit": "archaîos", "pronunciation": "ar-khah'-yos", "derivation": "from (G746);", "definition": "original or primeval", "kjv": "(them of) old (time)."}, "G745": {"greek": "Ἀρχέλαος", "translit": "Archélaos", "pronunciation": "ar-khel'-ah-os", "derivation": "from (G757) and (G2994);", "definition": "people-ruling; Archelaus, a Jewish king", "kjv": "Archelaus."}, "G746": {"greek": "ἀρχή", "translit": "archḗ", "pronunciation": "ar-khay'", "derivation": "from (G756);", "definition": "(properly abstract) a commencement, or (concretely) chief (in various applications of order, time, place, or rank)", "kjv": "beginning, corner, (at the, the) first (estate), magistrate, power, principality, principle, rule."}, "G747": {"greek": "ἀρχηγός", "translit": "archēgós", "pronunciation": "ar-khay-gos'", "derivation": "from (G746) and (G71);", "definition": "a chief leader", "kjv": "author, captain, prince."}, "G748": {"greek": "ἀρχιερατικός", "translit": "archieratikós", "pronunciation": "ar-khee-er-at-ee-kos'", "derivation": "from (G746) and a derivative of (G2413);", "definition": "high-priestly", "kjv": "of the high-priest."}, "G749": {"greek": "ἀρχιερεύς", "translit": "archiereús", "pronunciation": "ar-khee-er-yuce'", "derivation": "from (G746) and (G2409);", "definition": "the high-priest (literally, of the Jews, typically, Christ); by extension a chief priest", "kjv": "chief (high) priest, chief of the priests."}, "G750": {"greek": "ἀρχιποίμην", "translit": "archipoímēn", "pronunciation": "ar-khee-poy'-mane", "derivation": "from (G746) and (G4166);", "definition": "a head shepherd", "kjv": "chief shepherd."}, "G751": {"greek": "Ἄρχιππος", "translit": "Árchippos", "pronunciation": "ar'-khip-pos", "derivation": "from (G746) and (G2462);", "definition": "horse-ruler; Archippus, a Christian", "kjv": "Archippus."}, "G752": {"greek": "ἀρχισυνάγωγος", "translit": "archisynágōgos", "pronunciation": "ar-khee-soon-ag'-o-gos", "derivation": "from (G746) and (G4864);", "definition": "director of the synagogue services", "kjv": "(chief) ruler of the synagogue."}, "G753": {"greek": "ἀρχιτέκτων", "translit": "architéktōn", "pronunciation": "ar-khee-tek'-tone", "derivation": "from (G746) and (G5045);", "definition": "a chief constructor, i.e. \"architect\"", "kjv": "masterbuilder."}, "G754": {"greek": "ἀρχιτελώνης", "translit": "architelṓnēs", "pronunciation": "ar-khee-tel-o'-nace", "derivation": "from (G746) and (G5057);", "definition": "a principle tax-gatherer", "kjv": "chief among the publicans."}, "G755": {"greek": "ἀρχιτρίκλινος", "translit": "architríklinos", "pronunciation": "ar-khee-tree'-klee-nos", "derivation": "from (G746) and a compound of (G5140) and (G2827) (a dinner-bed, because composed of three couches);", "definition": "director of the entertainment", "kjv": "governor (ruler) of the feast."}, "G756": {"greek": "ἄρχομαι", "translit": "árchomai", "pronunciation": "ar'-khom-ahee", "derivation": "middle voice of (G757) (through the implication, of precedence);", "definition": "to commence (in order of time)", "kjv": "(rehearse from the) begin(-ning)."}, "G757": {"greek": "ἄρχω", "translit": "árchō", "pronunciation": "ar'-kho", "derivation": "a primary verb;", "definition": "to be first (in political rank or power)", "kjv": "reign (rule) over."}, "G758": {"greek": "ἄρχων", "translit": "árchōn", "pronunciation": "ar'-khone", "derivation": "present participle of (G757);", "definition": "a first (in rank or power)", "kjv": "chief (ruler), magistrate, prince, ruler."}, "G759": {"greek": "ἄρωμα", "translit": "árōma", "pronunciation": "ar'-o-mah", "derivation": "from (G142) (in the sense of sending off scent);", "definition": "an aromatic", "kjv": "(sweet) spice."}, "G760": {"greek": "Ἀσά", "translit": "Asá", "pronunciation": "as-ah'", "derivation": "of Hebrew origin ((G609));", "definition": "Asa, an Israelite", "kjv": "Asa."}, "G761": {"greek": "ἀσάλευτος", "translit": "asáleutos", "pronunciation": "as-al'-yoo-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G4531);", "definition": "unshaken, i.e. (by implication) immovable (figuratively)", "kjv": "which cannot be moved, unmovable."}, "G762": {"greek": "ἄσβεστος", "translit": "ásbestos", "pronunciation": "as'-bes-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G4570);", "definition": "not extinguished, i.e. (by implication) perpetual", "kjv": "not to be quenched, unquenchable."}, "G763": {"greek": "ἀσέβεια", "translit": "asébeia", "pronunciation": "as-eb'-i-ah", "derivation": "from (G765);", "definition": "impiety, i.e. (by implication) wickedness", "kjv": "ungodly(-liness)."}, "G764": {"greek": "ἀσεβέω", "translit": "asebéō", "pronunciation": "as-eb-eh'-o", "derivation": "from (G765);", "definition": "to be (by implied act) impious or wicked", "kjv": "commit (live, that after should live) ungodly."}, "G765": {"greek": "ἀσεβής", "translit": "asebḗs", "pronunciation": "as-eb-ace'", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G4576);", "definition": "irreverent, i.e. (by extension) impious or wicked", "kjv": "ungodly (man)."}, "G766": {"greek": "ἀσέλγεια", "translit": "asélgeia", "pronunciation": "as-elg'-i-a", "derivation": "from a compound of (G1) (as a negative particle) and a presumed (of uncertain derivation, but apparently meaning continent);", "definition": "licentiousness (sometimes including other vices)", "kjv": "filthy, lasciviousness, wantonness."}, "G767": {"greek": "ἄσημος", "translit": "ásēmos", "pronunciation": "as'-ay-mos", "derivation": "from (G1) (as a negative particle) and the base of (G4591);", "definition": "unmarked, i.e. (figuratively) ignoble", "kjv": "mean."}, "G768": {"greek": "Ἀσήρ", "translit": "Asḗr", "pronunciation": "as-ayr'", "derivation": "of Hebrew origin ((G836));", "definition": "Aser (i.e. Asher), an Israelite tribe", "kjv": "Aser."}, "G769": {"greek": "ἀσθένεια", "translit": "asthéneia", "pronunciation": "as-then'-i-ah", "derivation": "from (G772);", "definition": "feebleness (of mind or body); by implication, malady; morally, frailty", "kjv": "disease, infirmity, sickness, weakness."}, "G770": {"greek": "ἀσθενέω", "translit": "asthenéō", "pronunciation": "as-then-eh'-o", "derivation": "from (G772);", "definition": "to be feeble (in any sense)", "kjv": "be diseased, impotent folk (man), (be) sick, (be, be made) weak."}, "G771": {"greek": "ἀσθένημα", "translit": "asthénēma", "pronunciation": "as-then'-ay-mah", "derivation": "from (G770);", "definition": "a scruple of conscience", "kjv": "infirmity."}, "G772": {"greek": "ἀσθενής", "translit": "asthenḗs", "pronunciation": "as-then-ace'", "derivation": "from (G1) (as a negative particle) and the base of (G4599);", "definition": "strengthless (in various applications, literal, figurative and moral)", "kjv": "more feeble, impotent, sick, without strength, weak(-er, -ness, thing)."}, "G773": {"greek": "Ἀσία", "translit": "Asía", "pronunciation": "as-ee'-ah", "derivation": "of uncertain derivation;", "definition": "Asia, i.e. Asia Minor, or (usually) only its western shore", "kjv": "Asia."}, "G774": {"greek": "Ἀσιανός", "translit": "Asianós", "pronunciation": "as-ee-an-os'", "derivation": "from (G773);", "definition": "an Asian (i.e. Asiatic) or an inhabitant of Asia", "kjv": "of Asia."}, "G775": {"greek": "Ἀσιάρχης", "translit": "Asiárchēs", "pronunciation": "as-ee-ar'-khace", "derivation": "from (G773) and (G746);", "definition": "an Asiarch or president of the public festivities in a city of Asia Minor", "kjv": "chief of Asia."}, "G776": {"greek": "ἀσιτία", "translit": "asitía", "pronunciation": "as-ee-tee'-ah", "derivation": "from (G777);", "definition": "fasting (the state)", "kjv": "abstinence."}, "G777": {"greek": "ἄσιτος", "translit": "ásitos", "pronunciation": "as'-ee-tos", "derivation": "from (G1) (as a negative particle) and (G4621);", "definition": "without (taking) food", "kjv": "fasting."}, "G778": {"greek": "ἀσκέω", "translit": "askéō", "pronunciation": "as-keh'-o", "derivation": "probably from the same as (G4632);", "definition": "to elaborate, i.e. (figuratively) train (by implication, strive)", "kjv": "exercise."}, "G779": {"greek": "ἀσκός", "translit": "askós", "pronunciation": "as-kos'", "derivation": "from the same as (G778);", "definition": "a leathern (or skin) bag used as a bottle", "kjv": "bottle."}, "G780": {"greek": "ἀσμένως", "translit": "asménōs", "pronunciation": "as-men'-oce", "derivation": "adverb from a derivative of the base of (G2237);", "definition": "with pleasure", "kjv": "gladly."}, "G781": {"greek": "ἄσοφος", "translit": "ásophos", "pronunciation": "as'-of-os", "derivation": "from (G1) (as a negative particle) and (G4680);", "definition": "unwise", "kjv": "fool."}, "G782": {"greek": "ἀσπάζομαι", "translit": "aspázomai", "pronunciation": "as-pad'-zom-ahee", "derivation": "from (G1) (as a particle of union) and a presumed form of (G4685);", "definition": "to enfold in the arms, i.e. (by implication) to salute, (figuratively) to welcome", "kjv": "embrace, greet, salute, take leave."}, "G783": {"greek": "ἀσπασμός", "translit": "aspasmós", "pronunciation": "as-pas-mos'", "derivation": "from (G782);", "definition": "a greeting (in person or by letter)", "kjv": "greeting, salutation."}, "G784": {"greek": "ἄσπιλος", "translit": "áspilos", "pronunciation": "as'-pee-los", "derivation": "from (G1) (as a negative particle) and (G4695);", "definition": "unblemished (physically or morally)", "kjv": "without spot, unspotted."}, "G785": {"greek": "ἀσπίς", "translit": "aspís", "pronunciation": "as-pece'", "derivation": "of uncertain derivation;", "definition": "a buckler (or round shield); used of a serpent (as coiling itself), probably the \"asp\"", "kjv": "asp."}, "G786": {"greek": "ἄσπονδος", "translit": "áspondos", "pronunciation": "as'-pon-dos", "derivation": "from (G1) (as a negative particle) and a derivative of (G4689);", "definition": "literally, without libation (which usually accompanied a treaty), i.e. (by implication) truceless", "kjv": "implacable, truce-breaker."}, "G787": {"greek": "ἀσσάριον", "translit": "assárion", "pronunciation": "as-sar'-ee-on", "derivation": "of Latin origin;", "definition": "an assarius or as, a Roman coin", "kjv": "farthing."}, "G788": {"greek": "ἆσσον", "translit": "âsson", "pronunciation": "as'-son", "derivation": "neuter comparative of the base of (G1451);", "definition": "more nearly, i.e. very near", "kjv": "close."}, "G789": {"greek": "Ἄσσος", "translit": "Ássos", "pronunciation": "as'-sos", "derivation": "probably of foreign origin;", "definition": "Assus, a city of Asia MInor", "kjv": "Assos."}, "G790": {"greek": "ἀστατέω", "translit": "astatéō", "pronunciation": "as-tat-eh'-o", "derivation": "from (G1) (as a negative particle) and a derivative of (G2476);", "definition": "to be non-stationary, i.e. (figuratively) homeless", "kjv": "have no certain dwelling-place."}, "G791": {"greek": "ἀστεῖος", "translit": "asteîos", "pronunciation": "as-ti'-os", "derivation": "from (a city);", "definition": "urbane, i.e. (by implication) handsome", "kjv": "fair."}, "G792": {"greek": "ἀστήρ", "translit": "astḗr", "pronunciation": "as-tare'", "derivation": "probably from the base of (G4766);", "definition": "a star (as strown over the sky), literally or figuratively", "kjv": "star."}, "G793": {"greek": "ἀστήρικτος", "translit": "astḗriktos", "pronunciation": "as-tay'-rik-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G4741);", "definition": "unfixed, i.e. (figuratively) vacillating", "kjv": "unstable."}, "G794": {"greek": "ἄστοργος", "translit": "ástorgos", "pronunciation": "as'-tor-gos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (to cherish affectionately);", "definition": "hard-hearted towards kindred", "kjv": "without natural affection."}, "G795": {"greek": "ἀστοχέω", "translit": "astochéō", "pronunciation": "as-tokh-eh'-o", "derivation": "from a compound of (G1) (as a negative particle) and (an aim);", "definition": "to miss the mark, i.e. (figuratively) deviate from truth", "kjv": "err, swerve."}, "G796": {"greek": "ἀστραπή", "translit": "astrapḗ", "pronunciation": "as-trap-ay'", "derivation": "from (G797);", "definition": "lightning; by analogy, glare", "kjv": "lightning, bright shining."}, "G797": {"greek": "ἀστράπτω", "translit": "astráptō", "pronunciation": "as-trap'-to", "derivation": "probably from (G792);", "definition": "to flash as lightning", "kjv": "lighten, shine."}, "G798": {"greek": "ἄστρον", "translit": "ástron", "pronunciation": "as'-tron", "derivation": "neuter from (G792);", "definition": "properly, a constellation; put for a single star (natural or artificial)", "kjv": "star."}, "G799": {"greek": "Ἀσύγκριτος", "translit": "Asýnkritos", "pronunciation": "as-oong'-kree-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G4793);", "definition": "incomparable; Asyncritus, a Christian", "kjv": "Asyncritos."}, "G800": {"greek": "ἀσύμφωνος", "translit": "asýmphōnos", "pronunciation": "as-oom'-fo-nos", "derivation": "from (G1) (as a negative particle) and (G4859);", "definition": "inharmonious (figuratively)", "kjv": "agree not."}, "G801": {"greek": "ἀσύνετος", "translit": "asýnetos", "pronunciation": "as-oon'-ay-tos", "derivation": "from (G1) (as a negative particle) and (G4908);", "definition": "unintelligent; by implication, wicked", "kjv": "foolish, without understanding."}, "G802": {"greek": "ἀσύνθετος", "translit": "asýnthetos", "pronunciation": "as-oon'-thet-os", "derivation": "from (G1) (as a negative particle) and a derivative of (G4934);", "definition": "properly, not agreed, i.e. treacherous to compacts", "kjv": "covenant-breaker."}, "G803": {"greek": "ἀσφάλεια", "translit": "aspháleia", "pronunciation": "as-fal'-i-ah", "derivation": "from (G804);", "definition": "security (literally or figuratively)", "kjv": "certainty, safety."}, "G804": {"greek": "ἀσφαλής", "translit": "asphalḗs", "pronunciation": "as-fal-ace'", "derivation": "from (G1) (as a negative particle) and (to \"fail\");", "definition": "secure (literally or figuratively)", "kjv": "certain(-ty), safe, sure."}, "G805": {"greek": "ἀσφαλίζω", "translit": "asphalízō", "pronunciation": "as-fal-id'-zo", "derivation": "from (G804);", "definition": "to render secure", "kjv": "make fast (sure)."}, "G806": {"greek": "ἀσφαλῶς", "translit": "asphalōs", "pronunciation": "as-fal-oce'", "derivation": "adverb from (G804);", "definition": "securely (literally or figuratively)", "kjv": "assuredly, safely."}, "G807": {"greek": "ἀσχημονέω", "translit": "aschēmonéō", "pronunciation": "as-kay-mon-eh'-o", "derivation": "from (G809);", "definition": "to be (i.e. act) unbecoming", "kjv": "behave self uncomely (unseemly)."}, "G808": {"greek": "ἀσχημοσύνη", "translit": "aschēmosýnē", "pronunciation": "as-kay-mos-oo'-nay", "derivation": "from (G809);", "definition": "an indecency; by implication, the pudenda", "kjv": "shame, that which is unseemly."}, "G809": {"greek": "ἀσχήμων", "translit": "aschḗmōn", "pronunciation": "as-kay'-mone", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G2192) (in the sense of its congener (G4976));", "definition": "properly, shapeless, i.e. (figuratively) inelegant", "kjv": "uncomely."}, "G810": {"greek": "ἀσωτία", "translit": "asōtía", "pronunciation": "as-o-tee'-ah", "derivation": "from a compound of (G1) (as a negative particle) and a presumed derivative of (G4982);", "definition": "properly, unsavedness, i.e. (by implication) profligacy", "kjv": "excess, riot."}, "G811": {"greek": "ἀσώτως", "translit": "asṓtōs", "pronunciation": "as-o'-toce", "derivation": "adverb from the same as (G810);", "definition": "dissolutely", "kjv": "riotous."}, "G812": {"greek": "ἀτακτέω", "translit": "ataktéō", "pronunciation": "at-ak-teh'-o", "derivation": "from (G813);", "definition": "to be (i.e. act) irregular", "kjv": "behave self disorderly."}, "G813": {"greek": "ἄτακτος", "translit": "átaktos", "pronunciation": "at'-ak-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G5021);", "definition": "unarranged, i.e. (by implication) insubordinate (religiously)", "kjv": "unruly."}, "G814": {"greek": "ἀτάκτως", "translit": "atáktōs", "pronunciation": "at-ak'-toce", "derivation": "adverb from (G813), irregularly (morally)", "definition": "", "kjv": "disorderly."}, "G815": {"greek": "ἄτεκνος", "translit": "áteknos", "pronunciation": "at'-ek-nos", "derivation": "from (G1) (as a negative particle) and (G5043);", "definition": "childless", "kjv": "childless, without children."}, "G816": {"greek": "ἀτενίζω", "translit": "atenízō", "pronunciation": "at-en-id'-zo", "derivation": "from a compound of (G1) (as a particle of union) and (to stretch);", "definition": "to gaze intently", "kjv": "behold earnestly (stedfastly), fasten (eyes), look (earnestly, stedfastly, up stedfastly), set eyes."}, "G817": {"greek": "ἄτερ", "translit": "áter", "pronunciation": "at'-er", "derivation": "a particle probably akin to (G427);", "definition": "aloof, i.e. apart from (literally or figuratively)", "kjv": "in the absence of, without."}, "G818": {"greek": "ἀτιμάζω", "translit": "atimázō", "pronunciation": "at-im-ad'-zo", "derivation": "from (G820);", "definition": "to render infamous, i.e. (by implication) contemn or maltreat", "kjv": "despise, dishonour, suffer shame, entreat shamefully."}, "G819": {"greek": "ἀτιμία", "translit": "atimía", "pronunciation": "at-ee-mee'-ah", "derivation": "from (G820);", "definition": "infamy, i.e. (subjectively) comparative indignity, (objectively) disgrace", "kjv": "dishonour, reproach, shame, vile."}, "G820": {"greek": "ἄτιμος", "translit": "átimos", "pronunciation": "at'-ee-mos", "derivation": "from (G1) (as a negative particle) and (G5092);", "definition": "(negatively) unhonoured or (positively) dishonoured", "kjv": "despised, without honour, less honourable (comparative degree)."}, "G822": {"greek": "ἀτμίς", "translit": "atmís", "pronunciation": "at-mece'", "derivation": "from the same as (G109);", "definition": "mist", "kjv": "vapour."}, "G823": {"greek": "ἄτομος", "translit": "átomos", "pronunciation": "at'-om-os", "derivation": "from (G1) (as a negative particle) and the base of (G5114);", "definition": "uncut, i.e. (by implication) indivisible (an \"atom\" of time)", "kjv": "moment."}, "G824": {"greek": "ἄτοπος", "translit": "átopos", "pronunciation": "at'-op-os", "derivation": "from (G1) (as a negative particle) and (G5117);", "definition": "out of place, i.e. (figuratively) improper, injurious, wicked", "kjv": "amiss, harm, unreasonable."}, "G825": {"greek": "Ἀττάλεια", "translit": "Attáleia", "pronunciation": "at-tal'-i-ah", "derivation": "from (a king of Pergamus);", "definition": "Attaleia, a place in Pamphylia", "kjv": "Attalia."}, "G826": {"greek": "αὐγάζω", "translit": "augázō", "pronunciation": "ow-gad'-zo", "derivation": "from (G827);", "definition": "to beam forth (figuratively)", "kjv": "shine."}, "G827": {"greek": "αὐγή", "translit": "augḗ", "pronunciation": "owg'-ay", "derivation": "of uncertain derivation;", "definition": "a ray of light, i.e. (by implication) radiance, dawn", "kjv": "break of day."}, "G828": {"greek": "Αὐγοῦστος", "translit": "Augoûstos", "pronunciation": "ow'-goos-tos", "derivation": "from Latin (\"august\");", "definition": "Augustus, a title of the Roman emperor", "kjv": "Augustus."}, "G829": {"greek": "αὐθάδης", "translit": "authádēs", "pronunciation": "ow-thad'-ace", "derivation": "from (G846) and the base of (G2237);", "definition": "self-pleasing, i.e. arrogant", "kjv": "self-willed."}, "G830": {"greek": "αὐθαίρετος", "translit": "authaíretos", "pronunciation": "ow-thah'-ee-ret-os", "derivation": "from (G846) and the same as (G140);", "definition": "self-chosen, i.e. (by implication) voluntary", "kjv": "of own accord, willing of self."}, "G831": {"greek": "αὐθεντέω", "translit": "authentéō", "pronunciation": "ow-then-teh'-o", "derivation": "from a compound of (G846) and an obsolete (a worker);", "definition": "to act of oneself, i.e. (figuratively) dominate", "kjv": "usurp authority over."}, "G832": {"greek": "αὐλέω", "translit": "auléō", "pronunciation": "ow-leh'-o", "derivation": "from (G836);", "definition": "to play the flute", "kjv": "pipe."}, "G833": {"greek": "αὐλή", "translit": "aulḗ", "pronunciation": "ow-lay'", "derivation": "from the same as (G109);", "definition": "a yard (as open to the wind); by implication, a mansion", "kjv": "court, (sheep-)fold, hall, palace."}, "G834": {"greek": "αὐλητής", "translit": "aulētḗs", "pronunciation": "ow-lay-tace'", "derivation": "from (G832);", "definition": "a flute-player", "kjv": "minstrel, piper."}, "G835": {"greek": "αὐλίζομαι", "translit": "aulízomai", "pronunciation": "ow-lid'-zom-ahee", "derivation": "middle voice from (G833);", "definition": "to pass the night (properly, in the open air)", "kjv": "abide, lodge."}, "G836": {"greek": "αὐλός", "translit": "aulós", "pronunciation": "ow-los'", "derivation": "from the same as (G109);", "definition": "a flute (as blown)", "kjv": "pipe."}, "G837": {"greek": "αὐξάνω", "translit": "auxánō", "pronunciation": "owx-an'-o", "derivation": "a prolonged form of a primary verb;", "definition": "to grow (\"wax\"), i.e. enlarge (literal or figurative, active or passive)", "kjv": "grow (up), (give the) increase."}, "G838": {"greek": "αὔξησις", "translit": "aúxēsis", "pronunciation": "owx'-ay-sis", "derivation": "from (G837);", "definition": "growth", "kjv": "increase."}, "G839": {"greek": "αὔριον", "translit": "aúrion", "pronunciation": "ow'-ree-on", "derivation": "from a derivative of the same as (G109) (meaning a breeze, i.e. the morning air);", "definition": "properly, fresh, i.e. (adverb with ellipsis of (G2250)) to-morrow", "kjv": "(to-)morrow, next day."}, "G840": {"greek": "αὐστηρός", "translit": "austērós", "pronunciation": "ow-stay-ros'", "derivation": "from a (presumed) derivative of the same as (G109) (meaning blown);", "definition": "rough (properly as a gale), i.e. (figuratively) severe", "kjv": "austere."}, "G841": {"greek": "αὐτάρκεια", "translit": "autárkeia", "pronunciation": "ow-tar'-ki-ah", "derivation": "from (G842);", "definition": "self-satisfaction, i.e. (abstractly) contentedness, or (concretely) a competence", "kjv": "contentment, sufficiency."}, "G842": {"greek": "αὐτάρκης", "translit": "autárkēs", "pronunciation": "ow-tar'-kace", "derivation": "from (G846) and (G714);", "definition": "self-complacent, i.e. contented", "kjv": "content."}, "G843": {"greek": "αὐτοκατάκριτος", "translit": "autokatákritos", "pronunciation": "ow-tok-at-ak'-ree-tos", "derivation": "from (G846) and a derivative or (G2632);", "definition": "self-condemned", "kjv": "condemned of self."}, "G844": {"greek": "αὐτόματος", "translit": "autómatos", "pronunciation": "ow-tom'-at-os", "derivation": "from (G846) and the same as (G3155);", "definition": "self-moved (\"automatic\"), i.e. spontaneous", "kjv": "of own accord, of self."}, "G845": {"greek": "αὐτόπτης", "translit": "autóptēs", "pronunciation": "ow-top'-tace", "derivation": "from (G846) and (G3700);", "definition": "self-seeing, i.e. an eye-witness", "kjv": "eye-witness."}, "G846": {"greek": "αὐτός", "translit": "autós", "pronunciation": "ow-tos'", "derivation": "from the particle (perhaps akin to the base of (G109) through the idea of a baffling wind) (backward);", "definition": "the reflexive pronoun self, used (alone or in the compound (G1438)) of the third person , and (with the proper personal pronoun) of the other persons", "kjv": "her, it(-self), one, the other, (mine) own, said, (self-), the) same, ((him-, my-, thy- )self, (your-)selves, she, that, their(-s), them(-selves), there(-at, - by, -in, -into, -of, -on, -with), they, (these) things, this (man), those, together, very, which."}, "G847": {"greek": "αὐτοῦ", "translit": "autoû", "pronunciation": "ow-too'", "derivation": "genitive (i.e. possessive) of (G846), used as an adverb of location;", "definition": "properly, belonging to the same spot, i.e. in this (or that) place", "kjv": "(t-)here."}, "G849": {"greek": "αὐτόχειρ", "translit": "autócheir", "pronunciation": "ow-tokh'-ire", "derivation": "from (G846) and (G5495);", "definition": "self-handed, i.e. doing personally", "kjv": "with … own hands."}, "G850": {"greek": "αὐχμηρός", "translit": "auchmērós", "pronunciation": "owkh-may-ros'", "derivation": "from (probably from a base akin to that of (G109)) (dust, as dried by wind);", "definition": "properly, dirty, i.e. (by implication) obscure", "kjv": "dark."}, "G851": {"greek": "ἀφαιρέω", "translit": "aphairéō", "pronunciation": "af-ahee-reh'-o", "derivation": "from (G575) and (G138);", "definition": "to remove (literally or figuratively)", "kjv": "cut (smite) off, take away."}, "G852": {"greek": "ἀφανής", "translit": "aphanḗs", "pronunciation": "af-an-ace'", "derivation": "from (G1) (as a negative particle) and (G5316);", "definition": "non-apparent)", "kjv": "that is not manifest."}, "G853": {"greek": "ἀφανίζω", "translit": "aphanízō", "pronunciation": "af-an-id'-zo", "derivation": "from (G852);", "definition": "to render unapparent, i.e. (actively) consume (becloud), or (passively) disappear (be destroyed)", "kjv": "corrupt, disfigure, perish, vanish away."}, "G854": {"greek": "ἀφανισμός", "translit": "aphanismós", "pronunciation": "af-an-is-mos'", "derivation": "from (G853);", "definition": "disappearance, i.e. (figuratively) abrogation", "kjv": "vanish away."}, "G855": {"greek": "ἄφαντος", "translit": "áphantos", "pronunciation": "af'-an-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G5316);", "definition": "non-manifested, i.e. invisible", "kjv": "vanished out of sight."}, "G856": {"greek": "ἀφεδρών", "translit": "aphedrṓn", "pronunciation": "af-ed-rone'", "derivation": "from a compound of (G575) and the base of (G1476);", "definition": "a place of sitting apart, i.e. a privy", "kjv": "draught."}, "G857": {"greek": "ἀφειδία", "translit": "apheidía", "pronunciation": "af-i-dee'-ah", "derivation": "from a compound of (G1) (as a negative particle) and (G5339);", "definition": "unsparingness, i.e. austerity (asceticism)", "kjv": "neglecting."}, "G858": {"greek": "ἀφελότης", "translit": "aphelótēs", "pronunciation": "af-el-ot'-ace", "derivation": "from a compound of (G1) (as a negative particle) and (in the sense of a stone as stubbing the foot);", "definition": "smoothness, i.e. (figuratively) simplicity", "kjv": "singleness."}, "G859": {"greek": "ἄφεσις", "translit": "áphesis", "pronunciation": "af'-es-is", "derivation": "from (G863);", "definition": "freedom; (figuratively) pardon", "kjv": "deliverance, forgiveness, liberty, remission."}, "G860": {"greek": "ἁφή", "translit": "haphḗ", "pronunciation": "haf-ay'", "derivation": "from (G680);", "definition": "probably a ligament (as fastening)", "kjv": "joint."}, "G861": {"greek": "ἀφθαρσία", "translit": "aphtharsía", "pronunciation": "af-thar-see'-ah", "derivation": "from (G862);", "definition": "incorruptibility; genitive, unending existence; (figuratively) genuineness", "kjv": "immortality, incorruption, sincerity."}, "G862": {"greek": "ἄφθαρτος", "translit": "áphthartos", "pronunciation": "af'-thar-tos", "derivation": "from (G1) (as a negative particle) and a derivative of (G5351);", "definition": "undecaying (in essence or continuance)", "kjv": "not (in-, un-)corruptible, immortal."}, "G863": {"greek": "ἀφίημι", "translit": "aphíēmi", "pronunciation": "af-ee'-ay-mee", "derivation": "from (G575) and (to send; an intensive form of , to go);", "definition": "to send forth, in various applications (as follow)", "kjv": "cry, forgive, forsake, lay aside, leave, let (alone, be, go, have), omit, put (send) away, remit, suffer, yield up."}, "G864": {"greek": "ἀφικνέομαι", "translit": "aphiknéomai", "pronunciation": "af-ik-neh'-om-ahee", "derivation": "from (G575) and the base of (G2425);", "definition": "to go (i.e. spread) forth (by rumor)", "kjv": "come abroad."}, "G865": {"greek": "ἀφιλάγαθος", "translit": "aphilágathos", "pronunciation": "af-il-ag'-ath-os", "derivation": "from (G1) (as a negative particle) and (G5358);", "definition": "hostile to virtue", "kjv": "despiser of those that are good."}, "G866": {"greek": "ἀφιλάργυρος", "translit": "aphilárgyros", "pronunciation": "af-il-ar'-goo-ros", "derivation": "from (G1) (as a negative particle) and (G5366);", "definition": "unavaricious", "kjv": "without covetousness, not greedy of filthy lucre."}, "G867": {"greek": "ἄφιξις", "translit": "áphixis", "pronunciation": "af'-ix-is", "derivation": "from (G864);", "definition": "properly, arrival, i.e. (by implication) departure", "kjv": "departing."}, "G868": {"greek": "ἀφίστημι", "translit": "aphístēmi", "pronunciation": "af-is'-tay-mee", "derivation": "from (G575) and (G2476);", "definition": "to remove, i.e. (actively) instigate to revolt; usually (reflexively) to desist, desert, etc.", "kjv": "depart, draw (fall) away, refrain, withdraw self."}, "G869": {"greek": "ἄφνω", "translit": "áphnō", "pronunciation": "af'-no", "derivation": "adverb from (G852) (contraction);", "definition": "unawares, i.e. unexpectedly", "kjv": "suddenly."}, "G870": {"greek": "ἀφόβως", "translit": "aphóbōs", "pronunciation": "af-ob'-oce", "derivation": "adverb from a compound of (G1) (as a negative particle) and (G5401);", "definition": "fearlessly", "kjv": "without fear."}, "G871": {"greek": "ἀφομοιόω", "translit": "aphomoióō", "pronunciation": "af-om-oy-o'-o", "derivation": "from (G575) and (G3666);", "definition": "to assimilate closely", "kjv": "make like."}, "G872": {"greek": "ἀφοράω", "translit": "aphoráō", "pronunciation": "af-or-ah'-o", "derivation": "from (G575) and (G3708);", "definition": "to consider attentively", "kjv": "look."}, "G873": {"greek": "ἀφορίζω", "translit": "aphorízō", "pronunciation": "af-or-id'-zo", "derivation": "from (G575) and (G3724);", "definition": "to set off by boundary, i.e. (figuratively) limit, exclude, appoint, etc.", "kjv": "divide, separate, sever."}, "G874": {"greek": "ἀφορμή", "translit": "aphormḗ", "pronunciation": "af-or-may'", "derivation": "from a compound of (G575) and (G3729);", "definition": "a starting-point, i.e. (figuratively) an opportunity", "kjv": "occasion."}, "G875": {"greek": "ἀφρίζω", "translit": "aphrízō", "pronunciation": "af-rid'-zo", "derivation": "from (G876);", "definition": "to froth at the mouth (in epilepsy)", "kjv": "foam."}, "G876": {"greek": "ἀφρός", "translit": "aphrós", "pronunciation": "af-ros'", "derivation": "apparently a primary word;", "definition": "froth, i.e. slaver", "kjv": "foaming."}, "G877": {"greek": "ἀφροσύνη", "translit": "aphrosýnē", "pronunciation": "af-ros-oo'-nay", "derivation": "from (G878);", "definition": "senselessness, i.e. (euphemistically) egotism; (morally) recklessness", "kjv": "folly, foolishly(-ness)."}, "G878": {"greek": "ἄφρων", "translit": "áphrōn", "pronunciation": "af'-rone", "derivation": "from (G1) (as a negative particle) and (G5424);", "definition": "properly, mindless, i.e. stupid, (by implication) ignorant, (specially) egotistic, (practically) rash, or (morally) unbelieving", "kjv": "fool(-ish), unwise."}, "G879": {"greek": "ἀφυπνόω", "translit": "aphypnóō", "pronunciation": "af-oop-no'-o", "derivation": "from a compound of (G575) and (G5258);", "definition": "properly, to become awake, i.e. (by implication) to drop (off) in slumber", "kjv": "fall asleep."}, "G880": {"greek": "ἄφωνος", "translit": "áphōnos", "pronunciation": "af'-o-nos", "derivation": "from (G1) (as a negative particle) and (G5456);", "definition": "voiceless, i.e. mute (by nature or choice); figuratively, unmeaning", "kjv": "dumb, without signification."}, "G881": {"greek": "Ἀχάζ", "translit": "Acház", "pronunciation": "akh-adz'", "derivation": "of Hebrew origin ((G271));", "definition": "Achaz, an Israelite", "kjv": "Achaz."}, "G882": {"greek": "Ἀχαΐα", "translit": "Achaḯa", "pronunciation": "ach-ah-ee'-ah", "derivation": "of uncertain derivation;", "definition": "Achaia (i.e. Greece), a country of Europe", "kjv": "Achaia."}, "G883": {"greek": "Ἀχαϊκός", "translit": "Achaïkós", "pronunciation": "ach-ah-ee-kos'", "derivation": "from (G882);", "definition": "an Achaian; Achaicus, a Christian", "kjv": "Achaicus."}, "G884": {"greek": "ἀχάριστος", "translit": "acháristos", "pronunciation": "ach-ar'-is-tos", "derivation": "from (G1) (as a negative particle) and a presumed derivative of (G5483);", "definition": "thankless, i.e. ungrateful", "kjv": "unthankful."}, "G885": {"greek": "Ἀχείμ", "translit": "Acheím", "pronunciation": "akh-ime'", "derivation": "probably of Hebrew origin (compare (G3137));", "definition": "Achim, an Israelite", "kjv": "Achim."}, "G886": {"greek": "ἀχειροποίητος", "translit": "acheiropoíētos", "pronunciation": "akh-i-rop-oy'-ay-tos", "derivation": "from (G1) (as a negative particle) and (G5499);", "definition": "unmanufactured, i.e. inartificial", "kjv": "made without (not made with) hands."}, "G887": {"greek": "ἀχλύς", "translit": "achlýs", "pronunciation": "akh-looce'", "derivation": "of uncertain derivation;", "definition": "dimness of sight, i.e. (probably) a cataract", "kjv": "mist."}, "G888": {"greek": "ἀχρεῖος", "translit": "achreîos", "pronunciation": "akh-ri'-os", "derivation": "from (G1) (as a negative particle) and a derivative of (G5534) (compare (G5532));", "definition": "useless, i.e. (euphemistically) unmeritorious", "kjv": "unprofitable."}, "G889": {"greek": "ἀχρειόω", "translit": "achreióō", "pronunciation": "akh-ri-o'-o", "derivation": "from (G888);", "definition": "to render useless, i.e. spoil", "kjv": "become unprofitable."}, "G890": {"greek": "ἄχρηστος", "translit": "áchrēstos", "pronunciation": "akh'-race-tos", "derivation": "from (G1) (as a negative particle) and (G5543);", "definition": "inefficient, i.e. (by implication) detrimental", "kjv": "unprofitable."}, "G891": {"greek": "ἄχρι", "translit": "áchri", "pronunciation": "akh'-ree", "derivation": "akin to (G206) (through the idea of a terminus);", "definition": "(of time) until or (of place) up to", "kjv": "as far as, for, in(-to), till, (even, un-)to, until, while."}, "G892": {"greek": "ἄχυρον", "translit": "áchyron", "pronunciation": "akh'-oo-ron", "derivation": "perhaps remotely from (to shed forth);", "definition": "chaff (as diffusive)", "kjv": "chaff."}, "G893": {"greek": "ἀψευδής", "translit": "apseudḗs", "pronunciation": "aps-yoo-dace'", "derivation": "from (G1) (as a negative particle) and (G5579);", "definition": "veracious", "kjv": "that cannot lie."}, "G894": {"greek": "ἄψινθος", "translit": "ápsinthos", "pronunciation": "ap'-sin-thos", "derivation": "of uncertain derivation;", "definition": "wormwood (as a type of bitterness, i.e. (figuratively) calamity)", "kjv": "wormwood."}, "G895": {"greek": "ἄψυχος", "translit": "ápsychos", "pronunciation": "ap'-soo-khos", "derivation": "from (G1) (as a negative particle) and (G5590);", "definition": "lifeless, i.e. inanimate (mechanical)", "kjv": "without life."}, "G896": {"greek": "Βάαλ", "translit": "Báal", "pronunciation": "bah'-al", "derivation": "of Hebrew origin ((G1168));", "definition": "Baal, a Phœnician deity (used as a symbol of idolatry)", "kjv": "Baal."}, "G897": {"greek": "Βαβυλών", "translit": "Babylṓn", "pronunciation": "bab-oo-lone'", "derivation": "of Hebrew origin ((G894));", "definition": "Babylon, the capitol of Chaldæa (literally or figuratively (as a type of tyranny))", "kjv": "Babylon."}, "G898": {"greek": "βαθμός", "translit": "bathmós", "pronunciation": "bath-mos'", "derivation": "from the same as (G899);", "definition": "a step, i.e. (figuratively) grade (of dignity)", "kjv": "degree."}, "G899": {"greek": "βάθος", "translit": "báthos", "pronunciation": "bath'-os", "derivation": "from the same as (G901);", "definition": "profundity, i.e. (by implication) extent; (figuratively) mystery", "kjv": "deep(-ness, things), depth."}, "G900": {"greek": "βαθύνω", "translit": "bathýnō", "pronunciation": "bath-oo'-no", "derivation": "from (G901);", "definition": "to deepen", "kjv": "deep."}, "G901": {"greek": "βαθύς", "translit": "bathýs", "pronunciation": "bath-oos'", "derivation": "from the base of (G939);", "definition": "profound (as going down), literally or figuratively", "kjv": "deep, very early."}, "G902": {"greek": "βαΐον", "translit": "baḯon", "pronunciation": "bah-ee'-on", "derivation": "a diminutive of a derivative probably of the base of (G939);", "definition": "a palm twig (as going out far)", "kjv": "branch."}, "G903": {"greek": "Βαλαάμ", "translit": "Balaám", "pronunciation": "bal-ah-am'", "derivation": "of Hebrew origin ((G1109));", "definition": "Balaam, a Mesopotamian (symbolic of a false teacher)", "kjv": "Balaam."}, "G904": {"greek": "Βαλάκ", "translit": "Balák", "pronunciation": "bal-ak'", "derivation": "of Hebrew origin ((G1111));", "definition": "Balak, a Moabite", "kjv": "Balac."}, "G905": {"greek": "βαλάντιον", "translit": "balántion", "pronunciation": "bal-an'-tee-on", "derivation": "probably remotely from (G906) (as a depository);", "definition": "a pouch (for money)", "kjv": "bag, purse."}, "G906": {"greek": "βάλλω", "translit": "bállō", "pronunciation": "bal'-lo", "derivation": "a primary verb;", "definition": "to throw (in various applications, more or less violent or intense)", "kjv": "arise, cast (out), X dung, lay, lie, pour, put (up), send, strike, throw (down), thrust."}, "G907": {"greek": "βαπτίζω", "translit": "baptízō", "pronunciation": "bap-tid'-zo", "derivation": "from a derivative of (G911);", "definition": "to immerse, submerge; to make whelmed (i.e. fully wet); used only (in the New Testament) of ceremonial ablution, especially (technically) of the ordinance of Christian baptism", "kjv": "Baptist, baptize, wash."}, "G908": {"greek": "βάπτισμα", "translit": "báptisma", "pronunciation": "bap'-tis-mah", "derivation": "from (G907);", "definition": "baptism (technically or figuratively)", "kjv": "baptism."}, "G909": {"greek": "βαπτισμός", "translit": "baptismós", "pronunciation": "bap-tis-mos'", "derivation": "from (G907);", "definition": "ablution (ceremonial or Christian)", "kjv": "baptism, washing."}, "G910": {"greek": "Βαπτιστής", "translit": "Baptistḗs", "pronunciation": "bap-tis-tace'", "derivation": "from (G907);", "definition": "a baptizer, as an epithet of Christ's forerunner", "kjv": "Baptist."}, "G911": {"greek": "βάπτω", "translit": "báptō", "pronunciation": "bap'-to", "derivation": "a primary verb;", "definition": "to whelm, i.e. cover wholly with a fluid; in the New Testament only in a qualified or special sense, i.e. (literally) to moisten (a part of one's person), or (by implication) to stain (as with dye)", "kjv": "dip."}, "G912": {"greek": "Βαραββᾶς", "translit": "Barabbâs", "pronunciation": "bar-ab-bas'", "derivation": "of Chaldee origin ((G1347) and (G5));", "definition": "son of Abba; Bar-abbas, an Israelite", "kjv": "Barabbas."}, "G913": {"greek": "Βαράκ", "translit": "Barák", "pronunciation": "bar-ak'", "derivation": "of Hebrew origin ((G1301));", "definition": "Barak, an Israelite", "kjv": "Barak."}, "G914": {"greek": "Βαραχίας", "translit": "Barachías", "pronunciation": "bar-akh-ee'-as", "derivation": "of Hebrew origin ((G1296));", "definition": "Barachias (i.e. Berechijah), an Israelite", "kjv": "Barachias."}, "G915": {"greek": "βάρβαρος", "translit": "bárbaros", "pronunciation": "bar'-bar-os", "derivation": "of uncertain derivation;", "definition": "a foreigner (i.e. non-Greek)", "kjv": "barbarian(-rous)."}, "G916": {"greek": "βαρέω", "translit": "baréō", "pronunciation": "bar-eh'-o", "derivation": "from (G926);", "definition": "to weigh down (figuratively)", "kjv": "burden, charge, heavy, press."}, "G917": {"greek": "βαρέως", "translit": "baréōs", "pronunciation": "bar-eh'-oce", "derivation": "adverb from (G926);", "definition": "heavily (figuratively)", "kjv": "dull."}, "G918": {"greek": "Βαρθολομαῖος", "translit": "Bartholomaîos", "pronunciation": "bar-thol-om-ah'-yos", "derivation": "of Chaldee origin ((G1247) and (G8526));", "definition": "son of Tolmai; Bar-tholomæus, a Christian apostle", "kjv": "Bartholomeus."}, "G919": {"greek": "Βαριησοῦς", "translit": "Bariēsoûs", "pronunciation": "bar-ee-ay-sooce'", "derivation": "of Chaldee origin ((G1247) and (G3091));", "definition": "son of Jesus (or Joshua); Bar-jesus, an Israelite", "kjv": "Barjesus."}, "G920": {"greek": "Βαριωνᾶς", "translit": "Bariōnâs", "pronunciation": "bar-ee-oo-nas'", "derivation": "of Chaldee origin ((G1247) and (G3124));", "definition": "son of Jonas (or Jonah); Bar-jonas, an Israelite", "kjv": "Bar-jona."}, "G921": {"greek": "Βαρνάβας", "translit": "Barnábas", "pronunciation": "bar-nab'-as", "derivation": "of Chaldee origin ((G1247) and (G5029));", "definition": "son of Nabas (i.e. prophecy); Barnabas, an Israelite", "kjv": "Barnabas."}, "G922": {"greek": "βάρος", "translit": "báros", "pronunciation": "bar'-os", "derivation": "probably from the same as (G939) (through the notion of going down; compare (G899));", "definition": "weight; in the New Testament only, figuratively, a load, abundance, authority", "kjv": "burden(-some), weight."}, "G923": {"greek": "Βαρσαβᾶς", "translit": "Barsabâs", "pronunciation": "bar-sab-as'", "derivation": "of Chaldee origin ((G1247) and probably (G6634));", "definition": "son of Sabas (or Tsaba); Bar-sabas, the name of two Israelites", "kjv": "Barsabas."}, "G924": {"greek": "Βαρτιμαῖος", "translit": "Bartimaîos", "pronunciation": "bar-tim-ah'-yos", "derivation": "of Chaldee origin ((G1247) and (G2931));", "definition": "son of Timæus (or the unclean); Bar-timæus, an Israelite", "kjv": "Bartimæus."}, "G926": {"greek": "βαρύς", "translit": "barýs", "pronunciation": "bar-ooce'", "derivation": "from the same as (G922);", "definition": "weighty, i.e. (fig) burdensome, grave", "kjv": "grievous, heavy, weightier."}, "G927": {"greek": "βαρύτιμος", "translit": "barýtimos", "pronunciation": "bar-oo'-tim-os", "derivation": "from (G926) and (G5092);", "definition": "highly valuable", "kjv": "very precious."}, "G928": {"greek": "βασανίζω", "translit": "basanízō", "pronunciation": "bas-an-id'-zo", "derivation": "from (G931);", "definition": "to torture", "kjv": "pain, toil, torment, toss, vex."}, "G929": {"greek": "βασανισμός", "translit": "basanismós", "pronunciation": "bas-an-is-mos'", "derivation": "from (G928);", "definition": "torture", "kjv": "torment."}, "G930": {"greek": "βασανιστής", "translit": "basanistḗs", "pronunciation": "bas-an-is-tace'", "derivation": "from (G928);", "definition": "a torturer", "kjv": "tormentor."}, "G931": {"greek": "βάσανος", "translit": "básanos", "pronunciation": "bas'-an-os", "derivation": "perhaps remotely from the same as (G939) (through the notion of going to the bottom);", "definition": "a touch-stone, i.e. (by analogy) torture", "kjv": "torment."}, "G932": {"greek": "βασιλεία", "translit": "basileía", "pronunciation": "bas-il-i'-ah", "derivation": "from (G935);", "definition": "properly, royalty, i.e. (abstractly) rule, or (concretely) a realm (literally or figuratively)", "kjv": "kingdom, + reign."}, "G933": {"greek": "βασίλειον", "translit": "basíleion", "pronunciation": "bas-il'-i-on", "derivation": "neuter of (G934);", "definition": "a palace", "kjv": "king's court."}, "G934": {"greek": "βασίλειος", "translit": "basíleios", "pronunciation": "bas-il'-i-os", "derivation": "from (G935);", "definition": "kingly (in nature)", "kjv": "royal."}, "G935": {"greek": "βασιλεύς", "translit": "basileús", "pronunciation": "bas-il-yooce'", "derivation": "probably from (G939) (through the notion of a foundation of power);", "definition": "a sovereign (abstractly, relatively, or figuratively)", "kjv": "king."}, "G936": {"greek": "βασιλεύω", "translit": "basileúō", "pronunciation": "bas-il-yoo'-o", "derivation": "from (G935);", "definition": "to rule (literally or figuratively)", "kjv": "king, reign."}, "G937": {"greek": "βασιλικός", "translit": "basilikós", "pronunciation": "bas-il-ee-kos'", "derivation": "from (G935);", "definition": "regal (in relation), i.e. (literally) belonging to (or befitting) the sovereign (as land, dress, or a courtier), or (figuratively) preeminent", "kjv": "king's, nobleman, royal."}, "G938": {"greek": "βασίλισσα", "translit": "basílissa", "pronunciation": "bas-il'-is-sah", "derivation": "feminine from (G936);", "definition": "a queen", "kjv": "queen."}, "G939": {"greek": "βάσις", "translit": "básis", "pronunciation": "bas'-ece", "derivation": "from (to walk);", "definition": "a pace (\"base\"), i.e. (by implication) the foot", "kjv": "foot."}, "G940": {"greek": "βασκαίνω", "translit": "baskaínō", "pronunciation": "bas-kah'-ee-no", "derivation": "akin to (G5335);", "definition": "to malign, i.e. (by extension) to fascinate (by false representations)", "kjv": "bewitch."}, "G941": {"greek": "βαστάζω", "translit": "bastázō", "pronunciation": "bas-tad'-zo", "derivation": "perhaps remotely derived from the base of (G939) (through the idea of removal);", "definition": "to lift, literally or figuratively (endure, declare, sustain, receive, etc.)", "kjv": "bear, carry, take up."}, "G942": {"greek": "βάτος", "translit": "bátos", "pronunciation": "bat'-os", "derivation": "of uncertain derivation;", "definition": "a brier shrub", "kjv": "bramble, bush."}, "G944": {"greek": "βάτραχος", "translit": "bátrachos", "pronunciation": "bat'-rakh-os", "derivation": "of uncertain derivation;", "definition": "a frog", "kjv": "frog."}, "G945": {"greek": "βαττολογέω", "translit": "battologéō", "pronunciation": "bat-tol-og-eh'-o", "derivation": "from (a proverbial stammerer) and (G3056);", "definition": "to stutter, i.e. (by implication) to prate tediously", "kjv": "use vain repetitions."}, "G946": {"greek": "βδέλυγμα", "translit": "bdélygma", "pronunciation": "bdel'-oog-mah", "derivation": "from (G948);", "definition": "a detestation, i.e. (specially) idolatry", "kjv": "abomination."}, "G947": {"greek": "βδελυκτός", "translit": "bdelyktós", "pronunciation": "bdel-ook-tos'", "derivation": "from (G948);", "definition": "detestable, i.e. (specially) idolatrous", "kjv": "abominable."}, "G948": {"greek": "βδελύσσω", "translit": "bdelýssō", "pronunciation": "bdel-oos'-so", "derivation": "from a (presumed) derivative of (to stink);", "definition": "to be disgusted, i.e. (by implication) detest (especially of idolatry)", "kjv": "abhor, abominable."}, "G949": {"greek": "βέβαιος", "translit": "bébaios", "pronunciation": "beb'-ah-yos", "derivation": "from the base of (G939) (through the idea of basality);", "definition": "stable (literally or figuratively)", "kjv": "firm, of force, stedfast, sure."}, "G950": {"greek": "βεβαιόω", "translit": "bebaióō", "pronunciation": "beb-ah-yo'-o", "derivation": "from (G949);", "definition": "to stabilitate (figuratively)", "kjv": "confirm, (e-)stablish."}, "G951": {"greek": "βεβαίωσις", "translit": "bebaíōsis", "pronunciation": "beb-ah'-yo-sis", "derivation": "from (G950);", "definition": "stabiliment", "kjv": "confirmation."}, "G952": {"greek": "βέβηλος", "translit": "bébēlos", "pronunciation": "beb'-ay-los", "derivation": "from the base of (G939) and (a threshold);", "definition": "accessible (as by crossing the door-way), i.e. (by implication, of Jewish notions) heathenish, wicked", "kjv": "profane (person)."}, "G953": {"greek": "βεβηλόω", "translit": "bebēlóō", "pronunciation": "beb-ay-lo'-o", "derivation": "from (G952);", "definition": "to desecrate", "kjv": "profane."}, "G954": {"greek": "Βεελζεβούλ", "translit": "Beelzeboúl", "pronunciation": "beh-el-zeb-ool'", "derivation": "of Chaldee origin (by parody on (G1176));", "definition": "dung-god; Beelzebul, a name of Satan", "kjv": "Beelzebub."}, "G955": {"greek": "Βελίαλ", "translit": "Belíal", "pronunciation": "bel-ee'-al", "derivation": "of Hebrew origin ((G1100));", "definition": "worthlessness; Belial, as an epithet of Satan", "kjv": "Belial."}, "G956": {"greek": "βέλος", "translit": "bélos", "pronunciation": "bel'-os", "derivation": "from (G906);", "definition": "a missile, i.e. spear or arrow", "kjv": "dart."}, "G957": {"greek": "βελτίον", "translit": "beltíon", "pronunciation": "bel-tee'-on", "derivation": "neuter of a compound of a derivative of (G906) (used for the comparative of (G18));", "definition": "better", "kjv": "very well."}, "G958": {"greek": "Βενιαμίν", "translit": "Beniamín", "pronunciation": "ben-ee-am-een'", "derivation": "of Hebrew origin ((G1144));", "definition": "Benjamin, an Israelite", "kjv": "Benjamin."}, "G959": {"greek": "Βερνίκη", "translit": "Berníkē", "pronunciation": "ber-nee'-kay", "derivation": "from a provincial form of (G5342) and (G3529);", "definition": "victorious; Bernice, a member of the Herodian family", "kjv": "Bernice."}, "G960": {"greek": "Βέροια", "translit": "Béroia", "pronunciation": "ber'-oy-ah", "derivation": "perhaps a provincial from a derivative of (G4008) (Perœa, i.e. the region beyond the coast-line);", "definition": "Berœa, a place in Macedonia", "kjv": "Berea."}, "G961": {"greek": "Βεροιαῖος", "translit": "Beroiaîos", "pronunciation": "ber-oy-ah'-yos", "derivation": "from (G960);", "definition": "a Berœoean or native of Berœa", "kjv": "of Berea."}, "G963": {"greek": "Βηθανία", "translit": "Bēthanía", "pronunciation": "bay-than-ee'-ah", "derivation": "of Chaldee origin;", "definition": "date-house; Beth-any, a place in Palestine", "kjv": "Bethany."}, "G964": {"greek": "Βηθεσδά", "translit": "Bēthesdá", "pronunciation": "bay-thes-dah'", "derivation": "of Chaldee origin (compare (G1004) and (G2617));", "definition": "house of kindness; Beth-esda, a pool in Jerusalem", "kjv": "Bethesda."}, "G965": {"greek": "Βηθλεέμ", "translit": "Bēthleém", "pronunciation": "bayth-leh-em'", "derivation": "of Hebrew origin ((G1036));", "definition": "Bethleem (i.e. Beth-lechem), a place in Palestine", "kjv": "Bethlehem."}, "G966": {"greek": "Βηθσαϊδά", "translit": "Bēthsaïdá", "pronunciation": "bayth-sahee-dah'", "derivation": "of Chaldee origin (compare (G1004) and (G6719));", "definition": "fishing-house; Bethsaida, a place in Palestine", "kjv": "Bethsaida."}, "G967": {"greek": "Βηθφαγή", "translit": "Bēthphagḗ", "pronunciation": "bayth-fag-ay'", "derivation": "of Chaldee origin (compare (G1004) and (G6291));", "definition": "fig-house; Beth-phage, a place in Palestine", "kjv": "Bethphage."}, "G968": {"greek": "βῆμα", "translit": "bēma", "pronunciation": "bay'-ma", "derivation": "from the base of (G939);", "definition": "a step, i.e. foot-breath; by implication, a rostrum, i.e. a tribunal", "kjv": "judgment-seat, set (foot) on, throne."}, "G969": {"greek": "βήρυλλος", "translit": "bḗryllos", "pronunciation": "bay'-rool-los", "derivation": "of uncertain derivation;", "definition": "a \"beryl\"", "kjv": "beryl."}, "G970": {"greek": "βία", "translit": "bía", "pronunciation": "bee'-ah", "derivation": "probably akin to (G979) (through the idea of vital activity);", "definition": "force", "kjv": "violence."}, "G971": {"greek": "βιάζω", "translit": "biázō", "pronunciation": "bee-ad'-zo", "derivation": "from (G970);", "definition": "to force, i.e. (reflexively) to crowd oneself (into), or (passively) to be seized", "kjv": "press, suffer violence."}, "G972": {"greek": "βίαιος", "translit": "bíaios", "pronunciation": "bee'-ah-yos", "derivation": "from (G970);", "definition": "violent", "kjv": "mighty."}, "G973": {"greek": "βιαστής", "translit": "biastḗs", "pronunciation": "bee-as-tace'", "derivation": "from (G971);", "definition": "a forcer, i.e. (figuratively) energetic", "kjv": "violent."}, "G974": {"greek": "βιβλιαρίδιον", "translit": "bibliarídion", "pronunciation": "bib-lee-ar-id'-ee-on", "derivation": "a diminutive of (G975);", "definition": "a booklet", "kjv": "little book."}, "G975": {"greek": "βιβλίον", "translit": "biblíon", "pronunciation": "bib-lee'-on", "derivation": "a diminutive of (G976);", "definition": "a roll", "kjv": "bill, book, scroll, writing."}, "G976": {"greek": "βίβλος", "translit": "bíblos", "pronunciation": "bib'-los", "derivation": "properly, the inner bark of the papyrus plant, i.e. (by implication) a sheet or scroll of writing", "definition": "", "kjv": "book."}, "G977": {"greek": "βιβρώσκω", "translit": "bibrṓskō", "pronunciation": "bib-ro'-sko", "derivation": "a reduplicated and prolonged form of an obsolete primary verb (perhaps causative of (G1006));", "definition": "to eat", "kjv": "eat."}, "G978": {"greek": "Βιθυνία", "translit": "Bithynía", "pronunciation": "bee-thoo-nee'-ah", "derivation": "of uncertain derivation;", "definition": "Bithynia, a region of Asia", "kjv": "Bithynia."}, "G979": {"greek": "βίος", "translit": "bíos", "pronunciation": "bee'-os", "derivation": "a primary word;", "definition": "life, i.e. (literally) the present state of existence; by implication, the means of livelihood", "kjv": "good, life, living."}, "G980": {"greek": "βιόω", "translit": "bióō", "pronunciation": "bee-o'-o", "derivation": "from (G979);", "definition": "to spend existence", "kjv": "live."}, "G981": {"greek": "βίωσις", "translit": "bíōsis", "pronunciation": "bee'-o-sis", "derivation": "from (G980);", "definition": "living (properly, the act, by implication, the mode)", "kjv": "manner of life."}, "G982": {"greek": "βιωτικός", "translit": "biōtikós", "pronunciation": "bee-o-tee-kos'", "derivation": "from a derivative of (G980);", "definition": "relating to the present existence", "kjv": "of (pertaining to, things that pertain to) this life."}, "G983": {"greek": "βλαβερός", "translit": "blaberós", "pronunciation": "blab-er-os'", "derivation": "from (G984);", "definition": "injurious", "kjv": "hurtful."}, "G984": {"greek": "βλάπτω", "translit": "bláptō", "pronunciation": "blap'-to", "derivation": "a primary verb;", "definition": "properly, to hinder, i.e. (by implication) to injure", "kjv": "hurt."}, "G985": {"greek": "βλαστάνω", "translit": "blastánō", "pronunciation": "blas-tan'-o", "derivation": "from (a sprout);", "definition": "to germinate; by implication, to yield fruit", "kjv": "bring forth, bud, spring (up)."}, "G986": {"greek": "Βλάστος", "translit": "Blástos", "pronunciation": "blas'-tos", "derivation": "perhaps the same as the base of (G985);", "definition": "Blastus, an officer of Herod Agrippa", "kjv": "Blastus."}, "G987": {"greek": "βλασφημέω", "translit": "blasphēméō", "pronunciation": "blas-fay-meh'-o", "derivation": "from (G989);", "definition": "to vilify; specially, to speak impiously", "kjv": "(speak) blaspheme(-er, -mously, -my), defame, rail on, revile, speak evil."}, "G988": {"greek": "βλασφημία", "translit": "blasphēmía", "pronunciation": "blas-fay-me'-ah", "derivation": "from (G989);", "definition": "vilification (especially against God)", "kjv": "blasphemy, evil speaking, railing."}, "G989": {"greek": "βλάσφημος", "translit": "blásphēmos", "pronunciation": "blas'-fay-mos", "derivation": "from a derivative of (G984) and (G5345);", "definition": "scurrilious, i.e. calumnious (against men), or (specially) impious (against God)", "kjv": "blasphemer(-mous), railing."}, "G990": {"greek": "βλέμμα", "translit": "blémma", "pronunciation": "blem'-mah", "derivation": "from (G991);", "definition": "vision (properly concrete; by implication, abstract)", "kjv": "seeing."}, "G991": {"greek": "βλέπω", "translit": "blépō", "pronunciation": "blep'-o", "derivation": "a primary verb;", "definition": "to look at (literally or figuratively)", "kjv": "behold, beware, lie, look (on, to), perceive, regard, see, sight, take heed."}, "G992": {"greek": "βλητέος", "translit": "blētéos", "pronunciation": "blay-teh'-os", "derivation": "from (G906);", "definition": "fit to be cast (i.e. applied)", "kjv": "must be put."}, "G993": {"greek": "Βοανεργές", "translit": "Boanergés", "pronunciation": "bo-an-erg-es'", "derivation": "of Chaldee origin ((G1123) and (G7266));", "definition": "sons of commotion; Boanerges, an epithet of two of the apostles", "kjv": "Boanerges."}, "G994": {"greek": "βοάω", "translit": "boáō", "pronunciation": "bo-ah'-o", "derivation": "apparently a prolonged form of a primary verb;", "definition": "to halloo, i.e. shout (for help or in a tumultuous way)", "kjv": "cry."}, "G995": {"greek": "βοή", "translit": "boḗ", "pronunciation": "bo-ay'", "derivation": "from (G994);", "definition": "a halloo, i.e. call (for aid, etc.)", "kjv": "cry."}, "G996": {"greek": "βοήθεια", "translit": "boḗtheia", "pronunciation": "bo-ay'-thi-ah", "derivation": "from (G998);", "definition": "aid; specially, a rope or chain for frapping a vessel", "kjv": "help."}, "G997": {"greek": "βοηθέω", "translit": "boēthéō", "pronunciation": "bo-ay-theh'-o", "derivation": "from (G998);", "definition": "to aid or relieve", "kjv": "help, succor."}, "G998": {"greek": "βοηθός", "translit": "boēthós", "pronunciation": "bo-ay-thos'", "derivation": "from (G995) and theo (to run);", "definition": "a succorer", "kjv": "helper."}, "G999": {"greek": "βόθυνος", "translit": "bóthynos", "pronunciation": "both'-oo-nos", "derivation": "akin to (G900);", "definition": "a hole (in the ground); specially, a cistern", "kjv": "ditch, pit."}, "G1000": {"greek": "βολή", "translit": "bolḗ", "pronunciation": "bol-ay'", "derivation": "from (G906);", "definition": "a throw (as a measure of distance)", "kjv": "cast."}, "G1001": {"greek": "βολίζω", "translit": "bolízō", "pronunciation": "bol-id'-zo", "derivation": "from (G1002);", "definition": "to heave the lead", "kjv": "sound."}, "G1003": {"greek": "Βοόζ", "translit": "Boóz", "pronunciation": "bo-oz'", "derivation": "of Hebrew origin ((G1162));", "definition": "Booz, (i.e. Boaz), an Israelite", "kjv": "Booz."}, "G1004": {"greek": "βόρβορος", "translit": "bórboros", "pronunciation": "bor'-bor-os", "derivation": "of uncertain derivation;", "definition": "mud", "kjv": "mire."}, "G1005": {"greek": "βοῤῥᾶς", "translit": "borrhâs", "pronunciation": "bor-hras'", "derivation": "of uncertain derivation;", "definition": "the north (properly, wind)", "kjv": "north."}, "G1006": {"greek": "βόσκω", "translit": "bóskō", "pronunciation": "bos'-ko", "derivation": "a prolonged form of a primary verb (compare (G977), (G1016));", "definition": "to pasture; by extension to, fodder; reflexively, to graze", "kjv": "feed, keep."}, "G1007": {"greek": "Βοσόρ", "translit": "Bosór", "pronunciation": "bos-or'", "derivation": "of Hebrew origin ((G1160));", "definition": "Bosor (i.e. Beor), a Moabite", "kjv": "Bosor."}, "G1008": {"greek": "βοτάνη", "translit": "botánē", "pronunciation": "bot-an'-ay", "derivation": "from (G1006);", "definition": "herbage (as if for grazing)", "kjv": "herb."}, "G1009": {"greek": "βότρυς", "translit": "bótrys", "pronunciation": "bot'-rooce", "derivation": "of uncertain derivation;", "definition": "a bunch (of grapes)", "kjv": "(vine) cluster (of the vine)."}, "G1010": {"greek": "βουλευτής", "translit": "bouleutḗs", "pronunciation": "bool-yoo-tace'", "derivation": "from (G1011);", "definition": "an adviser, i.e. (specially) a councillor or member of the Jewish Sanhedrin", "kjv": "counsellor."}, "G1011": {"greek": "βουλεύω", "translit": "bouleúō", "pronunciation": "bool-yoo'-o", "derivation": "from (G1012);", "definition": "to advise, i.e. (reflexively) deliberate, or (by implication) resolve", "kjv": "consult, take counsel, determine, be minded, purpose."}, "G1012": {"greek": "βουλή", "translit": "boulḗ", "pronunciation": "boo-lay'", "derivation": "from (G1014);", "definition": "volition, i.e. (objectively) advice, or (by implication) purpose", "kjv": "+ advise, counsel, will."}, "G1013": {"greek": "βούλημα", "translit": "boúlēma", "pronunciation": "boo'-lay-mah", "derivation": "from (G1014);", "definition": "a resolve", "kjv": "purpose, will."}, "G1014": {"greek": "βούλομαι", "translit": "boúlomai", "pronunciation": "boo'-lom-ahee", "derivation": "middle voice of a primary verb;", "definition": "to \"will,\" i.e. (reflexively) be willing", "kjv": "be disposed, minded, intend, list, (be, of own) will (-ing)."}, "G1015": {"greek": "βουνός", "translit": "bounós", "pronunciation": "boo-nos'", "derivation": "probably of foreign origin;", "definition": "a hillock", "kjv": "hill."}, "G1016": {"greek": "βοῦς", "translit": "boûs", "pronunciation": "booce", "derivation": "probably from the base of (G1006);", "definition": "an ox (as grazing), i.e. an animal of that species (\"beef\")", "kjv": "ox."}, "G1017": {"greek": "βραβεῖον", "translit": "brabeîon", "pronunciation": "brab-i'-on", "derivation": "from (an umpire of uncertain derivation);", "definition": "an award (of arbitration), i.e. (specially) a prize in the public games", "kjv": "prize."}, "G1018": {"greek": "βραβεύω", "translit": "brabeúō", "pronunciation": "brab-yoo'-o", "derivation": "from the same as (G1017);", "definition": "to arbitrate, i.e. (genitive case) to govern (figuratively, prevail)", "kjv": "rule."}, "G1019": {"greek": "βραδύνω", "translit": "bradýnō", "pronunciation": "brad-oo'-no", "derivation": "from (G1021);", "definition": "to delay", "kjv": "be slack, tarry."}, "G1020": {"greek": "βραδυπλοέω", "translit": "bradyploéō", "pronunciation": "brad-oo-plo-eh'-o", "derivation": "from (G1021) and a prolonged form of (G4126);", "definition": "to sail slowly", "kjv": "sail slowly."}, "G1021": {"greek": "βραδύς", "translit": "bradýs", "pronunciation": "brad-ooce'", "derivation": "of uncertain affinity;", "definition": "slow; figuratively, dull", "kjv": "slow."}, "G1022": {"greek": "βραδύτης", "translit": "bradýtēs", "pronunciation": "brad-oo'-tace", "derivation": "from (G1021);", "definition": "tardiness", "kjv": "slackness."}, "G1023": {"greek": "βραχίων", "translit": "brachíōn", "pronunciation": "brakh-ee'-own", "derivation": "properly, comparative of (G1024), but apparently in the sense of (to wield);", "definition": "the arm, i.e. (figuratively) strength", "kjv": "arm."}, "G1024": {"greek": "βραχύς", "translit": "brachýs", "pronunciation": "brakh-ooce'", "derivation": "of uncertain affinity;", "definition": "short (of time, place, quantity, or number)", "kjv": "few words, little (space, while)."}, "G1025": {"greek": "βρέφος", "translit": "bréphos", "pronunciation": "bref'-os", "derivation": "of uncertain affinity;", "definition": "an infant (properly, unborn) literally or figuratively", "kjv": "babe, (young) child, infant."}, "G1026": {"greek": "βρέχω", "translit": "bréchō", "pronunciation": "brekh'-o", "derivation": "a primary verb;", "definition": "to moisten (especially by a shower)", "kjv": "(send) rain, wash."}, "G1027": {"greek": "βροντή", "translit": "brontḗ", "pronunciation": "bron-tay'", "derivation": "akin to (to roar);", "definition": "thunder", "kjv": "thunder(-ing)."}, "G1028": {"greek": "βροχή", "translit": "brochḗ", "pronunciation": "brokh-ay'", "derivation": "from (G1026);", "definition": "rain", "kjv": "rain."}, "G1029": {"greek": "βρόχος", "translit": "bróchos", "pronunciation": "brokh'-os", "derivation": "of uncertain derivation;", "definition": "a noose", "kjv": "snare."}, "G1030": {"greek": "βρυγμός", "translit": "brygmós", "pronunciation": "broog-mos'", "derivation": "from (G1031);", "definition": "a grating (of the teeth)", "kjv": "gnashing."}, "G1031": {"greek": "βρύχω", "translit": "brýchō", "pronunciation": "broo'-kho", "derivation": "a primary verb;", "definition": "to grate the teeth (in pain or rage)", "kjv": "gnash."}, "G1032": {"greek": "βρύω", "translit": "brýō", "pronunciation": "broo'-o", "derivation": "a primary verb;", "definition": "to swell out, i.e. (by implication) to gush", "kjv": "send forth."}, "G1033": {"greek": "βρῶμα", "translit": "brōma", "pronunciation": "bro'-mah", "derivation": "from the base of (G977);", "definition": "food (literally or figuratively), especially (ceremonially) articles allowed or forbidden by the Jewish law", "kjv": "meat, victuals."}, "G1034": {"greek": "βρώσιμος", "translit": "brṓsimos", "pronunciation": "bro'-sim-os", "derivation": "from (G1035);", "definition": "eatable", "kjv": "meat."}, "G1035": {"greek": "βρῶσις", "translit": "brōsis", "pronunciation": "bro'-sis", "derivation": "from the base of (G977);", "definition": "(abstractly) eating (literally or figuratively); by extension (concretely) food (literally or figuratively)", "kjv": "eating, food, meat."}, "G1036": {"greek": "βυθίζω", "translit": "bythízō", "pronunciation": "boo-thid'-zo", "derivation": "from (G1037);", "definition": "to sink; by implication, to drown", "kjv": "begin to sink, drown."}, "G1037": {"greek": "βυθός", "translit": "bythós", "pronunciation": "boo-thos'", "derivation": "a variation of (G899);", "definition": "depth, i.e. (by implication) the sea", "kjv": "deep."}, "G1038": {"greek": "βυρσεύς", "translit": "byrseús", "pronunciation": "boorce-yooce'", "derivation": "from (a hide);", "definition": "a tanner", "kjv": "tanner."}, "G1039": {"greek": "βύσσινος", "translit": "býssinos", "pronunciation": "boos'-see-nos", "derivation": "from (G1040);", "definition": "made of linen (neuter a linen cloth)", "kjv": "fine linen."}, "G1040": {"greek": "βύσσος", "translit": "býssos", "pronunciation": "boos'-sos", "derivation": "of Hebrew origin ((G948));", "definition": "white linen", "kjv": "fine linen."}, "G1041": {"greek": "βωμός", "translit": "bōmós", "pronunciation": "bo'-mos", "derivation": "from the base of (G939);", "definition": "properly, a stand, i.e. (specially) an altar", "kjv": "altar."}, "G1042": {"greek": "γαββαθά", "translit": "gabbathá", "pronunciation": "gab-bath-ah'", "derivation": "of Chaldee origin (compare (G1355));", "definition": "the knoll; gabbatha, a vernacular term for the Roman tribunal in Jerusalem", "kjv": "Gabbatha."}, "G1043": {"greek": "Γαβριήλ", "translit": "Gabriḗl", "pronunciation": "gab-ree-ale'", "derivation": "of Hebrew origin ((G1403));", "definition": "Gabriel, an archangel", "kjv": "Gabriel."}, "G1044": {"greek": "γάγγραινα", "translit": "gángraina", "pronunciation": "gang'-grahee-nah", "derivation": "from (to gnaw);", "definition": "an ulcer (\"gangrene\")", "kjv": "canker."}, "G1045": {"greek": "Γάδ", "translit": "Gád", "pronunciation": "gad", "derivation": "of Hebrew origin ((G1410));", "definition": "Gad, a tribe of Israelites", "kjv": "Gad."}, "G1046": {"greek": "Γαδαρηνός", "translit": "Gadarēnós", "pronunciation": "gad-ar-ay-nos'", "derivation": "from (a town east of the Jordan);", "definition": "a Gadarene or inhabitant of Gadara", "kjv": "Gadarene."}, "G1047": {"greek": "γάζα", "translit": "gáza", "pronunciation": "gad'-zah", "derivation": "of foreign origin;", "definition": "a treasure", "kjv": "treasure."}, "G1049": {"greek": "γαζοφυλάκιον", "translit": "gazophylákion", "pronunciation": "gad-zof-oo-lak'-ee-on", "derivation": "from (G1047) and (G5438);", "definition": "a treasure-house, i.e. a court in the temple for the collection-boxes", "kjv": "treasury."}, "G1050": {"greek": "Γάϊος", "translit": "Gáïos", "pronunciation": "gah'-ee-os", "derivation": "of Latin origin;", "definition": "Gaius (i.e. Caius), a Christian", "kjv": "Gaius."}, "G1051": {"greek": "γάλα", "translit": "gála", "pronunciation": "gal'-ah", "derivation": "of uncertain affinity;", "definition": "milk (figuratively)", "kjv": "milk."}, "G1052": {"greek": "Γαλάτης", "translit": "Galátēs", "pronunciation": "gal-at'-ace", "derivation": "from (G1053);", "definition": "a Galatian or inhabitant of Galatia", "kjv": "Galatian."}, "G1053": {"greek": "Γαλατία", "translit": "Galatía", "pronunciation": "gal-at-ee'-ah", "derivation": "of foreign origin;", "definition": "Galatia, a region of Asia", "kjv": "Galatia."}, "G1054": {"greek": "Γαλατικός", "translit": "Galatikós", "pronunciation": "gal-at-ee-kos'", "derivation": "from (G1053);", "definition": "Galatic or relating to Galatia", "kjv": "of Galatia."}, "G1055": {"greek": "γαλήνη", "translit": "galḗnē", "pronunciation": "gal-ay'-nay", "derivation": "of uncertain derivation;", "definition": "tranquillity", "kjv": "calm."}, "G1056": {"greek": "Γαλιλαία", "translit": "Galilaía", "pronunciation": "gal-il-ah'-yah", "derivation": "of Hebrew origin ((G1551));", "definition": "Galilæa (i.e. the heathen circle), a region of Palestine", "kjv": "Galilee."}, "G1057": {"greek": "Γαλιλαῖος", "translit": "Galilaîos", "pronunciation": "gal-ee-lah'-yos", "derivation": "from (G1056);", "definition": "Galilean or belonging to Galilea", "kjv": "Galilean, of Galilee."}, "G1058": {"greek": "Γαλλίων", "translit": "Gallíōn", "pronunciation": "gal-lee'-own", "derivation": "of Latin origin;", "definition": "Gallion (i.e. Gallio), a Roman officer", "kjv": "Gallio."}, "G1059": {"greek": "Γαμαλιήλ", "translit": "Gamaliḗl", "pronunciation": "gam-al-ee-ale'", "derivation": "of Hebrew origin ((G1583));", "definition": "Gamaliel (i.e. Gamliel), an Israelite", "kjv": "Gamaliel."}, "G1060": {"greek": "γαμέω", "translit": "gaméō", "pronunciation": "gam-eh'-o", "derivation": "from (G1062);", "definition": "to wed (of either sex)", "kjv": "marry (a wife)."}, "G1061": {"greek": "γαμίσκω", "translit": "gamískō", "pronunciation": "gam-is'-ko", "derivation": "from (G1062);", "definition": "to espouse (a daughter to a husband)", "kjv": "give in marriage."}, "G1062": {"greek": "γάμος", "translit": "gámos", "pronunciation": "gam'-os", "derivation": "of uncertain affinity;", "definition": "nuptials", "kjv": "marriage, wedding."}, "G1063": {"greek": "γάρ", "translit": "gár", "pronunciation": "gar", "derivation": "a primary particle;", "definition": "properly, assigning a reason (used in argument, explanation or intensification; often with other particles)", "kjv": "and, as, because (that), but, even, for, indeed, no doubt, seeing, then, therefore, verily, what, why, yet."}, "G1064": {"greek": "γαστήρ", "translit": "gastḗr", "pronunciation": "gas-tare'", "derivation": "of uncertain derivation;", "definition": "the stomach; by analogy, the matrix; figuratively, a gourmand", "kjv": "belly, + with child, womb."}, "G1065": {"greek": "γέ", "translit": "gé", "pronunciation": "gheh", "derivation": "a primary particle of emphasis or qualification (often used with other particles prefixed)", "definition": "", "kjv": "and besides, doubtless, at least, yet."}, "G1066": {"greek": "Γεδεών", "translit": "Gedeṓn", "pronunciation": "ghed-eh-own'", "derivation": "of Hebrew origin ((G1439));", "definition": "Gedeon (i.e. Gid(e)on), an Israelite", "kjv": "Gedeon (in the King James Version)."}, "G1067": {"greek": "γέεννα", "translit": "géenna", "pronunciation": "gheh'-en-nah", "derivation": "of Hebrew origin ((G1516) and (G2011));", "definition": "valley of (the son of) Hinnom; ge-henna (or Ge-Hinnom), a valley of Jerusalem, used (figuratively) as a name for the place (or state) of everlasting punishment", "kjv": "hell."}, "G1068": {"greek": "Γεθσημανῆ", "translit": "Gethsēmanē", "pronunciation": "gheth-say-man-ay'", "derivation": "of Chaldee origin (compare (G1660) and (G8081));", "definition": "oil-press; Gethsemane, a garden near Jerusalem", "kjv": "Gethsemane."}, "G1069": {"greek": "γείτων", "translit": "geítōn", "pronunciation": "ghi'-tone", "derivation": "from (G1093);", "definition": "a neighbour (as adjoining one's ground); by implication, a friend", "kjv": "neighbour."}, "G1070": {"greek": "γελάω", "translit": "geláō", "pronunciation": "ghel-ah'-o", "derivation": "of uncertain affinity;", "definition": "to laugh (as a sign of joy or satisfaction)", "kjv": "laugh."}, "G1071": {"greek": "γέλως", "translit": "gélōs", "pronunciation": "ghel'-os", "derivation": "from (G1070);", "definition": "laughter (as a mark of gratification)", "kjv": "laughter."}, "G1072": {"greek": "γεμίζω", "translit": "gemízō", "pronunciation": "ghem-id'-zo", "derivation": "transitive from (G1073);", "definition": "to fill entirely", "kjv": "fill (be) full."}, "G1073": {"greek": "γέμω", "translit": "gémō", "pronunciation": "ghem'-o", "derivation": "a primary verb;", "definition": "to swell out, i.e. be full", "kjv": "be full."}, "G1074": {"greek": "γενεά", "translit": "geneá", "pronunciation": "ghen-eh-ah'", "derivation": "from (a presumed derivative of) (G1085);", "definition": "a generation; by implication, an age (the period or the persons)", "kjv": "age, generation, nation, time."}, "G1075": {"greek": "γενεαλογέω", "translit": "genealogéō", "pronunciation": "ghen-eh-al-og-eh'-o", "derivation": "from (G1074) and (G3056);", "definition": "to reckon by generations, i.e. trace in genealogy", "kjv": "count by descent."}, "G1076": {"greek": "γενεαλογία", "translit": "genealogía", "pronunciation": "ghen-eh-al-og-ee'-ah", "derivation": "from the same as (G1075);", "definition": "tracing by generations, i.e. \"genealogy\"", "kjv": "genealogy."}, "G1077": {"greek": "γενέσια", "translit": "genésia", "pronunciation": "ghen-es'-ee-ah", "derivation": "neuter plural of a derivative of (G1078);", "definition": "birthday ceremonies", "kjv": "birthday."}, "G1078": {"greek": "γένεσις", "translit": "génesis", "pronunciation": "ghen'-es-is", "derivation": "from the same as (G1074);", "definition": "nativity; figuratively, nature", "kjv": "generation, nature(-ral)."}, "G1079": {"greek": "γενετή", "translit": "genetḗ", "pronunciation": "ghen-et-ay", "derivation": "feminine of a presumed derivative of the base of (G1074);", "definition": "birth", "kjv": "birth."}, "G1080": {"greek": "γεννάω", "translit": "gennáō", "pronunciation": "ghen-nah'-o", "derivation": "from a variation of (G1085);", "definition": "to procreate (properly, of the father, but by extension of the mother); figuratively, to regenerate", "kjv": "bear, beget, be born, bring forth, conceive, be delivered of, gender, make, spring."}, "G1081": {"greek": "γέννημα", "translit": "génnēma", "pronunciation": "ghen'-nay-mah", "derivation": "from (G1080);", "definition": "offspring; by analogy, produce (literally or figuratively)", "kjv": "fruit, generation."}, "G1082": {"greek": "Γεννησαρέτ", "translit": "Gennēsarét", "pronunciation": "ghen-nay-sar-et'", "derivation": "of Hebrew origin (compare (G3672));", "definition": "Gennesaret (i.e. Kinnereth), a lake and plain in Palestine", "kjv": "Gennesaret."}, "G1084": {"greek": "γεννητός", "translit": "gennētós", "pronunciation": "ghen-nay-tos'", "derivation": "from (G1080);", "definition": "born", "kjv": "they that are born."}, "G1085": {"greek": "γένος", "translit": "génos", "pronunciation": "ghen'-os", "derivation": "from (G1096);", "definition": "\"kin\" (abstract or concrete, literal or figurative, individual or collective)", "kjv": "born, country(-man), diversity, generation, kind(-red), nation, offspring, stock."}, "G1086": {"greek": "Γεργεσηνός", "translit": "Gergesēnós", "pronunciation": "gher-ghes-ay-nos'", "derivation": "of Hebrew origin ((G1622));", "definition": "a Gergesene (i.e. Girgashite) or one of the aborigines of Palestine", "kjv": "Gergesene."}, "G1087": {"greek": "γερουσία", "translit": "gerousía", "pronunciation": "gher-oo-see'-ah", "derivation": "from (G1088);", "definition": "the eldership, i.e. (collectively) the Jewish Sanhedrin", "kjv": "senate."}, "G1088": {"greek": "γέρων", "translit": "gérōn", "pronunciation": "gher'-own", "derivation": "of uncertain affinity (compare (G1094));", "definition": "aged", "kjv": "old."}, "G1089": {"greek": "γεύομαι", "translit": "geúomai", "pronunciation": "ghyoo'-om-ahee", "derivation": "a primary verb;", "definition": "to taste; by implication, to eat; figuratively, to experience (good or ill)", "kjv": "eat, taste."}, "G1090": {"greek": "γεωργέω", "translit": "geōrgéō", "pronunciation": "gheh-or-gheh'-o", "derivation": "from (G1092);", "definition": "to till (the soil)", "kjv": "dress."}, "G1091": {"greek": "γεώργιον", "translit": "geṓrgion", "pronunciation": "gheh-ore'-ghee-on", "derivation": "neuter of a (presumed) derivative of (G1092);", "definition": "cultivable, i.e. a farm", "kjv": "husbandry."}, "G1092": {"greek": "γεωργός", "translit": "geōrgós", "pronunciation": "gheh-ore-gos'", "derivation": "from (G1093) and the base of (G2041);", "definition": "a land-worker, i.e. farmer", "kjv": "husbandman."}, "G1093": {"greek": "γῆ", "translit": "gē", "pronunciation": "ghay", "derivation": "contracted from a primary word;", "definition": "soil; by extension a region, or the solid part or the whole of the terrene globe (including the occupants in each application)", "kjv": "country, earth(-ly), ground, land, world."}, "G1094": {"greek": "γῆρας", "translit": "gēras", "pronunciation": "ghay'-ras", "derivation": "akin to (G1088);", "definition": "senility", "kjv": "old age."}, "G1095": {"greek": "γηράσκω", "translit": "gēráskō", "pronunciation": "ghay-ras'-ko", "derivation": "from (G1094);", "definition": "to be senescent", "kjv": "be (wax) old."}, "G1096": {"greek": "γίνομαι", "translit": "gínomai", "pronunciation": "ghin'-om-ahee", "derivation": "a prolongation and middle voice form of a primary verb;", "definition": "to cause to be (\"gen\"-erate), i.e. (reflexively) to become (come into being), used with great latitude (literal, figurative, intensive, etc.)", "kjv": "arise, be assembled, be(-come, -fall, -have self), be brought (to pass), (be) come (to pass), continue, be divided, draw, be ended, fall, be finished, follow, be found, be fulfilled, + God forbid, grow, happen, have, be kept, be made, be married, be ordained to be, partake, pass, be performed, be published, require, seem, be showed, X soon as it was, sound, be taken, be turned, use, wax, will, would, be wrought."}, "G1097": {"greek": "γινώσκω", "translit": "ginṓskō", "pronunciation": "ghin-oce'-ko", "derivation": "a prolonged form of a primary verb;", "definition": "to \"know\" (absolutely) in a great variety of applications and with many implications (as follow, with others not thus clearly expressed)", "kjv": "allow, be aware (of), feel, (have) know(-ledge), perceived, be resolved, can speak, be sure, understand."}, "G1098": {"greek": "γλεῦκος", "translit": "gleûkos", "pronunciation": "glyoo'-kos", "derivation": "akin to (G1099);", "definition": "sweet wine, i.e. (properly) must (fresh juice), but used of the more saccharine (and therefore highly inebriating) fermented wine", "kjv": "new wine."}, "G1099": {"greek": "γλυκύς", "translit": "glykýs", "pronunciation": "gloo-koos'", "derivation": "of uncertain affinity;", "definition": "sweet (i.e. not bitter nor salt)", "kjv": "sweet, fresh."}, "G1100": {"greek": "γλῶσσα", "translit": "glōssa", "pronunciation": "gloce-sah'", "derivation": "of uncertain affinity;", "definition": "the tongue; by implication, a language (specially, one naturally unacquired)", "kjv": "tongue."}, "G1101": {"greek": "γλωσσόκομον", "translit": "glōssókomon", "pronunciation": "gloce-sok'-om-on", "derivation": "from (G1100) and the base of (G2889);", "definition": "properly, a case (to keep mouthpieces of wind-instruments in) i.e. (by extension) a casket or (specially) purse", "kjv": "bag."}, "G1102": {"greek": "γναφεύς", "translit": "gnapheús", "pronunciation": "gnaf-yuce'", "derivation": "by variation for a derivative from (to tease cloth);", "definition": "a cloth-dresser", "kjv": "fuller."}, "G1103": {"greek": "γνήσιος", "translit": "gnḗsios", "pronunciation": "gnay'-see-os", "derivation": "from the same as (G1077);", "definition": "legitimate (of birth), i.e. genuine", "kjv": "own, sincerity, true."}, "G1104": {"greek": "γνησίως", "translit": "gnēsíōs", "pronunciation": "gnay-see'-ose", "derivation": "adverb from (G1103);", "definition": "genuinely, i.e. really", "kjv": "naturally."}, "G1105": {"greek": "γνόφος", "translit": "gnóphos", "pronunciation": "gnof'-os", "derivation": "akin to (G3509);", "definition": "gloom (as of a storm)", "kjv": "blackness."}, "G1106": {"greek": "γνώμη", "translit": "gnṓmē", "pronunciation": "gno'-may", "derivation": "from (G1097);", "definition": "cognition, i.e. (subjectively) opinion, or (objectively) resolve (counsel, consent, etc.)", "kjv": "advice, + agree, judgment, mind, purpose, will."}, "G1107": {"greek": "γνωρίζω", "translit": "gnōrízō", "pronunciation": "gno-rid'-zo", "derivation": "from a derivative of (G1097);", "definition": "to make known; subjectively, to know", "kjv": "certify, declare, make known, give to understand, do to wit, wot."}, "G1108": {"greek": "γνῶσις", "translit": "gnōsis", "pronunciation": "gno'-sis", "derivation": "from (G1097);", "definition": "knowing (the act), i.e. (by implication) knowledge", "kjv": "knowledge, science."}, "G1109": {"greek": "γνώστης", "translit": "gnṓstēs", "pronunciation": "gnoce'-tace", "derivation": "from (G1097);", "definition": "a knower", "kjv": "expert."}, "G1110": {"greek": "γνωστός", "translit": "gnōstós", "pronunciation": "gnoce-tos'", "derivation": "from (G1097);", "definition": "well-known", "kjv": "acquaintance, (which may be) known, notable."}, "G1111": {"greek": "γογγύζω", "translit": "gongýzō", "pronunciation": "gong-good'-zo", "derivation": "of uncertain derivation;", "definition": "to grumble", "kjv": "murmur."}, "G1112": {"greek": "γογγυσμός", "translit": "gongysmós", "pronunciation": "gong-goos-mos'", "derivation": "from (G1111);", "definition": "a grumbling", "kjv": "grudging, murmuring."}, "G1113": {"greek": "γογγυστής", "translit": "gongystḗs", "pronunciation": "gong-goos-tace'", "derivation": "from (G1111);", "definition": "a grumbler", "kjv": "murmurer."}, "G1114": {"greek": "γόης", "translit": "góēs", "pronunciation": "go'-ace", "derivation": "from (to wail);", "definition": "properly, a wizard (as muttering spells), i.e. (by implication) an imposter", "kjv": "seducer."}, "G1115": {"greek": "Γολγοθᾶ", "translit": "Golgothâ", "pronunciation": "gol-goth-ah'", "derivation": "of Chaldee origin (compare (G1538));", "definition": "the skull; Golgotha, a knoll near Jerusalem", "kjv": "Golgotha."}, "G1116": {"greek": "Γόμοῤῥα", "translit": "Gómorrha", "pronunciation": "gom'-or-hrhah", "derivation": "of Hebrew origin ((G6017));", "definition": "Gomorrha (i.e. Amorah), a place near the Dead Sea", "kjv": "Gomorrha."}, "G1117": {"greek": "γόμος", "translit": "gómos", "pronunciation": "gom'-os", "derivation": "from (G1073);", "definition": "a load (as filling), i.e. (specially) a cargo, or (by extension) wares", "kjv": "burden, merchandise."}, "G1118": {"greek": "γονεύς", "translit": "goneús", "pronunciation": "gon-yooce'", "derivation": "from the base of (G1096);", "definition": "a parent", "kjv": "parent."}, "G1119": {"greek": "γόνυ", "translit": "góny", "pronunciation": "gon-oo'", "derivation": "of uncertain affinity;", "definition": "the \"knee\"", "kjv": "knee(X -l)."}, "G1120": {"greek": "γονυπετέω", "translit": "gonypetéō", "pronunciation": "gon-oo-pet-eh'-o", "derivation": "from a compound of (G1119) and the alternate of (G4098);", "definition": "to fall on the knee", "kjv": "bow the knee, kneel down."}, "G1121": {"greek": "γράμμα", "translit": "grámma", "pronunciation": "gram'-mah", "derivation": "from (G1125);", "definition": "a writing, i.e. a letter, note, epistle, book, etc.; plural learning", "kjv": "bill, learning, letter, scripture, writing, written."}, "G1122": {"greek": "γραμματεύς", "translit": "grammateús", "pronunciation": "gram-mat-yooce'", "derivation": "from (G1121). a writer, i.e. (professionally) scribe or secretary", "definition": "", "kjv": "scribe, town-clerk."}, "G1123": {"greek": "γραπτός", "translit": "graptós", "pronunciation": "grap-tos'", "derivation": "from (G1125);", "definition": "inscribed (figuratively)", "kjv": "written."}, "G1124": {"greek": "γραφή", "translit": "graphḗ", "pronunciation": "graf-ay'", "derivation": "from (G1125);", "definition": "a document, i.e. holy Writ (or its contents or a statement in it)", "kjv": "scripture."}, "G1125": {"greek": "γράφω", "translit": "gráphō", "pronunciation": "graf'-o", "derivation": "a primary verb;", "definition": "to \"grave\", especially to write; figuratively, to describe", "kjv": "describe, write(-ing, -ten)."}, "G1126": {"greek": "γραώδης", "translit": "graṓdēs", "pronunciation": "grah-o'-dace", "derivation": "from (an old woman) and (G1491);", "definition": "crone-like, i.e. silly", "kjv": "old wives'."}, "G1127": {"greek": "γρηγορεύω", "translit": "grēgoreúō", "pronunciation": "gray-gor-yoo'-o", "derivation": "from (G1453);", "definition": "to keep awake, i.e. watch (literally or figuratively)", "kjv": "be vigilant, wake, (be) watch(-ful)."}, "G1128": {"greek": "γυμνάζω", "translit": "gymnázō", "pronunciation": "goom-nad'-zo", "derivation": "from (G1131);", "definition": "to practise naked (in the games), i.e. train (figuratively)", "kjv": "exercise."}, "G1129": {"greek": "γυμνασία", "translit": "gymnasía", "pronunciation": "goom-nas-ee'-ah", "derivation": "from (G1128);", "definition": "training, i.e. (figuratively) asceticism", "kjv": "exercise."}, "G1130": {"greek": "γυμνητεύω", "translit": "gymnēteúō", "pronunciation": "goom-nayt-yoo'-o", "derivation": "from a derivative of (G1131);", "definition": "to strip, i.e. (reflexively) go poorly clad", "kjv": "be naked."}, "G1131": {"greek": "γυμνός", "translit": "gymnós", "pronunciation": "goom-nos'", "derivation": "of uncertain affinity;", "definition": "nude (absolute or relative, literal or figurative)", "kjv": "naked."}, "G1132": {"greek": "γυμνότης", "translit": "gymnótēs", "pronunciation": "goom-not'-ace", "derivation": "from (G1131);", "definition": "nudity (absolute or comparative)", "kjv": "nakedness."}, "G1133": {"greek": "γυναικάριον", "translit": "gynaikárion", "pronunciation": "goo-nahee-kar'-ee-on", "derivation": "a diminutive from (G1135);", "definition": "a little (i.e. foolish) woman", "kjv": "silly woman."}, "G1134": {"greek": "γυναικεῖος", "translit": "gynaikeîos", "pronunciation": "goo-nahee-ki'-os", "derivation": "from (G1135);", "definition": "feminine", "kjv": "wife."}, "G1135": {"greek": "γυνή", "translit": "gynḗ", "pronunciation": "goo-nay'", "derivation": "probably from the base of (G1096);", "definition": "a woman; specially, a wife", "kjv": "wife, woman."}, "G1136": {"greek": "Γώγ", "translit": "Gṓg", "pronunciation": "gogue", "derivation": "of Hebrew origin ((G1463));", "definition": "Gog, a symbolic name for some future Antichrist", "kjv": "Gog."}, "G1137": {"greek": "γωνία", "translit": "gōnía", "pronunciation": "go-nee'-ah", "derivation": "probably akin to (G1119);", "definition": "an angle", "kjv": "corner, quarter."}, "G1138": {"greek": "Δαβίδ", "translit": "Dabíd", "pronunciation": "dab-eed'", "derivation": "of Hebrew origin ((G1732));", "definition": "Dabid (i.e. David), the Israelite king", "kjv": "David."}, "G1139": {"greek": "δαιμονίζομαι", "translit": "daimonízomai", "pronunciation": "dahee-mon-id'-zom-ahee", "derivation": "middle voice from (G1142);", "definition": "to be exercised by a dæmon", "kjv": "have a (be vexed with, be possessed with) devil(-s)."}, "G1140": {"greek": "δαιμόνιον", "translit": "daimónion", "pronunciation": "dahee-mon'-ee-on", "derivation": "neuter of a derivative of (G1142);", "definition": "a dæmonic being; by extension a deity", "kjv": "devil, god."}, "G1141": {"greek": "δαιμονιώδης", "translit": "daimoniṓdēs", "pronunciation": "dahee-mon-ee-o'-dace", "derivation": "from (G1140) and (G1142);", "definition": "dæmon-like", "kjv": "devilish."}, "G1142": {"greek": "δαίμων", "translit": "daímōn", "pronunciation": "dah'-ee-mown", "derivation": "from (to distribute fortunes);", "definition": "a dæmon or supernatural spirit (of a bad nature)", "kjv": "devil."}, "G1143": {"greek": "δάκνω", "translit": "dáknō", "pronunciation": "dak'-no", "derivation": "a prolonged form of a primary root;", "definition": "to bite, i.e. (figuratively) thwart", "kjv": "bite."}, "G1144": {"greek": "δάκρυ", "translit": "dákry", "pronunciation": "dak'-roo", "derivation": "of uncertain affinity;", "definition": "a tear", "kjv": "tear."}, "G1145": {"greek": "δακρύω", "translit": "dakrýō", "pronunciation": "dak-roo'-o", "derivation": "from (G1144);", "definition": "to shed tears", "kjv": "weep."}, "G1146": {"greek": "δακτύλιος", "translit": "daktýlios", "pronunciation": "dak-too'-lee-os", "derivation": "from (G1147);", "definition": "a finger-ring", "kjv": "ring."}, "G1147": {"greek": "δάκτυλος", "translit": "dáktylos", "pronunciation": "dak'-too-los", "derivation": "probably from (G1176);", "definition": "a finger", "kjv": "finger."}, "G1148": {"greek": "Δαλμανουθά", "translit": "Dalmanouthá", "pronunciation": "dal-man-oo-thah'", "derivation": "probably of Chaldee origin;", "definition": "Dalmanutha, a place in Palestine", "kjv": "Dalmanutha."}, "G1149": {"greek": "Δαλματία", "translit": "Dalmatía", "pronunciation": "dal-mat-ee'-ah", "derivation": "probably of foreign derivation;", "definition": "Dalmatia, a region of Europe", "kjv": "Dalmatia."}, "G1150": {"greek": "δαμάζω", "translit": "damázō", "pronunciation": "dam-ad'-zo", "derivation": "a variation of an obsolete primary of the same meaning;", "definition": "to tame", "kjv": "tame."}, "G1151": {"greek": "δάμαλις", "translit": "dámalis", "pronunciation": "dam'-al-is", "derivation": "probably from the base of (G1150);", "definition": "a heifer (as tame)", "kjv": "heifer."}, "G1152": {"greek": "Δάμαρις", "translit": "Dámaris", "pronunciation": "dam'-ar-is", "derivation": "probably from the base of (G1150);", "definition": "perhaps gentle; Damaris, an Athenian woman", "kjv": "Damaris."}, "G1153": {"greek": "Δαμασκηνός", "translit": "Damaskēnós", "pronunciation": "dam-as-kay-nos'", "derivation": "from (G1154);", "definition": "a Damascene or inhabitant of Damascus", "kjv": "Damascene."}, "G1154": {"greek": "Δαμασκός", "translit": "Damaskós", "pronunciation": "dam-as-kos'", "derivation": "of Hebrew origin ((G1834));", "definition": "Damascus, a city of Syria", "kjv": "Damascus."}, "G1155": {"greek": "δανείζω", "translit": "daneízō", "pronunciation": "dan-ide'-zo", "derivation": "from (G1156);", "definition": "to loan on interest; reflexively, to borrow", "kjv": "borrow, lend."}, "G1156": {"greek": "δάνειον", "translit": "dáneion", "pronunciation": "dan'-i-on", "derivation": "from (a gift);", "definition": "probably akin to the base of (G1325); a loan", "kjv": "debt."}, "G1157": {"greek": "δανειστής", "translit": "daneistḗs", "pronunciation": "dan-ice-tace'", "derivation": "from (G1155);", "definition": "a lender", "kjv": "creditor."}, "G1158": {"greek": "Δανιήλ", "translit": "Daniḗl", "pronunciation": "dan-ee-ale'", "derivation": "of Hebrew origin ((G1840));", "definition": "Daniel, an Israelite", "kjv": "Daniel."}, "G1159": {"greek": "δαπανάω", "translit": "dapanáō", "pronunciation": "dap-an-ah'-o", "derivation": "from (G1160);", "definition": "to expend, i.e. (in a good sense) to incur cost, or (in a bad one) to waste", "kjv": "be at charges, consume, spend."}, "G1160": {"greek": "δαπάνη", "translit": "dapánē", "pronunciation": "dap-an'-ay", "derivation": "from (to devour);", "definition": "expense (as consuming)", "kjv": "cost."}, "G1161": {"greek": "δέ", "translit": "dé", "pronunciation": "deh", "derivation": "a primary particle (adversative or continuative);", "definition": "but, and, etc.", "kjv": "also, and, but, moreover, now (often unexpressed in English)."}, "G1162": {"greek": "δέησις", "translit": "déēsis", "pronunciation": "deh'-ay-sis", "derivation": "from (G1189);", "definition": "a petition", "kjv": "prayer, request, supplication."}, "G1163": {"greek": "δεῖ", "translit": "deî", "pronunciation": "die", "derivation": "3rd person singular active present of (G1210);", "definition": "also ; neuter active participle of the same; both used impersonally; it is (was, etc.) necessary (as binding)", "kjv": "behoved, be meet, must (needs), (be) need(-ful), ought, should."}, "G1164": {"greek": "δεῖγμα", "translit": "deîgma", "pronunciation": "digh'-mah", "derivation": "from the base of (G1166);", "definition": "a specimen (as shown)", "kjv": "example."}, "G1165": {"greek": "δειγματίζω", "translit": "deigmatízō", "pronunciation": "digh-mat-id'-zo", "derivation": "from (G1164);", "definition": "to exhibit", "kjv": "make a shew."}, "G1166": {"greek": "δεικνύω", "translit": "deiknýō", "pronunciation": "dike-noo'-o", "derivation": "a prolonged form of an obsolete primary of the same meaning;", "definition": "to show (literally or figuratively)", "kjv": "shew."}, "G1167": {"greek": "δειλία", "translit": "deilía", "pronunciation": "di-lee'-ah", "derivation": "from (G1169);", "definition": "timidity", "kjv": "fear."}, "G1168": {"greek": "δειλιάω", "translit": "deiliáō", "pronunciation": "di-lee-ah'-o", "derivation": "from (G1167);", "definition": "to be timid", "kjv": "be afraid."}, "G1169": {"greek": "δειλός", "translit": "deilós", "pronunciation": "di-los'", "derivation": "from (dread);", "definition": "timid, i.e. (by implication) faithless", "kjv": "fearful."}, "G1170": {"greek": "δεῖνα", "translit": "deîna", "pronunciation": "di'-nah", "derivation": "probably from the same as (G1171) (through the idea of forgetting the name as fearful, i.e. strange);", "definition": "so and so (when the person is not specified)", "kjv": "such a man."}, "G1171": {"greek": "δεινῶς", "translit": "deinōs", "pronunciation": "di-noce'", "derivation": "adverb from a derivative of the same as (G1169);", "definition": "terribly, i.e. excessively", "kjv": "grievously, vehemently."}, "G1172": {"greek": "δειπνέω", "translit": "deipnéō", "pronunciation": "dipe-neh'-o", "derivation": "from (G1173);", "definition": "to dine, i.e. take the principle (or evening) meal", "kjv": "sup (X -er)."}, "G1173": {"greek": "δεῖπνον", "translit": "deîpnon", "pronunciation": "dipe'-non", "derivation": "from the same as (G1160);", "definition": "dinner, i.e. the chief meal (usually in the evening)", "kjv": "feast, supper."}, "G1174": {"greek": "δεισιδαιμονέστερος", "translit": "deisidaimonésteros", "pronunciation": "dice-ee-dahee-mon-es'-ter-os", "derivation": "the compound of a derivative of the base of (G1169) and (G1142);", "definition": "more religious than others", "kjv": "too superstitious."}, "G1175": {"greek": "δεισιδαιμονία", "translit": "deisidaimonía", "pronunciation": "dice-ee-dahee-mon-ee'-ah", "derivation": "from the same as (G1174);", "definition": "religion", "kjv": "superstition."}, "G1176": {"greek": "δέκα", "translit": "déka", "pronunciation": "dek'-ah", "derivation": "a primary number;", "definition": "ten", "kjv": "(eight-)een, ten."}, "G1178": {"greek": "δεκαπέντε", "translit": "dekapénte", "pronunciation": "dek-ap-en'-teh", "derivation": "from (G1176) and (G4002);", "definition": "ten and five, i.e. fifteen", "kjv": "fifteen."}, "G1179": {"greek": "Δεκάπολις", "translit": "Dekápolis", "pronunciation": "dek-ap'-ol-is", "derivation": "from (G1176) and (G4172);", "definition": "the ten-city region; the Decapolis, a district in Syria", "kjv": "Decapolis."}, "G1180": {"greek": "δεκατέσσαρες", "translit": "dekatéssares", "pronunciation": "dek-at-es'-sar-es", "derivation": "from (G1176) and (G5064);", "definition": "ten and four, i.e. fourteen", "kjv": "fourteen."}, "G1181": {"greek": "δεκάτη", "translit": "dekátē", "pronunciation": "dek-at'-ay", "derivation": "feminine of (G1182);", "definition": "a tenth, i.e. as a percentage or (technically) tithe", "kjv": "tenth (part), tithe."}, "G1182": {"greek": "δέκατος", "translit": "dékatos", "pronunciation": "dek'-at-os", "derivation": "ordinal from (G1176);", "definition": "tenth", "kjv": "tenth."}, "G1183": {"greek": "δεκατόω", "translit": "dekatóō", "pronunciation": "dek-at-o'-o", "derivation": "from (G1181);", "definition": "to tithe, i.e. to give or take a tenth", "kjv": "pay (receive) tithes."}, "G1184": {"greek": "δεκτός", "translit": "dektós", "pronunciation": "dek-tos'", "derivation": "from (G1209);", "definition": "approved; (figuratively) propitious", "kjv": "accepted(-table)."}, "G1185": {"greek": "δελεάζω", "translit": "deleázō", "pronunciation": "del-eh-ad'-zo", "derivation": "from the base of (G1388);", "definition": "to entrap, i.e. (figuratively) delude", "kjv": "allure, beguile, entice."}, "G1186": {"greek": "δένδρον", "translit": "déndron", "pronunciation": "den'-dron", "derivation": "probably from (an oak);", "definition": "a tree", "kjv": "tree."}, "G1187": {"greek": "δεξιολάβος", "translit": "dexiolábos", "pronunciation": "dex-ee-ol-ab'-os", "derivation": "from (G1188) and (G2983);", "definition": "a guardsman (as if taking the right) or light-armed soldier", "kjv": "spearman."}, "G1188": {"greek": "δεξιός", "translit": "dexiós", "pronunciation": "dex-ee-os'", "derivation": "from (G1209);", "definition": "the right side or (feminine) hand (as that which usually takes)", "kjv": "right (hand, side)."}, "G1189": {"greek": "δέομαι", "translit": "déomai", "pronunciation": "deh'-om-ahee", "derivation": "middle voice of (G1210);", "definition": "to beg (as binding oneself), i.e. petition", "kjv": "beseech, pray (to), make request."}, "G1190": {"greek": "Δερβαῖος", "translit": "Derbaîos", "pronunciation": "der-bah'-ee-os", "derivation": "from (G1191);", "definition": "a Derbæan or inhabitant of Derbe", "kjv": "of Derbe."}, "G1191": {"greek": "Δέρβη", "translit": "Dérbē", "pronunciation": "der-bay'", "derivation": "of foreign origin;", "definition": "Derbe, a place in Asia Minor", "kjv": "Derbe."}, "G1192": {"greek": "δέρμα", "translit": "dérma", "pronunciation": "der'-mah", "derivation": "from (G1194);", "definition": "a hide", "kjv": "skin."}, "G1193": {"greek": "δερμάτινος", "translit": "dermátinos", "pronunciation": "der-mat'-ee-nos", "derivation": "from (G1192);", "definition": "made of hide", "kjv": "leathern, of a skin."}, "G1194": {"greek": "δέρω", "translit": "dérō", "pronunciation": "der'-o", "derivation": "a primary verb;", "definition": "properly, to flay, i.e. (by implication) to scourge, or (by analogy) to thrash", "kjv": "beat, smite."}, "G1195": {"greek": "δεσμεύω", "translit": "desmeúō", "pronunciation": "des-myoo'-o", "derivation": "from a (presumed) derivative of (G1196);", "definition": "to be a binder (captor), i.e. to enchain (a prisoner), to tie on (a load)", "kjv": "bind."}, "G1197": {"greek": "δέσμη", "translit": "désmē", "pronunciation": "des-may'", "derivation": "from (G1196);", "definition": "a bundle", "kjv": "bundle."}, "G1198": {"greek": "δέσμιος", "translit": "désmios", "pronunciation": "des'-mee-os", "derivation": "from (G1199);", "definition": "a captive (as bound)", "kjv": "in bonds, prisoner."}, "G1199": {"greek": "δεσμόν", "translit": "desmón", "pronunciation": "des-mon'", "derivation": "neuter and masculine respectively from (G1210);", "definition": "a band, i.e. ligament (of the body) or shackle (of a prisoner); figuratively, an impediment or disability", "kjv": "band, bond, chain, string."}, "G1200": {"greek": "δεσμοφύλαξ", "translit": "desmophýlax", "pronunciation": "des-mof-oo'-lax", "derivation": "from (G1199) and (G5441);", "definition": "a jailer (as guarding the prisoners)", "kjv": "jailor, keeper of the prison."}, "G1201": {"greek": "δεσμωτήριον", "translit": "desmōtḗrion", "pronunciation": "des-mo-tay'-ree-on", "derivation": "from a derivative of (G1199) (equivalent to (G1196));", "definition": "a place of bondage, i.e. a dungeon", "kjv": "prison."}, "G1202": {"greek": "δεσμώτης", "translit": "desmṓtēs", "pronunciation": "des-mo'-tace", "derivation": "from the same as (G1201);", "definition": "(passively) a captive", "kjv": "prisoner."}, "G1203": {"greek": "δεσπότης", "translit": "despótēs", "pronunciation": "des-pot'-ace", "derivation": "perhaps from (G1210) and (a husband);", "definition": "an absolute ruler (\"despot\")", "kjv": "Lord, master."}, "G1204": {"greek": "δεῦρο", "translit": "deûro", "pronunciation": "dyoo'-ro", "derivation": "of uncertain affinity;", "definition": "here; used also imperative hither!; and of time, hitherto", "kjv": "come (hither), hither(-to)."}, "G1205": {"greek": "δεῦτε", "translit": "deûte", "pronunciation": "dyoo'-teh", "derivation": "from (G1204) and an imperative form of (to go);", "definition": "come hither!", "kjv": "come, X follow."}, "G1206": {"greek": "δευτεραῖος", "translit": "deuteraîos", "pronunciation": "dyoo-ter-ah'-yos", "derivation": "from (G1208);", "definition": "secondary, i.e. (specially) on the second day", "kjv": "next day."}, "G1208": {"greek": "δεύτερος", "translit": "deúteros", "pronunciation": "dyoo'-ter-os", "derivation": "as the comparative of (G1417);", "definition": "(ordinal) second (in time, place, or rank; also adverb)", "kjv": "afterward, again, second(-arily, time)."}, "G1209": {"greek": "δέχομαι", "translit": "déchomai", "pronunciation": "dekh'-om-ahee", "derivation": "middle voice of a primary verb;", "definition": "to receive (in various applications, literally or figuratively)", "kjv": "accept, receive, take."}, "G1210": {"greek": "δέω", "translit": "déō", "pronunciation": "deh'-o", "derivation": "a primary verb;", "definition": "to bind (in various applications, literally or figuratively)", "kjv": "bind, be in bonds, knit, tie, wind."}, "G1211": {"greek": "δή", "translit": "dḗ", "pronunciation": "day", "derivation": "probably akin to (G1161);", "definition": "a particle of emphasis or explicitness; now, then, etc.", "kjv": "also, and, doubtless, now, therefore."}, "G1212": {"greek": "δῆλος", "translit": "dēlos", "pronunciation": "day'-los", "derivation": "of uncertain derivation;", "definition": "clear", "kjv": "+ bewray, certain, evident, manifest."}, "G1213": {"greek": "δηλόω", "translit": "dēlóō", "pronunciation": "day-lo'-o", "derivation": "from (G1212);", "definition": "to make plain (by words)", "kjv": "declare, shew, signify."}, "G1214": {"greek": "Δημᾶς", "translit": "Dēmâs", "pronunciation": "day-mas'", "derivation": "probably for (G1216);", "definition": "Demas, a Christian", "kjv": "Demas."}, "G1215": {"greek": "δημηγορέω", "translit": "dēmēgoréō", "pronunciation": "day-may-gor-eh'-o", "derivation": "from a compound of (G1218) and (G58);", "definition": "to be a people-gatherer, i.e. to address a public assembly", "kjv": "make an oration."}, "G1216": {"greek": "Δημήτριος", "translit": "Dēmḗtrios", "pronunciation": "day-may'-tree-os", "derivation": "from (Ceres);", "definition": "Demetrius, the name of an Ephesian and of a Christian", "kjv": "Demetrius."}, "G1217": {"greek": "δημιουργός", "translit": "dēmiourgós", "pronunciation": "day-me-oor-gos'", "derivation": "from (G1218) and (G2041);", "definition": "a worker for the people, i.e. mechanic (spoken of the Creator)", "kjv": "maker."}, "G1218": {"greek": "δῆμος", "translit": "dēmos", "pronunciation": "day'-mos", "derivation": "from (G1210);", "definition": "the public (as bound together socially)", "kjv": "people."}, "G1219": {"greek": "δημόσιος", "translit": "dēmósios", "pronunciation": "day-mos'ee-os", "derivation": "from (G1218);", "definition": "public; (feminine singular dative case as adverb) in public", "kjv": "common, openly, publickly."}, "G1220": {"greek": "δηνάριον", "translit": "dēnárion", "pronunciation": "day-nar'-ee-on", "derivation": "of Latin origin;", "definition": "a denarius (or ten asses)", "kjv": "pence, penny(-worth)."}, "G1222": {"greek": "δήπου", "translit": "dḗpou", "pronunciation": "day'-poo", "derivation": "from (G1211) and (G4225);", "definition": "a particle of asseveration; indeed doubtless", "kjv": "verily."}, "G1223": {"greek": "διά", "translit": "diá", "pronunciation": "dee-ah'", "derivation": "a primary preposition denoting the channel of an act;", "definition": "through (in very wide applications, local, causal, or occasional)", "kjv": "after, always, among, at, to avoid, because of (that), briefly, by, for (cause) … fore, from, in, by occasion of, of, by reason of, for sake, that, thereby, therefore, X though, through(-out), to, wherefore, with (-in)."}, "G1224": {"greek": "διαβαίνω", "translit": "diabaínō", "pronunciation": "dee-ab-ah'-ee-no", "derivation": "from (G1223) and the base of (G939);", "definition": "to cross", "kjv": "come over, pass (through)."}, "G1225": {"greek": "διαβάλλω", "translit": "diabállō", "pronunciation": "dee-ab-al'-lo", "derivation": "from (G1223) and (G906);", "definition": "(figuratively) to traduce", "kjv": "accuse."}, "G1226": {"greek": "διαβεβαιόομαι", "translit": "diabebaióomai", "pronunciation": "dee-ab-eb-ahee-o'-om-ahee", "derivation": "middle voice of a compound of (G1223) and (G950);", "definition": "to confirm thoroughly (by words), i.e. asseverate", "kjv": "affirm constantly."}, "G1227": {"greek": "διαβλέπω", "translit": "diablépō", "pronunciation": "dee-ab-lep'-o", "derivation": "from (G1223) and (G991);", "definition": "to look through, i.e. recover full vision", "kjv": "see clearly."}, "G1228": {"greek": "διάβολος", "translit": "diábolos", "pronunciation": "dee-ab'-ol-os", "derivation": "from (G1225);", "definition": "a traducer; specially, Satan (compare (G7854))", "kjv": "false accuser, devil, slanderer."}, "G1229": {"greek": "διαγγέλλω", "translit": "diangéllō", "pronunciation": "de-ang-gel'-lo", "derivation": "from (G1223) and the base of (G32);", "definition": "to herald thoroughly", "kjv": "declare, preach, signify."}, "G1230": {"greek": "διαγίνομαι", "translit": "diagínomai", "pronunciation": "dee-ag-in'-om-ahee", "derivation": "from (G1223) and (G1096);", "definition": "to elapse meanwhile", "kjv": "X after, be past, be spent."}, "G1231": {"greek": "διαγινώσκω", "translit": "diaginṓskō", "pronunciation": "dee-ag-in-o'-sko", "derivation": "from (G1223) and (G1097);", "definition": "to know thoroughly, i.e. ascertain exactly", "kjv": "(would) enquire, know the uttermost."}, "G1233": {"greek": "διάγνωσις", "translit": "diágnōsis", "pronunciation": "dee-ag'-no-sis", "derivation": "from (G1231);", "definition": "(magisterial) examination (\"diagnosis\")", "kjv": "hearing."}, "G1234": {"greek": "διαγογγύζω", "translit": "diagongýzō", "pronunciation": "dee-ag-ong-good'-zo", "derivation": "from (G1223) and (G1111);", "definition": "to complain throughout a crowd", "kjv": "murmur."}, "G1235": {"greek": "διαγρηγορέω", "translit": "diagrēgoréō", "pronunciation": "dee-ag-ray-gor-eh'-o", "derivation": "from (G1223) and (G1127);", "definition": "to waken thoroughly", "kjv": "be awake."}, "G1236": {"greek": "διάγω", "translit": "diágō", "pronunciation": "dee-ag'-o", "derivation": "from (G1223) and (G71);", "definition": "to pass time or life", "kjv": "lead life, living."}, "G1237": {"greek": "διαδέχομαι", "translit": "diadéchomai", "pronunciation": "dee-ad-ekh'-om-ahee", "derivation": "from (G1223) and (G1209);", "definition": "to receive in turn, i.e. (figuratively) succeed to", "kjv": "come after."}, "G1238": {"greek": "διάδημα", "translit": "diádēma", "pronunciation": "dee-ad'-ay-mah", "derivation": "from a compound of (G1223) and (G1210);", "definition": "a \"diadem\" (as bound about the head)", "kjv": "crown."}, "G1239": {"greek": "διαδίδωμι", "translit": "diadídōmi", "pronunciation": "dee-ad-id'-o-mee", "derivation": "from (G1223) and (G1325);", "definition": "to give throughout a crowd, i.e. deal out; also to deliver over (as to a successor)", "kjv": "(make) distribute(-ion), divide, give."}, "G1240": {"greek": "διάδοχος", "translit": "diádochos", "pronunciation": "dee-ad'-okh-os", "derivation": "from (G1237);", "definition": "a successor in office", "kjv": "room."}, "G1241": {"greek": "διαζώννυμι", "translit": "diazṓnnymi", "pronunciation": "dee-az-own'-noo-mee", "derivation": "from (G1223) and (G2224);", "definition": "to gird tightly", "kjv": "gird."}, "G1242": {"greek": "διαθήκη", "translit": "diathḗkē", "pronunciation": "dee-ath-ay'-kay", "derivation": "from (G1303);", "definition": "properly, a disposition, i.e. (specially) a contract (especially a devisory will)", "kjv": "covenant, testament."}, "G1243": {"greek": "διαίρεσις", "translit": "diaíresis", "pronunciation": "dee-ah'-ee-res-is", "derivation": "from (G1244);", "definition": "a distinction or (concretely) variety", "kjv": "difference, diversity."}, "G1244": {"greek": "διαιρέω", "translit": "diairéō", "pronunciation": "dee-ahee-reh'-o", "derivation": "from (G1223) and (G138);", "definition": "to separate, i.e. distribute", "kjv": "divide."}, "G1245": {"greek": "διακαθαρίζω", "translit": "diakatharízō", "pronunciation": "dee-ak-ath-ar-id'-zo", "derivation": "from (G1223) and (G2511);", "definition": "to cleanse perfectly, i.e. (specially) winnow", "kjv": "thoroughly purge."}, "G1246": {"greek": "διακατελέγχομαι", "translit": "diakatelénchomai", "pronunciation": "dee-ak-at-el-eng'-khom-ahee", "derivation": "middle voice from (G1223) and a compound of (G2596) and (G1651);", "definition": "to prove downright, i.e. confute", "kjv": "convince."}, "G1247": {"greek": "διακονέω", "translit": "diakonéō", "pronunciation": "dee-ak-on-eh'-o", "derivation": "from (G1249);", "definition": "to be an attendant, i.e. wait upon (menially or as a host, friend, or (figuratively) teacher); technically, to act as a Christian deacon", "kjv": "(ad-)minister (unto), serve, use the office of a deacon."}, "G1248": {"greek": "διακονία", "translit": "diakonía", "pronunciation": "dee-ak-on-ee'-ah", "derivation": "from (G1249);", "definition": "attendance (as a servant, etc.); figuratively (eleemosynary) aid, (official) service (especially of the Christian teacher, or technically of the diaconate)", "kjv": "(ad-)minister(-ing, -tration, -try), office, relief, service(-ing)."}, "G1249": {"greek": "διάκονος", "translit": "diákonos", "pronunciation": "dee-ak'-on-os", "derivation": "probably from an obsolete (to run on errands; compare (G1377));", "definition": "an attendant, i.e. (genitive case) a waiter (at table or in other menial duties); specially, a Christian teacher and pastor (technically, a deacon or deaconess)", "kjv": "deacon, minister, servant."}, "G1250": {"greek": "διακόσιοι", "translit": "diakósioi", "pronunciation": "dee-ak-os'-ee-oy", "derivation": "from (G1364) and (G1540);", "definition": "two hundred", "kjv": "two hundred."}, "G1251": {"greek": "διακούομαι", "translit": "diakoúomai", "pronunciation": "dee-ak-oo'-om-ahee", "derivation": "middle voice from (G1223) and (G191);", "definition": "to hear throughout, i.e. patiently listen (to a prisoner's plea)", "kjv": "hear."}, "G1252": {"greek": "διακρίνω", "translit": "diakrínō", "pronunciation": "dee-ak-ree'-no", "derivation": "from (G1223) and (G2919);", "definition": "to separate thoroughly, i.e. (literally and reflexively) to withdraw from, or (by implication) oppose; figuratively, to discriminate (by implication, decide), or (reflexively) hesitate", "kjv": "contend, make (to) differ(-ence), discern, doubt, judge, be partial, stagger, waver."}, "G1253": {"greek": "διάκρισις", "translit": "diákrisis", "pronunciation": "dee-ak'-ree-sis", "derivation": "from (G1252);", "definition": "judicial estimation", "kjv": "discern(-ing), disputation."}, "G1254": {"greek": "διακωλύω", "translit": "diakōlýō", "pronunciation": "dee-ak-o-loo'-o", "derivation": "from (G1223) and (G2967);", "definition": "to hinder altogether, i.e. utterly prohibit", "kjv": "forbid."}, "G1255": {"greek": "διαλαλέω", "translit": "dialaléō", "pronunciation": "dee-al-al-eh'-o", "derivation": "from (G1223) and (G2980);", "definition": "to talk throughout a company, i.e. converse or (genitive case) publish", "kjv": "commune, noise abroad."}, "G1256": {"greek": "διαλέγομαι", "translit": "dialégomai", "pronunciation": "dee-al-eg'-om-ahee", "derivation": "middle voice from (G1223) and (G3004);", "definition": "to say thoroughly, i.e. discuss (in argument or exhortation)", "kjv": "dispute, preach (unto), reason (with), speak."}, "G1257": {"greek": "διαλείπω", "translit": "dialeípō", "pronunciation": "dee-al-i'-po", "derivation": "from (G1223) and (G3007);", "definition": "to leave off in the middle, i.e. intermit", "kjv": "cease."}, "G1258": {"greek": "διάλεκτος", "translit": "diálektos", "pronunciation": "dee-al'-ek-tos", "derivation": "from (G1256);", "definition": "a (mode of) discourse, i.e. \"dialect\"", "kjv": "language, tongue."}, "G1259": {"greek": "διαλλάσσω", "translit": "diallássō", "pronunciation": "dee-al-las'-so", "derivation": "from (G1223) and (G236);", "definition": "to change thoroughly, i.e. (mentally) to conciliate", "kjv": "reconcile."}, "G1260": {"greek": "διαλογίζομαι", "translit": "dialogízomai", "pronunciation": "dee-al-og-id'-zom-ahee", "derivation": "from (G1223) and (G3049);", "definition": "to reckon thoroughly, i.e. (genitive case) to deliberate (by reflection or discussion)", "kjv": "cast in mind, consider, dispute, muse, reason, think."}, "G1261": {"greek": "διαλογισμός", "translit": "dialogismós", "pronunciation": "dee-al-og-is-mos'", "derivation": "from (G1260);", "definition": "discussion, i.e. (internal) consideration (by implication, purpose), or (external) debate", "kjv": "dispute, doubtful(-ing), imagination, reasoning, thought."}, "G1262": {"greek": "διαλύω", "translit": "dialýō", "pronunciation": "dee-al-oo'-o", "derivation": "from (G1223) and (G3089);", "definition": "to dissolve utterly", "kjv": "scatter."}, "G1263": {"greek": "διαμαρτύρομαι", "translit": "diamartýromai", "pronunciation": "dee-am-ar-too'-rom-ahee", "derivation": "from (G1223) and (G3140);", "definition": "to attest or protest earnestly, or (by implication) hortatively", "kjv": "charge, testify (unto), witness."}, "G1264": {"greek": "διαμάχομαι", "translit": "diamáchomai", "pronunciation": "dee-am-akh'-om-ahee", "derivation": "from (G1223) and (G3164);", "definition": "to fight fiercely (in altercation)", "kjv": "strive."}, "G1265": {"greek": "διαμένω", "translit": "diaménō", "pronunciation": "dee-am-en'-o", "derivation": "from (G1223) and (G3306);", "definition": "to stay constantly (in being or relation)", "kjv": "continue, remain."}, "G1266": {"greek": "διαμερίζω", "translit": "diamerízō", "pronunciation": "dee-am-er-id'-zo", "derivation": "from (G1223) and (G3307);", "definition": "to partition thoroughly (literally in distribution, figuratively in dissension)", "kjv": "cloven, divide, part."}, "G1267": {"greek": "διαμερισμός", "translit": "diamerismós", "pronunciation": "dee-am-er-is-mos'", "derivation": "from (G1266);", "definition": "disunion (of opinion and conduct)", "kjv": "division."}, "G1268": {"greek": "διανέμω", "translit": "dianémō", "pronunciation": "dee-an-em'-o", "derivation": "from (G1223) and the base of (G3551);", "definition": "to distribute, i.e. (of information) to disseminate", "kjv": "spread."}, "G1269": {"greek": "διανεύω", "translit": "dianeúō", "pronunciation": "dee-an-yoo'-o", "derivation": "from (G1223) and (G3506);", "definition": "to nod (or express by signs) across an intervening space", "kjv": "beckon."}, "G1270": {"greek": "διανόημα", "translit": "dianóēma", "pronunciation": "dee-an-o'-ay-mah", "derivation": "from a compound of (G1223) and (G3539);", "definition": "something thought through, i.e. a sentiment", "kjv": "thought."}, "G1271": {"greek": "διάνοια", "translit": "diánoia", "pronunciation": "dee-an'-oy-ah", "derivation": "from (G1223) and (G3563);", "definition": "deep thought, properly, the faculty (mind or its disposition), by implication, its exercise", "kjv": "imagination, mind, understanding."}, "G1272": {"greek": "διανοίγω", "translit": "dianoígō", "pronunciation": "dee-an-oy'-go", "derivation": "from (G1223) and (G455);", "definition": "to open thoroughly, literally (as a first-born) or figuratively (to expound)", "kjv": "open."}, "G1273": {"greek": "διανυκτερεύω", "translit": "dianyktereúō", "pronunciation": "dee-an-ook-ter-yoo'-o", "derivation": "from (G1223) and a derivative of (G3571);", "definition": "to sit up the whole night", "kjv": "continue all night."}, "G1274": {"greek": "διανύω", "translit": "dianýō", "pronunciation": "dee-an-oo'-o", "derivation": "from (G1223) and (to effect);", "definition": "to accomplish thoroughly", "kjv": "finish."}, "G1276": {"greek": "διαπεράω", "translit": "diaperáō", "pronunciation": "dee-ap-er-ah'-o", "derivation": "from (G1223) and a derivative of the base of (G4008);", "definition": "to cross entirely", "kjv": "go over, pass (over), sail over."}, "G1277": {"greek": "διαπλέω", "translit": "diapléō", "pronunciation": "dee-ap-leh'-o", "derivation": "from (G1223) and (G4126);", "definition": "to sail through", "kjv": "sail over."}, "G1278": {"greek": "διαπονέω", "translit": "diaponéō", "pronunciation": "dee-ap-on-eh'-o", "derivation": "from (G1223) and a derivative of (G4192);", "definition": "to toil through, i.e. (passively) be worried", "kjv": "be grieved."}, "G1279": {"greek": "διαπορεύομαι", "translit": "diaporeúomai", "pronunciation": "dee-ap-or-yoo'-om-ahee", "derivation": "from (G1223) and (G4198);", "definition": "to travel through", "kjv": "go through, journey in, pass by."}, "G1280": {"greek": "διαπορέω", "translit": "diaporéō", "pronunciation": "dee-ap-or-eh'-o", "derivation": "from (G1223) and (G639);", "definition": "to be thoroughly nonplussed", "kjv": "(be in) doubt, be (much) perplexed."}, "G1281": {"greek": "διαπραγματεύομαι", "translit": "diapragmateúomai", "pronunciation": "dee-ap-rag-mat-yoo'-om-ahee", "derivation": "from (G1223) and (G4231);", "definition": "to thoroughly occupy oneself, i.e. (transitively and by implication) to earn in business", "kjv": "gain by trading."}, "G1282": {"greek": "διαπρίω", "translit": "diapríō", "pronunciation": "dee-ap-ree'-o", "derivation": "from (G1223) and the base of (G4249);", "definition": "to saw asunder, i.e. (figuratively) to exasperate", "kjv": "cut (to the heart)."}, "G1283": {"greek": "διαρπάζω", "translit": "diarpázō", "pronunciation": "dee-ar-pad'-zo", "derivation": "from (G1223) and (G726);", "definition": "to seize asunder, i.e. plunder", "kjv": "spoil."}, "G1284": {"greek": "διαῤῥήσσω", "translit": "diarrhḗssō", "pronunciation": "dee-ar-hrayce'-so", "derivation": "from (G1223) and (G4486);", "definition": "to tear asunder", "kjv": "break, rend."}, "G1285": {"greek": "διασαφέω", "translit": "diasaphéō", "pronunciation": "dee-as-af-eh'-o", "derivation": "from (G1223) and (clear);", "definition": "to clear thoroughly, i.e. (figuratively) declare", "kjv": "tell unto."}, "G1286": {"greek": "διασείω", "translit": "diaseíō", "pronunciation": "dee-as-i'-o", "derivation": "from (G1223) and (G4579);", "definition": "to shake thoroughly, i.e. (figuratively) to intimidate", "kjv": "do violence to."}, "G1287": {"greek": "διασκορπίζω", "translit": "diaskorpízō", "pronunciation": "dee-as-kor-pid'-zo", "derivation": "from (G1223) and (G4650);", "definition": "to dissipate, i.e. (genitive case) to rout or separate; specially, to winnow; figuratively, to squander", "kjv": "disperse, scatter (abroad), strew, waste."}, "G1288": {"greek": "διασπάω", "translit": "diaspáō", "pronunciation": "dee-as-pah'-o", "derivation": "from (G1223) and (G4685);", "definition": "to draw apart, i.e. sever or dismember", "kjv": "pluck asunder, pull in pieces."}, "G1289": {"greek": "διασπείρω", "translit": "diaspeírō", "pronunciation": "dee-as-pi'-ro", "derivation": "from (G1223) and (G4687);", "definition": "to sow throughout, i.e. (figuratively) distribute in foreign lands", "kjv": "scatter abroad."}, "G1290": {"greek": "διασπορά", "translit": "diasporá", "pronunciation": "dee-as-por-ah'", "derivation": "from (G1289);", "definition": "dispersion, i.e. (specially and concretely) the (converted) Israelite resident in Gentile countries", "kjv": "(which are) scattered (abroad)."}, "G1291": {"greek": "διαστέλλομαι", "translit": "diastéllomai", "pronunciation": "dee-as-tel'-lom-ahee", "derivation": "middle voice from (G1223) and (G4724);", "definition": "to set (oneself) apart (figuratively, distinguish), i.e. (by implication) to enjoin", "kjv": "charge, that which was (give) commanded(-ment)."}, "G1292": {"greek": "διάστημα", "translit": "diástēma", "pronunciation": "dee-as'-tay-mah", "derivation": "from (G1339);", "definition": "an interval", "kjv": "space."}, "G1293": {"greek": "διαστολή", "translit": "diastolḗ", "pronunciation": "dee-as-tol-ay'", "derivation": "from (G1291);", "definition": "a variation", "kjv": "difference, distinction."}, "G1294": {"greek": "διαστρέφω", "translit": "diastréphō", "pronunciation": "dee-as-tref'-o", "derivation": "from (G1223) and (G4762);", "definition": "to distort, i.e. (figuratively) misinterpret, or (morally) corrupt", "kjv": "perverse(-rt), turn away."}, "G1295": {"greek": "διασώζω", "translit": "diasṓzō", "pronunciation": "dee-as-odze'-o", "derivation": "from (G1223) and (G4982);", "definition": "to save thoroughly, i.e. (by implication or analogy) to cure, preserve, rescue, etc.", "kjv": "bring safe, escape (safe), heal, make perfectly whole, save."}, "G1296": {"greek": "διαταγή", "translit": "diatagḗ", "pronunciation": "dee-at-ag-ay'", "derivation": "from (G1299);", "definition": "arrangement, i.e. institution", "kjv": "instrumentality."}, "G1297": {"greek": "διάταγμα", "translit": "diátagma", "pronunciation": "dee-at'-ag-mah", "derivation": "from (G1299);", "definition": "an arrangement, i.e. (authoritative) edict", "kjv": "commandment."}, "G1298": {"greek": "διαταράσσω", "translit": "diatarássō", "pronunciation": "dee-at-ar-as'-so", "derivation": "from (G1223) and (G5015);", "definition": "to disturb wholly, i.e. agitate (with alarm)", "kjv": "trouble."}, "G1299": {"greek": "διατάσσω", "translit": "diatássō", "pronunciation": "dee-at-as'-so", "derivation": "from (G1223) and (G5021);", "definition": "to arrange thoroughly, i.e. (specially) institute, prescribe, etc.", "kjv": "appoint, command, give, (set in) order, ordain."}, "G1300": {"greek": "διατελέω", "translit": "diateléō", "pronunciation": "dee-at-el-eh'-o", "derivation": "from (G1223) and (G5055);", "definition": "to accomplish thoroughly, i.e. (subjectively) to persist", "kjv": "continue."}, "G1301": {"greek": "διατηρέω", "translit": "diatēréō", "pronunciation": "dee-at-ay-reh'-o", "derivation": "from (G1223) and (G5083);", "definition": "to watch thoroughly, i.e. (positively and transitively) to observe strictly, or (negatively and reflexively) to avoid wholly", "kjv": "keep."}, "G1303": {"greek": "διατίθεμαι", "translit": "diatíthemai", "pronunciation": "dee-at-ith'-em-ahee", "derivation": "middle voice from (G1223) and (G5087);", "definition": "to put apart, i.e. (figuratively) dispose (by assignment, compact, or bequest)", "kjv": "appoint, make, testator."}, "G1304": {"greek": "διατρίβω", "translit": "diatríbō", "pronunciation": "dee-at-ree'-bo", "derivation": "from (G1223) and the base of (G5147);", "definition": "to wear through (time), i.e. remain", "kjv": "abide, be, continue, tarry."}, "G1305": {"greek": "διατροφή", "translit": "diatrophḗ", "pronunciation": "dee-at-rof-ay'", "derivation": "from a compound of (G1223) and (G5142);", "definition": "nourishment", "kjv": "food."}, "G1306": {"greek": "διαυγάζω", "translit": "diaugázō", "pronunciation": "dee-ow-gad'-zo", "derivation": "from (G1223) and (G826);", "definition": "to glimmer through, i.e. break (as day)", "kjv": "dawn."}, "G1307": {"greek": "διαφανής", "translit": "diaphanḗs", "pronunciation": "dee-af-an-ace'", "derivation": "from (G1223) and (G5316);", "definition": "appearing through, i.e. \"diaphanous\"", "kjv": "transparent."}, "G1308": {"greek": "διαφέρω", "translit": "diaphérō", "pronunciation": "dee-af-er'-o", "derivation": "from (G1223) and (G5342);", "definition": "to bear through, i.e. (literally) transport; usually to bear apart, i.e. (objectively) to toss about (figuratively, report); subjectively, to \"differ\", or (by implication) surpass", "kjv": "be better, carry, differ from, drive up and down, be (more) excellent, make matter, publish, be of more value."}, "G1309": {"greek": "διαφεύγω", "translit": "diapheúgō", "pronunciation": "dee-af-yoo'-go", "derivation": "from (G1223) and (G5343);", "definition": "to flee through, i.e. escape", "kjv": "escape."}, "G1310": {"greek": "διαφημίζω", "translit": "diaphēmízō", "pronunciation": "dee-af-ay-mid'-zo", "derivation": "from (G1223) and a derivative of (G5345);", "definition": "to report thoroughly, i.e. divulgate", "kjv": "blaze abroad, commonly report, spread abroad, fame."}, "G1311": {"greek": "διαφθείρω", "translit": "diaphtheírō", "pronunciation": "dee-af-thi'-ro", "derivation": "from (G1225) and (G5351);", "definition": "to rot thoroughly, i.e. (by implication) to ruin (passively, decay utterly, figuratively, pervert)", "kjv": "corrupt, destroy, perish."}, "G1312": {"greek": "διαφθορά", "translit": "diaphthorá", "pronunciation": "dee-af-thor-ah'", "derivation": "from (G1311);", "definition": "decay", "kjv": "corruption."}, "G1313": {"greek": "διάφορος", "translit": "diáphoros", "pronunciation": "dee-af'-or-os", "derivation": "from (G1308);", "definition": "varying; also surpassing", "kjv": "differing, divers, more excellent."}, "G1314": {"greek": "διαφυλάσσω", "translit": "diaphylássō", "pronunciation": "dee-af-oo-las'-so", "derivation": "from (G1223) and (G5442);", "definition": "to guard thoroughly, i.e. protect", "kjv": "keep."}, "G1315": {"greek": "διαχειρίζομαι", "translit": "diacheirízomai", "pronunciation": "dee-akh-i-rid'-zom-ahee", "derivation": "from (G1223) and a derivative of (G5495);", "definition": "to handle thoroughly, i.e. lay violent hands upon", "kjv": "kill, slay."}, "G1316": {"greek": "διαχωρίζομαι", "translit": "diachōrízomai", "pronunciation": "dee-akh-o-rid'-zom-ahee", "derivation": "from (G1223) and the middle voice of (G5563);", "definition": "to remove (oneself) wholly, i.e. retire", "kjv": "depart."}, "G1317": {"greek": "διδακτικός", "translit": "didaktikós", "pronunciation": "did-ak-tik-os'", "derivation": "from (G1318);", "definition": "instructive (\"didactic\")", "kjv": "apt to teach."}, "G1318": {"greek": "διδακτός", "translit": "didaktós", "pronunciation": "did-ak-tos'", "derivation": "from (G1321);", "definition": "(subjectively) instructed, or (objectively) communicated by teaching", "kjv": "taught, which … teacheth."}, "G1319": {"greek": "διδασκαλία", "translit": "didaskalía", "pronunciation": "did-as-kal-ee'-ah", "derivation": "from (G1320);", "definition": "instruction (the function or the information)", "kjv": "doctrine, learning, teaching."}, "G1320": {"greek": "διδάσκαλος", "translit": "didáskalos", "pronunciation": "did-as'-kal-os", "derivation": "from (G1321);", "definition": "an instructor (genitive case or specially)", "kjv": "doctor, master, teacher."}, "G1321": {"greek": "διδάσκω", "translit": "didáskō", "pronunciation": "did-as'-ko", "derivation": "a prolonged (causative) form of a primary verb (to learn);", "definition": "to teach (in the same broad application)", "kjv": "teach."}, "G1322": {"greek": "διδαχή", "translit": "didachḗ", "pronunciation": "did-akh-ay'", "derivation": "from (G1321);", "definition": "instruction (the act or the matter)", "kjv": "doctrine, hath been taught."}, "G1323": {"greek": "δίδραχμον", "translit": "dídrachmon", "pronunciation": "did'-rakh-mon", "derivation": "from (G1364) and (G1406);", "definition": "a double drachma (didrachm)", "kjv": "tribute."}, "G1324": {"greek": "Δίδυμος", "translit": "Dídymos", "pronunciation": "did'-oo-mos", "derivation": "prolongation from (G1364);", "definition": "double, i.e. twin; Didymus, a Christian", "kjv": "Didymus."}, "G1325": {"greek": "δίδωμι", "translit": "dídōmi", "pronunciation": "did'-o-mee", "derivation": "a prolonged form of a primary verb (which is used as an alternative in most of the tenses);", "definition": "to give (used in a very wide application, properly, or by implication, literally or figuratively; greatly modified by the connection)", "kjv": "adventure, bestow, bring forth, commit, deliver (up), give, grant, hinder, make, minister, number, offer, have power, put, receive, set, shew, smite (+ with the hand), strike (+ with the palm of the hand), suffer, take, utter, yield."}, "G1326": {"greek": "διεγείρω", "translit": "diegeírō", "pronunciation": "dee-eg-i'-ro", "derivation": "from (G1223) and (G1453);", "definition": "to wake fully; i.e. arouse (literally or figuratively)", "kjv": "arise, awake, raise, stir up."}, "G1327": {"greek": "διέξοδος", "translit": "diéxodos", "pronunciation": "dee-ex'-od-os", "derivation": "from (G1223) and (G1841);", "definition": "an outlet through, i.e. probably an open square (from which roads diverge)", "kjv": "highway."}, "G1328": {"greek": "διερμηνευτής", "translit": "diermēneutḗs", "pronunciation": "dee-er-main-yoo-tace'", "derivation": "from (G1329);", "definition": "an explainer", "kjv": "interpreter."}, "G1329": {"greek": "διερμηνεύω", "translit": "diermēneúō", "pronunciation": "dee-er-main-yoo'-o", "derivation": "from (G1223) and (G2059);", "definition": "to explain thoroughly, by implication, to translate", "kjv": "expound, interpret(-ation)."}, "G1330": {"greek": "διέρχομαι", "translit": "diérchomai", "pronunciation": "dee-er'-khom-ahee", "derivation": "from (G1223) and (G2064);", "definition": "to traverse (literally)", "kjv": "come, depart, go (about, abroad, everywhere, over, through, throughout), pass (by, over, through, throughout), pierce through, travel, walk through."}, "G1331": {"greek": "διερωτάω", "translit": "dierōtáō", "pronunciation": "dee-er-o-tah'-o", "derivation": "from (G1223) and (G2065);", "definition": "to question throughout, i.e. ascertain by interrogation", "kjv": "make enquiry for."}, "G1332": {"greek": "διετής", "translit": "dietḗs", "pronunciation": "dee-et-ace'", "derivation": "from (G1364) and (G2094);", "definition": "of two years (in age)", "kjv": "two years old."}, "G1333": {"greek": "διετία", "translit": "dietía", "pronunciation": "dee-et-ee'-a", "derivation": "from (G1332);", "definition": "a space of two years (biennium)", "kjv": "two years."}, "G1334": {"greek": "διηγέομαι", "translit": "diēgéomai", "pronunciation": "dee-ayg-eh'-om-ahee", "derivation": "from (G1223) and (G2233);", "definition": "to relate fully", "kjv": "declare, shew, tell."}, "G1335": {"greek": "διήγεσις", "translit": "diḗgesis", "pronunciation": "dee-ayg'-es-is", "derivation": "from (G1334);", "definition": "a recital", "kjv": "declaration."}, "G1336": {"greek": "διηνεκής", "translit": "diēnekḗs", "pronunciation": "dee-ay-nek-es'", "derivation": "neuter of a compound of (G1223) and a derivative of an alternate of (G5342);", "definition": "carried through, i.e. (adverbially with (G1519) and (G3588) prefixed) perpetually", "kjv": "+ continually, for ever."}, "G1337": {"greek": "διθάλασσος", "translit": "dithálassos", "pronunciation": "dee-thal'-as-sos", "derivation": "from (G1364) and (G2281);", "definition": "having two seas, i.e. a sound with a double outlet", "kjv": "where two seas meet."}, "G1338": {"greek": "διϊκνέομαι", "translit": "diïknéomai", "pronunciation": "dee-ik-neh'-om-ahee", "derivation": "from (G1223) and the base of (G2425);", "definition": "to reach through, i.e. penetrate", "kjv": "pierce."}, "G1339": {"greek": "διΐστημι", "translit": "diḯstēmi", "pronunciation": "dee-is'-tay-mee", "derivation": "from (G1223) and (G2476);", "definition": "to stand apart, i.e. (reflexively) to remove, intervene", "kjv": "go further, be parted, after the space of."}, "G1340": {"greek": "διϊσχυρίζομαι", "translit": "diïschyrízomai", "pronunciation": "dee-is-khoo-rid'-zom-ahee", "derivation": "from (G1223) and a derivative of (G2478);", "definition": "to stout it through, i.e. asservate", "kjv": "confidently (constantly) affirm."}, "G1341": {"greek": "δικαιοκρισία", "translit": "dikaiokrisía", "pronunciation": "dik-ah-yok-ris-ee'-ah", "derivation": "from (G1342) and (G2920);", "definition": "a just sentence", "kjv": "righteous judgment."}, "G1342": {"greek": "δίκαιος", "translit": "díkaios", "pronunciation": "dik'-ah-yos", "derivation": "from (G1349);", "definition": "equitable (in character or act); by implication, innocent, holy (absolutely or relatively)", "kjv": "just, meet, right(-eous)."}, "G1343": {"greek": "δικαιοσύνη", "translit": "dikaiosýnē", "pronunciation": "dik-ah-yos-oo'-nay", "derivation": "from (G1342);", "definition": "equity (of character or act); specially (Christian) justification", "kjv": "righteousness."}, "G1344": {"greek": "δικαιόω", "translit": "dikaióō", "pronunciation": "dik-ah-yo'-o", "derivation": "from (G1342);", "definition": "to render (i.e. show or regard as) just or innocent", "kjv": "free, justify(-ier), be righteous."}, "G1345": {"greek": "δικαίωμα", "translit": "dikaíōma", "pronunciation": "dik-ah'-yo-mah", "derivation": "from (G1344);", "definition": "an equitable deed; by implication, a statute or decision", "kjv": "judgment, justification, ordinance, righteousness."}, "G1346": {"greek": "δικαίως", "translit": "dikaíōs", "pronunciation": "dik-ah'-yoce", "derivation": "adverb from (G1342);", "definition": "equitably", "kjv": "justly, (to) righteously(-ness)."}, "G1347": {"greek": "δικαίωσις", "translit": "dikaíōsis", "pronunciation": "dik-ah'-yo-sis", "derivation": "from (G1344);", "definition": "aquittal (for Christ's sake)", "kjv": "justification."}, "G1348": {"greek": "δικαστής", "translit": "dikastḗs", "pronunciation": "dik-as-tace'", "derivation": "from a derivative of (G1349);", "definition": "a judger", "kjv": "judge."}, "G1349": {"greek": "δίκη", "translit": "díkē", "pronunciation": "dee'-kay", "derivation": "probably from (G1166);", "definition": "right (as self-evident), i.e. justice (the principle, a decision, or its execution)", "kjv": "judgment, punish, vengeance."}, "G1350": {"greek": "δίκτυον", "translit": "díktyon", "pronunciation": "dik'-too-on", "derivation": "probably from a primary verb (to cast);", "definition": "a seine (for fishing)", "kjv": "net."}, "G1351": {"greek": "δίλογος", "translit": "dílogos", "pronunciation": "dil'-og-os", "derivation": "from (G1364) and (G3056);", "definition": "equivocal, i.e. telling a different story", "kjv": "double-tongued."}, "G1352": {"greek": "διό", "translit": "dió", "pronunciation": "dee-o'", "derivation": "from (G1223) and (G3739);", "definition": "through which thing, i.e. consequently", "kjv": "for which cause, therefore, wherefore."}, "G1353": {"greek": "διοδεύω", "translit": "diodeúō", "pronunciation": "dee-od-yoo'-o", "derivation": "from (G1223) and (G3593);", "definition": "to travel through", "kjv": "go throughout, pass through."}, "G1354": {"greek": "Διονύσιος", "translit": "Dionýsios", "pronunciation": "dee-on-oo'-see-os", "derivation": "from (Bacchus);", "definition": "reveller; Dionysius, an Athenian", "kjv": "Dionysius."}, "G1355": {"greek": "διόπερ", "translit": "dióper", "pronunciation": "dee-op'-er", "derivation": "from (G1352) and (G4007);", "definition": "on which very account", "kjv": "wherefore."}, "G1356": {"greek": "διοπετής", "translit": "diopetḗs", "pronunciation": "dee-op-et'-ace", "derivation": "from the alternate of (G2203) and the alternate of (G4098);", "definition": "sky-fallen (i.e. an aerolite)", "kjv": "which fell down from Jupiter."}, "G1357": {"greek": "διόρθωσις", "translit": "diórthōsis", "pronunciation": "dee-or'-tho-sis", "derivation": "from a compound of (G1223) and a derivative of (G3717), meaning to straighten thoroughly;", "definition": "rectification, i.e. (specially) the Messianic restauration", "kjv": "reformation."}, "G1358": {"greek": "διορύσσω", "translit": "diorýssō", "pronunciation": "dee-or-oos'-so", "derivation": "from (G1223) and (G3736);", "definition": "to penetrate burglariously", "kjv": "break through (up)."}, "G1359": {"greek": "Διόσκουροι", "translit": "Dióskouroi", "pronunciation": "dee-os'-koo-roy", "derivation": "from the alternate of (G2203) and a form of the base of (G2877);", "definition": "sons of Jupiter, i.e. the twins Dioscuri", "kjv": "Castor and Pollux."}, "G1360": {"greek": "διότι", "translit": "dióti", "pronunciation": "dee-ot'-ee", "derivation": "from (G1223) and (G3754);", "definition": "on the very account that, or inasmuch as", "kjv": "because (that), for, therefore."}, "G1361": {"greek": "Διοτρεφής", "translit": "Diotrephḗs", "pronunciation": "dee-ot-ref-ace'", "derivation": "from the alternate of (G2203) and (G5142);", "definition": "Jove-nourished; Diotrephes, an opponent of Christianity", "kjv": "Diotrephes."}, "G1362": {"greek": "διπλοῦς", "translit": "diploûs", "pronunciation": "dip-looce'", "derivation": "from (G1364) and (probably) the base of (G4119);", "definition": "two-fold", "kjv": "double, two-fold more."}, "G1363": {"greek": "διπλόω", "translit": "diplóō", "pronunciation": "dip-lo'-o", "derivation": "from (G1362);", "definition": "to render two-fold", "kjv": "double."}, "G1364": {"greek": "δίς", "translit": "dís", "pronunciation": "dece", "derivation": "adverb from (G1417);", "definition": "twice", "kjv": "again, twice."}, "G1365": {"greek": "διστάζω", "translit": "distázō", "pronunciation": "dis-tad'-zo", "derivation": "from (G1364);", "definition": "properly, to duplicate, i.e. (mentally) to waver (in opinion)", "kjv": "doubt."}, "G1366": {"greek": "δίστομος", "translit": "dístomos", "pronunciation": "dis'-tom-os", "derivation": "from (G1364) and (G4750);", "definition": "double-edged", "kjv": "with two edges, two-edged."}, "G1367": {"greek": "δισχίλιοι", "translit": "dischílioi", "pronunciation": "dis-khil'-ee-oy", "derivation": "from (G1364) and (G5507);", "definition": "two thousand", "kjv": "two thousand."}, "G1368": {"greek": "διϋλίζω", "translit": "diÿlízō", "pronunciation": "dee-oo-lid'-zo", "derivation": "from (G1223) and (to filter);", "definition": "to strain out", "kjv": "strain at (probably by misprint)."}, "G1369": {"greek": "διχάζω", "translit": "dicházō", "pronunciation": "dee-khad'-zo", "derivation": "from a derivative of (G1364);", "definition": "to make apart, i.e. sunder (figuratively, alienate)", "kjv": "set at variance."}, "G1370": {"greek": "διχοστασία", "translit": "dichostasía", "pronunciation": "dee-khos-tas-ee'-ah", "derivation": "from a derivative of (G1364) and (G4714);", "definition": "disunion, i.e. (figuratively) dissension", "kjv": "division, sedition."}, "G1371": {"greek": "διχοτομέω", "translit": "dichotoméō", "pronunciation": "dee-khot-om-eh'-o", "derivation": "from a compound of a derivative of (G1364) and a derivative of (to cut);", "definition": "to bisect, i.e. (by extension) to flog severely", "kjv": "cut asunder (in sunder)."}, "G1372": {"greek": "διψάω", "translit": "dipsáō", "pronunciation": "dip-sah'-o", "derivation": "from a variation of (G1373);", "definition": "to thirst for (literally or figuratively)", "kjv": "(be, be a-)thirst(-y)."}, "G1373": {"greek": "δίψος", "translit": "dípsos", "pronunciation": "dip'-sos", "derivation": "of uncertain affinity;", "definition": "thirst", "kjv": "thirst."}, "G1374": {"greek": "δίψυχος", "translit": "dípsychos", "pronunciation": "dip'-soo-khos", "derivation": "from (G1364) and (G5590);", "definition": "two-spirited, i.e. vacillating (in opinion or purpose)", "kjv": "double minded."}, "G1375": {"greek": "διωγμός", "translit": "diōgmós", "pronunciation": "dee-ogue-mos'", "derivation": "from (G1377);", "definition": "persecution", "kjv": "persecution."}, "G1376": {"greek": "διώκτης", "translit": "diṓktēs", "pronunciation": "dee-oke'-tace", "derivation": "from (G1377);", "definition": "a persecutor", "kjv": "persecutor."}, "G1377": {"greek": "διώκω", "translit": "diṓkō", "pronunciation": "dee-o'-ko", "derivation": "a prolonged (and causative) form of a primary verb (to flee;", "definition": "compare the base of (G1169) and (G1249)); to pursue (literally or figuratively); by implication, to persecute", "kjv": "ensue, follow (after), given to, (suffer) persecute(-ion), press forward."}, "G1378": {"greek": "δόγμα", "translit": "dógma", "pronunciation": "dog'-mah", "derivation": "from the base of (G1380);", "definition": "a law (civil, ceremonial or ecclesiastical)", "kjv": "decree, ordinance."}, "G1379": {"greek": "δογματίζω", "translit": "dogmatízō", "pronunciation": "dog-mat-id'-zo", "derivation": "from (G1378);", "definition": "to prescribe by statute, i.e. (reflexively) to submit to, ceremonially rule", "kjv": "be subject to ordinances."}, "G1380": {"greek": "δοκέω", "translit": "dokéō", "pronunciation": "dok-eh'-o", "derivation": "a prolonged form of a primary verb, (used only in an alternate in certain tenses;", "definition": "compare the base of (G1166)) of the same meaning; to think; by implication, to seem (truthfully or uncertainly)", "kjv": "be accounted, (of own) please(-ure), be of reputation, seem (good), suppose, think, trow."}, "G1381": {"greek": "δοκιμάζω", "translit": "dokimázō", "pronunciation": "dok-im-ad'-zo", "derivation": "from (G1384);", "definition": "to test (literally or figuratively); by implication, to approve", "kjv": "allow, discern, examine, X like, (ap-)prove, try."}, "G1382": {"greek": "δοκιμή", "translit": "dokimḗ", "pronunciation": "dok-ee-may'", "derivation": "from the same as (G1384);", "definition": "test (abstractly or concretely); by implication, trustiness", "kjv": "experience(-riment), proof, trial."}, "G1383": {"greek": "δοκίμιον", "translit": "dokímion", "pronunciation": "dok-im'-ee-on", "derivation": "neuter of a presumed derivative of (G1382);", "definition": "a testing; by implication, trustworthiness", "kjv": "trial, trying."}, "G1384": {"greek": "δόκιμος", "translit": "dókimos", "pronunciation": "dok'-ee-mos", "derivation": "from (G1380);", "definition": "properly, acceptable (current after assayal), i.e. approved", "kjv": "approved, tried."}, "G1385": {"greek": "δοκός", "translit": "dokós", "pronunciation": "dok-os'", "derivation": "from (G1209) (through the idea of holding up);", "definition": "a stick of timber", "kjv": "beam."}, "G1386": {"greek": "δόλιος", "translit": "dólios", "pronunciation": "dol'-ee-os", "derivation": "from (G1388);", "definition": "guileful", "kjv": "deceitful."}, "G1387": {"greek": "δολιόω", "translit": "dolióō", "pronunciation": "dol-ee-o'-o", "derivation": "from (G1386);", "definition": "to be guileful", "kjv": "use deceit."}, "G1388": {"greek": "δόλος", "translit": "dólos", "pronunciation": "dol'-os", "derivation": "from an obsolete primary verb, (probably meaning to decoy; compare (G1185));", "definition": "a trick (bait), i.e. (figuratively) wile", "kjv": "craft, deceit, guile, subtilty."}, "G1389": {"greek": "δολόω", "translit": "dolóō", "pronunciation": "dol-o'-o", "derivation": "from (G1388);", "definition": "to ensnare, i.e. (figuratively) adulterate", "kjv": "handle deceitfully."}, "G1390": {"greek": "δόμα", "translit": "dóma", "pronunciation": "dom'-ah", "derivation": "from the base of (G1325);", "definition": "a present", "kjv": "gift."}, "G1391": {"greek": "δόξα", "translit": "dóxa", "pronunciation": "dox'-ah", "derivation": "from the base of (G1380);", "definition": "glory (as very apparent), in a wide application (literal or figurative, objective or subjective)", "kjv": "dignity, glory(-ious), honour, praise, worship."}, "G1392": {"greek": "δοξάζω", "translit": "doxázō", "pronunciation": "dox-ad'-zo", "derivation": "from (G1391);", "definition": "to render (or esteem) glorious (in a wide application)", "kjv": "(make) glorify(-ious), full of (have) glory, honour, magnify."}, "G1393": {"greek": "Δορκάς", "translit": "Dorkás", "pronunciation": "dor-kas'", "derivation": "", "definition": "gazelle; Dorcas, a Christian woman", "kjv": "Dorcas."}, "G1394": {"greek": "δόσις", "translit": "dósis", "pronunciation": "dos'-is", "derivation": "from the base of (G1325);", "definition": "a giving; by implication, (concretely) a gift", "kjv": "gift, giving."}, "G1395": {"greek": "δότης", "translit": "dótēs", "pronunciation": "dot'-ace", "derivation": "from the base of (G1325);", "definition": "a giver", "kjv": "giver."}, "G1396": {"greek": "δουλαγωγέω", "translit": "doulagōgéō", "pronunciation": "doo-lag-ogue-eh'-o", "derivation": "from a presumed compound of (G1401) and (G71);", "definition": "to be a slave-driver, i.e. to enslave (figuratively, subdue)", "kjv": "bring into subjection."}, "G1397": {"greek": "δουλεία", "translit": "douleía", "pronunciation": "doo-li'-ah", "derivation": "from (G1398);", "definition": "slavery (ceremonially or figuratively)", "kjv": "bondage."}, "G1398": {"greek": "δουλεύω", "translit": "douleúō", "pronunciation": "dool-yoo'-o", "derivation": "from (G1401);", "definition": "to be a slave to (literal or figurative, involuntary or voluntary)", "kjv": "be in bondage, (do) serve(-ice)."}, "G1399": {"greek": "δούλη", "translit": "doúlē", "pronunciation": "doo'-lay", "derivation": "feminine of (G1401);", "definition": "a female slave (involuntarily or voluntarily)", "kjv": "handmaid(-en)."}, "G1401": {"greek": "δοῦλος", "translit": "doûlos", "pronunciation": "doo'-los", "derivation": "from (G1210);", "definition": "a slave (literal or figurative, involuntary or voluntary; frequently, therefore in a qualified sense of subjection or subserviency)", "kjv": "bond(-man), servant."}, "G1402": {"greek": "δουλόω", "translit": "doulóō", "pronunciation": "doo-lo'-o", "derivation": "from (G1401);", "definition": "to enslave (literally or figuratively)", "kjv": "bring into (be under) bondage, X given, become (make) servant."}, "G1403": {"greek": "δοχή", "translit": "dochḗ", "pronunciation": "dokh-ay'", "derivation": "from (G1209);", "definition": "a reception, i.e. convivial entertainment", "kjv": "feast."}, "G1404": {"greek": "δράκων", "translit": "drákōn", "pronunciation": "drak'-own", "derivation": "probably from an alternate form of (to look);", "definition": "a fabulous kind of serpent (perhaps as supposed to fascinate)", "kjv": "dragon."}, "G1405": {"greek": "δράσσομαι", "translit": "drássomai", "pronunciation": "dras'-som-ahee", "derivation": "perhaps akin to the base of (G1404) (through the idea of capturing);", "definition": "to grasp, i.e. (figuratively) entrap", "kjv": "take."}, "G1406": {"greek": "δραχμή", "translit": "drachmḗ", "pronunciation": "drakh-may'", "derivation": "from (G1405);", "definition": "a drachma or (silver) coin (as handled)", "kjv": "piece (of silver)."}, "G1407": {"greek": "δρέπανον", "translit": "drépanon", "pronunciation": "drep'-an-on", "derivation": "from (to pluck);", "definition": "a gathering hook (especially for harvesting)", "kjv": "sickle."}, "G1408": {"greek": "δρόμος", "translit": "drómos", "pronunciation": "drom'-os", "derivation": "from the alternate of (G5143);", "definition": "a race, i.e. (figuratively) career", "kjv": "course."}, "G1409": {"greek": "Δρούσιλλα", "translit": "Droúsilla", "pronunciation": "droo'-sil-lah", "derivation": "a feminine diminutive of Drusus (a Roman name);", "definition": "Drusilla, a member of the Herodian family", "kjv": "Drusilla."}, "G1410": {"greek": "δύναμαι", "translit": "dýnamai", "pronunciation": "doo'-nam-ahee", "derivation": "of uncertain affinity;", "definition": "to be able or possible", "kjv": "be able, can (do, + -not), could, may, might, be possible, be of power."}, "G1411": {"greek": "δύναμις", "translit": "dýnamis", "pronunciation": "doo'-nam-is", "derivation": "from (G1410);", "definition": "force (literally or figuratively); specially, miraculous power (usually by implication, a miracle itself)", "kjv": "ability, abundance, meaning, might(-ily, -y, -y deed), (worker of) miracle(-s), power, strength, violence, mighty (wonderful) work."}, "G1412": {"greek": "δυναμόω", "translit": "dynamóō", "pronunciation": "doo-nam-o'-o", "derivation": "from (G1411);", "definition": "to enable", "kjv": "strengthen."}, "G1413": {"greek": "δυνάστης", "translit": "dynástēs", "pronunciation": "doo-nas'-tace", "derivation": "from (G1410);", "definition": "a ruler or officer", "kjv": "of great authority, mighty, potentate."}, "G1414": {"greek": "δυνατέω", "translit": "dynatéō", "pronunciation": "doo-nat-eh'-o", "derivation": "from (G1415);", "definition": "to be efficient (figuratively)", "kjv": "be mighty."}, "G1415": {"greek": "δυνατός", "translit": "dynatós", "pronunciation": "doo-nat-os'", "derivation": "from (G1410);", "definition": "powerful or capable (literally or figuratively); neuter possible", "kjv": "able, could, (that is) mighty (man), possible, power, strong."}, "G1416": {"greek": "δύνω", "translit": "dýnō", "pronunciation": "doo'-no", "derivation": "prolonged forms of an obsolete primary (to sink);", "definition": "to go \"down\"", "kjv": "set."}, "G1417": {"greek": "δύο", "translit": "dýo", "pronunciation": "doo'-o", "derivation": "a primary numeral;", "definition": "\"two\"", "kjv": "both, twain, two."}, "G1419": {"greek": "δυσβάστακτος", "translit": "dysbástaktos", "pronunciation": "doos-bas'-tak-tos", "derivation": "from (G1418) and a derivative of (G941);", "definition": "oppressive", "kjv": "grievous to be borne."}, "G1420": {"greek": "δυσεντερία", "translit": "dysentería", "pronunciation": "doos-en-ter-ee'-ah", "derivation": "from (G1418) and a compound of (G1787) (meaning a bowel);", "definition": "a \"dysentery\"", "kjv": "bloody flux."}, "G1421": {"greek": "δυσερμήνευτος", "translit": "dysermḗneutos", "pronunciation": "doos-er-mane'-yoo-tos", "derivation": "from (G1418) and a presumed derivative of (G2059);", "definition": "difficult of explanation", "kjv": "hard to be uttered."}, "G1422": {"greek": "δύσκολος", "translit": "dýskolos", "pronunciation": "doo'-kol-os", "derivation": "from (G1418) and (food);", "definition": "properly, fastidious about eating (peevish), i.e. (genitive case) impracticable", "kjv": "hard."}, "G1423": {"greek": "δυσκόλως", "translit": "dyskólōs", "pronunciation": "doos-kol'-oce", "derivation": "adverb from (G1422);", "definition": "impracticably", "kjv": "hardly."}, "G1424": {"greek": "δυσμή", "translit": "dysmḗ", "pronunciation": "doos-may'", "derivation": "from (G1416);", "definition": "the sun-set, i.e. (by implication) the western region", "kjv": "west."}, "G1425": {"greek": "δυσνόητος", "translit": "dysnóētos", "pronunciation": "doos-no'-ay-tos", "derivation": "from (G1418) and a derivative of (G3539);", "definition": "difficult of perception", "kjv": "hard to be understood."}, "G1426": {"greek": "δυσφημία", "translit": "dysphēmía", "pronunciation": "doos-fay-mee'-ah", "derivation": "from a compound of (G1418) and (G5345);", "definition": "defamation", "kjv": "evil report."}, "G1427": {"greek": "δώδεκα", "translit": "dṓdeka", "pronunciation": "do'-dek-ah", "derivation": "from (G1417) and (G1176);", "definition": "two and ten, i.e. a dozen", "kjv": "twelve."}, "G1428": {"greek": "δωδέκατος", "translit": "dōdékatos", "pronunciation": "do-dek'-at-os", "derivation": "from (G1427);", "definition": "twelfth", "kjv": "twelfth."}, "G1429": {"greek": "δωδεκάφυλον", "translit": "dōdekáphylon", "pronunciation": "do-dek-af'-oo-lon", "derivation": "from (G1427) and (G5443);", "definition": "the commonwealth of Israel", "kjv": "twelve tribes."}, "G1430": {"greek": "δῶμα", "translit": "dōma", "pronunciation": "do'-mah", "derivation": "from (to build);", "definition": "properly, an edifice, i.e. (specially) a roof", "kjv": "housetop."}, "G1431": {"greek": "δωρεά", "translit": "dōreá", "pronunciation": "do-reh-ah'", "derivation": "from (G1435);", "definition": "a gratuity", "kjv": "gift."}, "G1432": {"greek": "δωρεάν", "translit": "dōreán", "pronunciation": "do-reh-an'", "derivation": "accusative case of (G1431) as adverb;", "definition": "gratuitously (literally or figuratively)", "kjv": "without a cause, freely, for naught, in vain."}, "G1433": {"greek": "δωρέομαι", "translit": "dōréomai", "pronunciation": "do-reh'-om-ahee", "derivation": "middle voice from (G1435);", "definition": "to bestow gratuitously", "kjv": "give."}, "G1434": {"greek": "δώρημα", "translit": "dṓrēma", "pronunciation": "do'-ray-mah", "derivation": "from (G1433);", "definition": "a bestowment", "kjv": "gift."}, "G1435": {"greek": "δῶρον", "translit": "dōron", "pronunciation": "do'-ron", "derivation": "", "definition": "a present; specially, a sacrifice", "kjv": "gift, offering."}, "G1436": {"greek": "ἔα", "translit": "éa", "pronunciation": "eh'-ah", "derivation": "apparent imperative of (G1439);", "definition": "properly, let it be, i.e. (as interjection) aha!", "kjv": "let alone."}, "G1437": {"greek": "ἐάν", "translit": "eán", "pronunciation": "eh-an'", "derivation": "from (G1487) and (G302);", "definition": "a conditional particle; in case that, provided, etc.; often used in connection with other particles to denote indefiniteness or uncertainty", "kjv": "before, but, except, (and) if, (if) so, (what-, whither-)soever, though, when (-soever), whether (or), to whom, (who-)so(-ever)."}, "G1438": {"greek": "ἑαυτοῦ", "translit": "heautoû", "pronunciation": "heh-ow-too'", "derivation": "from a reflexive pronoun otherwise obsolete and the genitive case (dative case or accusative case) of (G846);", "definition": "him- (her-, it-, them-, also (in conjunction with the personal pronoun of the other persons) my-, thy-, our-, your-) self (selves), etc.", "kjv": "alone, her (own, -self), (he) himself, his (own), itself, one (to) another, our (thine) own(-selves), + that she had, their (own, own selves), (of) them(-selves), they, thyself, you, your (own, own conceits, own selves, -selves)."}, "G1439": {"greek": "ἐάω", "translit": "eáō", "pronunciation": "eh-ah'-o", "derivation": "of uncertain affinity;", "definition": "to let be, i.e. permit or leave alone", "kjv": "commit, leave, let (alone), suffer."}, "G1440": {"greek": "ἑβδομήκοντα", "translit": "hebdomḗkonta", "pronunciation": "heb-dom-ay'-kon-tah", "derivation": "from (G1442) and a modified form of (G1176);", "definition": "seventy", "kjv": "seventy, three score and ten."}, "G1441": {"greek": "ἑβδομηκοντάκις", "translit": "hebdomēkontákis", "pronunciation": "heb-dom-ay-kon-tak-is", "derivation": "multiple adverb from (G1440);", "definition": "seventy times", "kjv": "seventy times."}, "G1442": {"greek": "ἕβδομος", "translit": "hébdomos", "pronunciation": "heb'-dom-os", "derivation": "ordinal from (G2033);", "definition": "seventh", "kjv": "seventh."}, "G1443": {"greek": "Ἐβέρ", "translit": "Ebér", "pronunciation": "eb-er'", "derivation": "of Hebrew origin ((G5677));", "definition": "Eber, a patriarch", "kjv": "Eber."}, "G1445": {"greek": "Ἑβραῖος", "translit": "Hebraîos", "pronunciation": "heb-rah'-yos", "derivation": "from (G1443);", "definition": "a Hebræan (i.e. Hebrew) or Jew", "kjv": "Hebrew."}, "G1446": {"greek": "Ἑβραΐς", "translit": "Hebraḯs", "pronunciation": "heb-rah-is'", "derivation": "from (G1443);", "definition": "the Hebraistic (Hebrew) or Jewish (Chaldee) language", "kjv": "Hebrew."}, "G1447": {"greek": "Ἑβραϊστί", "translit": "Hebraïstí", "pronunciation": "heb-rah-is-tee'", "derivation": "adverb from (G1446);", "definition": "Hebraistically or in the Jewish (Chaldee) language", "kjv": "in (the) Hebrew (tongue)."}, "G1448": {"greek": "ἐγγίζω", "translit": "engízō", "pronunciation": "eng-id'-zo", "derivation": "from (G1451);", "definition": "to make near, i.e. (reflexively) approach", "kjv": "approach, be at hand, come (draw) near, be (come, draw) nigh."}, "G1449": {"greek": "ἐγγράφω", "translit": "engráphō", "pronunciation": "eng-graf'-o", "derivation": "from (G1722) and (G1125);", "definition": "to \"engrave\", i.e. inscribe", "kjv": "write (in)."}, "G1450": {"greek": "ἔγγυος", "translit": "éngyos", "pronunciation": "eng'-goo-os", "derivation": "from (G1722) and (a limb);", "definition": "pledged (as if articulated by a member), i.e. a bondsman", "kjv": "surety."}, "G1451": {"greek": "ἐγγύς", "translit": "engýs", "pronunciation": "eng-goos'", "derivation": "from a primary verb (to squeeze or throttle; akin to the base of (G43));", "definition": "near (literally or figuratively, of place or time)", "kjv": "from , at hand, near, nigh (at hand, unto), ready."}, "G1452": {"greek": "ἐγγύτερον", "translit": "engýteron", "pronunciation": "eng-goo'-ter-on", "derivation": "neuter of the comparative of (G1451);", "definition": "nearer", "kjv": "nearer."}, "G1453": {"greek": "ἐγείρω", "translit": "egeírō", "pronunciation": "eg-i'-ro", "derivation": "probably akin to the base of (G58) (through the idea of collecting one's faculties);", "definition": "to waken (transitively or intransitively), i.e. rouse (literally, from sleep, from sitting or lying, from disease, from death; or figuratively, from obscurity, inactivity, ruins, nonexistence)", "kjv": "awake, lift (up), raise (again, up), rear up, (a-)rise (again, up), stand, take up."}, "G1454": {"greek": "ἔγερσις", "translit": "égersis", "pronunciation": "eg'-er-sis", "derivation": "from (G1453);", "definition": "a resurgence (from death)", "kjv": "resurrection."}, "G1455": {"greek": "ἐγκάθετος", "translit": "enkáthetos", "pronunciation": "eng-kath'-et-os", "derivation": "from (G1722) and a derivative of (G2524);", "definition": "subinduced, i.e. surreptitiously suborned as a lier-in-wait", "kjv": "spy."}, "G1456": {"greek": "ἐγκαίνια", "translit": "enkaínia", "pronunciation": "eng-kah'-ee-nee-ah", "derivation": "neuter plural of a presumed compound from (G1722) and (G2537);", "definition": "innovatives, i.e. (specially) renewal (of religious services after the Antiochian interruption)", "kjv": "dedication."}, "G1457": {"greek": "ἐγκαινίζω", "translit": "enkainízō", "pronunciation": "eng-kahee-nid'-zo", "derivation": "from (G1456);", "definition": "to renew, i.e. inaugurate", "kjv": "consecrate, dedicate."}, "G1458": {"greek": "ἐγκαλέω", "translit": "enkaléō", "pronunciation": "eng-kal-eh'-o", "derivation": "from (G1722) and (G2564);", "definition": "to call in (as a debt or demand), i.e. bring to account (charge, criminate, etc.)", "kjv": "accuse, call in question, implead, lay to the charge."}, "G1459": {"greek": "ἐγκαταλείπω", "translit": "enkataleípō", "pronunciation": "eng-kat-al-i'-po", "derivation": "from (G1722) and (G2641);", "definition": "to leave behind in some place, i.e. (in a good sense) let remain over, or (in a bad sense) to desert", "kjv": "forsake, leave."}, "G1460": {"greek": "ἐγκατοικέω", "translit": "enkatoikéō", "pronunciation": "eng-kat-oy-keh'-o", "derivation": "from (G1722) and (G2730);", "definition": "to settle down in a place, i.e. reside", "kjv": "dwell among."}, "G1461": {"greek": "ἐγκεντρίζω", "translit": "enkentrízō", "pronunciation": "eng-ken-trid'-zo", "derivation": "from (G1722) and a derivative of (G2759);", "definition": "to prick in, i.e. ingraft", "kjv": "graff in(-to)."}, "G1462": {"greek": "ἔγκλημα", "translit": "énklēma", "pronunciation": "eng'-klay-mah", "derivation": "from (G1458);", "definition": "an accusation, i.e. offence alleged", "kjv": "crime laid against, laid to charge."}, "G1463": {"greek": "ἐγκομβόομαι", "translit": "enkombóomai", "pronunciation": "eng-kom-bo'-om-ahee", "derivation": "middle voice from (G1722) and (to gird);", "definition": "to engirdle oneself (for labor), i.e. figuratively (the apron as being a badge of servitude) to wear (in token of mutual deference)", "kjv": "be clothed with."}, "G1464": {"greek": "ἐγκοπή", "translit": "enkopḗ", "pronunciation": "eng-kop-ay'", "derivation": "from (G1465);", "definition": "a hindrance", "kjv": "X hinder."}, "G1465": {"greek": "ἐγκόπτω", "translit": "enkóptō", "pronunciation": "eng-kop'-to", "derivation": "from (G1722) and (G2875);", "definition": "to cut into, i.e. (figuratively) impede, detain", "kjv": "hinder, be tedious unto."}, "G1466": {"greek": "ἐγκράτεια", "translit": "enkráteia", "pronunciation": "eng-krat'-i-ah", "derivation": "from (G1468);", "definition": "self-control (especially continence)", "kjv": "temperance."}, "G1467": {"greek": "ἐγκρατεύομαι", "translit": "enkrateúomai", "pronunciation": "eng-krat-yoo'-om-ahee", "derivation": "middle voice from (G1468);", "definition": "to exercise self-restraint (in diet and chastity)", "kjv": "can(-not) contain, be temperate."}, "G1468": {"greek": "ἐγκρατής", "translit": "enkratḗs", "pronunciation": "eng-krat-ace'", "derivation": "from (G1722) and (G2904);", "definition": "strong in a thing (masterful), i.e. (figuratively and reflexively) self-controlled (in appetite, etc.)", "kjv": "temperate."}, "G1469": {"greek": "ἐγκρίνω", "translit": "enkrínō", "pronunciation": "eng-kree'-no", "derivation": "from (G1722) and (G2919);", "definition": "to judge in, i.e. count among", "kjv": "make of the number."}, "G1470": {"greek": "ἐγκρύπτω", "translit": "enkrýptō", "pronunciation": "eng-kroop'-to", "derivation": "from (G1722) and (G2928);", "definition": "to conceal in, i.e. incorporate with", "kjv": "hid in."}, "G1471": {"greek": "ἔγκυος", "translit": "énkyos", "pronunciation": "eng'-koo-os", "derivation": "from (G1722) and the base of (G2949);", "definition": "swelling inside, i.e. pregnant", "kjv": "great with child."}, "G1472": {"greek": "ἐγχρίω", "translit": "enchríō", "pronunciation": "eng-khree'-o", "derivation": "from (G1722) and (G5548);", "definition": "to rub in (oil), i.e. besmear", "kjv": "anoint."}, "G1473": {"greek": "ἐγώ", "translit": "egṓ", "pronunciation": "eg-o'", "derivation": "a primary pronoun of the first person I (only expressed when emphatic)", "definition": "", "kjv": "I, me."}, "G1474": {"greek": "ἐδαφίζω", "translit": "edaphízō", "pronunciation": "ed-af-id'-zo", "derivation": "from (G1475);", "definition": "to raze", "kjv": "lay even with the ground."}, "G1475": {"greek": "ἔδαφος", "translit": "édaphos", "pronunciation": "ed'-af-os", "derivation": "from the base of (G1476);", "definition": "a basis (bottom), i.e. the soil", "kjv": "ground."}, "G1476": {"greek": "ἑδραῖος", "translit": "hedraîos", "pronunciation": "hed-rah'-yos", "derivation": "from a derivative of (to sit);", "definition": "sedentary, i.e. (by implication) immovable", "kjv": "settled, stedfast."}, "G1477": {"greek": "ἑδραίωμα", "translit": "hedraíōma", "pronunciation": "hed-rah'-yo-mah", "derivation": "from a derivative of (G1476);", "definition": "a support, i.e. (figuratively) basis", "kjv": "ground."}, "G1478": {"greek": "Ἐζεκίας", "translit": "Ezekías", "pronunciation": "ed-zek-ee'-as", "derivation": "of Hebrew origin ((G2396));", "definition": "Ezekias (i.e. Hezekeiah), an Israelite", "kjv": "Ezekias."}, "G1479": {"greek": "ἐθελοθρησκεία", "translit": "ethelothrēskeía", "pronunciation": "eth-el-oth-race-ki'-ah", "derivation": "from (G2309) and (G2356);", "definition": "voluntary (arbitrary and unwarranted) piety, i.e. sanctimony", "kjv": "will worship."}, "G1480": {"greek": "ἐθίζω", "translit": "ethízō", "pronunciation": "eth-id'-zo", "derivation": "from (G1485);", "definition": "to accustom, i.e. (neuter passive participle) customary", "kjv": "custom."}, "G1481": {"greek": "ἐθνάρχης", "translit": "ethnárchēs", "pronunciation": "eth-nar'-khace", "derivation": "from (G1484) and (G746);", "definition": "the governor (not king) of a district", "kjv": "ethnarch."}, "G1482": {"greek": "ἐθνικός", "translit": "ethnikós", "pronunciation": "eth-nee-kos'", "derivation": "from (G1484);", "definition": "national (\"ethnic\"), i.e. (specially) a Gentile", "kjv": "heathen (man)."}, "G1483": {"greek": "ἐθνικῶς", "translit": "ethnikōs", "pronunciation": "eth-nee-koce'", "derivation": "adverb from (G1482);", "definition": "as a Gentile", "kjv": "after the manner of Gentiles."}, "G1484": {"greek": "ἔθνος", "translit": "éthnos", "pronunciation": "eth'-nos", "derivation": "probably from (G1486);", "definition": "a race (as of the same habit), i.e. a tribe; specially, a foreign (non-Jewish) one (usually, by implication, pagan)", "kjv": "Gentile, heathen, nation, people."}, "G1485": {"greek": "ἔθος", "translit": "éthos", "pronunciation": "eth'-os", "derivation": "from (G1486);", "definition": "a usage (prescribed by habit or law)", "kjv": "custom, manner, be wont."}, "G1486": {"greek": "ἔθω", "translit": "éthō", "pronunciation": "eth'-o", "derivation": "a primary verb;", "definition": "to be used (by habit or conventionality); neuter perfect participle usage", "kjv": "be custom (manner, wont)."}, "G1487": {"greek": "εἰ", "translit": "ei", "pronunciation": "i", "derivation": "a primary particle of conditionality;", "definition": "if, whether, that, etc.", "kjv": "forasmuch as, if, that, (al-)though, whether."}, "G1491": {"greek": "εἶδος", "translit": "eîdos", "pronunciation": "i'-dos", "derivation": "from (G1492);", "definition": "a view, i.e. form (literally or figuratively)", "kjv": "appearance, fashion, shape, sight."}, "G1492": {"greek": "εἴδω", "translit": "eídō", "pronunciation": "i'-do", "derivation": "a primary verb;", "definition": "used only in certain past tenses, the others being borrowed from the equivalent (G3700) and (G3708); properly, to see (literally or figuratively); by implication, (in the perfect tense only) to know", "kjv": "be aware, behold, X can (+ not tell), consider, (have) know(-ledge), look (on), perceive, see, be sure, tell, understand, wish, wot."}, "G1493": {"greek": "εἰδωλεῖον", "translit": "eidōleîon", "pronunciation": "i-do-li'-on", "derivation": "neuter of a presumed derivative of (G1497);", "definition": "an image-fane", "kjv": "idol's temple."}, "G1494": {"greek": "εἰδωλόθυτον", "translit": "eidōlóthyton", "pronunciation": "i-do-loth'-oo-ton", "derivation": "neuter of a compound of (G1497) and a presumed derivative of (G2380);", "definition": "an image-sacrifice, i.e. part of an idolatrous offering", "kjv": "(meat, thing that is) offered (in sacrifice, sacrificed) to (unto) idols."}, "G1495": {"greek": "εἰδωλολατρεία", "translit": "eidōlolatreía", "pronunciation": "i-do-lol-at-ri'-ah", "derivation": "from (G1497) and (G2999);", "definition": "image-worship (literally or figuratively)", "kjv": "idolatry."}, "G1496": {"greek": "εἰδωλολάτρης", "translit": "eidōlolátrēs", "pronunciation": "i-do-lol-at'-race", "derivation": "from (G1497) and the base of (G3000);", "definition": "an image- (servant or) worshipper (literally or figuratively)", "kjv": "idolater."}, "G1497": {"greek": "εἴδωλον", "translit": "eídōlon", "pronunciation": "i'-do-lon", "derivation": "from (G1491);", "definition": "an image (i.e. for worship); by implication, a heathen god, or (plural) the worship of such", "kjv": "idol."}, "G1500": {"greek": "εἰκῆ", "translit": "eikē", "pronunciation": "i-kay'", "derivation": "probably from (G1502) (through the idea of failure);", "definition": "idly, i.e. without reason (or effect)", "kjv": "without a cause, (in) vain(-ly)."}, "G1501": {"greek": "εἴκοσι", "translit": "eíkosi", "pronunciation": "i'-kos-ee", "derivation": "of uncertain affinity;", "definition": "a score", "kjv": "twenty."}, "G1502": {"greek": "εἴκω", "translit": "eíkō", "pronunciation": "i'-ko", "derivation": "apparently a primary verb;", "definition": "properly, to be weak, i.e. yield", "kjv": "give place."}, "G1503": {"greek": "εἴκω", "translit": "eíkō", "pronunciation": "i'-ko", "derivation": "apparently a primary verb (perhaps akin to (G1502) through the idea of faintness as a copy);", "definition": "to resemble", "kjv": "be like."}, "G1504": {"greek": "εἰκών", "translit": "eikṓn", "pronunciation": "i-kone'", "derivation": "from (G1503);", "definition": "a likeness, i.e. (literally) statue, profile, or (figuratively) representation, resemblance", "kjv": "image."}, "G1505": {"greek": "εἰλικρίνεια", "translit": "eilikríneia", "pronunciation": "i-lik-ree'-ni-ah", "derivation": "from (G1506);", "definition": "clearness, i.e. (by implication) purity (figuratively)", "kjv": "sincerity."}, "G1506": {"greek": "εἰλικρινής", "translit": "eilikrinḗs", "pronunciation": "i-lik-ree-nace'", "derivation": "from (the sun's ray) and (G2919);", "definition": "judged by sunlight, i.e. tested as genuine (figuratively)", "kjv": "pure, sincere."}, "G1510": {"greek": "εἰμί", "translit": "eimí", "pronunciation": "i-mee'", "derivation": "the first person singular present indicative; a prolonged form of a primary and defective verb;", "definition": "I exist (used only when emphatic)", "kjv": "am, have been, X it is I, was."}, "G1512": {"greek": "εἴ περ", "translit": "eí per", "pronunciation": "i per", "derivation": "from (G1487) and (G4007);", "definition": "if perhaps", "kjv": "if so be (that), seeing, though."}, "G1514": {"greek": "εἰρηνεύω", "translit": "eirēneúō", "pronunciation": "i-rane-yoo'-o", "derivation": "from (G1515);", "definition": "to be (act) peaceful", "kjv": "be at (have, live in) peace, live peaceably."}, "G1515": {"greek": "εἰρήνη", "translit": "eirḗnē", "pronunciation": "i-ray'-nay", "derivation": "probably from a primary verb (to join);", "definition": "peace (literally or figuratively); by implication, prosperity", "kjv": "one, peace, quietness, rest, + set at one again."}, "G1516": {"greek": "εἰρηνικός", "translit": "eirēnikós", "pronunciation": "i-ray-nee-kos'", "derivation": "from (G1515);", "definition": "pacific; by implication, salutary", "kjv": "peaceable."}, "G1517": {"greek": "εἰρηνοποιέω", "translit": "eirēnopoiéō", "pronunciation": "i-ray-nop-oy-eh'-o", "derivation": "from (G1518);", "definition": "to be a peace-maker, i.e. (figuratively) to harmonize", "kjv": "make peace."}, "G1518": {"greek": "εἰρηνοποιός", "translit": "eirēnopoiós", "pronunciation": "i-ray-nop-oy-os'", "derivation": "from (G1515) and (G4160);", "definition": "pacificatory, i.e. (subjectively) peaceable", "kjv": "peacemaker."}, "G1519": {"greek": "εἰς", "translit": "eis", "pronunciation": "ice", "derivation": "a primary preposition;", "definition": "to or into (indicating the point reached or entered), of place, time, or (figuratively) purpose (result, etc.); also in adverbial phrases", "kjv": "(abundant-)ly, against, among, as, at, (back-)ward, before, by, concerning, + continual, + far more exceeding, for (intent, purpose), fore, + forth, in (among, at, unto, -so much that, -to), to the intent that, + of one mind, + never, of, (up-)on, + perish, + set at one again, (so) that, therefore(-unto), throughout, til, to (be, the end, -ward), (here-)until(-to), …ward, (where-)fore, with."}, "G1520": {"greek": "εἷς", "translit": "heîs", "pronunciation": "hice", "derivation": "a primary numeral;", "definition": "one", "kjv": "a(-n, -ny, certain), + abundantly, man, one (another), only, other, some."}, "G1521": {"greek": "εἰσάγω", "translit": "eiságō", "pronunciation": "ice-ag'-o", "derivation": "from (G1519) and (G71);", "definition": "to introduce (literally or figuratively)", "kjv": "bring in(-to), (+ was to) lead into."}, "G1522": {"greek": "εἰσακούω", "translit": "eisakoúō", "pronunciation": "ice-ak-oo'-o", "derivation": "from (G1519) and (G191);", "definition": "to listen to", "kjv": "hear."}, "G1523": {"greek": "εἰσδέχομαι", "translit": "eisdéchomai", "pronunciation": "ice-dekh'-om-ahee", "derivation": "from (G1519) and (G1209);", "definition": "to take into one's favor", "kjv": "receive."}, "G1524": {"greek": "εἴσειμι", "translit": "eíseimi", "pronunciation": "ice'-i-mee", "derivation": "from (G1519) and (to go);", "definition": "to enter", "kjv": "enter (go) into."}, "G1525": {"greek": "εἰσέρχομαι", "translit": "eisérchomai", "pronunciation": "ice-er'-khom-ahee", "derivation": "from (G1519) and (G2064);", "definition": "to enter (literally or figuratively)", "kjv": "X arise, come (in, into), enter in(-to), go in (through)."}, "G1528": {"greek": "εἰσκαλέω", "translit": "eiskaléō", "pronunciation": "ice-kal-eh'-o", "derivation": "from (G1519) and (G2564);", "definition": "to invite in", "kjv": "call in."}, "G1529": {"greek": "εἴσοδος", "translit": "eísodos", "pronunciation": "ice'-od-os", "derivation": "from (G1519) and (G3598);", "definition": "an entrance (literally or figuratively)", "kjv": "coming, enter(-ing) in (to)."}, "G1530": {"greek": "εἰσπηδάω", "translit": "eispēdáō", "pronunciation": "ice-pay-dah'-o", "derivation": "from (G1519) and (to leap);", "definition": "to rush in", "kjv": "run (spring) in."}, "G1531": {"greek": "εἰσπορεύομαι", "translit": "eisporeúomai", "pronunciation": "ice-por-yoo'-om-ahee", "derivation": "from (G1519) and (G4198);", "definition": "to enter (literally or figuratively)", "kjv": "come (enter) in, go into."}, "G1532": {"greek": "εἰστρέχω", "translit": "eistréchō", "pronunciation": "ice-trekh'-o", "derivation": "from (G1519) and (G5143);", "definition": "to hasten inward", "kjv": "run in."}, "G1533": {"greek": "εἰσφέρω", "translit": "eisphérō", "pronunciation": "ice-fer'-o", "derivation": "from (G1519) and (G5342);", "definition": "to carry inward (literally or figuratively)", "kjv": "bring (in), lead into."}, "G1534": {"greek": "εἶτα", "translit": "eîta", "pronunciation": "i'-tah", "derivation": "of uncertain affinity;", "definition": "a particle of succession (in time or logical enumeration), then, moreover", "kjv": "after that(-ward), furthermore, then."}, "G1535": {"greek": "εἴτε", "translit": "eíte", "pronunciation": "i'-teh", "derivation": "from (G1487) and (G5037);", "definition": "if too", "kjv": "if, or, whether."}, "G1537": {"greek": "ἐκ", "translit": "ek", "pronunciation": "ek", "derivation": "a primary preposition denoting origin (the point whence action or motion proceeds), from, out (of place, time, or cause;", "definition": "literal or figurative; direct or remote)", "kjv": "after, among, X are, at, betwixt(-yond), by (the means of), exceedingly, (+ abundantly above), for(- th), from (among, forth, up), + grudgingly, + heartily, X heavenly, X hereby, + very highly, in, …ly, (because, by reason) of, off (from), on, out among (from, of), over, since, X thenceforth, through, X unto, X vehemently, with(-out)."}, "G1538": {"greek": "ἕκαστος", "translit": "hékastos", "pronunciation": "hek'-as-tos", "derivation": "as if a superlative of (afar);", "definition": "each or every", "kjv": "any, both, each (one), every (man, one, woman), particularly."}, "G1539": {"greek": "ἑκάστοτε", "translit": "hekástote", "pronunciation": "hek-as'-tot-eh", "derivation": "as if from (G1538) and (G5119);", "definition": "at every time", "kjv": "always."}, "G1540": {"greek": "ἑκατόν", "translit": "hekatón", "pronunciation": "hek-at-on'", "derivation": "of uncertain affinity;", "definition": "a hundred", "kjv": "hundred."}, "G1541": {"greek": "ἑκατονταέτης", "translit": "hekatontaétēs", "pronunciation": "hek-at-on-tah-et'-ace", "derivation": "from (G1540) and (G2094);", "definition": "centenarian", "kjv": "hundred years old."}, "G1542": {"greek": "ἑκατονταπλασίων", "translit": "hekatontaplasíōn", "pronunciation": "hek-at-on-ta-plah-sec'-own", "derivation": "from (G1540) and a presumed derivative of (G4111);", "definition": "a hundred times", "kjv": "hundredfold."}, "G1543": {"greek": "ἑκατοντάρχης", "translit": "hekatontárchēs", "pronunciation": "hek-at-on-tar'-khace", "derivation": "from (G1540) and (G757);", "definition": "the captain of one hundred men", "kjv": "centurion."}, "G1544": {"greek": "ἐκβάλλω", "translit": "ekbállō", "pronunciation": "ek-bal'-lo", "derivation": "from (G1537) and (G906);", "definition": "to eject (literally or figuratively)", "kjv": "bring forth, cast (forth, out), drive (out), expel, leave, pluck (pull, take, thrust) out, put forth (out), send away (forth, out)."}, "G1545": {"greek": "ἔκβασις", "translit": "ékbasis", "pronunciation": "ek'-bas-is", "derivation": "from a compound of (G1537) and the base of (G939) (meaning to go out);", "definition": "an exit (literally or figuratively)", "kjv": "end, way to escape."}, "G1546": {"greek": "ἐκβολή", "translit": "ekbolḗ", "pronunciation": "ek-bol-ay'", "derivation": "from (G1544);", "definition": "ejection, i.e. (specially) a throwing overboard of the cargo", "kjv": "+ lighten the ship."}, "G1549": {"greek": "ἔκγονον", "translit": "ékgonon", "pronunciation": "ek'-gon-on", "derivation": "neuter of a derivative of a compound of (G1537) and (G1096);", "definition": "a descendant, i.e. (specially) grandchild", "kjv": "nephew."}, "G1550": {"greek": "ἐκδαπανάω", "translit": "ekdapanáō", "pronunciation": "ek-dap-an-ah'-o", "derivation": "from (G1537) and (G1159);", "definition": "to expend (wholly), i.e. (figuratively) exhaust", "kjv": "spend."}, "G1551": {"greek": "ἐκδέχομαι", "translit": "ekdéchomai", "pronunciation": "ek-dekh'-om-ahee", "derivation": "from (G1537) and (G1209);", "definition": "to accept from some source, i.e. (by implication) to await", "kjv": "expect, look (tarry) for, wait (for)."}, "G1552": {"greek": "ἔκδηλος", "translit": "ékdēlos", "pronunciation": "ek'-day-los", "derivation": "from (G1537) and (G1212);", "definition": "wholly evident", "kjv": "manifest."}, "G1553": {"greek": "ἐκδημέω", "translit": "ekdēméō", "pronunciation": "ek-day-meh'-o", "derivation": "from a compound of (G1537) and (G1218);", "definition": "to emigrate, i.e. (figuratively) vacate or quit", "kjv": "be absent."}, "G1554": {"greek": "ἐκδίδωμι", "translit": "ekdídōmi", "pronunciation": "ek-did-o'-mee", "derivation": "from (G1537) and (G1325);", "definition": "to give forth, i.e. (specially) to lease", "kjv": "let forth (out)."}, "G1555": {"greek": "ἐκδιηγέομαι", "translit": "ekdiēgéomai", "pronunciation": "ek-dee-ayg-eh'-om-ahee", "derivation": "from (G1537) and a compound of (G1223) and (G2233);", "definition": "to narrate through wholly", "kjv": "declare."}, "G1556": {"greek": "ἐκδικέω", "translit": "ekdikéō", "pronunciation": "ek-dik-eh'-o", "derivation": "from (G1558);", "definition": "to vindicate, retaliate, punish", "kjv": "a (re-)venge."}, "G1557": {"greek": "ἐκδίκησις", "translit": "ekdíkēsis", "pronunciation": "ek-dik'-ay-sis", "derivation": "from (G1556);", "definition": "vindication, retribution", "kjv": "(a-, re-)venge(-ance), punishment."}, "G1558": {"greek": "ἔκδικος", "translit": "ékdikos", "pronunciation": "ek'-dik-os", "derivation": "from (G1537) and (G1349);", "definition": "carrying justice out, i.e. a punisher", "kjv": "a (re-)venger."}, "G1559": {"greek": "ἐκδιώκω", "translit": "ekdiṓkō", "pronunciation": "ek-dee-o'-ko", "derivation": "from (G1537) and (G1377);", "definition": "to pursue out, i.e. expel or persecute implacably", "kjv": "persecute."}, "G1560": {"greek": "ἔκδοτος", "translit": "ékdotos", "pronunciation": "ek'-dot-os", "derivation": "from (G1537) and a derivative of (G1325);", "definition": "given out or over, i.e. surrendered", "kjv": "delivered."}, "G1561": {"greek": "ἐκδοχή", "translit": "ekdochḗ", "pronunciation": "ek-dokh-ay'", "derivation": "from (G1551);", "definition": "expectation", "kjv": "looking for."}, "G1562": {"greek": "ἐκδύω", "translit": "ekdýō", "pronunciation": "ek-doo'-o", "derivation": "from (G1537) and the base of (G1416);", "definition": "to cause to sink out of, i.e. (specially as of clothing) to divest", "kjv": "strip, take off from, unclothe."}, "G1563": {"greek": "ἐκεῖ", "translit": "ekeî", "pronunciation": "ek-i'", "derivation": "of uncertain affinity;", "definition": "there; by extension, thither", "kjv": "there, thither(-ward), (to) yonder (place)."}, "G1564": {"greek": "ἐκεῖθεν", "translit": "ekeîthen", "pronunciation": "ek-i'-then", "derivation": "from (G1563);", "definition": "thence", "kjv": "from that place, (from) thence, there."}, "G1565": {"greek": "ἐκεῖνος", "translit": "ekeînos", "pronunciation": "ek-i'-nos", "derivation": "from (G1563);", "definition": "that one (or (neuter) thing); often intensified by the article prefixed", "kjv": "he, it, the other (same), selfsame, that (same, very), X their, X them, they, this, those."}, "G1566": {"greek": "ἐκεῖσε", "translit": "ekeîse", "pronunciation": "ek-i'-seh", "derivation": "from (G1563);", "definition": "thither", "kjv": "there."}, "G1567": {"greek": "ἐκζητέω", "translit": "ekzētéō", "pronunciation": "ek-zay-teh'-o", "derivation": "from (G1537) and (G2212);", "definition": "to search out, i.e. (figuratively)investigate, crave, demand, (by Hebraism) worship", "kjv": "en- (re-)quire, seek after (carefully, diligently)."}, "G1568": {"greek": "ἐκθαμβέω", "translit": "ekthambéō", "pronunciation": "ek-tham-beh'-o", "derivation": "from (G1569);", "definition": "to astonish utterly", "kjv": "affright, greatly (sore) amaze."}, "G1569": {"greek": "ἔκθαμβος", "translit": "ékthambos", "pronunciation": "ek'-tham-bos", "derivation": "from (G1537) and (G2285);", "definition": "utterly astounded", "kjv": "greatly wondering."}, "G1570": {"greek": "ἔκθετος", "translit": "ékthetos", "pronunciation": "ek'-thet-os", "derivation": "from (G1537) and a derivative of (G5087);", "definition": "put out, i.e. exposed to perish", "kjv": "cast out."}, "G1571": {"greek": "ἐκκαθαίρω", "translit": "ekkathaírō", "pronunciation": "ek-kath-ah'-ee-ro", "derivation": "from (G1537) and (G2508);", "definition": "to cleanse thoroughly", "kjv": "purge (out)."}, "G1572": {"greek": "ἐκκαίω", "translit": "ekkaíō", "pronunciation": "ek-kah'-yo", "derivation": "from (G1537) and (G2545);", "definition": "to inflame deeply", "kjv": "burn."}, "G1573": {"greek": "ἐκκακέω", "translit": "ekkakéō", "pronunciation": "ek-kak-eh'-o", "derivation": "from (G1537) and (G2556);", "definition": "to be (bad or) weak, i.e. (by implication) to fail (in heart)", "kjv": "faint, be weary."}, "G1574": {"greek": "ἐκκεντέω", "translit": "ekkentéō", "pronunciation": "ek-ken-teh'-o", "derivation": "from (G1537) and the base of (G2759);", "definition": "to transfix", "kjv": "pierce."}, "G1575": {"greek": "ἐκκλάω", "translit": "ekkláō", "pronunciation": "ek-klah'-o", "derivation": "from (G1537) and (G2806);", "definition": "to exscind", "kjv": "break off."}, "G1576": {"greek": "ἐκκλείω", "translit": "ekkleíō", "pronunciation": "ek-kli'-o", "derivation": "from (G1537) and (G2808);", "definition": "to shut out (literally or figuratively)", "kjv": "exclude."}, "G1577": {"greek": "ἐκκλησία", "translit": "ekklēsía", "pronunciation": "ek-klay-see'-ah", "derivation": "from a compound of (G1537) and a derivative of (G2564);", "definition": "a calling out, i.e. (concretely) a popular meeting, especially a religious congregation (Jewish synagogue, or Christian community of members on earth or saints in heaven or both)", "kjv": "assembly, church."}, "G1578": {"greek": "ἐκκλίνω", "translit": "ekklínō", "pronunciation": "ek-klee'-no", "derivation": "from (G1537) and (G2827);", "definition": "to deviate, i.e. (absolutely) to shun (literally or figuratively), or (relatively) to decline (from piety)", "kjv": "avoid, eschew, go out of the way."}, "G1579": {"greek": "ἐκκολυμβάω", "translit": "ekkolymbáō", "pronunciation": "ek-kol-oom-bah'-o", "derivation": "from (G1537) and (G2860);", "definition": "to escape by swimming", "kjv": "swim out."}, "G1580": {"greek": "ἐκκομίζω", "translit": "ekkomízō", "pronunciation": "ek-kom-id'-zo", "derivation": "from (G1537) and (G2865);", "definition": "to bear forth (to burial)", "kjv": "carry out."}, "G1581": {"greek": "ἐκκόπτω", "translit": "ekkóptō", "pronunciation": "ek-kop'-to", "derivation": "from (G1537) and (G2875);", "definition": "to exscind; figuratively, to frustrate", "kjv": "cut down (off, out), hew down, hinder."}, "G1582": {"greek": "ἐκκρέμαμαι", "translit": "ekkrémamai", "pronunciation": "ek-krem'-am-ahee", "derivation": "middle voice from (G1537) and (G2910);", "definition": "to hang upon the lips of a speaker, i.e. listen closely", "kjv": "be very attentive."}, "G1583": {"greek": "ἐκλαλέω", "translit": "eklaléō", "pronunciation": "ek-lal-eh'-o", "derivation": "from (G1537) and (G2980);", "definition": "to divulge", "kjv": "tell."}, "G1584": {"greek": "ἐκλάμπω", "translit": "eklámpō", "pronunciation": "ek-lam'-po", "derivation": "from (G1537) and (G2989);", "definition": "to be resplendent", "kjv": "shine forth."}, "G1585": {"greek": "ἐκλανθάνομαι", "translit": "eklanthánomai", "pronunciation": "ek-lan-than'-om-ahee", "derivation": "middle voice from (G1537) and (G2990);", "definition": "to be utterly oblivious of", "kjv": "forget."}, "G1586": {"greek": "ἐκλέγομαι", "translit": "eklégomai", "pronunciation": "ek-leg'-om-ahee", "derivation": "middle voice from (G1537) and (G3004) (in its primary sense);", "definition": "to select", "kjv": "make choice, choose (out), chosen."}, "G1587": {"greek": "ἐκλείπω", "translit": "ekleípō", "pronunciation": "ek-li'-po", "derivation": "from (G1537) and (G3007);", "definition": "to omit, i.e. (by implication) cease (die)", "kjv": "fail."}, "G1588": {"greek": "ἐκλεκτός", "translit": "eklektós", "pronunciation": "ek-lek-tos'", "derivation": "from (G1586);", "definition": "select; by implication, favorite", "kjv": "chosen, elect."}, "G1589": {"greek": "ἐκλογή", "translit": "eklogḗ", "pronunciation": "ek-log-ay'", "derivation": "from (G1586);", "definition": "(divine) selection (abstractly or concretely)", "kjv": "chosen, election."}, "G1590": {"greek": "ἐκλύω", "translit": "eklýō", "pronunciation": "ek-loo'-o", "derivation": "from (G1537) and (G3089);", "definition": "to relax (literally or figuratively)", "kjv": "faint."}, "G1591": {"greek": "ἐκμάσσω", "translit": "ekmássō", "pronunciation": "ek-mas'-so", "derivation": "from (G1537) and the base of (G3145);", "definition": "to knead out, i.e. (by analogy) to wipe dry", "kjv": "wipe."}, "G1592": {"greek": "ἐκμυκτηρίζω", "translit": "ekmyktērízō", "pronunciation": "ek-mook-ter-id'-zo", "derivation": "from (G1537) and (G3456);", "definition": "to sneer outright at", "kjv": "deride."}, "G1593": {"greek": "ἐκνεύω", "translit": "ekneúō", "pronunciation": "ek-nyoo'-o", "derivation": "from (G1537) and (G3506);", "definition": "(by analogy) to slip off, i.e. quietly withdraw", "kjv": "convey self away."}, "G1594": {"greek": "ἐκνήφω", "translit": "eknḗphō", "pronunciation": "ek-nay'-fo", "derivation": "from (G1537) and (G3525);", "definition": "(figuratively) to rouse (oneself) out of stupor", "kjv": "awake."}, "G1595": {"greek": "ἑκούσιον", "translit": "hekoúsion", "pronunciation": "hek-oo'-see-on", "derivation": "neuter of a derivative from (G1635);", "definition": "voluntariness", "kjv": "willingly."}, "G1596": {"greek": "ἑκουσίως", "translit": "hekousíōs", "pronunciation": "hek-oo-see'-ose", "derivation": "adverb from the same as (G1595);", "definition": "voluntarily", "kjv": "wilfully, willingly."}, "G1597": {"greek": "ἔκπαλαι", "translit": "ékpalai", "pronunciation": "eh'-pal-ahee", "derivation": "from (G1537) and (G3819);", "definition": "long ago, for a long while", "kjv": "of a long time, of old."}, "G1598": {"greek": "ἐκπειράζω", "translit": "ekpeirázō", "pronunciation": "ek-pi-rad'-zo", "derivation": "from (G1537) and (G3985);", "definition": "to test thoroughly", "kjv": "tempt."}, "G1599": {"greek": "ἐκπέμπω", "translit": "ekpémpō", "pronunciation": "ek-pem'-po", "derivation": "from (G1537) and (G3992);", "definition": "to despatch", "kjv": "send away (forth)."}, "G1600": {"greek": "ἐκπετάννυμι", "translit": "ekpetánnymi", "pronunciation": "ek-pet-an'-noo-mee", "derivation": "from (G1537) and a form of (G4072);", "definition": "to fly out, i.e. (by analogy) to extend", "kjv": "stretch forth."}, "G1601": {"greek": "ἐκπίπτω", "translit": "ekpíptō", "pronunciation": "ek-pip'-to", "derivation": "from (G1537) and (G4098);", "definition": "to drop away; specially, be driven out of one's course; figuratively, to lose, become inefficient", "kjv": "be cast, fail, fall (away, off), take none effect."}, "G1602": {"greek": "ἐκπλέω", "translit": "ekpléō", "pronunciation": "ek-pleh'-o", "derivation": "from (G1537) and (G4126);", "definition": "to depart by ship", "kjv": "sail (away, thence)."}, "G1603": {"greek": "ἐκπληρόω", "translit": "ekplēróō", "pronunciation": "ek-play-ro'-o", "derivation": "from (G1537) and (G4137);", "definition": "to accomplish entirely", "kjv": "fulfill."}, "G1604": {"greek": "ἐκπλήρωσις", "translit": "ekplḗrōsis", "pronunciation": "ek-play'-ro-sis", "derivation": "from (G1603);", "definition": "completion", "kjv": "accomplishment."}, "G1605": {"greek": "ἐκπλήσσω", "translit": "ekplḗssō", "pronunciation": "ek-place'-so", "derivation": "from (G1537) and (G4141);", "definition": "to strike with astonishment", "kjv": "amaze, astonish."}, "G1606": {"greek": "ἐκπνέω", "translit": "ekpnéō", "pronunciation": "ek-pneh'-o", "derivation": "from (G1537) and (G4154);", "definition": "to expire", "kjv": "give up the ghost."}, "G1607": {"greek": "ἐκπορεύομαι", "translit": "ekporeúomai", "pronunciation": "ek-por-yoo'-om-ahee", "derivation": "from (G1537) and (G4198);", "definition": "to depart, be discharged, proceed, project", "kjv": "come (forth, out of), depart, go (forth, out), issue, proceed (out of)."}, "G1608": {"greek": "ἐκπορνεύω", "translit": "ekporneúō", "pronunciation": "ek-porn-yoo'-o", "derivation": "from (G1537) and (G4203);", "definition": "to be utterly unchaste", "kjv": "give self over to fornication."}, "G1609": {"greek": "ἐκπτύω", "translit": "ekptýō", "pronunciation": "ek-ptoo'-o", "derivation": "from (G1537) and (G4429);", "definition": "to spit out, i.e. (figuratively) spurn", "kjv": "reject."}, "G1610": {"greek": "ἐκριζόω", "translit": "ekrizóō", "pronunciation": "ek-rid-zo'-o", "derivation": "from (G1537) and (G4492);", "definition": "to uproot", "kjv": "pluck up by the root, root up."}, "G1611": {"greek": "ἔκστασις", "translit": "ékstasis", "pronunciation": "ek'-stas-is", "derivation": "from (G1839);", "definition": "a displacement of the mind, i.e. bewilderment, \"ecstasy\"", "kjv": "+ be amazed, amazement, astonishment, trance."}, "G1612": {"greek": "ἐκστρέφω", "translit": "ekstréphō", "pronunciation": "ek-stref'-o", "derivation": "from (G1537) and (G4762);", "definition": "to pervert (figuratively)", "kjv": "subvert."}, "G1613": {"greek": "ἐκταράσσω", "translit": "ektarássō", "pronunciation": "ek-tar-as'-so", "derivation": "from (G1537) and (G5015);", "definition": "to disturb wholly", "kjv": "exceedingly trouble."}, "G1614": {"greek": "ἐκτείνω", "translit": "ekteínō", "pronunciation": "ek-ti'-no", "derivation": "from (G1537) and teino (to stretch);", "definition": "to extend", "kjv": "cast, put forth, stretch forth (out)."}, "G1615": {"greek": "ἐκτελέω", "translit": "ekteléō", "pronunciation": "ek-tel-eh'-o", "derivation": "from (G1537) and (G5055);", "definition": "to complete fully", "kjv": "finish."}, "G1616": {"greek": "ἐκτένεια", "translit": "ekténeia", "pronunciation": "ek-ten'-i-ah", "derivation": "from (G1618);", "definition": "intentness", "kjv": "X instantly."}, "G1617": {"greek": "ἐκτενέστερον", "translit": "ektenésteron", "pronunciation": "ek-ten-es'-ter-on", "derivation": "neuter of the comparative of (G1618);", "definition": "more intently", "kjv": "more earnestly."}, "G1618": {"greek": "ἐκτενής", "translit": "ektenḗs", "pronunciation": "ek-ten-ace'", "derivation": "from (G1614);", "definition": "intent", "kjv": "without ceasing, fervent."}, "G1619": {"greek": "ἐκτενῶς", "translit": "ektenōs", "pronunciation": "ek-ten-oce'", "derivation": "adverb from (G1618);", "definition": "intently", "kjv": "fervently."}, "G1620": {"greek": "ἐκτίθημι", "translit": "ektíthēmi", "pronunciation": "ek-tith'-ay-mee", "derivation": "from (G1537) and (G5087);", "definition": "to expose; figuratively, to declare", "kjv": "cast out, expound."}, "G1621": {"greek": "ἐκτινάσσω", "translit": "ektinássō", "pronunciation": "ek-tin-as'-so", "derivation": "from (G1537) and tinasso (to swing);", "definition": "to shake violently", "kjv": "shake (off)."}, "G1622": {"greek": "ἐκτός", "translit": "ektós", "pronunciation": "ek-tos'", "derivation": "from (G1537);", "definition": "the exterior; figuratively (as a preposition) aside from, besides", "kjv": "but, except(-ed), other than, out of, outside, unless, without."}, "G1624": {"greek": "ἐκτρέπω", "translit": "ektrépō", "pronunciation": "ek-trep'-o", "derivation": "from (G1537) and the base of (G5157);", "definition": "to deflect, i.e. turn away (literally or figuratively)", "kjv": "avoid, turn (aside, out of the way)."}, "G1625": {"greek": "ἐκτρέφω", "translit": "ektréphō", "pronunciation": "ek-tref'-o", "derivation": "from (G1537) and (G5142);", "definition": "to rear up to maturity, i.e. (genitive case) to cherish or train", "kjv": "bring up, nourish."}, "G1626": {"greek": "ἔκτρωμα", "translit": "éktrōma", "pronunciation": "ek'-tro-mah", "derivation": "from a compound of (G1537) and (to wound);", "definition": "a miscarriage (abortion), i.e. (by analogy) untimely birth", "kjv": "born out of due time."}, "G1627": {"greek": "ἐκφέρω", "translit": "ekphérō", "pronunciation": "ek-fer'-o", "derivation": "from (G1537) and (G5342);", "definition": "to bear out (literally or figuratively)", "kjv": "bear, bring forth, carry forth (out)."}, "G1628": {"greek": "ἐκφεύγω", "translit": "ekpheúgō", "pronunciation": "ek-fyoo'-go", "derivation": "from (G1537) and (G5343);", "definition": "to flee out", "kjv": "escape, flee."}, "G1629": {"greek": "ἐκφοβέω", "translit": "ekphobéō", "pronunciation": "ek-fob-eh'-o", "derivation": "from (G1537) and (G5399);", "definition": "to frighten utterly", "kjv": "terrify."}, "G1630": {"greek": "ἔκφοβος", "translit": "ékphobos", "pronunciation": "ek'-fob-os", "derivation": "from (G1537) and (G5401);", "definition": "frightened out of one's wits", "kjv": "sore afraid, exceedingly fear."}, "G1631": {"greek": "ἐκφύω", "translit": "ekphýō", "pronunciation": "ek-foo'-o", "derivation": "from (G1537) and (G5453);", "definition": "to sprout up", "kjv": "put forth."}, "G1632": {"greek": "ἐκχέω", "translit": "ekchéō", "pronunciation": "ek-kheh'-o", "derivation": "from (G1537) and (to pour);", "definition": "to pour forth; figuratively, to bestow", "kjv": "gush (pour) out, run greedily (out), shed (abroad, forth), spill."}, "G1633": {"greek": "ἐκχωρέω", "translit": "ekchōréō", "pronunciation": "ek-kho-reh'-o", "derivation": "from (G1537) and (G5562);", "definition": "to depart", "kjv": "depart out."}, "G1634": {"greek": "ἐκψύχω", "translit": "ekpsýchō", "pronunciation": "ek-psoo'-kho", "derivation": "from (G1537) and (G5594);", "definition": "to expire", "kjv": "give (yield) up the ghost."}, "G1635": {"greek": "ἑκών", "translit": "hekṓn", "pronunciation": "hek-own'", "derivation": "of uncertain affinity;", "definition": "voluntary", "kjv": "willingly."}, "G1636": {"greek": "ἐλαία", "translit": "elaía", "pronunciation": "el-ah'-yah", "derivation": "feminine of a presumed derivative from an obsolete primary;", "definition": "an olive (the tree or the fruit)", "kjv": "olive (berry, tree)."}, "G1637": {"greek": "ἔλαιον", "translit": "élaion", "pronunciation": "el'-ah-yon", "derivation": "neuter of the same as (G1636);", "definition": "olive oil", "kjv": "oil."}, "G1638": {"greek": "ἐλαιών", "translit": "elaiṓn", "pronunciation": "el-ah-yone'", "derivation": "from (G1636);", "definition": "an olive-orchard, i.e. (specially) the Mount of Olives", "kjv": "Olivet."}, "G1639": {"greek": "Ἐλαμίτης", "translit": "Elamítēs", "pronunciation": "el-am-ee'-tace", "derivation": "of Hebrew origin ((G5867));", "definition": "an Elamite or Persian", "kjv": "Elamite."}, "G1640": {"greek": "ἐλάσσων", "translit": "elássōn", "pronunciation": "el-as'-sone", "derivation": "comparative of the same as (G1646);", "definition": "smaller (in size, quantity, age or quality)", "kjv": "less, under, worse, younger."}, "G1641": {"greek": "ἐλαττονέω", "translit": "elattonéō", "pronunciation": "el-at-ton-eh-o", "derivation": "from (G1640);", "definition": "to diminish, i.e. fall short", "kjv": "have lack."}, "G1642": {"greek": "ἐλαττόω", "translit": "elattóō", "pronunciation": "el-at-to'-o", "derivation": "from (G1640);", "definition": "to lessen (in rank or influence)", "kjv": "decrease, make lower."}, "G1643": {"greek": "ἐλαύνω", "translit": "elaúnō", "pronunciation": "el-ow'-no", "derivation": "a prolonged form of a primary verb (obsolete except in certain tenses as an alternative of this) of uncertain affinity;", "definition": "to push (as wind, oars or dæmonical power)", "kjv": "carry, drive, row."}, "G1644": {"greek": "ἐλαφρία", "translit": "elaphría", "pronunciation": "el-af-ree'-ah", "derivation": "from (G1645);", "definition": "levity (figuratively), i.e. fickleness", "kjv": "lightness."}, "G1645": {"greek": "ἐλαφρός", "translit": "elaphrós", "pronunciation": "el-af-ros'", "derivation": "probably akin to (G1643) and the base of (G1640);", "definition": "light, i.e. easy", "kjv": "light."}, "G1646": {"greek": "ἐλάχιστος", "translit": "eláchistos", "pronunciation": "el-akh'-is-tos", "derivation": "superlative of (short);", "definition": "used as equivalent to (G3398); least (in size, amount, dignity, etc.)", "kjv": "least, very little (small), smallest."}, "G1648": {"greek": "Ἐλεάζαρ", "translit": "Eleázar", "pronunciation": "el-eh-ad'-zar", "derivation": "of Hebrew origin ((G499));", "definition": "Eleazar, an Israelite", "kjv": "Eleazar."}, "G1649": {"greek": "ἔλεγξις", "translit": "élenxis", "pronunciation": "el'-eng-xis", "derivation": "from (G1651);", "definition": "refutation, i.e. reproof", "kjv": "rebuke."}, "G1650": {"greek": "ἔλεγχος", "translit": "élenchos", "pronunciation": "el'-eng-khos", "derivation": "from (G1651);", "definition": "proof, conviction", "kjv": "evidence, reproof."}, "G1651": {"greek": "ἐλέγχω", "translit": "elénchō", "pronunciation": "el-eng'-kho", "derivation": "of uncertain affinity;", "definition": "to confute, admonish", "kjv": "convict, convince, tell a fault, rebuke, reprove."}, "G1652": {"greek": "ἐλεεινός", "translit": "eleeinós", "pronunciation": "el-eh-i-nos'", "derivation": "from (G1656);", "definition": "pitiable", "kjv": "miserable."}, "G1653": {"greek": "ἐλεέω", "translit": "eleéō", "pronunciation": "el-eh-eh'-o", "derivation": "from (G1656);", "definition": "to compassionate (by word or deed, specially, by divine grace)", "kjv": "have compassion (pity on), have (obtain, receive, shew) mercy (on)."}, "G1654": {"greek": "ἐλεημοσύνη", "translit": "eleēmosýnē", "pronunciation": "el-eh-ay-mos-oo'-nay", "derivation": "from (G1656);", "definition": "compassionateness, i.e. (as exercised towards the poor) beneficence, or (concretely) a benefaction", "kjv": "alms(-deeds)."}, "G1655": {"greek": "ἐλεήμων", "translit": "eleḗmōn", "pronunciation": "el-eh-ay'-mone", "derivation": "from (G1653);", "definition": "compassionate (actively)", "kjv": "merciful."}, "G1656": {"greek": "ἔλεος", "translit": "éleos", "pronunciation": "el'-eh-os", "derivation": "of uncertain affinity;", "definition": "compassion (human or divine, especially active)", "kjv": "(+ tender) mercy."}, "G1657": {"greek": "ἐλευθερία", "translit": "eleuthería", "pronunciation": "el-yoo-ther-ee'-ah", "derivation": "from (G1658);", "definition": "freedom (legitimate or licentious, chiefly moral or ceremonial)", "kjv": "liberty."}, "G1658": {"greek": "ἐλεύθερος", "translit": "eleútheros", "pronunciation": "el-yoo'-ther-os", "derivation": "probably from the alternate of (G2064);", "definition": "unrestrained (to go at pleasure), i.e. (as a citizen) not a slave (whether freeborn or manumitted), or (genitive case) exempt (from obligation or liability)", "kjv": "free (man, woman), at liberty."}, "G1659": {"greek": "ἐλευθερόω", "translit": "eleutheróō", "pronunciation": "el-yoo-ther-o'-o", "derivation": "from (G1658);", "definition": "to liberate, i.e. (figuratively) to exempt (from moral, ceremonial or mortal liability)", "kjv": "deliver, make free."}, "G1660": {"greek": "ἔλευσις", "translit": "éleusis", "pronunciation": "el'-yoo-sis", "derivation": "from the alternate of (G2064);", "definition": "an advent", "kjv": "coming."}, "G1661": {"greek": "ἐλεφάντινος", "translit": "elephántinos", "pronunciation": "el-ef-an'-tee-nos", "derivation": "from (an \"elephant\");", "definition": "elephantine, i.e. (by implication) composed of ivory", "kjv": "of ivory."}, "G1662": {"greek": "Ἐλιακείμ", "translit": "Eliakeím", "pronunciation": "el-ee-ak-ime'", "derivation": "of Hebrew origin ((G471));", "definition": "Eliakim, an Israelite", "kjv": "Eliakim."}, "G1663": {"greek": "Ἐλιέζερ", "translit": "Eliézer", "pronunciation": "el-ee-ed'-zer", "derivation": "of Hebrew origin ((G461));", "definition": "Eliezer, an Israelite", "kjv": "Eliezer."}, "G1664": {"greek": "Ἐλιούδ", "translit": "Elioúd", "pronunciation": "el-ee-ood'", "derivation": "of Hebrew origin ((G410) and (G1935));", "definition": "God of majesty; Eliud, an Israelite", "kjv": "Eliud."}, "G1665": {"greek": "Ἐλισάβετ", "translit": "Elisábet", "pronunciation": "el-ee-sab'-et", "derivation": "of Hebrew origin ((G472));", "definition": "Elisabet, an Israelitess", "kjv": "Elisabeth."}, "G1666": {"greek": "Ἐλισσαῖος", "translit": "Elissaîos", "pronunciation": "el-is-sah'-yos", "derivation": "of Hebrew origin ((G477));", "definition": "Elissæus, an Israelite", "kjv": "Elissæus."}, "G1667": {"greek": "ἑλίσσω", "translit": "helíssō", "pronunciation": "hel-is'-so", "derivation": "a form of (G1507);", "definition": "to coil or wrap", "kjv": "fold up."}, "G1668": {"greek": "ἕλκος", "translit": "hélkos", "pronunciation": "hel'-kos", "derivation": "probably from (G1670);", "definition": "an ulcer (as if drawn together)", "kjv": "sore."}, "G1669": {"greek": "ἑλκόω", "translit": "helkóō", "pronunciation": "hel-ko'-o", "derivation": "from (G1668);", "definition": "to cause to ulcerate, i.e. (passively) be ulcerous", "kjv": "full of sores."}, "G1670": {"greek": "ἑλκύω", "translit": "helkýō", "pronunciation": "hel-koo'-o", "derivation": "probably akin to (G138);", "definition": "to drag (literally or figuratively)", "kjv": "draw."}, "G1671": {"greek": "Ἑλλάς", "translit": "Hellás", "pronunciation": "hel-las'", "derivation": "of uncertain affinity;", "definition": "Hellas (or Greece), a country of Europe", "kjv": "Greece."}, "G1672": {"greek": "Ἕλλην", "translit": "Héllēn", "pronunciation": "hel'-lane", "derivation": "from (G1671);", "definition": "a Hellen (Grecian) or inhabitant of Hellas; by extension a Greek-speaking person, especially a non-Jew", "kjv": "Gentile, Greek."}, "G1673": {"greek": "Ἑλληνικός", "translit": "Hellēnikós", "pronunciation": "hel-lay-nee-kos'", "derivation": "from (G1672);", "definition": "Hellenic, i.e. Grecian (in language)", "kjv": "Greek."}, "G1674": {"greek": "Ἑλληνίς", "translit": "Hellēnís", "pronunciation": "hel-lay-nis'", "derivation": "feminine of (G1672);", "definition": "a Grecian (i.e. non-Jewish) woman", "kjv": "Greek."}, "G1675": {"greek": "Ἑλληνιστής", "translit": "Hellēnistḗs", "pronunciation": "hel-lay-nis-tace'", "derivation": "from a derivative of (G1672);", "definition": "a Hellenist or Greek-speaking Jew", "kjv": "Grecian."}, "G1676": {"greek": "Ἑλληνιστί", "translit": "Hellēnistí", "pronunciation": "hel-lay-nis-tee'", "derivation": "adverb from the same as (G1675);", "definition": "Hellenistically, i.e. in the Grecian language", "kjv": "Greek."}, "G1677": {"greek": "ἐλλογέω", "translit": "ellogéō", "pronunciation": "el-log-eh'-o", "derivation": "from (G1722) and (G3056) (in the sense of account);", "definition": "to reckon in, i.e. attribute", "kjv": "impute, put on account."}, "G1678": {"greek": "Ἐλμωδάμ", "translit": "Elmōdám", "pronunciation": "el-mo-dam'", "derivation": "of Hebrew origin (perhaps for (G486));", "definition": "Elmodam, an Israelite", "kjv": "Elmodam."}, "G1679": {"greek": "ἐλπίζω", "translit": "elpízō", "pronunciation": "el-pid'-zo", "derivation": "from (G1680);", "definition": "to expect or confide", "kjv": "(have, thing) hope(-d) (for), trust."}, "G1680": {"greek": "ἐλπίς", "translit": "elpís", "pronunciation": "el-pece'", "derivation": "from a primary (to anticipate, usually with pleasure);", "definition": "expectation (abstractly or concretely) or confidence", "kjv": "faith, hope."}, "G1681": {"greek": "Ἐλύμας", "translit": "Elýmas", "pronunciation": "el-oo'-mas", "derivation": "of foreign origin;", "definition": "Elymas, a wizard", "kjv": "Elymas."}, "G1682": {"greek": "ἐλοΐ", "translit": "eloḯ", "pronunciation": "el-o-ee'", "derivation": "of Chaldean origin ((G426) with pronominal suffix) my God", "definition": "", "kjv": "Eloi."}, "G1683": {"greek": "ἐμαυτοῦ", "translit": "emautoû", "pronunciation": "em-ow-too'", "derivation": "genitive case compound of (G1700) and (G846);", "definition": "of myself so likewise the dative case , and accusative case", "kjv": "me, mine own (self), myself."}, "G1684": {"greek": "ἐμβαίνω", "translit": "embaínō", "pronunciation": "em-ba'-hee-no", "derivation": "from (G1722) and the base of (G939);", "definition": "to walk on, i.e. embark (aboard a vessel), reach (a pool)", "kjv": "come (get) into, enter (into), go (up) into, step in, take ship."}, "G1685": {"greek": "ἐμβάλλω", "translit": "embállō", "pronunciation": "em-bal'-lo", "derivation": "from (G1722) and (G906);", "definition": "to throw on, i.e. (figuratively) subject to (eternal punishment)", "kjv": "cast into."}, "G1686": {"greek": "ἐμβάπτω", "translit": "embáptō", "pronunciation": "em-bap'-to", "derivation": "from (G1722) and (G911);", "definition": "to whelm on, i.e. wet (a part of the person, etc.) by contact with a fluid", "kjv": "dip."}, "G1687": {"greek": "ἐμβατεύω", "translit": "embateúō", "pronunciation": "em-bat-yoo'-o", "derivation": "from (G1722) and a presumed derivative of the base of (G939);", "definition": "equivalent to (G1684); to intrude on (figuratively)", "kjv": "intrude into."}, "G1688": {"greek": "ἐμβιβάζω", "translit": "embibázō", "pronunciation": "em-bib-ad'-zo", "derivation": "from (G1722) and (to mount; causative of (G1684));", "definition": "to place on, i.e. transfer (aboard a vessel)", "kjv": "put in."}, "G1689": {"greek": "ἐμβλέπω", "translit": "emblépō", "pronunciation": "em-blep'-o", "derivation": "from (G1722) and (G991);", "definition": "to look on, i.e. (relatively) to observe fixedly, or (absolutely) to discern clearly", "kjv": "behold, gaze up, look upon, (could) see."}, "G1690": {"greek": "ἐμβριμάομαι", "translit": "embrimáomai", "pronunciation": "em-brim-ah'-om-ahee", "derivation": "from (G1722) and (to snort with anger);", "definition": "to have indignation on, i.e. (transitively) to blame, (intransitively) to sigh with chagrin, (specially) to sternly enjoin", "kjv": "straitly charge, groan, murmur against."}, "G1691": {"greek": "ἐμέ", "translit": "emé", "pronunciation": "em-eh'", "derivation": "a prolonged form of (G3165);", "definition": "me", "kjv": "I, me, my(-self)."}, "G1692": {"greek": "ἐμέω", "translit": "eméō", "pronunciation": "em-eh'-o", "derivation": "of uncertain affinity;", "definition": "to vomit", "kjv": "(will) spue."}, "G1693": {"greek": "ἐμμαίνομαι", "translit": "emmaínomai", "pronunciation": "em-mah'-ee-nom-ahee", "derivation": "from (G1722) and (G3105);", "definition": "to rave on, i.e. rage at", "kjv": "be mad against."}, "G1694": {"greek": "Ἐμμανουήλ", "translit": "Emmanouḗl", "pronunciation": "em-man-oo-ale'", "derivation": "of Hebrew origin ((G6005));", "definition": "God with us; Emmanuel, a name of Christ", "kjv": "Emmanuel."}, "G1695": {"greek": "Ἐμμαούς", "translit": "Emmaoús", "pronunciation": "em-mah-ooce'", "derivation": "probably of Hebrew origin (compare (G3222));", "definition": "Emmaus, a place in Palestine", "kjv": "Emmaus."}, "G1696": {"greek": "ἐμμένω", "translit": "emménō", "pronunciation": "em-men'-o", "derivation": "from (G1722) and (G3306);", "definition": "to stay in the same place, i.e. (figuratively) persevere", "kjv": "continue."}, "G1697": {"greek": "Ἐμμόρ", "translit": "Emmór", "pronunciation": "em-mor'", "derivation": "of Hebrew origin ((G2544));", "definition": "Emmor (i.e. Chamor), a Canaanite", "kjv": "Emmor."}, "G1698": {"greek": "ἐμοί", "translit": "emoí", "pronunciation": "em-oy'", "derivation": "a prolonged form of (G3427);", "definition": "to me", "kjv": "I, me, mine, my."}, "G1699": {"greek": "ἐμός", "translit": "emós", "pronunciation": "em-os'", "derivation": "from the oblique cases of (G1473) ((G1698), (G1700), (G1691));", "definition": "my", "kjv": "of me, mine (own), my."}, "G1700": {"greek": "ἐμοῦ", "translit": "emoû", "pronunciation": "em-oo'", "derivation": "a prolonged form of (G3449);", "definition": "of me", "kjv": "me, mine, my."}, "G1701": {"greek": "ἐμπαιγμός", "translit": "empaigmós", "pronunciation": "emp-aheeg-mos'", "derivation": "from (G1702);", "definition": "derision", "kjv": "mocking."}, "G1702": {"greek": "ἐμπαίζω", "translit": "empaízō", "pronunciation": "emp-aheed'-zo", "derivation": "from (G1722) and (G3815);", "definition": "to jeer at, i.e. deride", "kjv": "mock."}, "G1703": {"greek": "ἐμπαίκτης", "translit": "empaíktēs", "pronunciation": "emp-aheek-tace'", "derivation": "from (G1702);", "definition": "a derider, i.e. (by implication) a false teacher", "kjv": "mocker, scoffer."}, "G1704": {"greek": "ἐμπεριπατέω", "translit": "emperipatéō", "pronunciation": "em-per-ee-pat-eh'-o", "derivation": "from (G1722) and (G4043);", "definition": "to perambulate on a place, i.e. (figuratively) to be occupied among persons", "kjv": "walk in."}, "G1705": {"greek": "ἐμπίπλημι", "translit": "empíplēmi", "pronunciation": "em-pip'-lay-mee", "derivation": "from (G1722) and the base of (G4118);", "definition": "to fill in (up), i.e. (by implication) to satisfy (literally or figuratively)", "kjv": "fill."}, "G1706": {"greek": "ἐμπίπτω", "translit": "empíptō", "pronunciation": "em-pip'-to", "derivation": "from (G1722) and (G4098);", "definition": "to fall on, i.e. (literally) to be entrapped by, or (figuratively) be overwhelmed with", "kjv": "fall among (into)."}, "G1707": {"greek": "ἐμπλέκω", "translit": "emplékō", "pronunciation": "em-plek'-o", "derivation": "from (G1722) and (G4120);", "definition": "to entwine, i.e. (figuratively) involve with", "kjv": "entangle (in, self with)."}, "G1708": {"greek": "ἐμπλοκή", "translit": "emplokḗ", "pronunciation": "em-plok-ay'", "derivation": "from (G1707);", "definition": "elaborate braiding of the hair", "kjv": "plaiting."}, "G1709": {"greek": "ἐμπνέω", "translit": "empnéō", "pronunciation": "emp-neh'-o", "derivation": "from (G1722) and (G4154);", "definition": "to inhale, i.e. (figuratively) to be animated by (bent upon)", "kjv": "breathe."}, "G1710": {"greek": "ἐμπορεύομαι", "translit": "emporeúomai", "pronunciation": "em-por-yoo'-om-ahee", "derivation": "from (G1722) and (G4198);", "definition": "to travel in (a country as a pedlar), i.e. (by implication) to trade", "kjv": "buy and sell, make merchandise."}, "G1711": {"greek": "ἐμπορία", "translit": "emporía", "pronunciation": "em-por-ee'-ah", "derivation": "feminine from (G1713);", "definition": "traffic", "kjv": "merchandise."}, "G1712": {"greek": "ἐμπόριον", "translit": "empórion", "pronunciation": "em-por'-ee-on", "derivation": "neuter from (G1713);", "definition": "a mart (\"emporium\")", "kjv": "merchandise."}, "G1713": {"greek": "ἔμπορος", "translit": "émporos", "pronunciation": "em'-por-os", "derivation": "from (G1722) and the base of (G4198);", "definition": "a (wholesale) tradesman", "kjv": "merchant."}, "G1714": {"greek": "ἐμπρήθω", "translit": "emprḗthō", "pronunciation": "em-pray'-tho", "derivation": "from (G1722) and (to blow a flame);", "definition": "to enkindle, i.e. set on fire", "kjv": "burn up."}, "G1715": {"greek": "ἔμπροσθεν", "translit": "émprosthen", "pronunciation": "em'-pros-then", "derivation": "from (G1722) and (G4314);", "definition": "in front of (in place (literally or figuratively) or time)", "kjv": "against, at, before, (in presence, sight) of."}, "G1716": {"greek": "ἐμπτύω", "translit": "emptýō", "pronunciation": "emp-too'-o", "derivation": "from (G1722) and (G4429);", "definition": "to spit at or on", "kjv": "spit (upon)."}, "G1717": {"greek": "ἐμφανής", "translit": "emphanḗs", "pronunciation": "em-fan-ace'", "derivation": "from a compound of (G1722) and (G5316);", "definition": "apparent in self", "kjv": "manifest, openly."}, "G1718": {"greek": "ἐμφανίζω", "translit": "emphanízō", "pronunciation": "em-fan-id'-zo", "derivation": "from (G1717);", "definition": "to exhibit (in person) or disclose (by words)", "kjv": "appear, declare (plainly), inform, (will) manifest, shew, signify."}, "G1719": {"greek": "ἔμφοβος", "translit": "émphobos", "pronunciation": "em'-fob-os", "derivation": "from (G1722) and (G5401);", "definition": "in fear, i.e. alarmed", "kjv": "affrighted, afraid, tremble."}, "G1720": {"greek": "ἐμφυσάω", "translit": "emphysáō", "pronunciation": "em-foo-sah'-o", "derivation": "from (G1722) and (to puff) (compare (G5453));", "definition": "to blow at or on", "kjv": "breathe on."}, "G1721": {"greek": "ἔμφυτος", "translit": "émphytos", "pronunciation": "em'-foo-tos", "derivation": "from (G1722) and a derivative of (G5453);", "definition": "implanted (figuratively)", "kjv": "engrafted."}, "G1722": {"greek": "ἐν", "translit": "en", "pronunciation": "en", "derivation": "a primary preposition denoting (fixed) position (in place, time or state), and (by implication) instrumentality (medially or constructively), i.e. a relation of rest (intermediate between (G1519) and (G1537));", "definition": "\"in,\" at, (up-)on, by, etc.", "kjv": "about, after, against, + almost, X altogether, among, X as, at, before, between, (here-)by (+ all means), for (… sake of), + give self wholly to, (here-)in(-to, -wardly), X mightily, (because) of, (up-)on, (open-)ly, X outwardly, one, X quickly, X shortly, (speedi-)ly, X that, X there(-in, -on), through(-out), (un-)to(-ward), under, when, where(-with), while, with(-in)."}, "G1723": {"greek": "ἐναγκαλίζομαι", "translit": "enankalízomai", "pronunciation": "en-ang-kal-id'-zom-ahee", "derivation": "from (G1722) and a derivative of (G43);", "definition": "to take in one's arms, i.e. embrace", "kjv": "take up in arms."}, "G1724": {"greek": "ἐνάλιος", "translit": "enálios", "pronunciation": "en-al'-ee-os", "derivation": "from (G1722) and (G251);", "definition": "in the sea, i.e. marine", "kjv": "thing in the sea."}, "G1725": {"greek": "ἔναντι", "translit": "énanti", "pronunciation": "en'-an-tee", "derivation": "from (G1722) and (G473);", "definition": "in front (i.e. figuratively, presence) of", "kjv": "before."}, "G1726": {"greek": "ἐναντίον", "translit": "enantíon", "pronunciation": "en-an-tee'-on", "derivation": "neuter of (G1727);", "definition": "(adverbially) in the presence (view) of", "kjv": "before, in the presence of."}, "G1727": {"greek": "ἐναντίος", "translit": "enantíos", "pronunciation": "en-an-tee'-os", "derivation": "from (G1725);", "definition": "opposite; figuratively, antagonistic", "kjv": "(over) against, contrary."}, "G1728": {"greek": "ἐνάρχομαι", "translit": "enárchomai", "pronunciation": "en-ar'-khom-ahee", "derivation": "from (G1722) and (G756);", "definition": "to commence on", "kjv": "rule (by mistake for (G757))."}, "G1729": {"greek": "ἐνδεής", "translit": "endeḗs", "pronunciation": "en-deh-ace'", "derivation": "from a compound of (G1722) and (G1210) (in the sense of lacking);", "definition": "deficient in", "kjv": "lacking."}, "G1730": {"greek": "ἔνδειγμα", "translit": "éndeigma", "pronunciation": "en'-dighe-mah", "derivation": "from (G1731);", "definition": "an indication (concretely)", "kjv": "manifest token."}, "G1731": {"greek": "ἐνδείκνυμι", "translit": "endeíknymi", "pronunciation": "en-dike'-noo-mee", "derivation": "from (G1722) and (G1166);", "definition": "to indicate (by word or act)", "kjv": "do, show (forth)."}, "G1732": {"greek": "ἔνδειξις", "translit": "éndeixis", "pronunciation": "en'-dike-sis", "derivation": "from (G1731);", "definition": "indication (abstractly)", "kjv": "declare, evident token, proof."}, "G1733": {"greek": "ἕνδεκα", "translit": "héndeka", "pronunciation": "hen'-dek-ah", "derivation": "from (the neuter of) (G1520) and (G1176);", "definition": "one and ten, i.e. eleven", "kjv": "eleven."}, "G1734": {"greek": "ἑνδέκατος", "translit": "hendékatos", "pronunciation": "hen-dek'-at-os", "derivation": "ordinal from (G1733);", "definition": "eleventh", "kjv": "eleventh."}, "G1735": {"greek": "ἐνδέχεται", "translit": "endéchetai", "pronunciation": "en-dekh'-et-ahee", "derivation": "third person singular present of a compound of (G1722) and (G1209);", "definition": "(impersonally) it is accepted in, i.e. admitted (possible)", "kjv": "can (+ not) be."}, "G1736": {"greek": "ἐνδημέω", "translit": "endēméō", "pronunciation": "en-day-meh'-o", "derivation": "from a compound of (G1722) and (G1218);", "definition": "to be in one's own country, i.e. home (figuratively)", "kjv": "be at home (present)."}, "G1737": {"greek": "ἐνδιδύσκω", "translit": "endidýskō", "pronunciation": "en-did-oos'-ko", "derivation": "a prolonged form of (G1746);", "definition": "to invest (with a garment)", "kjv": "clothe in, wear."}, "G1738": {"greek": "ἔνδικος", "translit": "éndikos", "pronunciation": "en'-dee-kos", "derivation": "from (G1722) and (G1349);", "definition": "in the right, i.e. equitable", "kjv": "just."}, "G1739": {"greek": "ἐνδόμησις", "translit": "endómēsis", "pronunciation": "en-dom'-ay-sis", "derivation": "from a compound of (G1722) and a derivative of the base of (G1218);", "definition": "a housing in (residence), i.e. structure", "kjv": "building."}, "G1740": {"greek": "ἐνδοξάζω", "translit": "endoxázō", "pronunciation": "en-dox-ad'-zo", "derivation": "from (G1741);", "definition": "to glorify", "kjv": "glorify."}, "G1741": {"greek": "ἔνδοξος", "translit": "éndoxos", "pronunciation": "en'-dox-os", "derivation": "from (G1722) and (G1391);", "definition": "in glory, i.e. splendid, (figuratively) noble", "kjv": "glorious, gorgeous(-ly), honourable."}, "G1742": {"greek": "ἔνδυμα", "translit": "éndyma", "pronunciation": "en'-doo-mah", "derivation": "from (G1746);", "definition": "apparel (especially the outer robe)", "kjv": "clothing, garment, raiment."}, "G1743": {"greek": "ἐνδυναμόω", "translit": "endynamóō", "pronunciation": "en-doo-nam-o'-o", "derivation": "from (G1722) and (G1412);", "definition": "to empower", "kjv": "enable, (increase in) strength(-en), be (make) strong."}, "G1744": {"greek": "ἐνδύνω", "translit": "endýnō", "pronunciation": "en-doo'-no", "derivation": "from (G1772) and (G1416);", "definition": "to sink (by implication, wrap (compare (G1746)) on, i.e. (figuratively) sneak", "kjv": "creep."}, "G1745": {"greek": "ἔνδυσις", "translit": "éndysis", "pronunciation": "en'-doo-sis", "derivation": "from (G1746);", "definition": "investment with clothing", "kjv": "putting on."}, "G1746": {"greek": "ἐνδύω", "translit": "endýō", "pronunciation": "en-doo'-o", "derivation": "from (G1722) and (G1416) (in the sense of sinking into a garment);", "definition": "to invest with clothing (literally or figuratively)", "kjv": "array, clothe (with), endue, have (put) on."}, "G1747": {"greek": "ἐνέδρα", "translit": "enédra", "pronunciation": "en-ed'-rah", "derivation": "feminine from (G1722) and the base of (G1476);", "definition": "an ambuscade, i.e. (figuratively) murderous purpose", "kjv": "lay wait."}, "G1748": {"greek": "ἐνεδρεύω", "translit": "enedreúō", "pronunciation": "en-ed-ryoo'-o", "derivation": "from (G1747);", "definition": "to lurk, i.e. (figuratively) plot assassination", "kjv": "lay wait for."}, "G1750": {"greek": "ἐνειλέω", "translit": "eneiléō", "pronunciation": "en-i-leh'-o", "derivation": "from (G1772) and the base of (G1507);", "definition": "to enwrap", "kjv": "wrap in."}, "G1751": {"greek": "ἔνειμι", "translit": "éneimi", "pronunciation": "en'-i-mee", "derivation": "from (G1772) and (G1510);", "definition": "to be within (neuter participle plural)", "kjv": "such things as … have."}, "G1752": {"greek": "ἕνεκα", "translit": "héneka", "pronunciation": "hen'-ek-ah", "derivation": "of uncertain affinity;", "definition": "on account of", "kjv": "because, for (cause, sake), (where-)fore, by reason of, that."}, "G1753": {"greek": "ἐνέργεια", "translit": "enérgeia", "pronunciation": "en-erg'-i-ah", "derivation": "from (G1756);", "definition": "efficiency (\"energy\")", "kjv": "operation, strong, (effectual) working."}, "G1754": {"greek": "ἐνεργέω", "translit": "energéō", "pronunciation": "en-erg-eh'-o", "derivation": "from (G1756);", "definition": "to be active, efficient", "kjv": "do, (be) effectual (fervent), be mighty in, shew forth self, work (effectually in)."}, "G1755": {"greek": "ἐνέργημα", "translit": "enérgēma", "pronunciation": "en-erg'-ay-mah", "derivation": "from (G1754);", "definition": "an effect", "kjv": "operation, working."}, "G1756": {"greek": "ἐνεργής", "translit": "energḗs", "pronunciation": "en-er-gace'", "derivation": "from (G1722) and (G2041);", "definition": "active, operative", "kjv": "effectual, powerful."}, "G1757": {"greek": "ἐνευλογέω", "translit": "eneulogéō", "pronunciation": "en-yoo-log-eh'-o", "derivation": "from (G1722) and (G2127);", "definition": "to confer a benefit on", "kjv": "bless."}, "G1758": {"greek": "ἐνέχω", "translit": "enéchō", "pronunciation": "en-ekh'-o", "derivation": "from (G1722) and (G2192);", "definition": "to hold in or upon, i.e. ensnare; by implication, to keep a grudge", "kjv": "entangle with, have a quarrel against, urge."}, "G1759": {"greek": "ἐνθάδε", "translit": "entháde", "pronunciation": "en-thad'-eh", "derivation": "from a prolonged form of (G1722);", "definition": "properly, within, i.e. (of place) here, hither", "kjv": "(t-)here, hither."}, "G1760": {"greek": "ἐνθυμέομαι", "translit": "enthyméomai", "pronunciation": "en-thoo-meh'-om-ahee", "derivation": "from a compound of (G1722) and (G2372);", "definition": "to be inspirited, i.e. ponder", "kjv": "think."}, "G1761": {"greek": "ἐνθύμησις", "translit": "enthýmēsis", "pronunciation": "en-thoo'-may-sis", "derivation": "from (G1760);", "definition": "deliberation", "kjv": "device, thought."}, "G1762": {"greek": "ἔνι", "translit": "éni", "pronunciation": "en'-ee", "derivation": "contraction for the third person singular present indicative of (G1751);", "definition": "impersonally, there is in or among", "kjv": "be, (there) is."}, "G1763": {"greek": "ἐνιαυτός", "translit": "eniautós", "pronunciation": "en-ee-ow-tos'", "derivation": "prolongation from a primary (a year);", "definition": "a year", "kjv": "year."}, "G1764": {"greek": "ἐνίστημι", "translit": "enístēmi", "pronunciation": "en-is'-tay-mee", "derivation": "from (G1722) and (G2476);", "definition": "to place on hand, i.e. (reflexively) impend, (participle) be instant", "kjv": "come, be at hand, present."}, "G1765": {"greek": "ἐνισχύω", "translit": "enischýō", "pronunciation": "en-is-khoo'-o", "derivation": "from (G1722) and (G2480);", "definition": "to invigorate (transitively or reflexively)", "kjv": "strengthen."}, "G1766": {"greek": "ἔννατος", "translit": "énnatos", "pronunciation": "en'-nat-os", "derivation": "ordinal from (G1767);", "definition": "ninth", "kjv": "ninth."}, "G1767": {"greek": "ἐννέα", "translit": "ennéa", "pronunciation": "en-neh'-ah", "derivation": "a primary number;", "definition": "nine", "kjv": "nine."}, "G1768": {"greek": "ἐννενηκονταεννέα", "translit": "ennenēkontaennéa", "pronunciation": "en-nen-ay-kon-tah-en-neh'-ah", "derivation": "from a (tenth) multiple of (G1767) and (G1767) itself;", "definition": "ninety-nine", "kjv": "ninety and nine."}, "G1769": {"greek": "ἐννεός", "translit": "enneós", "pronunciation": "en-neh-os'", "derivation": "from (G1770);", "definition": "dumb (as making signs), i.e. silent from astonishment", "kjv": "speechless."}, "G1770": {"greek": "ἐννεύω", "translit": "enneúō", "pronunciation": "en-nyoo'-o", "derivation": "from (G1722) and (G3506);", "definition": "to nod at, i.e. beckon or communicate by gesture", "kjv": "make signs."}, "G1771": {"greek": "ἔννοια", "translit": "énnoia", "pronunciation": "en'-noy-ah", "derivation": "from a compound of (G1722) and (G3563);", "definition": "thoughtfulness, i.e. moral understanding", "kjv": "intent, mind."}, "G1772": {"greek": "ἔννομος", "translit": "énnomos", "pronunciation": "en'-nom-os", "derivation": "from (G1722) and (G3551);", "definition": "(subjectively) legal, or (objectively) subject to", "kjv": "lawful, under law."}, "G1773": {"greek": "ἔννυχον", "translit": "énnychon", "pronunciation": "en'-noo-khon", "derivation": "neuter of a compound of (G1722) and (G3571);", "definition": "(adverbially) by night", "kjv": "before day."}, "G1774": {"greek": "ἐνοικέω", "translit": "enoikéō", "pronunciation": "en-oy-keh'-o", "derivation": "from (G1722) and (G3611);", "definition": "to inhabit (figuratively)", "kjv": "dwell in."}, "G1775": {"greek": "ἑνότης", "translit": "henótēs", "pronunciation": "hen-ot-ace'", "derivation": "from (G1520);", "definition": "oneness, i.e. (figuratively) unanimity", "kjv": "unity."}, "G1776": {"greek": "ἐνοχλέω", "translit": "enochléō", "pronunciation": "en-okh-leh'-o", "derivation": "from (G1722) and (G3791);", "definition": "to crowd in, i.e. (figuratively) to annoy", "kjv": "trouble."}, "G1777": {"greek": "ἔνοχος", "translit": "énochos", "pronunciation": "en'-okh-os", "derivation": "from (G1758);", "definition": "liable to (a condition, penalty or imputation)", "kjv": "in danger of, guilty of, subject to."}, "G1778": {"greek": "ἔνταλμα", "translit": "éntalma", "pronunciation": "en'-tal-mah", "derivation": "from (G1781);", "definition": "an injunction, i.e. religious precept", "kjv": "commandment."}, "G1779": {"greek": "ἐνταφιάζω", "translit": "entaphiázō", "pronunciation": "en-taf-ee-ad'-zo", "derivation": "from a compound of (G1722) and (G5028);", "definition": "to inswathe with cerements for interment", "kjv": "bury."}, "G1780": {"greek": "ἐνταφιασμός", "translit": "entaphiasmós", "pronunciation": "en-taf-ee-as-mos'", "derivation": "from (G1779);", "definition": "preparation for interment", "kjv": "burying."}, "G1781": {"greek": "ἐντέλλομαι", "translit": "entéllomai", "pronunciation": "en-tel'-lom-ahee", "derivation": "from (G1722) and the base of (G5056);", "definition": "to enjoin", "kjv": "(give) charge, (give) command(-ments), injoin."}, "G1782": {"greek": "ἐντεῦθεν", "translit": "enteûthen", "pronunciation": "ent-yoo'-then", "derivation": "from the same as (G1759);", "definition": "hence (literally or figuratively); (repeated) on both sides", "kjv": "(from) hence, on either side."}, "G1783": {"greek": "ἔντευξις", "translit": "énteuxis", "pronunciation": "ent'-yook-sis", "derivation": "from (G1793);", "definition": "an interview, i.e. (specially) supplication", "kjv": "intercession, prayer."}, "G1784": {"greek": "ἔντιμος", "translit": "éntimos", "pronunciation": "en'-tee-mos", "derivation": "from (G1722) and (G5092);", "definition": "valued (figuratively)", "kjv": "dear, more honourable, precious, in reputation."}, "G1785": {"greek": "ἐντολή", "translit": "entolḗ", "pronunciation": "en-tol-ay'", "derivation": "from (G1781);", "definition": "injunction, i.e. an authoritative prescription", "kjv": "commandment, precept."}, "G1786": {"greek": "ἐντόπιος", "translit": "entópios", "pronunciation": "en-top'-ee-os", "derivation": "from (G1722) and (G5117);", "definition": "a resident", "kjv": "of that place."}, "G1787": {"greek": "ἐντός", "translit": "entós", "pronunciation": "en-tos'", "derivation": "from (G1722);", "definition": "inside (adverb or noun)", "kjv": "within."}, "G1788": {"greek": "ἐντρέπω", "translit": "entrépō", "pronunciation": "en-trep'-o", "derivation": "from (G1722) and the base of (G5157);", "definition": "to invert, i.e. (figuratively and reflexively) in a good sense, to respect; or in a bad one, to confound", "kjv": "regard, (give) reference, shame."}, "G1789": {"greek": "ἐντρέφω", "translit": "entréphō", "pronunciation": "en-tref'-o", "derivation": "from (G1722) and (G5142);", "definition": "(figuratively) to educate", "kjv": "nourish up in."}, "G1790": {"greek": "ἔντρομος", "translit": "éntromos", "pronunciation": "en'-trom-os", "derivation": "from (G1722) and (G5156);", "definition": "terrified", "kjv": "X quake, X trembled."}, "G1791": {"greek": "ἐντροπή", "translit": "entropḗ", "pronunciation": "en-trop-ay'", "derivation": "from (G1788);", "definition": "confusion", "kjv": "shame."}, "G1792": {"greek": "ἐντρυφάω", "translit": "entrypháō", "pronunciation": "en-troo-fah'-o", "derivation": "from (G1722) and (G5171);", "definition": "to revel in", "kjv": "sporting selves."}, "G1793": {"greek": "ἐντυγχάνω", "translit": "entynchánō", "pronunciation": "en-toong-khan'-o", "derivation": "from (G1722) and (G5177);", "definition": "to chance upon, i.e. (by implication) confer with; by extension to entreat (in favor or against)", "kjv": "deal with, make intercession."}, "G1794": {"greek": "ἐντυλίσσω", "translit": "entylíssō", "pronunciation": "en-too-lis'-so", "derivation": "from (G1722) and (to twist; probably akin to (G1507));", "definition": "to entwine, i.e. wind up in", "kjv": "wrap in (together)."}, "G1795": {"greek": "ἐντυπόω", "translit": "entypóō", "pronunciation": "en-too-po'-o", "derivation": "from (G1722) and a derivative of (G5179);", "definition": "to enstamp, i.e. engrave", "kjv": "engrave."}, "G1796": {"greek": "ἐνυβρίζω", "translit": "enybrízō", "pronunciation": "en-oo-brid'-zo", "derivation": "from (G1722) and (G5195);", "definition": "to insult", "kjv": "do despite unto."}, "G1797": {"greek": "ἐνυπνιάζομαι", "translit": "enypniázomai", "pronunciation": "en-oop-nee-ad'-zom-ahee", "derivation": "middle voice from (G1798);", "definition": "to dream", "kjv": "dream(-er)."}, "G1798": {"greek": "ἐνύπνιον", "translit": "enýpnion", "pronunciation": "en-oop'-nee-on", "derivation": "from (G1722) and (G5258);", "definition": "something seen in sleep, i.e. a dream (vision in a dream)", "kjv": "dream."}, "G1799": {"greek": "ἐνώπιον", "translit": "enṓpion", "pronunciation": "en-o'-pee-on", "derivation": "neuter of a compound of (G1722) and a derivative of (G3700);", "definition": "in the face of (literally or figuratively)", "kjv": "before, in the presence (sight) of, to."}, "G1800": {"greek": "Ἐνώς", "translit": "Enṓs", "pronunciation": "en-oce'", "derivation": "of Hebrew origin ((G583));", "definition": "Enos (i.e. Enosh), a patriarch", "kjv": "Enos."}, "G1801": {"greek": "ἐνωτίζομαι", "translit": "enōtízomai", "pronunciation": "en-o-tid'-zom-ahee", "derivation": "middle voice from a compound of (G1722) and (G3775);", "definition": "to take in one's ear, i.e. to listen", "kjv": "hearken."}, "G1802": {"greek": "Ἐνώχ", "translit": "Enṓch", "pronunciation": "en-oke'", "derivation": "of Hebrew origin ((G2585));", "definition": "Enoch (i.e. Chanok), an antediluvian", "kjv": "Enoch."}, "G1803": {"greek": "ἕξ", "translit": "héx", "pronunciation": "hex", "derivation": "a primary numeral;", "definition": "six", "kjv": "six."}, "G1804": {"greek": "ἐξαγγέλλω", "translit": "exangéllō", "pronunciation": "ex-ang-el'-lo", "derivation": "from (G1537) and the base of (G32);", "definition": "to publish, i.e. celebrate", "kjv": "shew forth."}, "G1805": {"greek": "ἐξαγοράζω", "translit": "exagorázō", "pronunciation": "ex-ag-or-ad'-zo", "derivation": "from (G1537) and (G59);", "definition": "to buy up, i.e. ransom; figuratively, to rescue from loss (improve opportunity)", "kjv": "redeem."}, "G1806": {"greek": "ἐξάγω", "translit": "exágō", "pronunciation": "ex-ag'-o", "derivation": "from (G1537) and (G71);", "definition": "to lead forth", "kjv": "bring forth (out), fetch (lead) out."}, "G1807": {"greek": "ἐξαιρέω", "translit": "exairéō", "pronunciation": "ex-ahee-reh'-o", "derivation": "from (G1537) and (G138);", "definition": "actively, to tear out; middle voice, to select; figuratively, to release", "kjv": "deliver, pluck out, rescue."}, "G1808": {"greek": "ἐξαίρω", "translit": "exaírō", "pronunciation": "ex-ah'-ee-ro", "derivation": "from (G1537) and (G142);", "definition": "to remove", "kjv": "put (take) away."}, "G1809": {"greek": "ἐξαιτέομαι", "translit": "exaitéomai", "pronunciation": "ex-ahee-teh'-om-ahee", "derivation": "middle voice from (G1537) and (G154);", "definition": "to demand (for trial)", "kjv": "desire."}, "G1810": {"greek": "ἐξαίφνης", "translit": "exaíphnēs", "pronunciation": "ex-ah'-eef-nace", "derivation": "from (G1537) and the base of (G160);", "definition": "of a sudden (unexpectedly)", "kjv": "suddenly."}, "G1811": {"greek": "ἐξακολουθέω", "translit": "exakolouthéō", "pronunciation": "ex-ak-ol-oo-theh'-o", "derivation": "from (G1537) and (G190);", "definition": "to follow out, i.e. (figuratively) to imitate, obey, yield to", "kjv": "follow."}, "G1812": {"greek": "ἑξακόσιοι", "translit": "hexakósioi", "pronunciation": "hex-ak-os'-ee-oy", "derivation": "plural ordinal from (G1803) and (G1540);", "definition": "six hundred", "kjv": "six hundred."}, "G1813": {"greek": "ἐξαλείφω", "translit": "exaleíphō", "pronunciation": "ex-al-i'-fo", "derivation": "from (G1537) and (G218);", "definition": "to smear out, i.e. obliterate (erase tears, figuratively, pardon sin)", "kjv": "blot out, wipe away."}, "G1814": {"greek": "ἐξάλλομαι", "translit": "exállomai", "pronunciation": "ex-al'-lom-ahee", "derivation": "from (G1537) and (G242);", "definition": "to spring forth", "kjv": "leap up."}, "G1815": {"greek": "ἐξανάστασις", "translit": "exanástasis", "pronunciation": "ex-an-as'-tas-is", "derivation": "from (G1817);", "definition": "a rising from death", "kjv": "resurrection."}, "G1816": {"greek": "ἐξανατέλλω", "translit": "exanatéllō", "pronunciation": "ex-an-at-el'-lo", "derivation": "from (G1537) and (G393);", "definition": "to start up out of the ground, i.e. germinate", "kjv": "spring up."}, "G1817": {"greek": "ἐξανίστημι", "translit": "exanístēmi", "pronunciation": "ex-an-is'-tay-mee", "derivation": "from (G1537) and (G450);", "definition": "objectively, to produce, i.e. (figuratively) beget; subjectively, to arise, i.e. (figuratively) object", "kjv": "raise (rise) up."}, "G1818": {"greek": "ἐξαπατάω", "translit": "exapatáō", "pronunciation": "ex-ap-at-ah'-o", "derivation": "from (G1537) and (G538);", "definition": "to seduce wholly", "kjv": "beguile, deceive."}, "G1819": {"greek": "ἐξάπινα", "translit": "exápina", "pronunciation": "ex-ap'-ee-nah", "derivation": "from (G1537) and a derivative of the same as (G160);", "definition": "of a sudden, i.e. unexpectedly", "kjv": "suddenly."}, "G1820": {"greek": "ἐξαπορέομαι", "translit": "exaporéomai", "pronunciation": "ex-ap-or-eh'-om-ahee", "derivation": "middle voice from (G1537) and (G639);", "definition": "to be utterly at a loss, i.e. despond", "kjv": "(in) despair."}, "G1821": {"greek": "ἐξαποστέλλω", "translit": "exapostéllō", "pronunciation": "ex-ap-os-tel'-lo", "derivation": "from (G1537) and (G649);", "definition": "to send away forth, i.e. (on a mission) to despatch, or (peremptorily) to dismiss", "kjv": "send (away, forth, out)."}, "G1822": {"greek": "ἐξαρτίζω", "translit": "exartízō", "pronunciation": "ex-ar-tid'-zo", "derivation": "from (G1537) and a derivative of (G739);", "definition": "to finish out (time); figuratively, to equip fully (a teacher)", "kjv": "accomplish, thoroughly furnish."}, "G1823": {"greek": "ἐξαστράπτω", "translit": "exastráptō", "pronunciation": "ex-as-trap'-to", "derivation": "from (G1537) and (G797);", "definition": "to lighten forth, i.e. (figuratively) to be radiant (of very white garments)", "kjv": "glistening."}, "G1824": {"greek": "ἐξαυτῆς", "translit": "exautēs", "pronunciation": "ex-ow'-tace", "derivation": "from (G1537) and the genitive case singular feminine of (G846) ((G5610) being understood);", "definition": "from that hour, i.e. instantly", "kjv": "by and by, immediately, presently, straightway."}, "G1825": {"greek": "ἐξεγείρω", "translit": "exegeírō", "pronunciation": "ex-eg-i'-ro", "derivation": "from (G1537) and (G1453);", "definition": "to rouse fully, i.e. (figuratively) to resuscitate (from death), release (from infliction)", "kjv": "raise up."}, "G1826": {"greek": "ἔξειμι", "translit": "éxeimi", "pronunciation": "ex'-i-mee", "derivation": "from (G1537) and (to go);", "definition": "to issue, i.e. leave (a place), escape (to the shore)", "kjv": "depart, get (to land), go out."}, "G1828": {"greek": "ἐξέλκω", "translit": "exélkō", "pronunciation": "ex-el'-ko", "derivation": "from (G1537) and (G1670);", "definition": "to drag forth, i.e. (figuratively) to entice (to sin)", "kjv": "draw away."}, "G1829": {"greek": "ἐξέραμα", "translit": "exérama", "pronunciation": "ex-er'-am-ah", "derivation": "from a comparative of (G1537) and a presumed (to spue);", "definition": "vomit, i.e. food disgorged", "kjv": "vomit."}, "G1830": {"greek": "ἐξερευνάω", "translit": "exereunáō", "pronunciation": "ex-er-yoo-nah'-o", "derivation": "from (G1537) and (G2045);", "definition": "to explore (figuratively)", "kjv": "search diligently."}, "G1831": {"greek": "ἐξέρχομαι", "translit": "exérchomai", "pronunciation": "ex-er'-khom-ahee", "derivation": "from (G1537) and (G2064);", "definition": "to issue (literally or figuratively)", "kjv": "come (forth, out), depart (out of), escape, get out, go (abroad, away, forth, out, thence), proceed (forth), spread abroad."}, "G1832": {"greek": "ἔξεστι", "translit": "éxesti", "pronunciation": "ex'-es-tee", "derivation": "third person singular present indicative of a compound of (G1537) and (G1510);", "definition": "so also neuter present participle of the same (with or without some form of (G1510) expressed); impersonally, it is right (through the figurative idea of being out in public)", "kjv": "be lawful, let, X may(-est)."}, "G1833": {"greek": "ἐξετάζω", "translit": "exetázō", "pronunciation": "ex-et-ad'-zo", "derivation": "from (G1537) and (to examine);", "definition": "to test thoroughly (by questions), i.e. ascertain or interrogate", "kjv": "ask, enquire, search."}, "G1834": {"greek": "ἐξηγέομαι", "translit": "exēgéomai", "pronunciation": "ex-ayg-eh'-om-ahee", "derivation": "from (G1537) and (G2233);", "definition": "to consider out (aloud), i.e. rehearse, unfold", "kjv": "declare, tell."}, "G1835": {"greek": "ἑξήκοντα", "translit": "hexḗkonta", "pronunciation": "hex-ay'-kon-tah", "derivation": "the tenth multiple of (G1803);", "definition": "sixty", "kjv": "sixty(-fold), threescore."}, "G1836": {"greek": "ἑξῆς", "translit": "hexēs", "pronunciation": "hex-ace'", "derivation": "from (G2192) (in the sense of taking hold of, i.e. adjoining);", "definition": "successive", "kjv": "after, following, X morrow, next."}, "G1837": {"greek": "ἐξηχέομαι", "translit": "exēchéomai", "pronunciation": "ex-ay-kheh'-om-ahee", "derivation": "middle voice from (G1537) and (G2278);", "definition": "to \"echo\" forth, i.e. resound (be generally reported)", "kjv": "sound forth."}, "G1838": {"greek": "ἕξις", "translit": "héxis", "pronunciation": "hex'-is", "derivation": "from (G2192);", "definition": "habit, i.e. (by implication) practice", "kjv": "use."}, "G1839": {"greek": "ἐξίστημι", "translit": "exístēmi", "pronunciation": "ex-is'-tay-mee", "derivation": "from (G1537) and (G2476);", "definition": "to put (stand) out of wits, i.e. astound, or (reflexively) become astounded, insane", "kjv": "amaze, be (make) astonished, be beside self (selves), bewitch, wonder."}, "G1840": {"greek": "ἐξισχύω", "translit": "exischýō", "pronunciation": "ex-is-khoo'-o", "derivation": "from (G1537) and (G2480);", "definition": "to have full strength, i.e. be entirely competent", "kjv": "be able."}, "G1841": {"greek": "ἔξοδος", "translit": "éxodos", "pronunciation": "ex'-od-os", "derivation": "from (G1537) and (G3598);", "definition": "an exit, i.e. (figuratively) death", "kjv": "decease, departing."}, "G1842": {"greek": "ἐξολοθρεύω", "translit": "exolothreúō", "pronunciation": "ex-ol-oth-ryoo'-o", "derivation": "from (G1537) and (G3645);", "definition": "to extirpate", "kjv": "destroy."}, "G1843": {"greek": "ἐξομολογέω", "translit": "exomologéō", "pronunciation": "ex-om-ol-og-eh'-o", "derivation": "from (G1537) and (G3670);", "definition": "to acknowledge or (by implication, of assent) agree fully", "kjv": "confess, profess, promise."}, "G1844": {"greek": "ἐξορκίζω", "translit": "exorkízō", "pronunciation": "ex-or-kid'-zo", "derivation": "from (G1537) and (G3726);", "definition": "to exact an oath, i.e. conjure", "kjv": "adjure."}, "G1845": {"greek": "ἐξορκιστής", "translit": "exorkistḗs", "pronunciation": "ex-or-kis-tace'", "derivation": "from (G1844);", "definition": "one that binds by an oath (or spell), i.e. (by implication) an \"exorcist\" (conjurer)", "kjv": "exorcist."}, "G1846": {"greek": "ἐξορύσσω", "translit": "exorýssō", "pronunciation": "ex-or-oos'-so", "derivation": "from (G1537) and (G3736);", "definition": "to dig out, i.e. (by extension) to extract (an eye), remove (roofing)", "kjv": "break up, pluck out."}, "G1847": {"greek": "ἐξουδενόω", "translit": "exoudenóō", "pronunciation": "ex-oo-den-o'-o", "derivation": "from (G1537) and a derivative of the neuter of (G3762);", "definition": "to make utterly nothing of, i.e. despise", "kjv": "set at nought."}, "G1848": {"greek": "ἐξουθενέω", "translit": "exouthenéō", "pronunciation": "ex-oo-then-eh'-o", "derivation": "a variation of (G1847) and meaning the same", "definition": "", "kjv": "contemptible, despise, least esteemed, set at nought."}, "G1849": {"greek": "ἐξουσία", "translit": "exousía", "pronunciation": "ex-oo-see'-ah", "derivation": "from (G1832) (in the sense of ability);", "definition": "privilege, i.e. (subjectively) force, capacity, competency, freedom, or (objectively) mastery (concretely, magistrate, superhuman, potentate, token of control), delegated influence", "kjv": "authority, jurisdiction, liberty, power, right, strength."}, "G1850": {"greek": "ἐξουσιάζω", "translit": "exousiázō", "pronunciation": "ex-oo-see-ad'-zo", "derivation": "from (G1849);", "definition": "to control", "kjv": "exercise authority upon, bring under the (have) power of."}, "G1851": {"greek": "ἐξοχή", "translit": "exochḗ", "pronunciation": "ex-okh-ay'", "derivation": "from a compound of (G1537) and (G2192) (meaning to stand out);", "definition": "prominence (figuratively)", "kjv": "principal."}, "G1852": {"greek": "ἐξυπνίζω", "translit": "exypnízō", "pronunciation": "ex-oop-nid'-zo", "derivation": "from (G1853);", "definition": "to waken", "kjv": "awake out of sleep."}, "G1853": {"greek": "ἔξυπνος", "translit": "éxypnos", "pronunciation": "ex'-oop-nos", "derivation": "from (G1537) and (G5258);", "definition": "awake", "kjv": "X out of sleep."}, "G1854": {"greek": "ἔξω", "translit": "éxō", "pronunciation": "ex'-o", "derivation": "adverb from (G1537);", "definition": "out(-side, of doors), literally or figuratively", "kjv": "away, forth, (with-)out (of, -ward), strange."}, "G1855": {"greek": "ἔξωθεν", "translit": "éxōthen", "pronunciation": "ex'-o-then", "derivation": "from (G1854);", "definition": "external(-ly)", "kjv": "out(-side, -ward, - wardly), (from) without."}, "G1856": {"greek": "ἐξωθέω", "translit": "exōthéō", "pronunciation": "ex-o-theh'-o", "derivation": "from (G1537) and (to push);", "definition": "to expel; by implication, to propel", "kjv": "drive out, thrust in."}, "G1857": {"greek": "ἐξώτερος", "translit": "exṓteros", "pronunciation": "ex-o'-ter-os", "derivation": "comparative of (G1854);", "definition": "exterior", "kjv": "outer."}, "G1858": {"greek": "ἑορτάζω", "translit": "heortázō", "pronunciation": "heh-or-tad'-zo", "derivation": "from (G1859);", "definition": "to observe a festival", "kjv": "keep the feast."}, "G1859": {"greek": "ἑορτή", "translit": "heortḗ", "pronunciation": "heh-or-tay'", "derivation": "of uncertain affinity;", "definition": "a festival", "kjv": "feast, holyday."}, "G1860": {"greek": "ἐπαγγελία", "translit": "epangelía", "pronunciation": "ep-ang-el-ee'-ah", "derivation": "from (G1861);", "definition": "an announcement (for information, assent or pledge; especially a divine assurance of good)", "kjv": "message, promise."}, "G1861": {"greek": "ἐπαγγέλλω", "translit": "epangéllō", "pronunciation": "ep-ang-el'-lo", "derivation": "from (G1909) and the base of (G32);", "definition": "to announce upon (reflexively), i.e. (by implication) to engage to do something, to assert something respecting oneself", "kjv": "profess, (make) promise."}, "G1862": {"greek": "ἐπάγγελμα", "translit": "epángelma", "pronunciation": "ep-ang'-el-mah", "derivation": "from (G1861);", "definition": "a self-committal (by assurance of conferring some good)", "kjv": "promise."}, "G1863": {"greek": "ἐπάγω", "translit": "epágō", "pronunciation": "ep-ag'-o", "derivation": "from (G1909) and (G71);", "definition": "to superinduce, i.e. inflict (an evil), charge (a crime)", "kjv": "bring upon."}, "G1864": {"greek": "ἐπαγωνίζομαι", "translit": "epagōnízomai", "pronunciation": "ep-ag-o-nid'-zom-ahee", "derivation": "from (G1909) and (G75);", "definition": "to struggle for", "kjv": "earnestly contend for."}, "G1865": {"greek": "ἐπαθροίζω", "translit": "epathroízō", "pronunciation": "ep-ath-roid'-zo", "derivation": "from (G1909) and (to assemble);", "definition": "to accumulate", "kjv": "gather thick together."}, "G1866": {"greek": "Ἐπαίνετος", "translit": "Epaínetos", "pronunciation": "ep-a'-hee-net-os", "derivation": "from (G1867);", "definition": "praised; Epænetus, a Christian", "kjv": "Epenetus."}, "G1867": {"greek": "ἐπαινέω", "translit": "epainéō", "pronunciation": "ep-ahee-neh'-o", "derivation": "from (G1909) and (G134);", "definition": "to applaud", "kjv": "commend, laud, praise."}, "G1868": {"greek": "ἔπαινος", "translit": "épainos", "pronunciation": "ep'-ahee-nos", "derivation": "from (G1909) and the base of (G134);", "definition": "laudation; concretely, a commendable thing", "kjv": "praise."}, "G1869": {"greek": "ἐπαίρω", "translit": "epaírō", "pronunciation": "ep-ahee'-ro", "derivation": "from (G1909) and (G142);", "definition": "to raise up (literally or figuratively)", "kjv": "exalt self, poise (lift, take) up."}, "G1870": {"greek": "ἐπαισχύνομαι", "translit": "epaischýnomai", "pronunciation": "ep-ahee-skhoo'-nom-ahee", "derivation": "from (G1909) and (G153);", "definition": "to feel shame for something", "kjv": "be ashamed."}, "G1871": {"greek": "ἐπαιτέω", "translit": "epaitéō", "pronunciation": "ep-ahee-teh'-o", "derivation": "from (G1909) and (G154);", "definition": "to ask for", "kjv": "beg."}, "G1872": {"greek": "ἐπακολουθέω", "translit": "epakolouthéō", "pronunciation": "ep-ak-ol-oo-theh'-o", "derivation": "from (G1909) and (G190);", "definition": "to accompany", "kjv": "follow (after)."}, "G1873": {"greek": "ἐπακούω", "translit": "epakoúō", "pronunciation": "ep-ak-oo'-o", "derivation": "from (G1909) and (G191);", "definition": "to hearken (favorably) to", "kjv": "hear."}, "G1874": {"greek": "ἐπακροάομαι", "translit": "epakroáomai", "pronunciation": "ep-ak-ro-ah'-om-ahee", "derivation": "from (G1909) and the base of (G202);", "definition": "to listen (intently) to", "kjv": "hear."}, "G1875": {"greek": "ἐπάν", "translit": "epán", "pronunciation": "ep-an'", "derivation": "from (G1909) and (G302);", "definition": "a particle of indefinite contemporaneousness; whenever, as soon as", "kjv": "when."}, "G1876": {"greek": "ἐπάναγκες", "translit": "epánankes", "pronunciation": "ep-an'-ang-kes", "derivation": "neuter of a presumed compound of (G1909) and (G318);", "definition": "(adverbially) on necessity, i.e. necessarily", "kjv": "necessary."}, "G1877": {"greek": "ἐπανάγω", "translit": "epanágō", "pronunciation": "ep-an-ag'-o", "derivation": "from (G1909) and (G321);", "definition": "to lead up on, i.e. (technical) to put out (to sea); (intransitively) to return", "kjv": "launch (thrust) out, return."}, "G1878": {"greek": "ἐπαναμιμνήσκω", "translit": "epanamimnḗskō", "pronunciation": "ep-an-ah-mim-nace'-ko", "derivation": "from (G1909) and (G363);", "definition": "to remind of", "kjv": "put in mind."}, "G1879": {"greek": "ἐπαναπαύομαι", "translit": "epanapaúomai", "pronunciation": "ep-an-ah-pow'-om-ahee", "derivation": "middle voice from (G1909) and (G373);", "definition": "to settle on; literally (remain) or figuratively (rely)", "kjv": "rest in (upon)."}, "G1880": {"greek": "ἐπανέρχομαι", "translit": "epanérchomai", "pronunciation": "ep-an-er'-khom-ahee", "derivation": "from (G1909) and (G424);", "definition": "to come up on, i.e. return", "kjv": "come again, return."}, "G1881": {"greek": "ἐπανίσταμαι", "translit": "epanístamai", "pronunciation": "ep-an-is'-tam-ahee", "derivation": "middle voice from (G1909) and (G450);", "definition": "to stand up on, i.e. (figuratively) to attack", "kjv": "rise up against."}, "G1882": {"greek": "ἐπανόρθωσις", "translit": "epanórthōsis", "pronunciation": "ep-an-or'-tho-sis", "derivation": "from a compound of (G1909) and (G461);", "definition": "a straightening up again, i.e. (figuratively) rectification (reformation)", "kjv": "correction."}, "G1883": {"greek": "ἐπάνω", "translit": "epánō", "pronunciation": "ep-an'-o", "derivation": "from (G1909) and (G507);", "definition": "up above, i.e. over or on (of place, amount, rank, etc.)", "kjv": "above, more than, (up-)on, over."}, "G1884": {"greek": "ἐπαρκέω", "translit": "eparkéō", "pronunciation": "ep-ar-keh'-o", "derivation": "from (G1909) and (G714);", "definition": "to avail for, i.e. help", "kjv": "relieve."}, "G1885": {"greek": "ἐπαρχία", "translit": "eparchía", "pronunciation": "ep-ar-khee'-ah", "derivation": "from a compound of (G1909) and (G757) (meaning a governor of a district, \"eparch\");", "definition": "a special region of government, i.e. a Roman præfecture", "kjv": "province."}, "G1886": {"greek": "ἔπαυλις", "translit": "épaulis", "pronunciation": "ep'-ow-lis", "derivation": "from (G1909) and an equivalent of (G833);", "definition": "a hut over the head, i.e. a dwelling", "kjv": "habitation."}, "G1887": {"greek": "ἐπαύριον", "translit": "epaúrion", "pronunciation": "ep-ow'-ree-on", "derivation": "from (G1909) and (G839);", "definition": "occurring on the succeeding day, i.e. ((G2250) being implied) to-morrow", "kjv": "day following, morrow, next day (after)."}, "G1889": {"greek": "Ἐπαφρᾶς", "translit": "Epaphrâs", "pronunciation": "ep-af-ras'", "derivation": "contracted from (G1891);", "definition": "Epaphras, a Christian", "kjv": "Epaphras."}, "G1890": {"greek": "ἐπαφρίζω", "translit": "epaphrízō", "pronunciation": "ep-af-rid'-zo", "derivation": "from (G1909) and (G875);", "definition": "to foam upon, i.e. (figuratively) to exhibit (a vile passion)", "kjv": "foam out."}, "G1891": {"greek": "Ἐπαφρόδιτος", "translit": "Epaphróditos", "pronunciation": "ep-af-rod'-ee-tos", "derivation": "from (G1909) (in the sense of devoted to) and (Venus);", "definition": "Epaphroditus, a Christian", "kjv": "Epaphroditus."}, "G1892": {"greek": "ἐπεγείρω", "translit": "epegeírō", "pronunciation": "ep-eg-i'-ro", "derivation": "from (G1909) and (G1453);", "definition": "to rouse upon, i.e. (figuratively) to excite against", "kjv": "raise, stir up."}, "G1893": {"greek": "ἐπεί", "translit": "epeí", "pronunciation": "ep-i'", "derivation": "from (G1909) and (G1487);", "definition": "thereupon, i.e. since (of time or cause)", "kjv": "because, else, for that (then, -asmuch as), otherwise, seeing that, since, when."}, "G1894": {"greek": "ἐπειδή", "translit": "epeidḗ", "pronunciation": "ep-i-day'", "derivation": "from (G1893) and (G1211);", "definition": "since now, i.e. (of time) when, or (of cause) whereas", "kjv": "after that, because, for (that, -asmuch as), seeing, since."}, "G1895": {"greek": "ἐπειδήπερ", "translit": "epeidḗper", "pronunciation": "ep-i-day'-per", "derivation": "from (G1894) and (G4007);", "definition": "since indeed (of cause)", "kjv": "forasmuch."}, "G1896": {"greek": "ἐπεῖδον", "translit": "epeîdon", "pronunciation": "ep-i'-don", "derivation": "and other moods and persons of the same tense; from (G1909) and (G1492);", "definition": "to regard (favorably or otherwise)", "kjv": "behold, look upon."}, "G1898": {"greek": "ἐπεισαγωγή", "translit": "epeisagōgḗ", "pronunciation": "ep-ice-ag-o-gay'", "derivation": "from a compound of (G1909) and (G1521);", "definition": "a superintroduction", "kjv": "bringing in."}, "G1899": {"greek": "ἔπειτα", "translit": "épeita", "pronunciation": "ep'-i-tah", "derivation": "from (G1909) and (G1534);", "definition": "thereafter", "kjv": "after that(-ward), then."}, "G1900": {"greek": "ἐπέκεινα", "translit": "epékeina", "pronunciation": "ep-ek'-i-nah", "derivation": "from (G1909) and (the accusative case plural neuter of) (G1565);", "definition": "upon those parts of, i.e. on the further side of", "kjv": "beyond."}, "G1901": {"greek": "ἐπεκτείνομαι", "translit": "epekteínomai", "pronunciation": "ep-ek-ti'-nom-ahee", "derivation": "middle voice from (G1909) and (G1614);", "definition": "to stretch (oneself) forward upon", "kjv": "reach forth."}, "G1902": {"greek": "ἐπενδύομαι", "translit": "ependýomai", "pronunciation": "ep-en-doo'-om-ahee", "derivation": "middle voice from (G1909) and (G1746);", "definition": "to invest upon oneself", "kjv": "be clothed upon."}, "G1903": {"greek": "ἐπενδύτης", "translit": "ependýtēs", "pronunciation": "ep-en-doo'-tace", "derivation": "from (G1902);", "definition": "a wrapper, i.e. outer garment", "kjv": "fisher's coat."}, "G1904": {"greek": "ἐπέρχομαι", "translit": "epérchomai", "pronunciation": "ep-er'-khom-ahee", "derivation": "from (G1909) and (G2064);", "definition": "to supervene, i.e. arrive, occur, impend, attack, (figuratively) influence", "kjv": "come (in, upon)."}, "G1905": {"greek": "ἐπερωτάω", "translit": "eperōtáō", "pronunciation": "ep-er-o-tah'-o", "derivation": "from (G1909) and (G2065);", "definition": "to ask for, i.e. inquire, seek", "kjv": "ask (after, questions), demand, desire, question."}, "G1906": {"greek": "ἐπερώτημα", "translit": "eperṓtēma", "pronunciation": "ep-er-o'-tay-mah", "derivation": "from (G1905);", "definition": "an inquiry", "kjv": "answer."}, "G1907": {"greek": "ἐπέχω", "translit": "epéchō", "pronunciation": "ep-ekh'-o", "derivation": "from (G1909) and (G2192);", "definition": "to hold upon, i.e. (by implication) to retain; (by extension) to detain; (with implication, of (G3563)) to pay attention to", "kjv": "give (take) heed unto, hold forth, mark, stay."}, "G1908": {"greek": "ἐπηρεάζω", "translit": "epēreázō", "pronunciation": "ep-ay-reh-ad'-zo", "derivation": "from a compound of (G1909) and (probably) (threats);", "definition": "to insult, slander", "kjv": "use despitefully, falsely accuse."}, "G1909": {"greek": "ἐπί", "translit": "epí", "pronunciation": "ep-ee'", "derivation": "a primary preposition;", "definition": "properly, meaning superimposition (of time, place, order, etc.), as a relation of distribution (with the genitive case), i.e. over, upon, etc.; of rest (with the dative case) at, on, etc.; of direction (with the accusative case) towards, upon, etc.", "kjv": "about (the times), above, after, against, among, as long as (touching), at, beside, X have charge of, (be-, (where-))fore, in (a place, as much as, the time of, -to), (because) of, (up-)on (behalf of), over, (by, for) the space of, through(-out), (un-)to(-ward), with."}, "G1910": {"greek": "ἐπιβαίνω", "translit": "epibaínō", "pronunciation": "ep-ee-bah'-ee-no", "derivation": "from (G1909) and the base of (G939);", "definition": "to walk upon, i.e. mount, ascend, embark, arrive", "kjv": "come (into), enter into, go abroad, sit upon, take ship."}, "G1911": {"greek": "ἐπιβάλλω", "translit": "epibállō", "pronunciation": "ep-ee-bal'-lo", "derivation": "from (G1909) and (G906);", "definition": "to throw upon (literal or figurative, transitive or reflexive; usually with more or less force); specially (with (G1438) implied) to reflect; impersonally, to belong to", "kjv": "beat into, cast (up-)on, fall, lay (on), put (unto), stretch forth, think on."}, "G1912": {"greek": "ἐπιβαρέω", "translit": "epibaréō", "pronunciation": "ep-ee-bar-eh'-o", "derivation": "from (G1909) and (G916);", "definition": "to be heavy upon, i.e. (pecuniarily) to be expensive to; figuratively, to be severe towards", "kjv": "be chargeable to, overcharge."}, "G1913": {"greek": "ἐπιβιβάζω", "translit": "epibibázō", "pronunciation": "ep-ee-bee-bad'-zo", "derivation": "from (G1909) and a reduplicated derivative of the base of (G939) (compare (G307));", "definition": "to cause to mount (an animal)", "kjv": "set on."}, "G1914": {"greek": "ἐπιβλέπω", "translit": "epiblépō", "pronunciation": "ep-ee-blep'-o", "derivation": "from (G1909) and (G991);", "definition": "to gaze at (with favor, pity or partiality)", "kjv": "look upon, regard, have respect to."}, "G1915": {"greek": "ἐπίβλημα", "translit": "epíblēma", "pronunciation": "ep-ib'-lay-mah", "derivation": "from (G1911);", "definition": "a patch", "kjv": "piece."}, "G1917": {"greek": "ἐπιβουλή", "translit": "epiboulḗ", "pronunciation": "ep-ee-boo-lay'", "derivation": "from a presumed compound of (G1909) and (G1014);", "definition": "a plan against someone, i.e. a plot", "kjv": "laying (lying) in wait."}, "G1918": {"greek": "ἐπιγαμβρεύω", "translit": "epigambreúō", "pronunciation": "ep-ee-gam-bryoo'-o", "derivation": "from (G1909) and a derivative of (G1062);", "definition": "to form affinity with, i.e. (specially) in a levirate way", "kjv": "marry."}, "G1919": {"greek": "ἐπίγειος", "translit": "epígeios", "pronunciation": "ep-ig'-i-os", "derivation": "from (G1909) and (G1093);", "definition": "worldly (physically or morally)", "kjv": "earthly, in earth, terrestrial."}, "G1920": {"greek": "ἐπιγίνομαι", "translit": "epigínomai", "pronunciation": "ep-ig-in'-om-ahee", "derivation": "from (G1909) and (G1096);", "definition": "to arrive upon, i.e. spring up (as a wind)", "kjv": "blow."}, "G1921": {"greek": "ἐπιγινώσκω", "translit": "epiginṓskō", "pronunciation": "ep-ig-in-oce'-ko", "derivation": "from (G1909) and (G1097);", "definition": "to know upon some mark, i.e. recognize; by implication, to become fully acquainted with, to acknowledge", "kjv": "(ac-, have, take)know(-ledge, well), perceive."}, "G1922": {"greek": "ἐπίγνωσις", "translit": "epígnōsis", "pronunciation": "ep-ig'-no-sis", "derivation": "from (G1921);", "definition": "recognition, i.e. (by implication) full discernment, acknowledgement", "kjv": "(ac-)knowledge(-ing, - ment)."}, "G1923": {"greek": "ἐπιγραφή", "translit": "epigraphḗ", "pronunciation": "ep-ig-raf-ay'", "derivation": "from (G1924);", "definition": "an inscription", "kjv": "superscription."}, "G1924": {"greek": "ἐπιγράφω", "translit": "epigráphō", "pronunciation": "ep-ee-graf'-o", "derivation": "from (G1909) and (G1125);", "definition": "to inscribe (physically or mentally)", "kjv": "inscription, write in (over, thereon)."}, "G1925": {"greek": "ἐπιδείκνυμι", "translit": "epideíknymi", "pronunciation": "ep-ee-dike'-noo-mee", "derivation": "from (G1909) and (G1166);", "definition": "to exhibit (physically or mentally)", "kjv": "shew."}, "G1926": {"greek": "ἐπιδέχομαι", "translit": "epidéchomai", "pronunciation": "ep-ee-dekh'-om-ahee", "derivation": "from (G1909) and (G1209);", "definition": "to admit (as a guest or (figuratively) teacher)", "kjv": "receive."}, "G1927": {"greek": "ἐπιδημέω", "translit": "epidēméō", "pronunciation": "ep-ee-day-meh'-o", "derivation": "from a compound of (G1909) and (G1218);", "definition": "to make oneself at home, i.e. (by extension) to reside (in a foreign country)", "kjv": "(be) dwelling (which were) there, stranger."}, "G1928": {"greek": "ἐπιδιατάσσομαι", "translit": "epidiatássomai", "pronunciation": "ep-ee-dee-ah-tas'-som-ahee", "derivation": "middle voice from (G1909) and (G1299);", "definition": "to appoint besides, i.e. supplement (as a codicil)", "kjv": "add to."}, "G1929": {"greek": "ἐπιδίδωμι", "translit": "epidídōmi", "pronunciation": "ep-ee-did'-o-mee", "derivation": "from (G1909) and (G1325);", "definition": "to give over (by hand or surrender)", "kjv": "deliver unto, give, let (+ (her drive)), offer."}, "G1930": {"greek": "ἐπιδιορθόω", "translit": "epidiorthóō", "pronunciation": "ep-ee-dee-or-tho'-o", "derivation": "from (G1909) and a derivative of (G3717);", "definition": "to straighten further, i.e. (figuratively) arrange additionally", "kjv": "set in order."}, "G1931": {"greek": "ἐπιδύω", "translit": "epidýō", "pronunciation": "ep-ee-doo'-o", "derivation": "from (G1909) and (G1416);", "definition": "to set fully (as the sun)", "kjv": "go down."}, "G1932": {"greek": "ἐπιείκεια", "translit": "epieíkeia", "pronunciation": "ep-ee-i'-ki-ah", "derivation": "from (G1933);", "definition": "suitableness, i.e. (by implication) equity, mildness", "kjv": "clemency, gentleness."}, "G1933": {"greek": "ἐπιεικής", "translit": "epieikḗs", "pronunciation": "ep-ee-i-kace'", "derivation": "from (G1909) and (G1503);", "definition": "appropriate, i.e. (by implication) mild", "kjv": "gentle, moderation, patient."}, "G1934": {"greek": "ἐπιζητέω", "translit": "epizētéō", "pronunciation": "ep-eed-zay-teh'-o", "derivation": "from (G1909) and (G2212);", "definition": "to search (inquire) for; intensively, to demand, to crave", "kjv": "desire, enquire, seek (after, for)."}, "G1935": {"greek": "ἐπιθανάτιος", "translit": "epithanátios", "pronunciation": "ep-ee-than-at'-ee-os", "derivation": "from (G1909) and (G2288);", "definition": "doomed to death", "kjv": "appointed to death."}, "G1936": {"greek": "ἐπίθεσις", "translit": "epíthesis", "pronunciation": "ep-ith'-es-is", "derivation": "from (G2007);", "definition": "an imposition (of hands officially)", "kjv": "laying (putting) on."}, "G1937": {"greek": "ἐπιθυμέω", "translit": "epithyméō", "pronunciation": "ep-ee-thoo-meh'-o", "derivation": "from (G1909) and (G2372);", "definition": "to set the heart upon, i.e. long for (rightfully or otherwise)", "kjv": "covet, desire, would fain, lust (after)."}, "G1938": {"greek": "ἐπιθυμητής", "translit": "epithymētḗs", "pronunciation": "ep-ee-thoo-may-tace'", "derivation": "from (G1937);", "definition": "a craver", "kjv": "+ lust after."}, "G1939": {"greek": "ἐπιθυμία", "translit": "epithymía", "pronunciation": "ep-ee-thoo-mee'-ah", "derivation": "from (G1937);", "definition": "a longing (especially for what is forbidden)", "kjv": "concupiscence, desire, lust (after)."}, "G1940": {"greek": "ἐπικαθίζω", "translit": "epikathízō", "pronunciation": "ep-ee-kath-id'-zo", "derivation": "from (G1909) and (G2523);", "definition": "to seat upon", "kjv": "set on."}, "G1941": {"greek": "ἐπικαλέομαι", "translit": "epikaléomai", "pronunciation": "ep-ee-kal-eh'-om-ahee", "derivation": "middle voice from (G1909) and (G2564);", "definition": "to entitle; by implication, to invoke (for aid, worship, testimony, decision, etc.)", "kjv": "appeal (unto), call (on, upon), surname."}, "G1942": {"greek": "ἐπικάλυμα", "translit": "epikályma", "pronunciation": "ep-ee-kal'-oo-mah", "derivation": "from (G1943);", "definition": "a covering, i.e. (figuratively) pretext", "kjv": "cloke."}, "G1943": {"greek": "ἐπικαλύπτω", "translit": "epikalýptō", "pronunciation": "ep-ee-kal-oop'-to", "derivation": "from (G1909) and (G2572);", "definition": "to conceal, i.e. (figuratively) forgive", "kjv": "cover."}, "G1944": {"greek": "ἐπικατάρατος", "translit": "epikatáratos", "pronunciation": "ep-ee-kat-ar'-at-os", "derivation": "from (G1909) and a derivative of (G2672);", "definition": "imprecated, i.e. execrable", "kjv": "accursed."}, "G1945": {"greek": "ἐπίκειμαι", "translit": "epíkeimai", "pronunciation": "ep-ik'-i-mahee", "derivation": "from (G1909) and (G2749);", "definition": "to rest upon (literally or figuratively)", "kjv": "impose, be instant, (be) laid (there-, up-)on, (when) lay (on), lie (on), press upon."}, "G1946": {"greek": "Ἐπικούρειος", "translit": "Epikoúreios", "pronunciation": "ep-ee-koo'-ri-os", "derivation": "from (compare (G1947)) (a noted philosopher);", "definition": "an Epicurean or follower of Epicurus", "kjv": "Epicurean."}, "G1947": {"greek": "ἐπικουρία", "translit": "epikouría", "pronunciation": "ep-ee-koo-ree'-ah", "derivation": "from a compound of (G1909) and a (prolonged) form of the base of (G2877) (in the sense of servant);", "definition": "assistance", "kjv": "help."}, "G1948": {"greek": "ἐπικρίνω", "translit": "epikrínō", "pronunciation": "ep-ee-kree'-no", "derivation": "from (G1909) and (G2919);", "definition": "to adjudge", "kjv": "give sentence."}, "G1949": {"greek": "ἐπιλαμβάνομαι", "translit": "epilambánomai", "pronunciation": "ep-ee-lam-ban'-om-ahee", "derivation": "middle voice from (G1909) and (G2983);", "definition": "to seize (for help, injury, attainment, or any other purpose; literally or figuratively)", "kjv": "catch, lay hold (up-)on, take (by, hold of, on)."}, "G1950": {"greek": "ἐπιλανθάνομαι", "translit": "epilanthánomai", "pronunciation": "ep-ee-lan-than'-om-ahee", "derivation": "middle voice from (G1909) and (G2990);", "definition": "to lose out of mind; by implication, to neglect", "kjv": "(be) forget(-ful of)."}, "G1951": {"greek": "ἐπιλέγομαι", "translit": "epilégomai", "pronunciation": "ep-ee-leg'-om-ahee", "derivation": "middle voice from (G1909) and (G3004);", "definition": "to surname, select", "kjv": "call, choose."}, "G1952": {"greek": "ἐπιλείπω", "translit": "epileípō", "pronunciation": "ep-ee-li'-po", "derivation": "from (G1909) and (G3007);", "definition": "to leave upon, i.e. (figuratively) to be insufficient for", "kjv": "fail."}, "G1953": {"greek": "ἐπιλησμονή", "translit": "epilēsmonḗ", "pronunciation": "ep-ee-lace-mon-ay'", "derivation": "from a derivative of (G1950);", "definition": "negligence", "kjv": "X forgetful."}, "G1954": {"greek": "ἐπίλοιπος", "translit": "epíloipos", "pronunciation": "ep-il'-oy-pos", "derivation": "from (G1909) and (G3062);", "definition": "left over, i.e. remaining", "kjv": "rest."}, "G1955": {"greek": "ἐπίλυσις", "translit": "epílysis", "pronunciation": "ep-il'-oo-sis", "derivation": "from (G1956);", "definition": "explanation, i.e. application", "kjv": "interpretation."}, "G1956": {"greek": "ἐπιλύω", "translit": "epilýō", "pronunciation": "ep-ee-loo'-o", "derivation": "from (G1909) and (G3089);", "definition": "to solve further, i.e. (figuratively) to explain, decide", "kjv": "determine, expound."}, "G1957": {"greek": "ἐπιμαρτυρέω", "translit": "epimartyréō", "pronunciation": "ep-ee-mar-too-reh'-o", "derivation": "from (G1909) and (G3140);", "definition": "to attest further, i.e. corroborate", "kjv": "testify."}, "G1958": {"greek": "ἐπιμέλεια", "translit": "epiméleia", "pronunciation": "ep-ee-mel'-i-ah", "derivation": "from (G1959);", "definition": "carefulness, i.e. kind attention (hospitality)", "kjv": "+ refresh self."}, "G1959": {"greek": "ἐπιμελέομαι", "translit": "epimeléomai", "pronunciation": "ep-ee-mel-eh'-om-ahee", "derivation": "middle voice from (G1909) and the same as (G3199);", "definition": "to care for (physically or otherwise)", "kjv": "take care of."}, "G1960": {"greek": "ἐπιμελῶς", "translit": "epimelōs", "pronunciation": "ep-ee-mel-oce'", "derivation": "adverb from a derivative of (G1959);", "definition": "carefully", "kjv": "diligently."}, "G1961": {"greek": "ἐπιμένω", "translit": "epiménō", "pronunciation": "ep-ee-men'-o", "derivation": "from (G1909) and (G3306);", "definition": "to stay over, i.e. remain (figuratively, persevere)", "kjv": "abide (in), continue (in), tarry."}, "G1962": {"greek": "ἐπινεύω", "translit": "epineúō", "pronunciation": "ep-een-yoo'-o", "derivation": "from (G1909) and (G3506);", "definition": "to nod at, i.e. (by implication) to assent", "kjv": "consent."}, "G1963": {"greek": "ἐπίνοια", "translit": "epínoia", "pronunciation": "ep-in'-oy-ah", "derivation": "from (G1909) and (G3563);", "definition": "attention of the mind, i.e. (by implication) purpose", "kjv": "thought."}, "G1964": {"greek": "ἐπιορκέω", "translit": "epiorkéō", "pronunciation": "ep-ee-or-keh'-o", "derivation": "from (G1965);", "definition": "to commit perjury", "kjv": "forswear self."}, "G1965": {"greek": "ἐπίορκος", "translit": "epíorkos", "pronunciation": "ep-ee'-or-kos", "derivation": "from (G1909) and (G3727);", "definition": "on oath, i.e. (falsely) a forswearer", "kjv": "perjured person."}, "G1966": {"greek": "ἐπιοῦσα", "translit": "epioûsa", "pronunciation": "ep-ee-oo'-sah", "derivation": "feminine singular participle of a compound of (G1909) and (to go);", "definition": "supervening, i.e. ((G2250) or (G3571) being expressed or implied) the ensuing day or night", "kjv": "following, next."}, "G1967": {"greek": "ἐπιούσιος", "translit": "epioúsios", "pronunciation": "ep-ee-oo'-see-os", "derivation": "perhaps from the same as (G1966);", "definition": "tomorrow's; but more probably from (G1909) and a derivative of the present participle feminine of (G1510); for subsistence, i.e. needful", "kjv": "daily."}, "G1968": {"greek": "ἐπιπίπτω", "translit": "epipíptō", "pronunciation": "ep-ee-pip'-to", "derivation": "from (G1909) and (G4098);", "definition": "to embrace (with affection) or seize (with more or less violence; literally or figuratively)", "kjv": "fall into (on, upon) lie on, press upon."}, "G1969": {"greek": "ἐπιπλήσσω", "translit": "epiplḗssō", "pronunciation": "ep-ee-place'-so", "derivation": "from (G1909) and (G4141);", "definition": "to chastise, i.e. (with words) to upbraid", "kjv": "rebuke."}, "G1971": {"greek": "ἐπιποθέω", "translit": "epipothéō", "pronunciation": "ep-ee-poth-eh'-o", "derivation": "from (G1909) and potheo (to yearn);", "definition": "to dote upon, i.e. intensely crave possession (lawfully or wrongfully)", "kjv": "(earnestly) desire (greatly), (greatly) long (after), lust."}, "G1972": {"greek": "ἐπιπόθησις", "translit": "epipóthēsis", "pronunciation": "ep-ee-poth'-ay-sis", "derivation": "from (G1971);", "definition": "a longing for", "kjv": "earnest (vehement) desire."}, "G1973": {"greek": "ἐπιπόθητος", "translit": "epipóthētos", "pronunciation": "ep-ee-poth'-ay-tos", "derivation": "from (G1909) and a derivative of the latter part of (G1971);", "definition": "yearned upon, i.e. greatly loved", "kjv": "longed for."}, "G1974": {"greek": "ἐπιποθία", "translit": "epipothía", "pronunciation": "ep-ee-poth-ee'-ah", "derivation": "from (G1971);", "definition": "intense longing", "kjv": "great desire."}, "G1975": {"greek": "ἐπιπορεύομαι", "translit": "epiporeúomai", "pronunciation": "ep-ee-por-yoo'-om-ahee", "derivation": "from (G1909) and (G4198);", "definition": "to journey further, i.e. travel on (reach)", "kjv": "come."}, "G1976": {"greek": "ἐπιῤῥάπτω", "translit": "epirrháptō", "pronunciation": "ep-ir-hrap'-to", "derivation": "from (G1909) and the base of (G4476);", "definition": "to stitch upon, i.e. fasten with the needle", "kjv": "sew on."}, "G1977": {"greek": "ἐπιῤῥίπτω", "translit": "epirrhíptō", "pronunciation": "ep-ir-hrip'-to", "derivation": "from (G1909) and (G4496);", "definition": "to throw upon (literally or figuratively)", "kjv": "cast upon."}, "G1978": {"greek": "ἐπίσημος", "translit": "epísēmos", "pronunciation": "ep-is'-ay-mos", "derivation": "from (G1909) and some form of the base of (G4591);", "definition": "remarkable, i.e. (figuratively) eminent", "kjv": "notable, of note."}, "G1979": {"greek": "ἐπισιτισμός", "translit": "episitismós", "pronunciation": "ep-ee-sit-is-mos'", "derivation": "from a compound of (G1909) and a derivative of (G4621);", "definition": "a provisioning, i.e. (concretely) food", "kjv": "victuals."}, "G1980": {"greek": "ἐπισκέπτομαι", "translit": "episképtomai", "pronunciation": "ep-ee-skep'-tom-ahee", "derivation": "middle voice from (G1909) and the base of (G4649);", "definition": "to inspect, i.e. (by implication) to select; by extension, to go to see, relieve", "kjv": "look out, visit."}, "G1981": {"greek": "ἐπισκηνόω", "translit": "episkēnóō", "pronunciation": "ep-ee-skay-no'-o", "derivation": "from (G1909) and (G4637);", "definition": "to tent upon, i.e. (figuratively) abide with", "kjv": "rest upon."}, "G1982": {"greek": "ἐπισκιάζω", "translit": "episkiázō", "pronunciation": "ep-ee-skee-ad'-zo", "derivation": "from (G1909) and a derivative of (G4639);", "definition": "to cast a shade upon, i.e. (by analogy) to envelop in a haze of brilliancy; figuratively, to invest with preternatural influence", "kjv": "overshadow."}, "G1983": {"greek": "ἐπισκοπέω", "translit": "episkopéō", "pronunciation": "ep-ee-skop-eh'-o", "derivation": "from (G1909) and (G4648);", "definition": "to oversee; by implication, to beware", "kjv": "look diligently, take the oversight."}, "G1984": {"greek": "ἐπισκοπή", "translit": "episkopḗ", "pronunciation": "ep-is-kop-ay'", "derivation": "from (G1980);", "definition": "inspection (for relief); by implication, superintendence; specially, the Christian \"episcopate\"", "kjv": "the office of a \"bishop\", bishoprick, visitation."}, "G1985": {"greek": "ἐπίσκοπος", "translit": "epískopos", "pronunciation": "ep-is'-kop-os", "derivation": "from (G1909) and (G4649) (in the sense of (G1983));", "definition": "a superintendent, i.e. Christian officer in genitive case charge of a (or the) church (literally or figuratively)", "kjv": "bishop, overseer."}, "G1986": {"greek": "ἐπισπάομαι", "translit": "epispáomai", "pronunciation": "ep-ee-spah'-om-ahee", "derivation": "from (G1909) and (G4685);", "definition": "to draw over, i.e. (with (G203) implied) efface the mark of circumcision (by recovering with the foreskin)", "kjv": "become uncircumcised."}, "G1987": {"greek": "ἐπίσταμαι", "translit": "epístamai", "pronunciation": "ep-is'-tam-ahee", "derivation": "apparently a middle voice of (G2186) (with (G3563) implied);", "definition": "to put the mind upon, i.e. comprehend, or be acquainted with", "kjv": "know, understand."}, "G1988": {"greek": "ἐπιστάτης", "translit": "epistátēs", "pronunciation": "ep-is-tat'-ace", "derivation": "from (G1909) and a presumed derivative of (G2476);", "definition": "an appointee over, i.e. commander (teacher)", "kjv": "master."}, "G1989": {"greek": "ἐπιστέλλω", "translit": "epistéllō", "pronunciation": "ep-ee-stel'-lo", "derivation": "from (G1909) and (G4724);", "definition": "to enjoin (by writing), i.e. (genitive case) to communicate by letter (for any purpose)", "kjv": "write (a letter, unto)."}, "G1990": {"greek": "ἐπιστήμων", "translit": "epistḗmōn", "pronunciation": "ep-ee-stay'-mone", "derivation": "from (G1987);", "definition": "intelligent", "kjv": "endued with knowledge."}, "G1991": {"greek": "ἐπιστηρίζω", "translit": "epistērízō", "pronunciation": "ep-ee-stay-rid'-zo", "derivation": "from (G1909) and (G4741);", "definition": "to support further, i.e. reestablish", "kjv": "confirm, strengthen."}, "G1992": {"greek": "ἐπιστολή", "translit": "epistolḗ", "pronunciation": "ep-is-tol-ay'", "derivation": "from (G1989);", "definition": "a written message", "kjv": "\"epistle,\" letter."}, "G1993": {"greek": "ἐπιστομίζω", "translit": "epistomízō", "pronunciation": "ep-ee-stom-id'-zo", "derivation": "from (G1909) and (G4750);", "definition": "to put something over the mouth, i.e. (figuratively) to silence", "kjv": "stop mouths."}, "G1994": {"greek": "ἐπιστρέφω", "translit": "epistréphō", "pronunciation": "ep-ee-stref'-o", "derivation": "from (G1909) and (G4762);", "definition": "to revert (literally, figuratively or morally)", "kjv": "come (go) again, convert, (re-)turn (about, again)."}, "G1995": {"greek": "ἐπιστροφή", "translit": "epistrophḗ", "pronunciation": "ep-is-trof-ay'", "derivation": "from (G1994);", "definition": "reversion, i.e. morally, revolution", "kjv": "conversion."}, "G1996": {"greek": "ἐπισυνάγω", "translit": "episynágō", "pronunciation": "ep-ee-soon-ag'-o", "derivation": "from (G1909) and (G4863);", "definition": "to collect upon the same place", "kjv": "gather (together)."}, "G1997": {"greek": "ἐπισυναγωγή", "translit": "episynagōgḗ", "pronunciation": "ep-ee-soon-ag-o-gay'", "derivation": "from (G1996);", "definition": "a complete collection; especially a Christian meeting (for worship)", "kjv": "assembling (gathering) together."}, "G1998": {"greek": "ἐπισυντρέχω", "translit": "episyntréchō", "pronunciation": "ep-ee-soon-trekh'-o", "derivation": "from (G1909) and (G4936);", "definition": "to hasten together upon one place (or a particular occasion)", "kjv": "come running together."}, "G1999": {"greek": "ἐπισύστασις", "translit": "episýstasis", "pronunciation": "ep-ee-soo'-stas-is", "derivation": "from the middle voice of a compound of (G1909) and (G4921);", "definition": "a conspiracy, i.e. concourse (riotous or friendly)", "kjv": "that which cometh upon, + raising up."}, "G2000": {"greek": "ἐπισφαλής", "translit": "episphalḗs", "pronunciation": "ep-ee-sfal-ace'", "derivation": "from a compound of (G1909) and (to trip);", "definition": "figuratively, insecure", "kjv": "dangerous."}, "G2001": {"greek": "ἐπισχύω", "translit": "epischýō", "pronunciation": "ep-is-khoo'-o", "derivation": "from (G1909) and (G2480);", "definition": "to avail further, i.e. (figuratively) insist stoutly", "kjv": "be the more fierce."}, "G2002": {"greek": "ἐπισωρεύω", "translit": "episōreúō", "pronunciation": "ep-ee-so-ryoo'-o", "derivation": "from (G1909) and (G4987);", "definition": "to accumulate further, i.e. (figuratively) seek additionally", "kjv": "heap."}, "G2003": {"greek": "ἐπιταγή", "translit": "epitagḗ", "pronunciation": "ep-ee-tag-ay'", "derivation": "from (G2004);", "definition": "an injunction or decree; by implication, authoritativeness", "kjv": "authority, commandment."}, "G2004": {"greek": "ἐπιτάσσω", "translit": "epitássō", "pronunciation": "ep-ee-tas'-so", "derivation": "from (G1909) and (G5021);", "definition": "to arrange upon, i.e. order", "kjv": "charge, command, injoin."}, "G2005": {"greek": "ἐπιτελέω", "translit": "epiteléō", "pronunciation": "ep-ee-tel-eh'-o", "derivation": "from (G1909) and (G5055);", "definition": "to fulfill further (or completely), i.e. execute; by implication, to terminate, undergo", "kjv": "accomplish, do, finish, (make) (perfect), perform(X -ance)."}, "G2006": {"greek": "ἐπιτήδειος", "translit": "epitḗdeios", "pronunciation": "ep-ee-tay'-di-os", "derivation": "from (enough);", "definition": "serviceable, i.e. (by implication) requisite", "kjv": "things which are needful."}, "G2007": {"greek": "ἐπιτίθημι", "translit": "epitíthēmi", "pronunciation": "ep-ee-tith'-ay-mee", "derivation": "from (G1909) and (G5087);", "definition": "to impose (in a friendly or hostile sense)", "kjv": "add unto, lade, lay upon, put (up) on, set on (up), + surname, X wound."}, "G2008": {"greek": "ἐπιτιμάω", "translit": "epitimáō", "pronunciation": "ep-ee-tee-mah'-o", "derivation": "from (G1909) and (G5091);", "definition": "to tax upon, i.e. censure or admonish; by implication, forbid", "kjv": "(straitly) charge, rebuke."}, "G2009": {"greek": "ἐπιτιμία", "translit": "epitimía", "pronunciation": "ep-ee-tee-mee'-ah", "derivation": "from a compound of (G1909) and (G5092);", "definition": "properly, esteem, i.e. citizenship; used (in the sense of (G2008)) of a penalty", "kjv": "punishment."}, "G2010": {"greek": "ἐπιτρέπω", "translit": "epitrépō", "pronunciation": "ep-ee-trep'-o", "derivation": "from (G1909) and the base of (G5157);", "definition": "to turn over (transfer), i.e. allow", "kjv": "give leave (liberty, license), let, permit, suffer."}, "G2011": {"greek": "ἐπιτροπή", "translit": "epitropḗ", "pronunciation": "ep-ee-trop-ay'", "derivation": "from (G2010);", "definition": "permission, i.e. (by implication) full power", "kjv": "commission."}, "G2012": {"greek": "ἐπίτροπος", "translit": "epítropos", "pronunciation": "ep-it'-rop-os", "derivation": "from (G1909) and (G5158) (in the sense of (G2011));", "definition": "a commissioner, i.e. domestic manager, guardian", "kjv": "steward, tutor."}, "G2013": {"greek": "ἐπιτυγχάνω", "translit": "epitynchánō", "pronunciation": "ep-ee-toong-khan'-o", "derivation": "from (G1909) and (G5177);", "definition": "to chance upon, i.e. (by implication) to attain", "kjv": "obtain."}, "G2014": {"greek": "ἐπιφαίνω", "translit": "epiphaínō", "pronunciation": "ep-ee-fah'-ee-no", "derivation": "from (G1909) and (G5316);", "definition": "to shine upon, i.e. become (literally) visible or (figuratively) known", "kjv": "appear, give light."}, "G2015": {"greek": "ἐπιφάνεια", "translit": "epipháneia", "pronunciation": "ep-if-an'-i-ah", "derivation": "from (G2016);", "definition": "a manifestation, i.e. (specially) the advent of Christ (past or future)", "kjv": "appearing, brightness."}, "G2016": {"greek": "ἐπιφανής", "translit": "epiphanḗs", "pronunciation": "ep-if-an-ace'", "derivation": "from (G2014);", "definition": "conspicuous, i.e. (figuratively) memorable", "kjv": "notable."}, "G2017": {"greek": "ἐπιφαύω", "translit": "epiphaúō", "pronunciation": "ep-ee-fow'-o", "derivation": "a form of (G2014);", "definition": "to illuminate (figuratively)", "kjv": "give light."}, "G2018": {"greek": "ἐπιφέρω", "translit": "epiphérō", "pronunciation": "ep-ee-fer'-o", "derivation": "from (G1909) and (G5342);", "definition": "to bear upon (or further), i.e. adduce (personally or judicially (accuse, inflict)), superinduce", "kjv": "add, bring (against), take."}, "G2019": {"greek": "ἐπιφωνέω", "translit": "epiphōnéō", "pronunciation": "ep-ee-fo-neh'-o", "derivation": "from (G1909) and (G5455);", "definition": "to call at something, i.e. exclaim", "kjv": "cry (against), give a shout."}, "G2020": {"greek": "ἐπιφώσκω", "translit": "epiphṓskō", "pronunciation": "ep-ee-foce'-ko", "derivation": "a form of (G2017);", "definition": "to begin to grow light", "kjv": "begin to dawn, X draw on."}, "G2021": {"greek": "ἐπιχειρέω", "translit": "epicheiréō", "pronunciation": "ep-ee-khi-reh'-o", "derivation": "from (G1909) and (G5495);", "definition": "to put the hand upon, i.e. undertake", "kjv": "go about, take in hand (upon)."}, "G2022": {"greek": "ἐπιχέω", "translit": "epichéō", "pronunciation": "ep-ee-kheh'-o", "derivation": "from (G1909) and (to pour);", "definition": "", "kjv": "to pour upon:--pour in."}, "G2023": {"greek": "ἐπιχορηγέω", "translit": "epichorēgéō", "pronunciation": "ep-ee-khor-ayg-eh'-o", "derivation": "from (G1909) and (G5524);", "definition": "to furnish besides, i.e. fully supply, (figuratively) aid or contribute", "kjv": "add, minister (nourishment, unto)."}, "G2024": {"greek": "ἐπιχορηγία", "translit": "epichorēgía", "pronunciation": "ep-ee-khor-ayg-ee'-ah", "derivation": "from (G2023);", "definition": "contribution", "kjv": "supply."}, "G2025": {"greek": "ἐπιχρίω", "translit": "epichríō", "pronunciation": "ep-ee-khree'-o", "derivation": "from (G1909) and (G5548);", "definition": "to smear over", "kjv": "anoint."}, "G2026": {"greek": "ἐποικοδομέω", "translit": "epoikodoméō", "pronunciation": "ep-oy-kod-om-eh'-o", "derivation": "from (G1909) and (G3618);", "definition": "to build upon, i.e. (figuratively) to rear up", "kjv": "build thereon (thereupon, on, upon)."}, "G2027": {"greek": "ἐποκέλλω", "translit": "epokéllō", "pronunciation": "ep-ok-el'-lo", "derivation": "from (G1909) and (to urge);", "definition": "to drive upon the shore, i.e. to beach a vessel", "kjv": "run aground."}, "G2028": {"greek": "ἐπονομάζω", "translit": "eponomázō", "pronunciation": "ep-on-om-ad'-zo", "derivation": "from (G1909) and (G3687);", "definition": "to name further, i.e. denominate", "kjv": "call."}, "G2029": {"greek": "ἐποπτεύω", "translit": "epopteúō", "pronunciation": "ep-opt-yoo'-o", "derivation": "from (G1909) and a derivative of (G3700);", "definition": "to inspect, i.e. watch", "kjv": "behold."}, "G2030": {"greek": "ἐπόπτης", "translit": "epóptēs", "pronunciation": "ep-op'-tace", "derivation": "from (G1909) and a presumed derivative of (G3700);", "definition": "a looker-on", "kjv": "eye-witness."}, "G2031": {"greek": "ἔπος", "translit": "épos", "pronunciation": "ep'-os", "derivation": "from (G2036);", "definition": "a word", "kjv": "X say."}, "G2032": {"greek": "ἐπουράνιος", "translit": "epouránios", "pronunciation": "ep-oo-ran'-ee-os", "derivation": "from (G1909) and (G3772);", "definition": "above the sky", "kjv": "celestial, (in) heaven(-ly), high."}, "G2033": {"greek": "ἑπτά", "translit": "heptá", "pronunciation": "hep-tah'", "derivation": "a primary number;", "definition": "seven", "kjv": "seven."}, "G2034": {"greek": "ἑπτάκις", "translit": "heptákis", "pronunciation": "hep-tak-is'", "derivation": "adverb from (G2033);", "definition": "seven times", "kjv": "seven times."}, "G2035": {"greek": "ἑπτακισχίλιοι", "translit": "heptakischílioi", "pronunciation": "hep-tak-is-khil'-ee-oy", "derivation": "from (G2034) and (G5507);", "definition": "seven times a thousand", "kjv": "seven thousand."}, "G2036": {"greek": "ἔπω", "translit": "épō", "pronunciation": "ep'-o", "derivation": "a primary verb (used only in the definite past tense, the others being borrowed from (G2046), (G4483), and (G5346));", "definition": "to speak or say (by word or writing)", "kjv": "answer, bid, bring word, call, command, grant, say (on), speak, tell."}, "G2037": {"greek": "Ἔραστος", "translit": "Érastos", "pronunciation": "er'-as-tos", "derivation": "from (to love);", "definition": "beloved; Erastus, a Christian", "kjv": "Erastus."}, "G2038": {"greek": "ἐργάζομαι", "translit": "ergázomai", "pronunciation": "er-gad'-zom-ahee", "derivation": "middle voice from (G2041);", "definition": "to toil (as a task, occupation, etc.), (by implication) effect, be engaged in or with, etc.", "kjv": "commit, do, labor for, minister about, trade (by), work."}, "G2039": {"greek": "ἐργασία", "translit": "ergasía", "pronunciation": "er-gas-ee'-ah", "derivation": "from (G2040);", "definition": "occupation; by implication, profit, pains", "kjv": "craft, diligence, gain, work."}, "G2040": {"greek": "ἐργάτης", "translit": "ergátēs", "pronunciation": "er-gat'-ace", "derivation": "from (G2041);", "definition": "a toiler; figuratively, a teacher", "kjv": "labourer, worker(-men)."}, "G2041": {"greek": "ἔργον", "translit": "érgon", "pronunciation": "er'-gon", "derivation": "from a primary (but obsolete) (to work);", "definition": "toil (as an effort or occupation); by implication, an act", "kjv": "deed, doing, labour, work."}, "G2042": {"greek": "ἐρεθίζω", "translit": "erethízō", "pronunciation": "er-eth-id'-zo", "derivation": "from a presumed prolonged form of (G2054);", "definition": "to stimulate (especially to anger)", "kjv": "provoke."}, "G2043": {"greek": "ἐρείδω", "translit": "ereídō", "pronunciation": "er-i'-do", "derivation": "of obscure affinity;", "definition": "to prop, i.e. (reflexively) get fast", "kjv": "stick fast."}, "G2044": {"greek": "ἐρεύγομαι", "translit": "ereúgomai", "pronunciation": "er-yoog'-om-ahee", "derivation": "of uncertain affinity;", "definition": "to belch, i.e. (figuratively) to speak out", "kjv": "utter."}, "G2045": {"greek": "ἐρευνάω", "translit": "ereunáō", "pronunciation": "er-yoo-nah'-o", "derivation": "apparently from (G2046) (through the idea of inquiry);", "definition": "to seek, i.e. (figuratively) to investigate", "kjv": "search."}, "G2046": {"greek": "ἐρέω", "translit": "eréō", "pronunciation": "er-eh'-o", "derivation": "probably a fuller form of (G4483);", "definition": "an alternate for (G2036) in certain tenses; to utter, i.e. speak or say", "kjv": "call, say, speak (of), tell."}, "G2047": {"greek": "ἐρημία", "translit": "erēmía", "pronunciation": "er-ay-mee'-ah", "derivation": "from (G2048);", "definition": "solitude (concretely)", "kjv": "desert, wilderness."}, "G2048": {"greek": "ἔρημος", "translit": "érēmos", "pronunciation": "er'-ay-mos", "derivation": "of uncertain affinity;", "definition": "lonesome, i.e. (by implication) waste (usually as a noun, (G5561) being implied)", "kjv": "desert, desolate, solitary, wilderness."}, "G2049": {"greek": "ἐρημόω", "translit": "erēmóō", "pronunciation": "er-ay-mo'-o", "derivation": "from (G2048);", "definition": "to lay waste (literally or figuratively)", "kjv": "(bring to, make) desolate(-ion), come to nought."}, "G2050": {"greek": "ἐρήμωσις", "translit": "erḗmōsis", "pronunciation": "er-ay'-mo-sis", "derivation": "from (G2049);", "definition": "despoliation", "kjv": "desolation."}, "G2051": {"greek": "ἐρίζω", "translit": "erízō", "pronunciation": "er-id'-zo", "derivation": "from (G2054);", "definition": "to wrangle", "kjv": "strive."}, "G2052": {"greek": "ἐριθεία", "translit": "eritheía", "pronunciation": "er-ith-i'-ah", "derivation": "perhaps as the same as (G2042);", "definition": "properly, intrigue, i.e. (by implication) faction", "kjv": "contention(-ious), strife."}, "G2053": {"greek": "ἔριον", "translit": "érion", "pronunciation": "er'-ee-on", "derivation": "of obscure affinity;", "definition": "wool", "kjv": "wool."}, "G2054": {"greek": "ἔρις", "translit": "éris", "pronunciation": "er'-is", "derivation": "of uncertain affinity;", "definition": "a quarrel, i.e. (by implication) wrangling", "kjv": "contention, debate, strife, variance."}, "G2055": {"greek": "ἐρίφιον", "translit": "eríphion", "pronunciation": "er-if'-ee-on", "derivation": "from (G2056);", "definition": "a kidling, i.e. (genitive case) goat (symbolically, wicked person)", "kjv": "goat."}, "G2056": {"greek": "ἔριφος", "translit": "ériphos", "pronunciation": "er'-if-os", "derivation": "perhaps from the same as (G2053) (through the idea of hairiness);", "definition": "a kid or (genitive case) goat", "kjv": "goat, kid."}, "G2058": {"greek": "ἑρμηνεία", "translit": "hermēneía", "pronunciation": "her-may-ni'-ah", "derivation": "from the same as (G2059);", "definition": "translation", "kjv": "interpretation."}, "G2059": {"greek": "ἑρμηνεύω", "translit": "hermēneúō", "pronunciation": "her-mayn-yoo'-o", "derivation": "from a presumed derivative of (G2060) (as the god of language);", "definition": "to translate", "kjv": "interpret."}, "G2060": {"greek": "Ἑρμῆς", "translit": "Hermēs", "pronunciation": "her-mace'", "derivation": "perhaps from (G2046);", "definition": "Hermes, the name of the messenger of the Greek deities; also of a Christian", "kjv": "Hermes, Mercury."}, "G2061": {"greek": "Ἑρμογένης", "translit": "Hermogénēs", "pronunciation": "her-mog-en'-ace", "derivation": "from (G2060) and (G1096);", "definition": "born of Hermes; Hermogenes, an apostate Christian", "kjv": "Hermogenes."}, "G2062": {"greek": "ἑρπετόν", "translit": "herpetón", "pronunciation": "her-pet-on'", "derivation": "neuter of a derivative of (to creep);", "definition": "a reptile, i.e. (by Hebraism (compare (G7431))) a small animal", "kjv": "creeping thing, serpent."}, "G2063": {"greek": "ἐρυθρός", "translit": "erythrós", "pronunciation": "er-oo-thros'", "derivation": "of uncertain affinity;", "definition": "red, i.e. (with (G2281)) the Red Sea", "kjv": "red."}, "G2064": {"greek": "ἔρχομαι", "translit": "érchomai", "pronunciation": "er'-khom-ahee", "derivation": "middle voice of a primary verb (used only in the present and imperfect tenses, the others being supplied by a kindred (middle voice) , or (active) , which do not otherwise occur);", "definition": "to come or go (in a great variety of applications, literally and figuratively)", "kjv": "accompany, appear, bring, come, enter, fall out, go, grow, X light, X next, pass, resort, be set."}, "G2065": {"greek": "ἐρωτάω", "translit": "erōtáō", "pronunciation": "er-o-tah'-o", "derivation": "apparently from (G2046) (compare (G2045));", "definition": "to interrogate; by implication, to request", "kjv": "ask, beseech, desire, intreat, pray."}, "G2066": {"greek": "ἐσθής", "translit": "esthḗs", "pronunciation": "es-thace'", "derivation": "from (to clothe);", "definition": "dress", "kjv": "apparel, clothing, raiment, robe."}, "G2068": {"greek": "ἐσθίω", "translit": "esthíō", "pronunciation": "es-thee'-o", "derivation": "strengthened for a primary (to eat);", "definition": "used only in certain tenses, the rest being supplied by (G5315); to eat (usually literal)", "kjv": "devour, eat, live."}, "G2069": {"greek": "Ἐσλί", "translit": "Eslí", "pronunciation": "es-lee'", "derivation": "of Hebrew origin (probably for (G454));", "definition": "Esli, an Israelite", "kjv": "Esli."}, "G2072": {"greek": "ἔσοπτρον", "translit": "ésoptron", "pronunciation": "es'-op-tron", "derivation": "from (G1519) and a presumed derivative of (G3700);", "definition": "a mirror (for looking into)", "kjv": "glass."}, "G2073": {"greek": "ἑσπέρα", "translit": "hespéra", "pronunciation": "hes-per'-ah", "derivation": "feminine of an adjective hesperos (evening); the eve ((G5610) being implied)", "definition": "", "kjv": "evening(-tide)."}, "G2074": {"greek": "Ἐσρώμ", "translit": "Esrṓm", "pronunciation": "es-rome", "derivation": "of Hebrew origin ((G2696));", "definition": "Esrom (i.e. Chetsron), an Israelite", "kjv": "Esrom."}, "G2078": {"greek": "ἔσχατος", "translit": "éschatos", "pronunciation": "es'-khat-os", "derivation": "a superlative probably from (G2192) (in the sense of contiguity);", "definition": "farthest, final (of place or time)", "kjv": "ends of, last, latter end, lowest, uttermost."}, "G2079": {"greek": "ἐσχάτως", "translit": "eschátōs", "pronunciation": "es-khat'-oce", "derivation": "adverb from (G2078);", "definition": "finally, i.e. (with (G2192)) at the extremity of life", "kjv": "point of death."}, "G2080": {"greek": "ἔσω", "translit": "ésō", "pronunciation": "es'-o", "derivation": "from (G1519);", "definition": "inside (as preposition or adjective)", "kjv": "(with-)in(-ner, -to, -ward)."}, "G2081": {"greek": "ἔσωθεν", "translit": "ésōthen", "pronunciation": "es'-o-then", "derivation": "from (G2080);", "definition": "from inside; also used as equivalent to (G2080) (inside)", "kjv": "inward(-ly), (from) within, without."}, "G2082": {"greek": "ἐσώτερος", "translit": "esṓteros", "pronunciation": "es-o'-ter-os", "derivation": "comparative of (G2080);", "definition": "interior", "kjv": "inner, within."}, "G2083": {"greek": "ἑταῖρος", "translit": "hetaîros", "pronunciation": "het-ah'-ee-ros", "derivation": "from (a clansman);", "definition": "a comrade", "kjv": "fellow, friend."}, "G2084": {"greek": "ἑτερόγλωσσος", "translit": "heteróglōssos", "pronunciation": "het-er-og'-loce-sos", "derivation": "from (G2087) and (G1100);", "definition": "other- tongued, i.e. a foreigner", "kjv": "man of other tongue."}, "G2085": {"greek": "ἑτεροδιδασκαλέω", "translit": "heterodidaskaléō", "pronunciation": "het-er-od-id-as-kal-eh'-o", "derivation": "from (G2087) and (G1320);", "definition": "to instruct differently", "kjv": "teach other doctrine(-wise)."}, "G2086": {"greek": "ἑτεροζυγέω", "translit": "heterozygéō", "pronunciation": "het-er-od-zoog-eh'-o", "derivation": "from a compound of (G2087) and (G2218);", "definition": "to yoke up differently, i.e. (figuratively) to associate discordantly", "kjv": "unequally yoke together with."}, "G2087": {"greek": "ἕτερος", "translit": "héteros", "pronunciation": "het'-er-os", "derivation": "of uncertain affinity;", "definition": "(an-, the) other or different", "kjv": "altered, else, next (day), one, (an-)other, some, strange."}, "G2088": {"greek": "ἑτέρως", "translit": "hetérōs", "pronunciation": "het-er'-oce", "derivation": "adverb from (G2087);", "definition": "differently", "kjv": "otherwise."}, "G2089": {"greek": "ἔτι", "translit": "éti", "pronunciation": "et'-ee", "derivation": "perhaps akin to (G2094);", "definition": "\"yet,\" still (of time or degree)", "kjv": "after that, also, ever, (any) further, (t-)henceforth (more), hereafter, (any) longer, (any) more(-one), now, still, yet."}, "G2090": {"greek": "ἑτοιμάζω", "translit": "hetoimázō", "pronunciation": "het-oy-mad'-zo", "derivation": "from (G2092);", "definition": "to prepare", "kjv": "prepare, provide, make ready."}, "G2091": {"greek": "ἑτοιμασία", "translit": "hetoimasía", "pronunciation": "het-oy-mas-ee'-ah", "derivation": "from (G2090);", "definition": "preparation", "kjv": "preparation."}, "G2092": {"greek": "ἕτοιμος", "translit": "hétoimos", "pronunciation": "het-oy'-mos", "derivation": "from an old noun (fitness);", "definition": "adjusted, i.e. ready", "kjv": "prepared, (made) ready(-iness, to our hand)."}, "G2093": {"greek": "ἑτοίμως", "translit": "hetoímōs", "pronunciation": "het'-oy-moce", "derivation": "adverb from (G2092);", "definition": "in readiness", "kjv": "ready."}, "G2094": {"greek": "ἔτος", "translit": "étos", "pronunciation": "et'-os", "derivation": "apparently a primary word;", "definition": "a year", "kjv": "year."}, "G2095": {"greek": "εὖ", "translit": "eû", "pronunciation": "yoo", "derivation": "neuter of a primary (good);", "definition": "(adverbially) well", "kjv": "good, well (done)."}, "G2096": {"greek": "Εὖα", "translit": "Eûa", "pronunciation": "yoo'-ah", "derivation": "of Hebrew origin ((G2332));", "definition": "Eua (or Eva, i.e. Chavvah), the first woman", "kjv": "Eve."}, "G2097": {"greek": "εὐαγγελίζω", "translit": "euangelízō", "pronunciation": "yoo-ang-ghel-id'-zo", "derivation": "from (G2095) and (G32);", "definition": "to announce good news (\"evangelize\") especially the gospel", "kjv": "declare, bring (declare, show) glad (good) tidings, preach (the gospel)."}, "G2098": {"greek": "εὐαγγέλιον", "translit": "euangélion", "pronunciation": "yoo-ang-ghel'-ee-on", "derivation": "from the same as (G2097);", "definition": "a good message, i.e. the gospel", "kjv": "gospel."}, "G2099": {"greek": "εὐαγγελιστής", "translit": "euangelistḗs", "pronunciation": "yoo-ang-ghel-is-tace'", "derivation": "from (G2097);", "definition": "a preacher of the gospel", "kjv": "evangelist."}, "G2100": {"greek": "εὐαρεστέω", "translit": "euarestéō", "pronunciation": "yoo-ar-es-teh'-o", "derivation": "from (G2101);", "definition": "to gratify entirely", "kjv": "please (well)."}, "G2101": {"greek": "εὐάρεστος", "translit": "euárestos", "pronunciation": "yoo-ar'-es-tos", "derivation": "from (G2095) and (G701);", "definition": "fully agreeable", "kjv": "acceptable(-ted), wellpleasing."}, "G2102": {"greek": "εὐαρέστως", "translit": "euaréstōs", "pronunciation": "yoo-ar-es'-toce", "derivation": "adverb from (G2101);", "definition": "quite agreeably", "kjv": "acceptably, + please well."}, "G2103": {"greek": "Εὔβουλος", "translit": "Eúboulos", "pronunciation": "yoo'-boo-los", "derivation": "from (G2095) and (G1014);", "definition": "good-willer; Eubulus, a Christian", "kjv": "Eubulus."}, "G2104": {"greek": "εὐγενής", "translit": "eugenḗs", "pronunciation": "yoog-en'-ace", "derivation": "from (G2095) and (G1096);", "definition": "well born, i.e. (literally) high in rank, or (figuratively) generous", "kjv": "more noble, nobleman."}, "G2105": {"greek": "εὐδία", "translit": "eudía", "pronunciation": "yoo-dee'-ah", "derivation": "feminine from (G2095) and the alternate of (G2203) (as the god of the weather);", "definition": "a clear sky, i.e. fine weather", "kjv": "fair weather."}, "G2106": {"greek": "εὐδοκέω", "translit": "eudokéō", "pronunciation": "yoo-dok-eh'-o", "derivation": "from (G2095) and (G1380);", "definition": "to think well of, i.e. approve (an act); specially, to approbate (a person or thing)", "kjv": "think good, (be well) please(-d), be the good (have, take) pleasure, be willing."}, "G2107": {"greek": "εὐδοκία", "translit": "eudokía", "pronunciation": "yoo-dok-ee'-ah", "derivation": "from a presumed compound of (G2095) and the base of (G1380);", "definition": "satisfaction, i.e. (subjectively) delight, or (objectively) kindness, wish, purpose", "kjv": "desire, good pleasure (will), X seem good."}, "G2108": {"greek": "εὐεργεσία", "translit": "euergesía", "pronunciation": "yoo-erg-es-ee'-ah", "derivation": "from (G2110);", "definition": "beneficence (genitive case or specially)", "kjv": "benefit, good deed done."}, "G2109": {"greek": "εὐεργετέω", "translit": "euergetéō", "pronunciation": "yoo-erg-et-eh'-o", "derivation": "from (G2110);", "definition": "to be philanthropic", "kjv": "do good."}, "G2110": {"greek": "εὐεργέτης", "translit": "euergétēs", "pronunciation": "yoo-erg-et'-ace", "derivation": "from (G2095) and the base of (G2041);", "definition": "a worker of good, i.e. (specially) a philanthropist", "kjv": "benefactor."}, "G2111": {"greek": "εὔθετος", "translit": "eúthetos", "pronunciation": "yoo'-thet-os", "derivation": "from (G2095) and a derivative of (G5087);", "definition": "well placed, i.e. (figuratively) appropriate", "kjv": "fit, meet."}, "G2112": {"greek": "εὐθέως", "translit": "euthéōs", "pronunciation": "yoo-theh'-oce", "derivation": "adverb from (G2117);", "definition": "directly, i.e. at once or soon", "kjv": "anon, as soon as, forthwith, immediately, shortly, straightway."}, "G2113": {"greek": "εὐθυδρομέω", "translit": "euthydroméō", "pronunciation": "yoo-thoo-drom-eh'-o", "derivation": "from (G2117) and (G1408);", "definition": "to lay a straight course, i.e. sail direct", "kjv": "(come) with a straight course."}, "G2114": {"greek": "εὐθυμέω", "translit": "euthyméō", "pronunciation": "yoo-thoo-meh'-o", "derivation": "from (G2115);", "definition": "to cheer up, i.e. (intransitively) be cheerful; neuter comparative (adverbially) more cheerfully", "kjv": "be of good cheer (merry)."}, "G2115": {"greek": "εὔθυμος", "translit": "eúthymos", "pronunciation": "yoo'-thoo-mos", "derivation": "from (G2095) and (G2372);", "definition": "in fine spirits, i.e. cheerful", "kjv": "of good cheer, the more cheerfully."}, "G2116": {"greek": "εὐθύνω", "translit": "euthýnō", "pronunciation": "yoo-thoo'-no", "derivation": "from (G2117);", "definition": "to straighten (level); technically, to steer", "kjv": "governor, make straight."}, "G2117": {"greek": "εὐθύς", "translit": "euthýs", "pronunciation": "yoo-thoos'", "derivation": "perhaps from (G2095) and (G5087);", "definition": "straight, i.e. (literally) level, or (figuratively) true; adverbially (of time) at once", "kjv": "anon, by and by, forthwith, immediately, straightway."}, "G2118": {"greek": "εὐθύτης", "translit": "euthýtēs", "pronunciation": "yoo-thoo'-tace", "derivation": "from (G2117);", "definition": "rectitude", "kjv": "righteousness."}, "G2119": {"greek": "εὐκαιρέω", "translit": "eukairéō", "pronunciation": "yoo-kahee-reh'-o", "derivation": "from (G2121);", "definition": "to have good time, i.e. opportunity or leisure", "kjv": "have leisure (convenient time), spend time."}, "G2120": {"greek": "εὐκαιρία", "translit": "eukairía", "pronunciation": "yoo-kahee-ree'-ah", "derivation": "from (G2121);", "definition": "a favorable occasion", "kjv": "opportunity."}, "G2121": {"greek": "εὔκαιρος", "translit": "eúkairos", "pronunciation": "yoo'-kahee-ros", "derivation": "from (G2095) and (G2540);", "definition": "well-timed, i.e. opportune", "kjv": "convenient, in time of need."}, "G2122": {"greek": "εὐκαίρως", "translit": "eukaírōs", "pronunciation": "yoo-kah'-ee-roce", "derivation": "adverb from (G2121);", "definition": "opportunely", "kjv": "conveniently, in season."}, "G2123": {"greek": "εὐκοπώτερος", "translit": "eukopṓteros", "pronunciation": "yoo-kop-o'-ter-os", "derivation": "comparative of a compound of (G2095) and (G2873);", "definition": "better for toil, i.e. more facile", "kjv": "easier."}, "G2124": {"greek": "εὐλάβεια", "translit": "eulábeia", "pronunciation": "yoo-lab'-i-ah", "derivation": "from (G2126);", "definition": "properly, caution, i.e. (religiously) reverence (piety); by implication, dread (concretely)", "kjv": "fear(-ed)."}, "G2125": {"greek": "εὐλαβέομαι", "translit": "eulabéomai", "pronunciation": "yoo-lab-eh'-om-ahee", "derivation": "middle voice from (G2126);", "definition": "to be circumspect, i.e. (by implication) to be apprehensive; religiously, to reverence", "kjv": "(moved with) fear."}, "G2126": {"greek": "εὐλαβής", "translit": "eulabḗs", "pronunciation": "yoo-lab-ace'", "derivation": "from (G2095) and (G2983);", "definition": "taking well (carefully), i.e. circumspect (religiously, pious)", "kjv": "devout."}, "G2127": {"greek": "εὐλογέω", "translit": "eulogéō", "pronunciation": "yoo-log-eh'-o", "derivation": "from a compound of (G2095) and (G3056);", "definition": "to speak well of, i.e. (religiously) to bless (thank or invoke a benediction upon, prosper)", "kjv": "bless, praise."}, "G2128": {"greek": "εὐλογητός", "translit": "eulogētós", "pronunciation": "yoo-log-ay-tos'", "derivation": "from (G2127);", "definition": "adorable", "kjv": "blessed."}, "G2129": {"greek": "εὐλογία", "translit": "eulogía", "pronunciation": "yoo-log-ee'-ah", "derivation": "from the same as (G2127);", "definition": "fine speaking, i.e. elegance of language; commendation (\"eulogy\"), i.e. (reverentially) adoration; religiously, benediction; by implication, consecration; by extension, benefit or largess", "kjv": "blessing (a matter of) bounty (X -tifully), fair speech."}, "G2130": {"greek": "εὐμετάδοτος", "translit": "eumetádotos", "pronunciation": "yoo-met-ad'-ot-os", "derivation": "from (G2095) and a presumed derivative of (G3330);", "definition": "good at imparting, i.e. liberal", "kjv": "ready to distribute."}, "G2131": {"greek": "Εὐνίκη", "translit": "Euníkē", "pronunciation": "yoo-nee'-kay", "derivation": "from (G2095) and (G3529);", "definition": "victorious; Eunice, a Jewess", "kjv": "Eunice."}, "G2132": {"greek": "εὐνοέω", "translit": "eunoéō", "pronunciation": "yoo-no-eh'-o", "derivation": "from a compound of (G2095) and (G3563);", "definition": "to be well- minded, i.e. reconcile", "kjv": "agree."}, "G2133": {"greek": "εὔνοια", "translit": "eúnoia", "pronunciation": "yoo'-noy-ah", "derivation": "from the same as (G2132);", "definition": "kindness; euphemistically, conjugal duty", "kjv": "benevolence, good will."}, "G2134": {"greek": "εὐνουχίζω", "translit": "eunouchízō", "pronunciation": "yoo-noo-khid'-zo", "derivation": "from (G2135);", "definition": "to castrate (figuratively, live unmarried)", "kjv": "make…eunuch."}, "G2135": {"greek": "εὐνοῦχος", "translit": "eunoûchos", "pronunciation": "yoo-noo'-khos", "derivation": "from (a bed) and (G2192);", "definition": "a castrated person (such being employed in Oriental bed-chambers); by extension an impotent or unmarried man; by implication, a chamberlain (state-officer)", "kjv": "eunuch."}, "G2136": {"greek": "Εὐοδία", "translit": "Euodía", "pronunciation": "yoo-od-ee'-ah", "derivation": "from the same as (G2137);", "definition": "fine travelling; Euodia, a Christian woman", "kjv": "Euodias."}, "G2137": {"greek": "εὐοδόω", "translit": "euodóō", "pronunciation": "yoo-od-o'-o", "derivation": "from a compound of (G2095) and (G3598);", "definition": "to help on the road, i.e. (passively) succeed in reaching; figuratively, to succeed in business affairs", "kjv": "(have a) prosper(-ous journey)."}, "G2138": {"greek": "εὐπειθής", "translit": "eupeithḗs", "pronunciation": "yoo-pi-thace'", "derivation": "from (G2095) and (G3982);", "definition": "good for persuasion, i.e. (intransitively) complaint", "kjv": "easy to be intreated."}, "G2139": {"greek": "εὐπερίστατος", "translit": "euperístatos", "pronunciation": "yoo-per-is'-tat-os", "derivation": "from (G2095) and a derivative of a presumed compound of (G4012) and (G2476);", "definition": "well standing around, i.e. (a competitor) thwarting (a racer) in every direction (figuratively, of sin in genitive case)", "kjv": "which doth so easily beset."}, "G2140": {"greek": "εὐποιΐα", "translit": "eupoiḯa", "pronunciation": "yoo-poy-ee'-ah", "derivation": "from a compound of (G2095) and (G4160);", "definition": "well-doing, i.e. beneficence", "kjv": "to do good."}, "G2141": {"greek": "εὐπορέω", "translit": "euporéō", "pronunciation": "yoo-por-eh'-o", "derivation": "from a compound of (G2090) and the base of (G4197);", "definition": "(intransitively) to be good for passing through, i.e. (figuratively) have pecuniary means", "kjv": "ability."}, "G2142": {"greek": "εὐπορία", "translit": "euporía", "pronunciation": "yoo-por-ee'-ah", "derivation": "from the same as (G2141);", "definition": "pecuniary resources", "kjv": "wealth."}, "G2143": {"greek": "εὐπρέπεια", "translit": "euprépeia", "pronunciation": "yoo-prep'-i-ah", "derivation": "from a compound of (G2095) and (G4241);", "definition": "good suitableness, i.e. gracefulness", "kjv": "grace."}, "G2144": {"greek": "εὐπρόσδεκτος", "translit": "euprósdektos", "pronunciation": "yoo-pros'-dek-tos", "derivation": "from (G2095) and a derivative of (G4327);", "definition": "well-received, i.e. approved, favorable", "kjv": "acceptable(-ted)."}, "G2145": {"greek": "εὐπρόσεδρος", "translit": "euprósedros", "pronunciation": "yoo-pros'-ed-ros", "derivation": "from (G2095) and the same as (G4332);", "definition": "sitting well towards, i.e. (figuratively) assiduous (neuter, diligent service)", "kjv": "X attend upon."}, "G2146": {"greek": "εὐπροσωπέω", "translit": "euprosōpéō", "pronunciation": "yoo-pros-o-peh'-o", "derivation": "from a compound of (G2095) and (G4383);", "definition": "to be of good countenance, i.e. (figuratively) to make a display", "kjv": "make a fair show."}, "G2147": {"greek": "εὑρίσκω", "translit": "heurískō", "pronunciation": "hyoo-ris'-ko", "derivation": "a prolonged form of a primary , which (together with another cognate form) is used for it in all the tenses except the present and imperfect;", "definition": "to find (literally or figuratively)", "kjv": "find, get, obtain, perceive, see."}, "G2148": {"greek": "Εὐροκλύδων", "translit": "Euroklýdōn", "pronunciation": "yoo-rok-loo'-dohn", "derivation": "from (the east wind) and (G2830);", "definition": "a storm from the East (or southeast), i.e. (in modern phrase) a Levanter", "kjv": "Euroklydon."}, "G2149": {"greek": "εὐρύχωρος", "translit": "eurýchōros", "pronunciation": "yoo-roo'-kho-ros", "derivation": "from (wide) and (G5561);", "definition": "spacious", "kjv": "broad."}, "G2150": {"greek": "εὐσέβεια", "translit": "eusébeia", "pronunciation": "yoo-seb'-i-ah", "derivation": "from (G2152);", "definition": "piety; specially, the gospel scheme", "kjv": "godliness, holiness."}, "G2151": {"greek": "εὐσεβέω", "translit": "eusebéō", "pronunciation": "yoo-seb-eh'-o", "derivation": "from (G2152);", "definition": "to be pious, i.e. (towards God) to worship, or (towards parents) to respect (support)", "kjv": "show piety, worship."}, "G2152": {"greek": "εὐσεβής", "translit": "eusebḗs", "pronunciation": "yoo-seb-ace'", "derivation": "from (G2095) and (G4576);", "definition": "well-reverent, i.e. pious", "kjv": "devout, godly."}, "G2153": {"greek": "εὐσεβῶς", "translit": "eusebōs", "pronunciation": "yoo-seb-oce'", "derivation": "adverb from (G2152);", "definition": "piously", "kjv": "godly."}, "G2154": {"greek": "εὔσημος", "translit": "eúsēmos", "pronunciation": "yoo'-say-mos", "derivation": "from (G2095) and the base of (G4591);", "definition": "well indicated, i.e. (figuratively) significant", "kjv": "easy to be understood."}, "G2155": {"greek": "εὔσπλαγχνος", "translit": "eúsplanchnos", "pronunciation": "yoo'-splangkh-nos", "derivation": "from (G2095) and (G4698);", "definition": "well compassioned, i.e. sympathetic", "kjv": "pitiful, tender-hearted."}, "G2156": {"greek": "εὐσχημόνως", "translit": "euschēmónōs", "pronunciation": "yoo-skhay-mon'-ose", "derivation": "adverb from (G2158);", "definition": "decorously", "kjv": "decently, honestly."}, "G2157": {"greek": "εὐσχημοσύνη", "translit": "euschēmosýnē", "pronunciation": "yoo-skhay-mos-oo'-nay", "derivation": "from (G2158);", "definition": "decorousness", "kjv": "comeliness."}, "G2158": {"greek": "εὐσχήμων", "translit": "euschḗmōn", "pronunciation": "yoo-skhay'-mone", "derivation": "from (G2095) and (G4976);", "definition": "well-formed, i.e. (figuratively) decorous, noble (in rank)", "kjv": "comely, honourable."}, "G2159": {"greek": "εὐτόνως", "translit": "eutónōs", "pronunciation": "yoo-ton'-oce", "derivation": "adverb from a compound of (G2095) and a derivative of (to stretch);", "definition": "in a well-strung manner, i.e. (figuratively) intensely (in a good sense, cogently; in a bad one, fiercely)", "kjv": "mightily, vehemently."}, "G2160": {"greek": "εὐτραπελία", "translit": "eutrapelía", "pronunciation": "yoo-trap-el-ee'-ah", "derivation": "from a compound of (G2095) and a derivative of the base of (G5157) (meaning well-turned, i.e. ready at repartee, jocose);", "definition": "witticism, i.e. (in a vulgar sense) ribaldry", "kjv": "jesting."}, "G2161": {"greek": "Εὔτυχος", "translit": "Eútychos", "pronunciation": "yoo'-too-khos", "derivation": "from (G2095) and a derivative of (G5177);", "definition": "well- fated, i.e. fortunate; Eutychus, a young man", "kjv": "Eutychus."}, "G2162": {"greek": "εὐφημία", "translit": "euphēmía", "pronunciation": "yoo-fay-mee'-ah", "derivation": "from (G2163);", "definition": "good language (\"euphemy\"), i.e. praise (repute)", "kjv": "good report."}, "G2163": {"greek": "εὔφημος", "translit": "eúphēmos", "pronunciation": "yoo'-fay-mos", "derivation": "from (G2095) and (G5345);", "definition": "well spoken of, i.e. reputable", "kjv": "of good report."}, "G2164": {"greek": "εὐφορέω", "translit": "euphoréō", "pronunciation": "yoo-for-eh'-o", "derivation": "from (G2095) and (G5409);", "definition": "to bear well, i.e. be fertile", "kjv": "bring forth abundantly."}, "G2165": {"greek": "εὐφραίνω", "translit": "euphraínō", "pronunciation": "yoo-frah'-ee-no", "derivation": "from (G2095) and (G5424);", "definition": "to put (middle voice or passively, be) in a good frame of mind, i.e. rejoice", "kjv": "fare, make glad, be (make) merry, rejoice."}, "G2166": {"greek": "Εὐφράτης", "translit": "Euphrátēs", "pronunciation": "yoo-frat'-ace", "derivation": "of foreign origin (compare (G6578));", "definition": "Euphrates, a river of Asia", "kjv": "Euphrates."}, "G2167": {"greek": "εὐφροσύνη", "translit": "euphrosýnē", "pronunciation": "yoo-fros-oo'-nay", "derivation": "from the same as (G2165);", "definition": "joyfulness", "kjv": "gladness, joy."}, "G2168": {"greek": "εὐχαριστέω", "translit": "eucharistéō", "pronunciation": "yoo-khar-is-teh'-o", "derivation": "from (G2170);", "definition": "to be grateful, i.e. (actively) to express gratitude (towards); specially, to say grace at a meal", "kjv": "(give) thank(-ful, -s)."}, "G2169": {"greek": "εὐχαριστία", "translit": "eucharistía", "pronunciation": "yoo-khar-is-tee'-ah", "derivation": "from (G2170);", "definition": "gratitude; actively, grateful language (to God, as an act of worship)", "kjv": "thankfulness, (giving of) thanks(-giving)."}, "G2170": {"greek": "εὐχάριστος", "translit": "eucháristos", "pronunciation": "yoo-khar'-is-tos", "derivation": "from (G2095) and a derivative of (G5483);", "definition": "well favored, i.e. (by implication) grateful", "kjv": "thankful."}, "G2171": {"greek": "εὐχή", "translit": "euchḗ", "pronunciation": "yoo-khay'", "derivation": "from (G2172);", "definition": "properly, a wish, expressed as a petition to God, or in votive obligation", "kjv": "prayer, vow."}, "G2172": {"greek": "εὔχομαι", "translit": "eúchomai", "pronunciation": "yoo'-khom-ahee", "derivation": "middle voice of a primary verb;", "definition": "to wish; by implication, to pray to God", "kjv": "pray, will, wish."}, "G2173": {"greek": "εὔχρηστος", "translit": "eúchrēstos", "pronunciation": "yoo'-khrays-tos", "derivation": "from (G2095) and (G5543);", "definition": "easily used, i.e. useful", "kjv": "profitable, meet for use."}, "G2174": {"greek": "εὐψυχέω", "translit": "eupsychéō", "pronunciation": "yoo-psoo-kheh'-o", "derivation": "from a compound of (G2095) and (G5590);", "definition": "to be in good spirits, i.e. feel encouraged", "kjv": "be of good comfort."}, "G2175": {"greek": "εὐωδία", "translit": "euōdía", "pronunciation": "yoo-o-dee'-ah", "derivation": "from a compound of (G2095) and a derivative of (G3605);", "definition": "good-scentedness, i.e. fragrance", "kjv": "sweet savour (smell, -smelling)."}, "G2176": {"greek": "εὐώνυμος", "translit": "euṓnymos", "pronunciation": "yoo-o'-noo-mos", "derivation": "from (G2095) and (G3686);", "definition": "properly, well-named (good-omened), i.e. the left (which was the lucky side among the pagan Greeks); neuter as adverbial, at the left hand", "kjv": "(on the) left."}, "G2177": {"greek": "ἐφάλλομαι", "translit": "ephállomai", "pronunciation": "ef-al'-lom-ahee", "derivation": "from (G1909) and (G242);", "definition": "to spring upon", "kjv": "leap on."}, "G2178": {"greek": "ἐφάπαξ", "translit": "ephápax", "pronunciation": "ef-ap'-ax", "derivation": "from (G1909) and (G530);", "definition": "upon one occasion (only)", "kjv": "(at) once (for all)."}, "G2180": {"greek": "Ἐφέσιος", "translit": "Ephésios", "pronunciation": "ef-es'-ee-os", "derivation": "from (G2181);", "definition": "an Ephesian or inhabitant of Ephesus", "kjv": "Ephesian, of Ephesus."}, "G2181": {"greek": "Ἔφεσος", "translit": "Éphesos", "pronunciation": "ef'-es-os", "derivation": "probably of foreign origin;", "definition": "Ephesus, a city of Asia Minor", "kjv": "Ephesus."}, "G2182": {"greek": "ἐφευρετής", "translit": "epheuretḗs", "pronunciation": "ef-yoo-ret'-ace", "derivation": "from a compound of (G1909) and (G2147);", "definition": "a discoverer, i.e. contriver", "kjv": "inventor."}, "G2183": {"greek": "ἐφημερία", "translit": "ephēmería", "pronunciation": "ef-ay-mer-ee'-ah", "derivation": "from (G2184);", "definition": "diurnality, i.e. (specially) the quotidian rotation or class of the Jewish priests' service at the Temple, as distributed by families", "kjv": "course."}, "G2184": {"greek": "ἐφήμερος", "translit": "ephḗmeros", "pronunciation": "ef-ay'-mer-os", "derivation": "from (G1909) and (G2250);", "definition": "for a day (\"ephemeral\"), i.e. diurnal", "kjv": "daily."}, "G2185": {"greek": "ἐφικνέομαι", "translit": "ephiknéomai", "pronunciation": "ef-ik-neh'-om-ahee", "derivation": "from (G1909) and a cognate of (G2240);", "definition": "to arrive upon, i.e. extend to", "kjv": "reach."}, "G2186": {"greek": "ἐφίστημι", "translit": "ephístēmi", "pronunciation": "ef-is'-tay-mee", "derivation": "from (G1909) and (G2476);", "definition": "to stand upon, i.e. be present (in various applications, friendly or otherwise, usually literal);", "kjv": "assault, come (in, to, unto, upon), be at hand (instant), present, stand (before, by, over)."}, "G2187": {"greek": "Ἐφραίμ", "translit": "Ephraím", "pronunciation": "ef-rah-im'", "derivation": "of Hebrew origin ((G669) or better (G6085));", "definition": "Ephraim, a place in Palestine", "kjv": "Ephraim."}, "G2188": {"greek": "ἐφφαθά", "translit": "ephphathá", "pronunciation": "ef-fath-ah'", "derivation": "of Chaldee origin ((G6606));", "definition": "be opened!", "kjv": "Ephphatha."}, "G2189": {"greek": "ἔχθρα", "translit": "échthra", "pronunciation": "ekh'-thrah", "derivation": "feminine of (G2190);", "definition": "hostility; by implication, a reason for opposition", "kjv": "enmity, hatred."}, "G2190": {"greek": "ἐχθρός", "translit": "echthrós", "pronunciation": "ech-thros'", "derivation": "from a primary (to hate);", "definition": "hateful (passively, odious, or actively, hostile); usually as a noun, an adversary (especially Satan)", "kjv": "enemy, foe."}, "G2191": {"greek": "ἔχιδνα", "translit": "échidna", "pronunciation": "ekh'-id-nah", "derivation": "of uncertain origin;", "definition": "an adder or other poisonous snake (literally or figuratively)", "kjv": "viper."}, "G2192": {"greek": "ἔχω", "translit": "échō", "pronunciation": "ekh'-o", "derivation": "a primary verb;", "definition": "to hold (used in very various applications, literally or figuratively, direct or remote; such as possession; ability, contiuity, relation, or condition)", "kjv": "be (able, X hold, possessed with), accompany, + begin to amend, can(+ -not), X conceive, count, diseased, do + eat, + enjoy, + fear, following, have, hold, keep, + lack, + go to law, lie, + must needs, + of necessity, + need, next, + recover, + reign, + rest, + return, X sick, take for, + tremble, + uncircumcised, use."}, "G2193": {"greek": "ἕως", "translit": "héōs", "pronunciation": "heh'-oce", "derivation": "of uncertain affinity;", "definition": "a conjunction, preposition and adverb of continuance, until (of time and place)", "kjv": "even (until, unto), (as) far (as), how long, (un-)til(-l), (hither-, un-, up) to, while(-s)."}, "G2194": {"greek": "Ζαβουλών", "translit": "Zaboulṓn", "pronunciation": "dzab-oo-lone'", "derivation": "of Hebrew origin ((G2074));", "definition": "Zabulon (i.e. Zebulon), a region of Palestine", "kjv": "Zabulon."}, "G2195": {"greek": "Ζακχαῖος", "translit": "Zakchaîos", "pronunciation": "dzak-chah'-ee-yos", "derivation": "of Hebrew origin (compare (G2140));", "definition": "Zacchæus, an Israelite", "kjv": "Zacchæus."}, "G2196": {"greek": "Ζαρά", "translit": "Zará", "pronunciation": "dzar-ah'", "derivation": "of Hebrew origin ((G2226));", "definition": "Zara, (i.e. Zerach), an Israelite", "kjv": "Zara."}, "G2197": {"greek": "Ζαχαρίας", "translit": "Zacharías", "pronunciation": "dzakh-ar-ee'-as", "derivation": "of Hebrew origin ((G2148));", "definition": "Zacharias (i.e. Zechariah), the name of two Israelites", "kjv": "Zacharias."}, "G2198": {"greek": "ζάω", "translit": "záō", "pronunciation": "dzah'-o", "derivation": "a primary verb;", "definition": "to live (literally or figuratively)", "kjv": "life(-time), (a-)live(-ly), quick."}, "G2199": {"greek": "Ζεβεδαῖος", "translit": "Zebedaîos", "pronunciation": "dzeb-ed-ah'-yos", "derivation": "of Hebrew origin (compare (G2067));", "definition": "Zebedæus, an Israelite", "kjv": "Zebedee."}, "G2200": {"greek": "ζεστός", "translit": "zestós", "pronunciation": "dzes-tos'", "derivation": "from (G2204);", "definition": "boiled, i.e. (by implication) calid (figuratively, fervent)", "kjv": "hot."}, "G2201": {"greek": "ζεῦγος", "translit": "zeûgos", "pronunciation": "dzyoo'-gos", "derivation": "from the same as (G2218);", "definition": "a couple, i.e. a team (of oxen yoked together) or brace (of birds tied together)", "kjv": "yoke, pair."}, "G2202": {"greek": "ζευκτηρία", "translit": "zeuktēría", "pronunciation": "dzook-tay-ree'-ah", "derivation": "feminine of a derivative (at the second stage) from the same as (G2218);", "definition": "a fastening (tiller-rope)", "kjv": "band."}, "G2203": {"greek": "Ζεύς", "translit": "Zeús", "pronunciation": "dzyooce", "derivation": "of uncertain affinity;", "definition": "in the oblique cases there is used instead of it a (probably cognate) name , which is otherwise obsolete; Zeus or Dis (among the Latins, Jupiter or Jove), the supreme deity of the Greeks", "kjv": "Jupiter."}, "G2204": {"greek": "ζέω", "translit": "zéō", "pronunciation": "dzeh'-o", "derivation": "a primary verb;", "definition": "to be hot (boil, of liquids; or glow, of solids), i.e. (figuratively) be fervid (earnest)", "kjv": "be fervent."}, "G2205": {"greek": "ζῆλος", "translit": "zēlos", "pronunciation": "dzay'-los", "derivation": "from (G2204);", "definition": "properly, heat, i.e. (figuratively) \"zeal\" (in a favorable sense, ardor; in an unfavorable one, jealousy, as of a husband (figuratively, of God), or an enemy, malice)", "kjv": "emulation, envy(-ing), fervent mind, indignation, jealousy, zeal."}, "G2206": {"greek": "ζηλόω", "translit": "zēlóō", "pronunciation": "dzay-lo'-o", "derivation": "from (G2205);", "definition": "to have warmth of feeling for or against", "kjv": "affect, covet (earnestly), (have) desire, (move with) envy, be jealous over, (be) zealous(-ly affect)."}, "G2207": {"greek": "ζηλωτής", "translit": "zēlōtḗs", "pronunciation": "dzay-lo-tace'", "derivation": "from (G2206);", "definition": "a \"zealot\"", "kjv": "zealous."}, "G2209": {"greek": "ζημία", "translit": "zēmía", "pronunciation": "dzay-mee'-ah", "derivation": "probably akin to the base of (G1150) (through the idea of violence);", "definition": "detriment", "kjv": "damage, loss."}, "G2210": {"greek": "ζημιόω", "translit": "zēmióō", "pronunciation": "dzay-mee-o'-o", "derivation": "from (G2209);", "definition": "to injure, i.e. (reflexively or passively) to experience detriment", "kjv": "be cast away, receive damage, lose, suffer loss."}, "G2211": {"greek": "Ζηνᾶς", "translit": "Zēnâs", "pronunciation": "dzay-nas'", "derivation": "probably contracted from a poetic form of (G2203) and (G1435);", "definition": "Jove-given; Zenas, a Christian", "kjv": "Zenas."}, "G2212": {"greek": "ζητέω", "translit": "zētéō", "pronunciation": "dzay-teh'-o", "derivation": "of uncertain affinity;", "definition": "to seek (literally or figuratively); specially, (by Hebraism) to worship (God), or (in a bad sense) to plot (against life)", "kjv": "be (go) about, desire, endeavour, enquire (for), require, (X will) seek (after, for, means)."}, "G2213": {"greek": "ζήτημα", "translit": "zḗtēma", "pronunciation": "dzay'-tay-mah", "derivation": "from (G2212);", "definition": "a search (properly concretely), i.e. (in words) a debate", "kjv": "question."}, "G2214": {"greek": "ζήτησις", "translit": "zḗtēsis", "pronunciation": "dzay'-tay-sis", "derivation": "from (G2212);", "definition": "a searching (properly, the act), i.e. a dispute or its theme", "kjv": "question."}, "G2215": {"greek": "ζιζάνιον", "translit": "zizánion", "pronunciation": "dziz-an'-ee-on", "derivation": "of uncertain origin;", "definition": "darnel or false grain", "kjv": "tares."}, "G2216": {"greek": "Ζοροβάβελ", "translit": "Zorobábel", "pronunciation": "dzor-ob-ab'-el", "derivation": "of Hebrew origin ((G2216));", "definition": "Zorobabel (i.e. Zerubbabel), an Israelite", "kjv": "Zorobabel."}, "G2217": {"greek": "ζόφος", "translit": "zóphos", "pronunciation": "dzof'-os", "derivation": "akin to the base of (G3509);", "definition": "gloom (as shrouding like a cloud)", "kjv": "blackness, darkness, mist."}, "G2218": {"greek": "ζυγός", "translit": "zygós", "pronunciation": "dzoo-gos'", "derivation": "from the root of (to join, especially by a \"yoke\");", "definition": "a coupling, i.e. (figuratively) servitude (a law or obligation); also (literally) the beam of the balance (as connecting the scales)", "kjv": "pair of balances, yoke."}, "G2219": {"greek": "ζύμη", "translit": "zýmē", "pronunciation": "dzoo'-may", "derivation": "probably from (G2204);", "definition": "ferment (as if boiling up)", "kjv": "leaven."}, "G2220": {"greek": "ζυμόω", "translit": "zymóō", "pronunciation": "dzoo-mo'-o", "derivation": "from (G2219);", "definition": "to cause to ferment", "kjv": "leaven."}, "G2221": {"greek": "ζωγρέω", "translit": "zōgréō", "pronunciation": "dzogue-reh'-o", "derivation": "from the same as (G2226) and (G64);", "definition": "to take alive (make a prisoner of war), i.e. (figuratively) to capture or ensnare", "kjv": "take captive, catch."}, "G2222": {"greek": "ζωή", "translit": "zōḗ", "pronunciation": "dzo-ay'", "derivation": "from (G2198);", "definition": "life (literally or figuratively)", "kjv": "life(-time)."}, "G2223": {"greek": "ζώνη", "translit": "zṓnē", "pronunciation": "dzo'-nay", "derivation": "probably akin to the base of (G2218);", "definition": "a belt; by implication, a pocket", "kjv": "girdle, purse."}, "G2224": {"greek": "ζώννυμι", "translit": "zṓnnymi", "pronunciation": "dzone'-noo-mi", "derivation": "from (G2223);", "definition": "to bind about (especially with a belt)", "kjv": "gird."}, "G2225": {"greek": "ζωογονέω", "translit": "zōogonéō", "pronunciation": "dzo-og-on-eh'-o", "derivation": "from the same as (G2226) and a derivative of (G1096);", "definition": "to engender alive, i.e. (by analogy) to rescue (passively, be saved) from death", "kjv": "live, preserve."}, "G2226": {"greek": "ζῶον", "translit": "zōon", "pronunciation": "dzo'-on", "derivation": "neuter of a derivative of (G2198);", "definition": "a live thing, i.e. an animal", "kjv": "beast."}, "G2227": {"greek": "ζωοποιέω", "translit": "zōopoiéō", "pronunciation": "dzo-op-oy-eh'-o", "derivation": "from the same as (G2226) and (G4160);", "definition": "to (re-)vitalize (literally or figuratively)", "kjv": "make alive, give life, quicken."}, "G2228": {"greek": "ἤ", "translit": "ḗ", "pronunciation": "ay", "derivation": "a primary particle of distinction between two connected terms;", "definition": "disjunctive, or; comparative, than", "kjv": "and, but (either), (n-)either, except it be, (n-)or (else), rather, save, than, that, what, yea."}, "G2230": {"greek": "ἡγεμονεύω", "translit": "hēgemoneúō", "pronunciation": "hayg-em-on-yoo'-o", "derivation": "from (G2232);", "definition": "to act as ruler", "kjv": "be governor."}, "G2231": {"greek": "ἡγεμονία", "translit": "hēgemonía", "pronunciation": "hayg-em-on-ee'-ah", "derivation": "from (G2232);", "definition": "government, i.e. (in time) official term", "kjv": "reign."}, "G2232": {"greek": "ἡγεμών", "translit": "hēgemṓn", "pronunciation": "hayg-em-ohn'", "derivation": "from (G2233);", "definition": "a leader, i.e. chief person (or figuratively, place) of a province", "kjv": "governor, prince, ruler."}, "G2233": {"greek": "ἡγέομαι", "translit": "hēgéomai", "pronunciation": "hayg-eh'-om-ahee", "derivation": "middle voice of a (presumed) strengthened form of (G71);", "definition": "to lead, i.e. command (with official authority); figuratively, to deem, i.e. consider", "kjv": "account, (be) chief, count, esteem, governor, judge, have the rule over, suppose, think."}, "G2234": {"greek": "ἡδέως", "translit": "hēdéōs", "pronunciation": "hay-deh'-oce", "derivation": "adverb from a derivative of the base of (G2237);", "definition": "sweetly, i.e. (figuratively) with pleasure", "kjv": "gladly."}, "G2235": {"greek": "ἤδη", "translit": "ḗdē", "pronunciation": "ay'-day", "derivation": "apparently from (G2228) (or possibly (G2229)) and (G1211);", "definition": "even now", "kjv": "already, (even) now (already), by this time."}, "G2236": {"greek": "ἥδιστα", "translit": "hḗdista", "pronunciation": "hay'-dis-tah", "derivation": "neuter plural of the superlative of the same as (G2234);", "definition": "with great pleasure", "kjv": "most (very) gladly."}, "G2237": {"greek": "ἡδονή", "translit": "hēdonḗ", "pronunciation": "hay-don-ay'", "derivation": "from (to please);", "definition": "sensual delight; by implication, desire", "kjv": "lust, pleasure."}, "G2238": {"greek": "ἡδύοσμον", "translit": "hēdýosmon", "pronunciation": "hay-doo'-os-mon", "derivation": "neuter of the compound of the same as (G2234) and (G3744);", "definition": "a sweet-scented plant, i.e. mint", "kjv": "mint."}, "G2239": {"greek": "ἦθος", "translit": "ēthos", "pronunciation": "ay'-thos", "derivation": "a strengthened form of (G1485);", "definition": "usage, i.e. (plural) moral habits", "kjv": "manners."}, "G2240": {"greek": "ἥκω", "translit": "hḗkō", "pronunciation": "hay'-ko", "derivation": "a primary verb;", "definition": "to arrive, i.e. be present (literally or figuratively)", "kjv": "come."}, "G2241": {"greek": "ἠλί", "translit": "ēlí", "pronunciation": "ay-lee'", "derivation": "of Hebrew origin ((G410) with pronominal suffix);", "definition": "my God", "kjv": "Eli."}, "G2243": {"greek": "Ἡλίας", "translit": "Hēlías", "pronunciation": "hay-lee'-as", "derivation": "of Hebrew origin ((G452));", "definition": "Helias (i.e. Elijah), an Israelite", "kjv": "Elias."}, "G2244": {"greek": "ἡλικία", "translit": "hēlikía", "pronunciation": "hay-lik-ee'-ah", "derivation": "from the same as (G2245);", "definition": "maturity (in years or size)", "kjv": "age, stature."}, "G2245": {"greek": "ἡλίκος", "translit": "hēlíkos", "pronunciation": "hay-lee'-kos", "derivation": "from (a comrade, i.e. one of the same age);", "definition": "as big as, i.e. (interjectively) how much", "kjv": "how (what) great."}, "G2246": {"greek": "ἥλιος", "translit": "hḗlios", "pronunciation": "hay'-lee-os", "derivation": "from (a ray; perhaps akin to the alternate of (G138));", "definition": "the sun; by implication, light", "kjv": "+ east, sun."}, "G2247": {"greek": "ἧλος", "translit": "hēlos", "pronunciation": "hay'-los", "derivation": "of uncertain affinity;", "definition": "a stud, i.e. spike", "kjv": "nail."}, "G2248": {"greek": "ἡμᾶς", "translit": "hēmâs", "pronunciation": "hay-mas'", "derivation": "accusative case plural of (G1473);", "definition": "us", "kjv": "our, us, we."}, "G2249": {"greek": "ἡμεῖς", "translit": "hēmeîs", "pronunciation": "hay-mice'", "derivation": "nominative plural of (G1473);", "definition": "we (only used when emphatic)", "kjv": "us, we (ourselves)."}, "G2250": {"greek": "ἡμέρα", "translit": "hēméra", "pronunciation": "hay-mer'-ah", "derivation": "feminine (with (G5610) implied) of a derivative of (to sit; akin to the base of (G1476)) meaning tame, i.e. gentle;", "definition": "day, i.e. (literally) the time space between dawn and dark, or the whole 24 hours (but several days were usually reckoned by the Jews as inclusive of the parts of both extremes); figuratively, a period (always defined more or less clearly by the context)", "kjv": "age, + alway, (mid-)day (by day, (-ly)), + for ever, judgment, (day) time, while, years."}, "G2251": {"greek": "ἡμέτερος", "translit": "hēméteros", "pronunciation": "hay-met'-er-os", "derivation": "from (G2349);", "definition": "our", "kjv": "our, your (by a different reading)."}, "G2253": {"greek": "ἡμιθανής", "translit": "hēmithanḗs", "pronunciation": "hay-mee-than-ace'", "derivation": "from a presumed compound of the base of (G2255) and (G2348);", "definition": "half dead, i.e. entirely exhausted", "kjv": "half dead."}, "G2254": {"greek": "ἡμῖν", "translit": "hēmîn", "pronunciation": "hay-meen'", "derivation": "dative case plural of (G1473);", "definition": "to (or for, with, by) us", "kjv": "our, (for) us, we."}, "G2255": {"greek": "ἥμισυ", "translit": "hḗmisy", "pronunciation": "hay'-mee-soo", "derivation": "neuter of a derivative from an inseparable prefix akin to (G260) (through the idea of partition involved in connection) and meaning semi-;", "definition": "(as noun) half", "kjv": "half."}, "G2256": {"greek": "ἡμιώριον", "translit": "hēmiṓrion", "pronunciation": "hay-mee-o'-ree-on", "derivation": "from the base of (G2255) and (G5610);", "definition": "a half-hour", "kjv": "half an hour."}, "G2257": {"greek": "ἡμῶν", "translit": "hēmōn", "pronunciation": "hay-mone'", "derivation": "genitive case plural of (G1473);", "definition": "of (or from) us", "kjv": "our (company), us, we."}, "G2259": {"greek": "ἡνίκα", "translit": "hēníka", "pronunciation": "hay-nee'-kah", "derivation": "of uncertain affinity;", "definition": "at which time", "kjv": "when."}, "G2260": {"greek": "ἤπερ", "translit": "ḗper", "pronunciation": "ay'-per", "derivation": "from (G2228) and (G4007);", "definition": "than at all (or than perhaps, than indeed)", "kjv": "than."}, "G2261": {"greek": "ἤπιος", "translit": "ḗpios", "pronunciation": "ay'-pee-os", "derivation": "probably from (G2031);", "definition": "properly, affable, i.e. mild or kind", "kjv": "gentle."}, "G2262": {"greek": "Ἤρ", "translit": "Ḗr", "pronunciation": "ayr", "derivation": "of Hebrew origin ((G6147));", "definition": "Er, an Israelite", "kjv": "Er."}, "G2263": {"greek": "ἤρεμος", "translit": "ḗremos", "pronunciation": "ay'-rem-os", "derivation": "perhaps by transposition from (G2048) (through the idea of stillness);", "definition": "tranquil", "kjv": "quiet."}, "G2264": {"greek": "Ἡρώδης", "translit": "Hērṓdēs", "pronunciation": "hay-ro'-dace", "derivation": "compound of (a \"hero\") and (G1491);", "definition": "heroic; Herod, the name of four Jewish kings", "kjv": "Herod."}, "G2265": {"greek": "Ἡρωδιανοί", "translit": "Hērōdianoí", "pronunciation": "hay-ro-dee-an-oy'", "derivation": "plural of a derivative of (G2264);", "definition": "Herodians, i.e. partisans of Herod", "kjv": "Herodians."}, "G2266": {"greek": "Ἡρωδιάς", "translit": "Hērōdiás", "pronunciation": "hay-ro-dee-as'", "derivation": "from (G2264);", "definition": "Herodias, a woman of the Heodian family", "kjv": "Herodias."}, "G2267": {"greek": "Ἡρωδίων", "translit": "Hērōdíōn", "pronunciation": "hay-ro-dee'-ohn", "derivation": "from (G2264);", "definition": "Herodion, a Christian", "kjv": "Herodion."}, "G2268": {"greek": "Ἡσαΐας", "translit": "Hēsaḯas", "pronunciation": "hay-sah-ee'-as", "derivation": "of Hebrew origin ((G3470));", "definition": "Hesaias (i.e. Jeshajah), an Israelite", "kjv": "Esaias."}, "G2269": {"greek": "Ἠσαῦ", "translit": "Ēsaû", "pronunciation": "ay-sow'", "derivation": "of Hebrew origin ((G6215));", "definition": "Esau, an Edomite", "kjv": "Esau."}, "G2270": {"greek": "ἡσυχάζω", "translit": "hēsycházō", "pronunciation": "hay-soo-khad'-zo", "derivation": "from the same as (G2272);", "definition": "to keep still (intransitively), i.e. refrain from labor, meddlesomeness or speech", "kjv": "cease, hold peace, be quiet, rest."}, "G2271": {"greek": "ἡσυχία", "translit": "hēsychía", "pronunciation": "hay-soo-khee'-ah", "derivation": "feminine of (G2272);", "definition": "(as noun) stillness, i.e. desistance from bustle or language", "kjv": "quietness, silence."}, "G2272": {"greek": "ἡσύχιος", "translit": "hēsýchios", "pronunciation": "hay-soo'-khee-os", "derivation": "a prolonged form of a compound probably of a derivative of the base of (G1476) and perhaps (G2192);", "definition": "properly, keeping one's seat (sedentary), i.e. (by implication) still (undisturbed, undisturbing)", "kjv": "peaceable, quiet."}, "G2273": {"greek": "ἤτοι", "translit": "ḗtoi", "pronunciation": "ay'-toy", "derivation": "from (G2228) and (G5104);", "definition": "either indeed", "kjv": "whether."}, "G2274": {"greek": "ἡττάω", "translit": "hēttáō", "pronunciation": "hayt-tah'-o", "derivation": "from the same as (G2276);", "definition": "to make worse, i.e. vanquish (literally or figuratively); by implication, to rate lower", "kjv": "be inferior, overcome."}, "G2275": {"greek": "ἥττημα", "translit": "hḗttēma", "pronunciation": "hayt'-tay-mah", "derivation": "from (G2274);", "definition": "a deterioration, i.e. (objectively) failure or (subjectively) loss", "kjv": "diminishing, fault."}, "G2276": {"greek": "ἥττον", "translit": "hḗtton", "pronunciation": "hate'-ton", "derivation": "neuter of comparative of (slightly) used for that of (G2556);", "definition": "worse (as noun); by implication, less (as adverb)", "kjv": "less, worse."}, "G2278": {"greek": "ἠχέω", "translit": "ēchéō", "pronunciation": "ay-kheh'-o", "derivation": "from (G2279);", "definition": "to make a loud noise, i.e. reverberate", "kjv": "roar, sound."}, "G2279": {"greek": "ἦχος", "translit": "ēchos", "pronunciation": "ay'-khos", "derivation": "of uncertain affinity;", "definition": "a loud or confused noise (\"echo\"), i.e. roar; figuratively, a rumor", "kjv": "fame, sound."}, "G2280": {"greek": "Θαδδαῖος", "translit": "Thaddaîos", "pronunciation": "thad-dah'-yos", "derivation": "of uncertain origin;", "definition": "Thaddæus, one of the Apostles", "kjv": "Thaddæus."}, "G2281": {"greek": "θάλασσα", "translit": "thálassa", "pronunciation": "thal'-as-sah", "derivation": "probably prolonged from (G251);", "definition": "the sea (genitive case or specially)", "kjv": "sea."}, "G2282": {"greek": "θάλπω", "translit": "thálpō", "pronunciation": "thal'-po", "derivation": "probably akin to (to warm);", "definition": "to brood, i.e. (figuratively) to foster", "kjv": "cherish."}, "G2283": {"greek": "Θάμαρ", "translit": "Thámar", "pronunciation": "tham'-ar", "derivation": "of Hebrew origin ((G8559));", "definition": "Thamar (i.e. Tamar), an Israelitess", "kjv": "Thamar."}, "G2284": {"greek": "θαμβέω", "translit": "thambéō", "pronunciation": "tham-beh'-o", "derivation": "from (G2285);", "definition": "to stupefy (with surprise), i.e. astound", "kjv": "amaze, astonish."}, "G2285": {"greek": "θάμβος", "translit": "thámbos", "pronunciation": "tham'-bos", "derivation": "akin to an obsolete (to dumbfound);", "definition": "stupefaction (by surprise), i.e. astonishment", "kjv": "X amazed, + astonished, wonder."}, "G2286": {"greek": "θανάσιμος", "translit": "thanásimos", "pronunciation": "than-as'-ee-mos", "derivation": "from (G2288);", "definition": "fatal, i.e. poisonous", "kjv": "deadly."}, "G2287": {"greek": "θανατήφορος", "translit": "thanatḗphoros", "pronunciation": "than-at-ay'-for-os", "derivation": "from (the feminine form of) (G2288) and (G5342);", "definition": "death-bearing, i.e. fatal", "kjv": "deadly."}, "G2288": {"greek": "θάνατος", "translit": "thánatos", "pronunciation": "than'-at-os", "derivation": "from (G2348);", "definition": "(properly, an adjective used as a noun) death (literally or figuratively)", "kjv": "X deadly, (be…) death."}, "G2289": {"greek": "θανατόω", "translit": "thanatóō", "pronunciation": "than-at-o'-o", "derivation": "from (G2288) to kill (literally or figuratively)", "definition": "", "kjv": "become dead, (cause to be) put to death, kill, mortify."}, "G2290": {"greek": "θάπτω", "translit": "tháptō", "pronunciation": "thap'-to", "derivation": "a primary verb;", "definition": "to celebrate funeral rites, i.e. inter", "kjv": "bury."}, "G2291": {"greek": "Θάρα", "translit": "Thára", "pronunciation": "thar'-ah", "derivation": "of Hebrew origin ((G8646));", "definition": "Thara (i.e. Terach), the father of Abraham", "kjv": "Thara."}, "G2292": {"greek": "θαῤῥέω", "translit": "tharrhéō", "pronunciation": "thar-hreh'-o", "derivation": "another form for (G2293);", "definition": "to exercise courage", "kjv": "be bold, X boldly, have confidence, be confident."}, "G2293": {"greek": "θαρσέω", "translit": "tharséō", "pronunciation": "thar-seh'-o", "derivation": "from (G2294);", "definition": "to have courage", "kjv": "be of good cheer (comfort)."}, "G2294": {"greek": "θάρσος", "translit": "thársos", "pronunciation": "thar'-sos", "derivation": "akin (by transposition) to (daring);", "definition": "boldness (subjectively)", "kjv": "courage."}, "G2295": {"greek": "θαῦμα", "translit": "thaûma", "pronunciation": "thos'-mah", "derivation": "apparently from a form of (G2300);", "definition": "wonder (properly concrete; but by implication, abstract)", "kjv": "admiration."}, "G2296": {"greek": "θαυμάζω", "translit": "thaumázō", "pronunciation": "thou-mad'-zo", "derivation": "from (G2295);", "definition": "to wonder; by implication, to admire", "kjv": "admire, have in admiration, marvel, wonder."}, "G2297": {"greek": "θαυμάσιος", "translit": "thaumásios", "pronunciation": "thow-mas'-ee-os", "derivation": "from (G2295);", "definition": "wondrous, i.e. (neuter as noun) a miracle", "kjv": "wonderful thing."}, "G2298": {"greek": "θαυμαστός", "translit": "thaumastós", "pronunciation": "thow-mas-tos'", "derivation": "from (G2296);", "definition": "wondered at, i.e. (by implication) wonderful", "kjv": "marvel(-lous)."}, "G2299": {"greek": "θεά", "translit": "theá", "pronunciation": "theh-ah'", "derivation": "feminine of (G2316);", "definition": "a female deity", "kjv": "goddess."}, "G2300": {"greek": "θεάομαι", "translit": "theáomai", "pronunciation": "theh-ah'-om-ahee", "derivation": "a prolonged form of a primary verb;", "definition": "to look closely at, i.e. (by implication) perceive (literally or figuratively); by extension to visit", "kjv": "behold, look (upon), see."}, "G2301": {"greek": "θεατρίζω", "translit": "theatrízō", "pronunciation": "theh-at-rid'-zo", "derivation": "from (G2302);", "definition": "to expose as a spectacle", "kjv": "make a gazing stock."}, "G2302": {"greek": "θέατρον", "translit": "théatron", "pronunciation": "theh'-at-ron", "derivation": "from (G2300);", "definition": "a place for public show (\"theatre\"), i.e. general audience-room; by implication, a show itself (figuratively)", "kjv": "spectacle, theatre."}, "G2303": {"greek": "θεῖον", "translit": "theîon", "pronunciation": "thi'-on", "derivation": "probably neuter of (G2304) (in its original sense of flashing);", "definition": "sulphur", "kjv": "brimstone."}, "G2304": {"greek": "θεῖος", "translit": "theîos", "pronunciation": "thi'-os", "derivation": "from (G2316);", "definition": "godlike (neuter as noun, divinity)", "kjv": "divine, godhead."}, "G2305": {"greek": "θειότης", "translit": "theiótēs", "pronunciation": "thi-ot'-ace", "derivation": "from (G2304);", "definition": "divinity (abstractly)", "kjv": "godhead."}, "G2306": {"greek": "θειώδης", "translit": "theiṓdēs", "pronunciation": "thi-o'-dace", "derivation": "from (G2303) and 1491;", "definition": "sulphur-like, i.e. sulphurous", "kjv": "brimstone."}, "G2307": {"greek": "θέλημα", "translit": "thélēma", "pronunciation": "thel'-ay-mah", "derivation": "from the prolonged form of (G2309);", "definition": "a determination (properly, the thing), i.e. (actively) choice (specially, purpose, decree; abstractly, volition) or (passively) inclination", "kjv": "desire, pleasure, will."}, "G2308": {"greek": "θέλησις", "translit": "thélēsis", "pronunciation": "thel'-ay-sis", "derivation": "from (G2309);", "definition": "determination (properly, the act), i.e. option", "kjv": "will."}, "G2309": {"greek": "θέλω", "translit": "thélō", "pronunciation": "thel'-o", "derivation": "apparently strengthened from the alternate form of (G138);", "definition": "to determine (as an active option from subjective impulse; whereas (G1014) properly denotes rather a passive acquiescence in objective considerations), i.e. choose or prefer (literally or figuratively); by implication, to wish, i.e. be inclined to (sometimes adverbially, gladly); impersonally for the future tense, to be about to; by Hebraism, to delight in", "kjv": "desire, be disposed (forward), intend, list, love, mean, please, have rather, (be) will (have, -ling, - ling(-ly))."}, "G2310": {"greek": "θεμέλιος", "translit": "themélios", "pronunciation": "them-el'-ee-os", "derivation": "from a derivative of (G5087);", "definition": "something put down, i.e. a substruction (of a building, etc.), (literally or figuratively)", "kjv": "foundation."}, "G2311": {"greek": "θεμελιόω", "translit": "themelióō", "pronunciation": "them-el-ee-o'-o", "derivation": "from (G2310);", "definition": "to lay a basis for, i.e. (literally) erect, or (figuratively) consolidate", "kjv": "(lay the) found(- ation), ground, settle."}, "G2312": {"greek": "θεοδίδακτος", "translit": "theodídaktos", "pronunciation": "theh-od-id'-ak-tos", "derivation": "from (G2316) and (G1321);", "definition": "divinely instructed", "kjv": "taught of God."}, "G2314": {"greek": "θεομάχος", "translit": "theomáchos", "pronunciation": "theh-om'-akh-os", "derivation": "from (G2316) and (G3164);", "definition": "an opponent of deity", "kjv": "to fight against God."}, "G2315": {"greek": "θεόπνευστος", "translit": "theópneustos", "pronunciation": "theh-op'-nyoo-stos", "derivation": "from (G2316) and a presumed derivative of (G4154);", "definition": "divinely breathed in", "kjv": "given by inspiration of God."}, "G2316": {"greek": "θεός", "translit": "theós", "pronunciation": "theh'-os", "derivation": "of uncertain affinity;", "definition": "a deity, especially (with (G3588)) the supreme Divinity; figuratively, a magistrate; by Hebraism, very", "kjv": "X exceeding, God, god(-ly, -ward)."}, "G2317": {"greek": "θεοσέβεια", "translit": "theosébeia", "pronunciation": "theh-os-eb'-i-ah", "derivation": "from (G2318);", "definition": "devoutness, i.e. piety", "kjv": "godliness."}, "G2318": {"greek": "θεοσεβής", "translit": "theosebḗs", "pronunciation": "theh-os-eb-ace'", "derivation": "from (G2316) and (G4576);", "definition": "reverent of God, i.e. pious", "kjv": "worshipper of God."}, "G2319": {"greek": "θεοστυγής", "translit": "theostygḗs", "pronunciation": "theh-os-too-gace'", "derivation": "from (G2316) and the base of (G4767);", "definition": "hateful to God, i.e. impious", "kjv": "hater of God."}, "G2320": {"greek": "θεότης", "translit": "theótēs", "pronunciation": "theh-ot'-ace", "derivation": "from (G2316);", "definition": "divinity (abstractly)", "kjv": "godhead."}, "G2321": {"greek": "Θεόφιλος", "translit": "Theóphilos", "pronunciation": "theh-of'-il-os", "derivation": "from (G2316) and (G5384);", "definition": "friend of God; Theophilus, a Christian", "kjv": "Theophilus."}, "G2322": {"greek": "θεραπεία", "translit": "therapeía", "pronunciation": "ther-ap-i'-ah", "derivation": "from (G2323);", "definition": "attendance (specially, medical, i.e. cure); figuratively and collectively, domestics", "kjv": "healing, household."}, "G2323": {"greek": "θεραπεύω", "translit": "therapeúō", "pronunciation": "ther-ap-yoo'-o", "derivation": "from the same as (G2324);", "definition": "to wait upon menially, i.e. (figuratively) to adore (God), or (specially) to relieve (of disease)", "kjv": "cure, heal, worship."}, "G2324": {"greek": "θεράπων", "translit": "therápōn", "pronunciation": "ther-ap'-ohn", "derivation": "apparently a participle from an otherwise obsolete derivative of the base of (G2330);", "definition": "a menial attendant (as if cherishing)", "kjv": "servant."}, "G2325": {"greek": "θερίζω", "translit": "therízō", "pronunciation": "ther-id'-zo", "derivation": "from (G2330) (in the sense of the crop);", "definition": "to harvest", "kjv": "reap."}, "G2326": {"greek": "θερισμός", "translit": "therismós", "pronunciation": "ther-is-mos'", "derivation": "from (G2325);", "definition": "reaping, i.e. the crop", "kjv": "harvest."}, "G2327": {"greek": "θεριστής", "translit": "theristḗs", "pronunciation": "ther-is-tace'", "derivation": "from (G2325);", "definition": "a harvester", "kjv": "reaper."}, "G2328": {"greek": "θερμαίνω", "translit": "thermaínō", "pronunciation": "ther-mah'-ee-no", "derivation": "from (G2329);", "definition": "to heat (oneself)", "kjv": "(be) warm(-ed, self)."}, "G2329": {"greek": "θέρμη", "translit": "thérmē", "pronunciation": "ther'-may", "derivation": "from the base of (G2330);", "definition": "warmth", "kjv": "heat."}, "G2330": {"greek": "θέρος", "translit": "théros", "pronunciation": "ther'-os", "derivation": "from a primary (to heat);", "definition": "properly, heat, i.e. summer", "kjv": "summer."}, "G2331": {"greek": "Θεσσαλονικεύς", "translit": "Thessalonikeús", "pronunciation": "thes-sal-on-ik-yoos'", "derivation": "from (G2332);", "definition": "a Thessalonican, i.e. inhabitant of Thessalonice", "kjv": "Thessalonian."}, "G2332": {"greek": "Θεσσαλονίκη", "translit": "Thessaloníkē", "pronunciation": "thes-sal-on-ee'-kay", "derivation": "from (a Thessalian) and (G3529);", "definition": "Thessalonice, a place in Asia Minor", "kjv": "Thessalonica."}, "G2333": {"greek": "Θευδᾶς", "translit": "Theudâs", "pronunciation": "thyoo-das'", "derivation": "of uncertain origin;", "definition": "Theudas, an Israelite", "kjv": "Theudas."}, "G2334": {"greek": "θεωρέω", "translit": "theōréō", "pronunciation": "theh-o-reh'-o", "derivation": "from a derivative of (G2300) (perhaps by addition of (G3708));", "definition": "to be a spectator of, i.e. discern, (literally, figuratively (experience) or intensively (acknowledge))", "kjv": "behold, consider, look on, perceive, see."}, "G2335": {"greek": "θεωρία", "translit": "theōría", "pronunciation": "theh-o-ree'-ah", "derivation": "from the same as (G2334);", "definition": "spectatorship, i.e. (concretely) a spectacle", "kjv": "sight."}, "G2336": {"greek": "θήκη", "translit": "thḗkē", "pronunciation": "thay'-kay", "derivation": "from (G5087);", "definition": "a receptacle, i.e. scabbard", "kjv": "sheath."}, "G2337": {"greek": "θηλάζω", "translit": "thēlázō", "pronunciation": "thay-lad'-zo", "derivation": "from (the nipple);", "definition": "to suckle, (by implication) to suck", "kjv": "(give) suck(-ling)."}, "G2338": {"greek": "θῆλυς", "translit": "thēlys", "pronunciation": "thay'-loos", "derivation": "from the same as (G2337);", "definition": "female", "kjv": "female, woman."}, "G2339": {"greek": "θήρα", "translit": "thḗra", "pronunciation": "thay'-rah", "derivation": "from (a wild animal, as game);", "definition": "hunting, i.e. (figuratively) destruction", "kjv": "trap."}, "G2340": {"greek": "θηρεύω", "translit": "thēreúō", "pronunciation": "thay-ryoo'-o", "derivation": "from (G2339);", "definition": "to hunt (an animal), i.e. (figuratively) to carp at", "kjv": "catch."}, "G2341": {"greek": "θηριομαχέω", "translit": "thēriomachéō", "pronunciation": "thay-ree-om-akh-eh'-o", "derivation": "from a compound of (G2342) and (G3164);", "definition": "to be a beast-fighter (in the gladiatorial show), i.e. (figuratively) to encounter (furious men)", "kjv": "fight with wild beasts."}, "G2342": {"greek": "θηρίον", "translit": "thēríon", "pronunciation": "thay-ree'-on", "derivation": "diminutive from the same as (G2339);", "definition": "a dangerous animal", "kjv": "(venomous, wild) beast."}, "G2343": {"greek": "θησαυρίζω", "translit": "thēsaurízō", "pronunciation": "thay-sow-rid'-zo", "derivation": "from (G2344);", "definition": "to amass or reserve (literally or figuratively)", "kjv": "lay up (treasure), (keep) in store, (heap) treasure (together, up)."}, "G2344": {"greek": "θησαυρός", "translit": "thēsaurós", "pronunciation": "thay-sow-ros'", "derivation": "from (G5087);", "definition": "a deposit, i.e. wealth (literally or figuratively)", "kjv": "treasure."}, "G2345": {"greek": "θιγγάνω", "translit": "thingánō", "pronunciation": "thing-gan'-o", "derivation": "a prolonged form of an obsolete primary (to finger);", "definition": "to manipulate, i.e. have to do with; by implication, to injure", "kjv": "handle, touch."}, "G2346": {"greek": "θλίβω", "translit": "thlíbō", "pronunciation": "thlee'-bo", "derivation": "akin to the base of (G5147);", "definition": "to crowd (literally or figuratively)", "kjv": "afflict, narrow, throng, suffer tribulation, trouble."}, "G2347": {"greek": "θλῖψις", "translit": "thlîpsis", "pronunciation": "thlip'-sis", "derivation": "from (G2346);", "definition": "pressure (literally or figuratively)", "kjv": "afflicted(-tion), anguish, burdened, persecution, tribulation, trouble."}, "G2348": {"greek": "θνήσκω", "translit": "thnḗskō", "pronunciation": "thnay'-sko", "derivation": "a strengthened form of a simpler primary (which is used for it only in certain tenses);", "definition": "to die (literally or figuratively)", "kjv": "be dead, die."}, "G2349": {"greek": "θνητός", "translit": "thnētós", "pronunciation": "thnay-tos'", "derivation": "from (G2348);", "definition": "liable to die", "kjv": "mortal(-ity)."}, "G2350": {"greek": "θορυβέω", "translit": "thorybéō", "pronunciation": "thor-oo-beh'-o", "derivation": "from (G2351);", "definition": "to be in tumult, i.e. disturb, clamor", "kjv": "make ado (a noise), trouble self, set on an uproar."}, "G2351": {"greek": "θόρυβος", "translit": "thórybos", "pronunciation": "thor'-oo-bos", "derivation": "from the base of (G2360);", "definition": "a disturbance", "kjv": "tumult, uproar."}, "G2352": {"greek": "θραύω", "translit": "thraúō", "pronunciation": "throw'-o", "derivation": "a primary verb;", "definition": "to crush", "kjv": "bruise."}, "G2353": {"greek": "θρέμμα", "translit": "thrémma", "pronunciation": "threm'-mah", "derivation": "from (G5142);", "definition": "stock (as raised on a farm)", "kjv": "cattle."}, "G2354": {"greek": "θρηνέω", "translit": "thrēnéō", "pronunciation": "thray-neh'-o", "derivation": "from (G2355);", "definition": "to bewail", "kjv": "lament, mourn."}, "G2356": {"greek": "θρησκεία", "translit": "thrēskeía", "pronunciation": "thrace-ki'-ah", "derivation": "from a derivative of (G2357);", "definition": "ceremonial observance", "kjv": "religion, worshipping."}, "G2357": {"greek": "θρησκός", "translit": "thrēskós", "pronunciation": "thrace'-kos", "derivation": "probably from the base of (G2360);", "definition": "ceremonious in worship (as demonstrative), i.e. pious", "kjv": "religious."}, "G2358": {"greek": "θριαμβεύω", "translit": "thriambeúō", "pronunciation": "three-am-byoo'-o", "derivation": "from a prolonged compound of the base of (G2360);", "definition": "and a derivative of (G680) (meaning a noisy iambus, sung in honor of Bacchus); to make an acclamatory procession, i.e. (figuratively) to conquer or (by Hebraism) to give victory", "kjv": "(cause) to triumph (over)."}, "G2359": {"greek": "θρίξ", "translit": "thríx", "pronunciation": "threeks", "derivation": "genitive case , etc.;", "definition": "of uncertain derivation; hair", "kjv": "hair."}, "G2360": {"greek": "θροέω", "translit": "throéō", "pronunciation": "thro-eh'-o", "derivation": "from to wail;", "definition": "to clamor, i.e. (by implication) to frighten", "kjv": "trouble."}, "G2361": {"greek": "θρόμβος", "translit": "thrómbos", "pronunciation": "throm'-bos", "derivation": "perhaps from (G5142) (in the sense of thickening);", "definition": "a clot", "kjv": "great drop."}, "G2362": {"greek": "θρόνος", "translit": "thrónos", "pronunciation": "thron'-os", "derivation": "from (to sit);", "definition": "a stately seat (\"throne\"); by implication, power or (concretely) a potentate", "kjv": "seat, throne."}, "G2363": {"greek": "Θυάτειρα", "translit": "Thyáteira", "pronunciation": "thoo-at'-i-rah", "derivation": "of uncertain derivation;", "definition": "Thyatira, a place in Asia Minor", "kjv": "Thyatira."}, "G2364": {"greek": "θυγάτηρ", "translit": "thygátēr", "pronunciation": "thoo-gat'-air", "derivation": "apparently a primary word (compare \"daughter\");", "definition": "a female child, or (by Hebraism) descendant (or inhabitant)", "kjv": "daughter."}, "G2365": {"greek": "θυγάτριον", "translit": "thygátrion", "pronunciation": "thoo-gat'-ree-on", "derivation": "from (G2364);", "definition": "a daughterling", "kjv": "little (young) daughter."}, "G2366": {"greek": "θύελλα", "translit": "thýella", "pronunciation": "thoo'-el-lah", "derivation": "from (G2380) (in the sense of blowing) a storm", "definition": "", "kjv": "tempest."}, "G2367": {"greek": "θύϊνος", "translit": "thýïnos", "pronunciation": "thoo'-ee-nos", "derivation": "from a derivative of (G2380) (in the sense of blowing; denoting a certain fragrant tree);", "definition": "made of citron-wood", "kjv": "thyine."}, "G2368": {"greek": "θυμίαμα", "translit": "thymíama", "pronunciation": "thoo-mee'-am-ah", "derivation": "from (G2370);", "definition": "an aroma, i.e. fragrant powder burnt in religious service; by implication, the burning itself", "kjv": "incense, odour."}, "G2369": {"greek": "θυμιαστήριον", "translit": "thymiastḗrion", "pronunciation": "thoo-mee-as-tay'-ree-on", "derivation": "from a derivative of (G2370);", "definition": "a place of fumigation, i.e. the alter of incense (in the Temple)", "kjv": "censer."}, "G2370": {"greek": "θυμιάω", "translit": "thymiáō", "pronunciation": "thoo-mee-ah'-o", "derivation": "from a derivative of (G2380) (in the sense of smoking);", "definition": "to fumigate, i.e. offer aromatic fumes", "kjv": "burn incense."}, "G2371": {"greek": "θυμομαχέω", "translit": "thymomachéō", "pronunciation": "thoo-mom-akh-eh'-o", "derivation": "from a presumed compound of (G2372) and (G3164);", "definition": "to be in a furious fight, i.e. (figuratively) to be exasperated", "kjv": "be highly displeased."}, "G2372": {"greek": "θυμός", "translit": "thymós", "pronunciation": "thoo-mos'", "derivation": "from (G2380);", "definition": "passion (as if breathing hard)", "kjv": "fierceness, indignation, wrath."}, "G2373": {"greek": "θυμόω", "translit": "thymóō", "pronunciation": "tho-mo'-o", "derivation": "from (G2372);", "definition": "to put in a passion, i.e. enrage", "kjv": "be wroth."}, "G2374": {"greek": "θύρα", "translit": "thýra", "pronunciation": "thoo'-rah", "derivation": "apparently a primary word (compare \"door\");", "definition": "a portal or entrance (the opening or the closure, literally or figuratively)", "kjv": "door, gate."}, "G2375": {"greek": "θυρεός", "translit": "thyreós", "pronunciation": "thoo-reh-os'", "derivation": "from (G2374);", "definition": "a large shield (as door-shaped)", "kjv": "shield."}, "G2376": {"greek": "θυρίς", "translit": "thyrís", "pronunciation": "thoo-rece'", "derivation": "from (G2374);", "definition": "an aperture, i.e. window", "kjv": "window."}, "G2377": {"greek": "θυρωρός", "translit": "thyrōrós", "pronunciation": "thoo-ro-ros'", "derivation": "from (G2374) and (a watcher);", "definition": "a gate- warden", "kjv": "that kept the door, porter."}, "G2378": {"greek": "θυσία", "translit": "thysía", "pronunciation": "thoo-see'-ah", "derivation": "from (G2380);", "definition": "sacrifice (the act or the victim, literally or figuratively)", "kjv": "sacrifice."}, "G2379": {"greek": "θυσιαστήριον", "translit": "thysiastḗrion", "pronunciation": "thoo-see-as-tay'-ree-on", "derivation": "from a derivative of (G2378);", "definition": "a place of sacrifice, i.e. an altar (special or genitive case, literal or figurative)", "kjv": "altar."}, "G2380": {"greek": "θύω", "translit": "thýō", "pronunciation": "thoo'-o", "derivation": "a primary verb;", "definition": "properly, to rush (breathe hard, blow, smoke), i.e. (by implication) to sacrifice (properly, by fire, but genitive case); by extension to immolate (slaughter for any purpose)", "kjv": "kill, (do) sacrifice, slay."}, "G2381": {"greek": "Θωμᾶς", "translit": "Thōmâs", "pronunciation": "tho-mas'", "derivation": "of Chaldee origin (compare (G8380));", "definition": "the twin; Thomas, a Christian", "kjv": "Thomas."}, "G2382": {"greek": "θώραξ", "translit": "thṓrax", "pronunciation": "tho'-rax", "derivation": "of uncertain affinity;", "definition": "the chest (\"thorax\"), i.e. (by implication) a corslet", "kjv": "breast-plate."}, "G2383": {"greek": "Ἰάειρος", "translit": "Iáeiros", "pronunciation": "ee-ah'-i-ros", "derivation": "of Hebrew origin ((G2971));", "definition": "Jairus (i.e. Jair), an Israelite", "kjv": "Jairus."}, "G2384": {"greek": "Ἰακώβ", "translit": "Iakṓb", "pronunciation": "ee-ak-obe'", "derivation": "of Hebrew origin ((G3290));", "definition": "Jacob (i.e. Ja`akob), the progenitor of the Israelites", "kjv": "also an Israelite:--Jacob."}, "G2385": {"greek": "Ἰάκωβος", "translit": "Iákōbos", "pronunciation": "ee-ak'-o-bos", "derivation": "the same as (G2384) Græcized;", "definition": "Jacobus, the name of three Israelites", "kjv": "James."}, "G2386": {"greek": "ἴαμα", "translit": "íama", "pronunciation": "ee'-am-ah", "derivation": "from (G2390);", "definition": "a cure (the effect)", "kjv": "healing."}, "G2387": {"greek": "Ἰαμβρῆς", "translit": "Iambrēs", "pronunciation": "ee-am-brace'", "derivation": "of Egyptian origin;", "definition": "Jambres, an Egyptian", "kjv": "Jambres."}, "G2388": {"greek": "Ἰαννά", "translit": "Ianná", "pronunciation": "ee-an-nah'", "derivation": "probably of Hebrew origin (compare (G3238));", "definition": "Janna, an Israelite", "kjv": "Janna."}, "G2389": {"greek": "Ἰαννῆς", "translit": "Iannēs", "pronunciation": "ee-an-nace'", "derivation": "of Egyptian origin;", "definition": "Jannes, an Egyptian", "kjv": "Jannes."}, "G2390": {"greek": "ἰάομαι", "translit": "iáomai", "pronunciation": "ee-ah'-om-ahee", "derivation": "middle voice of apparently a primary verb;", "definition": "to cure (literally or figuratively)", "kjv": "heal, make whole."}, "G2391": {"greek": "Ἰάρεδ", "translit": "Iáred", "pronunciation": "ee-ar'-ed", "derivation": "of Hebrew origin ((G3382));", "definition": "Jared (i.e. Jered), an antediluvian", "kjv": "Jared."}, "G2392": {"greek": "ἴασις", "translit": "íasis", "pronunciation": "ee'-as-is", "derivation": "from (G2390);", "definition": "curing (the act)", "kjv": "cure, heal(-ing)."}, "G2393": {"greek": "ἴασπις", "translit": "íaspis", "pronunciation": "ee'-as-pis", "derivation": "probably of foreign origin (see (G3471));", "definition": "\"jasper\", a gem", "kjv": "jasper."}, "G2394": {"greek": "Ἰάσων", "translit": "Iásōn", "pronunciation": "ee-as'-oan", "derivation": "future active participle masculine of (G2390);", "definition": "about to cure; Jason, a Christian", "kjv": "Jason."}, "G2395": {"greek": "ἰατρός", "translit": "iatrós", "pronunciation": "ee-at-ros'", "derivation": "from (G2390);", "definition": "a physician", "kjv": "physician."}, "G2396": {"greek": "ἴδε", "translit": "íde", "pronunciation": "id'-eh", "derivation": "second person singular imperative active of (G1492);", "definition": "used as an interjection to denote surprise; lo!", "kjv": "behold, lo, see."}, "G2397": {"greek": "ἰδέα", "translit": "idéa", "pronunciation": "id-eh'-ah", "derivation": "from (G1492);", "definition": "a sight (compare figuratively \"idea\"), i.e. aspect", "kjv": "countenance."}, "G2398": {"greek": "ἴδιος", "translit": "ídios", "pronunciation": "id'-ee-os", "derivation": "of uncertain affinity;", "definition": "pertaining to self, i.e. one's own; by implication, private or separate", "kjv": "X his acquaintance, when they were alone, apart, aside, due, his (own, proper, several), home, (her, our, thine, your) own (business), private(-ly), proper, severally, their (own)."}, "G2399": {"greek": "ἰδιώτης", "translit": "idiṓtēs", "pronunciation": "id-ee-o'-tace", "derivation": "from (G2398);", "definition": "a private person, i.e. (by implication) an ignoramus (compare \"idiot\")", "kjv": "ignorant, rude, unlearned."}, "G2400": {"greek": "ἰδού", "translit": "idoú", "pronunciation": "id-oo'", "derivation": "second person singular imperative middle voice of (G1492);", "definition": "used as imperative lo!;", "kjv": "behold, lo, see."}, "G2401": {"greek": "Ἰδουμαία", "translit": "Idoumaía", "pronunciation": "id-oo-mah'-yah", "derivation": "of Hebrew origin ((G123));", "definition": "Idumæa (i.e. Edom), a region East (and South) of Palestine", "kjv": "Idumæa."}, "G2402": {"greek": "ἱδρώς", "translit": "hidrṓs", "pronunciation": "hid-roce'", "derivation": "a strengthened form of a primary (sweat): perspiration", "definition": "", "kjv": "sweat."}, "G2403": {"greek": "Ἰεζαβήλ", "translit": "Iezabḗl", "pronunciation": "ee-ed-zab-ale'", "derivation": "of Hebrew origin ((G348));", "definition": "Jezabel (i.e. Jezebel), a Tyrian woman (used as a synonym of a termagant or false teacher)", "kjv": "Jezabel."}, "G2404": {"greek": "Ἱεράπολις", "translit": "Hierápolis", "pronunciation": "hee-er-ap'-ol-is", "derivation": "from (G2413) and (G4172);", "definition": "holy city; Hierapolis, a place in Asia Minor", "kjv": "Hierapolis."}, "G2405": {"greek": "ἱερατεία", "translit": "hierateía", "pronunciation": "hee-er-at-i'-ah", "derivation": "from (G2407);", "definition": "priestliness, i.e. the sacerdotal function", "kjv": "office of the priesthood, priest's office."}, "G2406": {"greek": "ἱεράτευμα", "translit": "hieráteuma", "pronunciation": "hee-er-at'-yoo-mah", "derivation": "from (G2407);", "definition": "the priestly fraternity, i.e. sacerdotal order (figuratively)", "kjv": "priesthood."}, "G2407": {"greek": "ἱερατεύω", "translit": "hierateúō", "pronunciation": "hee-er-at-yoo'-o", "derivation": "prolongation from (G2409);", "definition": "to be a priest, i.e. perform his functions", "kjv": "execute the priest's office."}, "G2408": {"greek": "Ἱερεμίας", "translit": "Hieremías", "pronunciation": "hee-er-em-ee'-as", "derivation": "of Hebrew origin ((G3414));", "definition": "Hieremias (i.e. Jermijah), an Israelite", "kjv": "Jeremiah."}, "G2409": {"greek": "ἱερεύς", "translit": "hiereús", "pronunciation": "hee-er-yooce'", "derivation": "from (G2413);", "definition": "a priest (literally or figuratively)", "kjv": "(high) priest."}, "G2410": {"greek": "Ἱεριχώ", "translit": "Hierichṓ", "pronunciation": "hee-er-ee-kho'", "derivation": "of Hebrew origin ((G3405));", "definition": "Jericho, a place in Palestine", "kjv": "Jericho."}, "G2411": {"greek": "ἱερόν", "translit": "hierón", "pronunciation": "hee-er-on'", "derivation": "neuter of (G2413);", "definition": "a sacred place, i.e. the entire precincts (whereas (G3485) denotes the central sanctuary itself) of the Temple (at Jerusalem or elsewhere)", "kjv": "temple."}, "G2412": {"greek": "ἱεροπρεπής", "translit": "hieroprepḗs", "pronunciation": "hee-er-op-rep-ace'", "derivation": "from (G2413) and the same as (G4241);", "definition": "reverent", "kjv": "as becometh holiness."}, "G2413": {"greek": "ἱερός", "translit": "hierós", "pronunciation": "hee-er-os'", "derivation": "of uncertain affinity;", "definition": "sacred", "kjv": "holy."}, "G2414": {"greek": "Ἱεροσόλυμα", "translit": "Hierosólyma", "pronunciation": "hee-er-os-ol'-oo-mah", "derivation": "of Hebrew origin ((G3389));", "definition": "Hierosolyma (i.e. Jerushalaim), the capitol of Palestine", "kjv": "Jerusalem."}, "G2415": {"greek": "Ἱεροσολυμίτης", "translit": "Hierosolymítēs", "pronunciation": "hee-er-os-ol-oo-mee'-tace", "derivation": "from (G2414);", "definition": "a Hierosolymite, i.e. inhabitant of Hierosolyma", "kjv": "of Jerusalem."}, "G2416": {"greek": "ἱεροσυλέω", "translit": "hierosyléō", "pronunciation": "hee-er-os-ool-eh'-o", "derivation": "from (G2417);", "definition": "to be a temple-robber (figuratively)", "kjv": "commit sacrilege."}, "G2417": {"greek": "ἱερόσυλος", "translit": "hierósylos", "pronunciation": "hee-er-os'-oo-los", "derivation": "from (G2411) and (G4813);", "definition": "a temple-despoiler", "kjv": "robber of churches."}, "G2418": {"greek": "ἱερουργέω", "translit": "hierourgéō", "pronunciation": "hee-er-oorg-eh'-o", "derivation": "from a compound of (G2411) and the base of (G2041);", "definition": "to be a temple-worker, i.e. officiate as a priest (figuratively)", "kjv": "minister."}, "G2419": {"greek": "Ἱερουσαλήμ", "translit": "Hierousalḗm", "pronunciation": "hee-er-oo-sal-ame'", "derivation": "of Hebrew origin ((G3389));", "definition": "Hierusalem (i.e. Jerushalem), the capitol of Palestine", "kjv": "Jerusalem."}, "G2420": {"greek": "ἱερωσύνη", "translit": "hierōsýnē", "pronunciation": "hee-er-o-soo'-nay", "derivation": "from (G2413);", "definition": "sacredness, i.e. (by implication) the priestly office", "kjv": "priesthood."}, "G2421": {"greek": "Ἰεσσαί", "translit": "Iessaí", "pronunciation": "es-es-sah'-ee", "derivation": "of Hebrew origin ((G3448));", "definition": "Jessæ (i.e. Jishai), an Israelite", "kjv": "Jesse."}, "G2422": {"greek": "Ἰεφθάε", "translit": "Iephtháe", "pronunciation": "ee-ef-thah'-eh", "derivation": "of Hebrew origin ((G3316));", "definition": "Jephthaë (i.e. Jiphtach), an Israelite", "kjv": "Jephthah."}, "G2423": {"greek": "Ἰεχονίας", "translit": "Iechonías", "pronunciation": "ee-ekh-on-ee'-as", "derivation": "of Hebrew origin ((G3204));", "definition": "Jechonias (i.e. Jekonjah), an Israelite", "kjv": "Jechonias."}, "G2424": {"greek": "Ἰησοῦς", "translit": "Iēsoûs", "pronunciation": "ee-ay-sooce'", "derivation": "of Hebrew origin ((G3091));", "definition": "Jesus (i.e. Jehoshua), the name of our Lord and two (three) other Israelites", "kjv": "Jesus."}, "G2425": {"greek": "ἱκανός", "translit": "hikanós", "pronunciation": "hik-an-os'", "derivation": "from ( or , akin to (G2240)) (to arrive);", "definition": "competent (as if coming in season), i.e. ample (in amount) or fit (in character)", "kjv": "able, + content, enough, good, great, large, long (while), many, meet, much, security, sore, sufficient, worthy."}, "G2426": {"greek": "ἱκανότης", "translit": "hikanótēs", "pronunciation": "hik-an-ot'-ace", "derivation": "from (G2425);", "definition": "ability", "kjv": "sufficiency."}, "G2427": {"greek": "ἱκανόω", "translit": "hikanóō", "pronunciation": "hik-an-o'-o", "derivation": "from (G2425);", "definition": "to enable, i.e. qualify", "kjv": "make able (meet)."}, "G2428": {"greek": "ἱκετηρία", "translit": "hiketēría", "pronunciation": "hik-et-ay-ree'-ah", "derivation": "from a derivative of the base of (G2425) (through the idea of approaching for a favor);", "definition": "intreaty", "kjv": "supplication."}, "G2429": {"greek": "ἱκμάς", "translit": "hikmás", "pronunciation": "hik-mas'", "derivation": "of uncertain affinity;", "definition": "dampness", "kjv": "moisture."}, "G2430": {"greek": "Ἰκόνιον", "translit": "Ikónion", "pronunciation": "ee-kon'-ee-on", "derivation": "perhaps from (G1504);", "definition": "image-like; Iconium, a place in Asia Minor", "kjv": "Iconium."}, "G2431": {"greek": "ἱλαρός", "translit": "hilarós", "pronunciation": "hil-ar-os'", "derivation": "from the same as (G2436);", "definition": "propitious or merry (\"hilarious\"), i.e. prompt or willing", "kjv": "cheerful."}, "G2432": {"greek": "ἱλαρότης", "translit": "hilarótēs", "pronunciation": "hil-ar-ot'-ace", "derivation": "from (G2431);", "definition": "alacrity", "kjv": "cheerfulness."}, "G2433": {"greek": "ἱλάσκομαι", "translit": "hiláskomai", "pronunciation": "hil-as'-kom-ahee", "derivation": "middle voice from the same as (G2436);", "definition": "to conciliate, i.e. (transitively) to atone for (sin), or (intransitively) be propitious", "kjv": "be merciful, make reconciliation for."}, "G2434": {"greek": "ἱλασμός", "translit": "hilasmós", "pronunciation": "hil-as-mos'", "derivation": "", "definition": "atonement, i.e. (concretely) an expiator", "kjv": "propitiation."}, "G2435": {"greek": "ἱλαστήριον", "translit": "hilastḗrion", "pronunciation": "hil-as-tay'-ree-on", "derivation": "neuter of a derivative of (G2433);", "definition": "an expiatory (place or thing), i.e. (concretely) an atoning victim, or (specially) the lid of the Ark (in the Temple)", "kjv": "mercyseat, propitiation."}, "G2436": {"greek": "ἵλεως", "translit": "híleōs", "pronunciation": "hil'-eh-oce", "derivation": "perhaps from the alternate form of (G138);", "definition": "cheerful (as attractive), i.e. propitious; adverbially (by Hebraism) God be gracious!, i.e. (in averting some calamity) far be it", "kjv": "be it far, merciful."}, "G2437": {"greek": "Ἰλλυρικόν", "translit": "Illyrikón", "pronunciation": "il-loo-ree-kon'", "derivation": "neuter of an adjective from a name of uncertain derivation;", "definition": "(the) Illyrican (shore), i.e. (as a name itself) Illyricum, a region of Europe", "kjv": "Illyricum."}, "G2438": {"greek": "ἱμάς", "translit": "himás", "pronunciation": "hee-mas'", "derivation": "perhaps from the same as (G260);", "definition": "a strap, i.e. (specially) the tie (of a sandal) or the lash (of a scourge)", "kjv": "latchet, thong."}, "G2439": {"greek": "ἱματίζω", "translit": "himatízō", "pronunciation": "him-at-id'-zo", "derivation": "from (G2440);", "definition": "to dress", "kjv": "clothe."}, "G2440": {"greek": "ἱμάτιον", "translit": "himátion", "pronunciation": "him-at'-ee-on", "derivation": "neuter of a presumed derivative of ennumi (to put on);", "definition": "a dress (inner or outer)", "kjv": "apparel, cloke, clothes, garment, raiment, robe, vesture."}, "G2441": {"greek": "ἱματισμός", "translit": "himatismós", "pronunciation": "him-at-is-mos'", "derivation": "from (G2439);", "definition": "clothing", "kjv": "apparel (X -led), array, raiment, vesture."}, "G2442": {"greek": "ἱμείρομαι", "translit": "himeíromai", "pronunciation": "him-i'-rom-ahee", "derivation": "middle voice from (a yearning; of uncertain affinity);", "definition": "to long for", "kjv": "be affectionately desirous."}, "G2443": {"greek": "ἵνα", "translit": "hína", "pronunciation": "hin'-ah", "derivation": "probably from the same as the former part of (G1438) (through the demonstrative idea; compare (G3588));", "definition": "in order that (denoting the purpose or the result)", "kjv": "albeit, because, to the intent (that), lest, so as, (so) that, (for) to."}, "G2444": {"greek": "ἱνατί", "translit": "hinatí", "pronunciation": "hin-at-ee'", "derivation": "from (G2443) and (G5101);", "definition": "for what reason ?, i.e. why?", "kjv": "wherefore, why."}, "G2445": {"greek": "Ἰόππη", "translit": "Ióppē", "pronunciation": "ee-op'-pay", "derivation": "of Hebrew origin ((G3305));", "definition": "Joppe (i.e. Japho), a place in Palestine", "kjv": "Joppa."}, "G2446": {"greek": "Ἰορδάνης", "translit": "Iordánēs", "pronunciation": "ee-or-dan'-ace", "derivation": "of Hebrew origin ((G3383));", "definition": "the Jordanes (i.e. Jarden), a river of Palestine", "kjv": "Jordan."}, "G2447": {"greek": "ἰός", "translit": "iós", "pronunciation": "ee-os'", "derivation": "perhaps from (to go) or (to send);", "definition": "rust (as if emitted by metals); also venom (as emitted by serpents)", "kjv": "poison, rust."}, "G2448": {"greek": "Ἰουδά", "translit": "Ioudá", "pronunciation": "ee-oo-dah'", "derivation": "of Hebrew origin ((G3063) or perhaps (G3194));", "definition": "Judah (i.e. Jehudah or Juttah), a part of (or place in) Palestine", "kjv": "Judah."}, "G2449": {"greek": "Ἰουδαία", "translit": "Ioudaía", "pronunciation": "ee-oo-dah'-yah", "derivation": "feminine of (G2453) (with (G1093) implied);", "definition": "the Judæan land (i.e. Judæa), a region of Palestine", "kjv": "Judæa."}, "G2450": {"greek": "Ἰουδαΐζω", "translit": "Ioudaḯzō", "pronunciation": "ee-oo-dah-id'-zo", "derivation": "from (G2453);", "definition": "to become a Judæan, i.e. \"Judaize\"", "kjv": "live as the Jews."}, "G2451": {"greek": "Ἰουδαϊκός", "translit": "Ioudaïkós", "pronunciation": "ee-oo-dah-ee-kos'", "derivation": "from (G2453);", "definition": "Judaïc, i.e. resembling a Judæan", "kjv": "Jewish."}, "G2452": {"greek": "Ἰουδαϊκῶς", "translit": "Ioudaïkōs", "pronunciation": "ee-oo-dah-ee-koce'", "derivation": "adverb from (G2451);", "definition": "Judaïcally or in a manner resembling a Judæan", "kjv": "as do the Jews."}, "G2453": {"greek": "Ἰουδαῖος", "translit": "Ioudaîos", "pronunciation": "ee-oo-dah'-yos", "derivation": "from (G2448) (in the sense of (G2455) as a country);", "definition": "Judæan, i.e. belonging to Jehudah", "kjv": "Jew(-ess), of Judæa."}, "G2454": {"greek": "Ἰουδαϊσμός", "translit": "Ioudaïsmós", "pronunciation": "ee-oo-dah-is-mos'", "derivation": "from (G2450);", "definition": "\"Judaism\", i.e. the Jewish faith and usages", "kjv": "Jews' religion."}, "G2455": {"greek": "Ἰούδας", "translit": "Ioúdas", "pronunciation": "ee-oo-das'", "derivation": "of Hebrew origin ((G3063));", "definition": "Judas (i.e. Jehudah), the name of ten Israelites; also of the posterity of one of them and its region", "kjv": "Juda(-h, -s); Jude."}, "G2456": {"greek": "Ἰουλία", "translit": "Ioulía", "pronunciation": "ee-oo-lee'-ah", "derivation": "feminine of the same as (G2457);", "definition": "Julia, a Christian woman", "kjv": "Julia."}, "G2457": {"greek": "Ἰούλιος", "translit": "Ioúlios", "pronunciation": "ee-oo'-lee-os", "derivation": "of Latin origin;", "definition": "Julius, a centurion", "kjv": "Julius."}, "G2458": {"greek": "Ἰουνιᾶς", "translit": "Iouniâs", "pronunciation": "ee-oo-nee'-as", "derivation": "of Latin origin;", "definition": "Junias, a Christian", "kjv": "Junias."}, "G2459": {"greek": "Ἰοῦστος", "translit": "Ioûstos", "pronunciation": "ee-ooce'-tos", "derivation": "of Latin origin (\"just\");", "definition": "Justus, the name of three Christian", "kjv": "Justus."}, "G2460": {"greek": "ἱππεύς", "translit": "hippeús", "pronunciation": "hip-yooce'", "derivation": "from (G2462);", "definition": "an equestrian, i.e. member of a cavalry corps", "kjv": "horseman."}, "G2461": {"greek": "ἱππικόν", "translit": "hippikón", "pronunciation": "hip-pee-kon'", "derivation": "neuter of a derivative of (G2462);", "definition": "the cavalry force", "kjv": "horse(-men)."}, "G2462": {"greek": "ἵππος", "translit": "híppos", "pronunciation": "hip'-pos", "derivation": "of uncertain affinity;", "definition": "a horse", "kjv": "horse."}, "G2463": {"greek": "ἶρις", "translit": "îris", "pronunciation": "ee'-ris", "derivation": "perhaps from (G2046) (as a symbol of the female messenger of the pagan deities);", "definition": "a rainbow (\"iris\")", "kjv": "rainbow."}, "G2464": {"greek": "Ἰσαάκ", "translit": "Isaák", "pronunciation": "ee-sah-ak'", "derivation": "of Hebrew origin ((G3327));", "definition": "Isaac (i.e. Jitschak), the son of Abraham", "kjv": "Isaac."}, "G2465": {"greek": "ἰσάγγελος", "translit": "isángelos", "pronunciation": "ee-sang'-el-los", "derivation": "from (G2470) and (G32);", "definition": "like an angel, i.e. angelic", "kjv": "equal unto the angels."}, "G2466": {"greek": "Ἰσαχάρ", "translit": "Isachár", "pronunciation": "ee-sakh-ar'", "derivation": "of Hebrew origin ((G3485));", "definition": "Isachar (i.e. Jissaskar), a son of Jacob (figuratively, his descendant)", "kjv": "Issachar."}, "G2469": {"greek": "Ἰσκαριώτης", "translit": "Iskariṓtēs", "pronunciation": "is-kar-ee-o'-tace", "derivation": "of Hebrew origin (probably (G377) and (G7149));", "definition": "inhabitant of Kerioth; Iscariotes (i.e. Keriothite), an epithet of Judas the traitor", "kjv": "Iscariot."}, "G2470": {"greek": "ἴσος", "translit": "ísos", "pronunciation": "ee'-sos", "derivation": "probably from (G1492) (through the idea of seeming);", "definition": "similar (in amount and kind)", "kjv": "+ agree, as much, equal, like."}, "G2471": {"greek": "ἰσότης", "translit": "isótēs", "pronunciation": "ee-sot'-ace", "derivation": "", "definition": "likeness (in condition or proportion); by implication, equity", "kjv": "equal(-ity)."}, "G2472": {"greek": "ἰσότιμος", "translit": "isótimos", "pronunciation": "ee-sot'-ee-mos", "derivation": "from (G2470) and (G5092);", "definition": "of equal value or honor", "kjv": "like precious."}, "G2473": {"greek": "ἰσόψυχος", "translit": "isópsychos", "pronunciation": "ee-sop'-soo-khos", "derivation": "from (G2470) and (G5590);", "definition": "of similar spirit", "kjv": "likeminded."}, "G2474": {"greek": "Ἰσραήλ", "translit": "Israḗl", "pronunciation": "is-rah-ale'", "derivation": "of Hebrew origin ((G3478));", "definition": "Israel (i.e. Jisrael), the adopted name of Jacob, including his descendants (literally or figuratively)", "kjv": "Israel."}, "G2475": {"greek": "Ἰσραηλίτης", "translit": "Israēlítēs", "pronunciation": "is-rah-ale-ee'-tace", "derivation": "from (G2474);", "definition": "an \"Israelite\", i.e. descendant of Israel (literally or figuratively)", "kjv": "Israelite."}, "G2476": {"greek": "ἵστημι", "translit": "hístēmi", "pronunciation": "his'-tay-mee", "derivation": "a prolonged form of a primary (of the same meaning, and used for it in certain tenses);", "definition": "to stand (transitively or intransitively), used in various applications (literally or figuratively)", "kjv": "abide, appoint, bring, continue, covenant, establish, hold up, lay, present, set (up), stanch, stand (by, forth, still, up)."}, "G2477": {"greek": "ἱστορέω", "translit": "historéō", "pronunciation": "his-tor-eh'-o", "derivation": "from a derivative of (G1492);", "definition": "to be knowing (learned), i.e. (by implication) to visit for information (interview)", "kjv": "see."}, "G2478": {"greek": "ἰσχυρός", "translit": "ischyrós", "pronunciation": "is-khoo-ros'", "derivation": "from (G2479);", "definition": "forcible (literally or figuratively)", "kjv": "boisterous, mighty(-ier), powerful, strong(-er, man), valiant."}, "G2479": {"greek": "ἰσχύς", "translit": "ischýs", "pronunciation": "is-khoos'", "derivation": "from a derivative of (force;", "definition": "compare , a form of (G2192)); forcefulness (literally or figuratively)", "kjv": "ability, might(-ily), power, strength."}, "G2480": {"greek": "ἰσχύω", "translit": "ischýō", "pronunciation": "is-khoo'-o", "derivation": "from (G2479);", "definition": "to have (or exercise) force (literally or figuratively)", "kjv": "be able, avail, can do(-not), could, be good, might, prevail, be of strength, be whole, + much work."}, "G2481": {"greek": "ἴσως", "translit": "ísōs", "pronunciation": "ee'-soce", "derivation": "adverb from (G2470);", "definition": "likely, i.e. perhaps", "kjv": "it may be."}, "G2482": {"greek": "Ἰταλία", "translit": "Italía", "pronunciation": "ee-tal-ee'-ah", "derivation": "probably of foreign origin;", "definition": "Italia, a region of Europe", "kjv": "Italy."}, "G2483": {"greek": "Ἰταλικός", "translit": "Italikós", "pronunciation": "ee-tal-ee-kos'", "derivation": "from (G2482);", "definition": "Italic, i.e. belonging to Italia", "kjv": "Italian."}, "G2484": {"greek": "Ἰτουραΐα", "translit": "Itouraḯa", "pronunciation": "ee-too-rah'-yah", "derivation": "of Hebrew origin ((G3195));", "definition": "Ituræa (i.e. Jetur), a region of Palestine", "kjv": "Ituræa."}, "G2485": {"greek": "ἰχθύδιον", "translit": "ichthýdion", "pronunciation": "ikh-thoo'-dee-on", "derivation": "diminutive from (G2486);", "definition": "a petty fish", "kjv": "little (small) fish."}, "G2486": {"greek": "ἰχθύς", "translit": "ichthýs", "pronunciation": "ikh-thoos'", "derivation": "of uncertain affinity;", "definition": "a fish", "kjv": "fish."}, "G2487": {"greek": "ἴχνος", "translit": "íchnos", "pronunciation": "ikh'-nos", "derivation": "from (to arrive; compare (G2240));", "definition": "a track (figuratively)", "kjv": "step."}, "G2488": {"greek": "Ἰωάθαμ", "translit": "Iōátham", "pronunciation": "ee-o-ath'-am", "derivation": "of Hebrew origin ((G3147));", "definition": "Joatham (i.e. Jotham), an Israelite", "kjv": "Joatham."}, "G2489": {"greek": "Ἰωάννα", "translit": "Iōánna", "pronunciation": "ee-o-an'-nah", "derivation": "feminine of the same as (G2491);", "definition": "Joanna, a Christian", "kjv": "Joanna."}, "G2490": {"greek": "Ἰωαννᾶς", "translit": "Iōannâs", "pronunciation": "ee-o-an-nas'", "derivation": "a form of (G2491);", "definition": "Joannas, an Israelite", "kjv": "Joannas."}, "G2491": {"greek": "Ἰωάννης", "translit": "Iōánnēs", "pronunciation": "ee-o-an'-nace", "derivation": "of Hebrew origin ((G3110));", "definition": "Joannes (i.e. Jochanan), the name of four Israelites", "kjv": "John."}, "G2492": {"greek": "Ἰώβ", "translit": "Iṓb", "pronunciation": "ee-obe'", "derivation": "of Hebrew origin ((G347));", "definition": "Job (i.e. Ijob), a patriarch", "kjv": "Job."}, "G2493": {"greek": "Ἰωήλ", "translit": "Iōḗl", "pronunciation": "ee-o-ale'", "derivation": "of Hebrew origin ((G3100));", "definition": "Joel, an Israelite", "kjv": "Joel."}, "G2494": {"greek": "Ἰωνάν", "translit": "Iōnán", "pronunciation": "ee-o-nan'", "derivation": "probably for (G2491) or (G2495);", "definition": "Jonan, an Israelite", "kjv": "Jonan."}, "G2495": {"greek": "Ἰωνᾶς", "translit": "Iōnâs", "pronunciation": "ee-o-nas'", "derivation": "of Hebrew origin ((G3124));", "definition": "Jonas (i.e. Jonah), the name of two Israelites", "kjv": "Jonas."}, "G2496": {"greek": "Ἰωράμ", "translit": "Iōrám", "pronunciation": "ee-o-ram'", "derivation": "of Hebrew origin ((G3141));", "definition": "Joram, an Israelite", "kjv": "Joram."}, "G2497": {"greek": "Ἰωρείμ", "translit": "Iōreím", "pronunciation": "ee-o-rime'", "derivation": "perhaps for (G2496);", "definition": "Jorim, an Israelite", "kjv": "Jorim."}, "G2498": {"greek": "Ἰωσαφάτ", "translit": "Iōsaphát", "pronunciation": "ee-o-saf-at'", "derivation": "of Hebrew origin ((G3092));", "definition": "Josaphat (i.e. Jehoshaphat), an Israelite", "kjv": "Josaphat."}, "G2499": {"greek": "Ἰωσή", "translit": "Iōsḗ", "pronunciation": "ee-o-say'", "derivation": "genitive case of (G2500);", "definition": "Jose, an Israelite", "kjv": "Jose."}, "G2500": {"greek": "Ἰωσῆς", "translit": "Iōsēs", "pronunciation": "ee-o-sace'", "derivation": "perhaps for (G2501);", "definition": "Joses, the name of two Israelites", "kjv": "Joses."}, "G2501": {"greek": "Ἰωσήφ", "translit": "Iōsḗph", "pronunciation": "ee-o-safe'", "derivation": "of Hebrew origin ((G3130));", "definition": "Joseph, the name of seven Israelites", "kjv": "Joseph."}, "G2502": {"greek": "Ἰωσίας", "translit": "Iōsías", "pronunciation": "ee-o-see'-as", "derivation": "of Hebrew origin ((G2977));", "definition": "Josias (i.e. Joshiah), an Israelite", "kjv": "Josias."}, "G2503": {"greek": "ἰῶτα", "translit": "iōta", "pronunciation": "ee-o'-tah", "derivation": "of Hebrew origin (the tenth letter of the Hebrew alphabet);", "definition": "\"iota\", the name of the eighth letter of the Greek alphabet, put (figuratively) for a very small part of anything", "kjv": "jot."}, "G2504": {"greek": "κἀγώ", "translit": "kagṓ", "pronunciation": "kag-o'", "derivation": "from (G2532) and (G1473);", "definition": "so also the dative case , and accusative case and (or also, even, etc.) I, (to) me", "kjv": "(and, even, even so, so) I (also, in like wise), both me, me also."}, "G2505": {"greek": "καθά", "translit": "kathá", "pronunciation": "kath-ah'", "derivation": "from (G2596) and the neuter plural of (G3739);", "definition": "according to which things, i.e. just as", "kjv": "as."}, "G2506": {"greek": "καθαίρεσις", "translit": "kathaíresis", "pronunciation": "kath-ah'-ee-res-is", "derivation": "from (G2507);", "definition": "demolition; figuratively, extinction", "kjv": "destruction, pulling down."}, "G2507": {"greek": "καθαιρέω", "translit": "kathairéō", "pronunciation": "kath-ahee-reh'-o", "derivation": "from (G2596) and (G138) (including its alternate);", "definition": "to lower (or with violence) demolish (literally or figuratively)", "kjv": "cast (pull, put, take) down, destroy."}, "G2508": {"greek": "καθαίρω", "translit": "kathaírō", "pronunciation": "kath-ah'-ee-ro", "derivation": "from (G2513);", "definition": "to cleanse, i.e. (specially) to prune; figuratively, to expiate", "kjv": "purge."}, "G2509": {"greek": "καθάπερ", "translit": "katháper", "pronunciation": "kath-ap'-er", "derivation": "from (G2505) and (G4007);", "definition": "exactly as", "kjv": "(even, as well) as."}, "G2510": {"greek": "καθάπτω", "translit": "katháptō", "pronunciation": "kath-ap'-to", "derivation": "from (G2596) and (G680);", "definition": "to seize upon", "kjv": "fasten on."}, "G2511": {"greek": "καθαρίζω", "translit": "katharízō", "pronunciation": "kath-ar-id'-zo", "derivation": "from (G2513);", "definition": "to cleanse (literally or figuratively)", "kjv": "(make) clean(-se), purge, purify."}, "G2512": {"greek": "καθαρισμός", "translit": "katharismós", "pronunciation": "kath-ar-is-mos'", "derivation": "from (G2511);", "definition": "a washing off, i.e. (ceremonially) ablution, (morally) expiation", "kjv": "cleansing, + purge, purification(-fying)."}, "G2513": {"greek": "καθαρός", "translit": "katharós", "pronunciation": "kath-ar-os'", "derivation": "of uncertain affinity;", "definition": "clean (literally or figuratively)", "kjv": "clean, clear, pure."}, "G2514": {"greek": "καθαρότης", "translit": "katharótēs", "pronunciation": "kath-ar-ot'-ace", "derivation": "from (G2513);", "definition": "cleanness (ceremonially)", "kjv": "purification."}, "G2515": {"greek": "καθέδρα", "translit": "kathédra", "pronunciation": "kath-ed'-rah", "derivation": "from (G2596) and the same as (G1476);", "definition": "a bench (literally or figuratively)", "kjv": "seat."}, "G2516": {"greek": "καθέζομαι", "translit": "kathézomai", "pronunciation": "kath-ed'-zom-ahee", "derivation": "from (G2596) and the base of (G1476);", "definition": "to sit down", "kjv": "sit."}, "G2517": {"greek": "καθεξῆς", "translit": "kathexēs", "pronunciation": "kath-ex-ace'", "derivation": "from (G2596) and (G1836);", "definition": "thereafter, i.e. consecutively; as a noun (by ellipsis of noun) a subsequent person or time", "kjv": "after(-ward), by (in) order."}, "G2518": {"greek": "καθεύδω", "translit": "katheúdō", "pronunciation": "kath-yoo'-do", "derivation": "from (G2596) and (to sleep);", "definition": "to lie down to rest, i.e. (by implication) to fall asleep (literally or figuratively)", "kjv": "(be a-)sleep."}, "G2519": {"greek": "καθηγητής", "translit": "kathēgētḗs", "pronunciation": "kath-ayg-ay-tace'", "derivation": "from a compound of (G2596) and (G2233);", "definition": "a guide, i.e. (figuratively) a teacher", "kjv": "master."}, "G2520": {"greek": "καθήκω", "translit": "kathḗkō", "pronunciation": "kath-ay'-ko", "derivation": "from (G2596) and (G2240);", "definition": "to reach to, i.e. (neuter of present active participle, figuratively as adjective) becoming", "kjv": "convenient, fit."}, "G2521": {"greek": "κάθημαι", "translit": "káthēmai", "pronunciation": "kath'-ay-mahee", "derivation": "from (G2596);", "definition": "and (to sit; akin to the base of (G1476)); to sit down; figuratively, to remain, reside", "kjv": "dwell, sit (by, down)."}, "G2522": {"greek": "καθημερινός", "translit": "kathēmerinós", "pronunciation": "kath-ay-mer-ee-nos'", "derivation": "from (G2596) and (G2250);", "definition": "quotidian", "kjv": "daily."}, "G2523": {"greek": "καθίζω", "translit": "kathízō", "pronunciation": "kath-id'-zo", "derivation": "another (active) form for (G2516);", "definition": "to seat down, i.e. set (figuratively, appoint); intransitively, to sit (down); figuratively, to settle (hover, dwell)", "kjv": "continue, set, sit (down), tarry."}, "G2524": {"greek": "καθίημι", "translit": "kathíēmi", "pronunciation": "kath-ee'-ay-mee", "derivation": "from (G2596);", "definition": "and (to send); to lower", "kjv": "let down."}, "G2525": {"greek": "καθίστημι", "translit": "kathístēmi", "pronunciation": "kath-is'-tay-mee", "derivation": "from (G2596) and (G2476);", "definition": "to place down (permanently), i.e. (figuratively) to designate, constitute, convoy", "kjv": "appoint, be, conduct, make, ordain, set."}, "G2526": {"greek": "καθό", "translit": "kathó", "pronunciation": "kath-o'", "derivation": "from (G2596) and (G3739);", "definition": "according to which thing, i.e. precisely as, in proportion as", "kjv": "according to that, (inasmuch) as."}, "G2527": {"greek": "καθόλου", "translit": "kathólou", "pronunciation": "kath-ol'-oo", "derivation": "from (G2596) and (G3650);", "definition": "on the whole, i.e. entirely", "kjv": "at all."}, "G2528": {"greek": "καθοπλίζω", "translit": "kathoplízō", "pronunciation": "kath-op-lid'-zo", "derivation": "from (G2596);", "definition": "and (G3695); to equip fully with armor", "kjv": "arm."}, "G2529": {"greek": "καθοράω", "translit": "kathoráō", "pronunciation": "kath-or-ah'-o", "derivation": "from (G2596) and (G3708);", "definition": "to behold fully, i.e. (figuratively) distinctly apprehend", "kjv": "clearly see."}, "G2530": {"greek": "καθότι", "translit": "kathóti", "pronunciation": "kath-ot'-ee", "derivation": "from (G2596);", "definition": "and (G3739) and (G5100); according to which certain thing, i.e. as far (or inasmuch) as", "kjv": "(according, forasmuch) as, because (that)."}, "G2531": {"greek": "καθώς", "translit": "kathṓs", "pronunciation": "kath-oce'", "derivation": "from (G2596) and (G5613);", "definition": "just (or inasmuch) as, that", "kjv": "according to, (according, even) as, how, when."}, "G2532": {"greek": "καί", "translit": "kaí", "pronunciation": "kahee", "derivation": "apparently, a primary particle, having a copulative and sometimes also a cumulative force;", "definition": "and, also, even, so then, too, etc.; often used in connection (or composition) with other particles or small words", "kjv": "and, also, both, but, even, for, if, or, so, that, then, therefore, when, yet."}, "G2533": {"greek": "Καϊάφας", "translit": "Kaïáphas", "pronunciation": "kah-ee-af'-as", "derivation": "of Chaldee origin;", "definition": "the dell; Caiaphas (i.e. Cajepha), an Israelite", "kjv": "Caiaphas."}, "G2535": {"greek": "Κάϊν", "translit": "Káïn", "pronunciation": "kah'-in", "derivation": "of Hebrew origin ((G7014));", "definition": "Cain, (i.e. Cajin), the son of Adam", "kjv": "Cain."}, "G2536": {"greek": "Καϊνάν", "translit": "Kaïnán", "pronunciation": "kah-ee-nan'", "derivation": "of Hebrew origin ((G7018));", "definition": "Cainan (i.e. Kenan), the name of two patriarchs", "kjv": "Cainan."}, "G2537": {"greek": "καινός", "translit": "kainós", "pronunciation": "kahee-nos'", "derivation": "of uncertain affinity;", "definition": "new (especially in freshness; while (G3501) is properly so with respect to age", "kjv": "new."}, "G2538": {"greek": "καινότης", "translit": "kainótēs", "pronunciation": "kahee-not'-ace", "derivation": "from (G2537);", "definition": "renewal (figuratively)", "kjv": "newness."}, "G2539": {"greek": "καίπερ", "translit": "kaíper", "pronunciation": "kah'-ee-per", "derivation": "from (G2532) and (G4007);", "definition": "and indeed, i.e. nevertheless or notwithstanding", "kjv": "and yet, although."}, "G2540": {"greek": "καιρός", "translit": "kairós", "pronunciation": "kahee-ros'", "derivation": "of uncertain affinity;", "definition": "an occasion, i.e. set or proper time", "kjv": "X always, opportunity, (convenient, due) season, (due, short, while) time, a while."}, "G2541": {"greek": "Καῖσαρ", "translit": "Kaîsar", "pronunciation": "kah'-ee-sar", "derivation": "of Latin origin;", "definition": "Cæsar, a title of the Roman emperor", "kjv": "Cæsar."}, "G2542": {"greek": "Καισάρεια", "translit": "Kaisáreia", "pronunciation": "kahee-sar'-i-a", "derivation": "from (G2541);", "definition": "Cæsaria, the name of two places in Palestine", "kjv": "Cæsarea."}, "G2543": {"greek": "καίτοι", "translit": "kaítoi", "pronunciation": "kah'-ee-toy", "derivation": "from (G2532) and (G5104);", "definition": "and yet, i.e. nevertheless", "kjv": "although."}, "G2544": {"greek": "καίτοιγε", "translit": "kaítoige", "pronunciation": "kah'-ee-toyg-eh", "derivation": "from (G2543) and (G1065);", "definition": "and yet indeed, i.e. although really", "kjv": "nevertheless, though."}, "G2545": {"greek": "καίω", "translit": "kaíō", "pronunciation": "kah'-yo", "derivation": "apparently a primary verb;", "definition": "to set on fire, i.e. kindle or (by implication) consume", "kjv": "burn, light."}, "G2546": {"greek": "κἀκεῖ", "translit": "kakeî", "pronunciation": "kak-i'", "derivation": "from (G2532) and (G1563);", "definition": "likewise in that place", "kjv": "and there, there (thither) also."}, "G2547": {"greek": "κἀκεῖθεν", "translit": "kakeîthen", "pronunciation": "kak-i'-then", "derivation": "from (G2532) and (G1564);", "definition": "likewise from that place (or time)", "kjv": "and afterward (from) (thence), thence also."}, "G2548": {"greek": "κἀκεῖνος", "translit": "kakeînos", "pronunciation": "kak-i'-nos", "derivation": "from (G2532) and (G1565);", "definition": "likewise that (or those)", "kjv": "and him (other, them), even he, him also, them (also), (and) they."}, "G2549": {"greek": "κακία", "translit": "kakía", "pronunciation": "kak-ee'-ah", "derivation": "from (G2556);", "definition": "badness, i.e. (subjectively) depravity, or (actively) malignity, or (passively) trouble", "kjv": "evil, malice(-iousness), naughtiness, wickedness."}, "G2550": {"greek": "κακοήθεια", "translit": "kakoḗtheia", "pronunciation": "kak-o-ay'-thi-ah", "derivation": "from a compound of (G2556) and (G2239);", "definition": "bad character, i.e. (specially) mischievousness", "kjv": "malignity."}, "G2551": {"greek": "κακολογέω", "translit": "kakologéō", "pronunciation": "kak-ol-og-eh'-o", "derivation": "from a compound of (G2556) and (G3056);", "definition": "to revile", "kjv": "curse, speak evil of."}, "G2552": {"greek": "κακοπάθεια", "translit": "kakopátheia", "pronunciation": "kak-op-ath'-i-ah", "derivation": "from a compound of (G2256) and (G3806);", "definition": "hardship", "kjv": "suffering affliction."}, "G2553": {"greek": "κακοπαθέω", "translit": "kakopathéō", "pronunciation": "kak-op-ath-eh'-o", "derivation": "from the same as (G2552);", "definition": "to undergo hardship", "kjv": "be afflicted, endure afflictions (hardness), suffer trouble."}, "G2554": {"greek": "κακοποιέω", "translit": "kakopoiéō", "pronunciation": "kak-op-oy-eh'-o", "derivation": "from (G2555);", "definition": "to be a bad-doer, i.e. (objectively) to injure, or (genitive) to sin", "kjv": "do(ing) evil."}, "G2555": {"greek": "κακοποιός", "translit": "kakopoiós", "pronunciation": "kak-op-oy-os'", "derivation": "from (G2556) and (G4160);", "definition": "a bad-doer; (specially), a criminal", "kjv": "evil-doer, malefactor."}, "G2556": {"greek": "κακός", "translit": "kakós", "pronunciation": "kak-os'", "derivation": "apparently a primary word;", "definition": "worthless (intrinsically, such; whereas (G4190) properly refers to effects), i.e. (subjectively) depraved, or (objectively) injurious", "kjv": "bad, evil, harm, ill, noisome, wicked."}, "G2557": {"greek": "κακοῦργος", "translit": "kakoûrgos", "pronunciation": "kak-oor'-gos", "derivation": "from (G2556) and the base of (G2041);", "definition": "a wrong-doer, i.e. criminal", "kjv": "evil-doer, malefactor."}, "G2558": {"greek": "κακουχέω", "translit": "kakouchéō", "pronunciation": "kak-oo-kheh'-o", "derivation": "from a presumed compound of (G2556) and (G2192);", "definition": "to maltreat", "kjv": "which suffer adversity, torment."}, "G2559": {"greek": "κακόω", "translit": "kakóō", "pronunciation": "kak-o'-o", "derivation": "from (G2556);", "definition": "to injure; figuratively, to exasperate", "kjv": "make evil affected, entreat evil, harm, hurt, vex."}, "G2560": {"greek": "κακῶς", "translit": "kakōs", "pronunciation": "kak-oce'", "derivation": "from (G2556);", "definition": "badly (physically or morally)", "kjv": "amiss, diseased, evil, grievously, miserably, sick, sore."}, "G2561": {"greek": "κάκωσις", "translit": "kákōsis", "pronunciation": "kak'-o-sis", "derivation": "from (G2559);", "definition": "maltreatment", "kjv": "affliction."}, "G2562": {"greek": "καλάμη", "translit": "kalámē", "pronunciation": "kal-am'-ay", "derivation": "feminine of (G2563);", "definition": "a stalk of grain, i.e. (collectively) stubble", "kjv": "stubble."}, "G2563": {"greek": "κάλαμος", "translit": "kálamos", "pronunciation": "kal'-am-os", "derivation": "of uncertain affinity;", "definition": "a reed (the plant or its stem, or that of a similar plant); by implication, a pen", "kjv": "pen, reed."}, "G2564": {"greek": "καλέω", "translit": "kaléō", "pronunciation": "kal-eh'-o", "derivation": "akin to the base of (G2753);", "definition": "to \"call\" (properly, aloud, but used in a variety of applications, directly or otherwise)", "kjv": "bid, call (forth), (whose, whose sur-)name (was (called))."}, "G2565": {"greek": "καλλιέλαιος", "translit": "kalliélaios", "pronunciation": "kal-le-el'-ah-yos", "derivation": "from the base of (G2566) and (G1636);", "definition": "a cultivated olive tree, i.e. a domesticated or improved one", "kjv": "good olive tree."}, "G2567": {"greek": "καλοδιδάσκαλος", "translit": "kalodidáskalos", "pronunciation": "kal-od-id-as'-kal-os", "derivation": "from (G2570) and (G1320);", "definition": "a teacher of the right", "kjv": "teacher of good things."}, "G2569": {"greek": "καλοποιέω", "translit": "kalopoiéō", "pronunciation": "kal-op-oy-eh'-o", "derivation": "from (G2570) and (G4160);", "definition": "to do well, i.e. live virtuously", "kjv": "well doing."}, "G2570": {"greek": "καλός", "translit": "kalós", "pronunciation": "kal-os'", "derivation": "of uncertain affinity;", "definition": "properly, beautiful, but chiefly (figuratively) good (literally or morally), i.e. valuable or virtuous (for appearance or use, and thus distinguished from (G18), which is properly intrinsic)", "kjv": "X better, fair, good(-ly), honest, meet, well, worthy."}, "G2571": {"greek": "κάλυμα", "translit": "kályma", "pronunciation": "kal'-oo-mah", "derivation": "from (G2572);", "definition": "a cover, i.e. veil", "kjv": "vail."}, "G2572": {"greek": "καλύπτω", "translit": "kalýptō", "pronunciation": "kal-oop'-to", "derivation": "akin to (G2813) and (G2928);", "definition": "to cover up (literally or figuratively)", "kjv": "cover, hide."}, "G2573": {"greek": "καλῶς", "translit": "kalōs", "pronunciation": "kal-oce'", "derivation": "adverb from (G2570);", "definition": "well (usually morally)", "kjv": "(in a) good (place), honestly, + recover, (full) well."}, "G2574": {"greek": "κάμηλος", "translit": "kámēlos", "pronunciation": "kam'-ay-los", "derivation": "of Hebrew origin ((G1581));", "definition": "a \"camel\"", "kjv": "camel."}, "G2575": {"greek": "κάμινος", "translit": "káminos", "pronunciation": "kam'-ee-nos", "derivation": "probably from (G2545);", "definition": "a furnace", "kjv": "furnace."}, "G2576": {"greek": "καμμύω", "translit": "kammýō", "pronunciation": "kam-moo'-o", "derivation": "from a compound of (G2596) and the base of (G3466);", "definition": "to shut down, i.e. close the eyes", "kjv": "close."}, "G2577": {"greek": "κάμνω", "translit": "kámnō", "pronunciation": "kam'-no", "derivation": "apparently a primary verb;", "definition": "properly, to toil, i.e. (by implication) to tire (figuratively, faint, sicken)", "kjv": "faint, sick, be wearied."}, "G2578": {"greek": "κάμπτω", "translit": "kámptō", "pronunciation": "kamp'-to", "derivation": "apparently a primary verb;", "definition": "to bend", "kjv": "bow."}, "G2579": {"greek": "κἄν", "translit": "kán", "pronunciation": "kan", "derivation": "from (G2532) and (G1437);", "definition": "and (or even) if", "kjv": "and (also) if (so much as), if but, at the least, though, yet."}, "G2580": {"greek": "Κανᾶ", "translit": "Kanâ", "pronunciation": "kan-ah'", "derivation": "of Hebrew origin (compare (G7071));", "definition": "Cana, a place in Palestine", "kjv": "Cana."}, "G2581": {"greek": "Κανανίτης", "translit": "Kananítēs", "pronunciation": "kan-an-ee'-tace", "derivation": "of Chaldee origin (compare (G7067));", "definition": "zealous; Cananites, an epithet", "kjv": "Canaanite (by mistake for a derivative from (G5477))."}, "G2582": {"greek": "Κανδάκη", "translit": "Kandákē", "pronunciation": "kan-dak'-ay", "derivation": "of foreign origin;", "definition": "Candacè, an Egyptian queen", "kjv": "Candace."}, "G2583": {"greek": "κανών", "translit": "kanṓn", "pronunciation": "kan-ohn'", "derivation": "from (a straight reed, i.e. rod);", "definition": "a rule (\"canon\"), i.e. (figuratively) a standard (of faith and practice); by implication, a boundary, i.e. (figuratively) a sphere (of activity)", "kjv": "line, rule."}, "G2584": {"greek": "Καπερναούμ", "translit": "Kapernaoúm", "pronunciation": "cap-er-nah-oom'", "derivation": "of Hebrew origin (probably (G3723) and (G5151));", "definition": "Capernaum (i.e. Caphanachum), a place in Palestine", "kjv": "Capernaum."}, "G2585": {"greek": "καπηλεύω", "translit": "kapēleúō", "pronunciation": "kap-ale-yoo'-o", "derivation": "from (a huckster);", "definition": "to retail, i.e. (by implication) to adulterate (figuratively)", "kjv": "corrupt."}, "G2586": {"greek": "καπνός", "translit": "kapnós", "pronunciation": "kap-nos'", "derivation": "of uncertain affinity;", "definition": "smoke", "kjv": "smoke."}, "G2587": {"greek": "Καππαδοκία", "translit": "Kappadokía", "pronunciation": "kap-pad-ok-ee'-ah", "derivation": "of foreign origin;", "definition": "Cappadocia, a region of Asia Minor", "kjv": "Cappadocia."}, "G2588": {"greek": "καρδία", "translit": "kardía", "pronunciation": "kar-dee'-ah", "derivation": "prolonged from a primary (Latin cor, \"heart\");", "definition": "the heart, i.e. (figuratively) the thoughts or feelings (mind); also (by analogy) the middle", "kjv": "(+ broken-)heart(-ed)."}, "G2589": {"greek": "καρδιογνώστης", "translit": "kardiognṓstēs", "pronunciation": "kar-dee-og-noce'-tace", "derivation": "from (G2588) and (G1097);", "definition": "a heart-knower", "kjv": "which knowest the hearts."}, "G2590": {"greek": "καρπός", "translit": "karpós", "pronunciation": "kar-pos'", "derivation": "probably from the base of (G726);", "definition": "fruit (as plucked), literally or figuratively", "kjv": "fruit."}, "G2591": {"greek": "Κάρπος", "translit": "Kárpos", "pronunciation": "kar'-pos", "derivation": "perhaps for (G2590);", "definition": "Carpus, probably a Christian", "kjv": "Carpus."}, "G2592": {"greek": "καρποφορέω", "translit": "karpophoréō", "pronunciation": "kar-pof-or-eh'-o", "derivation": "from (G2593);", "definition": "to be fertile (literally or figuratively)", "kjv": "be (bear, bring forth) fruit(-ful)."}, "G2593": {"greek": "καρποφόρος", "translit": "karpophóros", "pronunciation": "kar-pof-or'-os", "derivation": "from (G2590) and (G5342);", "definition": "fruitbearing (figuratively)", "kjv": "fruitful."}, "G2594": {"greek": "καρτερέω", "translit": "karteréō", "pronunciation": "kar-ter-eh'-o", "derivation": "from a derivative of (G2904) (transposed);", "definition": "to be strong, i.e. (figuratively) steadfast (patient)", "kjv": "endure."}, "G2595": {"greek": "κάρφος", "translit": "kárphos", "pronunciation": "kar'-fos", "derivation": "from (to wither);", "definition": "a dry twig or straw", "kjv": "mote."}, "G2596": {"greek": "κατά", "translit": "katá", "pronunciation": "kat-ah'", "derivation": "a primary particle;", "definition": "(prepositionally) down (in place or time), in varied relations (according to the case (genitive, dative or accusative) with which it is joined)", "kjv": "about, according as (to), after, against, (when they were) X alone, among, and, X apart, (even, like) as (concerning, pertaining to touching), X aside, at, before, beyond, by, to the charge of, (charita-)bly, concerning, + covered, (dai-)ly, down, every, (+ far more) exceeding, X more excellent, for, from … to, godly, in(-asmuch, divers, every, -to, respect of), … by, after the manner of, + by any means, beyond (out of) measure, X mightily, more, X natural, of (up-)on (X part), out (of every), over against, (+ your) X own, + particularly, so, through(-oughout, -oughout every), thus, (un-)to(-gether, -ward), X uttermost, where(-by), with."}, "G2597": {"greek": "καταβαίνω", "translit": "katabaínō", "pronunciation": "kat-ab-ah'-ee-no", "derivation": "from (G2596) and the base of (G939);", "definition": "to descend (literally or figuratively)", "kjv": "come (get, go, step) down, fall (down)."}, "G2598": {"greek": "καταβάλλω", "translit": "katabállō", "pronunciation": "kat-ab-al'-lo", "derivation": "from (G2596) and (G906);", "definition": "to throw down", "kjv": "cast down, lay."}, "G2599": {"greek": "καταβαρέω", "translit": "katabaréō", "pronunciation": "kat-ab-ar-eh'-o", "derivation": "from (G2596) and (G916);", "definition": "to impose upon", "kjv": "burden."}, "G2600": {"greek": "κατάβασις", "translit": "katábasis", "pronunciation": "kat-ab'-as-is", "derivation": "from (G2597);", "definition": "a declivity", "kjv": "descent."}, "G2601": {"greek": "καταβιβάζω", "translit": "katabibázō", "pronunciation": "kat-ab-ib-ad'-zo", "derivation": "from (G2596) and a derivative of the base of (G939);", "definition": "to cause to go down, i.e. precipitate", "kjv": "bring (thrust) down."}, "G2602": {"greek": "καταβολή", "translit": "katabolḗ", "pronunciation": "kat-ab-ol-ay'", "derivation": "from (G2598);", "definition": "a deposition, i.e. founding; figuratively, conception", "kjv": "conceive, foundation."}, "G2603": {"greek": "καταβραβεύω", "translit": "katabrabeúō", "pronunciation": "kat-ab-rab-yoo'-o", "derivation": "from (G2596) and (G1018) (in its original sense);", "definition": "to award the price against, i.e. (figuratively) to defraud (of salvation)", "kjv": "beguile of reward."}, "G2604": {"greek": "καταγγελεύς", "translit": "katangeleús", "pronunciation": "kat-ang-gel-yooce'", "derivation": "from (G2605);", "definition": "a proclaimer", "kjv": "setter forth."}, "G2605": {"greek": "καταγγέλλω", "translit": "katangéllō", "pronunciation": "kat-ang-gel'-lo", "derivation": "from (G2596) and the base of (G32);", "definition": "to proclaim, promulgate", "kjv": "declare, preach, shew, speak of, teach."}, "G2606": {"greek": "καταγελάω", "translit": "katageláō", "pronunciation": "kat-ag-el-ah'-o", "derivation": "", "definition": "to laugh down, i.e. deride", "kjv": "laugh to scorn."}, "G2607": {"greek": "καταγινώσκω", "translit": "kataginṓskō", "pronunciation": "kat-ag-in-o'-sko", "derivation": "from (G2596) and (G1097);", "definition": "to note against, i.e. find fault with", "kjv": "blame, condemn."}, "G2608": {"greek": "κατάγνυμι", "translit": "katágnymi", "pronunciation": "kat-ag'-noo-mee", "derivation": "from (G2596) and the base of (G4486);", "definition": "to rend in pieces, i.e. crack apart", "kjv": "break."}, "G2609": {"greek": "κατάγω", "translit": "katágō", "pronunciation": "kat-ag'-o", "derivation": "from (G2596) and (G71);", "definition": "to lead down; specially, to moor a vessel", "kjv": "bring (down, forth), (bring to) land, touch."}, "G2610": {"greek": "καταγωνίζομαι", "translit": "katagōnízomai", "pronunciation": "kat-ag-o-nid'-zom-ahee", "derivation": "from (G2596) and (G75);", "definition": "to struggle against, i.e. (by implication) to overcome", "kjv": "subdue."}, "G2611": {"greek": "καταδέω", "translit": "katadéō", "pronunciation": "kat-ad-eh'-o", "derivation": "from (G2596) and (G1210);", "definition": "to tie down, i.e. bandage (a wound)", "kjv": "bind up."}, "G2612": {"greek": "κατάδηλος", "translit": "katádēlos", "pronunciation": "kat-ad'-ay-los", "derivation": "from (G2596) intensive and (G1212);", "definition": "manifest", "kjv": "far more evident."}, "G2613": {"greek": "καταδικάζω", "translit": "katadikázō", "pronunciation": "kat-ad-ik-ad'-zo", "derivation": "from (G2596) and a derivative of (G1349);", "definition": "to adjudge against, i.e. pronounce guilty", "kjv": "condemn."}, "G2614": {"greek": "καταδιώκω", "translit": "katadiṓkō", "pronunciation": "kat-ad-ee-o'-ko", "derivation": "from (G2596) and (G1377);", "definition": "to hunt down, i.e. search for", "kjv": "follow after."}, "G2615": {"greek": "καταδουλόω", "translit": "katadoulóō", "pronunciation": "kat-ad-oo-lo'-o", "derivation": "from (G2596) and (G1402);", "definition": "to enslave utterly", "kjv": "bring into bondage."}, "G2616": {"greek": "καταδυναστεύω", "translit": "katadynasteúō", "pronunciation": "kat-ad-oo-nas-tyoo'-o", "derivation": "from (G2596) and a derivative of (G1413);", "definition": "to exercise dominion against, i.e. oppress", "kjv": "oppress."}, "G2617": {"greek": "καταισχύνω", "translit": "kataischýnō", "pronunciation": "kat-ahee-skhoo'-no", "derivation": "from (G2596) and (G153);", "definition": "to shame down, i.e. disgrace or (by implication) put to the blush", "kjv": "confound, dishonour, (be a-, make a-)shame(-d)."}, "G2618": {"greek": "κατακαίω", "translit": "katakaíō", "pronunciation": "kat-ak-ah'-ee-o", "derivation": "from (G2596) and (G2545);", "definition": "to burn down (to the ground), i.e. consume wholly", "kjv": "burn (up, utterly)."}, "G2619": {"greek": "κατακαλύπτω", "translit": "katakalýptō", "pronunciation": "kat-ak-al-oop'-to", "derivation": "from (G2596) and (G2572);", "definition": "to cover wholly, i.e. veil", "kjv": "cover, hide."}, "G2620": {"greek": "κατακαυχάομαι", "translit": "katakaucháomai", "pronunciation": "kat-ak-ow-khah'-om-ahee", "derivation": "from (G2596) and (G2744);", "definition": "to exult against (i.e. over)", "kjv": "boast (against), glory, rejoice against."}, "G2621": {"greek": "κατάκειμαι", "translit": "katákeimai", "pronunciation": "kat-ak'-i-mahee", "derivation": "from (G2596) and (G2749);", "definition": "to lie down, i.e. (by implication) be sick; specially, to recline at a meal", "kjv": "keep, lie, sit at meat (down)."}, "G2622": {"greek": "κατακλάω", "translit": "katakláō", "pronunciation": "kat-ak-lah'-o", "derivation": "from (G2596) and (G2806);", "definition": "to break down, i.e. divide", "kjv": "break."}, "G2623": {"greek": "κατακλείω", "translit": "katakleíō", "pronunciation": "kat-ak-li'-o", "derivation": "from (G2596) and (G2808);", "definition": "to shut down (in a dungeon), i.e. incarcerate", "kjv": "shut up."}, "G2624": {"greek": "κατακληροδοτέω", "translit": "kataklērodotéō", "pronunciation": "kat-ak-lay-rod-ot-eh'-o", "derivation": "from (G2596) and a derivative of a compound of (G2819) and (G1325);", "definition": "to be a giver of lots to each, i.e. (by implication) to apportion an estate", "kjv": "divide by lot."}, "G2625": {"greek": "κατακλίνω", "translit": "kataklínō", "pronunciation": "kat-ak-lee'-no", "derivation": "from (G2596) and (G2827);", "definition": "to recline down, i.e. (specially) to take a place at table", "kjv": "(make) sit down (at meat)."}, "G2626": {"greek": "κατακλύζω", "translit": "kataklýzō", "pronunciation": "kat-ak-lood'-zo", "derivation": "from (G2596) and the base of (G2830);", "definition": "to dash (wash) down, i.e. (by implication) to deluge", "kjv": "overflow."}, "G2627": {"greek": "κατακλυσμός", "translit": "kataklysmós", "pronunciation": "kat-ak-looce-mos'", "derivation": "from (G2626);", "definition": "an inundation", "kjv": "flood."}, "G2628": {"greek": "κατακολουθέω", "translit": "katakolouthéō", "pronunciation": "kat-ak-ol-oo-theh'-o", "derivation": "from (G2596) and (G190);", "definition": "to accompany closely", "kjv": "follow (after)."}, "G2629": {"greek": "κατακόπτω", "translit": "katakóptō", "pronunciation": "kat-ak-op'-to", "derivation": "from (G2596) and (G2875);", "definition": "to chop down, i.e. mangle", "kjv": "cut."}, "G2630": {"greek": "κατακρημνίζω", "translit": "katakrēmnízō", "pronunciation": "kat-ak-rame-nid'-zo", "derivation": "from (G2596) and a derivative of (G2911);", "definition": "to precipitate down", "kjv": "cast down headlong."}, "G2631": {"greek": "κατάκριμα", "translit": "katákrima", "pronunciation": "kat-ak'-ree-mah", "derivation": "from (G2632);", "definition": "an adverse sentence (the verdict)", "kjv": "condemnation."}, "G2632": {"greek": "κατακρίνω", "translit": "katakrínō", "pronunciation": "kat-ak-ree'-no", "derivation": "from (G2596) and (G2919);", "definition": "to judge against, i.e. sentence", "kjv": "condemn, damn."}, "G2633": {"greek": "κατάκρισις", "translit": "katákrisis", "pronunciation": "kat-ak'-ree-sis", "derivation": "from (G2632);", "definition": "sentencing adversely (the act)", "kjv": "condemn(-ation)."}, "G2634": {"greek": "κατακυριεύω", "translit": "katakyrieúō", "pronunciation": "kat-ak-oo-ree-yoo'-o", "derivation": "from (G2596) and (G2961);", "definition": "to lord against, i.e. control, subjugate", "kjv": "exercise dominion over (lordship), be lord over, overcome."}, "G2635": {"greek": "καταλαλέω", "translit": "katalaléō", "pronunciation": "kat-al-al-eh'-o", "derivation": "from (G2637);", "definition": "to be a traducer, i.e. to slander", "kjv": "speak against (evil of)."}, "G2636": {"greek": "καταλαλία", "translit": "katalalía", "pronunciation": "kat-al-al-ee'-ah", "derivation": "from (G2637);", "definition": "defamation", "kjv": "backbiting, evil speaking."}, "G2637": {"greek": "κατάλαλος", "translit": "katálalos", "pronunciation": "kat-al'-al-os", "derivation": "from (G2596) and the base of (G2980);", "definition": "talkative against, i.e. a slanderer", "kjv": "backbiter."}, "G2638": {"greek": "καταλαμβάνω", "translit": "katalambánō", "pronunciation": "kat-al-am-ban'-o", "derivation": "from (G2596) and (G2983);", "definition": "to take eagerly, i.e. seize, possess, etc. (literally or figuratively)", "kjv": "apprehend, attain, come upon, comprehend, find, obtain, perceive, (over-)take."}, "G2639": {"greek": "καταλέγω", "translit": "katalégō", "pronunciation": "kat-al-eg'-o", "derivation": "from (G2596) and (G3004) (in its original meaning);", "definition": "to lay down, i.e. (figuratively) to enrol", "kjv": "take into the number."}, "G2641": {"greek": "καταλείπω", "translit": "kataleípō", "pronunciation": "kat-al-i'-po", "derivation": "from (G2596) and (G3007);", "definition": "to leave down, i.e. behind; by implication, to abandon, have remaining", "kjv": "forsake, leave, reserve."}, "G2642": {"greek": "καταλιθάζω", "translit": "katalitházō", "pronunciation": "kat-al-ith-ad'-zo", "derivation": "from (G2596) and (G3034);", "definition": "to stone down, i.e. to death", "kjv": "stone."}, "G2643": {"greek": "καταλλαγή", "translit": "katallagḗ", "pronunciation": "kat-al-lag-ay'", "derivation": "from (G2644);", "definition": "exchange (figuratively, adjustment), i.e. restoration to (the divine) favor", "kjv": "atonement, reconciliation(-ing)."}, "G2644": {"greek": "καταλλάσσω", "translit": "katallássō", "pronunciation": "kat-al-las'-so", "derivation": "from (G2596) and (G236);", "definition": "to change mutually, i.e. (figuratively) to compound a difference", "kjv": "reconcile."}, "G2645": {"greek": "κατάλοιπος", "translit": "katáloipos", "pronunciation": "kat-al'-oy-pos", "derivation": "from (G2596) and (G3062);", "definition": "left down (behind), i.e remaining (plural the rest)", "kjv": "residue."}, "G2646": {"greek": "κατάλυμα", "translit": "katályma", "pronunciation": "kat-al'-oo-mah", "derivation": "from (G2647);", "definition": "properly, a dissolution (breaking up of a journey), i.e. (by implication) a lodging-place", "kjv": "guestchamber, inn."}, "G2647": {"greek": "καταλύω", "translit": "katalýō", "pronunciation": "kat-al-oo'-o", "derivation": "from (G2596) and (G3089);", "definition": "to loosen down (disintegrate), i.e. (by implication) to demolish (literally or figuratively); specially (compare (G2646)) to halt for the night", "kjv": "destroy, dissolve, be guest, lodge, come to nought, overthrow, throw down."}, "G2648": {"greek": "καταμανθάνω", "translit": "katamanthánō", "pronunciation": "kat-am-an-than'-o", "derivation": "from (G2596) and (G3129);", "definition": "to learn thoroughly, i.e. (by implication) to note carefully", "kjv": "consider."}, "G2649": {"greek": "καταμαρτυρέω", "translit": "katamartyréō", "pronunciation": "kat-am-ar-too-reh'-o", "derivation": "from (G2596) and (G3140);", "definition": "to testify against", "kjv": "witness against."}, "G2650": {"greek": "καταμένω", "translit": "kataménō", "pronunciation": "kat-am-en'-o", "derivation": "from (G2596) and (G3306);", "definition": "to stay fully, i.e. reside", "kjv": "abide."}, "G2652": {"greek": "κατανάθεμα", "translit": "katanáthema", "pronunciation": "kat-an-ath'-em-ah", "derivation": "from (G2596) (intensive) and (G331);", "definition": "an imprecation", "kjv": "curse."}, "G2653": {"greek": "καταναθεματίζω", "translit": "katanathematízō", "pronunciation": "kat-an-ath-em-at-id'-zo", "derivation": "from (G2596) (intensive) and (G332);", "definition": "to imprecate", "kjv": "curse."}, "G2654": {"greek": "καταναλίσκω", "translit": "katanalískō", "pronunciation": "kat-an-al-is'-ko", "derivation": "from (G2596) and (G355);", "definition": "to consume utterly", "kjv": "consume."}, "G2655": {"greek": "καταναρκάω", "translit": "katanarkáō", "pronunciation": "kat-an-ar-kah'-o", "derivation": "from (G2596) and (to be numb);", "definition": "to grow utterly torpid, i.e. (by implication) slothful (figuratively, expensive)", "kjv": "be burdensome (chargeable)."}, "G2656": {"greek": "κατανεύω", "translit": "kataneúō", "pronunciation": "kat-an-yoo'-o", "derivation": "from (G2596) and (G3506);", "definition": "to nod down (towards), i.e. (by analogy) to make signs to", "kjv": "beckon."}, "G2657": {"greek": "κατανοέω", "translit": "katanoéō", "pronunciation": "kat-an-o-eh'-o", "derivation": "from (G2596) and (G3539);", "definition": "to observe fully", "kjv": "behold, consider, discover, perceive."}, "G2658": {"greek": "καταντάω", "translit": "katantáō", "pronunciation": "kat-an-tah'-o", "derivation": "from (G2596) and a derivative of (G473);", "definition": "to meet against, i.e. arrive at (literally or figuratively)", "kjv": "attain, come."}, "G2659": {"greek": "κατάνυξις", "translit": "katányxis", "pronunciation": "kat-an'-oox-is", "derivation": "from (G2660);", "definition": "a prickling (sensation, as of the limbs asleep), i.e. (by implication, (perhaps by some confusion with (G3506) or even with (G3571))) stupor (lethargy)", "kjv": "slumber."}, "G2660": {"greek": "κατανύσσω", "translit": "katanýssō", "pronunciation": "kat-an-oos'-so", "derivation": "from (G2596) and (G3572);", "definition": "to pierce thoroughly, i.e. (figuratively) to agitate violently (\"sting to the quick\")", "kjv": "prick."}, "G2661": {"greek": "καταξιόω", "translit": "kataxióō", "pronunciation": "kat-ax-ee-o'-o", "derivation": "from (G2596) and (G515);", "definition": "to deem entirely deserving", "kjv": "(ac-)count worthy."}, "G2662": {"greek": "καταπατέω", "translit": "katapatéō", "pronunciation": "kat-ap-at-eh'-o", "derivation": "from (G2596) and (G3961);", "definition": "to trample down; figuratively, to reject with disdain", "kjv": "trample, tread (down, underfoot)."}, "G2663": {"greek": "κατάπαυσις", "translit": "katápausis", "pronunciation": "kat-ap'-ow-sis", "derivation": "from (G2664);", "definition": "reposing down, i.e. (by Hebraism) abode", "kjv": "rest."}, "G2664": {"greek": "καταπαύω", "translit": "katapaúō", "pronunciation": "kat-ap-ow'-o", "derivation": "from (G2596) and (G3973);", "definition": "to settle down, i.e. (literally) to colonize, or (figuratively) to (cause to) desist", "kjv": "cease, (give) rest(-rain)."}, "G2665": {"greek": "καταπέτασμα", "translit": "katapétasma", "pronunciation": "kat-ap-et'-as-mah", "derivation": "from a compound of (G2596) and a congener of (G4072);", "definition": "something spread thoroughly, i.e. (specially) the door screen (to the Most Holy Place) in the Jewish Temple", "kjv": "vail."}, "G2666": {"greek": "καταπίνω", "translit": "katapínō", "pronunciation": "kat-ap-ee'-no", "derivation": "from (G2596) and (G4095);", "definition": "to drink down, i.e. gulp entire (literally or figuratively)", "kjv": "devour, drown, swallow (up)."}, "G2667": {"greek": "καταπίπτω", "translit": "katapíptō", "pronunciation": "kat-ap-ip'-to", "derivation": "from (G2596) and (G4098);", "definition": "to fall down", "kjv": "fall (down)."}, "G2668": {"greek": "καταπλέω", "translit": "katapléō", "pronunciation": "kat-ap-leh'-o", "derivation": "from (G2596) and (G4126);", "definition": "to sail down upon a place, i.e. to land at", "kjv": "arrive."}, "G2669": {"greek": "καταπονέω", "translit": "kataponéō", "pronunciation": "kat-ap-on-eh'-o", "derivation": "from (G2596) and a derivative of (G4192);", "definition": "to labor down, i.e. wear with toil (figuratively, harass)", "kjv": "oppress, vex."}, "G2670": {"greek": "καταποντίζω", "translit": "katapontízō", "pronunciation": "kat-ap-on-tid'-zo", "derivation": "from (G2596) and a derivative of the same as (G4195);", "definition": "to plunge down, i.e. submerge", "kjv": "drown, sink."}, "G2671": {"greek": "κατάρα", "translit": "katára", "pronunciation": "kat-ar'-ah", "derivation": "from (G2596) (intensive) and (G685);", "definition": "imprecation, execration", "kjv": "curse(-d, ing)."}, "G2672": {"greek": "καταράομαι", "translit": "kataráomai", "pronunciation": "kat-ar-ah'-om-ahee", "derivation": "middle voice from (G2671);", "definition": "to execrate; by analogy, to doom", "kjv": "curse."}, "G2673": {"greek": "καταργέω", "translit": "katargéō", "pronunciation": "kat-arg-eh'-o", "derivation": "from (G2596) and (G691);", "definition": "to be (render) entirely idle (useless), literally or figuratively", "kjv": "abolish, cease, cumber, deliver, destroy, do away, become (make) of no (none, without) effect, fail, loose, bring (come) to nought, put away (down), vanish away, make void."}, "G2674": {"greek": "καταριθμέω", "translit": "katarithméō", "pronunciation": "kat-ar-ith-meh'-o", "derivation": "from (G2596) and (G705);", "definition": "to reckon among", "kjv": "number with."}, "G2675": {"greek": "καταρτίζω", "translit": "katartízō", "pronunciation": "kat-ar-tid'-zo", "derivation": "from (G2596) and a derivative of (G739);", "definition": "to complete thoroughly, i.e. repair (literally or figuratively) or adjust", "kjv": "fit, frame, mend, (make) perfect(-ly join together), prepare, restore."}, "G2676": {"greek": "κατάρτισις", "translit": "katártisis", "pronunciation": "kat-ar'-tis-is", "derivation": "from (G2675);", "definition": "thorough equipment (subjectively)", "kjv": "perfection."}, "G2677": {"greek": "καταρτισμός", "translit": "katartismós", "pronunciation": "kat-ar-tis-mos'", "derivation": "from (G2675);", "definition": "complete furnishing (objectively)", "kjv": "perfecting."}, "G2678": {"greek": "κατασείω", "translit": "kataseíō", "pronunciation": "kat-as-i'-o", "derivation": "from (G2596) and (G4579);", "definition": "to sway downward, i.e. make a signal", "kjv": "beckon."}, "G2679": {"greek": "κατασκάπτω", "translit": "kataskáptō", "pronunciation": "kat-as-kap'-to", "derivation": "from (G2596) and (G4626);", "definition": "to undermine, i.e. (by implication) destroy", "kjv": "dig down, ruin."}, "G2680": {"greek": "κατασκευάζω", "translit": "kataskeuázō", "pronunciation": "kat-ask-yoo-ad'-zo", "derivation": "from (G2596) and a derivative of (G4632);", "definition": "to prepare thoroughly (properly, by external equipment; whereas (G2090) refers rather to internal fitness); by implication, to construct, create", "kjv": "build, make, ordain, prepare."}, "G2681": {"greek": "κατασκηνόω", "translit": "kataskēnóō", "pronunciation": "kat-as-kay-no'-o", "derivation": "from (G2596) and (G4637);", "definition": "to camp down, i.e. haunt; figuratively, to remain", "kjv": "lodge, rest."}, "G2682": {"greek": "κατασκήνωσις", "translit": "kataskḗnōsis", "pronunciation": "kat-as-kay'-no-sis", "derivation": "from (G2681);", "definition": "an encamping, i.e. (figuratively) a perch", "kjv": "nest."}, "G2683": {"greek": "κατασκιάζω", "translit": "kataskiázō", "pronunciation": "kat-as-kee-ad'-zo", "derivation": "from (G2596) and a derivative of (G4639);", "definition": "to overshade, i.e. cover", "kjv": "shadow."}, "G2684": {"greek": "κατασκοπέω", "translit": "kataskopéō", "pronunciation": "kat-as-kop-eh'-o", "derivation": "from (G2685);", "definition": "to be a sentinel, i.e. to inspect insidiously", "kjv": "spy out."}, "G2685": {"greek": "κατάσκοπος", "translit": "katáskopos", "pronunciation": "kat-as'-kop-os", "derivation": "from (G2596) (intensive) and (G4649) (in the sense of a watcher);", "definition": "a reconnoiterer", "kjv": "spy."}, "G2686": {"greek": "κατασοφίζομαι", "translit": "katasophízomai", "pronunciation": "kat-as-of-id'-zom-ahee", "derivation": "middle voice from (G2596) and (G4679);", "definition": "to be crafty against, i.e. circumvent", "kjv": "deal subtilly with."}, "G2687": {"greek": "καταστέλλω", "translit": "katastéllō", "pronunciation": "kat-as-tel'-lo", "derivation": "from (G2596) and (G4724);", "definition": "to put down, i.e. quell", "kjv": "appease, quiet."}, "G2688": {"greek": "κατάστημα", "translit": "katástēma", "pronunciation": "kat-as'-tay-mah", "derivation": "from (G2525);", "definition": "properly, a position or condition, i.e. (subjectively) demeanor", "kjv": "behaviour."}, "G2689": {"greek": "καταστολή", "translit": "katastolḗ", "pronunciation": "kat-as-tol-ay'", "derivation": "from (G2687);", "definition": "a deposit, i.e. (specially) costume", "kjv": "apparel."}, "G2690": {"greek": "καταστρέφω", "translit": "katastréphō", "pronunciation": "kat-as-tref'-o", "derivation": "from (G2596) and (G4762);", "definition": "to turn upside down, i.e. upset", "kjv": "overthrow."}, "G2691": {"greek": "καταστρηνιάω", "translit": "katastrēniáō", "pronunciation": "kat-as-tray-nee-ah'-o", "derivation": "from (G2596) and (G4763);", "definition": "to become voluptuous against", "kjv": "begin to wax wanton against."}, "G2692": {"greek": "καταστροφή", "translit": "katastrophḗ", "pronunciation": "kat-as-trof-ay'", "derivation": "from (G2690);", "definition": "an overturn (\"catastrophe\"), i.e. demolition; figuratively, apostasy", "kjv": "overthrow, subverting."}, "G2693": {"greek": "καταστρώννυμι", "translit": "katastrṓnnymi", "pronunciation": "kat-as-trone'-noo-mee", "derivation": "from (G2596) and (G4766);", "definition": "to strew down, i.e. (by implication) to prostrate (slay)", "kjv": "overthrow."}, "G2694": {"greek": "κατασύρω", "translit": "katasýrō", "pronunciation": "kat-as-oo'-ro", "derivation": "from (G2596) and (G4951);", "definition": "to drag down, i.e. arrest judicially", "kjv": "hale."}, "G2695": {"greek": "κατασφάττω", "translit": "kataspháttō", "pronunciation": "kat-as-fat'-to", "derivation": "from (G2596) and (G4969);", "definition": "to kill down, i.e. slaughter", "kjv": "slay."}, "G2696": {"greek": "κατασφραγίζω", "translit": "katasphragízō", "pronunciation": "kat-as-frag-id'-zo", "derivation": "from (G2596) and (G4972);", "definition": "to seal closely", "kjv": "seal."}, "G2697": {"greek": "κατάσχεσις", "translit": "katáschesis", "pronunciation": "kat-as'-khes-is", "derivation": "from (G2722);", "definition": "a holding down, i.e. occupancy", "kjv": "possession."}, "G2698": {"greek": "κατατίθημι", "translit": "katatíthēmi", "pronunciation": "kat-at-ith'-ay-mee", "derivation": "from (G2596) and (G5087);", "definition": "to place down, i.e. deposit (literally or figuratively)", "kjv": "do, lay, shew."}, "G2699": {"greek": "κατατομή", "translit": "katatomḗ", "pronunciation": "kat-at-om-ay'", "derivation": "from a compound of (G2596) and (to cut);", "definition": "a cutting down (off), i.e. mutilation (ironically)", "kjv": "concision."}, "G2701": {"greek": "κατατρέχω", "translit": "katatréchō", "pronunciation": "kat-at-rekh'-o", "derivation": "from (G2596) and (G5143);", "definition": "to run down, i.e. hasten from a tower", "kjv": "run down."}, "G2702": {"greek": "καταφέρω", "translit": "kataphérō", "pronunciation": "kat-af-er'-o", "derivation": "from (G2596) and (G5342) (including its alternate);", "definition": "to bear down, i.e. (figuratively) overcome (with drowsiness); specially, to cast a vote", "kjv": "fall, give, sink down."}, "G2703": {"greek": "καταφεύγω", "translit": "katapheúgō", "pronunciation": "kat-af-yoo'-go", "derivation": "from (G2596) and (G5343);", "definition": "to flee down (away)", "kjv": "flee."}, "G2704": {"greek": "καταφθείρω", "translit": "kataphtheírō", "pronunciation": "kat-af-thi'-ro", "derivation": "from (G2596) and (G5351);", "definition": "to spoil entirely, i.e. (literally) to destroy; or (figuratively) to deprave;", "kjv": "--corrupt, utterly perish."}, "G2705": {"greek": "καταφιλέω", "translit": "kataphiléō", "pronunciation": "kat-af-ee-leh'-o", "derivation": "from 2596 and 5368;", "definition": "to kiss earnestly", "kjv": "kiss."}, "G2706": {"greek": "καταφρονέω", "translit": "kataphronéō", "pronunciation": "kat-af-ron-eh'-o", "derivation": "from (G2596) and (G5426);", "definition": "to think against, i.e. disesteem", "kjv": "despise."}, "G2707": {"greek": "καταφροντής", "translit": "kataphrontḗs", "pronunciation": "kat-af-ron-tace'", "derivation": "from (G2706);", "definition": "a contemner", "kjv": "despiser."}, "G2708": {"greek": "καταχέω", "translit": "katachéō", "pronunciation": "kat-akh-eh'-o", "derivation": "from (G2596) and cheo (to pour);", "definition": "to pour down (out)", "kjv": "pour."}, "G2709": {"greek": "καταχθόνιος", "translit": "katachthónios", "pronunciation": "kat-akh-thon'-ee-os", "derivation": "from (G2596) and (the ground);", "definition": "subterranean, i.e. infernal (belonging to the world of departed spirits)", "kjv": "under the earth."}, "G2710": {"greek": "καταχράομαι", "translit": "katachráomai", "pronunciation": "kat-akh-rah'-om-ahee", "derivation": "from (G2596) and (G5530);", "definition": "to overuse, i.e. misuse", "kjv": "abuse."}, "G2711": {"greek": "καταψύχω", "translit": "katapsýchō", "pronunciation": "kat-ap-soo'-kho", "derivation": "from (G2596) and (G5594);", "definition": "to cool down (off), i.e. refresh", "kjv": "cool."}, "G2712": {"greek": "κατείδωλος", "translit": "kateídōlos", "pronunciation": "kat-i'-do-los", "derivation": "from (G2596) (intensively) and (G1497);", "definition": "utterly idolatrous", "kjv": "wholly given to idolatry."}, "G2713": {"greek": "κατέναντι", "translit": "katénanti", "pronunciation": "kat-en'-an-tee", "derivation": "from (G2596) and (G1725);", "definition": "directly opposite", "kjv": "before, over against."}, "G2714": {"greek": "κατενώπιον", "translit": "katenṓpion", "pronunciation": "kat-en-o'-pee-on", "derivation": "from (G2596) and (G1799);", "definition": "directly in front of", "kjv": "before (the presence of), in the sight of."}, "G2715": {"greek": "κατεξουσιάζω", "translit": "katexousiázō", "pronunciation": "kat-ex-oo-see-ad'-zo", "derivation": "from (G2596) and (G1850);", "definition": "to have (wield) full privilege over", "kjv": "exercise authority."}, "G2716": {"greek": "κατεργάζομαι", "translit": "katergázomai", "pronunciation": "kat-er-gad'-zom-ahee", "derivation": "from (G2596) and (G2038);", "definition": "to work fully, i.e. accomplish; by implication, to finish, fashion", "kjv": "cause, to (deed), perform, work (out)."}, "G2718": {"greek": "κατέρχομαι", "translit": "katérchomai", "pronunciation": "kat-er'-khom-ahee", "derivation": "from (G2596) and (G2064) (including its alternate);", "definition": "to come (or go) down (literally or figuratively)", "kjv": "come (down), depart, descend, go down, land."}, "G2719": {"greek": "κατεσθίω", "translit": "katesthíō", "pronunciation": "kat-es-thee'-o", "derivation": "from (G2596) and (G2068) (including its alternate);", "definition": "to eat down, i.e. devour (literally or figuratively)", "kjv": "devour."}, "G2720": {"greek": "κατευθύνω", "translit": "kateuthýnō", "pronunciation": "kat-yoo-thoo'-no", "derivation": "from (G2596) and (G2116);", "definition": "to straighten fully, i.e. (figuratively) direct", "kjv": "guide, direct."}, "G2721": {"greek": "κατεφίστημι", "translit": "katephístēmi", "pronunciation": "kat-ef-is'-tay-mee", "derivation": "from (G2596) and (G2186);", "definition": "to stand over against, i.e. rush upon (assault)", "kjv": "make insurrection against."}, "G2722": {"greek": "κατέχω", "translit": "katéchō", "pronunciation": "kat-ekh'-o", "derivation": "from (G2596) and (G2192);", "definition": "to hold down (fast), in various applications (literally or figuratively)", "kjv": "have, hold (fast), keep (in memory), let, X make toward, possess, retain, seize on, stay, take, withhold."}, "G2723": {"greek": "κατηγορέω", "translit": "katēgoréō", "pronunciation": "kat-ay-gor-eh'-o", "derivation": "from (G2725);", "definition": "to be a plaintiff, i.e. to charge with some offence", "kjv": "accuse, object."}, "G2724": {"greek": "κατηγορία", "translit": "katēgoría", "pronunciation": "kat-ay-gor-ee'-ah", "derivation": "from (G2725);", "definition": "a complaint (\"category\"), i.e. criminal charge", "kjv": "accusation (X -ed)."}, "G2725": {"greek": "κατήγορος", "translit": "katḗgoros", "pronunciation": "kat-ay'-gor-os", "derivation": "from (G2596) and (G58);", "definition": "against one in the assembly, i.e. a complainant at law; specially, Satan", "kjv": "accuser."}, "G2726": {"greek": "κατήφεια", "translit": "katḗpheia", "pronunciation": "kat-ay'-fi-ah", "derivation": "from a compound of (G2596) and perhaps a derivative of the base of (G5316) (meaning downcast in look);", "definition": "demureness, i.e. (by implication) sadness", "kjv": "heaviness."}, "G2727": {"greek": "κατηχέω", "translit": "katēchéō", "pronunciation": "kat-ay-kheh'-o", "derivation": "from (G2596) and (G2279);", "definition": "to sound down into the ears, i.e. (by implication) to indoctrinate (\"catechize\") or (genitive case) to apprise of", "kjv": "inform, instruct, teach."}, "G2728": {"greek": "κατιόω", "translit": "katióō", "pronunciation": "kat-ee-o'-o", "derivation": "from (G2596) and a derivative of (G2447);", "definition": "to rust down, i.e. corrode", "kjv": "canker."}, "G2729": {"greek": "κατισχύω", "translit": "katischýō", "pronunciation": "kat-is-khoo'-o", "derivation": "from (G2596) and (G2480);", "definition": "to overpower", "kjv": "prevail (against)."}, "G2730": {"greek": "κατοικέω", "translit": "katoikéō", "pronunciation": "kat-oy-keh'-o", "derivation": "from (G2596) and (G3611);", "definition": "to house permanently, i.e. reside (literally or figuratively)", "kjv": "dwell(-er), inhabitant(-ter)."}, "G2731": {"greek": "κατοίκησις", "translit": "katoíkēsis", "pronunciation": "kat-oy'-kay-sis", "derivation": "from (G2730);", "definition": "residence (properly, the act; but by implication, concretely, the mansion)", "kjv": "dwelling."}, "G2732": {"greek": "κατοικητήριον", "translit": "katoikētḗrion", "pronunciation": "kat-oy-kay-tay'-ree-on", "derivation": "from a derivative of (G2730);", "definition": "a dwelling-place", "kjv": "habitation."}, "G2733": {"greek": "κατοικία", "translit": "katoikía", "pronunciation": "kat-oy-kee'-ah", "derivation": "", "definition": "residence (properly, the condition; but by implication, the abode itself)", "kjv": "habitation."}, "G2734": {"greek": "κατοπτρίζομαι", "translit": "katoptrízomai", "pronunciation": "kat-op-trid'-zom-ahee", "derivation": "middle voice from a compound of (G2596) and a derivative of (G3700) (compare (G2072));", "definition": "to mirror oneself, i.e. to see reflected (figuratively)", "kjv": "behold as in a glass."}, "G2735": {"greek": "κατόρθωμα", "translit": "katórthōma", "pronunciation": "kat-or'-tho-mah", "derivation": "from a compound of (G2596) and a derivative of (G3717) (compare (G1357));", "definition": "something made fully upright, i.e. (figuratively) rectification (specially, good public administration)", "kjv": "very worthy deed."}, "G2736": {"greek": "κάτω", "translit": "kátō", "pronunciation": "kat'-o", "derivation": "(compare (G2737)); adverb from (G2596);", "definition": "downwards", "kjv": "beneath, bottom, down, under."}, "G2737": {"greek": "κατώτερος", "translit": "katṓteros", "pronunciation": "kat-o'-ter-os", "derivation": "comparative from (G2736);", "definition": "inferior (locally, of Hades)", "kjv": "lower."}, "G2738": {"greek": "καῦμα", "translit": "kaûma", "pronunciation": "kow'-mah", "derivation": "from (G2545);", "definition": "properly, a burn (concretely), but used (abstractly) of a glow", "kjv": "heat."}, "G2739": {"greek": "καυματίζω", "translit": "kaumatízō", "pronunciation": "kow-mat-id'-zo", "derivation": "from (G2738);", "definition": "to burn", "kjv": "scorch."}, "G2740": {"greek": "καῦσις", "translit": "kaûsis", "pronunciation": "kow'-sis", "derivation": "from (G2545);", "definition": "burning (the act)", "kjv": "be burned."}, "G2741": {"greek": "καυσόω", "translit": "kausóō", "pronunciation": "kow-so'-o", "derivation": "from (G2740);", "definition": "to set on fire", "kjv": "fervent heat."}, "G2742": {"greek": "καύσων", "translit": "kaúsōn", "pronunciation": "kow'-sone", "derivation": "from (G2741);", "definition": "a glare", "kjv": "(burning) heat."}, "G2743": {"greek": "καυτηριάζω", "translit": "kautēriázō", "pronunciation": "kow-tay-ree-ad'-zo", "derivation": "from a derivative of (G2545);", "definition": "to brand (\"cauterize\"), i.e. (by implication) to render unsensitive (figuratively)", "kjv": "sear with a hot iron."}, "G2744": {"greek": "καυχάομαι", "translit": "kaucháomai", "pronunciation": "kow-khah'-om-ahee", "derivation": "from some (obsolete) base akin to that of (to boast) and (G2172);", "definition": "to vaunt (in a good or a bad sense)", "kjv": "(make) boast, glory, joy, rejoice."}, "G2745": {"greek": "καύχημα", "translit": "kaúchēma", "pronunciation": "kow'-khay-mah", "derivation": "from (G2744);", "definition": "a boast (properly, the object; by implication, the act) in a good or a bad sense", "kjv": "boasting, (whereof) to glory (of), glorying, rejoice(-ing)."}, "G2746": {"greek": "καύχησις", "translit": "kaúchēsis", "pronunciation": "kow'-khay-sis", "derivation": "from (G2744);", "definition": "boasting (properly, the act; by implication, the object), in a good or a bad sense", "kjv": "boasting, whereof I may glory, glorying, rejoicing."}, "G2747": {"greek": "Κεγχρεαί", "translit": "Kenchreaí", "pronunciation": "keng-khreh-a'-hee", "derivation": "probably from (millet);", "definition": "Cenchreæ, a port of Corinth", "kjv": "Cencrea."}, "G2748": {"greek": "Κεδρών", "translit": "Kedrṓn", "pronunciation": "ked-rone'", "derivation": "of Hebrew origin ((G6939));", "definition": "Cedron (i.e. Kidron), a brook near Jerusalem", "kjv": "Cedron."}, "G2749": {"greek": "κεῖμαι", "translit": "keîmai", "pronunciation": "ki'-mahee", "derivation": "middle voice of a primary verb;", "definition": "to lie outstretched (literally or figuratively)", "kjv": "be (appointed, laid up, made, set), lay, lie."}, "G2750": {"greek": "κειρία", "translit": "keiría", "pronunciation": "ki-ree'-ah", "derivation": "of uncertain affinity;", "definition": "a swathe, i.e. winding-sheet", "kjv": "graveclothes."}, "G2751": {"greek": "κείρω", "translit": "keírō", "pronunciation": "ki'-ro", "derivation": "a primary verb;", "definition": "to shear", "kjv": "shear(-er)."}, "G2752": {"greek": "κέλευμα", "translit": "kéleuma", "pronunciation": "kel'-yoo-mah", "derivation": "from (G2753);", "definition": "a cry of incitement", "kjv": "shout."}, "G2753": {"greek": "κελεύω", "translit": "keleúō", "pronunciation": "kel-yoo'-o", "derivation": "from a primary (to urge on);", "definition": "\"hail\"; to incite by word, i.e. order", "kjv": "bid, (at, give) command(-ment)."}, "G2754": {"greek": "κενοδοξία", "translit": "kenodoxía", "pronunciation": "ken-od-ox-ee'-ah", "derivation": "from (G2755);", "definition": "empty glorying, i.e. self-conceit", "kjv": "vain-glory."}, "G2755": {"greek": "κενόδοξος", "translit": "kenódoxos", "pronunciation": "ken-od'-ox-os", "derivation": "from (G2756) and (G1391);", "definition": "vainly glorifying, i.e. self-conceited", "kjv": "desirous of vain-glory."}, "G2756": {"greek": "κενός", "translit": "kenós", "pronunciation": "ken-os'", "derivation": "apparently a primary word;", "definition": "empty (literally or figuratively)", "kjv": "empty, (in) vain."}, "G2757": {"greek": "κενοφωνία", "translit": "kenophōnía", "pronunciation": "ken-of-o-nee'-ah", "derivation": "from a presumed compound of (G2756) and (G5456);", "definition": "empty sounding, i.e. fruitless discussion", "kjv": "vain."}, "G2758": {"greek": "κενόω", "translit": "kenóō", "pronunciation": "ken-o'-o", "derivation": "from (G2756);", "definition": "to make empty, i.e. (figuratively) to abase, neutralize, falsify", "kjv": "make (of none effect, of no reputation, void), be in vain."}, "G2759": {"greek": "κέντρον", "translit": "kéntron", "pronunciation": "ken'-tron", "derivation": "from (to prick);", "definition": "a point (\"centre\"), i.e. a sting (figuratively, poison) or goad (figuratively, divine impulse)", "kjv": "prick, sting."}, "G2760": {"greek": "κεντυρίων", "translit": "kentyríōn", "pronunciation": "ken-too-ree'-ohn", "derivation": "of Latin origin;", "definition": "a centurion, i.e. captain of one hundred soldiers", "kjv": "centurion."}, "G2761": {"greek": "κενῶς", "translit": "kenōs", "pronunciation": "ken-oce'", "derivation": "adverb from (G2756);", "definition": "vainly, i.e. to no purpose", "kjv": "in vain."}, "G2762": {"greek": "κεραία", "translit": "keraía", "pronunciation": "ker-ah'-yah", "derivation": "feminine of a presumed derivative of the base of (G2768);", "definition": "something horn-like, i.e. (specially) the apex of a Hebrew letter (figuratively, the least particle)", "kjv": "tittle."}, "G2763": {"greek": "κεραμεύς", "translit": "kerameús", "pronunciation": "ker-am-yooce'", "derivation": "from (G2766);", "definition": "a potter", "kjv": "potter."}, "G2764": {"greek": "κεραμικός", "translit": "keramikós", "pronunciation": "ker-am-ik-os'", "derivation": "from (G2766);", "definition": "made of clay, i.e. earthen", "kjv": "of a potter."}, "G2765": {"greek": "κεράμιον", "translit": "kerámion", "pronunciation": "ker-am'-ee-on", "derivation": "neuter of a presumed derivative of (G2766);", "definition": "an earthenware vessel, i.e. jar", "kjv": "pitcher."}, "G2766": {"greek": "κέραμος", "translit": "kéramos", "pronunciation": "ker'-am-os", "derivation": "probably from the base of (G2767) (through the idea of mixing clay and water);", "definition": "earthenware, i.e. a tile (by analogy, a thin roof or awning)", "kjv": "tiling."}, "G2767": {"greek": "κεράννυμι", "translit": "keránnymi", "pronunciation": "ker-an'-noo-mee", "derivation": "prolonged form of a more primary (which is used in certain tenses);", "definition": "to mingle, i.e. (by implication) to pour out (for drinking)", "kjv": "fill, pour out."}, "G2768": {"greek": "κέρας", "translit": "kéras", "pronunciation": "ker'-as", "derivation": "from a primary (the hair of the head);", "definition": "a horn (literally or figuratively)", "kjv": "horn."}, "G2769": {"greek": "κεράτιον", "translit": "kerátion", "pronunciation": "ker-at'-ee-on", "derivation": "neuter of a presumed derivative of (G2768);", "definition": "something horned, i.e. (specially) the pod of the carob-tree", "kjv": "husk."}, "G2770": {"greek": "κερδαίνω", "translit": "kerdaínō", "pronunciation": "ker-dah'-ee-no", "derivation": "from (G2771);", "definition": "to gain (literally or figuratively)", "kjv": "(get) gain, win."}, "G2771": {"greek": "κέρδος", "translit": "kérdos", "pronunciation": "ker'-dos", "derivation": "of uncertain affinity;", "definition": "gain (pecuniary or genitive case)", "kjv": "gain, lucre."}, "G2772": {"greek": "κέρμα", "translit": "kérma", "pronunciation": "ker'-mah", "derivation": "from (G2751);", "definition": "a clipping (bit), i.e. (specially) a coin", "kjv": "money."}, "G2773": {"greek": "κερματιστής", "translit": "kermatistḗs", "pronunciation": "ker-mat-is-tace'", "derivation": "from a derivative of (G2772);", "definition": "a handler of coins, i.e. money-broker", "kjv": "changer of money."}, "G2774": {"greek": "κεφάλαιον", "translit": "kephálaion", "pronunciation": "kef-al'-ah-yon", "derivation": "neuter of a derivative of (G2776);", "definition": "a principal thing, i.e. main point; specially, an amount (of money)", "kjv": "sum."}, "G2775": {"greek": "κεφαλαιόω", "translit": "kephalaióō", "pronunciation": "kef-al-ahee-o'-o", "derivation": "from the same as (G2774);", "definition": "(specially) to strike on the head", "kjv": "wound in the head."}, "G2776": {"greek": "κεφαλή", "translit": "kephalḗ", "pronunciation": "kef-al-ay'", "derivation": "from the primary (in the sense of seizing);", "definition": "the head (as the part most readily taken hold of), literally or figuratively", "kjv": "head."}, "G2777": {"greek": "κεφαλίς", "translit": "kephalís", "pronunciation": "kef-al-is'", "derivation": "from (G2776);", "definition": "properly, a knob, i.e. (by implication) a roll (by extension from the end of a stick on which the manuscript was rolled)", "kjv": "volume."}, "G2778": {"greek": "κῆνσος", "translit": "kēnsos", "pronunciation": "kane'-sos", "derivation": "of Latin origin;", "definition": "properly, an enrollment (\"census\"), i.e. (by implication) a tax", "kjv": "tribute."}, "G2779": {"greek": "κῆπος", "translit": "kēpos", "pronunciation": "kay'-pos", "derivation": "of uncertain affinity;", "definition": "a garden", "kjv": "garden."}, "G2780": {"greek": "κηπουρός", "translit": "kēpourós", "pronunciation": "kay-poo-ros'", "derivation": "from (G2779) and (a warden);", "definition": "a garden-keeper, i.e. gardener", "kjv": "gardener."}, "G2782": {"greek": "κήρυγμα", "translit": "kḗrygma", "pronunciation": "kay'-roog-mah", "derivation": "from (G2784);", "definition": "a proclamation (especially of the gospel; by implication, the gospel itself)", "kjv": "preaching."}, "G2783": {"greek": "κῆρυξ", "translit": "kēryx", "pronunciation": "kay'-roox", "derivation": "from (G2784);", "definition": "a herald, i.e. of divine truth (especially of the gospel)", "kjv": "preacher."}, "G2784": {"greek": "κηρύσσω", "translit": "kērýssō", "pronunciation": "kay-roos'-so", "derivation": "of uncertain affinity;", "definition": "to herald (as a public crier), especially divine truth (the gospel)", "kjv": "preacher(-er), proclaim, publish."}, "G2785": {"greek": "κῆτος", "translit": "kētos", "pronunciation": "kay'-tos", "derivation": "probably from the base of (G5490);", "definition": "a huge fish (as gaping for prey)", "kjv": "whale."}, "G2786": {"greek": "Κηφᾶς", "translit": "Kēphâs", "pronunciation": "kay-fas'", "derivation": "of Chaldee origin (compare (G3710));", "definition": "the Rock; Cephas (i.e. Kepha), a surname of Peter", "kjv": "Cephas."}, "G2787": {"greek": "κιβωτός", "translit": "kibōtós", "pronunciation": "kib-o-tos'", "derivation": "of uncertain derivation;", "definition": "a box, i.e. the sacred ark and that of Noah", "kjv": "ark."}, "G2788": {"greek": "κιθάρα", "translit": "kithára", "pronunciation": "kith-ar'-ah", "derivation": "of uncertain affinity;", "definition": "a lyre", "kjv": "harp."}, "G2789": {"greek": "κιθαρίζω", "translit": "kitharízō", "pronunciation": "kith-ar-id'-zo", "derivation": "from (G2788);", "definition": "to play on a lyre", "kjv": "harp."}, "G2790": {"greek": "κιθαρῳδός", "translit": "kitharōidós", "pronunciation": "kith-ar-o'-dos", "derivation": "from (G2788) and a derivative of the same as (G5603);", "definition": "a lyre-singer(-player), i.e. harpist", "kjv": "harper."}, "G2791": {"greek": "Κιλικία", "translit": "Kilikía", "pronunciation": "kil-ik-ee'-ah", "derivation": "probably of foreign origin;", "definition": "Cilicia, a region of Asia Minor", "kjv": "Cilicia."}, "G2792": {"greek": "κινάμωμον", "translit": "kinámōmon", "pronunciation": "kin-am'-o-mon", "derivation": "of foreign origin (compare (G7076));", "definition": "cinnamon", "kjv": "cinnamon."}, "G2793": {"greek": "κινδυνεύω", "translit": "kindyneúō", "pronunciation": "kin-doon-yoo'-o", "derivation": "from (G2794);", "definition": "to undergo peril", "kjv": "be in danger, be (stand) in jeopardy."}, "G2794": {"greek": "κίνδυνος", "translit": "kíndynos", "pronunciation": "kin'-doo-nos", "derivation": "of uncertain derivation;", "definition": "danger", "kjv": "peril."}, "G2795": {"greek": "κινέω", "translit": "kinéō", "pronunciation": "kin-eh'-o", "derivation": "from (poetic for , to go);", "definition": "to stir (transitively), literally or figuratively", "kjv": "(re-)move(-r), way."}, "G2797": {"greek": "Κίς", "translit": "Kís", "pronunciation": "kis", "derivation": "of Hebrew origin ((G7027));", "definition": "Cis (i.e. Kish), an Israelite", "kjv": "Cis."}, "G2798": {"greek": "κλάδος", "translit": "kládos", "pronunciation": "klad'-os", "derivation": "from (G2806);", "definition": "a twig or bough (as if broken off)", "kjv": "branch."}, "G2799": {"greek": "κλαίω", "translit": "klaíō", "pronunciation": "klah'-yo", "derivation": "of uncertain affinity;", "definition": "to sob, i.e. wail aloud (whereas 1145 is rather to cry silently)", "kjv": "bewail, weep."}, "G2800": {"greek": "κλάσις", "translit": "klásis", "pronunciation": "klas'-is", "derivation": "from (G2806);", "definition": "fracture (the act)", "kjv": "breaking."}, "G2801": {"greek": "κλάσμα", "translit": "klásma", "pronunciation": "klas'-mah", "derivation": "from (G2806);", "definition": "a piece (bit)", "kjv": "broken, fragment."}, "G2802": {"greek": "Κλαύδη", "translit": "Klaúdē", "pronunciation": "klow'-day", "derivation": "of uncertain derivation;", "definition": "Claude, an island near Crete", "kjv": "Clauda."}, "G2803": {"greek": "Κλαυδία", "translit": "Klaudía", "pronunciation": "klow-dee'-ah", "derivation": "feminine of (G2804);", "definition": "Claudia, a Christian woman", "kjv": "Claudia."}, "G2804": {"greek": "Κλαύδιος", "translit": "Klaúdios", "pronunciation": "klow'-dee-os", "derivation": "of Latin origin;", "definition": "Claudius, the name of two Romans", "kjv": "Claudius."}, "G2805": {"greek": "κλαυθμός", "translit": "klauthmós", "pronunciation": "klowth-mos'", "derivation": "from (G2799);", "definition": "lamentation", "kjv": "wailing, weeping, X wept."}, "G2806": {"greek": "κλάω", "translit": "kláō", "pronunciation": "klah'-o", "derivation": "a primary verb;", "definition": "to break (specially, of bread)", "kjv": "break."}, "G2807": {"greek": "κλείς", "translit": "kleís", "pronunciation": "klice", "derivation": "from (G2808);", "definition": "a key (as shutting a lock), literally or figuratively", "kjv": "key."}, "G2808": {"greek": "κλείω", "translit": "kleíō", "pronunciation": "kli'-o", "derivation": "a primary verb;", "definition": "to close (literally or figuratively)", "kjv": "shut (up)."}, "G2809": {"greek": "κλέμμα", "translit": "klémma", "pronunciation": "klem'-mah", "derivation": "from (G2813);", "definition": "stealing (properly, the thing stolen, but used of the act)", "kjv": "theft."}, "G2810": {"greek": "Κλεόπας", "translit": "Kleópas", "pronunciation": "kleh-op'-as", "derivation": "probably contracted from (compound of (G2811) and (G3962));", "definition": "Cleopas, a Christian", "kjv": "Cleopas."}, "G2811": {"greek": "κλέος", "translit": "kléos", "pronunciation": "kleh'-os", "derivation": "from a shorter form of (G2564);", "definition": "renown (as if being called)", "kjv": "glory."}, "G2812": {"greek": "κλέπτης", "translit": "kléptēs", "pronunciation": "klep'-tace", "derivation": "from (G2813);", "definition": "a stealer (literally or figuratively)", "kjv": "thief."}, "G2813": {"greek": "κλέπτω", "translit": "kléptō", "pronunciation": "klep'-to", "derivation": "a primary verb;", "definition": "to filch", "kjv": "steal."}, "G2814": {"greek": "κλῆμα", "translit": "klēma", "pronunciation": "kaly'-mah", "derivation": "from (G2806);", "definition": "a limb or shoot (as if broken off)", "kjv": "branch."}, "G2815": {"greek": "Κλήμης", "translit": "Klḗmēs", "pronunciation": "klay'-mace", "derivation": "of Latin origin;", "definition": "merciful; Clemes (i.e. Clemens), a Christian", "kjv": "Clement."}, "G2816": {"greek": "κληρονομέω", "translit": "klēronoméō", "pronunciation": "klay-ron-om-eh'-o", "derivation": "from (G2818);", "definition": "to be an heir to (literally or figuratively)", "kjv": "be heir, (obtain by) inherit(-ance)."}, "G2817": {"greek": "κληρονομία", "translit": "klēronomía", "pronunciation": "klay-ron-om-ee'-ah", "derivation": "from (G2818);", "definition": "heirship, i.e. (concretely) a patrimony or (genitive case) a possession", "kjv": "inheritance."}, "G2818": {"greek": "κληρονόμος", "translit": "klēronómos", "pronunciation": "klay-ron-om'-os", "derivation": "from (G2819) and the base of (G3551) (in its original sense of partitioning, i.e. (reflexively) getting by apportionment);", "definition": "a sharer by lot, i.e. inheritor (literally or figuratively); by implication, a possessor", "kjv": "heir."}, "G2819": {"greek": "κλῆρος", "translit": "klēros", "pronunciation": "klay'-ros", "derivation": "probably from (G2806) (through the idea of using bits of wood, etc., for the purpose;", "definition": "a die (for drawing chances); by implication, a portion (as if so secured); by extension, an acquisition (especially a patrimony, figuratively)", "kjv": "heritage, inheritance, lot, part."}, "G2820": {"greek": "κληρόω", "translit": "klēróō", "pronunciation": "klay-ro'-o", "derivation": "from (G2819);", "definition": "to allot, i.e. (figuratively) to assign (a privilege)", "kjv": "obtain an inheritance."}, "G2821": {"greek": "κλῆσις", "translit": "klēsis", "pronunciation": "klay'-sis", "derivation": "from a shorter form of (G2564);", "definition": "an invitation (figuratively)", "kjv": "calling."}, "G2822": {"greek": "κλητός", "translit": "klētós", "pronunciation": "klay-tos'", "derivation": "from the same as (G2821);", "definition": "invited, i.e. appointed, or (specially), a saint", "kjv": "called."}, "G2823": {"greek": "κλίβανος", "translit": "klíbanos", "pronunciation": "klib'-an-os", "derivation": "of uncertain derivation;", "definition": "an earthen pot used for baking in", "kjv": "oven."}, "G2824": {"greek": "κλίμα", "translit": "klíma", "pronunciation": "klee'-mah", "derivation": "from (G2827);", "definition": "a slope, i.e. (specially) a \"clime\" or tract of country", "kjv": "part, region."}, "G2825": {"greek": "κλίνη", "translit": "klínē", "pronunciation": "klee'-nay", "derivation": "from (G2827);", "definition": "a couch (for sleep, sickness, sitting or eating)", "kjv": "bed, table."}, "G2826": {"greek": "κλινίδιον", "translit": "klinídion", "pronunciation": "klin-id'-ee-on", "derivation": "neuter of a presumed derivative of (G2825);", "definition": "a pallet or little couch", "kjv": "bed."}, "G2827": {"greek": "κλίνω", "translit": "klínō", "pronunciation": "klee'-no", "derivation": "a primary verb;", "definition": "to slant or slope, i.e. incline or recline (literally or figuratively)", "kjv": "bow (down), be far spent, lay, turn to flight, wear away."}, "G2828": {"greek": "κλισία", "translit": "klisía", "pronunciation": "klee-see'-ah", "derivation": "from a derivative of (G2827);", "definition": "properly, reclination, i.e. (concretely and specially), a party at a meal", "kjv": "company."}, "G2829": {"greek": "κλοπή", "translit": "klopḗ", "pronunciation": "klop-ay'", "derivation": "from (G2813);", "definition": "stealing", "kjv": "theft."}, "G2830": {"greek": "κλύδων", "translit": "klýdōn", "pronunciation": "kloo'-dohn", "derivation": "from (to billow or dash over);", "definition": "a surge of the sea (literally or figuratively)", "kjv": "raging, wave."}, "G2831": {"greek": "κλυδωνίζομαι", "translit": "klydōnízomai", "pronunciation": "kloo-do-nid'-zom-ahee", "derivation": "middle voice from (G2830);", "definition": "to surge, i.e. (figuratively) to fluctuate", "kjv": "toss to and fro."}, "G2832": {"greek": "Κλωπᾶς", "translit": "Klōpâs", "pronunciation": "klo-pas'", "derivation": "of Chaldee origin (corresponding to (G256));", "definition": "Clopas, an Israelite", "kjv": "Cleophas."}, "G2833": {"greek": "κνήθω", "translit": "knḗthō", "pronunciation": "knay'-tho", "derivation": "from a primary (to scrape);", "definition": "to scratch, i.e. (by implication) to tickle", "kjv": "X itching."}, "G2834": {"greek": "Κνίδος", "translit": "Knídos", "pronunciation": "knee'-dos", "derivation": "probably of foreign origin;", "definition": "Cnidus, a place in Asia Minor", "kjv": "Cnidus."}, "G2835": {"greek": "κοδράντης", "translit": "kodrántēs", "pronunciation": "kod-ran'-tace", "derivation": "of Latin origin;", "definition": "a quadrans, i.e. the fourth part of an as", "kjv": "farthing."}, "G2836": {"greek": "κοιλία", "translit": "koilía", "pronunciation": "koy-lee'-ah", "derivation": "from (\"hollow\");", "definition": "a cavity, i.e. (especially) the abdomen; by implication, the matrix; figuratively, the heart", "kjv": "belly, womb."}, "G2837": {"greek": "κοιμάω", "translit": "koimáō", "pronunciation": "koy-mah'-o", "derivation": "from (G2749);", "definition": "to put to sleep, i.e. (passively or reflexively) to slumber; figuratively, to decease", "kjv": "(be a-, fall a-, fall on) sleep, be dead."}, "G2838": {"greek": "κοίμησις", "translit": "koímēsis", "pronunciation": "koy'-may-sis", "derivation": "from (G2837);", "definition": "sleeping, i.e. (by implication) repose", "kjv": "taking of rest."}, "G2839": {"greek": "κοινός", "translit": "koinós", "pronunciation": "koy-nos'", "derivation": "probably from (G4862);", "definition": "common, i.e. (literally) shared by all or several, or (ceremonially) profane", "kjv": "common, defiled, unclean, unholy."}, "G2840": {"greek": "κοινόω", "translit": "koinóō", "pronunciation": "koy-no'-o", "derivation": "from (G2839);", "definition": "to make (or consider) profane (ceremonially)", "kjv": "call common, defile, pollute, unclean."}, "G2841": {"greek": "κοινωνέω", "translit": "koinōnéō", "pronunciation": "koy-no-neh'-o", "derivation": "from (G2844);", "definition": "to share with others (objectively or subjectively)", "kjv": "communicate, distribute, be partaker."}, "G2842": {"greek": "κοινωνία", "translit": "koinōnía", "pronunciation": "koy-nohn-ee'-ah", "derivation": "from (G2844);", "definition": "partnership, i.e. (literally) participation, or (social) intercourse, or (pecuniary) benefaction", "kjv": "(to) communicate(-ation), communion, (contri-)distribution, fellowship."}, "G2843": {"greek": "κοινωνικός", "translit": "koinōnikós", "pronunciation": "koy-no-nee-kos'", "derivation": "from (G2844);", "definition": "communicative, i.e. (pecuniarily) liberal", "kjv": "willing to communicate."}, "G2844": {"greek": "κοινωνός", "translit": "koinōnós", "pronunciation": "koy-no-nos'", "derivation": "from (G2839);", "definition": "a sharer, i.e. associate", "kjv": "companion, X fellowship, partaker, partner."}, "G2845": {"greek": "κοίτη", "translit": "koítē", "pronunciation": "koy'-tay", "derivation": "from (G2749);", "definition": "a couch; by extension, cohabitation; by implication, the male sperm", "kjv": "bed, chambering, X conceive."}, "G2846": {"greek": "κοιτών", "translit": "koitṓn", "pronunciation": "koy-tone'", "derivation": "from (G2845);", "definition": "a bedroom", "kjv": "+ chamberlain."}, "G2847": {"greek": "κόκκινος", "translit": "kókkinos", "pronunciation": "kok'-kee-nos", "derivation": "from (G2848) (from the kernel-shape of the insect);", "definition": "crimson-colored", "kjv": "scarlet (colour, coloured)."}, "G2848": {"greek": "κόκκος", "translit": "kókkos", "pronunciation": "kok'-kos", "derivation": "apparently a primary word;", "definition": "a kernel of seed", "kjv": "corn, grain."}, "G2849": {"greek": "κολάζω", "translit": "kolázō", "pronunciation": "kol-ad'-zo", "derivation": "from (dwarf);", "definition": "properly, to curtail, i.e. (figuratively) to chastise (or reserve for infliction)", "kjv": "punish."}, "G2850": {"greek": "κολακεία", "translit": "kolakeía", "pronunciation": "kol-ak-i'-ah", "derivation": "from a derivative of (a fawner);", "definition": "flattery", "kjv": "X flattering."}, "G2851": {"greek": "κόλασις", "translit": "kólasis", "pronunciation": "kol'-as-is", "derivation": "from (G2849);", "definition": "penal infliction", "kjv": "punishment, torment."}, "G2852": {"greek": "κολαφίζω", "translit": "kolaphízō", "pronunciation": "kol-af-id'-zo", "derivation": "from a derivative of the base of (G2849);", "definition": "to rap with the fist", "kjv": "buffet."}, "G2853": {"greek": "κολλάω", "translit": "kolláō", "pronunciation": "kol-lah'-o", "derivation": "from (\"glue\");", "definition": "to glue, i.e. (passively or reflexively) to stick (figuratively)", "kjv": "cleave, join (self), keep company."}, "G2854": {"greek": "κολλούριον", "translit": "kolloúrion", "pronunciation": "kol-loo'-ree-on", "derivation": "neuter of a presumed derivative of (a cake; prob akin to the base of (G2853));", "definition": "properly, a poultice (as made of or in the form of crackers), i.e. (by analogy) a plaster", "kjv": "eyesalve."}, "G2855": {"greek": "κολλυβιστής", "translit": "kollybistḗs", "pronunciation": "kol-loo-bis-tace'", "derivation": "from a presumed derivative of (a small coin; probably akin to (G2854));", "definition": "a coin-dealer", "kjv": "(money-)changer."}, "G2856": {"greek": "κολοβόω", "translit": "kolobóō", "pronunciation": "kol-ob-o'-o", "derivation": "from a derivative of the base of (G2849);", "definition": "to dock, i.e. (figuratively) abridge", "kjv": "shorten."}, "G2857": {"greek": "Κολοσσαί", "translit": "Kolossaí", "pronunciation": "kol-os-sah'-ee", "derivation": "apparently feminine plural of kolossos (\"colossal\");", "definition": "Colossæ, a place in Asia Minor", "kjv": "Colosse."}, "G2859": {"greek": "κόλπος", "translit": "kólpos", "pronunciation": "kol'-pos", "derivation": "apparently a primary word;", "definition": "the bosom; by analogy, a bay", "kjv": "bosom, creek."}, "G2860": {"greek": "κολυμβάω", "translit": "kolymbáō", "pronunciation": "kol-oom-bah'-o", "derivation": "from (a diver);", "definition": "to plunge into water", "kjv": "swim."}, "G2861": {"greek": "κολυμβήθρα", "translit": "kolymbḗthra", "pronunciation": "kol-oom-bay'-thrah", "derivation": "from (G2860);", "definition": "a diving-place, i.e. pond for bathing (or swimming)", "kjv": "pool."}, "G2862": {"greek": "κολωνία", "translit": "kolōnía", "pronunciation": "kol-o-nee'-ah", "derivation": "of Latin origin;", "definition": "a Roman \"colony\" for veterans", "kjv": "colony."}, "G2863": {"greek": "κομάω", "translit": "komáō", "pronunciation": "kom-ah'-o", "derivation": "from (G2864);", "definition": "to wear tresses of hair", "kjv": "have long hair."}, "G2864": {"greek": "κόμη", "translit": "kómē", "pronunciation": "kom'-ay", "derivation": "apparently from the same as (G2865);", "definition": "the hair of the head (locks, as ornamental, and thus differing from (G2359); which properly denotes merely the scalp)", "kjv": "hair."}, "G2865": {"greek": "κομίζω", "translit": "komízō", "pronunciation": "kom-id'-zo", "derivation": "from a primary (to tend, i.e. take care of);", "definition": "properly, to provide for, i.e. (by implication) to carry off (as if from harm; genitive case obtain)", "kjv": "bring, receive."}, "G2866": {"greek": "κομψότερον", "translit": "kompsóteron", "pronunciation": "komp-sot'-er-on", "derivation": "neuter comparative of a derivative of the base of 2865 (meaning, properly, well dressed, i.e. nice);", "definition": "figuratively, convalescent", "kjv": "+ began to amend."}, "G2867": {"greek": "κονιάω", "translit": "koniáō", "pronunciation": "kon-ee-ah'-o", "derivation": "from (dust; by analogy, lime);", "definition": "to whitewash", "kjv": "whiten."}, "G2868": {"greek": "κονιορτός", "translit": "koniortós", "pronunciation": "kon-ee-or-tos'", "derivation": "from the base of (G2867) and (to \"rouse\");", "definition": "pulverulence (as blown about)", "kjv": "dust."}, "G2869": {"greek": "κοπάζω", "translit": "kopázō", "pronunciation": "kop-ad'-zo", "derivation": "from (G2873);", "definition": "to tire, i.e. (figuratively) to relax", "kjv": "cease."}, "G2870": {"greek": "κοπετός", "translit": "kopetós", "pronunciation": "kop-et-os'", "derivation": "from (G2875);", "definition": "mourning (properly, by beating the breast)", "kjv": "lamentation."}, "G2871": {"greek": "κοπή", "translit": "kopḗ", "pronunciation": "kop-ay'", "derivation": "from (G2875);", "definition": "cutting, i.e. carnage", "kjv": "slaughter."}, "G2872": {"greek": "κοπιάω", "translit": "kopiáō", "pronunciation": "kop-ee-ah'-o", "derivation": "from a derivative of (G2873);", "definition": "to feel fatigue; by implication, to work hard", "kjv": "(bestow) labour, toil, be wearied."}, "G2873": {"greek": "κόπος", "translit": "kópos", "pronunciation": "kop'-os", "derivation": "from (G2875);", "definition": "a cut, i.e. (by analogy) toil (as reducing the strength), literally or figuratively; by implication, pains", "kjv": "labour, + trouble, weariness."}, "G2874": {"greek": "κοπρία", "translit": "kopría", "pronunciation": "kop-ree'-ah", "derivation": "from (ordure; perhaps akin to (G2875));", "definition": "manure", "kjv": "dung(-hill)."}, "G2875": {"greek": "κόπτω", "translit": "kóptō", "pronunciation": "kop'-to", "derivation": "a primary verb;", "definition": "to \"chop\"; specially, to beat the breast in grief", "kjv": "cut down, lament, mourn, (be-)wail."}, "G2876": {"greek": "κόραξ", "translit": "kórax", "pronunciation": "kor'-ax", "derivation": "perhaps from (G2880);", "definition": "a crow (from its voracity)", "kjv": "raven."}, "G2877": {"greek": "κοράσιον", "translit": "korásion", "pronunciation": "kor-as'-ee-on", "derivation": "neuter of a presumed derivative of (a maiden);", "definition": "a (little) girl", "kjv": "damsel, maid."}, "G2878": {"greek": "κορβᾶν", "translit": "korbân", "pronunciation": "kor-ban'", "derivation": "of Hebrew and Chaldee origin respectively ((G7133));", "definition": "a votive offering and the offering; a consecrated present (to the Temple fund); by extension (the latter term) the Treasury itself, i.e. the room where the contribution boxes stood", "kjv": "Corban, treasury."}, "G2879": {"greek": "Κορέ", "translit": "Koré", "pronunciation": "kor-eh'", "derivation": "of Hebrew origin ((G7141));", "definition": "Core (i.e. Korach), an Israelite", "kjv": "Core."}, "G2880": {"greek": "κορέννυμι", "translit": "korénnymi", "pronunciation": "kor-en'-noo-mee", "derivation": "a primary verb;", "definition": "to cram, i.e. glut or sate", "kjv": "eat enough, full."}, "G2881": {"greek": "Κορίνθιος", "translit": "Korínthios", "pronunciation": "kor-in'-thee-os", "derivation": "from (G2882);", "definition": "a Corinthian, i.e. inhabitant of Corinth", "kjv": "Corinthian."}, "G2882": {"greek": "Κόρινθος", "translit": "Kórinthos", "pronunciation": "kor'-in-thos", "derivation": "of uncertain derivation;", "definition": "Corinthus, a city of Greece", "kjv": "Corinth."}, "G2883": {"greek": "Κορνήλιος", "translit": "Kornḗlios", "pronunciation": "kor-nay'-lee-os", "derivation": "of Latin origin;", "definition": "Cornelius, a Roman", "kjv": "Cornelius."}, "G2884": {"greek": "κόρος", "translit": "kóros", "pronunciation": "kor'-os", "derivation": "of Hebrew origin ((G3734));", "definition": "a cor, i.e. a specific measure", "kjv": "measure."}, "G2885": {"greek": "κοσμέω", "translit": "kosméō", "pronunciation": "kos-meh'-o", "derivation": "from (G2889);", "definition": "to put in proper order, i.e. decorate (literally or figuratively); specially, to snuff (a wick)", "kjv": "adorn, garnish, trim."}, "G2886": {"greek": "κοσμικός", "translit": "kosmikós", "pronunciation": "kos-mee-kos'", "derivation": "from (G2889) (in its secondary sense);", "definition": "terrene (\"cosmic\"), literally (mundane) or figuratively (corrupt)", "kjv": "worldly."}, "G2887": {"greek": "κόσμιος", "translit": "kósmios", "pronunciation": "kos'-mee-os", "derivation": "from (G2889) (in its primary sense);", "definition": "orderly, i.e. decorous", "kjv": "of good behaviour, modest."}, "G2888": {"greek": "κοσμοκράτωρ", "translit": "kosmokrátōr", "pronunciation": "kos-mok-fat'-ore", "derivation": "from (G2889) and (G2902);", "definition": "a world-ruler, an epithet of Satan", "kjv": "ruler."}, "G2889": {"greek": "κόσμος", "translit": "kósmos", "pronunciation": "kos'-mos", "derivation": "probably from the base of (G2865);", "definition": "orderly arrangement, i.e. decoration; by implication, the world (in a wide or narrow sense, including its inhabitants, literally or figuratively (morally))", "kjv": "adorning, world."}, "G2890": {"greek": "Κούαρτος", "translit": "Koúartos", "pronunciation": "koo'-ar-tos", "derivation": "of Latin origin (fourth);", "definition": "Quartus, a Christian", "kjv": "Quartus."}, "G2891": {"greek": "κοῦμι", "translit": "koûmi", "pronunciation": "koo'-mee", "derivation": "of Chaldee origin ((G6966));", "definition": "cumi (i.e. rise!)", "kjv": "cumi."}, "G2892": {"greek": "κουστωδία", "translit": "koustōdía", "pronunciation": "koos-to-dee'-ah", "derivation": "of Latin origin;", "definition": "\"custody\", i.e. a Roman sentry", "kjv": "watch."}, "G2893": {"greek": "κουφίζω", "translit": "kouphízō", "pronunciation": "koo-fid'-zo", "derivation": "from (light in weight);", "definition": "to unload", "kjv": "lighten."}, "G2894": {"greek": "κόφινος", "translit": "kóphinos", "pronunciation": "kof'-ee-nos", "derivation": "of uncertain derivation;", "definition": "a (small) basket", "kjv": "basket."}, "G2895": {"greek": "κράββατος", "translit": "krábbatos", "pronunciation": "krab'-bat-os", "derivation": "probably of foreign origin;", "definition": "a mattress", "kjv": "bed."}, "G2896": {"greek": "κράζω", "translit": "krázō", "pronunciation": "krad'-zo", "derivation": "a primary verb;", "definition": "properly, to \"croak\" (as a raven) or scream, i.e. (genitive case) to call aloud (shriek, exclaim, intreat)", "kjv": "cry (out)."}, "G2897": {"greek": "κραιπάλη", "translit": "kraipálē", "pronunciation": "krahee-pal'-ay", "derivation": "probably from the same as (G726);", "definition": "properly, a headache (as a seizure of pain) from drunkenness, i.e. (by implication) a debauch (by analogy, a glut)", "kjv": "surfeiting."}, "G2898": {"greek": "κρανίον", "translit": "kraníon", "pronunciation": "kran-ee'-on", "derivation": "diminutive of a derivative of the base of (G2768);", "definition": "a skull (\"cranium\")", "kjv": "Calvary, skull."}, "G2899": {"greek": "κράσπεδον", "translit": "kráspedon", "pronunciation": "kras'-ped-on", "derivation": "of uncertain derivation;", "definition": "a margin, i.e. (specially), a fringe or tassel", "kjv": "border, hem."}, "G2900": {"greek": "κραταιός", "translit": "krataiós", "pronunciation": "krat-ah-yos'", "derivation": "from (G2904);", "definition": "powerful", "kjv": "mighty."}, "G2901": {"greek": "κραταιόω", "translit": "krataióō", "pronunciation": "krat-ah-yo'-o", "derivation": "from (G2900);", "definition": "to empower, i.e. (passively) increase in vigor", "kjv": "be strengthened, be (wax) strong."}, "G2902": {"greek": "κρατέω", "translit": "kratéō", "pronunciation": "krat-eh'-o", "derivation": "from (G2904);", "definition": "to use strength, i.e. seize or retain (literally or figuratively)", "kjv": "hold (by, fast), keep, lay hand (hold) on, obtain, retain, take (by)."}, "G2903": {"greek": "κράτιστος", "translit": "krátistos", "pronunciation": "krat'-is-tos", "derivation": "superlative of a derivative of (G2904);", "definition": "strongest, i.e. (in dignity) very honorable", "kjv": "most excellent (noble)."}, "G2904": {"greek": "κράτος", "translit": "krátos", "pronunciation": "krat'-os", "derivation": "perhaps a primary word;", "definition": "vigor (\"great\") (literally or figuratively)", "kjv": "dominion, might(-ily), power, strength."}, "G2905": {"greek": "κραυγάζω", "translit": "kraugázō", "pronunciation": "krow-gad'-zo", "derivation": "from (G2906);", "definition": "to clamor", "kjv": "cry out."}, "G2906": {"greek": "κραυγή", "translit": "kraugḗ", "pronunciation": "krow-gay'", "derivation": "from (G2896);", "definition": "an outcry (in notification, tumult or grief)", "kjv": "clamour, cry(-ing)."}, "G2907": {"greek": "κρέας", "translit": "kréas", "pronunciation": "kreh'-as", "derivation": "perhaps a primary word;", "definition": "(butcher's) meat", "kjv": "flesh."}, "G2909": {"greek": "κρείττων", "translit": "kreíttōn", "pronunciation": "krite'-tohn", "derivation": "comparative of a derivative of (G2904);", "definition": "stronger, i.e. (figuratively) better, i.e. nobler", "kjv": "best, better."}, "G2910": {"greek": "κρεμάννυμι", "translit": "kremánnymi", "pronunciation": "krem-an'-noo-mee", "derivation": "a prolonged form of a primary verb;", "definition": "to hang", "kjv": "hang."}, "G2911": {"greek": "κρημνός", "translit": "krēmnós", "pronunciation": "krame-nos'", "derivation": "from (G2910);", "definition": "overhanging, i.e. a precipice", "kjv": "steep place."}, "G2912": {"greek": "Κρής", "translit": "Krḗs", "pronunciation": "krace", "derivation": "from (G2914);", "definition": "a Cretan, i.e. inhabitant of Crete", "kjv": "Crete, Cretian."}, "G2913": {"greek": "Κρήσκης", "translit": "Krḗskēs", "pronunciation": "krace'-kace", "derivation": "of Latin origin;", "definition": "growing; Cresces (i.e. Crescens), a Christian", "kjv": "Crescens."}, "G2914": {"greek": "Κρήτη", "translit": "Krḗtē", "pronunciation": "kray'-tay", "derivation": "of uncertain derivation;", "definition": "Crete, an island in the Mediterranean", "kjv": "Crete."}, "G2915": {"greek": "κριθή", "translit": "krithḗ", "pronunciation": "kree-thay'", "derivation": "of uncertain derivation;", "definition": "barley", "kjv": "barley."}, "G2916": {"greek": "κρίθινος", "translit": "kríthinos", "pronunciation": "kree'-thee-nos", "derivation": "from (G2915);", "definition": "consisting of barley", "kjv": "barley."}, "G2917": {"greek": "κρίμα", "translit": "kríma", "pronunciation": "kree'-mah", "derivation": "from (G2919);", "definition": "a decision (the function or the effect, for or against (\"crime\"))", "kjv": "avenge, condemned, condemnation, damnation, + go to law, judgment."}, "G2918": {"greek": "κρίνον", "translit": "krínon", "pronunciation": "kree'-non", "derivation": "perhaps a prim word;", "definition": "a lily", "kjv": "lily."}, "G2919": {"greek": "κρίνω", "translit": "krínō", "pronunciation": "kree'-no", "derivation": "properly, to distinguish, i.e. decide (mentally or judicially);", "definition": "by implication, to try, condemn, punish", "kjv": "avenge, conclude, condemn, damn, decree, determine, esteem, judge, go to (sue at the) law, ordain, call in question, sentence to, think."}, "G2920": {"greek": "κρίσις", "translit": "krísis", "pronunciation": "kree'-sis", "derivation": "", "definition": "decision (subjectively or objectively, for or against); by extension, a tribunal; by implication, justice (especially, divine law)", "kjv": "accusation, condemnation, damnation, judgment."}, "G2921": {"greek": "Κρίσπος", "translit": "Kríspos", "pronunciation": "kris'-pos", "derivation": "of Latin origin;", "definition": "\"crisp\"; Crispus, a Corinthian", "kjv": "Crispus."}, "G2922": {"greek": "κριτήριον", "translit": "kritḗrion", "pronunciation": "kree-tay'-ree-on", "derivation": "neuter of a presumed derivative of (G2923);", "definition": "a rule of judging (\"criterion\"), i.e. (by implication) a tribunal", "kjv": "to judge, judgment (seat)."}, "G2923": {"greek": "κριτής", "translit": "kritḗs", "pronunciation": "kree-tace'", "derivation": "from (G2919);", "definition": "a judge (genitive case or specially)", "kjv": "judge."}, "G2924": {"greek": "κριτικός", "translit": "kritikós", "pronunciation": "krit-ee-kos'", "derivation": "from (G2923);", "definition": "decisive (\"critical\"), i.e. discriminative", "kjv": "discerner."}, "G2925": {"greek": "κρούω", "translit": "kroúō", "pronunciation": "kroo'-o", "derivation": "apparently a primary verb;", "definition": "to rap", "kjv": "knock."}, "G2926": {"greek": "κρύπτη", "translit": "krýptē", "pronunciation": "kroop-tay'", "derivation": "feminine of (G2927);", "definition": "a hidden place, i.e. cellar (\"crypt\")", "kjv": "secret."}, "G2927": {"greek": "κρυπτός", "translit": "kryptós", "pronunciation": "kroop-tos'", "derivation": "from (G2928);", "definition": "concealed, i.e. private", "kjv": "hid(-den), inward(-ly), secret."}, "G2928": {"greek": "κρύπτω", "translit": "krýptō", "pronunciation": "kroop'-to", "derivation": "a primary verb;", "definition": "to conceal (properly, by covering)", "kjv": "hide (self), keep secret, secret(-ly)."}, "G2929": {"greek": "κρυσταλλίζω", "translit": "krystallízō", "pronunciation": "kroos-tal-lid'-zo", "derivation": "from (G2930);", "definition": "to make (i.e. intransitively, resemble) ice (\"crystallize\")", "kjv": "be clear as crystal."}, "G2930": {"greek": "κρύσταλλος", "translit": "krýstallos", "pronunciation": "kroos'-tal-los", "derivation": "from a derivative of (frost);", "definition": "ice, i.e. (by analogy) rock \"crystal\"", "kjv": "crystal."}, "G2931": {"greek": "κρυφῆ", "translit": "kryphē", "pronunciation": "kroo-fay'", "derivation": "adverb from (G2928);", "definition": "privately", "kjv": "in secret."}, "G2932": {"greek": "κτάομαι", "translit": "ktáomai", "pronunciation": "ktah'-om-ahee", "derivation": "a primary verb;", "definition": "to get, i.e. acquire (by any means; own)", "kjv": "obtain, possess, provide, purchase."}, "G2933": {"greek": "κτῆμα", "translit": "ktēma", "pronunciation": "ktay'-mah", "derivation": "from (G2932);", "definition": "an acquirement, i.e. estate", "kjv": "possession."}, "G2934": {"greek": "κτῆνος", "translit": "ktēnos", "pronunciation": "ktay'-nos", "derivation": "from (G2932);", "definition": "property, i.e. (specially) a domestic animal", "kjv": "beast."}, "G2935": {"greek": "κτήτωρ", "translit": "ktḗtōr", "pronunciation": "ktay'-tore", "derivation": "from (G2932);", "definition": "an owner", "kjv": "possessor."}, "G2936": {"greek": "κτίζω", "translit": "ktízō", "pronunciation": "ktid'-zo", "derivation": "probably akin to (G2932) (through the idea of proprietorship of the manufacturer);", "definition": "to fabricate, i.e. found (form originally)", "kjv": "create, Creator, make."}, "G2937": {"greek": "κτίσις", "translit": "ktísis", "pronunciation": "ktis'-is", "derivation": "from (G2936);", "definition": "original formation (properly, the act; by implication, the thing, literally or figuratively)", "kjv": "building, creation, creature, ordinance."}, "G2938": {"greek": "κτίσμα", "translit": "ktísma", "pronunciation": "ktis'-mah", "derivation": "from (G2936);", "definition": "an original formation (concretely), i.e. product (created thing)", "kjv": "creature."}, "G2939": {"greek": "κτίστης", "translit": "ktístēs", "pronunciation": "ktis-tace'", "derivation": "from (G2936);", "definition": "a founder, i.e. God (as author of all things)", "kjv": "Creator."}, "G2940": {"greek": "κυβεία", "translit": "kybeía", "pronunciation": "koo-bi'-ah", "derivation": "from (a \"cube\", i.e. die for playing);", "definition": "gambling, i.e. (figuratively) artifice or fraud", "kjv": "sleight."}, "G2941": {"greek": "κυβέρνησις", "translit": "kybérnēsis", "pronunciation": "koo-ber'-nay-sis", "derivation": "from (of Latin origin, to steer);", "definition": "pilotage, i.e. (figuratively) directorship (in the church)", "kjv": "government."}, "G2942": {"greek": "κυβερνήτης", "translit": "kybernḗtēs", "pronunciation": "koo-ber-nay'-tace", "derivation": "from the same as (G2941);", "definition": "helmsman, i.e. (by implication) captain", "kjv": "(ship) master."}, "G2943": {"greek": "κυκλόθεν", "translit": "kyklóthen", "pronunciation": "koo-kloth'-en", "derivation": "adverb from the same as (G2945);", "definition": "from the circle, i.e. all around", "kjv": "(round) about."}, "G2944": {"greek": "κυκλόω", "translit": "kyklóō", "pronunciation": "koo-klo'-o", "derivation": "from the same as (G2945);", "definition": "to encircle, i.e. surround", "kjv": "compass (about), come (stand) round about."}, "G2945": {"greek": "κύκλῳ", "translit": "kýklōi", "pronunciation": "koo'-klo", "derivation": "as if dative case of (a ring, \"cycle\"; akin to (G2947));", "definition": "i.e. in a circle (by implication, of (G1722)), i.e. (adverbially) all around", "kjv": "round about."}, "G2946": {"greek": "κύλισμα", "translit": "kýlisma", "pronunciation": "koo'-lis-mah", "derivation": "from (G2947);", "definition": "a wallow (the effect of rolling), i.e. filth", "kjv": "wallowing."}, "G2947": {"greek": "κυλιόω", "translit": "kylióō", "pronunciation": "koo-lee-o'-o", "derivation": "from the base of (G2949) (through the idea of circularity; compare (G2945), (G1507));", "definition": "to roll about", "kjv": "wallow."}, "G2948": {"greek": "κυλλός", "translit": "kyllós", "pronunciation": "kool-los'", "derivation": "from the same as (G2947);", "definition": "rocking about, i.e. crippled (maimed, in feet or hands)", "kjv": "maimed."}, "G2949": {"greek": "κῦμα", "translit": "kŷma", "pronunciation": "koo'-mah", "derivation": "from (to swell (with young), i.e. bend, curve);", "definition": "a billow (as bursting or toppling)", "kjv": "wave."}, "G2950": {"greek": "κύμβαλον", "translit": "kýmbalon", "pronunciation": "koom'-bal-on", "derivation": "from a derivative of the base of (G2949);", "definition": "a \"cymbal\" (as hollow)", "kjv": "cymbal."}, "G2951": {"greek": "κύμινον", "translit": "kýminon", "pronunciation": "koo'-min-on", "derivation": "of foreign origin (compare (G3646));", "definition": "dill or fennel (\"cummin\")", "kjv": "cummin."}, "G2952": {"greek": "κυνάριον", "translit": "kynárion", "pronunciation": "koo-nar'-ee-on", "derivation": "neuter of a presumed derivative of (G2965);", "definition": "a puppy", "kjv": "dog."}, "G2953": {"greek": "Κύπριος", "translit": "Kýprios", "pronunciation": "koo'-pree-os", "derivation": "from (G2954);", "definition": "a Cyprian (Cypriot), i.e. inhabitant of Cyprus", "kjv": "of Cyprus."}, "G2954": {"greek": "Κύπρος", "translit": "Kýpros", "pronunciation": "koo'-pros", "derivation": "of uncertain origin;", "definition": "Cyprus, an island in the Mediterranean", "kjv": "Cyprus."}, "G2955": {"greek": "κύπτω", "translit": "kýptō", "pronunciation": "koop'-to", "derivation": "probably from the base of (G2949);", "definition": "to bend forward", "kjv": "stoop (down)."}, "G2956": {"greek": "Κυρηναῖος", "translit": "Kyrēnaîos", "pronunciation": "koo-ray-nah'-yos", "derivation": "from (G2957);", "definition": "i.e. Cyrenæan, i.e. inhabitant of Cyrene", "kjv": "of Cyrene, Cyrenian."}, "G2957": {"greek": "Κυρήνη", "translit": "Kyrḗnē", "pronunciation": "koo-ray'-nay", "derivation": "of uncertain derivation;", "definition": "Cyrene, a region of Africa", "kjv": "Cyrene."}, "G2958": {"greek": "Κυρήνιος", "translit": "Kyrḗnios", "pronunciation": "koo-ray'-nee-os", "derivation": "of Latin origin;", "definition": "Cyrenius (i.e. Quirinus), a Roman", "kjv": "Cyrenius."}, "G2959": {"greek": "Κυρία", "translit": "Kyría", "pronunciation": "koo-ree'-ah", "derivation": "feminine of (G2962);", "definition": "Cyria, a Christian woman", "kjv": "lady."}, "G2960": {"greek": "κυριακός", "translit": "kyriakós", "pronunciation": "koo-ree-ak-os'", "derivation": "from (G2962);", "definition": "belonging to the Lord (Jehovah or Jesus)", "kjv": "Lord's."}, "G2961": {"greek": "κυριεύω", "translit": "kyrieúō", "pronunciation": "ko-ree-yoo'-o", "derivation": "from (G2962);", "definition": "to rule", "kjv": "have dominion over, lord, be lord of, exercise lordship over."}, "G2962": {"greek": "κύριος", "translit": "kýrios", "pronunciation": "koo'-ree-os", "derivation": "from (supremacy);", "definition": "supreme in authority, i.e. (as noun) controller; by implication, Master (as a respectful title)", "kjv": "God, Lord, master, Sir."}, "G2963": {"greek": "κυριότης", "translit": "kyriótēs", "pronunciation": "koo-ree-ot'-ace", "derivation": "from (G2962);", "definition": "mastery, i.e. (concretely and collectively) rulers", "kjv": "dominion, government."}, "G2964": {"greek": "κυρόω", "translit": "kyróō", "pronunciation": "koo-ro'-o", "derivation": "from the same as (G2962);", "definition": "to make authoritative, i.e. ratify", "kjv": "confirm."}, "G2965": {"greek": "κύων", "translit": "kýōn", "pronunciation": "koo'-ohn", "derivation": "a primary word;", "definition": "a dog (\"hound\") (literally or figuratively)", "kjv": "dog."}, "G2966": {"greek": "κῶλον", "translit": "kōlon", "pronunciation": "ko'-lon", "derivation": "from the base of (G2849);", "definition": "a limb of the body (as if lopped)", "kjv": "carcase."}, "G2967": {"greek": "κωλύω", "translit": "kōlýō", "pronunciation": "ko-loo'-o", "derivation": "from the base of (G2849);", "definition": "to estop, i.e. prevent (by word or act)", "kjv": "forbid, hinder, keep from, let, not suffer, withstand."}, "G2968": {"greek": "κώμη", "translit": "kṓmē", "pronunciation": "ko'-may", "derivation": "from (G2749);", "definition": "a hamlet (as if laid down)", "kjv": "town, village."}, "G2969": {"greek": "κωμόπολις", "translit": "kōmópolis", "pronunciation": "ko-mop'-ol-is", "derivation": "from (G2968) and (G4172);", "definition": "an unwalled city", "kjv": "town."}, "G2970": {"greek": "κῶμος", "translit": "kōmos", "pronunciation": "ko'-mos", "derivation": "from (G2749);", "definition": "a carousal (as if letting loose)", "kjv": "revelling, rioting."}, "G2971": {"greek": "κώνωψ", "translit": "kṓnōps", "pronunciation": "ko'-nopes", "derivation": "apparently a derivative of the base of (G2759) and a derivative of (G3700);", "definition": "a mosquito (from its stinging proboscis)", "kjv": "gnat."}, "G2972": {"greek": "Κώς", "translit": "Kṓs", "pronunciation": "koce", "derivation": "of uncertain origin;", "definition": "Cos, an island in the Mediterranean", "kjv": "Cos."}, "G2973": {"greek": "Κωσάμ", "translit": "Kōsám", "pronunciation": "ko-sam'", "derivation": "of Hebrew origin (compare (G7081));", "definition": "Cosam (i.e. Kosam) an Israelite", "kjv": "Cosam."}, "G2974": {"greek": "κωφός", "translit": "kōphós", "pronunciation": "ko-fos'", "derivation": "from (G2875);", "definition": "blunted, i.e. (figuratively) of hearing (deaf) or speech (dumb)", "kjv": "deaf, dumb, speechless."}, "G2975": {"greek": "λαγχάνω", "translit": "lanchánō", "pronunciation": "lang-khan'-o", "derivation": "a prolonged form of a primary verb, which is only used as an alternate in certain tenses;", "definition": "to lot, i.e. determine (by implication, receive) especially by lot", "kjv": "his lot be, cast lots, obtain."}, "G2976": {"greek": "Λάζαρος", "translit": "Lázaros", "pronunciation": "lad'-zar-os", "derivation": "probably of Hebrew origin ((G499));", "definition": "Lazarus (i.e. Elazar), the name of two Israelites (one imaginary)", "kjv": "Lazarus."}, "G2977": {"greek": "λάθρα", "translit": "láthra", "pronunciation": "lath'-rah", "derivation": "adverb from (G2990);", "definition": "privately", "kjv": "privily, secretly."}, "G2978": {"greek": "λαῖλαψ", "translit": "laîlaps", "pronunciation": "lah'-ee-laps", "derivation": "of uncertain derivation;", "definition": "a whirlwind (squall)", "kjv": "storm, tempest."}, "G2979": {"greek": "λακτίζω", "translit": "laktízō", "pronunciation": "lak-tid'-zo", "derivation": "from adverb (heelwise);", "definition": "to recalcitrate", "kjv": "kick."}, "G2980": {"greek": "λαλέω", "translit": "laléō", "pronunciation": "lal-eh'-o", "derivation": "a prolonged form of an otherwise obsolete verb;", "definition": "to talk, i.e. utter words", "kjv": "preach, say, speak (after), talk, tell, utter."}, "G2981": {"greek": "λαλιά", "translit": "laliá", "pronunciation": "lal-ee-ah'", "derivation": "from (G2980);", "definition": "talk", "kjv": "saying, speech."}, "G2982": {"greek": "λαμά", "translit": "lamá", "pronunciation": "lam-ah'", "derivation": "of Hebrew origin ((G4100) with prepositional prefix);", "definition": "lama (i.e. why)", "kjv": "lama."}, "G2983": {"greek": "λαμβάνω", "translit": "lambánō", "pronunciation": "lam-ban'-o", "derivation": "a prolonged form of a primary verb, which is use only as an alternate in certain tenses; to take (in very many applications, literally and figuratively (properly objective or active, to get hold of; whereas (G1209) is rather subjective or passive, to have offered to one;", "definition": "while (G138) is more violent, to seize or remove))", "kjv": "accept, + be amazed, assay, attain, bring, X when I call, catch, come on (X unto), + forget, have, hold, obtain, receive (X after), take (away, up)."}, "G2984": {"greek": "Λάμεχ", "translit": "Lámech", "pronunciation": "lam'-ekh", "derivation": "of Hebrew origin ((G3929));", "definition": "Lamech (i.e. Lemek), a patriarch", "kjv": "Lamech."}, "G2985": {"greek": "λαμπάς", "translit": "lampás", "pronunciation": "lam-pas'", "derivation": "from (G2989);", "definition": "a \"lamp\" or flambeau", "kjv": "lamp, light, torch."}, "G2986": {"greek": "λαμπρός", "translit": "lamprós", "pronunciation": "lam-pros'", "derivation": "from the same as (G2985);", "definition": "radiant; by analogy, limpid; figuratively, magnificent or sumptuous (in appearance)", "kjv": "bright, clear, gay, goodly, gorgeous, white."}, "G2987": {"greek": "λαμπρότης", "translit": "lamprótēs", "pronunciation": "lam-prot'-ace", "derivation": "from (G2986);", "definition": "brilliancy", "kjv": "brightness."}, "G2988": {"greek": "λαμπρῶς", "translit": "lamprōs", "pronunciation": "lam-proce'", "derivation": "adverb from (G2986);", "definition": "brilliantly, i.e. figuratively, luxuriously", "kjv": "sumptuously."}, "G2989": {"greek": "λάμπω", "translit": "lámpō", "pronunciation": "lam'-po", "derivation": "a primary verb;", "definition": "to beam, i.e. radiate brilliancy (literally or figuratively)", "kjv": "give light, shine."}, "G2990": {"greek": "λανθάνω", "translit": "lanthánō", "pronunciation": "lan-than'-o", "derivation": "a prolonged form of a primary verb, which is used only as an alternate in certain tenses;", "definition": "to lie hid (literally or figuratively); often used adverbially, unwittingly", "kjv": "be hid, be ignorant of, unawares."}, "G2991": {"greek": "λαξευτός", "translit": "laxeutós", "pronunciation": "lax-yoo-tos'", "derivation": "from a compound of (a stone) and the base of (G3584) (in its original sense of scraping);", "definition": "rock-quarried", "kjv": "hewn in stone."}, "G2992": {"greek": "λαός", "translit": "laós", "pronunciation": "lah-os'", "derivation": "apparently a primary word;", "definition": "a people (in general; thus differing from (G1218), which denotes one's own populace)", "kjv": "people."}, "G2993": {"greek": "Λαοδίκεια", "translit": "Laodíkeia", "pronunciation": "lah-od-ik'-i-ah", "derivation": "from a compound of (G2992) and (G1349);", "definition": "Laodicia, a place in Asia Minor", "kjv": "Laodicea."}, "G2994": {"greek": "Λαοδικεύς", "translit": "Laodikeús", "pronunciation": "lah-od-ik-yooce'", "derivation": "from (G2993);", "definition": "a Laodicean, i.e. inhabitant of Laodicia", "kjv": "Laodicean."}, "G2995": {"greek": "λάρυγξ", "translit": "lárynx", "pronunciation": "lar'-oongks", "derivation": "of uncertain derivation;", "definition": "the throat (\"larynx\")", "kjv": "throat."}, "G2996": {"greek": "Λασαία", "translit": "Lasaía", "pronunciation": "las-ah'-yah", "derivation": "of uncertain origin;", "definition": "Lasæa, a place in Crete", "kjv": "Lasea."}, "G2997": {"greek": "λάσχω", "translit": "láschō", "pronunciation": "las'-kho", "derivation": "a strengthened form of a primary verb, which only occurs in this and another prolonged form as alternate in certain tenses;", "definition": "to crack open (from a fall)", "kjv": "burst asunder."}, "G2998": {"greek": "λατομέω", "translit": "latoméō", "pronunciation": "lat-om-eh'-o", "derivation": "from the same as the first part of (G2991) and the base of (G5114);", "definition": "to quarry", "kjv": "hew."}, "G2999": {"greek": "λατρεία", "translit": "latreía", "pronunciation": "lat-ri'-ah", "derivation": "from (G3000);", "definition": "ministration of God, i.e. worship", "kjv": "(divine) service."}, "G3000": {"greek": "λατρεύω", "translit": "latreúō", "pronunciation": "lat-ryoo'-o", "derivation": "from (a hired menial);", "definition": "to minister (to God), i.e. render religious homage", "kjv": "serve, do the service, worship(-per)."}, "G3001": {"greek": "λάχανον", "translit": "láchanon", "pronunciation": "lakh'-an-on", "derivation": "from (to dig);", "definition": "a vegetable", "kjv": "herb."}, "G3003": {"greek": "λεγεών", "translit": "legeṓn", "pronunciation": "leg-eh-ohn'", "derivation": "of Latin origin;", "definition": "a \"legion\", i.e. Roman regiment (figuratively)", "kjv": "legion."}, "G3004": {"greek": "λέγω", "translit": "légō", "pronunciation": "leg'-o", "derivation": "a primary verb;", "definition": "properly, to \"lay\" forth, i.e. (figuratively) relate (in words (usually of systematic or set discourse; whereas (G2036) and (G5346) generally refer to an individual expression or speech respectively; while (G4483) is properly to break silence merely, and (G2980) means an extended or random harangue)); by implication, to mean", "kjv": "ask, bid, boast, call, describe, give out, name, put forth, say(-ing, on), shew, speak, tell, utter."}, "G3005": {"greek": "λεῖμμα", "translit": "leîmma", "pronunciation": "lime'-mah", "derivation": "from (G3007);", "definition": "a remainder", "kjv": "remnant."}, "G3006": {"greek": "λεῖος", "translit": "leîos", "pronunciation": "li'-os", "derivation": "apparently a primary word;", "definition": "smooth, i.e. \"level\"", "kjv": "smooth."}, "G3007": {"greek": "λείπω", "translit": "leípō", "pronunciation": "li'-po", "derivation": "a primary verb;", "definition": "to leave, i.e. (intransitively or passively) to fail or be absent", "kjv": "be destitute (wanting), lack."}, "G3008": {"greek": "λειτουργέω", "translit": "leitourgéō", "pronunciation": "li-toorg-eh'-o", "derivation": "from (G3011);", "definition": "to be a public servant, i.e. (by analogy) to perform religious or charitable functions (worship, obey, relieve)", "kjv": "minister."}, "G3009": {"greek": "λειτουργία", "translit": "leitourgía", "pronunciation": "li-toorg-ee'-ah", "derivation": "from (G3008);", "definition": "public function (as priest (\"liturgy\") or almsgiver)", "kjv": "ministration(-try), service."}, "G3010": {"greek": "λειτουργικός", "translit": "leitourgikós", "pronunciation": "li-toorg-ik-os'", "derivation": "from the same as (G3008);", "definition": "functional publicly (\"liturgic\"); i.e. beneficient", "kjv": "ministering."}, "G3011": {"greek": "λειτουργός", "translit": "leitourgós", "pronunciation": "li-toorg-os'", "derivation": "from a derivative of (G2992) and (G2041);", "definition": "a public servant, i.e. a functionary in the Temple or Gospel, or (genitive case) a worshipper (of God) or benefactor (of man)", "kjv": "minister(-ed)."}, "G3012": {"greek": "λέντιον", "translit": "léntion", "pronunciation": "len'-tee-on", "derivation": "of Latin origin;", "definition": "a \"linen\" cloth, i.e. apron", "kjv": "towel."}, "G3013": {"greek": "λεπίς", "translit": "lepís", "pronunciation": "lep-is'", "derivation": "from (to peel);", "definition": "a flake", "kjv": "scale."}, "G3014": {"greek": "λέπρα", "translit": "lépra", "pronunciation": "lep'-rah", "derivation": "from the same as (G3013);", "definition": "scaliness, i.e. \"leprosy\"", "kjv": "leprosy."}, "G3015": {"greek": "λεπρός", "translit": "leprós", "pronunciation": "lep-ros'", "derivation": "from the same as (G3014);", "definition": "scaly, i.e. leprous (a leper)", "kjv": "leper."}, "G3016": {"greek": "λεπτόν", "translit": "leptón", "pronunciation": "lep-ton'", "derivation": "neuter of a derivative of the same as (G3013);", "definition": "something scaled (light), i.e. a small coin", "kjv": "mite."}, "G3017": {"greek": "Λευΐ", "translit": "Leuḯ", "pronunciation": "lyoo'-ee", "derivation": "of Hebrew origin ((G3878));", "definition": "Levi, the name of three Israelites", "kjv": "Levi."}, "G3018": {"greek": "Λευΐς", "translit": "Leuḯs", "pronunciation": "lyoo-is'", "derivation": "a form of (G3017);", "definition": "Lewis (i.e. Levi), a Christian", "kjv": "Levi."}, "G3019": {"greek": "Λευΐτης", "translit": "Leuḯtēs", "pronunciation": "lyoo-ee'-tace", "derivation": "from (G3017);", "definition": "a Levite, i.e. descendant of Levi", "kjv": "Levite."}, "G3020": {"greek": "Λευϊτικός", "translit": "Leuïtikós", "pronunciation": "lyoo-it'-ee-kos", "derivation": "from (G3019);", "definition": "Levitic, i.e. relating to the Levites", "kjv": "Levitical."}, "G3021": {"greek": "λευκαίνω", "translit": "leukaínō", "pronunciation": "lyoo-kah'-ee-no", "derivation": "from (G3022);", "definition": "to whiten", "kjv": "make white, whiten."}, "G3022": {"greek": "λευκός", "translit": "leukós", "pronunciation": "lyoo-kos'", "derivation": "from (\"light\");", "definition": "white", "kjv": "white."}, "G3023": {"greek": "λέων", "translit": "léōn", "pronunciation": "leh-ohn'", "derivation": "a primary word;", "definition": "a \"lion\"", "kjv": "lion."}, "G3024": {"greek": "λήθη", "translit": "lḗthē", "pronunciation": "lay'-thay", "derivation": "from (G2990);", "definition": "forgetfulness", "kjv": "+ forget."}, "G3025": {"greek": "ληνός", "translit": "lēnós", "pronunciation": "lay-nos'", "derivation": "apparently a primary word;", "definition": "a trough, i.e. wine-vat", "kjv": "winepress."}, "G3026": {"greek": "λῆρος", "translit": "lēros", "pronunciation": "lay'-ros", "derivation": "apparently a primary word;", "definition": "twaddle, i.e. an incredible story", "kjv": "idle tale."}, "G3027": {"greek": "λῃστής", "translit": "lēistḗs", "pronunciation": "lace-tace'", "derivation": "from (to plunder);", "definition": "a brigand", "kjv": "robber, thief."}, "G3028": {"greek": "λῆμψις", "translit": "lēmpsis", "pronunciation": "lape'-sis", "derivation": "from (G2983);", "definition": "receipt (the act)", "kjv": "receiving."}, "G3029": {"greek": "λίαν", "translit": "lían", "pronunciation": "lee'-an", "derivation": "of uncertain affinity;", "definition": "much (adverbially)", "kjv": "exceeding, great(-ly), sore, very (+ chiefest)."}, "G3030": {"greek": "λίβανος", "translit": "líbanos", "pronunciation": "lib'-an-os", "derivation": "of foreign origin ((G3828));", "definition": "the incense-tree, i.e. (by implication) incense itself", "kjv": "frankincense."}, "G3031": {"greek": "λιβανωτός", "translit": "libanōtós", "pronunciation": "lib-an-o-tos'", "derivation": "from (G3030);", "definition": "frankincense, i.e. (by extension) a censer for burning it", "kjv": "censer."}, "G3032": {"greek": "Λιβερτῖνος", "translit": "Libertînos", "pronunciation": "lib-er-tee'-nos", "derivation": "of Latin origin;", "definition": "a Roman freedman", "kjv": "Libertine."}, "G3033": {"greek": "Λιβύη", "translit": "Libýē", "pronunciation": "lib-oo'-ay", "derivation": "probably from (G3047);", "definition": "Libye, a region of Africa", "kjv": "Libya."}, "G3034": {"greek": "λιθάζω", "translit": "litházō", "pronunciation": "lith-ad'-zo", "derivation": "from (G3037);", "definition": "to lapidate", "kjv": "stone."}, "G3035": {"greek": "λίθινος", "translit": "líthinos", "pronunciation": "lith-ee'-nos", "derivation": "from (G3037);", "definition": "stony, i.e. made of stone", "kjv": "of stone."}, "G3036": {"greek": "λιθοβολέω", "translit": "lithoboléō", "pronunciation": "lith-ob-ol-eh'-o", "derivation": "from a compound of (G3037) and (G906);", "definition": "to throw stones, i.e. lapidate", "kjv": "stone, cast stones."}, "G3037": {"greek": "λίθος", "translit": "líthos", "pronunciation": "lee'-thos", "derivation": "apparently a primary word;", "definition": "a stone (literally or figuratively)", "kjv": "(mill-, stumbling-)stone."}, "G3038": {"greek": "λιθόστρωτος", "translit": "lithóstrōtos", "pronunciation": "lith-os'-tro-tos", "derivation": "from (G3037) and a derivative of (G4766);", "definition": "stone-strewed, i.e. a tessellated mosaic on which the Roman tribunal was placed", "kjv": "Pavement."}, "G3039": {"greek": "λικμάω", "translit": "likmáō", "pronunciation": "lik-mah'-o", "derivation": "from , the equivalent of (a winnowing fan or basket);", "definition": "to winnow, i.e. (by analogy), to triturate", "kjv": "grind to powder."}, "G3040": {"greek": "λιμήν", "translit": "limḗn", "pronunciation": "lee-mane'", "derivation": "apparently a primary word;", "definition": "a harbor", "kjv": "haven."}, "G3041": {"greek": "λίμνη", "translit": "límnē", "pronunciation": "lim'-nay", "derivation": "probably from (G3040) (through the idea of nearness of shore);", "definition": "a pond (large or small)", "kjv": "lake."}, "G3042": {"greek": "λιμός", "translit": "limós", "pronunciation": "lee-mos'", "derivation": "probably from (G3007) (through the idea of destitution);", "definition": "a scarcity of food", "kjv": "dearth, famine, hunger."}, "G3043": {"greek": "λίνον", "translit": "línon", "pronunciation": "lee'-non", "derivation": "probably a primary word;", "definition": "flax, i.e. (by implication) \"linen\"", "kjv": "linen."}, "G3044": {"greek": "Λίνος", "translit": "Línos", "pronunciation": "lee'-nos", "derivation": "perhaps from (G3043);", "definition": "Linus, a Christian", "kjv": "Linus."}, "G3045": {"greek": "λιπαρός", "translit": "liparós", "pronunciation": "lip-ar-os'", "derivation": "from (grease);", "definition": "fat, i.e. (figuratively) sumptuous", "kjv": "dainty."}, "G3046": {"greek": "λίτρα", "translit": "lítra", "pronunciation": "lee'-trah", "derivation": "of Latin origin (libra);", "definition": "a pound in weight", "kjv": "pound."}, "G3047": {"greek": "λίψ", "translit": "líps", "pronunciation": "leeps", "derivation": "probably from (to pour a \"libation\");", "definition": "the south(- west) wind (as bringing rain, i.e. (by extension) the south quarter)", "kjv": "southwest."}, "G3048": {"greek": "λογία", "translit": "logía", "pronunciation": "log-ee'-ah", "derivation": "from (G3056) (in the commercial sense);", "definition": "a contribution", "kjv": "collection, gathering."}, "G3049": {"greek": "λογίζομαι", "translit": "logízomai", "pronunciation": "log-id'-zom-ahee", "derivation": "middle voice from (G3056);", "definition": "to take an inventory, i.e. estimate (literally or figuratively)", "kjv": "conclude, (ac-)count (of), + despise, esteem, impute, lay, number, reason, reckon, suppose, think (on)."}, "G3050": {"greek": "λογικός", "translit": "logikós", "pronunciation": "log-ik-os'", "derivation": "from (G3056);", "definition": "rational (\"logical\")", "kjv": "reasonable, of the word."}, "G3051": {"greek": "λόγιον", "translit": "lógion", "pronunciation": "log'-ee-on", "derivation": "neuter of (G3052);", "definition": "an utterance (of God)", "kjv": "oracle."}, "G3052": {"greek": "λόγιος", "translit": "lógios", "pronunciation": "log'-ee-os", "derivation": "from (G3056);", "definition": "fluent, i.e. an orator", "kjv": "eloquent."}, "G3053": {"greek": "λογισμός", "translit": "logismós", "pronunciation": "log-is-mos'", "derivation": "from (G3049);", "definition": "computation, i.e. (figuratively) reasoning (conscience, conceit)", "kjv": "imagination, thought."}, "G3054": {"greek": "λογομαχέω", "translit": "logomachéō", "pronunciation": "log-om-akh-eh'-o", "derivation": "from a compound of (G3056) and (G3164);", "definition": "to be disputatious (on trifles)", "kjv": "strive about words."}, "G3055": {"greek": "λογομαχία", "translit": "logomachía", "pronunciation": "log-om-akh-ee'-ah", "derivation": "from the same as (G3054);", "definition": "disputation about trifles (\"logomachy\")", "kjv": "strife of words."}, "G3056": {"greek": "λόγος", "translit": "lógos", "pronunciation": "log'-os", "derivation": "from (G3004);", "definition": "something said (including the thought); by implication, a topic (subject of discourse), also reasoning (the mental faculty) or motive; by extension, a computation; specially, (with the article in John) the Divine Expression (i.e. Christ)", "kjv": "account, cause, communication, X concerning, doctrine, fame, X have to do, intent, matter, mouth, preaching, question, reason, + reckon, remove, say(-ing), shew, X speaker, speech, talk, thing, + none of these things move me, tidings, treatise, utterance, word, work."}, "G3057": {"greek": "λόγχη", "translit": "lónchē", "pronunciation": "long'-khay", "derivation": "perhaps a primary word;", "definition": "a \"lance\"", "kjv": "spear."}, "G3058": {"greek": "λοιδορέω", "translit": "loidoréō", "pronunciation": "loy-dor-eh'-o", "derivation": "from (G3060);", "definition": "to reproach, i.e. vilify", "kjv": "revile."}, "G3059": {"greek": "λοιδορία", "translit": "loidoría", "pronunciation": "loy-dor-ee'-ah", "derivation": "from (G3060);", "definition": "slander or vituperation", "kjv": "railing, reproach(-fully)."}, "G3060": {"greek": "λοίδορος", "translit": "loídoros", "pronunciation": "loy'-dor-os", "derivation": "from (mischief);", "definition": "abusive, i.e. a blackguard", "kjv": "railer, reviler."}, "G3061": {"greek": "λοιμός", "translit": "loimós", "pronunciation": "loy'-mos", "derivation": "of uncertain affinity;", "definition": "a plague (literally, the disease, or figuratively, a pest)", "kjv": "pestilence(-t)."}, "G3062": {"greek": "λοιποί", "translit": "loipoí", "pronunciation": "loy-poy'", "derivation": "masculine plural of a derivative of (G3007);", "definition": "remaining ones", "kjv": "other, which remain, remnant, residue, rest."}, "G3063": {"greek": "λοιπόν", "translit": "loipón", "pronunciation": "loy-pon'", "derivation": "neuter singular of the same as (G3062);", "definition": "something remaining (adverbially)", "kjv": "besides, finally, furthermore, (from) henceforth, moreover, now, + it remaineth, then."}, "G3064": {"greek": "λοιποῦ", "translit": "loipoû", "pronunciation": "loy-poo'", "derivation": "genitive case singular of the same as (G3062);", "definition": "remaining time", "kjv": "from henceforth."}, "G3065": {"greek": "Λουκᾶς", "translit": "Loukâs", "pronunciation": "loo-kas'", "derivation": "contracted from Latin Lucanus;", "definition": "Lucas, a Christian", "kjv": "Lucas, Luke."}, "G3066": {"greek": "Λούκιος", "translit": "Loúkios", "pronunciation": "loo'-kee-os", "derivation": "of Latin origin;", "definition": "illuminative; Lucius, a Christian", "kjv": "Lucius."}, "G3067": {"greek": "λουτρόν", "translit": "loutrón", "pronunciation": "loo-tron'", "derivation": "from (G3068);", "definition": "a bath, i.e. (figuratively), baptism", "kjv": "washing."}, "G3068": {"greek": "λούω", "translit": "loúō", "pronunciation": "loo'-o", "derivation": "a primary verb;", "definition": "to bathe (the whole person; whereas (G3538) means to wet a part only, and (G4150) to wash, cleanse garments exclusively)", "kjv": "wash."}, "G3069": {"greek": "Λύδδα", "translit": "Lýdda", "pronunciation": "lud'-dah", "derivation": "of Hebrew origin ((G3850));", "definition": "Lydda (i.e. Lod), a place in Palestine", "kjv": "Lydda."}, "G3070": {"greek": "Λυδία", "translit": "Lydía", "pronunciation": "loo-dee'-ah", "derivation": "properly, feminine of Ludios (of foreign origin) (a Lydian, in Asia Minor);", "definition": "Lydia, a Christian woman", "kjv": "Lydia."}, "G3071": {"greek": "Λυκαονία", "translit": "Lykaonía", "pronunciation": "loo-kah-on-ee'-ah", "derivation": "perhaps remotely from (G3074);", "definition": "Lycaonia, a region of Asia Minor", "kjv": "Lycaonia."}, "G3072": {"greek": "Λυκαονιστί", "translit": "Lykaonistí", "pronunciation": "loo-kah-on-is-tee'", "derivation": "adverb from a derivative of (G3071);", "definition": "Lycaonistically, i.e. in the language of the Lycaonians", "kjv": "in the speech of Lycaonia."}, "G3073": {"greek": "Λυκία", "translit": "Lykía", "pronunciation": "loo-kee'-ah", "derivation": "probably remotely from (G3074);", "definition": "Lycia, a province of Asia Minor", "kjv": "Lycia."}, "G3074": {"greek": "λύκος", "translit": "lýkos", "pronunciation": "loo'-kos", "derivation": "perhaps akin to the base of (G3022) (from the whitish hair);", "definition": "a wolf", "kjv": "wolf."}, "G3075": {"greek": "λυμαίνομαι", "translit": "lymaínomai", "pronunciation": "loo-mah'-ee-nom-ahee", "derivation": "middle voice from a probably derivative of (G3089) (meaning filth);", "definition": "properly, to soil, i.e. (figuratively) insult (maltreat)", "kjv": "make havock of."}, "G3076": {"greek": "λυπέω", "translit": "lypéō", "pronunciation": "loo-peh'-o", "derivation": "from (G3077);", "definition": "to distress; reflexively or passively, to be sad", "kjv": "cause grief, grieve, be in heaviness, (be) sorrow(-ful), be (make) sorry."}, "G3077": {"greek": "λύπη", "translit": "lýpē", "pronunciation": "loo'-pay", "derivation": "apparently a primary word;", "definition": "sadness", "kjv": "grief, grievous, + grudgingly, heaviness, sorrow."}, "G3078": {"greek": "Λυσανίας", "translit": "Lysanías", "pronunciation": "loo-san-ee'-as", "derivation": "from (G3080) and (trouble);", "definition": "grief-dispelling; Lysanias, a governor of Abilene", "kjv": "Lysanias."}, "G3079": {"greek": "Λυσίας", "translit": "Lysías", "pronunciation": "loo-see'-as", "derivation": "of uncertain affinity;", "definition": "Lysias, a Roman", "kjv": "Lysias."}, "G3080": {"greek": "λύσις", "translit": "lýsis", "pronunciation": "loo'-sis", "derivation": "from (G3089);", "definition": "a loosening, i.e. (specially), divorce", "kjv": "to be loosed."}, "G3081": {"greek": "λυσιτελεῖ", "translit": "lysiteleî", "pronunciation": "loo-sit-el-i'", "derivation": "third person singular present indicative active of a derivative of a compound of (G3080) and (G5056);", "definition": "impersonally, it answers the purpose, i.e. is advantageous", "kjv": "it is better."}, "G3082": {"greek": "Λύστρα", "translit": "Lýstra", "pronunciation": "loos'-trah", "derivation": "of uncertain origin;", "definition": "Lystra, a place in Asia Minor", "kjv": "Lystra."}, "G3083": {"greek": "λύτρον", "translit": "lýtron", "pronunciation": "loo'-tron", "derivation": "from (G3089);", "definition": "something to loosen with, i.e. a redemption price (figuratively, atonement)", "kjv": "ransom."}, "G3084": {"greek": "λυτρόω", "translit": "lytróō", "pronunciation": "loo-tro'-o", "derivation": "from (G3083);", "definition": "to ransom (literally or figuratively)", "kjv": "redeem."}, "G3085": {"greek": "λύτρωσις", "translit": "lýtrōsis", "pronunciation": "loo'-tro-sis", "derivation": "from (G3084);", "definition": "a ransoming (figuratively)", "kjv": "+ redeemed, redemption."}, "G3086": {"greek": "λυτρωτής", "translit": "lytrōtḗs", "pronunciation": "loo-tro-tace'", "derivation": "from (G3084);", "definition": "a redeemer (figuratively)", "kjv": "deliverer."}, "G3087": {"greek": "λυχνία", "translit": "lychnía", "pronunciation": "lookh-nee'-ah", "derivation": "from (G3088);", "definition": "a lamp-stand (literally or figuratively)", "kjv": "candlestick."}, "G3088": {"greek": "λύχνος", "translit": "lýchnos", "pronunciation": "lookh'-nos", "derivation": "from the base of (G3022);", "definition": "a portable lamp or other illuminator (literally or figuratively)", "kjv": "candle, light."}, "G3089": {"greek": "λύω", "translit": "lýō", "pronunciation": "loo'-o", "derivation": "a primary verb;", "definition": "to \"loosen\" (literally or figuratively)", "kjv": "break (up), destroy, dissolve, (un-)loose, melt, put off."}, "G3090": {"greek": "Λωΐς", "translit": "Lōḯs", "pronunciation": "lo-ece'", "derivation": "of uncertain origin;", "definition": "Lois, a Christian woman", "kjv": "Lois."}, "G3091": {"greek": "Λώτ", "translit": "Lṓt", "pronunciation": "lote", "derivation": "of Hebrew origin ((G3876));", "definition": "Lot, a patriarch", "kjv": "Lot."}, "G3092": {"greek": "Μαάθ", "translit": "Maáth", "pronunciation": "mah-ath'", "derivation": "probably of Hebrew origin;", "definition": "Maath, an Israelite", "kjv": "Maath."}, "G3093": {"greek": "Μαγδαλά", "translit": "Magdalá", "pronunciation": "mag-dal-ah'", "derivation": "of Chaldee origin (compare (G4026));", "definition": "the tower; Magdala (i.e. Migdala), a place in Palestine", "kjv": "Magdala."}, "G3094": {"greek": "Μαγδαληνή", "translit": "Magdalēnḗ", "pronunciation": "mag-dal-ay-nay'", "derivation": "feminine of a derivative of (G3093);", "definition": "a female Magdalene, i.e. inhabitant of Magdala", "kjv": "Magdalene."}, "G3095": {"greek": "μαγεία", "translit": "mageía", "pronunciation": "mag-i'-ah", "derivation": "from (G3096);", "definition": "\"magic\"", "kjv": "sorcery."}, "G3096": {"greek": "μαγεύω", "translit": "mageúō", "pronunciation": "mag-yoo'-o", "derivation": "from (G3097);", "definition": "to practice magic", "kjv": "use sorcery."}, "G3097": {"greek": "μάγος", "translit": "mágos", "pronunciation": "mag'-os", "derivation": "of foreign origin ((G7248));", "definition": "a Magian, i.e. Oriental scientist; by implication, a magician", "kjv": "sorcerer, wise man."}, "G3098": {"greek": "Μαγώγ", "translit": "Magṓg", "pronunciation": "mag-ogue'", "derivation": "of Hebrew origin ((G4031));", "definition": "Magog, a foreign nation, i.e. (figuratively) an Antichristian party", "kjv": "Magog."}, "G3099": {"greek": "Μαδιάν", "translit": "Madián", "pronunciation": "mad-ee-on'", "derivation": "of Hebrew origin ((G4080));", "definition": "Madian (i.e. Midian), a region of Arabia", "kjv": "Madian."}, "G3100": {"greek": "μαθητεύω", "translit": "mathēteúō", "pronunciation": "math-ayt-yoo'-o", "derivation": "from (G3101);", "definition": "intransitively, to become a pupil; transitively, to disciple, i.e. enrol as scholar", "kjv": "be disciple, instruct, teach."}, "G3101": {"greek": "μαθητής", "translit": "mathētḗs", "pronunciation": "math-ay-tes'", "derivation": "from (G3129);", "definition": "a learner, i.e. pupil", "kjv": "disciple."}, "G3102": {"greek": "μαθήτρια", "translit": "mathḗtria", "pronunciation": "math-ay'-tree-ah", "derivation": "feminine from (G3101);", "definition": "a female pupil", "kjv": "disciple."}, "G3103": {"greek": "Μαθουσάλα", "translit": "Mathousála", "pronunciation": "math-oo-sal'-ah", "derivation": "of Hebrew origin ((G4968));", "definition": "Mathusala (i.e. Methushelach), an antediluvian", "kjv": "Mathusala."}, "G3104": {"greek": "Μαϊνάν", "translit": "Maïnán", "pronunciation": "mahee-nan'", "derivation": "probably of Hebrew origin;", "definition": "Mainan, an Israelite", "kjv": "Mainan."}, "G3105": {"greek": "μαίνομαι", "translit": "maínomai", "pronunciation": "mah'-ee-nom-ahee", "derivation": "middle voice from a primary (to long for;", "definition": "through the idea of insensate craving); to rave as a \"maniac\"", "kjv": "be beside self (mad)."}, "G3106": {"greek": "μακαρίζω", "translit": "makarízō", "pronunciation": "mak-ar-id'-zo", "derivation": "from (G3107);", "definition": "to beatify, i.e. pronounce (or esteem) fortunate", "kjv": "call blessed, count happy."}, "G3107": {"greek": "μακάριος", "translit": "makários", "pronunciation": "mak-ar'-ee-os", "derivation": "a prolonged form of the poetical (meaning the same);", "definition": "supremely blest; by extension, fortunate, well off", "kjv": "blessed, happy(X -ier)."}, "G3108": {"greek": "μακαρισμός", "translit": "makarismós", "pronunciation": "mak-ar-is-mos'", "derivation": "from (G3106);", "definition": "beatification, i.e. attribution of good fortune", "kjv": "blessedness."}, "G3109": {"greek": "Μακεδονία", "translit": "Makedonía", "pronunciation": "mak-ed-on-ee'-ah", "derivation": "from (G3110);", "definition": "Macedonia, a region of Greece", "kjv": "Macedonia."}, "G3110": {"greek": "Μακεδών", "translit": "Makedṓn", "pronunciation": "mak-ed'-ohn", "derivation": "of uncertain derivation;", "definition": "a Macedon (Macedonian), i.e. inhabitant of Macedonia", "kjv": "of Macedonia, Macedonian."}, "G3111": {"greek": "μάκελλον", "translit": "mákellon", "pronunciation": "mak'-el-lon", "derivation": "of Latin origin (macellum);", "definition": "a butcher's stall, meat market or provision-shop", "kjv": "shambles."}, "G3112": {"greek": "μακράν", "translit": "makrán", "pronunciation": "mak-ran'", "derivation": "feminine accusative case singular of (G3117) ((G3598) being implied);", "definition": "at a distance (literally or figuratively)", "kjv": "(a-)far (off), good (great) way off."}, "G3113": {"greek": "μακρόθεν", "translit": "makróthen", "pronunciation": "mak-roth'-en", "derivation": "adverb from (G3117);", "definition": "from a distance or afar", "kjv": "afar off, from far."}, "G3114": {"greek": "μακροθυμέω", "translit": "makrothyméō", "pronunciation": "mak-roth-oo-meh'-o", "derivation": "from the same as (G3116);", "definition": "to be long-spirited, i.e. (objectively) forbearing or (subjectively) patient", "kjv": "bear (suffer) long, be longsuffering, have (long) patience, be patient, patiently endure."}, "G3115": {"greek": "μακροθυμία", "translit": "makrothymía", "pronunciation": "mak-roth-oo-mee'-ah", "derivation": "from the same as (G3116);", "definition": "longanimity, i.e. (objectively) forbearance or (subjectively) fortitude", "kjv": "longsuffering, patience."}, "G3116": {"greek": "μακροθυμώς", "translit": "makrothymṓs", "pronunciation": "mak-roth-oo-moce'", "derivation": "adverb of a compound of (G3117) and (G2372);", "definition": "with long (enduring) temper, i.e. leniently", "kjv": "patiently."}, "G3117": {"greek": "μακρός", "translit": "makrós", "pronunciation": "mak-ros'", "derivation": "from (G3372);", "definition": "long (in place (distant) or time (neuter plural))", "kjv": "far, long."}, "G3118": {"greek": "μακροχρόνιος", "translit": "makrochrónios", "pronunciation": "mak-rokh-ron'-ee-os", "derivation": "from (G3117) and (G5550);", "definition": "long-timed, i.e. long-lived", "kjv": "live long."}, "G3119": {"greek": "μαλακία", "translit": "malakía", "pronunciation": "mal-ak-ee'-ah", "derivation": "from (G3120);", "definition": "softness, i.e. enervation (debility)", "kjv": "disease."}, "G3120": {"greek": "μαλακός", "translit": "malakós", "pronunciation": "mal-ak-os'", "derivation": "of uncertain affinity;", "definition": "soft, i.e. fine (clothing); figuratively, a catamite", "kjv": "effeminate, soft."}, "G3121": {"greek": "Μαλελεήλ", "translit": "Maleleḗl", "pronunciation": "mal-el-eh-ale'", "derivation": "of Hebrew origin ((G4111));", "definition": "Maleleel (i.e. Mahalalel), an antediluvian", "kjv": "Maleleel."}, "G3122": {"greek": "μάλιστα", "translit": "málista", "pronunciation": "mal'-is-tah", "derivation": "neuter plural of the superlative of an apparently primary adverb (very);", "definition": "(adverbially) most (in the greatest degree) or particularly", "kjv": "chiefly, most of all, (e-)specially."}, "G3123": {"greek": "μᾶλλον", "translit": "mâllon", "pronunciation": "mal'-lon", "derivation": "neuter of the comparative of the same as (G3122);", "definition": "(adverbially) more (in a greater degree) or rather", "kjv": "+ better, X far, (the) more (and more), (so) much (the more), rather."}, "G3124": {"greek": "Μάλχος", "translit": "Málchos", "pronunciation": "mal'-khos", "derivation": "of Hebrew origin ((G4429));", "definition": "Malchus, an Israelite", "kjv": "Malchus."}, "G3125": {"greek": "μάμμη", "translit": "mámmē", "pronunciation": "mam'-may", "derivation": "of natural origin (\"mammy\");", "definition": "a grandmother", "kjv": "grandmother."}, "G3126": {"greek": "μαμμωνᾶς", "translit": "mammōnâs", "pronunciation": "mam-mo-nas'", "derivation": "of Chaldee origin (confidence, i.e. wealth, personified);", "definition": "mammonas, i.e. avarice (deified)", "kjv": "mammon."}, "G3127": {"greek": "Μαναήν", "translit": "Manaḗn", "pronunciation": "man-ah-ane'", "derivation": "of uncertain origin;", "definition": "Manaën, a Christian", "kjv": "Manaen."}, "G3128": {"greek": "Μανασσῆς", "translit": "Manassēs", "pronunciation": "man-as-sace'", "derivation": "of Hebrew origin ((G4519));", "definition": "Mannasses (i.e. Menashsheh), an Israelite", "kjv": "Manasses."}, "G3129": {"greek": "μανθάνω", "translit": "manthánō", "pronunciation": "man-than'-o", "derivation": "prolongation from a primary verb, another form of which, , is used as an alternate in certain tenses;", "definition": "to learn (in any way)", "kjv": "learn, understand."}, "G3130": {"greek": "μανία", "translit": "manía", "pronunciation": "man-ee'-ah", "derivation": "from (G3105);", "definition": "craziness", "kjv": "(+ make) X mad."}, "G3131": {"greek": "μάννα", "translit": "mánna", "pronunciation": "man'-nah", "derivation": "of Hebrew origin ((G4478));", "definition": "manna (i.e. man), an edible gum", "kjv": "manna."}, "G3132": {"greek": "μαντεύομαι", "translit": "manteúomai", "pronunciation": "mant-yoo'-om-ahee", "derivation": "from a derivative of (G3105) (meaning a prophet, as supposed to rave through inspiration);", "definition": "to divine, i.e. utter spells (under pretense of foretelling", "kjv": "by soothsaying."}, "G3133": {"greek": "μαραίνω", "translit": "maraínō", "pronunciation": "mar-ah'-ee-no", "derivation": "of uncertain affinity;", "definition": "to extinguish (as fire), i.e. (figuratively and passively) to pass away", "kjv": "fade away."}, "G3134": {"greek": "μαρὰν ἀθά", "translit": "maràn athá", "pronunciation": "mar'-an ath'-ah", "derivation": "of Chaldee origin (meaning our Lord has come);", "definition": "maranatha, i.e. an exclamation of the approaching divine judgment", "kjv": "Maran-atha."}, "G3135": {"greek": "μαργαρίτης", "translit": "margarítēs", "pronunciation": "mar-gar-ee'-tace", "derivation": "from (a pearl-oyster);", "definition": "a pearl", "kjv": "pearl."}, "G3136": {"greek": "Μάρθα", "translit": "Mártha", "pronunciation": "mar'-thah", "derivation": "probably of Chaldee origin (meaning mistress);", "definition": "Martha, a Christian woman", "kjv": "Martha."}, "G3137": {"greek": "Μαρία", "translit": "María", "pronunciation": "mar-ee'-ah", "derivation": "of Hebrew origin ((G4813));", "definition": "Maria or Mariam (i.e. Mirjam), the name of six Christian females", "kjv": "Mary."}, "G3138": {"greek": "Μάρκος", "translit": "Márkos", "pronunciation": "mar'-kos", "derivation": "of Latin origin;", "definition": "Marcus, a Christian", "kjv": "Marcus, Mark."}, "G3139": {"greek": "μάρμαρος", "translit": "mármaros", "pronunciation": "mar'-mar-os", "derivation": "from (to glisten);", "definition": "marble (as sparkling white)", "kjv": "marble."}, "G3140": {"greek": "μαρτυρέω", "translit": "martyréō", "pronunciation": "mar-too-reh'-o", "derivation": "from (G3144);", "definition": "to be a witness, i.e. testify (literally or figuratively)", "kjv": "charge, give (evidence), bear record, have (obtain, of) good (honest) report, be well reported of, testify, give (have) testimony, (be, bear, give, obtain) witness."}, "G3141": {"greek": "μαρτυρία", "translit": "martyría", "pronunciation": "mar-too-ree'-ah", "derivation": "from (G3144);", "definition": "evidence given (judicially or genitive case)", "kjv": "record, report, testimony, witness."}, "G3142": {"greek": "μαρτύριον", "translit": "martýrion", "pronunciation": "mar-too'-ree-on", "derivation": "neuter of a presumed derivative of (G3144);", "definition": "something evidential, i.e. (genitive case) evidence given or (specially), the Decalogue (in the sacred Tabernacle)", "kjv": "to be testified, testimony, witness."}, "G3143": {"greek": "μαρτύρομαι", "translit": "martýromai", "pronunciation": "mar-too'-rom-ahee", "derivation": "middle voice from (G3144);", "definition": "to be adduced as a witness, i.e. (figuratively) to obtest (in affirmation or exhortation)", "kjv": "take to record, testify."}, "G3144": {"greek": "μάρτυς", "translit": "mártys", "pronunciation": "mar'-toos", "derivation": "of uncertain affinity;", "definition": "a witness (literally (judicially) or figuratively (genitive case)); by analogy, a \"martyr\"", "kjv": "martyr, record, witness."}, "G3145": {"greek": "μασσάομαι", "translit": "massáomai", "pronunciation": "mas-sah'-om-ahee", "derivation": "from a primary (to handle or squeeze);", "definition": "to chew", "kjv": "gnaw."}, "G3146": {"greek": "μαστιγόω", "translit": "mastigóō", "pronunciation": "mas-tig-o'-o", "derivation": "from (G3148);", "definition": "to flog (literally or figuratively)", "kjv": "scourge."}, "G3147": {"greek": "μαστίζω", "translit": "mastízō", "pronunciation": "mas-tid'-zo", "derivation": "from (G3149);", "definition": "to whip (literally)", "kjv": "scourge."}, "G3148": {"greek": "μάστιξ", "translit": "mástix", "pronunciation": "mas'-tix", "derivation": "probably from the base of (G3145) (through the idea of contact);", "definition": "a whip (literally, the Roman flagellum for criminals; figuratively, a disease)", "kjv": "plague, scourging."}, "G3149": {"greek": "μαστός", "translit": "mastós", "pronunciation": "mas-tos'", "derivation": "from the base of (G3145);", "definition": "a (properly, female) breast (as if kneaded up)", "kjv": "pap."}, "G3150": {"greek": "ματαιολογία", "translit": "mataiología", "pronunciation": "mat-ah-yol-og-ee'-ah", "derivation": "from (G3151);", "definition": "random talk, i.e. babble", "kjv": "vain jangling."}, "G3151": {"greek": "ματαιολόγος", "translit": "mataiológos", "pronunciation": "mat-ah-yol-og'-os", "derivation": "from (G3152) and (G3004);", "definition": "an idle (i.e. senseless or mischievous) talker, i.e. a wrangler", "kjv": "vain talker."}, "G3152": {"greek": "μάταιος", "translit": "mátaios", "pronunciation": "mat'-ah-yos", "derivation": "from the base of (G3155);", "definition": "empty, i.e. (literally) profitless, or (specially), an idol", "kjv": "vain, vanity."}, "G3153": {"greek": "ματαιότης", "translit": "mataiótēs", "pronunciation": "mat-ah-yot'-ace", "derivation": "from (G3152);", "definition": "inutility; figuratively, transientness; morally, depravity", "kjv": "vanity."}, "G3154": {"greek": "ματαιόω", "translit": "mataióō", "pronunciation": "mat-ah-yo'-o", "derivation": "from (G3152);", "definition": "to render (passively, become) foolish, i.e. (morally) wicked or (specially), idolatrous", "kjv": "become vain."}, "G3155": {"greek": "μάτην", "translit": "mátēn", "pronunciation": "mat'-ane", "derivation": "accusative case of a derivative of the base of (G3145) (through the idea of tentative manipulation, i.e. unsuccessful search, or else of punishment);", "definition": "folly, i.e. (adverbially) to no purpose", "kjv": "in vain."}, "G3156": {"greek": "Ματθαῖος", "translit": "Matthaîos", "pronunciation": "mat-thah'-yos", "derivation": "a shorter form of (G3161);", "definition": "Matthæus (i.e. Matthitjah), an Israelite and a Christian", "kjv": "Matthew."}, "G3157": {"greek": "Ματθάν", "translit": "Matthán", "pronunciation": "mat-than'", "derivation": "of Hebrew origin ((G4977));", "definition": "Matthan (i.e. Mattan), an Israelite", "kjv": "Matthan."}, "G3158": {"greek": "Ματθάτ", "translit": "Matthát", "pronunciation": "mat-that'", "derivation": "probably a shortened form of (G3161);", "definition": "Matthat (i.e. Mattithjah), the name of two Israelites", "kjv": "Mathat."}, "G3159": {"greek": "Ματθίας", "translit": "Matthías", "pronunciation": "mat-thee'-as", "derivation": "apparently a shortened form of (G3161);", "definition": "Matthias (i.e. Mattithjah), an Israelite", "kjv": "Matthias."}, "G3160": {"greek": "Ματταθά", "translit": "Mattathá", "pronunciation": "mat-tath-ah'", "derivation": "probably a shortened form of (G3161) (compare (G4992));", "definition": "Mattatha (i.e. Mattithjah), an Israelite", "kjv": "Mattatha."}, "G3161": {"greek": "Ματταθίας", "translit": "Mattathías", "pronunciation": "mat-tath-ee'-as", "derivation": "of Hebrew origin ((G4993));", "definition": "Mattathias (i.e. Mattithjah), an Israelite and a Christian", "kjv": "Mattathias."}, "G3162": {"greek": "μάχαιρα", "translit": "máchaira", "pronunciation": "makh'-ahee-rah", "derivation": "probably feminine of a presumed derivative of (G3163);", "definition": "a knife, i.e. dirk; figuratively, war, judicial punishment", "kjv": "sword."}, "G3163": {"greek": "μάχη", "translit": "máchē", "pronunciation": "makh'-ay", "derivation": "from (G3164);", "definition": "a battle, i.e. (figuratively) controversy", "kjv": "fighting, strive, striving."}, "G3164": {"greek": "μάχομαι", "translit": "máchomai", "pronunciation": "makh'-om-ahee", "derivation": "middle voice of an apparently primary verb;", "definition": "to war, i.e. (figuratively) to quarrel, dispute", "kjv": "fight, strive."}, "G3165": {"greek": "μέ", "translit": "mé", "pronunciation": "meh", "derivation": "a shorter (and probably original) form of (G1691);", "definition": "me", "kjv": "I, me, my."}, "G3166": {"greek": "μεγαλαυχέω", "translit": "megalauchéō", "pronunciation": "meg-al-ow-kheh'-o", "derivation": "from a compound of (G3173) and (to boast; akin to (G837) and (G2744));", "definition": "to talk big, i.e. be grandiloquent (arrogant, egotistic)", "kjv": "boast great things."}, "G3167": {"greek": "μεγαλεῖος", "translit": "megaleîos", "pronunciation": "meg-al-i'-os", "derivation": "from (G3173);", "definition": "magnificent, i.e. (neuter, plural as noun) a conspicuous favor, or (subjectively) perfection", "kjv": "great things, wonderful works."}, "G3168": {"greek": "μεγαλειότης", "translit": "megaleiótēs", "pronunciation": "meg-al-i-ot'-ace", "derivation": "from (G3167);", "definition": "superbness, i.e. glory or splendor", "kjv": "magnificence, majesty, mighty power."}, "G3169": {"greek": "μεγαλοπρεπής", "translit": "megaloprepḗs", "pronunciation": "meg-al-op-rep-ace'", "derivation": "from (G3173) and (G4241);", "definition": "befitting greatness or magnificence (majestic)", "kjv": "excellent."}, "G3170": {"greek": "μεγαλύνω", "translit": "megalýnō", "pronunciation": "meg-al-oo'-no", "derivation": "from (G3173);", "definition": "to make (or declare) great, i.e. increase or (figuratively) extol", "kjv": "enlarge, magnify, shew great."}, "G3171": {"greek": "μεγάλως", "translit": "megálōs", "pronunciation": "meg-al'-oce", "derivation": "adverb from (G3173);", "definition": "much", "kjv": "greatly."}, "G3172": {"greek": "μεγαλωσύνη", "translit": "megalōsýnē", "pronunciation": "meg-al-o-soo'-nay", "derivation": "from (G3173);", "definition": "greatness, i.e. (figuratively) divinity (often God himself)", "kjv": "majesty."}, "G3173": {"greek": "μέγας", "translit": "mégas", "pronunciation": "meg'-as", "derivation": "(including the prolonged forms, feminine , plural , etc.; compare also (G3176), (G3187));", "definition": "big (literally or figuratively, in a very wide application)", "kjv": "(+ fear) exceedingly, great(-est), high, large, loud, mighty, + (be) sore (afraid), strong, X to years."}, "G3174": {"greek": "μέγεθος", "translit": "mégethos", "pronunciation": "meg'-eth-os", "derivation": "from (G3173);", "definition": "magnitude (figuratively)", "kjv": "greatness."}, "G3175": {"greek": "μεγιστᾶνες", "translit": "megistânes", "pronunciation": "meg-is-tan'-es", "derivation": "plural from (G3176);", "definition": "grandees", "kjv": "great men, lords."}, "G3176": {"greek": "μέγιστος", "translit": "mégistos", "pronunciation": "meg'-is-tos", "derivation": "superlative of (G3173);", "definition": "greatest or very great", "kjv": "exceeding great."}, "G3177": {"greek": "μεθερμηνεύω", "translit": "methermēneúō", "pronunciation": "meth-er-mane-yoo'-o", "derivation": "from (G3326) and (G2059);", "definition": "to explain over, i.e. translate", "kjv": "(by) interpret(-ation)."}, "G3178": {"greek": "μέθη", "translit": "méthē", "pronunciation": "meth'-ay", "derivation": "apparently a primary word;", "definition": "an intoxicant, i.e. (by implication) intoxication", "kjv": "drunkenness."}, "G3179": {"greek": "μεθίστημι", "translit": "methístēmi", "pronunciation": "meth-is'-tay-mee", "derivation": "from (G3326) and (G2476);", "definition": "to transfer, i.e. carry away, depose or (figuratively) exchange, seduce", "kjv": "put out, remove, translate, turn away."}, "G3180": {"greek": "μεθοδεία", "translit": "methodeía", "pronunciation": "meth-od-i'-ah", "derivation": "from a compound of (G3326) and (G3593) (compare \"method\");", "definition": "travelling over, i.e. travesty (trickery)", "kjv": "wile, lie in wait."}, "G3182": {"greek": "μεθύσκω", "translit": "methýskō", "pronunciation": "meth-oos'-ko", "derivation": "a prolonged (transitive) form of (G3184);", "definition": "to intoxicate", "kjv": "be drunk(-en)."}, "G3183": {"greek": "μέθυσος", "translit": "méthysos", "pronunciation": "meth'-oo-sos", "derivation": "from (G3184);", "definition": "tipsy, i.e. (as noun) a sot", "kjv": "drunkard."}, "G3184": {"greek": "μεθύω", "translit": "methýō", "pronunciation": "meth-oo'-o", "derivation": "from another form of (G3178);", "definition": "to drink to intoxication, i.e. get drunk", "kjv": "drink well, make (be) drunk(-en)."}, "G3186": {"greek": "μειζότερος", "translit": "meizóteros", "pronunciation": "mide-zot'-er-os", "derivation": "continued comparative of (G3187);", "definition": "still larger (figuratively)", "kjv": "greater."}, "G3187": {"greek": "μείζων", "translit": "meízōn", "pronunciation": "mide'-zone", "derivation": "irregular comparative of (G3173);", "definition": "larger (literally or figuratively, specially, in age)", "kjv": "elder, greater(-est), more."}, "G3188": {"greek": "μέλαν", "translit": "mélan", "pronunciation": "mel'-an", "derivation": "neuter of (G3189) as noun;", "definition": "ink", "kjv": "ink."}, "G3189": {"greek": "μέλας", "translit": "mélas", "pronunciation": "mel'-as", "derivation": "apparently a primary word;", "definition": "black", "kjv": "black."}, "G3190": {"greek": "Μελεᾶς", "translit": "Meleâs", "pronunciation": "mel-eh-as'", "derivation": "of uncertain origin;", "definition": "Meleas, an Israelite", "kjv": "Meleas."}, "G3191": {"greek": "μελετάω", "translit": "meletáō", "pronunciation": "mel-et-ah'-o", "derivation": "from a presumed derivative of (G3199);", "definition": "to take care of, i.e. (by implication) revolve in the mind", "kjv": "imagine, (pre-)meditate."}, "G3192": {"greek": "μέλι", "translit": "méli", "pronunciation": "mel'-ee", "derivation": "apparently a primary word;", "definition": "honey", "kjv": "honey."}, "G3194": {"greek": "Μελίτη", "translit": "Melítē", "pronunciation": "mel-ee'-tay", "derivation": "of uncertain origin;", "definition": "Melita, an island in the Mediterranean", "kjv": "Melita."}, "G3195": {"greek": "μέλλω", "translit": "méllō", "pronunciation": "mel'-lo", "derivation": "a strengthened form of (G3199) (through the idea of expectation);", "definition": "to intend, i.e. be about to be, do, or suffer something (of persons or things, especially events; in the sense of purpose, duty, necessity, probability, possibility, or hesitation)", "kjv": "about, after that, be (almost), (that which is, things, + which was for) to come, intend, was to (be), mean, mind, be at the point, (be) ready, + return, shall (begin), (which, that) should (after, afterwards, hereafter) tarry, which was for, will, would, be yet."}, "G3196": {"greek": "μέλος", "translit": "mélos", "pronunciation": "mel'-os", "derivation": "of uncertain affinity;", "definition": "a limb or part of the body", "kjv": "member."}, "G3197": {"greek": "Μελχί", "translit": "Melchí", "pronunciation": "mel-khee'", "derivation": "of Hebrew origin ((G4428) with pronominal suffix, my king);", "definition": "Melchi (i.e. Malki), the name of two Israelites", "kjv": "Melchi."}, "G3198": {"greek": "Μελχισεδέκ", "translit": "Melchisedék", "pronunciation": "mel-khis-ed-ek'", "derivation": "of Hebrew origin ((G4442));", "definition": "Melchisedek (i.e. Malkitsedek), a patriarch", "kjv": "Melchisedec."}, "G3199": {"greek": "μέλω", "translit": "mélō", "pronunciation": "mel'-o", "derivation": "a primary verb;", "definition": "to be of interest to, i.e. to concern (only third person singular present indicative used impersonally, it matters)", "kjv": "(take) care."}, "G3200": {"greek": "μεμβράνα", "translit": "membrána", "pronunciation": "mem-bran'-ah", "derivation": "of Latin origin (\"membrane\");", "definition": "a (written) sheep-skin", "kjv": "parchment."}, "G3201": {"greek": "μέμφομαι", "translit": "mémphomai", "pronunciation": "mem'-fom-ahee", "derivation": "middle voice of an apparently primary verb;", "definition": "to blame", "kjv": "find fault."}, "G3202": {"greek": "μεμψίμοιρος", "translit": "mempsímoiros", "pronunciation": "mem-psim'-oy-ros", "derivation": "from a presumed derivative of (G3201) and (fate; akin to the base of (G3313));", "definition": "blaming fate, i.e. querulous (discontented)", "kjv": "complainer."}, "G3303": {"greek": "μέν", "translit": "mén", "pronunciation": "men", "derivation": "a primary particle;", "definition": "properly, indicative of affirmation or concession (in fact); usually followed by a contrasted clause with (G1161) (this one, the former, etc.)", "kjv": "even, indeed, so, some, truly, verily."}, "G3304": {"greek": "μενοῦνγε", "translit": "menoûnge", "pronunciation": "men-oon'-geh", "derivation": "from (G3303) and (G3767) and (G1065);", "definition": "so then at least", "kjv": "nay but, yea doubtless (rather, verily)."}, "G3305": {"greek": "μέντοι", "translit": "méntoi", "pronunciation": "men'-toy", "derivation": "from (G3303) and (G5104);", "definition": "indeed though, i.e. however", "kjv": "also, but, howbeit, nevertheless, yet."}, "G3306": {"greek": "μένω", "translit": "ménō", "pronunciation": "men'-o", "derivation": "a primary verb;", "definition": "to stay (in a given place, state, relation or expectancy)", "kjv": "abide, continue, dwell, endure, be present, remain, stand, tarry (for), X thine own."}, "G3307": {"greek": "μερίζω", "translit": "merízō", "pronunciation": "mer-id'-zo", "derivation": "from (G3313);", "definition": "to part, i.e. (literally) to apportion, bestow, share, or (figuratively) to disunite, differ", "kjv": "deal, be difference between, distribute, divide, give part."}, "G3308": {"greek": "μέριμνα", "translit": "mérimna", "pronunciation": "mer'-im-nah", "derivation": "from (G3307) (through the idea of distraction);", "definition": "solicitude", "kjv": "care."}, "G3309": {"greek": "μεριμνάω", "translit": "merimnáō", "pronunciation": "mer-im-nah'-o", "derivation": "from (G3308);", "definition": "to be anxious about", "kjv": "(be, have) care(-ful), take thought."}, "G3310": {"greek": "μερίς", "translit": "merís", "pronunciation": "mer-ece'", "derivation": "feminine of (G3313);", "definition": "a portion, i.e. province, share or (abstractly) participation", "kjv": "part (X -akers)."}, "G3311": {"greek": "μερισμός", "translit": "merismós", "pronunciation": "mer-is-mos'", "derivation": "from (G3307);", "definition": "a separation or distribution", "kjv": "dividing asunder, gift."}, "G3312": {"greek": "μεριστής", "translit": "meristḗs", "pronunciation": "mer-is-tace'", "derivation": "from (G3307);", "definition": "an apportioner (administrator)", "kjv": "divider."}, "G3313": {"greek": "μέρος", "translit": "méros", "pronunciation": "mer'-os", "derivation": "from an obsolete but more primary form of (to get as a section or allotment);", "definition": "a division or share (literally or figuratively, in a wide application)", "kjv": "behalf, course, coast, craft, particular (+ -ly), part (+ -ly), piece, portion, respect, side, some sort(-what)."}, "G3314": {"greek": "μεσημβρία", "translit": "mesēmbría", "pronunciation": "mes-ame-bree'-ah", "derivation": "from (G3319) and (G2250);", "definition": "midday; by implication, the south", "kjv": "noon, south."}, "G3315": {"greek": "μεσιτεύω", "translit": "mesiteúō", "pronunciation": "mes-it-yoo'-o", "derivation": "from (G3316);", "definition": "to interpose (as arbiter), i.e (by implication) to ratify (as surety)", "kjv": "confirm."}, "G3316": {"greek": "μεσίτης", "translit": "mesítēs", "pronunciation": "mes-ee'-tace", "derivation": "from (G3319);", "definition": "a go-between, i.e. (simply) an internunciator, or (by implication) a reconciler (intercessor)", "kjv": "mediator."}, "G3317": {"greek": "μεσονύκτιον", "translit": "mesonýktion", "pronunciation": "mes-on-ook'-tee-on", "derivation": "neuter of compound of (G3319) and (G3571);", "definition": "midnight (especially as a watch)", "kjv": "midnight."}, "G3318": {"greek": "Μεσοποταμία", "translit": "Mesopotamía", "pronunciation": "mes-op-ot-am-ee'-ah", "derivation": "from (G3319) and (G4215);", "definition": "Mesopotamia (as lying between the Euphrates and the Tigris; compare (G763)), a region of Asia", "kjv": "Mesopotamia."}, "G3319": {"greek": "μέσος", "translit": "mésos", "pronunciation": "mes'-os", "derivation": "from (G3326);", "definition": "middle (as an adjective or (neuter) noun)", "kjv": "among, X before them, between, + forth, mid(-day, -night), midst, way."}, "G3320": {"greek": "μεσότοιχον", "translit": "mesótoichon", "pronunciation": "mes-ot'-oy-khon", "derivation": "from (G3319) and (G5109);", "definition": "a partition (figuratively)", "kjv": "middle wall."}, "G3321": {"greek": "μεσουράνημα", "translit": "mesouránēma", "pronunciation": "mes-oo-ran'-ay-mah", "derivation": "from a presumed compound of (G3319) and (G3772);", "definition": "mid-sky", "kjv": "midst of heaven."}, "G3322": {"greek": "μεσόω", "translit": "mesóō", "pronunciation": "mes-o'-o", "derivation": "from (G3319);", "definition": "to form the middle, i.e. (in point of time), to be half-way over", "kjv": "be about the midst."}, "G3323": {"greek": "Μεσσίας", "translit": "Messías", "pronunciation": "mes-see'-as", "derivation": "of Hebrew origin ((G4899));", "definition": "the Messias (i.e. Mashiach), or Christ", "kjv": "Messias."}, "G3324": {"greek": "μεστός", "translit": "mestós", "pronunciation": "mes-tos'", "derivation": "of uncertain derivation;", "definition": "replete (literally or figuratively)", "kjv": "full."}, "G3325": {"greek": "μεστόω", "translit": "mestóō", "pronunciation": "mes-to'-o", "derivation": "from (G3324);", "definition": "to replenish, i.e. (by implication) to intoxicate", "kjv": "fill."}, "G3326": {"greek": "μετά", "translit": "metá", "pronunciation": "met-ah'", "derivation": "a primary preposition (often used adverbially);", "definition": "properly, denoting accompaniment; \"amid\" (local or causal); modified variously according to the case (genitive association, or accusative succession) with which it is joined; occupying an intermediate position between (G575) or (G1537) and (G1519) or (G4314); less intimate than (G1722) and less close than (G4862))", "kjv": "after(-ward), X that he again, against, among, X and, + follow, hence, hereafter, in, of, (up-)on, + our, X and setting, since, (un-)to, + together, when, with (+ -out)."}, "G3327": {"greek": "μεταβαίνω", "translit": "metabaínō", "pronunciation": "met-ab-ah'-ee-no", "derivation": "from (G3326) and the base of (G939);", "definition": "to change place", "kjv": "depart, go, pass, remove."}, "G3328": {"greek": "μεταβάλλω", "translit": "metabállō", "pronunciation": "met-ab-al'-lo", "derivation": "from (G3326) and (G906);", "definition": "to throw over, i.e. (middle voice figuratively) to turn about in opinion", "kjv": "change mind."}, "G3329": {"greek": "μετάγω", "translit": "metágō", "pronunciation": "met-ag'-o", "derivation": "from (G3326) and (G718);", "definition": "to lead over, i.e. transfer (direct)", "kjv": "turn about."}, "G3330": {"greek": "μεταδίδωμι", "translit": "metadídōmi", "pronunciation": "met-ad-id'-o-mee", "derivation": "from (G3326) and (G1325);", "definition": "to give over, i.e. share", "kjv": "give, impart."}, "G3331": {"greek": "μετάθεσις", "translit": "metáthesis", "pronunciation": "met-ath'-es-is", "derivation": "from (G3346);", "definition": "transposition, i.e. transferral (to heaven), disestablishment (of a law)", "kjv": "change, removing, translation."}, "G3332": {"greek": "μεταίρω", "translit": "metaírō", "pronunciation": "met-ah'-ee-ro", "derivation": "from (G3326) and (G142);", "definition": "to betake oneself, i.e. remove (locally)", "kjv": "depart."}, "G3333": {"greek": "μετακαλέω", "translit": "metakaléō", "pronunciation": "met-ak-al-eh'-o", "derivation": "from (G3326) and (G2564);", "definition": "to call elsewhere, i.e. summon", "kjv": "call (for, hither)."}, "G3334": {"greek": "μετακινέω", "translit": "metakinéō", "pronunciation": "met-ak-ee-neh'-o", "derivation": "from (G3326) and (G2795);", "definition": "to stir to a place elsewhere, i.e. remove (figuratively)", "kjv": "move away."}, "G3335": {"greek": "μεταλαμβάνω", "translit": "metalambánō", "pronunciation": "met-al-am-ban'-o", "derivation": "from (G3326) and (G2983);", "definition": "to participate; genitive case, to accept (and use)", "kjv": "eat, have, be partaker, receive, take."}, "G3336": {"greek": "μετάλημψις", "translit": "metálēmpsis", "pronunciation": "met-al'-ape-sis", "derivation": "from (G3335);", "definition": "participation", "kjv": "taking."}, "G3337": {"greek": "μεταλλάσσω", "translit": "metallássō", "pronunciation": "met-al-las'-so", "derivation": "from (G3326) and (G236);", "definition": "to exchange", "kjv": "change."}, "G3338": {"greek": "μεταμέλλομαι", "translit": "metaméllomai", "pronunciation": "met-am-el'-lom-ahee", "derivation": "from (G3326) and the middle voice of (G3199);", "definition": "to care afterwards, i.e. regret", "kjv": "repent (self)."}, "G3339": {"greek": "μεταμορφόω", "translit": "metamorphóō", "pronunciation": "met-am-or-fo'-o", "derivation": "from (G3326) and (G3445);", "definition": "to transform (literally or figuratively, \"metamorphose\")", "kjv": "change, transfigure, transform."}, "G3340": {"greek": "μετανοέω", "translit": "metanoéō", "pronunciation": "met-an-o-eh'-o", "derivation": "from (G3326) and (G3539);", "definition": "to think differently or afterwards, i.e. reconsider (morally, feel compunction)", "kjv": "repent."}, "G3341": {"greek": "μετάνοια", "translit": "metánoia", "pronunciation": "met-an'-oy-ah", "derivation": "from (G3340);", "definition": "(subjectively) compunction (for guilt, including reformation); by implication, reversal (of (another's) decision)", "kjv": "repentance."}, "G3342": {"greek": "μεταξύ", "translit": "metaxý", "pronunciation": "met-ax-oo'", "derivation": "from (G3326) and a form of (G4862);", "definition": "betwixt (of place or person); (of time) as adjective, intervening, or (by implication) adjoining", "kjv": "between, mean while, next."}, "G3343": {"greek": "μεταπέμπω", "translit": "metapémpō", "pronunciation": "met-ap-emp'-o", "derivation": "from (G3326) and (G3992);", "definition": "to send from elsewhere, i.e. (middle voice) to summon or invite", "kjv": "call (send) for."}, "G3344": {"greek": "μεταστρέφω", "translit": "metastréphō", "pronunciation": "met-as-tref'-o", "derivation": "from (G3326) and (G4762);", "definition": "to turn across, i.e. transmute or (figuratively) corrupt", "kjv": "pervert, turn."}, "G3345": {"greek": "μετασχηματίζω", "translit": "metaschēmatízō", "pronunciation": "met-askh-ay-mat-id'-zo", "derivation": "from (G3326) and a derivative of (G4976);", "definition": "to transfigure or disguise; figuratively, to apply (by accommodation)", "kjv": "transfer, transform (self)."}, "G3346": {"greek": "μετατίθημι", "translit": "metatíthēmi", "pronunciation": "met-at-ith'-ay-mee", "derivation": "from (G3326) and (G5087);", "definition": "to transfer, i.e. (literally) transport, (by implication) exchange, (reflexively) change sides, or (figuratively) pervert", "kjv": "carry over, change, remove, translate, turn."}, "G3347": {"greek": "μετέπειτα", "translit": "metépeita", "pronunciation": "met-ep'-i-tah", "derivation": "from (G3326) and (G1899);", "definition": "thereafter", "kjv": "afterward."}, "G3348": {"greek": "μετέχω", "translit": "metéchō", "pronunciation": "met-ekh'-o", "derivation": "from (G3326) and (G2192);", "definition": "to share or participate; by implication, belong to, eat (or drink)", "kjv": "be partaker, pertain, take part, use."}, "G3349": {"greek": "μετεωρίζω", "translit": "meteōrízō", "pronunciation": "met-eh-o-rid'-zo", "derivation": "from a compound of (G3326) and a collateral form of (G142) or perhaps rather (G109) (compare \"meteor\");", "definition": "to raise in mid-air, i.e. (figuratively) suspend (passively, fluctuate or be anxious)", "kjv": "be of doubtful mind."}, "G3350": {"greek": "μετοικεσία", "translit": "metoikesía", "pronunciation": "met-oy-kes-ee'-ah", "derivation": "from a derivative of a compound of (G3326) and (G3624);", "definition": "a change of abode, i.e. (specially), expatriation", "kjv": "X brought, carried(-ying) away (in-)to."}, "G3351": {"greek": "μετοικίζω", "translit": "metoikízō", "pronunciation": "met-oy-kid'-zo", "derivation": "from the same as (G3350);", "definition": "to transfer as a settler or captive, i.e colonize or exile", "kjv": "carry away, remove into."}, "G3352": {"greek": "μετοχή", "translit": "metochḗ", "pronunciation": "met-okh-ay'", "derivation": "from (G3348);", "definition": "participation, i.e. intercourse", "kjv": "fellowship."}, "G3353": {"greek": "μέτοχος", "translit": "métochos", "pronunciation": "met'-okh-os", "derivation": "from (G3348);", "definition": "participant, i.e. (as noun) a sharer; by implication, an associate", "kjv": "fellow, partaker, partner."}, "G3354": {"greek": "μετρέω", "translit": "metréō", "pronunciation": "met-reh'-o", "derivation": "from (G3358);", "definition": "to measure (i.e. ascertain in size by a fixed standard); by implication, to admeasure (i.e. allot by rule)", "kjv": "figuratively, to estimate:--measure, mete."}, "G3355": {"greek": "μετρητής", "translit": "metrētḗs", "pronunciation": "met-ray-tace'", "derivation": "from (G3354);", "definition": "a measurer, i.e. (specially), a certain standard measure of capacity for liquids", "kjv": "firkin."}, "G3356": {"greek": "μετριοπαθέω", "translit": "metriopathéō", "pronunciation": "met-ree-op-ath-eh'-o", "derivation": "from a compound of the base of (G3357) and (G3806);", "definition": "to be moderate in passion, i.e. gentle (to treat indulgently)", "kjv": "have compassion."}, "G3357": {"greek": "μετρίως", "translit": "metríōs", "pronunciation": "met-ree'-oce", "derivation": "adverb from a derivative of (G3358);", "definition": "moderately, i.e. slightly", "kjv": "a little."}, "G3358": {"greek": "μέτρον", "translit": "métron", "pronunciation": "met'-ron", "derivation": "an apparently primary word;", "definition": "a measure (\"metre\"), literally or figuratively; by implication, a limited portion (degree)", "kjv": "measure."}, "G3359": {"greek": "μέτωπον", "translit": "métōpon", "pronunciation": "met'-o-pon", "derivation": "from (G3326) and ops (the face);", "definition": "the forehead (as opposite the countenance)", "kjv": "forehead."}, "G3360": {"greek": "μέχρι", "translit": "méchri", "pronunciation": "mekh'-ree", "derivation": "from (G3372);", "definition": "as far as, i.e. up to a certain point (as a preposition, of extent (denoting the terminus, whereas (G891) refers especially to the space of time or place intervening) or conjunction)", "kjv": "till, (un-)to, until."}, "G3361": {"greek": "μή", "translit": "mḗ", "pronunciation": "may", "derivation": "a primary particle of qualified negation (whereas (G3756) expresses an absolute denial);", "definition": "(adverb) not, (conjunction) lest; also (as an interrogative implying a negative answer (whereas (G3756) expects an affirmative one)) whether", "kjv": "any but (that), X forbear, + God forbid, + lack, lest, neither, never, no (X wise in), none, nor, (can-)not, nothing, that not, un(-taken), without."}, "G3365": {"greek": "μηδαμῶς", "translit": "mēdamōs", "pronunciation": "may-dam-oce'", "derivation": "adverb from a compound of (G3361) and (somebody);", "definition": "by no means", "kjv": "not so."}, "G3366": {"greek": "μηδέ", "translit": "mēdé", "pronunciation": "may-deh'", "derivation": "from (G3361) and (G1161);", "definition": "but not, not even; in a continued negation, nor", "kjv": "neither, nor (yet), (no) not (once, so much as)."}, "G3367": {"greek": "μηδείς", "translit": "mēdeís", "pronunciation": "may-dice'", "derivation": "from (G3361) and (G1520);", "definition": "not even one (man, woman, thing)", "kjv": "any (man, thing), no (man), none, not (at all, any man, a whit), nothing, + without delay."}, "G3368": {"greek": "μηδέποτε", "translit": "mēdépote", "pronunciation": "may-dep'-ot-eh", "derivation": "from (G3366) and (G4218);", "definition": "not even ever", "kjv": "never."}, "G3369": {"greek": "μηδέπω", "translit": "mēdépō", "pronunciation": "may-dep'-o", "derivation": "from (G3366) and (G4452);", "definition": "not even yet", "kjv": "not yet."}, "G3370": {"greek": "Μῆδος", "translit": "Mēdos", "pronunciation": "may'-dos", "derivation": "of foreign origin (compare (G4074));", "definition": "a Median, or inhabitant of Media", "kjv": "Mede."}, "G3371": {"greek": "μηκέτι", "translit": "mēkéti", "pronunciation": "may-ket'-ee", "derivation": "from (G3361) and (G2089);", "definition": "no further", "kjv": "any longer, (not) henceforth, hereafter, no henceforward (longer, more, soon), not any more."}, "G3372": {"greek": "μῆκος", "translit": "mēkos", "pronunciation": "may'-kos", "derivation": "probably akin to (G3173);", "definition": "length (literally or figuratively) length.", "kjv": ""}, "G3373": {"greek": "μηκύνω", "translit": "mēkýnō", "pronunciation": "may-koo'-no", "derivation": "from (G3372);", "definition": "to lengthen, i.e. (middle voice) to enlarge", "kjv": "grow up."}, "G3374": {"greek": "μηλωτή", "translit": "mēlōtḗ", "pronunciation": "may-lo-tay'", "derivation": "from (a sheep);", "definition": "a sheep-skin", "kjv": "sheepskin."}, "G3375": {"greek": "μήν", "translit": "mḗn", "pronunciation": "mane", "derivation": "a stronger form of (G3303);", "definition": "a particle of affirmation (only with (G2229)); assuredly", "kjv": "+ surely."}, "G3377": {"greek": "μηνύω", "translit": "mēnýō", "pronunciation": "may-noo'-o", "derivation": "probably from the same base as (G3145) and (G3415) (i.e. , to strive);", "definition": "to disclose (through the idea of mental effort and thus calling to mind), i.e. report, declare, intimate", "kjv": "shew, tell."}, "G3379": {"greek": "μήποτε", "translit": "mḗpote", "pronunciation": "may'-pot-eh", "derivation": "from (G3361) and (G4218);", "definition": "not ever; also if (or lest) ever (or perhaps)", "kjv": "if peradventure, lest (at any time, haply), not at all, whether or not."}, "G3380": {"greek": "μήπω", "translit": "mḗpō", "pronunciation": "may'-po", "derivation": "from (G3361) and (G4452);", "definition": "not yet", "kjv": "not yet."}, "G3382": {"greek": "μηρός", "translit": "mērós", "pronunciation": "may-ros'", "derivation": "perhaps a primary word;", "definition": "a thigh", "kjv": "thigh."}, "G3383": {"greek": "μήτε", "translit": "mḗte", "pronunciation": "may'-teh", "derivation": "from (G3361) and (G5037);", "definition": "not too, i.e. (in continued negation) neither or nor; also, not even", "kjv": "neither, (n-)or, so as much."}, "G3384": {"greek": "μήτηρ", "translit": "mḗtēr", "pronunciation": "may'-tare", "derivation": "apparently a primary word;", "definition": "a \"mother\" (literally or figuratively, immediate or remote)", "kjv": "mother."}, "G3385": {"greek": "μήτι", "translit": "mḗti", "pronunciation": "may'-tee", "derivation": "from (G3361) and the neuter of (G5100);", "definition": "whether at all", "kjv": "not (the particle usually not expressed, except by the form of the question)."}, "G3386": {"greek": "μήτιγε", "translit": "mḗtige", "pronunciation": "may'-tig-eh", "derivation": "from (G3385) and (G1065);", "definition": "not at all then, i.e. not to say (the rather still)", "kjv": "how much more."}, "G3388": {"greek": "μήτρα", "translit": "mḗtra", "pronunciation": "may'-trah", "derivation": "from (G3384);", "definition": "the matrix", "kjv": "womb."}, "G3389": {"greek": "μητραλῴας", "translit": "mētralṓias", "pronunciation": "may-tral-o'-as", "derivation": "from (G3384) and the base of (G257);", "definition": "a mother-thresher, i.e. matricide", "kjv": "murderer of mothers."}, "G3392": {"greek": "μιαίνω", "translit": "miaínō", "pronunciation": "me-ah'-ee-no", "derivation": "perhaps a primary verb;", "definition": "to sully or taint, i.e. contaminate (ceremonially or morally)", "kjv": "defile."}, "G3393": {"greek": "μίασμα", "translit": "míasma", "pronunciation": "mee'-as-mah", "derivation": "from (G3392) (\"miasma\");", "definition": "(morally) foulness (properly, the effect)", "kjv": "pollution."}, "G3394": {"greek": "μιασμός", "translit": "miasmós", "pronunciation": "mee-as-mos'", "derivation": "from (G3392);", "definition": "(morally) contamination (properly, the act)", "kjv": "uncleanness."}, "G3395": {"greek": "μίγμα", "translit": "mígma", "pronunciation": "mig'-mah", "derivation": "from (G3396);", "definition": "a compound", "kjv": "mixture."}, "G3396": {"greek": "μίγνυμι", "translit": "mígnymi", "pronunciation": "mig'-noo-mee", "derivation": "a primary verb;", "definition": "to mix", "kjv": "mingle."}, "G3398": {"greek": "μικρός", "translit": "mikrós", "pronunciation": "mik-ros'", "derivation": "apparently a primary word;", "definition": "small (in size, quantity, number or (figuratively) dignity)", "kjv": "least, less, little, small."}, "G3399": {"greek": "Μίλητος", "translit": "Mílētos", "pronunciation": "mil'-ay-tos", "derivation": "of uncertain origin;", "definition": "Miletus, a city of Asia Minor", "kjv": "Miletus."}, "G3400": {"greek": "μίλιον", "translit": "mílion", "pronunciation": "mil'-ee-on", "derivation": "of Latin origin;", "definition": "a thousand paces, i.e. a \"mile\"", "kjv": "mile."}, "G3401": {"greek": "μιμέομαι", "translit": "miméomai", "pronunciation": "mim-eh'-om-ahee", "derivation": "middle voice from (a \"mimic\");", "definition": "to imitate", "kjv": "follow."}, "G3402": {"greek": "μιμητής", "translit": "mimētḗs", "pronunciation": "mim-ay-tace'", "derivation": "from (G3401);", "definition": "an imitator", "kjv": "follower."}, "G3403": {"greek": "μιμνήσκω", "translit": "mimnḗskō", "pronunciation": "mim-nace'-ko", "derivation": "a prolonged form of (G3415) (from which some of the tenses are borrowed);", "definition": "to remind, i.e. (middle voice) to recall to mind", "kjv": "be mindful, remember."}, "G3404": {"greek": "μισέω", "translit": "miséō", "pronunciation": "mis-eh'-o", "derivation": "from a primary (hatred);", "definition": "to detest (especially to persecute); by extension, to love less", "kjv": "hate(-ful)."}, "G3405": {"greek": "μισθαποδοσία", "translit": "misthapodosía", "pronunciation": "mis-thap-od-os-ee'-ah", "derivation": "from (G3406);", "definition": "requital (good or bad)", "kjv": "recompence of reward."}, "G3406": {"greek": "μισθαποδότης", "translit": "misthapodótēs", "pronunciation": "mis-thap-od-ot'-ace", "derivation": "from (G3409) and (G591);", "definition": "a renumerator", "kjv": "rewarder."}, "G3407": {"greek": "μίσθιος", "translit": "místhios", "pronunciation": "mis'-thee-os", "derivation": "from (G3408);", "definition": "a wage-earner", "kjv": "hired servant."}, "G3408": {"greek": "μισθός", "translit": "misthós", "pronunciation": "mis-thos'", "derivation": "apparently a primary word;", "definition": "pay for service (literally or figuratively), good or bad", "kjv": "hire, reward, wages."}, "G3409": {"greek": "μισθόω", "translit": "misthóō", "pronunciation": "mis-tho'-o", "derivation": "from (G3408);", "definition": "to let out for wages, i.e. (middle voice) to hire", "kjv": "hire."}, "G3410": {"greek": "μίσθωμα", "translit": "místhōma", "pronunciation": "mis'-tho-mah", "derivation": "from (G3409);", "definition": "a rented building", "kjv": "hired house."}, "G3411": {"greek": "μισθωτός", "translit": "misthōtós", "pronunciation": "mis-tho-tos'", "derivation": "from (G3409);", "definition": "a wage-worker (good or bad)", "kjv": "hired servant, hireling."}, "G3412": {"greek": "Μιτυλήνη", "translit": "Mitylḗnē", "pronunciation": "mit-oo-lay'-nay", "derivation": "for (abounding in shellfish);", "definition": "Mitylene (or Mytilene), a town on the island of Lesbos", "kjv": "Mitylene."}, "G3413": {"greek": "Μιχαήλ", "translit": "Michaḗl", "pronunciation": "mikh-ah-ale'", "derivation": "of Hebrew origin ((G4317));", "definition": "Michael, an archangel", "kjv": "Michael."}, "G3414": {"greek": "μνᾶ", "translit": "mnâ", "pronunciation": "mnah", "derivation": "of Latin origin;", "definition": "a mna (i.e. mina), a certain weight", "kjv": "pound."}, "G3416": {"greek": "Μνάσων", "translit": "Mnásōn", "pronunciation": "mnah'-sohn", "derivation": "of uncertain origin;", "definition": "Mnason, a Christian", "kjv": "Mnason."}, "G3417": {"greek": "μνεία", "translit": "mneía", "pronunciation": "mni'-ah", "derivation": "from (G3415) or (G3403);", "definition": "recollection; by implication, recital", "kjv": "mention, remembrance."}, "G3418": {"greek": "μνῆμα", "translit": "mnēma", "pronunciation": "mnay'-mah", "derivation": "from (G3415);", "definition": "a memorial, i.e. sepulchral monument (burial-place)", "kjv": "grave, sepulchre, tomb."}, "G3419": {"greek": "μνημεῖον", "translit": "mnēmeîon", "pronunciation": "mnay-mi'-on", "derivation": "from (G3420);", "definition": "a remembrance, i.e. cenotaph (place of interment)", "kjv": "grave, sepulchre, tomb."}, "G3420": {"greek": "μνήμη", "translit": "mnḗmē", "pronunciation": "mnay'-may", "derivation": "from (G3403);", "definition": "memory", "kjv": "remembrance."}, "G3421": {"greek": "μνημονεύω", "translit": "mnēmoneúō", "pronunciation": "mnay-mon-yoo'-o", "derivation": "from a derivative of (G3420);", "definition": "to exercise memory, i.e. recollect; by implication, to punish; also to rehearse", "kjv": "make mention; be mindful, remember."}, "G3422": {"greek": "μνημόσυνον", "translit": "mnēmósynon", "pronunciation": "mnay-mos'-oo-non", "derivation": "from (G3421);", "definition": "a reminder (memorandum), i.e. record", "kjv": "memorial."}, "G3423": {"greek": "μνηστεύω", "translit": "mnēsteúō", "pronunciation": "mnace-tyoo'-o", "derivation": "from a derivative of (G3415);", "definition": "to give a souvenir (engagement present), i.e. betroth", "kjv": "espouse."}, "G3424": {"greek": "μογιλάλος", "translit": "mogilálos", "pronunciation": "mog-il-al'-os", "derivation": "from (G3425) and (G2980);", "definition": "hardly talking, i.e. dumb (tongue-tied)", "kjv": "having an impediment in his speech."}, "G3425": {"greek": "μόγις", "translit": "mógis", "pronunciation": "mog'-is", "derivation": "adverb from a primary (toil);", "definition": "with difficulty", "kjv": "hardly."}, "G3426": {"greek": "μόδιος", "translit": "módios", "pronunciation": "mod'-ee-os", "derivation": "of Latin origin;", "definition": "a modius, i.e. certain measure for things dry (the quantity or the utensil)", "kjv": "bushel."}, "G3427": {"greek": "μοί", "translit": "moí", "pronunciation": "moy", "derivation": "the simpler form of (G1698);", "definition": "to me", "kjv": "I, me, mine, my."}, "G3428": {"greek": "μοιχαλίς", "translit": "moichalís", "pronunciation": "moy-khal-is'", "derivation": "a prolonged form of the feminine of (G3432);", "definition": "an adulteress (literally or figuratively)", "kjv": "adulteress(-ous, -y)."}, "G3429": {"greek": "μοιχάω", "translit": "moicháō", "pronunciation": "moy-khah'-o", "derivation": "from (G3432);", "definition": "(middle voice) to commit adultery", "kjv": "commit adultery."}, "G3430": {"greek": "μοιχεία", "translit": "moicheía", "pronunciation": "moy-khi'-ah", "derivation": "from (G3431);", "definition": "adultery", "kjv": "adultery."}, "G3431": {"greek": "μοιχεύω", "translit": "moicheúō", "pronunciation": "moy-khyoo'-o", "derivation": "from (G3432);", "definition": "to commit adultery", "kjv": "commit adultery."}, "G3432": {"greek": "μοιχός", "translit": "moichós", "pronunciation": "moy-khos'", "derivation": "perhaps a primary word;", "definition": "a (male) paramour; figuratively, apostate", "kjv": "adulterer."}, "G3433": {"greek": "μόλις", "translit": "mólis", "pronunciation": "mol'-is", "derivation": "probably by variation for (G3425);", "definition": "with difficulty", "kjv": "hardly, scarce(-ly), + with much work."}, "G3434": {"greek": "Μολόχ", "translit": "Molóch", "pronunciation": "mol-okh'", "derivation": "of Hebrew origin ((G4432));", "definition": "Moloch (i.e. Molek), an idol", "kjv": "Moloch."}, "G3435": {"greek": "μολύνω", "translit": "molýnō", "pronunciation": "mol-oo'-no", "derivation": "probably from (G3189);", "definition": "to soil (figuratively)", "kjv": "defile."}, "G3436": {"greek": "μολυσμός", "translit": "molysmós", "pronunciation": "mol-oos-mos'", "derivation": "from (G3435);", "definition": "a stain; i.e. (figuratively) immorality", "kjv": "filthiness."}, "G3437": {"greek": "μομφή", "translit": "momphḗ", "pronunciation": "mom-fay'", "derivation": "from (G3201);", "definition": "blame, i.e. (by implication), a fault", "kjv": "quarrel."}, "G3438": {"greek": "μονή", "translit": "monḗ", "pronunciation": "mon-ay'", "derivation": "from (G3306);", "definition": "a staying, i.e. residence (the act or the place)", "kjv": "abode, mansion."}, "G3439": {"greek": "μονογενής", "translit": "monogenḗs", "pronunciation": "mon-og-en-ace'", "derivation": "from (G3441) and (G1096);", "definition": "only-born, i.e. sole", "kjv": "only (begotten, child)."}, "G3440": {"greek": "μόνον", "translit": "mónon", "pronunciation": "mon'-on", "derivation": "neuter of (G3441) as adverb;", "definition": "merely", "kjv": "alone, but, only."}, "G3441": {"greek": "μόνος", "translit": "mónos", "pronunciation": "mon'-os", "derivation": "probably from (G3306);", "definition": "remaining, i.e. sole or single; by implication, mere", "kjv": "alone, only, by themselves."}, "G3442": {"greek": "μονόφθαλμος", "translit": "monóphthalmos", "pronunciation": "mon-of'-thal-mos", "derivation": "from (G3441) and (G3788);", "definition": "one-eyed", "kjv": "with one eye."}, "G3443": {"greek": "μονόω", "translit": "monóō", "pronunciation": "mon-o'-o", "derivation": "from (G3441);", "definition": "to isolate, i.e. bereave", "kjv": "be desolate."}, "G3444": {"greek": "μορφή", "translit": "morphḗ", "pronunciation": "mor-fay'", "derivation": "perhaps from the base of (G3313) (through the idea of adjustment of parts);", "definition": "shape; figuratively, nature", "kjv": "form."}, "G3445": {"greek": "μορφόω", "translit": "morphóō", "pronunciation": "mor-fo'-o", "derivation": "from the same as (G3444);", "definition": "to fashion (figuratively)", "kjv": "form."}, "G3446": {"greek": "μόρφωσις", "translit": "mórphōsis", "pronunciation": "mor'-fo-sis", "derivation": "from (G3445);", "definition": "formation, i.e. (by implication), appearance (semblance or (concretely) formula)", "kjv": "form."}, "G3447": {"greek": "μοσχοποιέω", "translit": "moschopoiéō", "pronunciation": "mos-khop-oy-eh'-o", "derivation": "from (G3448) and (G4160);", "definition": "to fabricate the image of a bullock", "kjv": "make a calf."}, "G3448": {"greek": "μόσχος", "translit": "móschos", "pronunciation": "mos'-khos", "derivation": "probably strengthened for (a shoot);", "definition": "a young bullock", "kjv": "calf."}, "G3449": {"greek": "μόχθος", "translit": "móchthos", "pronunciation": "mokh'-thos", "derivation": "from the base of (G3425);", "definition": "toil, i.e. (by implication) sadness", "kjv": "painfulness, travail."}, "G3450": {"greek": "μοῦ", "translit": "moû", "pronunciation": "moo", "derivation": "the simpler form of (G1700);", "definition": "of me", "kjv": "I, me, mine (own), my."}, "G3451": {"greek": "μουσικός", "translit": "mousikós", "pronunciation": "moo-sik-os'", "derivation": "from (a Muse);", "definition": "\"musical\", i.e. (as noun) a minstrel", "kjv": "musician."}, "G3452": {"greek": "μυελός", "translit": "myelós", "pronunciation": "moo-el-os'", "derivation": "perhaps a primary word;", "definition": "the marrow", "kjv": "marrow."}, "G3453": {"greek": "μυέω", "translit": "myéō", "pronunciation": "moo-eh'-o", "derivation": "from the base of (G3466);", "definition": "to initiate, i.e. (by implication) to teach", "kjv": "instruct."}, "G3454": {"greek": "μῦθος", "translit": "mŷthos", "pronunciation": "moo'-thos", "derivation": "perhaps from the same as (G3453) (through the idea of tuition);", "definition": "a tale, i.e. fiction (\"myth\")", "kjv": "fable."}, "G3455": {"greek": "μυκάομαι", "translit": "mykáomai", "pronunciation": "moo-kah'-om-ahee", "derivation": "from a presumed derivative of ( to \"moo\");", "definition": "to bellow (roar)", "kjv": "roar."}, "G3456": {"greek": "μυκτηρίζω", "translit": "myktērízō", "pronunciation": "mook-tay-rid'-zo", "derivation": "from a derivative of the base of (G3455) (meaning snout, as that whence lowing proceeds);", "definition": "to make mouths at, i.e. ridicule", "kjv": "mock."}, "G3457": {"greek": "μυλικός", "translit": "mylikós", "pronunciation": "moo-lee-kos'", "derivation": "from (G3458);", "definition": "belonging to a mill", "kjv": "mill(-stone)."}, "G3458": {"greek": "μύλος", "translit": "mýlos", "pronunciation": "moo'-los", "derivation": "probably ultimately from the base of (G3433) (through the idea of hardship);", "definition": "a \"mill\", i.e. (by implication), a grinder (millstone)", "kjv": "millstone."}, "G3460": {"greek": "Μύρα", "translit": "Mýra", "pronunciation": "moo'-rah", "derivation": "of uncertain derivation;", "definition": "Myra, a place in Asia Minor", "kjv": "Myra."}, "G3461": {"greek": "μυριάς", "translit": "myriás", "pronunciation": "moo-ree'-as", "derivation": "from (G3463);", "definition": "a ten-thousand; by extension, a \"myriad\" or indefinite number", "kjv": "ten thousand."}, "G3462": {"greek": "μυρίζω", "translit": "myrízō", "pronunciation": "moo-rid'-zo", "derivation": "from (G3464);", "definition": "to apply (perfumed) unguent to", "kjv": "anoint."}, "G3463": {"greek": "μύριοι", "translit": "mýrioi", "pronunciation": "moo'-ree-oi", "derivation": "plural of an apparently primary word (properly, meaning very many);", "definition": "ten thousand; by extension, innumerably many", "kjv": "ten thousand."}, "G3464": {"greek": "μύρον", "translit": "mýron", "pronunciation": "moo'-ron", "derivation": "probably of foreign origin (compare (G4753), (G4666));", "definition": "\"myrrh\", i.e. (by implication) perfumed oil", "kjv": "ointment."}, "G3465": {"greek": "Μυσία", "translit": "Mysía", "pronunciation": "moo-see'-ah", "derivation": "of uncertain origin;", "definition": "Mysia, a region of Asia Minor", "kjv": "Mysia."}, "G3466": {"greek": "μυστήριον", "translit": "mystḗrion", "pronunciation": "moos-tay'-ree-on", "derivation": "from a derivative of (to shut the mouth);", "definition": "a secret or \"mystery\" (through the idea of silence imposed by initiation into religious rites)", "kjv": "mystery."}, "G3467": {"greek": "μυωπάζω", "translit": "myōpázō", "pronunciation": "moo-ope-ad'-zo", "derivation": "from a compound of the base of (G3466) and (the face; from (G3700));", "definition": "to shut the eyes, i.e. blink (see indistinctly)", "kjv": "cannot see far off."}, "G3468": {"greek": "μώλωψ", "translit": "mṓlōps", "pronunciation": "mo'-lopes", "derivation": "from (\"moil\"; probably akin to the base of (G3433))", "definition": "and probably (the face; from (G3700)); a mole (\"black eye\") or blow-mark", "kjv": "stripe."}, "G3469": {"greek": "μωμάομαι", "translit": "mōmáomai", "pronunciation": "mo-mah'-om-ahee", "derivation": "from (G3470);", "definition": "to carp at, i.e. censure (discredit)", "kjv": "blame."}, "G3470": {"greek": "μῶμος", "translit": "mōmos", "pronunciation": "mo'-mos", "derivation": "perhaps from (G3201);", "definition": "a flaw or blot, i.e. (figuratively) disgraceful person", "kjv": "blemish."}, "G3471": {"greek": "μωραίνω", "translit": "mōraínō", "pronunciation": "mo-rah'-ee-no", "derivation": "from (G3474);", "definition": "to become insipid; figuratively, to make (passively, act) as a simpleton", "kjv": "become fool, make foolish, lose savour."}, "G3472": {"greek": "μωρία", "translit": "mōría", "pronunciation": "mo-ree'-ah", "derivation": "from (G3474);", "definition": "silliness, i.e. absurdity", "kjv": "foolishness."}, "G3473": {"greek": "μωρολογία", "translit": "mōrología", "pronunciation": "mo-rol-og-ee'-ah", "derivation": "from a compound of (G3474) and (G3004);", "definition": "silly talk, i.e. buffoonery", "kjv": "foolish talking."}, "G3474": {"greek": "μωρός", "translit": "mōrós", "pronunciation": "mo-ros'", "derivation": "probably from the base of (G3466);", "definition": "dull or stupid (as if shut up), i.e. heedless, (morally) blockhead, (apparently) absurd", "kjv": "fool(-ish, X -ishness)."}, "G3475": {"greek": "Μωσεύς", "translit": "Mōseús", "pronunciation": "moce-yoos'", "derivation": "of Hebrew origin; ((G4872));", "definition": "Moseus, Moses, or Mouses (i.e. Mosheh), the Hebrew lawgiver", "kjv": "Moses."}, "G3476": {"greek": "Ναασσών", "translit": "Naassṓn", "pronunciation": "nah-as-sone'", "derivation": "of Hebrew origin ((G5177));", "definition": "Naasson (i.e. Nachshon), an Israelite", "kjv": "Naasson."}, "G3477": {"greek": "Ναγγαί", "translit": "Nangaí", "pronunciation": "nang-gah'-ee", "derivation": "probably of Hebrew origin (compare (G5052));", "definition": "Nangæ (i.e. perhaps Nogach), an Israelite", "kjv": "Nagge."}, "G3478": {"greek": "Ναζαρέθ", "translit": "Nazaréth", "pronunciation": "nad-zar-eth'", "derivation": "of uncertain derivation;", "definition": "Nazareth or Nazaret, a place in Palestine", "kjv": "Nazareth."}, "G3479": {"greek": "Ναζαρηνός", "translit": "Nazarēnós", "pronunciation": "nad-zar-ay-nos'", "derivation": "from (G3478);", "definition": "a Nazarene, i.e. inhabitant of Nazareth", "kjv": "of Nazareth."}, "G3480": {"greek": "Ναζωραῖος", "translit": "Nazōraîos", "pronunciation": "nad-zo-rah'-yos", "derivation": "from (G3478);", "definition": "a Nazoræan, i.e. inhabitant of Nazareth; by extension, a Christian", "kjv": "Nazarene, of Nazareth."}, "G3481": {"greek": "Ναθάν", "translit": "Nathán", "pronunciation": "nath-an'", "derivation": "of Hebrew origin ((G5416));", "definition": "Nathan, an Israelite", "kjv": "Nathan."}, "G3482": {"greek": "Ναθαναήλ", "translit": "Nathanaḗl", "pronunciation": "nath-an-ah-ale'", "derivation": "of Hebrew origin ((G5417));", "definition": "Nathanaël (i.e. Nathanel), an Israelite and Christian", "kjv": "Nathanael."}, "G3483": {"greek": "ναί", "translit": "naí", "pronunciation": "nahee", "derivation": "a primary particle of strong affirmation;", "definition": "yes", "kjv": "even so, surely, truth, verily, yea, yes."}, "G3484": {"greek": "Ναΐν", "translit": "Naḯn", "pronunciation": "nah-in'", "derivation": "probably of Hebrew origin (compare (G4999));", "definition": "Nain, a place in Palestine", "kjv": "Nain."}, "G3485": {"greek": "ναός", "translit": "naós", "pronunciation": "nah-os'", "derivation": "from a primary (to dwell);", "definition": "a fane, shrine, temple", "kjv": "shrine, temple."}, "G3486": {"greek": "Ναούμ", "translit": "Naoúm", "pronunciation": "nah-oom'", "derivation": "of Hebrew origin ((G5151));", "definition": "Naum (i.e. Nachum), an Israelite", "kjv": "Naum."}, "G3487": {"greek": "νάρδος", "translit": "nárdos", "pronunciation": "nar'dos", "derivation": "of foreign origin (compare (G5373));", "definition": "\"nard\"", "kjv": "(spike-)nard."}, "G3488": {"greek": "Νάρκισσος", "translit": "Nárkissos", "pronunciation": "nar'-kis-sos", "derivation": "a flower of the same name, from (stupefaction, as a \"narcotic\");", "definition": "Narcissus, a Roman", "kjv": "Narcissus."}, "G3489": {"greek": "ναυαγέω", "translit": "nauagéō", "pronunciation": "now-ag-eh'-o", "derivation": "from a compound of (G3491) and (G71);", "definition": "to be shipwrecked (stranded, \"navigate\"), literally or figuratively", "kjv": "make (suffer) shipwreck."}, "G3490": {"greek": "ναύκληρος", "translit": "naúklēros", "pronunciation": "now'-klay-ros", "derivation": "from (G3491) and (G2819) (\"clerk\");", "definition": "a captain", "kjv": "owner of a ship."}, "G3491": {"greek": "ναῦς", "translit": "naûs", "pronunciation": "nowce", "derivation": "from or (to float);", "definition": "a boat (of any size)", "kjv": "ship."}, "G3492": {"greek": "ναύτης", "translit": "naútēs", "pronunciation": "now'-tace", "derivation": "from (G3491);", "definition": "a boatman, i.e. seaman", "kjv": "sailor, shipman."}, "G3493": {"greek": "Ναχώρ", "translit": "Nachṓr", "pronunciation": "nakh-ore'", "derivation": "of Hebrew origin ((G5152));", "definition": "Nachor, the grandfather of Abraham", "kjv": "Nachor."}, "G3494": {"greek": "νεανίας", "translit": "neanías", "pronunciation": "neh-an-ee'-as", "derivation": "from a derivative of (G3501);", "definition": "a youth (up to about forty years)", "kjv": "young man."}, "G3495": {"greek": "νεανίσκος", "translit": "neanískos", "pronunciation": "neh-an-is'-kos", "derivation": "from the same as (G3494);", "definition": "a youth (under forty)", "kjv": "young man."}, "G3496": {"greek": "Νεάπολις", "translit": "Neápolis", "pronunciation": "neh-ap'-ol-is", "derivation": "from (G3501) and (G4172);", "definition": "new town; Neapolis, a place in Macedonia", "kjv": "Neapolis."}, "G3497": {"greek": "Νεεμάν", "translit": "Neemán", "pronunciation": "neh-eh-man'", "derivation": "of Hebrew origin ((G5283));", "definition": "Neeman (i.e. Naaman), a Syrian", "kjv": "Naaman."}, "G3498": {"greek": "νεκρός", "translit": "nekrós", "pronunciation": "nek-ros'", "derivation": "from an apparently primary (a corpse);", "definition": "dead (literally or figuratively; also as noun)", "kjv": "dead."}, "G3499": {"greek": "νεκρόω", "translit": "nekróō", "pronunciation": "nek-ro'-o", "derivation": "from (G3498);", "definition": "to deaden, i.e. (figuratively) to subdue", "kjv": "be dead, mortify."}, "G3500": {"greek": "νέκρωσις", "translit": "nékrōsis", "pronunciation": "nek'-ro-sis", "derivation": "from (G3499);", "definition": "decease; figuratively, impotency", "kjv": "deadness, dying."}, "G3501": {"greek": "νέος", "translit": "néos", "pronunciation": "neh'-os", "derivation": "including the comparative ; a primary word;", "definition": "\"new\", i.e. (of persons) youthful, or (of things) fresh; figuratively, regenerate", "kjv": "new, young."}, "G3502": {"greek": "νεοσσός", "translit": "neossós", "pronunciation": "neh-os-sos'", "derivation": "from (G3501);", "definition": "a youngling (nestling)", "kjv": "young."}, "G3503": {"greek": "νεότης", "translit": "neótēs", "pronunciation": "neh-ot'-ace", "derivation": "from (G3501);", "definition": "newness, i.e. youthfulness", "kjv": "youth."}, "G3504": {"greek": "νεόφυτος", "translit": "neóphytos", "pronunciation": "neh-of'-oo-tos", "derivation": "from (G3501) and a derivative of (G5453);", "definition": "newly planted, i.e. (figuratively) a young convert (\"neophyte\")", "kjv": "novice."}, "G3506": {"greek": "νεύω", "translit": "neúō", "pronunciation": "nyoo'-o", "derivation": "apparently a primary verb;", "definition": "to \"nod\", i.e. (by analogy), signal", "kjv": "beckon."}, "G3507": {"greek": "νεφέλη", "translit": "nephélē", "pronunciation": "nef-el'-ay", "derivation": "from (G3509);", "definition": "properly, cloudiness, i.e. (concretely) a cloud", "kjv": "cloud."}, "G3508": {"greek": "Νεφθαλείμ", "translit": "Nephthaleím", "pronunciation": "nef-thal-ime'", "derivation": "of Hebrew origin ((G5321));", "definition": "Nephthaleim (i.e. Naphthali), a tribe in Palestine", "kjv": "Nephthalim."}, "G3509": {"greek": "νέφος", "translit": "néphos", "pronunciation": "nef'-os", "derivation": "apparently a primary word;", "definition": "a cloud", "kjv": "cloud."}, "G3510": {"greek": "νεφρός", "translit": "nephrós", "pronunciation": "nef-ros'", "derivation": "of uncertain affinity;", "definition": "a kidney (plural), i.e. (figuratively) the inmost mind", "kjv": "reins."}, "G3511": {"greek": "νεωκόρος", "translit": "neōkóros", "pronunciation": "neh-o-kor'-os", "derivation": "from a form of (G3485) and (to sweep);", "definition": "a temple-servant, i.e. (by implication) a votary", "kjv": "worshipper."}, "G3512": {"greek": "νεωτερικός", "translit": "neōterikós", "pronunciation": "neh-o-ter'-ik-os", "derivation": "from the comparative of (G3501);", "definition": "appertaining to younger persons, i.e. juvenile", "kjv": "youthful."}, "G3513": {"greek": "νή", "translit": "nḗ", "pronunciation": "nay", "derivation": "probably an intensive form of (G3483);", "definition": "a particle of attestation (accompanied by the object invoked or appealed to in confirmation); as sure as", "kjv": "I protest by."}, "G3514": {"greek": "νήθω", "translit": "nḗthō", "pronunciation": "nay'-tho", "derivation": "from (of like meaning);", "definition": "to spin", "kjv": "spin."}, "G3515": {"greek": "νηπιάζω", "translit": "nēpiázō", "pronunciation": "nay-pee-ad'-zo", "derivation": "from (G3516);", "definition": "to act as a babe, i.e. (figuratively) innocently", "kjv": "be a child."}, "G3516": {"greek": "νήπιος", "translit": "nḗpios", "pronunciation": "nay'-pee-os", "derivation": "from an obsolete particle (implying negation) and (G2031);", "definition": "not speaking, i.e. an infant (minor); figuratively, a simple-minded person, an immature Christian", "kjv": "babe, child (+ -ish)."}, "G3517": {"greek": "Νηρεύς", "translit": "Nēreús", "pronunciation": "nare-yoos'", "derivation": "apparently from a derivative of the base of (G3491) (meaning wet);", "definition": "Nereus, a Christian", "kjv": "Nereus."}, "G3518": {"greek": "Νηρί", "translit": "Nērí", "pronunciation": "nay-ree'", "derivation": "of Hebrew origin ((G5374));", "definition": "Neri (i.e. Nerijah), an Israelite", "kjv": "Neri."}, "G3519": {"greek": "νησίον", "translit": "nēsíon", "pronunciation": "nay-see'-on", "derivation": "diminutive of (G3520);", "definition": "an islet", "kjv": "island."}, "G3520": {"greek": "νῆσος", "translit": "nēsos", "pronunciation": "nay'-sos", "derivation": "probably from the base of (G3491);", "definition": "an island", "kjv": "island, isle."}, "G3521": {"greek": "νηστεία", "translit": "nēsteía", "pronunciation": "nace-ti'-ah", "derivation": "from (G3522);", "definition": "abstinence (from lack of food, or voluntary and religious); specially, the fast of the Day of Atonement", "kjv": "fast(-ing)."}, "G3522": {"greek": "νηστεύω", "translit": "nēsteúō", "pronunciation": "nace-tyoo'-o", "derivation": "from (G3523);", "definition": "to abstain from food (religiously)", "kjv": "fast."}, "G3523": {"greek": "νῆστις", "translit": "nēstis", "pronunciation": "nace'-tis", "derivation": "from the inseparable negative particle (not) and (G2068);", "definition": "not eating, i.e. abstinent from food (religiously)", "kjv": "fasting."}, "G3524": {"greek": "νηφάλεος", "translit": "nēpháleos", "pronunciation": "nay-fal'-eh-os", "derivation": "from (G3525);", "definition": "sober, i.e. (figuratively) circumspect", "kjv": "sober."}, "G3525": {"greek": "νήφω", "translit": "nḗphō", "pronunciation": "nay'-fo", "derivation": "of uncertain affinity;", "definition": "to abstain from wine (keep sober), i.e. (figuratively) be discreet", "kjv": "be sober, watch."}, "G3526": {"greek": "Νίγερ", "translit": "Níger", "pronunciation": "neeg'-er", "derivation": "of Latin origin;", "definition": "black; Niger, a Christian", "kjv": "Niger."}, "G3527": {"greek": "Νικάνωρ", "translit": "Nikánōr", "pronunciation": "nik-an'-ore", "derivation": "probably from (G3528);", "definition": "victorious; Nicanor, a Christian", "kjv": "Nicanor."}, "G3528": {"greek": "νικάω", "translit": "nikáō", "pronunciation": "nik-ah'-o", "derivation": "from (G3529);", "definition": "to subdue (literally or figuratively)", "kjv": "conquer, overcome, prevail, get the victory."}, "G3529": {"greek": "νίκη", "translit": "níkē", "pronunciation": "nee'-kay", "derivation": "apparently a primary word;", "definition": "conquest (abstractly), i.e. (figuratively) the means of success", "kjv": "victory."}, "G3530": {"greek": "Νικόδημος", "translit": "Nikódēmos", "pronunciation": "nik-od'-ay-mos", "derivation": "from (G3534) and (G1218);", "definition": "victorious among his people; Nicodemus, an Israelite", "kjv": "Nicodemus."}, "G3531": {"greek": "Νικολαΐτης", "translit": "Nikolaḯtēs", "pronunciation": "nik-ol-ah-ee'-tace", "derivation": "from (G3532);", "definition": "a Nicolaite, i.e. adherent of Nicolaus", "kjv": "Nicolaitane."}, "G3532": {"greek": "Νικόλαος", "translit": "Nikólaos", "pronunciation": "nik-ol'-ah-os", "derivation": "from (G3534) and (G2992);", "definition": "victorious over the people; Nicolaüs, a heretic", "kjv": "Nicolaus."}, "G3533": {"greek": "Νικόπολις", "translit": "Nikópolis", "pronunciation": "nik-op'-ol-is", "derivation": "from (G3534) and (G4172);", "definition": "victorious city; Nicopolis, a place in Macedonia", "kjv": "Nicopolis."}, "G3534": {"greek": "νῖκος", "translit": "nîkos", "pronunciation": "nee'-kos", "derivation": "from (G3529);", "definition": "a conquest (concretely), i.e. (by implication) triumph", "kjv": "victory."}, "G3536": {"greek": "Νινευΐτης", "translit": "Nineuḯtēs", "pronunciation": "nin-yoo-ee'-tace", "derivation": "from (G3535);", "definition": "a Ninevite, i.e. inhabitant of Nineveh", "kjv": "of Nineve, Ninevite."}, "G3537": {"greek": "νιπτήρ", "translit": "niptḗr", "pronunciation": "nip-tare'", "derivation": "from (G3538);", "definition": "a ewer", "kjv": "bason."}, "G3538": {"greek": "νίπτω", "translit": "níptō", "pronunciation": "nip'-to", "derivation": "", "definition": "to cleanse (especially the hands or the feet or the face); ceremonially, to perform ablution", "kjv": "wash."}, "G3539": {"greek": "νοιέω", "translit": "noiéō", "pronunciation": "noy-eh'-o", "derivation": "from (G3563);", "definition": "to exercise the mind (observe), i.e. (figuratively) to comprehend, heed", "kjv": "consider, perceive, think, understand."}, "G3540": {"greek": "νόημα", "translit": "nóēma", "pronunciation": "no'-ay-mah", "derivation": "from (G3539);", "definition": "a perception, i.e. purpose, or (by implication) the intellect, disposition, itself", "kjv": "device, mind, thought."}, "G3541": {"greek": "νόθος", "translit": "nóthos", "pronunciation": "noth'-os", "derivation": "of uncertain affinity;", "definition": "a spurious or illegitimate son", "kjv": "bastard."}, "G3542": {"greek": "νομή", "translit": "nomḗ", "pronunciation": "nom-ay'", "derivation": "feminine from the same as (G3551);", "definition": "pasture, i.e. (the act) feeding (figuratively, spreading of a gangrene), or (the food) pasturage", "kjv": "X eat, pasture."}, "G3543": {"greek": "νομίζω", "translit": "nomízō", "pronunciation": "nom-id'-zo", "derivation": "from (G3551);", "definition": "properly, to do by law (usage), i.e. to accustom (passively, be usual); by extension, to deem or regard", "kjv": "suppose, thing, be wont."}, "G3544": {"greek": "νομικός", "translit": "nomikós", "pronunciation": "nom-ik-os'", "derivation": "from (G3551);", "definition": "according (or pertaining) to law, i.e. legal (ceremonially); as noun, an expert in the (Mosaic) law", "kjv": "about the law, lawyer."}, "G3545": {"greek": "νομίμως", "translit": "nomímōs", "pronunciation": "nom-im'-oce", "derivation": "adverb from a derivative of (G3551);", "definition": "legitimately (specially, agreeably to the rules of the lists)", "kjv": "lawfully."}, "G3546": {"greek": "νόμισμα", "translit": "nómisma", "pronunciation": "nom'-is-mah", "derivation": "from (G3543);", "definition": "what is reckoned as of value (after the Latin numisma), i.e. current coin", "kjv": "money."}, "G3547": {"greek": "νομοδιδάσκαλος", "translit": "nomodidáskalos", "pronunciation": "nom-od-id-as'-kal-os", "derivation": "from (G3551) and (G1320);", "definition": "an expounder of the (Jewish) law, i.e. a Rabbi", "kjv": "doctor (teacher) of the law."}, "G3548": {"greek": "νομοθεσία", "translit": "nomothesía", "pronunciation": "nom-oth-es-ee'-ah", "derivation": "from (G3550);", "definition": "legislation (specially, the institution of the Mosaic code)", "kjv": "giving of the law."}, "G3549": {"greek": "νομοθετέω", "translit": "nomothetéō", "pronunciation": "nom-oth-et-eh'-o", "derivation": "from (G3550);", "definition": "to legislate, i.e. (passively) to have (the Mosaic) enactments injoined, be sanctioned (by them)", "kjv": "establish, receive the law."}, "G3550": {"greek": "νομοθέτης", "translit": "nomothétēs", "pronunciation": "nom-oth-et'-ace", "derivation": "from (G3551) and a derivative of (G5087);", "definition": "a legislator", "kjv": "lawgiver."}, "G3551": {"greek": "νόμος", "translit": "nómos", "pronunciation": "nom'-os", "derivation": "from a primary (to parcel out, especially food or grazing to animals);", "definition": "law (through the idea of prescriptive usage), genitive case (regulation), specially, (of Moses (including the volume); also of the Gospel), or figuratively (a principle)", "kjv": "law."}, "G3552": {"greek": "νοσέω", "translit": "noséō", "pronunciation": "nos-eh'-o", "derivation": "from (G3554);", "definition": "to be sick, i.e. (by implication, of a diseased appetite) to hanker after (figuratively, to harp upon)", "kjv": "dote."}, "G3554": {"greek": "νόσος", "translit": "nósos", "pronunciation": "nos'-os", "derivation": "of uncertain affinity;", "definition": "a malady (rarely figuratively, of moral disability)", "kjv": "disease, infirmity, sickness."}, "G3555": {"greek": "νοσσιά", "translit": "nossiá", "pronunciation": "nos-see-ah'", "derivation": "from (G3502);", "definition": "a brood (of chickens)", "kjv": "brood."}, "G3556": {"greek": "νοσσίον", "translit": "nossíon", "pronunciation": "nos-see'-on", "derivation": "diminutive of (G3502);", "definition": "a birdling", "kjv": "chicken."}, "G3557": {"greek": "νοσφίζομαι", "translit": "nosphízomai", "pronunciation": "nos-fid'-zom-ahee", "derivation": "middle voice from (apart or clandestinely);", "definition": "to sequestrate for oneself, i.e. embezzle", "kjv": "keep back, purloin."}, "G3558": {"greek": "νότος", "translit": "nótos", "pronunciation": "not'-os", "derivation": "of uncertain affinity;", "definition": "the south(-west) wind; by extension, the southern quarter itself", "kjv": "south (wind)."}, "G3559": {"greek": "νουθεσία", "translit": "nouthesía", "pronunciation": "noo-thes-ee'-ah", "derivation": "from (G3563) and a derivative of (G5087);", "definition": "calling attention to, i.e. (by implication) mild rebuke or warning", "kjv": "admonition."}, "G3560": {"greek": "νουθετέω", "translit": "nouthetéō", "pronunciation": "noo-thet-eh'-o", "derivation": "from the same as (G3559);", "definition": "to put in mind, i.e. (by implication) to caution or reprove gently", "kjv": "admonish, warn."}, "G3561": {"greek": "νουμηνία", "translit": "noumēnía", "pronunciation": "noo-may-nee'-ah", "derivation": "feminine of a compound of (G3501) and (G3376) (as noun by implication, of (G2250));", "definition": "the festival of new moon", "kjv": "new moon."}, "G3562": {"greek": "νουνεχῶς", "translit": "nounechōs", "pronunciation": "noon-ekh-oce'", "derivation": "adverb from a compound of the accusative case of (G3563) and (G2192);", "definition": "in a mind-having way, i.e. prudently", "kjv": "discreetly."}, "G3563": {"greek": "νοῦς", "translit": "noûs", "pronunciation": "nooce", "derivation": "probably from the base of (G1097);", "definition": "the intellect, i.e. mind (divine or human; in thought, feeling, or will); by implication, meaning", "kjv": "mind, understanding."}, "G3564": {"greek": "Νυμφᾶς", "translit": "Nymphâs", "pronunciation": "noom-fas'", "derivation": "probably contracted for a compound of (G3565) and (G1435);", "definition": "nymph-given (i.e. -born); Nymphas, a Christian", "kjv": "Nymphas."}, "G3565": {"greek": "νύμφη", "translit": "nýmphē", "pronunciation": "noom-fay'", "derivation": "from a primary but obsolete verb (to veil as a bride; compare Latin \"nupto,\" to marry);", "definition": "a young married woman (as veiled), including a betrothed girl; by implication, a son's wife", "kjv": "bride, daughter in law."}, "G3566": {"greek": "νυμφίος", "translit": "nymphíos", "pronunciation": "noom-fee'-os", "derivation": "from (G3565);", "definition": "a bride-groom (literally or figuratively)", "kjv": "bridegroom."}, "G3567": {"greek": "νυμφών", "translit": "nymphṓn", "pronunciation": "noom-fohn'", "derivation": "from (G3565);", "definition": "the bridal room", "kjv": "bridechamber."}, "G3568": {"greek": "νῦν", "translit": "nŷn", "pronunciation": "noon", "derivation": "a primary particle of present time;", "definition": "\"now\" (as adverb of date, a transition or emphasis); also as noun or adjective present or immediate", "kjv": "henceforth, + hereafter, of late, soon, present, this (time)."}, "G3570": {"greek": "νυνί", "translit": "nyní", "pronunciation": "noo-nee'", "derivation": "a prolonged form of (G3568) for emphasis;", "definition": "just now", "kjv": "now."}, "G3571": {"greek": "νύξ", "translit": "nýx", "pronunciation": "noox", "derivation": "a primary word;", "definition": "\"night\" (literally or figuratively)", "kjv": "(mid-)night."}, "G3572": {"greek": "νύσσω", "translit": "nýssō", "pronunciation": "noos'-so", "derivation": "apparently a primary word;", "definition": "to prick (\"nudge\")", "kjv": "pierce."}, "G3573": {"greek": "νυστάζω", "translit": "nystázō", "pronunciation": "noos-tad'-zo", "derivation": "from a presumed derivative of (G3506);", "definition": "to nod, i.e. (by implication) to fall asleep; figuratively, to delay", "kjv": "slumber."}, "G3574": {"greek": "νυχθήμερον", "translit": "nychthḗmeron", "pronunciation": "nookh-thay'-mer-on", "derivation": "from (G3571) and (G2250);", "definition": "a day-and-night, i.e. full day of twenty-four hours", "kjv": "night and day."}, "G3575": {"greek": "Νῶε", "translit": "Nōe", "pronunciation": "no'-eh", "derivation": "of Hebrew origin ((G5146));", "definition": "Noë, (i.e. Noäch), a patriarch", "kjv": "Noe."}, "G3576": {"greek": "νωθρός", "translit": "nōthrós", "pronunciation": "no-thros'", "derivation": "from a derivative of (G3541);", "definition": "sluggish, i.e. (literally) lazy, or (figuratively) stupid", "kjv": "dull, slothful."}, "G3577": {"greek": "νῶτος", "translit": "nōtos", "pronunciation": "no'-tos", "derivation": "of uncertain affinity;", "definition": "the back", "kjv": "back."}, "G3578": {"greek": "ξενία", "translit": "xenía", "pronunciation": "xen-ee'-ah", "derivation": "from (G3581);", "definition": "hospitality, i.e. (by implication) a place of entertainment", "kjv": "lodging."}, "G3579": {"greek": "ξενίζω", "translit": "xenízō", "pronunciation": "xen-id'-zo", "derivation": "from (G3581);", "definition": "to be a host (passively, a guest); by implication, be (make, appear) strange", "kjv": "entertain, lodge, (think it) strange."}, "G3580": {"greek": "ξενοδοχέω", "translit": "xenodochéō", "pronunciation": "xen-od-okh-eh'-o", "derivation": "from a compound of (G3581) and (G1209);", "definition": "to be hospitable", "kjv": "lodge strangers."}, "G3581": {"greek": "ξένος", "translit": "xénos", "pronunciation": "xen'-os", "derivation": "apparently a primary word;", "definition": "foreign (literally, alien, or figuratively, novel); by implication, a guest or (vice-versa) entertainer", "kjv": "host, strange(-r)."}, "G3582": {"greek": "ξέστης", "translit": "xéstēs", "pronunciation": "xes'-tace", "derivation": "as if from (properly, to smooth;", "definition": "by implication, (of friction) to boil or heat); a vessel (as fashioned or for cooking) (or perhaps by corruption from the Latin sextarius, the sixth of a modius, i.e. about a pint), i.e. (specially), a measure for liquids or solids, (by analogy, a pitcher)", "kjv": "pot."}, "G3583": {"greek": "ξηραίνω", "translit": "xēraínō", "pronunciation": "xay-rah'-ee-no", "derivation": "from (G3584);", "definition": "to desiccate; by implication, to shrivel, to mature", "kjv": "dry up, pine away, be ripe, wither (away)."}, "G3584": {"greek": "ξηρός", "translit": "xērós", "pronunciation": "xay-ros'", "derivation": "from the base of (G3582) (through the idea of scorching);", "definition": "arid; by implication, shrunken, earth (as opposed to water)", "kjv": "dry land, withered."}, "G3585": {"greek": "ξύλινος", "translit": "xýlinos", "pronunciation": "xoo'-lin-os", "derivation": "from (G3586);", "definition": "wooden", "kjv": "of wood."}, "G3586": {"greek": "ξύλον", "translit": "xýlon", "pronunciation": "xoo'-lon", "derivation": "from another form of the base of (G3582);", "definition": "timber (as fuel or material); by implication, a stick, club or tree or other wooden article or substance", "kjv": "staff, stocks, tree, wood."}, "G3587": {"greek": "ξυράω", "translit": "xyráō", "pronunciation": "xoo-rah'-o", "derivation": "from a derivative of the same as (G3586) (meaning a razor);", "definition": "to shave or \"shear\" the hair", "kjv": "shave."}, "G3588": {"greek": "ὁ", "translit": "ho", "pronunciation": "ho", "derivation": "the definite article;", "definition": "the (sometimes to be supplied, at others omitted, in English idiom)", "kjv": "the, this, that, one, he, she, it, etc."}, "G3589": {"greek": "ὀγδοήκοντα", "translit": "ogdoḗkonta", "pronunciation": "og-do-ay'-kon-tah", "derivation": "from (G3590);", "definition": "ten times eight", "kjv": "fourscore."}, "G3590": {"greek": "ὄγδοος", "translit": "ógdoos", "pronunciation": "og'-do-os", "derivation": "from (G3638);", "definition": "the eighth", "kjv": "eighth."}, "G3591": {"greek": "ὄγκος", "translit": "ónkos", "pronunciation": "ong'-kos", "derivation": "probably from the same as (G43);", "definition": "a mass (as bending or bulging by its load), i.e. burden (hindrance)", "kjv": "weight."}, "G3592": {"greek": "ὅδε", "translit": "hóde", "pronunciation": "hod'-eh", "derivation": "from (G3588) and (G1161);", "definition": "the same, i.e. this or that one (plural these or those); often used as a personal pronoun", "kjv": "he, she, such, these, thus."}, "G3593": {"greek": "ὁδεύω", "translit": "hodeúō", "pronunciation": "hod-yoo'-o", "derivation": "from (G3598);", "definition": "to travel", "kjv": "journey."}, "G3594": {"greek": "ὁδηγέω", "translit": "hodēgéō", "pronunciation": "hod-ayg-eh'-o", "derivation": "from (G3595);", "definition": "to show the way (literally or figuratively (teach))", "kjv": "guide, lead."}, "G3595": {"greek": "ὁδηγός", "translit": "hodēgós", "pronunciation": "hod-ayg-os'", "derivation": "from (G3598) and (G2233);", "definition": "a conductor (literally or figuratively (teacher))", "kjv": "guide, leader."}, "G3596": {"greek": "ὁδοιπορέω", "translit": "hodoiporéō", "pronunciation": "hod-oy-por-eh'-o", "derivation": "from a compound of (G3598) and (G4198);", "definition": "to be a wayfarer, i.e. travel", "kjv": "go on a journey."}, "G3597": {"greek": "ὁδοιπορία", "translit": "hodoiporía", "pronunciation": "hod-oy-por-ee'-ah", "derivation": "from the same as (G3596);", "definition": "travel", "kjv": "journey(-ing)."}, "G3598": {"greek": "ὁδός", "translit": "hodós", "pronunciation": "hod-os'", "derivation": "apparently a primary word;", "definition": "a road; by implication, a progress (the route, act or distance); figuratively, a mode or means", "kjv": "journey, (high-)way."}, "G3599": {"greek": "ὀδούς", "translit": "odoús", "pronunciation": "od-ooce", "derivation": "perhaps from the base of (G2068);", "definition": "a \"tooth\"", "kjv": "tooth."}, "G3600": {"greek": "ὀδυνάω", "translit": "odynáō", "pronunciation": "od-oo-nah'-o", "derivation": "from (G3601);", "definition": "to grieve", "kjv": "sorrow, torment."}, "G3601": {"greek": "ὀδύνη", "translit": "odýnē", "pronunciation": "od-oo'-nay", "derivation": "from (G1416);", "definition": "grief (as dejecting)", "kjv": "sorrow."}, "G3602": {"greek": "ὀδυρμός", "translit": "odyrmós", "pronunciation": "od-oor-mos'", "derivation": "from a derivative of the base of (G1416);", "definition": "moaning, i.e. lamentation", "kjv": "mourning."}, "G3604": {"greek": "Ὀζίας", "translit": "Ozías", "pronunciation": "od-zee'-as", "derivation": "of Hebrew origin ((G5818));", "definition": "Ozias (i.e. Uzzijah), an Israelite", "kjv": "Ozias."}, "G3605": {"greek": "ὄζω", "translit": "ózō", "pronunciation": "od'-zo", "derivation": "a primary verb (in a strengthened form);", "definition": "to scent (usually an ill \"odor\")", "kjv": "stink."}, "G3606": {"greek": "ὅθεν", "translit": "hóthen", "pronunciation": "hoth'-en", "derivation": "from (G3739) with the directive enclitic of source;", "definition": "from which place or source or cause (adverb or conjunction)", "kjv": "from thence, (from) whence, where(-by, -fore, -upon)."}, "G3607": {"greek": "ὀθόνη", "translit": "othónē", "pronunciation": "oth-on'-ay", "derivation": "of uncertain affinity;", "definition": "a linen cloth, i.e. (especially) a sail", "kjv": "sheet."}, "G3608": {"greek": "ὀθόνιον", "translit": "othónion", "pronunciation": "oth-on'-ee-on", "derivation": "neuter of a presumed derivative of (G3607);", "definition": "a linen bandage", "kjv": "linen clothes."}, "G3609": {"greek": "οἰκεῖος", "translit": "oikeîos", "pronunciation": "oy-ki'-os", "derivation": "from (G3624);", "definition": "domestic, i.e. (as noun), a relative, adherent", "kjv": "(those) of the (his own) house(-hold)."}, "G3610": {"greek": "οἰκέτης", "translit": "oikétēs", "pronunciation": "oy-ket'-ace", "derivation": "from (G3611);", "definition": "a fellow resident, i.e. menial domestic", "kjv": "(household) servant."}, "G3611": {"greek": "οἰκέω", "translit": "oikéō", "pronunciation": "oy-keh'-o", "derivation": "from (G3624);", "definition": "to occupy a house, i.e. reside (figuratively, inhabit, remain, inhere); by implication, to cohabit", "kjv": "dwell."}, "G3612": {"greek": "οἴκημα", "translit": "oíkēma", "pronunciation": "oy'-kay-mah", "derivation": "from (G3611);", "definition": "a tenement, i.e. (specially), a jail", "kjv": "prison."}, "G3613": {"greek": "οἰκητήριον", "translit": "oikētḗrion", "pronunciation": "oy-kay-tay'-ree-on", "derivation": "neuter of a presumed derivative of (G3611) (equivalent to (G3612));", "definition": "a residence (literally or figuratively)", "kjv": "habitation, house."}, "G3614": {"greek": "οἰκία", "translit": "oikía", "pronunciation": "oy-kee'-ah", "derivation": "from (G3624);", "definition": "properly, residence (abstractly), but usually (concretely) an abode (literally or figuratively); by implication, a family (especially domestics)", "kjv": "home, house(-hold)."}, "G3615": {"greek": "οἰκιακός", "translit": "oikiakós", "pronunciation": "oy-kee-ak-os'", "derivation": "from (G3614);", "definition": "familiar, i.e. (as noun) relatives", "kjv": "they (them) of (his own) household."}, "G3616": {"greek": "οἰκοδεσποτέω", "translit": "oikodespotéō", "pronunciation": "oy-kod-es-pot-eh'-o", "derivation": "from (G3617);", "definition": "to be the head of (i.e. rule) a family", "kjv": "guide the house."}, "G3617": {"greek": "οἰκοδεσπότης", "translit": "oikodespótēs", "pronunciation": "oy-kod-es-pot'-ace", "derivation": "from (G3624) and (G1203);", "definition": "the head of a family", "kjv": "goodman (of the house), householder, master of the house."}, "G3618": {"greek": "οἰκοδομέω", "translit": "oikodoméō", "pronunciation": "oy-kod-om-eh'-o", "derivation": "from the same as (G3619);", "definition": "to be a house-builder, i.e. construct or (figuratively) confirm", "kjv": "(be in) build(-er, -ing, up), edify, embolden."}, "G3619": {"greek": "οἰκοδομή", "translit": "oikodomḗ", "pronunciation": "oy-kod-om-ay'", "derivation": "feminine (abstract) of a compound of (G3624) and the base of (G1430);", "definition": "architecture, i.e. (concretely) a structure; figuratively, confirmation", "kjv": "building, edify(-ication, -ing)."}, "G3621": {"greek": "οἰκονομέω", "translit": "oikonoméō", "pronunciation": "oy-kon-om-eh'-o", "derivation": "from (G3623);", "definition": "to manage (a house, i.e. an estate)", "kjv": "be steward."}, "G3622": {"greek": "οἰκονομία", "translit": "oikonomía", "pronunciation": "oy-kon-om-ee'-ah", "derivation": "from (G3623);", "definition": "administration (of a household or estate); specially, a (religious) \"economy\"", "kjv": "dispensation, stewardship."}, "G3623": {"greek": "οἰκονόμος", "translit": "oikonómos", "pronunciation": "oy-kon-om'-os", "derivation": "from (G3624) and the base of (G3551);", "definition": "a house-distributor (i.e. manager), or overseer, i.e. an employee in that capacity; by extension, a fiscal agent (treasurer); figuratively, a preacher (of the Gospel)", "kjv": "chamberlain, governor, steward."}, "G3624": {"greek": "οἶκος", "translit": "oîkos", "pronunciation": "oy'-kos", "derivation": "of uncertain affinity;", "definition": "a dwelling (more or less extensive, literal or figurative); by implication, a family (more or less related, literally or figuratively)", "kjv": "home, house(-hold), temple."}, "G3625": {"greek": "οἰκουμένη", "translit": "oikouménē", "pronunciation": "oy-kou-men'-ay", "derivation": "feminine participle present passive of (G3611) (as noun, by implication, of (G1093));", "definition": "land, i.e. the (terrene part of the) globe; specially, the Roman empire", "kjv": "earth, world."}, "G3626": {"greek": "οἰκουρός", "translit": "oikourós", "pronunciation": "oy-koo-ros'", "derivation": "from (G3624) and (a guard; be \"ware\");", "definition": "a stayer at home, i.e. domestically inclined (a \"good housekeeper\")", "kjv": "keeper at home."}, "G3627": {"greek": "οἰκτείρω", "translit": "oikteírō", "pronunciation": "oyk-ti'-ro", "derivation": "from (pity);", "definition": "to exercise pity", "kjv": "have compassion on."}, "G3628": {"greek": "οἰκτιρμός", "translit": "oiktirmós", "pronunciation": "oyk-tir-mos'", "derivation": "from (G3627);", "definition": "pity", "kjv": "mercy."}, "G3629": {"greek": "οἰκτίρμων", "translit": "oiktírmōn", "pronunciation": "oyk-tir'-mone", "derivation": "from (G3627);", "definition": "compassionate", "kjv": "merciful, of tender mercy."}, "G3630": {"greek": "οἰνοπότης", "translit": "oinopótēs", "pronunciation": "oy-nop-ot'-ace", "derivation": "from (G3631) and a derivative of the alternate of (G4095);", "definition": "a tippler", "kjv": "winebibber."}, "G3631": {"greek": "οἶνος", "translit": "oînos", "pronunciation": "oy'-nos", "derivation": "a primary word (or perhaps of Hebrew origin ((G3196)));", "definition": "\"wine\" (literally or figuratively)", "kjv": "wine."}, "G3632": {"greek": "οἰνοφλυγία", "translit": "oinophlygía", "pronunciation": "oy-nof-loog-ee'-ah", "derivation": "from (G3631) and a form of the base of (G5397);", "definition": "an overflow (or surplus) of wine, i.e. vinolency (drunkenness)", "kjv": "excess of wine."}, "G3633": {"greek": "οἴομαι", "translit": "oíomai", "pronunciation": "oy'-om-ahee", "derivation": "middle voice apparently from (G3634);", "definition": "to make like (oneself), i.e. imagine (be of the opinion)", "kjv": "suppose, think."}, "G3634": {"greek": "οἷος", "translit": "hoîos", "pronunciation": "hoy'-os", "derivation": "probably akin to (G3588), (G3739), and (G3745);", "definition": "such or what sort of (as a correlation or exclamation); especially the neuter (adverbially) with negative, not so", "kjv": "so (as), such as, what (manner of), which."}, "G3635": {"greek": "ὀκνέω", "translit": "oknéō", "pronunciation": "ok-neh'-o", "derivation": "from (hesitation);", "definition": "to be slow (figuratively, loath)", "kjv": "delay."}, "G3636": {"greek": "ὀκνηρός", "translit": "oknērós", "pronunciation": "ok-nay-ros'", "derivation": "from (G3635);", "definition": "tardy, i.e. indolent; (figuratively) irksome", "kjv": "grievous, slothful."}, "G3637": {"greek": "ὀκταήμερος", "translit": "oktaḗmeros", "pronunciation": "ok-tah-ay'-mer-os", "derivation": "from (G3638) and (G2250);", "definition": "an eight-day old person or act", "kjv": "the eighth day."}, "G3638": {"greek": "ὀκτώ", "translit": "oktṓ", "pronunciation": "ok-to'", "derivation": "a primary numeral;", "definition": "\"eight\"", "kjv": "eight."}, "G3639": {"greek": "ὄλεθρος", "translit": "ólethros", "pronunciation": "ol'-eth-ros", "derivation": "from a primary (to destroy; a prolonged form);", "definition": "ruin, i.e. death, punishment", "kjv": "destruction."}, "G3640": {"greek": "ὀλιγόπιστος", "translit": "oligópistos", "pronunciation": "ol-ig-op'-is-tos", "derivation": "from (G3641) and (G4102);", "definition": "incredulous, i.e. lacking confidence (in Christ)", "kjv": "of little faith."}, "G3641": {"greek": "ὀλίγος", "translit": "olígos", "pronunciation": "ol-ee'-gos", "derivation": "of uncertain affinity;", "definition": "puny (in extent, degree, number, duration or value); especially neuter (adverbially) somewhat", "kjv": "+ almost, brief(-ly), few, (a) little, + long, a season, short, small, a while."}, "G3642": {"greek": "ὀλιγόψυχος", "translit": "oligópsychos", "pronunciation": "ol-ig-op'-soo-khos", "derivation": "from (G3641) and (G6590);", "definition": "little-spirited, i.e. faint-hearted", "kjv": "feebleminded."}, "G3643": {"greek": "ὀλιγωρέω", "translit": "oligōréō", "pronunciation": "ol-ig-o-reh'-o", "derivation": "from a compound of (G3641) and (\"care\");", "definition": "to have little regard for, i.e. to disesteem", "kjv": "despise."}, "G3644": {"greek": "ὀλοθρευτής", "translit": "olothreutḗs", "pronunciation": "ol-oth-ryoo-tace'", "derivation": "from (G3645);", "definition": "a ruiner, i.e. (specially), a venomous serpent", "kjv": "destroyer."}, "G3645": {"greek": "ὀλοθρεύω", "translit": "olothreúō", "pronunciation": "ol-oth-ryoo'-o", "derivation": "from (G3639);", "definition": "to spoil, i.e. slay", "kjv": "destroy."}, "G3646": {"greek": "ὁλοκαύτωμα", "translit": "holokaútōma", "pronunciation": "hol-ok-ow'-to-mah", "derivation": "from a derivative of a compound of (G3650) and a derivative of (G2545);", "definition": "a wholly-consumed sacrifice (\"holocaust\")", "kjv": "(whole) burnt offering."}, "G3647": {"greek": "ὁλοκληρία", "translit": "holoklēría", "pronunciation": "hol-ok-lay-ree'-ah", "derivation": "from (G3648);", "definition": "integrity, i.e. physical wholeness", "kjv": "perfect soundness."}, "G3648": {"greek": "ὁλόκληρος", "translit": "holóklēros", "pronunciation": "hol'-ok'-lay-ros", "derivation": "from (G3650) and (G2819);", "definition": "complete in every part, i.e. perfectly sound (in body)", "kjv": "entire, whole."}, "G3649": {"greek": "ὀλολύζω", "translit": "ololýzō", "pronunciation": "ol-ol-odd'-zo", "derivation": "a reduplicated primary verb;", "definition": "to \"howl\" or \"halloo\", i.e. shriek", "kjv": "howl."}, "G3650": {"greek": "ὅλος", "translit": "hólos", "pronunciation": "hol'-os", "derivation": "a primary word;", "definition": "\"whole\" or \"all\", i.e. complete (in extent, amount, time or degree), especially (neuter) as noun or adverb", "kjv": "all, altogether, every whit, + throughout, whole."}, "G3651": {"greek": "ὁλοτελής", "translit": "holotelḗs", "pronunciation": "hol-ot-el-ace'", "derivation": "from (G3650) and (G5056);", "definition": "complete to the end, i.e. absolutely perfect", "kjv": "wholly."}, "G3652": {"greek": "Ὀλυμπᾶς", "translit": "Olympâs", "pronunciation": "ol-oom-pas'", "derivation": "probably a contraction from (Olympian-bestowed, i.e. heaven-descended);", "definition": "Olympas, a Christian", "kjv": "Olympas."}, "G3653": {"greek": "ὄλυνθος", "translit": "ólynthos", "pronunciation": "ol'-oon-thos", "derivation": "of uncertain derivation;", "definition": "an unripe (because out of season) fig", "kjv": "untimely fig."}, "G3654": {"greek": "ὅλως", "translit": "hólōs", "pronunciation": "hol'-oce", "derivation": "adverb from (G3650);", "definition": "completely, i.e. altogether; (by analogy), everywhere; (negatively) not by any means", "kjv": "at all, commonly, utterly."}, "G3655": {"greek": "ὄμβρος", "translit": "ómbros", "pronunciation": "om'-bros", "derivation": "of uncertain affinity;", "definition": "a thunder storm", "kjv": "shower."}, "G3656": {"greek": "ὁμιλέω", "translit": "homiléō", "pronunciation": "hom-il-eh'-o", "derivation": "from (G3658);", "definition": "to be in company with, i.e. (by implication) to converse", "kjv": "commune, talk."}, "G3657": {"greek": "ὁμιλία", "translit": "homilía", "pronunciation": "hom-il-ee'-ah", "derivation": "from (G3658);", "definition": "companionship (\"homily\"), i.e. (by implication) intercourse", "kjv": "communication."}, "G3659": {"greek": "ὄμμα", "translit": "ómma", "pronunciation": "om'-mah", "derivation": "from (G3700);", "definition": "a sight, i.e. (by implication) the eye", "kjv": "eye."}, "G3660": {"greek": "ὀμνύω", "translit": "omnýō", "pronunciation": "om-noo'-o", "derivation": "a prolonged form of a primary, but obsolete , for which another prolonged form is used in certain tenses;", "definition": "to swear, i.e. take (or declare on) oath", "kjv": "swear."}, "G3661": {"greek": "ὁμοθυμαδόν", "translit": "homothymadón", "pronunciation": "hom-oth-oo-mad-on'", "derivation": "adverb from a compound of the base of (G3674) and (G2372);", "definition": "unanimously", "kjv": "with one accord (mind)."}, "G3662": {"greek": "ὁμοιάζω", "translit": "homoiázō", "pronunciation": "hom-oy-ad'-zo", "derivation": "from (G3664);", "definition": "to resemble", "kjv": "agree."}, "G3663": {"greek": "ὁμοιοπαθής", "translit": "homoiopathḗs", "pronunciation": "hom-oy-op-ath-ace'", "derivation": "from (G3664) and the alternate of (G3958);", "definition": "similarly affected", "kjv": "of (subject to) like passions."}, "G3664": {"greek": "ὅμοιος", "translit": "hómoios", "pronunciation": "hom'-oy-os", "derivation": "from the base of (G3674);", "definition": "similar (in appearance or character)", "kjv": "like, + manner."}, "G3665": {"greek": "ὁμοιότης", "translit": "homoiótēs", "pronunciation": "hom-oy-ot'-ace", "derivation": "from (G3664);", "definition": "resemblance", "kjv": "like as, similitude."}, "G3666": {"greek": "ὁμοιόω", "translit": "homoióō", "pronunciation": "hom-oy-o'-o", "derivation": "from (G3664);", "definition": "to assimilate, i.e. compare; passively, to become similar", "kjv": "be (make) like, (in the) liken(-ess), resemble."}, "G3667": {"greek": "ὁμοίωμα", "translit": "homoíōma", "pronunciation": "hom-oy'-o-mah", "derivation": "from (G3666);", "definition": "a form; abstractly, resemblance", "kjv": "made like to, likeness, shape, similitude."}, "G3668": {"greek": "ὁμοίως", "translit": "homoíōs", "pronunciation": "hom-oy'-oce", "derivation": "adverb from (G3664);", "definition": "similarly", "kjv": "likewise, so."}, "G3669": {"greek": "ὁμοίωσις", "translit": "homoíōsis", "pronunciation": "hom-oy'-o-sis", "derivation": "from (G3666);", "definition": "assimilation, i.e. resemblance", "kjv": "similitude."}, "G3670": {"greek": "ὁμολογέω", "translit": "homologéō", "pronunciation": "hom-ol-og-eh'-o", "derivation": "from a compound of the base of (G3674) and (G3056);", "definition": "to assent, i.e. covenant, acknowledge", "kjv": "con- (pro-)fess, confession is made, give thanks, promise."}, "G3671": {"greek": "ὁμολογία", "translit": "homología", "pronunciation": "hom-ol-og-ee'-ah", "derivation": "from the same as (G3670);", "definition": "acknowledgment", "kjv": "con- (pro-)fession, professed."}, "G3672": {"greek": "ὁμολογουμένως", "translit": "homologouménōs", "pronunciation": "hom-ol-og-ow-men'-oce", "derivation": "adverb of present passive participle of (G3670);", "definition": "confessedly", "kjv": "without controversy."}, "G3673": {"greek": "ὁμότεχνος", "translit": "homótechnos", "pronunciation": "hom-ot'-ekh-nos", "derivation": "from the base of (G3674) and (G5078);", "definition": "a fellow-artificer", "kjv": "of the same craft."}, "G3674": {"greek": "ὁμοῦ", "translit": "homoû", "pronunciation": "hom-oo'", "derivation": "genitive case of (the same;", "definition": "akin to (G260)) as adverb; at the same place or time", "kjv": "together."}, "G3675": {"greek": "ὁμόφρων", "translit": "homóphrōn", "pronunciation": "hom-of'-rone", "derivation": "from the base of (G3674) and (G5424);", "definition": "like-minded, i.e. harmonious", "kjv": "of one mind."}, "G3676": {"greek": "ὅμως", "translit": "hómōs", "pronunciation": "hom'-oce", "derivation": "adverb from the base of (G3674);", "definition": "at the same time, i.e. (conjunctionally) notwithstanding, yet still", "kjv": "and even, nevertheless, though but."}, "G3677": {"greek": "ὄναρ", "translit": "ónar", "pronunciation": "on'-ar", "derivation": "of uncertain derivation;", "definition": "a dream", "kjv": "dream."}, "G3678": {"greek": "ὀνάριον", "translit": "onárion", "pronunciation": "on-ar'-ee-on", "derivation": "neuter of a presumed derivative of (G3688);", "definition": "a little ass", "kjv": "young ass."}, "G3679": {"greek": "ὀνειδίζω", "translit": "oneidízō", "pronunciation": "on-i-did'-zo", "derivation": "from (G3681);", "definition": "to defame, i.e. rail at, chide, taunt", "kjv": "cast in teeth, (suffer) reproach, revile, upbraid."}, "G3680": {"greek": "ὀνειδισμός", "translit": "oneidismós", "pronunciation": "on-i-dis-mos'", "derivation": "from (G3679);", "definition": "contumely", "kjv": "reproach."}, "G3681": {"greek": "ὄνειδος", "translit": "óneidos", "pronunciation": "on'-i-dos", "derivation": "probably akin to the base of (G3686);", "definition": "notoriety, i.e. a taunt (disgrace)", "kjv": "reproach."}, "G3682": {"greek": "Ὀνήσιμος", "translit": "Onḗsimos", "pronunciation": "on-ay'-sim-os", "derivation": "from (G3685);", "definition": "profitable; Onesimus, a Christian", "kjv": "Onesimus."}, "G3683": {"greek": "Ὀνησίφορος", "translit": "Onēsíphoros", "pronunciation": "on-ay-sif'-or-os", "derivation": "from a derivative of (G3685) and (G5411);", "definition": "profit-bearer; Onesiphorus, a Christian", "kjv": "Onespiphorus."}, "G3684": {"greek": "ὀνικός", "translit": "onikós", "pronunciation": "on-ik-os'", "derivation": "from (G3688);", "definition": "belonging to a ass, i.e. large (so as to be turned by a ass)", "kjv": "millstone."}, "G3685": {"greek": "ὀνίνημι", "translit": "onínēmi", "pronunciation": "on-in'-ay-mee", "derivation": "a prolonged form of an apparently primary verb (, to slur);", "definition": "for which another prolonged form () is used as an alternate in some tenses (unless indeed it be identical with the base of (G3686) through the idea of notoriety); to gratify, i.e. (middle voice) to derive pleasure or advantage from", "kjv": "have joy."}, "G3686": {"greek": "ὄνομα", "translit": "ónoma", "pronunciation": "on'-om-ah", "derivation": "from a presumed derivative of the base of (G1097) (compare (G3685));", "definition": "a \"name\" (literally or figuratively) (authority, character)", "kjv": "called, (+ sur-)name(-d)."}, "G3687": {"greek": "ὀνομάζω", "translit": "onomázō", "pronunciation": "on-om-ad'-zo", "derivation": "from (G3686);", "definition": "to name, i.e. assign an appellation; by extension, to utter, mention, profess", "kjv": "call, name."}, "G3688": {"greek": "ὄνος", "translit": "ónos", "pronunciation": "on'-os", "derivation": "apparently a primary word;", "definition": "a donkey", "kjv": "an ass."}, "G3689": {"greek": "ὄντως", "translit": "óntōs", "pronunciation": "on'-toce", "derivation": "adverb of the oblique cases of (G5607);", "definition": "really", "kjv": "certainly, clean, indeed, of a truth, verily."}, "G3690": {"greek": "ὄξος", "translit": "óxos", "pronunciation": "oz-os", "derivation": "from (G3691);", "definition": "vinegar, i.e. sour wine", "kjv": "vinegar."}, "G3691": {"greek": "ὀξύς", "translit": "oxýs", "pronunciation": "oz-oos'", "derivation": "probably akin to the base of (G188) (\"acid\");", "definition": "keen; by analogy, rapid", "kjv": "sharp, swift."}, "G3692": {"greek": "ὀπή", "translit": "opḗ", "pronunciation": "op-ay'", "derivation": "probably from (G3700);", "definition": "a hole (as if for light), i.e. cavern; by analogy, a spring (of water)", "kjv": "cave, place."}, "G3693": {"greek": "ὄπισθεν", "translit": "ópisthen", "pronunciation": "op'-is-then", "derivation": "from (regard;", "definition": "from (G3700)) with enclitic of source; from the rear (as a secure aspect), i.e. at the back (adverb and preposition of place or time)", "kjv": "after, backside, behind."}, "G3694": {"greek": "ὀπίσω", "translit": "opísō", "pronunciation": "op-is'-o", "derivation": "from the same as (G3693) with enclitic of direction;", "definition": "to the back, i.e. aback (as adverb or preposition of time or place; or as noun)", "kjv": "after, back(-ward), (+ get) behind, + follow."}, "G3695": {"greek": "ὁπλίζω", "translit": "hoplízō", "pronunciation": "hop-lid'-zo", "derivation": "from (G3696);", "definition": "to equip (with weapons (middle voice and figuratively))", "kjv": "arm self."}, "G3696": {"greek": "ὅπλον", "translit": "hóplon", "pronunciation": "hop'-lon", "derivation": "probably from a primary (to be busy about);", "definition": "an implement or utensil or tool (literally or figuratively, especially, offensive for war)", "kjv": "armour, instrument, weapon."}, "G3697": {"greek": "ὁποῖος", "translit": "hopoîos", "pronunciation": "hop-oy'-os", "derivation": "from (G3739) and (G4169);", "definition": "of what kind that, i.e. how (as) great (excellent) (specially, as an indefinite correlative to the definite antecedent (G5108) of quality)", "kjv": "what manner (sort) of, such as whatsoever."}, "G3698": {"greek": "ὁπότε", "translit": "hopóte", "pronunciation": "hop-ot'-eh", "derivation": "from (G3739) and (G4218);", "definition": "what(-ever) then, i.e. (of time) as soon as", "kjv": "when."}, "G3699": {"greek": "ὅπου", "translit": "hópou", "pronunciation": "hop'-oo", "derivation": "from (G3739) and (G4225);", "definition": "what(-ever) where, i.e. at whichever spot", "kjv": "in what place, where(-as, -soever), whither (+ soever)."}, "G3700": {"greek": "ὀπτάνομαι", "translit": "optánomai", "pronunciation": "op-tan'-om-ahee", "derivation": "a (middle voice) prolonged form of the primary (middle voice) ; which is used for it in certain tenses; and both as alternate of (G3708);", "definition": "to gaze (i.e. with wide-open eyes, as at something remarkable; and thus differing from (G991), which denotes simply voluntary observation; and from (G1492), which expresses merely mechanical, passive or casual vision; while (G2300), and still more emphatically its intensive (G2334), signifies an earnest but more continued inspection; and (G4648) a watching from a distance)", "kjv": "appear, look, see, shew self."}, "G3701": {"greek": "ὀπτασία", "translit": "optasía", "pronunciation": "op-tas-ee'-ah", "derivation": "from a presumed derivative of (G3700);", "definition": "visuality, i.e. (concretely) an apparition", "kjv": "vision."}, "G3702": {"greek": "ὀπτός", "translit": "optós", "pronunciation": "op-tos'", "derivation": "from an obsolete verb akin to (to \"steep\");", "definition": "cooked, i.e. roasted", "kjv": "broiled."}, "G3703": {"greek": "ὀπώρα", "translit": "opṓra", "pronunciation": "op-o'-rah", "derivation": "apparently from the base of (G3796) and (G5610);", "definition": "properly, even-tide of the (summer) season (dog-days), i.e. (by implication) ripe fruit", "kjv": "fruit."}, "G3704": {"greek": "ὅπως", "translit": "hópōs", "pronunciation": "hop'-oce", "derivation": "from (G3739) and (G4459);", "definition": "what(-ever) how, i.e. in the manner that (as adverb or conjunction of coincidence, intentional or actual)", "kjv": "because, how, (so) that, to, when."}, "G3705": {"greek": "ὅραμα", "translit": "hórama", "pronunciation": "hor'-am-ah", "derivation": "from (G3708);", "definition": "something gazed at, i.e. a spectacle (especially supernatural)", "kjv": "sight, vision."}, "G3706": {"greek": "ὅρασις", "translit": "hórasis", "pronunciation": "hor'-as-is", "derivation": "from (G3708);", "definition": "the act of gazing, i.e. (externally) an aspect or (internally) an inspired appearance", "kjv": "sight, vision."}, "G3707": {"greek": "ὁρατός", "translit": "horatós", "pronunciation": "hor-at-os'", "derivation": "from (G3708);", "definition": "gazed at, i.e. (by implication) capable of being seen", "kjv": "visible."}, "G3708": {"greek": "ὁράω", "translit": "horáō", "pronunciation": "hor-ah'-o", "derivation": "properly, to stare at (compare (G3700)), i.e. (by implication) to discern clearly (physically or mentally);", "definition": "by extension, to attend to; by Hebraism, to experience; passively, to appear", "kjv": "behold, perceive, see, take heed."}, "G3709": {"greek": "ὀργή", "translit": "orgḗ", "pronunciation": "or-gay'", "derivation": "from (G3713);", "definition": "properly, desire (as a reaching forth or excitement of the mind), i.e. (by analogy), violent passion (ire, or (justifiable) abhorrence); by implication punishment", "kjv": "anger, indignation, vengeance, wrath."}, "G3710": {"greek": "ὀργίζω", "translit": "orgízō", "pronunciation": "or-gid'-zo", "derivation": "from (G3709);", "definition": "to provoke or enrage, i.e. (passively) become exasperated", "kjv": "be angry (wroth)."}, "G3711": {"greek": "ὀργίλος", "translit": "orgílos", "pronunciation": "org-ee'-los", "derivation": "from (G3709);", "definition": "irascible", "kjv": "soon angry."}, "G3712": {"greek": "ὀργυιά", "translit": "orguiá", "pronunciation": "org-wee-ah'", "derivation": "from (G3713);", "definition": "a stretch of the arms, i.e. a fathom", "kjv": "fathom."}, "G3713": {"greek": "ὀρέγομαι", "translit": "orégomai", "pronunciation": "or-eg'-om-ahee", "derivation": "middle voice of apparently a prolonged form of an obsolete primary (compare (G3735));", "definition": "to stretch oneself, i.e. reach out after (long for)", "kjv": "covet after, desire."}, "G3714": {"greek": "ὀρεινός", "translit": "oreinós", "pronunciation": "or-i-nos", "derivation": "from (G3735);", "definition": "mountainous, i.e. (feminine by implication, of (G5561)) the Highlands (of Judæa)", "kjv": "hill country."}, "G3715": {"greek": "ὄρεξις", "translit": "órexis", "pronunciation": "or'-ex-is", "derivation": "from (G3713);", "definition": "excitement of the mind, i.e. longing after", "kjv": "lust."}, "G3716": {"greek": "ὀρθοποδέω", "translit": "orthopodéō", "pronunciation": "or-thop-od-eh'-o", "derivation": "from a compound of (G3717) and (G4228);", "definition": "to be straight-footed, i.e. (figuratively) to go directly forward", "kjv": "walk uprightly."}, "G3717": {"greek": "ὀρθός", "translit": "orthós", "pronunciation": "or-thos'", "derivation": "probably from the base of (G3735);", "definition": "right (as rising), i.e. (perpendicularly) erect (figuratively, honest), or (horizontally) level or direct", "kjv": "straight, upright."}, "G3718": {"greek": "ὀρθοτομέω", "translit": "orthotoméō", "pronunciation": "or-thot-om-eh'-o", "derivation": "from a compound of (G3717) and the base of (G5114), to make a straight cut, i.e. (figuratively) to dissect (expound) correctly (the divine message)", "definition": "", "kjv": "rightly divide."}, "G3719": {"greek": "ὀρθρίζω", "translit": "orthrízō", "pronunciation": "or-thrid'-zo", "derivation": "from (G3722);", "definition": "to use the dawn, i.e. (by implication) to repair betimes", "kjv": "come early in the morning."}, "G3720": {"greek": "ὀρθρινός", "translit": "orthrinós", "pronunciation": "or-thrin-os'", "derivation": "from (G3722);", "definition": "relating to the dawn, i.e. matutinal (as an epithet of Venus, especially brilliant in the early day)", "kjv": "morning."}, "G3722": {"greek": "ὄρθρος", "translit": "órthros", "pronunciation": "or'-thros", "derivation": "from the same as (G3735);", "definition": "dawn (as sun-rise, rising of light); by extension, morn", "kjv": "early in the morning."}, "G3723": {"greek": "ὀρθῶς", "translit": "orthōs", "pronunciation": "or-thoce'", "derivation": "adverb from (G3717);", "definition": "in a straight manner, i.e. (figuratively) correctly (also morally)", "kjv": "plain, right(-ly)."}, "G3724": {"greek": "ὁρίζω", "translit": "horízō", "pronunciation": "hor-id'-zo", "derivation": "from (G3725);", "definition": "to mark out or bound (\"horizon\"), i.e. (figuratively) to appoint, decree, specify", "kjv": "declare, determine, limit, ordain."}, "G3725": {"greek": "ὅριον", "translit": "hórion", "pronunciation": "hor'-ee-on", "derivation": "neuter of a derivative of an apparently primary (a bound or limit);", "definition": "a boundary-line, i.e. (by implication) a frontier (region)", "kjv": "border, coast."}, "G3726": {"greek": "ὁρκίζω", "translit": "horkízō", "pronunciation": "hor-kid'-zo", "derivation": "from (G3727);", "definition": "to put on oath, i.e. make swear; by analogy, to solemnly enjoin", "kjv": "adjure, charge."}, "G3727": {"greek": "ὅρκος", "translit": "hórkos", "pronunciation": "hor'-kos", "derivation": "from (a fence; perhaps akin to (G3725));", "definition": "a limit, i.e. (sacred) restraint (specially, an oath)", "kjv": "oath."}, "G3728": {"greek": "ὁρκωμοσία", "translit": "horkōmosía", "pronunciation": "hor-ko-mos-ee'ah", "derivation": "from a compound of (G3727) and a derivative of (G3660);", "definition": "asseveration on oath", "kjv": "oath."}, "G3729": {"greek": "ὁρμάω", "translit": "hormáō", "pronunciation": "hor-mah'-o", "derivation": "from (G3730);", "definition": "to start, spur or urge on, i.e. (reflexively) to dash or plunge", "kjv": "run (violently), rush."}, "G3730": {"greek": "ὁρμή", "translit": "hormḗ", "pronunciation": "hor-may'", "derivation": "of uncertain affinity;", "definition": "a violent impulse, i.e. onset", "kjv": "assault."}, "G3731": {"greek": "ὅρμημα", "translit": "hórmēma", "pronunciation": "hor'-may-mah", "derivation": "from (G3730);", "definition": "an attack, i.e. (abstractly) precipitancy", "kjv": "violence."}, "G3732": {"greek": "ὄρνεον", "translit": "órneon", "pronunciation": "or'-neh-on", "derivation": "neuter of a presumed derivative of (G3733);", "definition": "a birdling", "kjv": "bird, fowl."}, "G3733": {"greek": "ὄρνις", "translit": "órnis", "pronunciation": "or'-nis", "derivation": "probably from a prolonged form of the base of (G3735);", "definition": "a bird (as rising in the air), i.e. (specially), a hen (or female domestic fowl)", "kjv": "hen."}, "G3734": {"greek": "ὁροθεσία", "translit": "horothesía", "pronunciation": "hor-oth-es-ee'-ah", "derivation": "from a compound of the base of (G3725) and a derivative of (G5087);", "definition": "a limit-placing, i.e. (concretely) boundary-line", "kjv": "bound."}, "G3735": {"greek": "ὄρος", "translit": "óros", "pronunciation": "or'-os", "derivation": "probably from an obsolete (to rise or \"rear\"; perhaps akin to (G142); compare (G3733));", "definition": "a mountain (as lifting itself above the plain)", "kjv": "hill, mount(-ain)."}, "G3736": {"greek": "ὀρύσσω", "translit": "orýssō", "pronunciation": "or-oos'-so", "derivation": "apparently a primary verb;", "definition": "to \"burrow\" in the ground, i.e. dig", "kjv": "dig."}, "G3737": {"greek": "ὀρφανός", "translit": "orphanós", "pronunciation": "or-fan-os'", "derivation": "of uncertain affinity;", "definition": "bereaved (\"orphan\"), i.e. parentless", "kjv": "comfortless, fatherless."}, "G3738": {"greek": "ὀρχέομαι", "translit": "orchéomai", "pronunciation": "or-kheh'-om-ahee", "derivation": "middle voice from (a row or ring);", "definition": "to dance (from the ranklike or regular motion)", "kjv": "dance."}, "G3739": {"greek": "ὅς", "translit": "hós", "pronunciation": "hos", "derivation": "probably a primary word (or perhaps a form of the article (G3588));", "definition": "the relatively (sometimes demonstrative) pronoun, who, which, what, that", "kjv": "one, (an-, the) other, some, that, what, which, who(-m, -se), etc."}, "G3740": {"greek": "ὁσάκις", "translit": "hosákis", "pronunciation": "hos-ak'-is", "derivation": "multiple adverb from (G3739);", "definition": "how (i.e. with (G302), so) many times as", "kjv": "as oft(-en) as."}, "G3741": {"greek": "ὅσιος", "translit": "hósios", "pronunciation": "hos'-ee-os", "derivation": "of uncertain affinity;", "definition": "properly, right (by intrinsic or divine character; thus distinguished from 1342, which refers rather to human statutes and relations; from (G2413), which denotes formal consecration; and from (G40), which relates to purity from defilement), i.e. hallowed (pious, sacred, sure)", "kjv": "holy, mercy, shalt be."}, "G3742": {"greek": "ὁσιότης", "translit": "hosiótēs", "pronunciation": "hos-ee-ot'-ace", "derivation": "from (G3741);", "definition": "piety", "kjv": "holiness."}, "G3743": {"greek": "ὁσίως", "translit": "hosíōs", "pronunciation": "hos-ee-oce'", "derivation": "adverb from (G3741);", "definition": "piously", "kjv": "holily."}, "G3744": {"greek": "ὀσμή", "translit": "osmḗ", "pronunciation": "os-may'", "derivation": "from (G3605);", "definition": "fragrance (literally or figuratively)", "kjv": "odour, savour."}, "G3745": {"greek": "ὅσος", "translit": "hósos", "pronunciation": "hos'-os", "derivation": "by reduplication from (G3739);", "definition": "as (much, great, long, etc.) as", "kjv": "all (that), as (long, many, much) (as), how great (many, much), (in-)asmuch as, so many as, that (ever), the more, those things, what (great, -soever), wheresoever, wherewithsoever, which, X while, who(-soever)."}, "G3747": {"greek": "ὀστέον", "translit": "ostéon", "pronunciation": "os-teh'-on", "derivation": "of uncertain affinity;", "definition": "a bone", "kjv": "bone."}, "G3748": {"greek": "ὅστις", "translit": "hóstis", "pronunciation": "hos'-tis", "derivation": "from (G3739) and (G5100);", "definition": "which some, i.e. any that; also (definite) which same", "kjv": "X and (they), (such) as, (they) that, in that they, what(-soever), whereas ye, (they) which, who(-soever)."}, "G3749": {"greek": "ὀστράκινος", "translit": "ostrákinos", "pronunciation": "os-tra'-kin-os", "derivation": "from (\"oyster\") (a tile, i.e. terra cotta);", "definition": "earthen-ware, i.e. clayey; by implication, frail", "kjv": "of earth, earthen."}, "G3750": {"greek": "ὄσφρησις", "translit": "ósphrēsis", "pronunciation": "os'-fray-sis", "derivation": "from a derivative of (G3605);", "definition": "smell (the sense)", "kjv": "smelling."}, "G3751": {"greek": "ὀσφῦς", "translit": "osphŷs", "pronunciation": "os-foos'", "derivation": "of uncertain affinity;", "definition": "the loin (externally), i.e. the hip; internally (by extension) procreative power", "kjv": "loin."}, "G3752": {"greek": "ὅταν", "translit": "hótan", "pronunciation": "hot'-an", "derivation": "from (G3753) and (G302);", "definition": "whenever (implying hypothesis or more or less uncertainty); also causatively (conjunctionally) inasmuch as", "kjv": "as long (soon) as, that, + till, when(-soever), while."}, "G3753": {"greek": "ὅτε", "translit": "hóte", "pronunciation": "hot'-eh", "derivation": "from (G3739) and (G5037);", "definition": "at which (thing) too, i.e. when", "kjv": "after (that), as soon as, that, when, while."}, "G3754": {"greek": "ὅτι", "translit": "hóti", "pronunciation": "hot'-ee", "derivation": "neuter of (G3748) as conjunction;", "definition": "demonstrative, that (sometimes redundant); causative, because", "kjv": "as concerning that, as though, because (that), for (that), how (that), (in) that, though, why."}, "G3755": {"greek": "ὅτου", "translit": "hótou", "pronunciation": "hot'-oo", "derivation": "for the genitive case of (G3748) (as adverb);", "definition": "during which same time, i.e. whilst", "kjv": "whiles."}, "G3756": {"greek": "οὐ", "translit": "ou", "pronunciation": "oo", "derivation": "a primary word;", "definition": "the absolute negative (compare (G3361)) adverb; no or not", "kjv": "+ long, nay, neither, never, no (X man), none, (can-)not, + nothing, + special, un(-worthy), when, + without, + yet but."}, "G3757": {"greek": "οὗ", "translit": "hoû", "pronunciation": "hoo", "derivation": "genitive case of (G3739) as adverb;", "definition": "at which place, i.e. where", "kjv": "where(-in), whither(-soever)."}, "G3758": {"greek": "οὐά", "translit": "ouá", "pronunciation": "oo-ah'", "derivation": "a primary exclamation of surprise;", "definition": "\"ah\"", "kjv": "ah."}, "G3759": {"greek": "οὐαί", "translit": "ouaí", "pronunciation": "oo-ah'-ee", "derivation": "a primary exclamation of grief;", "definition": "\"woe\"", "kjv": "alas, woe."}, "G3760": {"greek": "οὐδαμῶς", "translit": "oudamōs", "pronunciation": "oo-dam-oce'", "derivation": "adverb from (the feminine) of (G3762);", "definition": "by no means", "kjv": "not."}, "G3761": {"greek": "οὐδέ", "translit": "oudé", "pronunciation": "oo-deh'", "derivation": "from (G3756) and (G1161);", "definition": "not however, i.e. neither, nor, not even", "kjv": "neither (indeed), never, no (more, nor, not), nor (yet), (also, even, then) not (even, so much as), + nothing, so much as."}, "G3762": {"greek": "οὐδείς", "translit": "oudeís", "pronunciation": "oo-dice'", "derivation": "from (G3761) and (G1520);", "definition": "not even one (man, woman or thing), i.e. none, nobody, nothing", "kjv": "any (man), aught, man, neither any (thing), never (man), no (man), none (+ of these things), not (any, at all, -thing), nought."}, "G3763": {"greek": "οὐδέποτε", "translit": "oudépote", "pronunciation": "oo-dep'-ot-eh", "derivation": "from (G3761) and (G4218);", "definition": "not even at any time, i.e. never at all", "kjv": "neither at any time, never, nothing at any time."}, "G3764": {"greek": "οὐδέπω", "translit": "oudépō", "pronunciation": "oo-dep'-o", "derivation": "from (G3761) and (G4452);", "definition": "not even yet", "kjv": "as yet not, never before (yet), (not) yet."}, "G3765": {"greek": "οὐκέτι", "translit": "oukéti", "pronunciation": "ook-et'-ee", "derivation": "from (G3756) and (G2089);", "definition": "not yet, no longer", "kjv": "after that (not), (not) any more, henceforth (hereafter) not, no longer (more), not as yet (now), now no more (not), yet (not)."}, "G3766": {"greek": "οὐκοῦν", "translit": "oukoûn", "pronunciation": "ook-oon'", "derivation": "from (G3756) and (G3767);", "definition": "is it not therefore that, i.e. (affirmatively) hence or so", "kjv": "then."}, "G3767": {"greek": "οὖν", "translit": "oûn", "pronunciation": "oon", "derivation": "apparently a primary word;", "definition": "(adverbially) certainly, or (conjunctionally) accordingly", "kjv": "and (so, truly), but, now (then), so (likewise then), then, therefore, verily, wherefore."}, "G3768": {"greek": "οὔπω", "translit": "oúpō", "pronunciation": "oo'-po", "derivation": "from (G3756) and (G4452);", "definition": "not yet", "kjv": "hitherto not, (no…) as yet, not yet."}, "G3769": {"greek": "οὐρά", "translit": "ourá", "pronunciation": "oo-rah'", "derivation": "apparently a primary word;", "definition": "a tail", "kjv": "tail."}, "G3770": {"greek": "οὐράνιος", "translit": "ouránios", "pronunciation": "oo-ran'-ee-os", "derivation": "from (G3772);", "definition": "celestial, i.e. belonging to or coming from the sky", "kjv": "heavenly."}, "G3771": {"greek": "οὐρανόθεν", "translit": "ouranóthen", "pronunciation": "oo-ran-oth'-en", "derivation": "from (G3772) and the enclitic of source;", "definition": "from the sky", "kjv": "from heaven."}, "G3772": {"greek": "οὐρανός", "translit": "ouranós", "pronunciation": "oo-ran-os'", "derivation": "perhaps from the same as (G3735) (through the idea of elevation);", "definition": "the sky; by extension, heaven (as the abode of God); by implication, happiness, power, eternity; specially, the Gospel (Christianity)", "kjv": "air, heaven(-ly), sky."}, "G3773": {"greek": "Οὐρβανός", "translit": "Ourbanós", "pronunciation": "oor-ban-os'", "derivation": "of Latin origin;", "definition": "Urbanus (of the city, \"urbane\"), a Christian", "kjv": "Urbanus."}, "G3774": {"greek": "Οὐρίας", "translit": "Ourías", "pronunciation": "oo-ree'-as", "derivation": "of Hebrew origin ((G223));", "definition": "Urias (i.e. Urijah), a Hittite", "kjv": "Urias."}, "G3775": {"greek": "οὖς", "translit": "oûs", "pronunciation": "ooce", "derivation": "apparently a primary word;", "definition": "the ear (physically or mentally)", "kjv": "ear."}, "G3776": {"greek": "οὐσία", "translit": "ousía", "pronunciation": "oo-see'-ah", "derivation": "from the feminine of (G5607);", "definition": "substance, i.e. property (possessions)", "kjv": "goods, substance."}, "G3777": {"greek": "οὔτε", "translit": "oúte", "pronunciation": "oo'-teh", "derivation": "from (G3756) and (G5037);", "definition": "not too, i.e. neither or nor; by analogy, not even", "kjv": "neither, none, nor (yet), (no, yet) not, nothing."}, "G3778": {"greek": "οὗτος", "translit": "hoûtos", "pronunciation": "hoo'-tos", "derivation": "from the article (G3588) and (G846);", "definition": "the he (she or it), i.e. this or that (often with article repeated)", "kjv": "he (it was that), hereof, it, she, such as, the same, these, they, this (man, same, woman), which, who."}, "G3779": {"greek": "οὕτω", "translit": "hoútō", "pronunciation": "hoo'-to", "derivation": "adverb from (G3778);", "definition": "in this way (referring to what precedes or follows)", "kjv": "after that, after (in) this manner, as, even (so), for all that, like(-wise), no more, on this fashion(-wise), so (in like manner), thus, what."}, "G3780": {"greek": "οὐχί", "translit": "ouchí", "pronunciation": "oo-khee'", "derivation": "intensive of (G3756);", "definition": "not indeed", "kjv": "nay, not."}, "G3781": {"greek": "ὀφειλέτης", "translit": "opheilétēs", "pronunciation": "of-i-let'-ace", "derivation": "from (G3784);", "definition": "an ower, i.e. person indebted; figuratively, a delinquent; morally, a transgressor (against God)", "kjv": "debtor, which owed, sinner."}, "G3782": {"greek": "ὀφειλή", "translit": "opheilḗ", "pronunciation": "of-i-lay'", "derivation": "from (G3784);", "definition": "indebtedness, i.e. (concretely) a sum owed; figuratively, obligation, i.e. (conjugal) duty", "kjv": "debt, due."}, "G3783": {"greek": "ὀφείλημα", "translit": "opheílēma", "pronunciation": "of-i'-lay-mah", "derivation": "from (the alternate of) (G3784);", "definition": "something owed, i.e. (figuratively) a due; morally, a fault", "kjv": "debt."}, "G3784": {"greek": "ὀφείλω", "translit": "opheílō", "pronunciation": "of-i'-lo", "derivation": "probably from the base of (G3786) (through the idea of accruing);", "definition": "to owe (pecuniarily); figuratively, to be under obligation (ought, must, should); morally, to fail in duty", "kjv": "behove, be bound, (be) debt(-or), (be) due(-ty), be guilty (indebted), (must) need(-s), ought, owe, should."}, "G3785": {"greek": "ὄφελον", "translit": "óphelon", "pronunciation": "of'-el-on", "derivation": "first person singular of a past tense of (G3784);", "definition": "I ought (wish), i.e. (interjection) oh that!", "kjv": "would (to God)."}, "G3786": {"greek": "ὄφελος", "translit": "óphelos", "pronunciation": "of'-el-os", "derivation": "from (to heap up, i.e. accumulate or benefit);", "definition": "gain", "kjv": "advantageth, profit."}, "G3787": {"greek": "ὀφθαλμοδουλεία", "translit": "ophthalmodouleía", "pronunciation": "of-thal-mod-oo-li'-ah", "derivation": "from (G3788) and (G1397);", "definition": "sight-labor, i.e. that needs watching (remissness)", "kjv": "eye-service."}, "G3788": {"greek": "ὀφθαλμός", "translit": "ophthalmós", "pronunciation": "of-thal-mos'", "derivation": "from (G3700);", "definition": "the eye (literally or figuratively); by implication, vision; figuratively, envy (from the jealous side-glance)", "kjv": "eye, sight."}, "G3789": {"greek": "ὄφις", "translit": "óphis", "pronunciation": "of'-is", "derivation": "probably from (G3700) (through the idea of sharpness of vision);", "definition": "a snake, figuratively, (as a type of sly cunning) an artful malicious person, especially Satan", "kjv": "serpent."}, "G3790": {"greek": "ὀφρῦς", "translit": "ophrŷs", "pronunciation": "of-roos'", "derivation": "perhaps from (G3700) (through the idea of the shading or proximity to the organ of vision);", "definition": "the eye-\"brow\" or forehead, i.e. (figuratively) the brink of a precipice", "kjv": "brow."}, "G3791": {"greek": "ὀχλέω", "translit": "ochléō", "pronunciation": "okh-leh'-o", "derivation": "from (G3793);", "definition": "to mob, i.e. (by implication) to harass", "kjv": "vex."}, "G3792": {"greek": "ὀχλοποιέω", "translit": "ochlopoiéō", "pronunciation": "okh-lop-oy-eh'-o", "derivation": "from (G3793) and (G4160);", "definition": "to make a crowd, i.e. raise a public disturbance", "kjv": "gather a company."}, "G3793": {"greek": "ὄχλος", "translit": "óchlos", "pronunciation": "okh'los", "derivation": "from a derivative of (G2192) (meaning a vehicle);", "definition": "a throng (as borne along); by implication, the rabble; by extension, a class of people; figuratively, a riot", "kjv": "company, multitude, number (of people), people, press."}, "G3794": {"greek": "ὀχύρωμα", "translit": "ochýrōma", "pronunciation": "okh-oo'-ro-mah", "derivation": "from a remote derivative of (G2192) (meaning to fortify, through the idea of holding safely);", "definition": "a castle (figuratively, argument)", "kjv": "stronghold."}, "G3795": {"greek": "ὀψάριον", "translit": "opsárion", "pronunciation": "op-sar'-ee-on", "derivation": "neuter of a presumed derivative of the base of (G3702);", "definition": "a relish to other food (as if cooked sauce), i.e. (specially), fish (presumably salted and dried as a condiment)", "kjv": "fish."}, "G3796": {"greek": "ὀψέ", "translit": "opsé", "pronunciation": "op-seh'", "derivation": "from the same as (G3694) (through the idea of backwardness);", "definition": "(adverbially) late in the day; by extension, after the close of the day", "kjv": "(at) even, in the end."}, "G3797": {"greek": "ὄψιμος", "translit": "ópsimos", "pronunciation": "op'-sim-os", "derivation": "from (G3796);", "definition": "later, i.e. vernal (showering)", "kjv": "latter."}, "G3798": {"greek": "ὄψιος", "translit": "ópsios", "pronunciation": "op'-see-os", "derivation": "from (G3796);", "definition": "late; feminine (as noun) afternoon (early eve) or nightfall (later eve)", "kjv": "even(-ing, (-tide))."}, "G3799": {"greek": "ὄψις", "translit": "ópsis", "pronunciation": "op'-sis", "derivation": "from (G3700);", "definition": "properly, sight (the act), i.e. (by implication) the visage, an external show", "kjv": "appearance, countenance, face."}, "G3800": {"greek": "ὀψώνιον", "translit": "opsṓnion", "pronunciation": "op-so'-nee-on", "derivation": "neuter of a presumed derivative of the same as (G3795);", "definition": "rations for a soldier, i.e. (by extension) his stipend or pay", "kjv": "wages."}, "G3802": {"greek": "παγιδεύω", "translit": "pagideúō", "pronunciation": "pag-id-yoo'-o", "derivation": "from (G3803);", "definition": "to ensnare (figuratively)", "kjv": "entangle."}, "G3803": {"greek": "παγίς", "translit": "pagís", "pronunciation": "pag-ece'", "derivation": "from (G4078);", "definition": "a trap (as fastened by a noose or notch); figuratively, a trick or statagem (temptation)", "kjv": "snare."}, "G3804": {"greek": "πάθημα", "translit": "páthēma", "pronunciation": "path'-ay-mah", "derivation": "from a presumed derivative of (G3806);", "definition": "something undergone, i.e. hardship or pain; subjectively, an emotion or influence", "kjv": "affection, affliction, motion, suffering."}, "G3805": {"greek": "παθητός", "translit": "pathētós", "pronunciation": "path-ay-tos'", "derivation": "from the same as (G3804);", "definition": "liable (i.e. doomed) to experience pain", "kjv": "suffer."}, "G3806": {"greek": "πάθος", "translit": "páthos", "pronunciation": "path'-os", "derivation": "from the alternate of (G3958);", "definition": "properly, suffering (\"pathos\"), i.e. (subjectively) a passion (especially concupiscence)", "kjv": "(inordinate) affection, lust."}, "G3807": {"greek": "παιδαγωγός", "translit": "paidagōgós", "pronunciation": "pahee-dag-o-gos'", "derivation": "from (G3816) and a reduplicated form of (G71);", "definition": "a boy-leader, i.e. a servant whose office it was to take the children to school; (by implication, (figuratively) a tutor (\"pædagogue\"))", "kjv": "instructor, schoolmaster."}, "G3808": {"greek": "παιδάριον", "translit": "paidárion", "pronunciation": "pahee-dar'-ee-on", "derivation": "neuter of a presumed derivative of (G3816);", "definition": "a little boy", "kjv": "child, lad."}, "G3809": {"greek": "παιδεία", "translit": "paideía", "pronunciation": "pahee-di'-ah", "derivation": "from (G3811);", "definition": "tutorage, i.e. education or training; by implication, disciplinary correction", "kjv": "chastening, chastisement, instruction, nurture."}, "G3810": {"greek": "παιδευτής", "translit": "paideutḗs", "pronunciation": "pahee-dyoo-tace'", "derivation": "from (G3811);", "definition": "a trainer, i.e. teacher or (by implication) discipliner", "kjv": "which corrected, instructor."}, "G3811": {"greek": "παιδεύω", "translit": "paideúō", "pronunciation": "pahee-dyoo'-o", "derivation": "from (G3816);", "definition": "to train up a child, i.e. educate, or (by implication), discipline (by punishment)", "kjv": "chasten(-ise), instruct, learn, teach."}, "G3812": {"greek": "παιδιόθεν", "translit": "paidióthen", "pronunciation": "pahee-dee-oth'-en", "derivation": "adverb (of source) from (G3813);", "definition": "from infancy", "kjv": "of a child."}, "G3813": {"greek": "παιδίον", "translit": "paidíon", "pronunciation": "pahee-dee'-on", "derivation": "neuter diminutive of (G3816);", "definition": "a childling (of either sex), i.e. (properly), an infant, or (by extension) a half-grown boy or girl; figuratively, an immature Christian", "kjv": "(little, young) child, damsel."}, "G3814": {"greek": "παιδίσκη", "translit": "paidískē", "pronunciation": "pahee-dis'-kay", "derivation": "feminine diminutive of (G3816);", "definition": "a girl, i.e. (specially), a female slave or servant", "kjv": "bondmaid(-woman), damsel, maid(-en)."}, "G3815": {"greek": "παίζω", "translit": "paízō", "pronunciation": "paheed'-zo", "derivation": "from (G3816);", "definition": "to sport (as a boy)", "kjv": "play."}, "G3816": {"greek": "παῖς", "translit": "paîs", "pronunciation": "paheece", "derivation": "perhaps from (G3817);", "definition": "a boy (as often beaten with impunity), or (by analogy), a girl, and (genitive case) a child; specially, a slave or servant (especially a minister to a king; and by eminence to God)", "kjv": "child, maid(-en), (man) servant, son, young man."}, "G3817": {"greek": "παίω", "translit": "paíō", "pronunciation": "pah'-yo", "derivation": "a primary verb;", "definition": "to hit (as if by a single blow and less violently than (G5180)); specially, to sting (as a scorpion)", "kjv": "smite, strike."}, "G3819": {"greek": "πάλαι", "translit": "pálai", "pronunciation": "pal'-ahee", "derivation": "probably another form for (G3825) (through the idea of retrocession);", "definition": "(adverbially) formerly, or (by relatively) sometime since; (elliptically as adjective) ancient", "kjv": "any while, a great while ago, (of) old, in time past."}, "G3820": {"greek": "παλαιός", "translit": "palaiós", "pronunciation": "pal-ah-yos'", "derivation": "from (G3819);", "definition": "antique, i.e. not recent, worn out", "kjv": "old."}, "G3821": {"greek": "παλαιότης", "translit": "palaiótēs", "pronunciation": "pal-ah-yot'-ace", "derivation": "from (G3820);", "definition": "antiquatedness", "kjv": "oldness."}, "G3822": {"greek": "παλαιόω", "translit": "palaióō", "pronunciation": "pal-ah-yo'-o", "derivation": "from (G3820);", "definition": "to make (passively, become) worn out, or declare obsolete", "kjv": "decay, make (wax) old."}, "G3823": {"greek": "πάλη", "translit": "pálē", "pronunciation": "pal'-ay", "derivation": "from (to vibrate; another form for (G906));", "definition": "wrestling", "kjv": "+ wrestle."}, "G3824": {"greek": "παλιγγενεσία", "translit": "palingenesía", "pronunciation": "pal-ing-ghen-es-ee'-ah", "derivation": "from (G3825) and (G1078);", "definition": "(spiritual) rebirth (the state or the act), i.e. (figuratively) spiritual renovation; specially, Messianic restoration", "kjv": "regeneration."}, "G3825": {"greek": "πάλιν", "translit": "pálin", "pronunciation": "pal'-in", "derivation": "probably from the same as (G3823) (through the idea of oscillatory repetition);", "definition": "(adverbially) anew, i.e. (of place) back, (of time) once more, or (conjunctionally) furthermore or on the other hand", "kjv": "again."}, "G3826": {"greek": "παμπληθεί", "translit": "pamplētheí", "pronunciation": "pam-play-thi'", "derivation": "dative case (adverb) of a compound of (G3956) and (G4128);", "definition": "in full multitude, i.e. concertedly or simultaneously", "kjv": "all at once."}, "G3828": {"greek": "Παμφυλία", "translit": "Pamphylía", "pronunciation": "pam-fool-ee'-ah", "derivation": "from a compound of (G3956) and (G4443);", "definition": "every-tribal, i.e. heterogeneous ((G5561) being implied); Pamphylia, a region of Asia Minor", "kjv": "Pamphylia."}, "G3829": {"greek": "πανδοχεῖον", "translit": "pandocheîon", "pronunciation": "pan-dokk-i'-on", "derivation": "neuter of a presumed compound of (G3956) and a derivative of (G1209);", "definition": "all-receptive, i.e. a public lodging-place (caravanserai or khan)", "kjv": "inn."}, "G3830": {"greek": "πανδοχεύς", "translit": "pandocheús", "pronunciation": "pan-dokh-yoos'", "derivation": "from the same as (G3829);", "definition": "an innkeeper (warden of a caravanserai)", "kjv": "host."}, "G3831": {"greek": "πανήγυρις", "translit": "panḗgyris", "pronunciation": "pan-ay'-goo-ris", "derivation": "from (G3956) and a derivative of (G58);", "definition": "a mass-meeting, i.e. (figuratively) universal companionship", "kjv": "general assembly."}, "G3832": {"greek": "πανοικί", "translit": "panoikí", "pronunciation": "pan-oy-kee'", "derivation": "adverb from (G3956) and (G3624);", "definition": "with the whole family", "kjv": "with all his house."}, "G3833": {"greek": "πανοπλία", "translit": "panoplía", "pronunciation": "pan-op-lee'-ah", "derivation": "from a compound of (G3956) and (G3696);", "definition": "full armor (\"panoply\")", "kjv": "all (whole) armour."}, "G3834": {"greek": "πανουργία", "translit": "panourgía", "pronunciation": "pan-oorg-ee'-ah", "derivation": "from (G3835);", "definition": "adroitness, i.e. (in a bad sense) trickery or sophistry", "kjv": "(cunning) craftiness, subtilty."}, "G3835": {"greek": "πανοῦργος", "translit": "panoûrgos", "pronunciation": "pan-oor'-gos", "derivation": "from (G3956) and (G2041);", "definition": "all-working, i.e. adroit (shrewd)", "kjv": "crafty."}, "G3837": {"greek": "πανταχοῦ", "translit": "pantachoû", "pronunciation": "pan-takh-oo'", "derivation": "genitive case (as adverb of place) of a presumed derivative of (G3956);", "definition": "universally", "kjv": "in all places, everywhere."}, "G3838": {"greek": "παντελής", "translit": "pantelḗs", "pronunciation": "pan-tel-ace'", "derivation": "from (G3956) and (G5056);", "definition": "full-ended, i.e. entire (neuter as noun, completion)", "kjv": "+ in (no) wise, uttermost."}, "G3839": {"greek": "πάντη", "translit": "pántē", "pronunciation": "pan'-tay", "derivation": "adverb (of manner) from (G3956);", "definition": "wholly", "kjv": "always."}, "G3840": {"greek": "πάντοθεν", "translit": "pántothen", "pronunciation": "pan-toth'-en", "derivation": "adverb (of source) from (G3956);", "definition": "from (i.e. on) all sides", "kjv": "on every side, round about."}, "G3841": {"greek": "παντοκράτωρ", "translit": "pantokrátōr", "pronunciation": "pan-tok-rat'-ore", "derivation": "from (G3956) and (G2904);", "definition": "the all-ruling, i.e. God (as absolute and universal sovereign)", "kjv": "Almighty, Omnipotent."}, "G3842": {"greek": "πάντοτε", "translit": "pántote", "pronunciation": "pan'-tot-eh", "derivation": "from (G3956) and (G3753);", "definition": "every when, i.e. at all times", "kjv": "alway(-s), ever(-more)."}, "G3843": {"greek": "πάντως", "translit": "pántōs", "pronunciation": "pan'-toce", "derivation": "adverb from (G3956);", "definition": "entirely; specially, at all events, (with negative, following) in no event", "kjv": "by all means, altogether, at all, needs, no doubt, in (no) wise, surely."}, "G3844": {"greek": "παρά", "translit": "pará", "pronunciation": "par-ah'", "derivation": "a primary preposition;", "definition": "properly, near; i.e. (with genitive case) from beside (literally or figuratively), (with dative case) at (or in) the vicinity of (objectively or subjectively), (with accusative case) to the proximity with (local (especially beyond or opposed to) or causal (on account of)", "kjv": "above, against, among, at, before, by, contrary to, X friend, from, + give (such things as they), + that (she) had, X his, in, more than, nigh unto, (out) of, past, save, side…by, in the sight of, than, (there-)fore, with."}, "G3845": {"greek": "παραβαίνω", "translit": "parabaínō", "pronunciation": "par-ab-ah'-ee-no", "derivation": "from (G3844) and the base of (G939);", "definition": "to go contrary to, i.e. violate a command", "kjv": "(by) transgress(-ion)."}, "G3846": {"greek": "παραβάλλω", "translit": "parabállō", "pronunciation": "par-ab-al'-lo", "derivation": "from (G3844) and (G906);", "definition": "to throw alongside, i.e. (reflexively) to reach a place, or (figuratively) to liken", "kjv": "arrive, compare."}, "G3847": {"greek": "παράβασις", "translit": "parábasis", "pronunciation": "par-ab'-as-is", "derivation": "from (G3845);", "definition": "violation", "kjv": "breaking, transgression."}, "G3848": {"greek": "παραβάτης", "translit": "parabátēs", "pronunciation": "par-ab-at'-ace", "derivation": "from (G3845);", "definition": "a violator", "kjv": "breaker, transgress(-or)."}, "G3849": {"greek": "παραβιάζομαι", "translit": "parabiázomai", "pronunciation": "par-ab-ee-ad'-zom-ahee", "derivation": "from (G3844) and the middle voice of (G971);", "definition": "to force contrary to (nature), i.e. compel (by entreaty)", "kjv": "constrain."}, "G3850": {"greek": "παραβολή", "translit": "parabolḗ", "pronunciation": "par-ab-ol-ay'", "derivation": "from (G3846);", "definition": "a similitude (\"parable\"), i.e. (symbolic) fictitious narrative (of common life conveying a moral), apothegm or adage", "kjv": "comparison, figure, parable, proverb."}, "G3851": {"greek": "παραβουλεύομαι", "translit": "parabouleúomai", "pronunciation": "par-ab-ool-yoo'-om-ahee", "derivation": "from (G3844) and the middle voice of (G1011);", "definition": "to misconsult, i.e. disregard", "kjv": "not (to) regard(-ing)."}, "G3852": {"greek": "παραγγελία", "translit": "parangelía", "pronunciation": "par-ang-gel-ee'-ah", "derivation": "from (G3853);", "definition": "a mandate", "kjv": "charge, command."}, "G3853": {"greek": "παραγγέλλω", "translit": "parangéllō", "pronunciation": "par-ang-gel'-lo", "derivation": "from (G3844) and the base of (G32);", "definition": "to transmit a message, i.e. (by implication) to enjoin", "kjv": "(give in) charge, (give) command(-ment), declare."}, "G3854": {"greek": "παραγίνομαι", "translit": "paragínomai", "pronunciation": "par-ag-in'-om-ahee", "derivation": "from (G3844) and (G1096);", "definition": "to become near, i.e. approach (have arrived); by implication, to appear publicly", "kjv": "come, go, be present."}, "G3855": {"greek": "παράγω", "translit": "parágō", "pronunciation": "par-ag'-o", "derivation": "from (G3844) and (G71);", "definition": "to lead near, i.e. (reflexively or intransitively) to go along or away", "kjv": "depart, pass (away, by, forth)."}, "G3856": {"greek": "παραδειγματίζω", "translit": "paradeigmatízō", "pronunciation": "par-ad-igue-mat-id'-zo", "derivation": "from (G3844) and (G1165);", "definition": "to show alongside (the public), i.e. expose to infamy", "kjv": "make a public example, put to an open shame."}, "G3857": {"greek": "παράδεισος", "translit": "parádeisos", "pronunciation": "par-ad'-i-sos", "derivation": "of Oriental origin (compare (G6508));", "definition": "a park, i.e. (specially), an Eden (place of future happiness, \"paradise\")", "kjv": "paradise."}, "G3858": {"greek": "παραδέχομαι", "translit": "paradéchomai", "pronunciation": "par-ad-ekh'-om-ahee", "derivation": "from (G3844) and (G1209);", "definition": "to accept near, i.e. admit or (by implication) delight in", "kjv": "receive."}, "G3859": {"greek": "παραδιατριβή", "translit": "paradiatribḗ", "pronunciation": "par-ad-ee-at-ree-bay'", "derivation": "from a compound of (G3844) and (G1304);", "definition": "misemployment, i.e. meddlesomeness", "kjv": "perverse disputing."}, "G3860": {"greek": "παραδίδωμι", "translit": "paradídōmi", "pronunciation": "par-ad-id'-o-mee", "derivation": "from (G3844) and (G1325);", "definition": "to surrender, i.e yield up, intrust, transmit", "kjv": "betray, bring forth, cast, commit, deliver (up), give (over, up), hazard, put in prison, recommend."}, "G3861": {"greek": "παράδοξος", "translit": "parádoxos", "pronunciation": "par-ad'-ox-os", "derivation": "from (G3844) and (G1391) (in the sense of seeming);", "definition": "contrary to expectation, i.e. extraordinary (\"paradox\")", "kjv": "strange."}, "G3862": {"greek": "παράδοσις", "translit": "parádosis", "pronunciation": "par-ad'-os-is", "derivation": "from (G3860);", "definition": "transmission, i.e. (concretely) a precept; specially, the Jewish traditionary law", "kjv": "ordinance, tradition."}, "G3863": {"greek": "παραζηλόω", "translit": "parazēlóō", "pronunciation": "par-ad-zay-lo'-o", "derivation": "from (G3844) and (G2206);", "definition": "to stimulate alongside, i.e. excite to rivalry", "kjv": "provoke to emulation (jealousy)."}, "G3864": {"greek": "παραθαλάσσιος", "translit": "parathalássios", "pronunciation": "par-ath-al-as'-see-os", "derivation": "from (G3844) and (G2281);", "definition": "along the sea, i.e. maritime (lacustrine)", "kjv": "upon the sea coast."}, "G3865": {"greek": "παραθεωρέω", "translit": "paratheōréō", "pronunciation": "par-ath-eh-o-reh'-o", "derivation": "from (G3844) and (G2334);", "definition": "to overlook or disregard", "kjv": "neglect."}, "G3866": {"greek": "παραθήκη", "translit": "parathḗkē", "pronunciation": "par-ath-ay'-kay", "derivation": "from (G3908);", "definition": "a deposit, i.e. (figuratively) trust", "kjv": "committed unto."}, "G3867": {"greek": "παραινέω", "translit": "parainéō", "pronunciation": "par-ahee-neh'-o", "derivation": "from (G3844) and (G134);", "definition": "to mispraise, i.e. recommend or advise (a different course)", "kjv": "admonish, exhort."}, "G3868": {"greek": "παραιτέομαι", "translit": "paraitéomai", "pronunciation": "par-ahee-teh'-om-ahee", "derivation": "from (G3844) and the middle voice of (G154);", "definition": "to beg off, i.e. deprecate, decline, shun", "kjv": "avoid, (make) excuse, intreat, refuse, reject."}, "G3869": {"greek": "παρακαθίζω", "translit": "parakathízō", "pronunciation": "par-ak-ath-id'-zo", "derivation": "from (G3844) and (G2523);", "definition": "to sit down near", "kjv": "sit."}, "G3870": {"greek": "παρακαλέω", "translit": "parakaléō", "pronunciation": "par-ak-al-eh'-o", "derivation": "from (G3844) and (G2564);", "definition": "to call near, i.e. invite, invoke (by imploration, hortation or consolation)", "kjv": "beseech, call for, (be of good) comfort, desire, (give) exhort(-ation), intreat, pray."}, "G3871": {"greek": "παρακαλύπτω", "translit": "parakalýptō", "pronunciation": "par-ak-al-oop'-to", "derivation": "from (G3844) and (G2572);", "definition": "to cover alongside, i.e. veil (figuratively)", "kjv": "hide."}, "G3873": {"greek": "παράκειμαι", "translit": "parákeimai", "pronunciation": "par-ak'-i-mahee", "derivation": "from (G3844) and (G2749);", "definition": "to lie near, i.e. be at hand (figuratively, be prompt or easy)", "kjv": "be present."}, "G3874": {"greek": "παράκλησις", "translit": "paráklēsis", "pronunciation": "par-ak'-lay-sis", "derivation": "from (G3870);", "definition": "imploration, hortation, solace", "kjv": "comfort, consolation, exhortation, intreaty."}, "G3875": {"greek": "παράκλητος", "translit": "paráklētos", "pronunciation": "par-ak'-lay-tos", "derivation": "", "definition": "an intercessor, consoler", "kjv": "advocate, comforter."}, "G3876": {"greek": "παρακοή", "translit": "parakoḗ", "pronunciation": "par-ak-o-ay'", "derivation": "from (G3878);", "definition": "inattention, i.e. (by implication) disobedience", "kjv": "disobedience."}, "G3877": {"greek": "παρακολουθέω", "translit": "parakolouthéō", "pronunciation": "par-ak-ol-oo-theh'-o", "derivation": "from (G3844) and (G190);", "definition": "to follow near, i.e. (figuratively) attend (as a result), trace out, conform to", "kjv": "attain, follow, fully know, have understanding."}, "G3878": {"greek": "παρακούω", "translit": "parakoúō", "pronunciation": "par-ak-oo'-o", "derivation": "from (G3844) and (G191);", "definition": "to mishear, i.e. (by implication) to disobey", "kjv": "neglect to hear."}, "G3879": {"greek": "παρακύπτω", "translit": "parakýptō", "pronunciation": "par-ak-oop'-to", "derivation": "from (G3844) and (G2955);", "definition": "to bend beside, i.e. lean over (so as to peer within)", "kjv": "look (into), stoop down."}, "G3880": {"greek": "παραλαμβάνω", "translit": "paralambánō", "pronunciation": "par-al-am-ban'-o", "derivation": "from (G3844) and (G2983);", "definition": "to receive near, i.e. associate with oneself (in any familiar or intimate act or relation); by analogy, to assume an office; figuratively, to learn", "kjv": "receive, take (unto, with)."}, "G3881": {"greek": "παραλέγομαι", "translit": "paralégomai", "pronunciation": "par-al-eg'-om-ahee", "derivation": "from (G3844) and the middle voice of (G3004) (in its original sense);", "definition": "(specially), to lay one's course near, i.e. sail past", "kjv": "pass, sail by."}, "G3882": {"greek": "παράλιος", "translit": "parálios", "pronunciation": "par-al'-ee-os", "derivation": "from (G3844) and (G251);", "definition": "beside the salt (sea), i.e. maritime", "kjv": "sea coast."}, "G3883": {"greek": "παραλλαγή", "translit": "parallagḗ", "pronunciation": "par-al-lag-ay'", "derivation": "from a compound of (G3844) and (G236);", "definition": "transmutation (of phase or orbit), i.e. (figuratively) fickleness", "kjv": "variableness."}, "G3884": {"greek": "παραλογίζομαι", "translit": "paralogízomai", "pronunciation": "par-al-og-id'-zom-ahee", "derivation": "from (G3844) and (G3049);", "definition": "to misreckon, i.e. delude", "kjv": "beguile, deceive."}, "G3885": {"greek": "παραλυτικός", "translit": "paralytikós", "pronunciation": "par-al-oo-tee-kos'", "derivation": "from a derivative of (G3886);", "definition": "as if dissolved, i.e. \"paralytic\"", "kjv": "that had (sick of) the palsy."}, "G3886": {"greek": "παραλύω", "translit": "paralýō", "pronunciation": "par-al-oo'-o", "derivation": "from (G3844) and (G3089);", "definition": "to loosen beside, i.e. relax (perfect passive participle, paralyzed or enfeebled)", "kjv": "feeble, sick of the (taken with) palsy."}, "G3887": {"greek": "παραμένω", "translit": "paraménō", "pronunciation": "par-am-en'-o", "derivation": "from (G3844) and (G3306);", "definition": "to stay near, i.e. remain (literally, tarry; or figuratively, be permanent, persevere)", "kjv": "abide, continue."}, "G3888": {"greek": "παραμυθέομαι", "translit": "paramythéomai", "pronunciation": "par-am-oo-theh'-om-ahee", "derivation": "from (G3844) and the middle voice of a derivative of (G3454);", "definition": "to relate near, i.e. (by implication) encourage, console", "kjv": "comfort."}, "G3889": {"greek": "παραμυθία", "translit": "paramythía", "pronunciation": "par-am-oo-thee'-ah", "derivation": "from (G3888);", "definition": "consolation (properly, abstract)", "kjv": "comfort."}, "G3890": {"greek": "παραμύθιον", "translit": "paramýthion", "pronunciation": "par-am-oo'-thee-on", "derivation": "neuter of (G3889);", "definition": "consolation (properly, concretely)", "kjv": "comfort."}, "G3891": {"greek": "παρανομέω", "translit": "paranoméō", "pronunciation": "par-an-om-eh'-o", "derivation": "from a compound of (G3844) and (G3551);", "definition": "to be opposed to law, i.e. to transgress", "kjv": "contrary to law."}, "G3892": {"greek": "παρανομία", "translit": "paranomía", "pronunciation": "par-an-om-ee'-ah", "derivation": "from the same as (G3891);", "definition": "transgression", "kjv": "iniquity."}, "G3893": {"greek": "παραπικραίνω", "translit": "parapikraínō", "pronunciation": "par-ap-ik-rah'-ee-no", "derivation": "from (G3844) and (G4087);", "definition": "to embitter alongside, i.e. (figuratively) to exasperate", "kjv": "provoke."}, "G3894": {"greek": "παραπικρασμός", "translit": "parapikrasmós", "pronunciation": "par-ap-ik-ras-mos'", "derivation": "from (G3893);", "definition": "irritation", "kjv": "provocation."}, "G3895": {"greek": "παραπίπτω", "translit": "parapíptō", "pronunciation": "par-ap-ip'-to", "derivation": "from (G3844) and (G4098);", "definition": "to fall aside, i.e. (figuratively) to apostatize", "kjv": "fall away."}, "G3896": {"greek": "παραπλέω", "translit": "parapléō", "pronunciation": "par-ap-leh'-o", "derivation": "from (G3844) and (G4126);", "definition": "to sail near", "kjv": "sail by."}, "G3897": {"greek": "παραπλήσιον", "translit": "paraplḗsion", "pronunciation": "par-ap-lay'-see-on", "derivation": "neuter of a compound of (G3844) and the base of (G4139) (as adverb);", "definition": "close by, i.e. (figuratively) almost", "kjv": "nigh unto."}, "G3898": {"greek": "παραπλησίως", "translit": "paraplēsíōs", "pronunciation": "par-ap-lay-see'-oce", "derivation": "adverb from the same as (G3897);", "definition": "in a manner near by, i.e. (figuratively) similarly", "kjv": "likewise."}, "G3899": {"greek": "παραπορεύομαι", "translit": "paraporeúomai", "pronunciation": "par-ap-or-yoo'-om-ahee", "derivation": "from (G3844) and (G4198);", "definition": "to travel near", "kjv": "go, pass (by)."}, "G3900": {"greek": "παράπτωμα", "translit": "paráptōma", "pronunciation": "par-ap'-to-mah", "derivation": "from (G3895);", "definition": "a side-slip (lapse or deviation), i.e. (unintentional) error or (wilful) transgression", "kjv": "fall, fault, offence, sin, trespass."}, "G3901": {"greek": "παραῤῥυέω", "translit": "pararrhyéō", "pronunciation": "par-ar-hroo-eh'-o", "derivation": "from (G3844) and the alternate of (G4482);", "definition": "to flow by, i.e. (figuratively) carelessly pass (miss)", "kjv": "let slip."}, "G3902": {"greek": "παράσημος", "translit": "parásēmos", "pronunciation": "par-as'-ay-mos", "derivation": "from (G3844) and the base of (G4591);", "definition": "side-marked, i.e. labelled (with a badge (figure-head) of a ship)", "kjv": "sign."}, "G3903": {"greek": "παρασκευάζω", "translit": "paraskeuázō", "pronunciation": "par-ask-yoo-ad'-zo", "derivation": "from (G3844) and a derivative of (G4632);", "definition": "to furnish aside, i.e. get ready", "kjv": "prepare self, be (make) ready."}, "G3904": {"greek": "παρασκευή", "translit": "paraskeuḗ", "pronunciation": "par-ask-yoo-ay'", "derivation": "as if from (G3903);", "definition": "readiness", "kjv": "preparation."}, "G3905": {"greek": "παρατείνω", "translit": "parateínō", "pronunciation": "par-at-i'-no", "derivation": "from (G3844) and teino (to stretch);", "definition": "to extend along, i.e. prolong (in point of time)", "kjv": "continue."}, "G3906": {"greek": "παρατηρέω", "translit": "paratēréō", "pronunciation": "par-at-ay-reh'-o", "derivation": "from (G3844) and (G5083);", "definition": "to inspect alongside, i.e. note insidiously or scrupulously", "kjv": "observe, watch."}, "G3907": {"greek": "παρατήρησις", "translit": "paratḗrēsis", "pronunciation": "par-at-ay'-ray-sis", "derivation": "from (G3906);", "definition": "inspection, i.e. ocular evidence", "kjv": "obervation."}, "G3908": {"greek": "παρατίθημι", "translit": "paratíthēmi", "pronunciation": "par-at-ith'-ay-mee", "derivation": "from (G3844) and (G5087);", "definition": "to place alongside, i.e. present (food, truth); by implication, to deposit (as a trust or for protection)", "kjv": "allege, commend, commit (the keeping of), put forth, set before."}, "G3909": {"greek": "παρατυγχάνω", "translit": "paratynchánō", "pronunciation": "par-at-oong-khan'-o", "derivation": "from (G3844) and (G5177);", "definition": "to chance near, i.e. fall in with", "kjv": "meet with."}, "G3910": {"greek": "παραυτίκα", "translit": "parautíka", "pronunciation": "par-ow-tee'-kah", "derivation": "from (G3844) and a derivative of (G846);", "definition": "at the very instant, i.e. momentary", "kjv": "but for a moment."}, "G3911": {"greek": "παραφέρω", "translit": "paraphérō", "pronunciation": "par-af-er'-o", "derivation": "from (G3844) and (G5342) (including its alternate forms);", "definition": "to bear along or aside, i.e. carry off (literally or figuratively); by implication, to avert", "kjv": "remove, take away."}, "G3912": {"greek": "παραφρονέω", "translit": "paraphronéō", "pronunciation": "par-af-ron-eh'-o", "derivation": "from (G3844) and (G5426);", "definition": "to misthink, i.e. be insane (silly)", "kjv": "as a fool."}, "G3913": {"greek": "παραφρονία", "translit": "paraphronía", "pronunciation": "par-af-ron-ee'-ah", "derivation": "from (G3912);", "definition": "insanity, i.e. foolhardiness", "kjv": "madness."}, "G3914": {"greek": "παραχειμάζω", "translit": "paracheimázō", "pronunciation": "par-akh-i-mad'-zo", "derivation": "from (G3844) and (G5492);", "definition": "to winter near, i.e. stay with over the rainy season", "kjv": "winter."}, "G3915": {"greek": "παραχειμασία", "translit": "paracheimasía", "pronunciation": "par-akh-i-mas-ee'-ah", "derivation": "from (G3914);", "definition": "a wintering over", "kjv": "winter in."}, "G3916": {"greek": "παραχρῆμα", "translit": "parachrēma", "pronunciation": "par-akh-ray'-mah", "derivation": "from (G3844) and (G5536) (in its original sense);", "definition": "at the thing itself, i.e. instantly", "kjv": "forthwith, immediately, presently, straightway, soon."}, "G3917": {"greek": "πάρδαλις", "translit": "párdalis", "pronunciation": "par'-dal-is", "derivation": "feminine of (a panther);", "definition": "a leopard", "kjv": "leopard."}, "G3918": {"greek": "πάρειμι", "translit": "páreimi", "pronunciation": "par'-i-mee", "derivation": "from (G3844) and (G1510) (including its various forms);", "definition": "to be near, i.e. at hand; neuter present participle (singular) time being, or (plural) property", "kjv": "come, X have, be here, + lack, (be here) present."}, "G3919": {"greek": "παρεισάγω", "translit": "pareiságō", "pronunciation": "par-ice-ag'-o", "derivation": "from (G3844) and (G1521);", "definition": "to lead in aside, i.e. introduce surreptitiously", "kjv": "privily bring in."}, "G3920": {"greek": "παρείσακτος", "translit": "pareísaktos", "pronunciation": "par-ice'-ak-tos", "derivation": "from (G3919);", "definition": "smuggled in", "kjv": "unawares brought in."}, "G3921": {"greek": "παρεισδύνω", "translit": "pareisdýnō", "pronunciation": "par-ice-doo'-no", "derivation": "from (G3844) and a compound of (G1519) and (G1416);", "definition": "to settle in alongside, i.e. lodge stealthily", "kjv": "creep in unawares."}, "G3922": {"greek": "παρεισέρχομαι", "translit": "pareisérchomai", "pronunciation": "par-ice-er'-khom-ahee", "derivation": "from (G3844) and (G1525);", "definition": "to come in alongside, i.e. supervene additionally or steathily", "kjv": "come in privily, enter."}, "G3923": {"greek": "παρεισφέρω", "translit": "pareisphérō", "pronunciation": "par-ice-fer'-o", "derivation": "from (G3844) and (G1533);", "definition": "to bear in alongside, i.e. introduce simultaneously", "kjv": "give."}, "G3924": {"greek": "παρεκτός", "translit": "parektós", "pronunciation": "par-ek-tos'", "derivation": "from (G3844) and (G1622);", "definition": "near outside, i.e. besides", "kjv": "except, saving, without."}, "G3925": {"greek": "παρεμβολή", "translit": "parembolḗ", "pronunciation": "par-em-bol-ay'", "derivation": "from a compound of (G3844) and (G1685);", "definition": "a throwing in beside (juxtaposition), i.e. (specially), battle-array, encampment or barracks (tower Antonia)", "kjv": "army, camp, castle."}, "G3926": {"greek": "παρενοχλέω", "translit": "parenochléō", "pronunciation": "par-en-okh-leh'-o", "derivation": "from (G3844) and (G1776);", "definition": "to harass further, i.e. annoy", "kjv": "trouble."}, "G3927": {"greek": "παρεπίδημος", "translit": "parepídēmos", "pronunciation": "par-ep-id'-ay-mos", "derivation": "from (G3844) and the base of (G1927);", "definition": "an alien alongside, i.e. a resident foreigner", "kjv": "pilgrim, stranger."}, "G3928": {"greek": "παρέρχομαι", "translit": "parérchomai", "pronunciation": "par-er'-khom-ahee", "derivation": "from (G3844) and (G2064);", "definition": "to come near or aside, i.e. to approach (arrive), go by (or away), (figuratively) perish or neglect, (causative) avert", "kjv": "come (forth), go, pass (away, by, over), past, transgress."}, "G3929": {"greek": "πάρεσις", "translit": "páresis", "pronunciation": "par'-es-is", "derivation": "from (G2935);", "definition": "praetermission, i.e. toleration", "kjv": "remission."}, "G3930": {"greek": "παρέχω", "translit": "paréchō", "pronunciation": "par-ekh'-o", "derivation": "from (G3844) and (G2192);", "definition": "to hold near, i.e. present, afford, exhibit, furnish occasion", "kjv": "bring, do, give, keep, minister, offer, shew, + trouble."}, "G3931": {"greek": "παρηγορία", "translit": "parēgoría", "pronunciation": "par-ay-gor-ee'-ah", "derivation": "from a compound of (G3844) and a derivative of (G58) (meaning to harangue an assembly);", "definition": "an address alongside, i.e. (specially), consolation", "kjv": "comfort."}, "G3932": {"greek": "παρθενία", "translit": "parthenía", "pronunciation": "par-then-ee'-ah", "derivation": "from (G3933);", "definition": "maidenhood", "kjv": "virginity."}, "G3933": {"greek": "παρθένος", "translit": "parthénos", "pronunciation": "par-then'-os", "derivation": "of unknown origin;", "definition": "a maiden; by implication, an unmarried daughter", "kjv": "virgin."}, "G3934": {"greek": "Πάρθος", "translit": "Párthos", "pronunciation": "par'-thos", "derivation": "probably of foreign origin;", "definition": "a Parthian, i.e. inhabitant of Parthia", "kjv": "Parthian."}, "G3935": {"greek": "παρίημι", "translit": "paríēmi", "pronunciation": "par-ee'-ay-mi", "derivation": "from (G3844) and hiemi (to send);", "definition": "to let by, i.e. relax", "kjv": "hang down."}, "G3936": {"greek": "παρίστημι", "translit": "parístēmi", "pronunciation": "par-is'-tay-mee", "derivation": "from (G3844) and (G2476);", "definition": "to stand beside, i.e. (transitively) to exhibit, proffer, (specially), recommend, (figuratively) substantiate; or (intransitively) to be at hand (or ready), aid", "kjv": "assist, bring before, command, commend, give presently, present, prove, provide, shew, stand (before, by, here, up, with), yield."}, "G3937": {"greek": "Παρμενᾶς", "translit": "Parmenâs", "pronunciation": "par-men-as'", "derivation": "probably by contraction for (a derivative of a compound of (G3844) and (G3306));", "definition": "constant; Parmenas, a Christian", "kjv": "Parmenas."}, "G3938": {"greek": "πάροδος", "translit": "párodos", "pronunciation": "par'-od-os", "derivation": "from (G3844) and (G3598);", "definition": "a by-road, i.e. (actively) a route", "kjv": "way."}, "G3939": {"greek": "παροικέω", "translit": "paroikéō", "pronunciation": "par-oy-keh'-o", "derivation": "from (G3844) and (G3611);", "definition": "to dwell near, i.e. reside as a foreigner", "kjv": "sojourn in, be a stranger."}, "G3940": {"greek": "παροικία", "translit": "paroikía", "pronunciation": "par-oy-kee'-ah", "derivation": "from (G3941);", "definition": "foreign residence", "kjv": "sojourning, X as strangers."}, "G3941": {"greek": "πάροικος", "translit": "pároikos", "pronunciation": "par'-oy-kos", "derivation": "from (G3844) and (G3624);", "definition": "having a home near, i.e. (as noun) a by-dweller (alien resident)", "kjv": "foreigner, sojourn, stranger."}, "G3942": {"greek": "παροιμία", "translit": "paroimía", "pronunciation": "par-oy-mee'-ah", "derivation": "from a compound of (G3844) and perhaps a derivative of (G3633);", "definition": "apparently a state alongside of supposition, i.e. (concretely) an adage; specially, an enigmatical or fictitious illustration", "kjv": "parable, proverb."}, "G3943": {"greek": "πάροινος", "translit": "pároinos", "pronunciation": "par'-oy-nos", "derivation": "from (G3844) and (G3631);", "definition": "staying near wine, i.e. tippling (a toper)", "kjv": "given to wine."}, "G3944": {"greek": "παροίχομαι", "translit": "paroíchomai", "pronunciation": "par-oy'-khom-ahee", "derivation": "from (G3844) and (to depart);", "definition": "to escape along, i.e. be gone", "kjv": "past."}, "G3945": {"greek": "παρομοιάζω", "translit": "paromoiázō", "pronunciation": "par-om-oy-ad'-zo", "derivation": "from (G3946);", "definition": "to resemble", "kjv": "be like unto."}, "G3946": {"greek": "παρόμοιος", "translit": "parómoios", "pronunciation": "par-om'-oy-os", "derivation": "from (G3844) and (G3664);", "definition": "alike nearly, i.e. similar", "kjv": "like."}, "G3947": {"greek": "παροξύνω", "translit": "paroxýnō", "pronunciation": "par-ox-oo'-no", "derivation": "from (G3844) and a derivative of (G3691);", "definition": "to sharpen alongside, i.e. (figuratively) to exasperate", "kjv": "easily provoke, stir."}, "G3948": {"greek": "παροξυσμός", "translit": "paroxysmós", "pronunciation": "par-ox-oos-mos'", "derivation": "from (G3947) (\"paroxysm\");", "definition": "incitement (to good), or dispute (in anger)", "kjv": "contention, provoke unto."}, "G3949": {"greek": "παροργίζω", "translit": "parorgízō", "pronunciation": "par-org-id'-zo", "derivation": "from (G3844) and (G3710);", "definition": "to anger alongside, i.e. enrage", "kjv": "anger, provoke to wrath."}, "G3950": {"greek": "παροργισμός", "translit": "parorgismós", "pronunciation": "par-org-is-mos'", "derivation": "from (G3949);", "definition": "rage", "kjv": "wrath."}, "G3951": {"greek": "παροτρύνω", "translit": "parotrýnō", "pronunciation": "par-ot-roo'-no", "derivation": "from (G3844) and (to spur);", "definition": "to urge along, i.e. stimulate (to hostility)", "kjv": "stir up."}, "G3952": {"greek": "παρουσία", "translit": "parousía", "pronunciation": "par-oo-see'-ah", "derivation": "from the present participle of (G3918);", "definition": "a being near, i.e. advent (often, return; specially, of Christ to punish Jerusalem, or finally the wicked); (by implication) physically, aspect", "kjv": "coming, presence."}, "G3953": {"greek": "παροψίς", "translit": "paropsís", "pronunciation": "par-op-sis'", "derivation": "from (G3844) and the base of (G3795);", "definition": "a side-dish (the receptacle)", "kjv": "platter."}, "G3954": {"greek": "παῤῥησία", "translit": "parrhēsía", "pronunciation": "par-rhay-see'-ah", "derivation": "from (G3956) and a derivative of (G4483);", "definition": "all out-spokenness, i.e. frankness, bluntness, publicity; by implication, assurance", "kjv": "bold (X -ly, -ness, -ness of speech), confidence, X freely, X openly, X plainly(-ness)."}, "G3955": {"greek": "παῤῥησιάζομαι", "translit": "parrhēsiázomai", "pronunciation": "par-hray-see-ad'-zom-ahee", "derivation": "middle voice from (G3954);", "definition": "to be frank in utterance, or confident in spirit and demeanor", "kjv": "be (wax) bold, (preach, speak) boldly."}, "G3956": {"greek": "πᾶς", "translit": "pâs", "pronunciation": "pas", "derivation": "including all the forms of declension; apparently a primary word;", "definition": "all, any, every, the whole", "kjv": "all (manner of, means), alway(-s), any (one), X daily, + ever, every (one, way), as many as, + no(-thing), X thoroughly, whatsoever, whole, whosoever."}, "G3957": {"greek": "πάσχα", "translit": "páscha", "pronunciation": "pas'-khah", "derivation": "of Chaldee origin (compare (G6453));", "definition": "the Passover (the meal, the day, the festival or the special sacrifices connected with it)", "kjv": "Easter, Passover."}, "G3958": {"greek": "πάσχω", "translit": "páschō", "pronunciation": "pas'-kho", "derivation": "apparently a primary verb;", "definition": "to experience a sensation or impression (usually painful)", "kjv": "feel, passion, suffer, vex."}, "G3959": {"greek": "Πάταρα", "translit": "Pátara", "pronunciation": "pat'-ar-ah", "derivation": "probably of foreign origin;", "definition": "Patara, a place in Asia Minor", "kjv": "Patara."}, "G3960": {"greek": "πατάσσω", "translit": "patássō", "pronunciation": "pat-as'-so", "derivation": "probably prolongation from (G3817);", "definition": "to knock (gently or with a weapon or fatally)", "kjv": "smite, strike."}, "G3961": {"greek": "πατέω", "translit": "patéō", "pronunciation": "pat-eh'-o", "derivation": "from a derivative probably of (G3817) (meaning a \"path\");", "definition": "to trample (literally or figuratively)", "kjv": "tread (down, under foot)."}, "G3962": {"greek": "πατήρ", "translit": "patḗr", "pronunciation": "pat-ayr'", "derivation": "apparently a primary word;", "definition": "a \"father\" (literally or figuratively, near or more remote)", "kjv": "father, parent."}, "G3963": {"greek": "Πάτμος", "translit": "Pátmos", "pronunciation": "pat'-mos", "derivation": "of uncertain derivation;", "definition": "Patmus, an islet in the Mediterranean", "kjv": "Patmos."}, "G3964": {"greek": "πατραλῴας", "translit": "patralṓias", "pronunciation": "pat-ral-o'-as", "derivation": "from (G3962) and the same as the latter part of (G3389);", "definition": "a parricide", "kjv": "murderer of fathers."}, "G3965": {"greek": "πατριά", "translit": "patriá", "pronunciation": "pat-ree-ah'", "derivation": "as if feminine of a derivative of (G3962);", "definition": "paternal descent, i.e. (concretely) a group of families or a whole race (nation)", "kjv": "family, kindred, lineage."}, "G3966": {"greek": "πατριάρχης", "translit": "patriárchēs", "pronunciation": "pat-ree-arkh'-ace", "derivation": "from (G3965) and (G757);", "definition": "a progenitor (\"patriarch\")", "kjv": "patriarch."}, "G3967": {"greek": "πατρικός", "translit": "patrikós", "pronunciation": "pat-ree-kos'", "derivation": "from (G3962);", "definition": "paternal, i.e. ancestral", "kjv": "of fathers."}, "G3968": {"greek": "πατρίς", "translit": "patrís", "pronunciation": "pat-rece'", "derivation": "from (G3902);", "definition": "a father-land, i.e. native town; (figuratively) heavenly home", "kjv": "(own) country."}, "G3969": {"greek": "Πατροβᾶς", "translit": "Patrobâs", "pronunciation": "pat-rob'-as", "derivation": "perhaps a contraction for (a compound of (G3962) and (G979));", "definition": "father's life; Patrobas, a Christian", "kjv": "Patrobas."}, "G3970": {"greek": "πατροπαράδοτος", "translit": "patroparádotos", "pronunciation": "pat-rop-ar-ad'-ot-os", "derivation": "from (G3962) and a derivative of (G3860) (in the sense of handing over or down);", "definition": "traditionary", "kjv": "received by tradition from fathers."}, "G3971": {"greek": "πατρῷος", "translit": "patrōios", "pronunciation": "pat-ro'-os", "derivation": "from (G3962);", "definition": "paternal, i.e. hereditary", "kjv": "of fathers."}, "G3972": {"greek": "Παῦλος", "translit": "Paûlos", "pronunciation": "pow'-los", "derivation": "of Latin origin;", "definition": "(little; but remotely from a derivative of (G3973), meaning the same); Paulus, the name of a Roman and of an apostle", "kjv": "Paul, Paulus."}, "G3973": {"greek": "παύω", "translit": "paúō", "pronunciation": "pow'-o", "derivation": "a primary verb (\"pause\");", "definition": "to stop (transitively or intransitively), i.e. restrain, quit, desist, come to an end", "kjv": "cease, leave, refrain."}, "G3974": {"greek": "Πάφος", "translit": "Páphos", "pronunciation": "paf'-os", "derivation": "of uncertain derivation;", "definition": "Paphus, a place in Cyprus", "kjv": "Paphos."}, "G3975": {"greek": "παχύνω", "translit": "pachýnō", "pronunciation": "pakh-oo'-no", "derivation": "from a derivative of (G4078) (meaning thick);", "definition": "to thicken, i.e. (by implication) to fatten (figuratively, stupefy or render callous)", "kjv": "wax gross."}, "G3976": {"greek": "πέδη", "translit": "pédē", "pronunciation": "ped'-ay", "derivation": "ultimately from (G4228);", "definition": "a shackle for the feet", "kjv": "fetter."}, "G3977": {"greek": "πεδινός", "translit": "pedinós", "pronunciation": "ped-ee-nos'", "derivation": "from a derivative of (G4228) (meaning the ground);", "definition": "level (as easy for the feet)", "kjv": "plain."}, "G3978": {"greek": "πεζεύω", "translit": "pezeúō", "pronunciation": "ped-zyoo'-o", "derivation": "from the same as (G3979);", "definition": "to foot a journey, i.e. travel by land", "kjv": "go afoot."}, "G3979": {"greek": "πεζῇ", "translit": "pezēi", "pronunciation": "ped-zay'", "derivation": "dative case feminine of a derivative of (G4228) (as adverb);", "definition": "foot-wise, i.e. by walking", "kjv": "a- (on) foot."}, "G3980": {"greek": "πειθαρχέω", "translit": "peitharchéō", "pronunciation": "pi-tharkh-eh'-o", "derivation": "from a compound of (G3982) and (G757);", "definition": "to be persuaded by a ruler, i.e. (genitive case) to submit to authority; by analogy, to conform to advice", "kjv": "hearken, obey (magistrates)."}, "G3981": {"greek": "πειθός", "translit": "peithós", "pronunciation": "pi-thos'", "derivation": "from (G3982);", "definition": "persuasive", "kjv": "enticing."}, "G3982": {"greek": "πείθω", "translit": "peíthō", "pronunciation": "pi'-tho", "derivation": "a primary verb;", "definition": "to convince (by argument, true or false); by analogy, to pacify or conciliate (by other fair means); reflexively or passively, to assent (to evidence or authority), to rely (by inward certainty)", "kjv": "agree, assure, believe, have confidence, be (wax) conflent, make friend, obey, persuade, trust, yield."}, "G3983": {"greek": "πεινάω", "translit": "peináō", "pronunciation": "pi-nah'-o", "derivation": "from the same as (G3993) (through the idea of pinching toil; \"pine\");", "definition": "to famish (absolutely or comparatively); figuratively, to crave", "kjv": "be an hungered."}, "G3984": {"greek": "πεῖρα", "translit": "peîra", "pronunciation": "pi'-rah", "derivation": "from the base of (G4008) (through the idea of piercing);", "definition": "a test, i.e. attempt, experience", "kjv": "assaying, trial."}, "G3985": {"greek": "πειράζω", "translit": "peirázō", "pronunciation": "pi-rad'-zo", "derivation": "from (G3984);", "definition": "to test (objectively), i.e. endeavor, scrutinize, entice, discipline", "kjv": "assay, examine, go about, prove, tempt(-er), try."}, "G3986": {"greek": "πειρασμός", "translit": "peirasmós", "pronunciation": "pi-ras-mos'", "derivation": "from (G3985);", "definition": "a putting to proof (by experiment (of good), experience (of evil), solicitation, discipline or provocation); by implication, adversity", "kjv": "temptation, X try."}, "G3987": {"greek": "πειράω", "translit": "peiráō", "pronunciation": "pi-rah'-o", "derivation": "from (G3984);", "definition": "to test (subjectively), i.e. (reflexively) to attempt", "kjv": "assay."}, "G3988": {"greek": "πεισμονή", "translit": "peismonḗ", "pronunciation": "pice-mon-ay'", "derivation": "from a presumed derivative of (G3982);", "definition": "persuadableness, i.e. credulity", "kjv": "persuasion."}, "G3989": {"greek": "πέλαγος", "translit": "pélagos", "pronunciation": "pel'-ag-os", "derivation": "of uncertain affinity;", "definition": "deep or open sea, i.e. the main", "kjv": "depth, sea."}, "G3990": {"greek": "πελεκίζω", "translit": "pelekízō", "pronunciation": "pel-ek-id'-zo", "derivation": "from a derivative of (G4141) (meaning an axe);", "definition": "to chop off (the head), i.e. truncate", "kjv": "behead."}, "G3991": {"greek": "πέμπτος", "translit": "pémptos", "pronunciation": "pemp'-tos", "derivation": "from (G4002);", "definition": "fifth", "kjv": "fifth."}, "G3992": {"greek": "πέμπω", "translit": "pémpō", "pronunciation": "pem'-po", "derivation": "apparently a primary verb;", "definition": "to dispatch (from the subjective view or point of departure, whereas (as a stronger form of ) refers rather to the objective point or terminus ad quem, and (G4724) denotes properly, the orderly motion involved), especially on a temporary errand; also to transmit, bestow, or wield", "kjv": "send, thrust in."}, "G3993": {"greek": "πένης", "translit": "pénēs", "pronunciation": "pen'-ace", "derivation": "from a primary (to toil for daily subsistence);", "definition": "starving, i.e. indigent", "kjv": "poor."}, "G3994": {"greek": "πενθερά", "translit": "pentherá", "pronunciation": "pen-ther-ah'", "derivation": "feminine of (G3995);", "definition": "a wife's mother", "kjv": "mother in law, wife's mother."}, "G3995": {"greek": "πενθερός", "translit": "pentherós", "pronunciation": "pen-ther-os'", "derivation": "of uncertain affinity;", "definition": "a wife's father", "kjv": "father in law."}, "G3996": {"greek": "πενθέω", "translit": "penthéō", "pronunciation": "pen-theh'-o", "derivation": "from (G3997);", "definition": "to grieve (the feeling or the act)", "kjv": "mourn, (be-)wail."}, "G3997": {"greek": "πένθος", "translit": "pénthos", "pronunciation": "pen'-thos", "derivation": "strengthened from the alternate of (G3958);", "definition": "grief", "kjv": "mourning, sorrow."}, "G3998": {"greek": "πενιχρός", "translit": "penichrós", "pronunciation": "pen-tikh-ros'", "derivation": "prolongation from the base of (G3993);", "definition": "necessitous", "kjv": "poor."}, "G3999": {"greek": "πεντάκις", "translit": "pentákis", "pronunciation": "pen-tak-ece'", "derivation": "multiplicative adverb from (G4002);", "definition": "five times", "kjv": "five times."}, "G4000": {"greek": "πεντακισχίλιοι", "translit": "pentakischílioi", "pronunciation": "pen-tak-is-khil'-ee-oy", "derivation": "from (G3999) and (G5507);", "definition": "five times a thousand", "kjv": "five thousand."}, "G4001": {"greek": "πεντακόσιοι", "translit": "pentakósioi", "pronunciation": "pen-tak-os'-ee-oy", "derivation": "from (G4002) and (G1540);", "definition": "five hundred", "kjv": "five hundred."}, "G4002": {"greek": "πέντε", "translit": "pénte", "pronunciation": "pen'-teh", "derivation": "a primary number;", "definition": "\"five\"", "kjv": "five."}, "G4003": {"greek": "πεντεκαιδέκατος", "translit": "pentekaidékatos", "pronunciation": "pen-tek-ahee-dek'-at-os", "derivation": "from (G4002) and (G2532) and (G1182);", "definition": "five and tenth", "kjv": "fifteenth."}, "G4004": {"greek": "πεντήκοντα", "translit": "pentḗkonta", "pronunciation": "pen-tay'-kon-tah", "derivation": "multiplicative of (G4002);", "definition": "fifty", "kjv": "fifty."}, "G4005": {"greek": "πεντηκοστή", "translit": "pentēkostḗ", "pronunciation": "pen-tay-kos-tay'", "derivation": "feminine of the ordinal of (G4004);", "definition": "fiftieth ((G2250) being implied) from Passover, i.e. the festival of \"Pentecost\"", "kjv": "Pentecost."}, "G4006": {"greek": "πεποίθησις", "translit": "pepoíthēsis", "pronunciation": "pep-oy'-thay-sis", "derivation": "from the perfect of the alternate of (G3958);", "definition": "reliance", "kjv": "confidence, trust."}, "G4008": {"greek": "πέραν", "translit": "péran", "pronunciation": "per'-an", "derivation": "apparently accusative case of an obsolete derivative of (to \"pierce\");", "definition": "through (as adverb or preposition), i.e. across", "kjv": "beyond, farther (other) side, over."}, "G4009": {"greek": "πέρας", "translit": "péras", "pronunciation": "per'-as", "derivation": "from the same as (G4008);", "definition": "an extremity", "kjv": "end, ut-(ter-)most part."}, "G4010": {"greek": "Πέργαμος", "translit": "Pérgamos", "pronunciation": "per'-gam-os", "derivation": "from (G4444);", "definition": "fortified; Pergamus, a place in Asia Minor", "kjv": "Pergamos."}, "G4011": {"greek": "Πέργη", "translit": "Pérgē", "pronunciation": "perg'-ay", "derivation": "probably from the same as (G4010);", "definition": "a tower; Perga, a place in Asia Minor", "kjv": "Perga."}, "G4012": {"greek": "περί", "translit": "perí", "pronunciation": "per-ee'", "derivation": "from the base of (G4008);", "definition": "properly, through (all over), i.e. around; figuratively with respect to; used in various applications, of place, cause or time (with the genitive case denoting the subject or occasion or superlative point; with the accusative case the locality, circuit, matter, circumstance or general period)", "kjv": "(there-)about, above, against, at, on behalf of, X and his company, which concern, (as) concerning, for, X how it will go with, ((there-, where-)) of, on, over, pertaining (to), for sake, X (e-)state, (as) touching, (where-)by (in), with."}, "G4013": {"greek": "περιάγω", "translit": "periágō", "pronunciation": "per-ee-ag'-o", "derivation": "from (G4012) and (G71);", "definition": "to take around (as a companion); reflexively, to walk around", "kjv": "compass, go (round) about, lead about."}, "G4014": {"greek": "περιαιρέω", "translit": "periairéō", "pronunciation": "per-ee-ahee-reh'-o", "derivation": "from (G4012) and (G138) (including its alternate);", "definition": "to remove all around, i.e. unveil, cast off (anchor); figuratively, to expiate", "kjv": "take away (up)."}, "G4015": {"greek": "περιαστράπτω", "translit": "periastráptō", "pronunciation": "per-ee-as-trap'-to", "derivation": "from (G4012) and (G797);", "definition": "to flash all around, i.e. envelop in light", "kjv": "shine round (about)."}, "G4016": {"greek": "περιβάλλω", "translit": "peribállō", "pronunciation": "per-ee-bal'-lo", "derivation": "from (G4012) and (G906);", "definition": "to throw all around, i.e. invest (with a palisade or with clothing)", "kjv": "array, cast about, clothe(-d me), put on."}, "G4017": {"greek": "περιβλέπω", "translit": "periblépō", "pronunciation": "per-ee-blep'-o", "derivation": "from (G4012) and (G991);", "definition": "to look all around", "kjv": "look (round) about (on)."}, "G4018": {"greek": "περιβόλαιον", "translit": "peribólaion", "pronunciation": "per-ib-ol'-ah-yon", "derivation": "neuter of a presumed derivative of (G4016);", "definition": "something thrown around one, i.e. a mantle, veil", "kjv": "covering, vesture."}, "G4019": {"greek": "περιδέω", "translit": "peridéō", "pronunciation": "per-ee-deh'-o", "derivation": "from (G4012) and (G1210);", "definition": "to bind around one, i.e. enwrap", "kjv": "bind about."}, "G4020": {"greek": "περιεργάζομαι", "translit": "periergázomai", "pronunciation": "per-ee-er-gad'-zom-ahee", "derivation": "from (G4012) and (G2038);", "definition": "to work all around, i.e. bustle about (meddle)", "kjv": "be a busybody."}, "G4021": {"greek": "περίεργος", "translit": "períergos", "pronunciation": "per-ee'-er-gos", "derivation": "from (G4012) and (G2041);", "definition": "working all around, i.e. officious (meddlesome, neuter plural magic)", "kjv": "busybody, curious arts."}, "G4022": {"greek": "περιέρχομαι", "translit": "periérchomai", "pronunciation": "per-ee-er'-khom-ahee", "derivation": "from (G4012) and (G2064) (including its alternate);", "definition": "to come all around, i.e. stroll, vacillate, veer", "kjv": "fetch a compass, vagabond, wandering about."}, "G4023": {"greek": "περιέχω", "translit": "periéchō", "pronunciation": "per-ee-ekh'-o", "derivation": "from (G4012) and (G2192);", "definition": "to hold all around, i.e. include, clasp (figuratively)", "kjv": "+ astonished, contain, after (this manner)."}, "G4024": {"greek": "περιζώννυμι", "translit": "perizṓnnymi", "pronunciation": "per-id-zone'-noo-mee", "derivation": "from (G4012) and (G2224);", "definition": "to gird all around, i.e. (middle voice or passive) to fasten on one's belt (literally or figuratively)", "kjv": "gird (about, self)."}, "G4025": {"greek": "περίθεσις", "translit": "períthesis", "pronunciation": "per-ith'-es-is", "derivation": "from (G4060);", "definition": "a putting all around, i.e. decorating oneself with", "kjv": "wearing."}, "G4026": {"greek": "περιΐστημι", "translit": "periḯstēmi", "pronunciation": "per-ee-is'-tay-mee", "derivation": "from (G4012) and (G2476);", "definition": "to stand all around, i.e. (near) to be a bystander, or (aloof) to keep away from", "kjv": "avoid, shun, stand by (round about)."}, "G4027": {"greek": "περικάθαρμα", "translit": "perikátharma", "pronunciation": "per-ee-kath'-ar-mah", "derivation": "from a compound of (G4012) and (G2508);", "definition": "something cleaned off all around, i.e. refuse (figuratively)", "kjv": "filth."}, "G4028": {"greek": "περικαλύπτω", "translit": "perikalýptō", "pronunciation": "per-ee-kal-oop'-to", "derivation": "from (G4012) and (G2572);", "definition": "to cover all around, i.e. entirely (the face, a surface)", "kjv": "blindfold, cover, overlay."}, "G4029": {"greek": "περίκειμαι", "translit": "períkeimai", "pronunciation": "per-ik'-i-mahee", "derivation": "from (G4012) and (G2749);", "definition": "to lie all around, i.e. inclose, encircle, hamper (literally or figuratively)", "kjv": "be bound (compassed) with, hang about."}, "G4030": {"greek": "περικεφαλαία", "translit": "perikephalaía", "pronunciation": "per-ee-kef-al-ah'-yah", "derivation": "feminine of a compound of (G4012) and (G2776);", "definition": "encirclement of the head, i.e. a helmet", "kjv": "helmet."}, "G4031": {"greek": "περικρατής", "translit": "perikratḗs", "pronunciation": "per-ee-krat-ace'", "derivation": "from (G4012) and (G2904);", "definition": "strong all around, i.e. a master (manager)", "kjv": "+ come by."}, "G4032": {"greek": "περικρύπτω", "translit": "perikrýptō", "pronunciation": "per-ee-kroop'-to", "derivation": "from (G4012) and (G2928);", "definition": "to conceal all around, i.e. entirely", "kjv": "hide."}, "G4033": {"greek": "περικυκλόω", "translit": "perikyklóō", "pronunciation": "per-ee-koo-klo'-o", "derivation": "from (G4012) and (G2944);", "definition": "to encircle all around, i.e. blockade completely", "kjv": "compass round."}, "G4034": {"greek": "περιλάμπω", "translit": "perilámpō", "pronunciation": "per-ee-lam'-po", "derivation": "from (G4012) and (G2989);", "definition": "to illuminate all around, i.e. invest with a halo", "kjv": "shine round about."}, "G4035": {"greek": "περιλείπω", "translit": "perileípō", "pronunciation": "per-ee-li'-po", "derivation": "from (G4012) and (G3007);", "definition": "to leave all around, i.e. (passively) survive", "kjv": "remain."}, "G4036": {"greek": "περίλυπος", "translit": "perílypos", "pronunciation": "per-il'-oo-pos", "derivation": "from (G4012) and (G3077);", "definition": "grieved all around, i.e. intensely sad", "kjv": "exceeding (very) sorry(-owful)."}, "G4037": {"greek": "περιμένω", "translit": "periménō", "pronunciation": "per-ee-men'-o", "derivation": "from (G4012) and (G3306);", "definition": "to stay around, i.e. await", "kjv": "wait for."}, "G4038": {"greek": "πέριξ", "translit": "périx", "pronunciation": "per'-ix", "derivation": "adverb from (G4012);", "definition": "all around, i.e. (as an adjective) circumjacent", "kjv": "round about."}, "G4039": {"greek": "περιοικέω", "translit": "perioikéō", "pronunciation": "per-ee-oy-keh'-o", "derivation": "from (G4012) and (G3611);", "definition": "to reside around, i.e. be a neighbor", "kjv": "dwell round about."}, "G4040": {"greek": "περίοικος", "translit": "períoikos", "pronunciation": "per-ee'-oy-kos", "derivation": "from (G4012) and (G3624);", "definition": "housed around, i.e. neighboring (used elliptically as a noun)", "kjv": "neighbour."}, "G4041": {"greek": "περιούσιος", "translit": "perioúsios", "pronunciation": "per-ee-oo'-see-os", "derivation": "from the present participle feminine of a compound of 4012 and (G1510);", "definition": "being beyond usual, i.e. special (one's own)", "kjv": "peculiar."}, "G4042": {"greek": "περιοχή", "translit": "periochḗ", "pronunciation": "per-ee-okh-ay'", "derivation": "from (G4023);", "definition": "a being held around, i.e. (concretely) a passage (of Scripture, as circumscribed)", "kjv": "place."}, "G4043": {"greek": "περιπατέω", "translit": "peripatéō", "pronunciation": "per-ee-pat-eh'-o", "derivation": "from (G4012) and (G3961);", "definition": "to tread all around, i.e. walk at large (especially as proof of ability); figuratively, to live, deport oneself, follow (as a companion or votary)", "kjv": "go, be occupied with, walk (about)."}, "G4044": {"greek": "περιπείρω", "translit": "peripeírō", "pronunciation": "per-ee-pi'-ro", "derivation": "from (G4012) and the base of (G4008);", "definition": "to penetrate entirely, i.e. transfix (figuratively)", "kjv": "pierce through."}, "G4045": {"greek": "περιπίπτω", "translit": "peripíptō", "pronunciation": "per-ee-pip'-to", "derivation": "from (G4012) and (G4098);", "definition": "to fall into something that is all around, i.e. light among or upon, be surrounded with", "kjv": "fall among (into)."}, "G4046": {"greek": "περιποιέομαι", "translit": "peripoiéomai", "pronunciation": "per-ee-poy-eh'-om-ahee", "derivation": "middle voice from (G4012) and (G4160);", "definition": "to make around oneself, i.e. acquire (buy)", "kjv": "purchase."}, "G4047": {"greek": "περιποίησις", "translit": "peripoíēsis", "pronunciation": "per-ee-poy'-ay-sis", "derivation": "from (G4046);", "definition": "acquisition (the act or the thing); by extension, preservation", "kjv": "obtain(-ing), peculiar, purchased, possession, saving."}, "G4048": {"greek": "περιῤῥήγνυμι", "translit": "perirrhḗgnymi", "pronunciation": "per-ir-hrayg'-noo-mee", "derivation": "from (G4012) and (G4486);", "definition": "to tear all around, i.e. completely away", "kjv": "rend off."}, "G4049": {"greek": "περισπάω", "translit": "perispáō", "pronunciation": "per-ee-spah'-o", "derivation": "from (G4012) and (G4685);", "definition": "to drag all around, i.e. (figuratively) to distract (with care)", "kjv": "cumber."}, "G4050": {"greek": "περισσεία", "translit": "perisseía", "pronunciation": "per-is-si'-ah", "derivation": "from (G4052);", "definition": "surplusage, i.e. superabundance", "kjv": "abundance(-ant, (-ly)), superfluity."}, "G4051": {"greek": "περίσσευμα", "translit": "perísseuma", "pronunciation": "per-is'-syoo-mah", "derivation": "from (G4052);", "definition": "a surplus, or superabundance", "kjv": "abundance, that was left, over and above."}, "G4052": {"greek": "περισσεύω", "translit": "perisseúō", "pronunciation": "per-is-syoo'-o", "derivation": "from (G4053);", "definition": "to superabound (in quantity or quality), be in excess, be superfluous; also (transitively) to cause to superabound or excel", "kjv": "(make, more) abound, (have, have more) abundance (be more) abundant, be the better, enough and to spare, exceed, excel, increase, be left, redound, remain (over and above)."}, "G4053": {"greek": "περισσός", "translit": "perissós", "pronunciation": "per-is-sos'", "derivation": "from (G4012) (in the sense of beyond);", "definition": "superabundant (in quantity) or superior (in quality); by implication, excessive; adverbially (with (G1537)) violently; neuter (as noun) preeminence", "kjv": "exceeding abundantly above, more abundantly, advantage, exceedingly, very highly, beyond measure, more, superfluous, vehement(-ly)."}, "G4055": {"greek": "περισσότερος", "translit": "perissóteros", "pronunciation": "per-is-sot'-er-os", "derivation": "comparative of (G4053);", "definition": "more superabundant (in number, degree or character)", "kjv": "more abundant, greater (much) more, overmuch."}, "G4056": {"greek": "περισσοτέρως", "translit": "perissotérōs", "pronunciation": "per-is-sot-er'-oce", "derivation": "adverb from (G4055);", "definition": "more superabundantly", "kjv": "more abundant(-ly), X the more earnest, (more) exceedingly, more frequent, much more, the rather."}, "G4057": {"greek": "περισσῶς", "translit": "perissōs", "pronunciation": "per-is-soce'", "derivation": "adverb from (G4053);", "definition": "superabundantly", "kjv": "exceedingly, out of measure, the more."}, "G4058": {"greek": "περιστερά", "translit": "peristerá", "pronunciation": "per-is-ter-ah'", "derivation": "of uncertain derivation;", "definition": "a pigeon", "kjv": "dove, pigeon."}, "G4059": {"greek": "περιτέμνω", "translit": "peritémnō", "pronunciation": "per-ee-tem'-no", "derivation": "from (G4012) and the base of (G5114);", "definition": "to cut around, i.e. (specially) to circumcise", "kjv": "circumcise."}, "G4060": {"greek": "περιτίθημι", "translit": "peritíthēmi", "pronunciation": "per-ee-tith'-ay-mee", "derivation": "from (G4012) and (G5087);", "definition": "to place around; by implication, to present", "kjv": "bestow upon, hedge round about, put about (on, upon), set about."}, "G4061": {"greek": "περιτομή", "translit": "peritomḗ", "pronunciation": "per-it-om-ay'", "derivation": "from (G4059);", "definition": "circumcision (the rite, the condition or the people, literally or figuratively)", "kjv": "X circumcised, circumcision."}, "G4062": {"greek": "περιτρέπω", "translit": "peritrépō", "pronunciation": "per-ee-trep'-o", "derivation": "from (G4012) and the base of (G5157);", "definition": "to turn around, i.e. (mentally) to craze", "kjv": "+ make mad."}, "G4063": {"greek": "περιτρέχω", "translit": "peritréchō", "pronunciation": "per-ee-trekh'-o", "derivation": "from (G4012) and (G5143) (including its alternate);", "definition": "to run around, i.e. traverse", "kjv": "run through."}, "G4064": {"greek": "περιφέρω", "translit": "periphérō", "pronunciation": "per-ee-fer'-o", "derivation": "from (G4012) and (G5342);", "definition": "to convey around, i.e. transport hither and thither", "kjv": "bear (carry) about."}, "G4065": {"greek": "περιφρονέω", "translit": "periphronéō", "pronunciation": "per-ee-fron-eh'-o", "derivation": "from (G4012) and (G5426);", "definition": "to think beyond, i.e. depreciate (contemn)", "kjv": "despise."}, "G4066": {"greek": "περίχωρος", "translit": "períchōros", "pronunciation": "per-ikh'-o-ros", "derivation": "from (G4012) and (G5561);", "definition": "around the region, i.e. circumjacent (as noun, with (G1093) implied vicinity)", "kjv": "country (round) about, region (that lieth) round about."}, "G4067": {"greek": "περίψωμα", "translit": "perípsōma", "pronunciation": "per-ip'-so-mah", "derivation": "from a compound of (G4012) and (to rub);", "definition": "something brushed all around, i.e. off-scrapings (figuratively, scum)", "kjv": "offscouring."}, "G4068": {"greek": "περπερεύομαι", "translit": "perpereúomai", "pronunciation": "per-per-yoo'-om-ahee", "derivation": "middle voice from (braggart;", "definition": "perhaps by reduplication of the base of (G4008)); to boast", "kjv": "vaunt itself."}, "G4069": {"greek": "Περσίς", "translit": "Persís", "pronunciation": "per-sece'", "derivation": "", "definition": "a Persian woman; Persis, a Christian female", "kjv": "Persis."}, "G4070": {"greek": "πέρυσι", "translit": "pérysi", "pronunciation": "per'-oo-si", "derivation": "adverb from (G4009);", "definition": "the by-gone, i.e. (as noun) last year", "kjv": "+ a year ago."}, "G4071": {"greek": "πετεινόν", "translit": "peteinón", "pronunciation": "pet-i-non'", "derivation": "neuter of a derivative of (G4072);", "definition": "a flying animal, i.e. bird", "kjv": "bird, fowl."}, "G4072": {"greek": "πέτομαι", "translit": "pétomai", "pronunciation": "pet'-om-ahee", "derivation": "middle voice of a primary verb;", "definition": "to fly", "kjv": "fly(-ing)."}, "G4073": {"greek": "πέτρα", "translit": "pétra", "pronunciation": "pet'-ra", "derivation": "feminine of the same as (G4074);", "definition": "a (mass of) rock (literally or figuratively)", "kjv": "rock."}, "G4074": {"greek": "Πέτρος", "translit": "Pétros", "pronunciation": "pet'-ros", "derivation": "apparently a primary word;", "definition": "a (piece of) rock (larger than (G3037)); as a name, Petrus, an apostle", "kjv": "Peter, rock."}, "G4075": {"greek": "πετρώδης", "translit": "petrṓdēs", "pronunciation": "pet-ro'-dace", "derivation": "from (G4073) and (G1491);", "definition": "rock-like, i.e. rocky", "kjv": "stony."}, "G4076": {"greek": "πήγανον", "translit": "pḗganon", "pronunciation": "pay'-gan-on", "derivation": "from (G4078);", "definition": "rue (from its thick or fleshy leaves)", "kjv": "rue."}, "G4077": {"greek": "πηγή", "translit": "pēgḗ", "pronunciation": "pay-gay'", "derivation": "probably from (G4078) (through the idea of gushing plumply);", "definition": "a fount (literally or figuratively), i.e. source or supply (of water, blood, enjoyment) (not necessarily the original spring)", "kjv": "fountain, well."}, "G4078": {"greek": "πήγνυμι", "translit": "pḗgnymi", "pronunciation": "payg'-noo-mee", "derivation": "a prolonged form of a primary verb (which in its simpler form occurs only as an alternate in certain tenses);", "definition": "to fix (\"peg\"), i.e. (specially) to set up (a tent)", "kjv": "pitch."}, "G4079": {"greek": "πηδάλιον", "translit": "pēdálion", "pronunciation": "pay-dal'-ee-on", "derivation": "neuter of a (presumed) derivative of (the blade of an oar; from the same as (G3976));", "definition": "a \"pedal\", i.e. helm", "kjv": "rudder."}, "G4080": {"greek": "πηλίκος", "translit": "pēlíkos", "pronunciation": "pay-lee'-kos", "derivation": "a quantitative form (the feminine) of the base of (G4225);", "definition": "how much (as an indefinite), i.e. in size or (figuratively) dignity", "kjv": "how great (large)."}, "G4081": {"greek": "πηλός", "translit": "pēlós", "pronunciation": "pay-los'", "derivation": "perhaps a primary word;", "definition": "clay", "kjv": "clay."}, "G4082": {"greek": "πήρα", "translit": "pḗra", "pronunciation": "pay'-rah", "derivation": "of uncertain affinity;", "definition": "a wallet or leather pouch for food", "kjv": "scrip."}, "G4083": {"greek": "πῆχυς", "translit": "pēchys", "pronunciation": "pay'-khoos", "derivation": "of uncertain affinity;", "definition": "the fore-arm, i.e. (as a measure) a cubit", "kjv": "cubit."}, "G4084": {"greek": "πιάζω", "translit": "piázō", "pronunciation": "pee-ad'-zo", "derivation": "probably another form of (G971);", "definition": "to squeeze, i.e. seize (gently by the hand (press), or officially (arrest), or in hunting (capture))", "kjv": "apprehend, catch, lay hand on, take."}, "G4085": {"greek": "πιέζω", "translit": "piézō", "pronunciation": "pee-ed'-zo", "derivation": "another form for (G4084);", "definition": "to pack", "kjv": "press down."}, "G4086": {"greek": "πιθανολογία", "translit": "pithanología", "pronunciation": "pith-an-ol-og-ee'-ah", "derivation": "from a compound of a derivative of (G3982) and (G3056);", "definition": "persuasive language", "kjv": "enticing words."}, "G4087": {"greek": "πικραίνω", "translit": "pikraínō", "pronunciation": "pik-rah'-ee-no", "derivation": "from (G4089);", "definition": "to embitter (literally or figuratively)", "kjv": "be (make) bitter."}, "G4088": {"greek": "πικρία", "translit": "pikría", "pronunciation": "pik-ree'-ah", "derivation": "from (G4089);", "definition": "acridity (especially poison), literally or figuratively", "kjv": "bitterness."}, "G4089": {"greek": "πικρός", "translit": "pikrós", "pronunciation": "pik-ros'", "derivation": "perhaps from (G4078) (through the idea of piercing);", "definition": "sharp (pungent), i.e. acrid (literally or figuratively)", "kjv": "bitter."}, "G4090": {"greek": "πικρῶς", "translit": "pikrōs", "pronunciation": "pik-roce'", "derivation": "adverb from (G4089);", "definition": "bitterly, i.e. (figuratively) violently", "kjv": "bitterly."}, "G4091": {"greek": "Πιλᾶτος", "translit": "Pilâtos", "pronunciation": "pil-at'-os", "derivation": "of Latin origin;", "definition": "close-pressed, i.e. firm; Pilatus, a Roman", "kjv": "Pilate."}, "G4092": {"greek": "πίμπρημι", "translit": "pímprēmi", "pronunciation": "pim'-pray-mee", "derivation": "a reduplicated and prolonged form of a primary ; which occurs only as an alternate in certain tenses);", "definition": "to fire, i.e. burn (figuratively and passively, become inflamed with fever)", "kjv": "be (X should have) swollen."}, "G4093": {"greek": "πινακίδιον", "translit": "pinakídion", "pronunciation": "pin-ak-id'-ee-on", "derivation": "diminutive of (G4094);", "definition": "a tablet (for writing on)", "kjv": "writing table."}, "G4094": {"greek": "πίναξ", "translit": "pínax", "pronunciation": "pin'-ax", "derivation": "apparently a form of (G4109);", "definition": "a plate", "kjv": "charger, platter."}, "G4095": {"greek": "πίνω", "translit": "pínō", "pronunciation": "pee'-no", "derivation": "a prolonged form of ; which (together with another form) ; occurs only as an alternate in certain tenses;", "definition": "to imbibe (literally or figuratively)", "kjv": "drink."}, "G4096": {"greek": "πιότης", "translit": "piótēs", "pronunciation": "pee-ot'-ace", "derivation": "from (fat; perhaps akin to the alternate of (G4095) through the idea of repletion);", "definition": "plumpness, i.e. (by implication) richness (oiliness)", "kjv": "fatness."}, "G4097": {"greek": "πιπράσκω", "translit": "pipráskō", "pronunciation": "pip-ras'-ko", "derivation": "contracted from (to traverse;", "definition": "from the base of (G4008)); to traffic (by travelling), i.e. dispose of as merchandise or into slavery (literally or figuratively)", "kjv": "sell."}, "G4098": {"greek": "πίπτω", "translit": "píptō", "pronunciation": "pip'-to", "derivation": "probably akin to (G4072) through the idea of alighting;", "definition": "to fall (literally or figuratively)", "kjv": "fail, fall (down), light on."}, "G4099": {"greek": "Πισιδία", "translit": "Pisidía", "pronunciation": "pis-id-ee'-ah", "derivation": "probably of foreign origin;", "definition": "Pisidia, a region of Asia Minor", "kjv": "Pisidia."}, "G4100": {"greek": "πιστεύω", "translit": "pisteúō", "pronunciation": "pist-yoo'-o", "derivation": "from (G4102);", "definition": "to have faith (in, upon, or with respect to, a person or thing), i.e. credit; by implication, to entrust (especially one's spiritual well-being to Christ)", "kjv": "believe(-r), commit (to trust), put in trust with."}, "G4101": {"greek": "πιστικός", "translit": "pistikós", "pronunciation": "pis-tik-os'", "derivation": "from (G4102);", "definition": "trustworthy, i.e. genuine (unadulterated)", "kjv": "spike-(nard)."}, "G4102": {"greek": "πίστις", "translit": "pístis", "pronunciation": "pis'-tis", "derivation": "from (G3982);", "definition": "persuasion, i.e. credence; moral conviction (of religious truth, or the truthfulness of God or a religious teacher), especially reliance upon Christ for salvation; abstractly, constancy in such profession; by extension, the system of religious (Gospel) truth itself", "kjv": "assurance, belief, believe, faith, fidelity."}, "G4103": {"greek": "πιστός", "translit": "pistós", "pronunciation": "pis-tos'", "derivation": "from (G3982);", "definition": "objectively, trustworthy; subjectively, trustful", "kjv": "believe(-ing, -r), faithful(-ly), sure, true."}, "G4104": {"greek": "πιστόω", "translit": "pistóō", "pronunciation": "pis-to'-o", "derivation": "from (G4103);", "definition": "to assure", "kjv": "assure of."}, "G4105": {"greek": "πλανάω", "translit": "planáō", "pronunciation": "plan-ah'-o", "derivation": "from (G4106);", "definition": "to (properly, cause to) roam (from safety, truth, or virtue)", "kjv": "go astray, deceive, err, seduce, wander, be out of the way."}, "G4106": {"greek": "πλάνη", "translit": "plánē", "pronunciation": "plan'-ay", "derivation": "feminine of (G4108) (as abstractly);", "definition": "objectively, fraudulence; subjectively, a straying from orthodoxy or piety", "kjv": "deceit, to deceive, delusion, error."}, "G4107": {"greek": "πλανήτης", "translit": "planḗtēs", "pronunciation": "plan-ay'-tace", "derivation": "from (G4108);", "definition": "a rover (\"planet\"), i.e. (figuratively) an erratic teacher", "kjv": "wandering."}, "G4108": {"greek": "πλάνος", "translit": "plános", "pronunciation": "plan'-os", "derivation": "of uncertain affinity;", "definition": "roving (as a tramp), i.e. (by implication) an impostor or misleader;", "kjv": "deceiver, seducing."}, "G4109": {"greek": "πλάξ", "translit": "pláx", "pronunciation": "plax", "derivation": "from (G4111);", "definition": "a moulding-board, i.e. flat surface (\"plate\", or tablet, literally or figuratively)", "kjv": "table."}, "G4110": {"greek": "πλάσμα", "translit": "plásma", "pronunciation": "plas'-mah", "derivation": "from (G4111);", "definition": "something moulded", "kjv": "thing formed."}, "G4111": {"greek": "πλάσσω", "translit": "plássō", "pronunciation": "plas'-so", "derivation": "a primary verb;", "definition": "to mould, i.e. shape or fabricate", "kjv": "form."}, "G4112": {"greek": "πλαστός", "translit": "plastós", "pronunciation": "plas-tos'", "derivation": "from (G4111);", "definition": "moulded, i.e. (by implication) artificial or (figuratively) fictitious (false)", "kjv": "feigned."}, "G4113": {"greek": "πλατεῖα", "translit": "plateîa", "pronunciation": "plat-i'-ah", "derivation": "feminine of (G4116);", "definition": "a wide \"plat\" or \"place\", i.e. open square", "kjv": "street."}, "G4114": {"greek": "πλάτος", "translit": "plátos", "pronunciation": "plat'-os", "derivation": "from (G4116);", "definition": "width", "kjv": "breadth."}, "G4115": {"greek": "πλατύνω", "translit": "platýnō", "pronunciation": "plat-oo'-no", "derivation": "from (G4116);", "definition": "to widen (literally or figuratively)", "kjv": "make broad, enlarge."}, "G4116": {"greek": "πλατύς", "translit": "platýs", "pronunciation": "plat-oos'", "derivation": "from (G4111);", "definition": "spread out \"flat\" (\"plot\"), i.e. broad", "kjv": "wide."}, "G4117": {"greek": "πλέγμα", "translit": "plégma", "pronunciation": "pleg'-mah", "derivation": "from (G4120);", "definition": "a plait (of hair)", "kjv": "broidered hair."}, "G4119": {"greek": "πλείων", "translit": "pleíōn", "pronunciation": "pli-own", "derivation": "comparative of (G4183);", "definition": "more in quantity, number, or quality; also (in plural) the major portion", "kjv": "X above, + exceed, more excellent, further, (very) great(-er), long(-er), (very) many, greater (more) part, + yet but."}, "G4120": {"greek": "πλέκω", "translit": "plékō", "pronunciation": "plek'-o", "derivation": "a primary word;", "definition": "to twine or braid", "kjv": "plait."}, "G4121": {"greek": "πλεονάζω", "translit": "pleonázō", "pronunciation": "pleh-on-ad'-zo", "derivation": "from (G4119);", "definition": "to do, make or be more, i.e. increase (transitively or intransitively); by extension, to superabound", "kjv": "abound, abundant, make to increase, have over."}, "G4122": {"greek": "πλεονεκτέω", "translit": "pleonektéō", "pronunciation": "pleh-on-cek-teh'-o", "derivation": "from (G4123);", "definition": "to be covetous, i.e. (by implication) to over-reach", "kjv": "get an advantage, defraud, make a gain."}, "G4123": {"greek": "πλεονέκτης", "translit": "pleonéktēs", "pronunciation": "pleh-on-ek'-tace", "derivation": "from (G4119) and (G2192);", "definition": "holding (desiring) more, i.e. eager for gain (avaricious, hence a defrauder)", "kjv": "covetous."}, "G4124": {"greek": "πλεονεξία", "translit": "pleonexía", "pronunciation": "pleh-on-ex-ee'-ah", "derivation": "from (G4123);", "definition": "avarice, i.e. (by implication) fraudulency, extortion", "kjv": "covetous(-ness) practices, greediness."}, "G4125": {"greek": "πλευρά", "translit": "pleurá", "pronunciation": "plyoo-rah'", "derivation": "of uncertain affinity;", "definition": "a rib, i.e. (by extension) side", "kjv": "side."}, "G4126": {"greek": "πλέω", "translit": "pléō", "pronunciation": "pleh'-o", "derivation": "probably a form of (G4150) (through the idea of plunging through the water);", "definition": "to pass in a vessel", "kjv": "sail."}, "G4127": {"greek": "πληγή", "translit": "plēgḗ", "pronunciation": "play-gay'", "derivation": "from (G4141);", "definition": "a stroke; by implication, a wound; figuratively, a calamity", "kjv": "plague, stripe, wound(-ed)."}, "G4128": {"greek": "πλῆθος", "translit": "plēthos", "pronunciation": "play'-thos", "derivation": "from (G4130);", "definition": "a fulness, i.e. a large number, throng, populace", "kjv": "bundle, company, multitude."}, "G4129": {"greek": "πληθύνω", "translit": "plēthýnō", "pronunciation": "play-thoo'-no", "derivation": "from another form of (G4128);", "definition": "to increase (transitively or intransitively)", "kjv": "abound, multiply."}, "G4130": {"greek": "πλήθω", "translit": "plḗthō", "pronunciation": "play'-tho", "derivation": "a prolonged form of a primary (which appears only as an alternate in certain tenses and in the reduplicated form );", "definition": "to \"fill\" (literally or figuratively (imbue, influence, supply)); specially, to fulfil (time)", "kjv": "accomplish, full (…come), furnish."}, "G4131": {"greek": "πλήκτης", "translit": "plḗktēs", "pronunciation": "plake'-tace", "derivation": "from (G4141);", "definition": "a smiter, i.e. pugnacious (quarrelsome)", "kjv": "striker."}, "G4132": {"greek": "πλήμμυρα", "translit": "plḗmmyra", "pronunciation": "plame-moo'-rah", "derivation": "prolonged from (G4130);", "definition": "flood-tide, i.e. (by analogy) a freshet", "kjv": "flood."}, "G4133": {"greek": "πλήν", "translit": "plḗn", "pronunciation": "plane", "derivation": "from (G4119);", "definition": "moreover (besides), i.e. albeit, save that, rather, yet", "kjv": "but (rather), except, nevertheless, notwithstanding, save, than."}, "G4134": {"greek": "πλήρης", "translit": "plḗrēs", "pronunciation": "play'-race", "derivation": "from (G4130);", "definition": "replete, or covered over; by analogy, complete", "kjv": "full."}, "G4135": {"greek": "πληροφορέω", "translit": "plērophoréō", "pronunciation": "play-rof-or-eh'-o", "derivation": "from (G4134) and (G5409);", "definition": "to carry out fully (in evidence), i.e. completely assure (or convince), entirely accomplish", "kjv": "most surely believe, fully know (persuade), make full proof of."}, "G4136": {"greek": "πληροφορία", "translit": "plērophoría", "pronunciation": "play-rof-or-ee'-ah", "derivation": "from (G4135);", "definition": "entire confidence", "kjv": "(full) assurance."}, "G4137": {"greek": "πληρόω", "translit": "plēróō", "pronunciation": "play-ro'-o", "derivation": "from (G4134);", "definition": "to make replete, i.e. (literally) to cram (a net), level up (a hollow), or (figuratively) to furnish (or imbue, diffuse, influence), satisfy, execute (an office), finish (a period or task), verify (or coincide with a prediction), etc.", "kjv": "accomplish, X after, (be) complete, end, expire, fill (up), fulfil, (be, make) full (come), fully preach, perfect, supply."}, "G4138": {"greek": "πλήρωμα", "translit": "plḗrōma", "pronunciation": "play'-ro-mah", "derivation": "from (G4137);", "definition": "repletion or completion, i.e. (subjectively) what fills (as contents, supplement, copiousness, multitude), or (objectively) what is filled (as container, performance, period)", "kjv": "which is put in to fill up, piece that filled up, fulfilling, full, fulness."}, "G4139": {"greek": "πλησίον", "translit": "plēsíon", "pronunciation": "play-see'-on", "derivation": "neuter of a derivative of (near);", "definition": "(adverbially) close by; as noun, a neighbor, i.e. fellow (as man, countryman, Christian or friend)", "kjv": "near, neighbour."}, "G4140": {"greek": "πλησμονή", "translit": "plēsmonḗ", "pronunciation": "place-mon-ay'", "derivation": "from a presumed derivative of (G4130);", "definition": "a filling up, i.e. (figuratively) gratification", "kjv": "satisfying."}, "G4141": {"greek": "πλήσσω", "translit": "plḗssō", "pronunciation": "place'-so", "derivation": "apparently another form of (G4111) (through the idea of flattening out);", "definition": "to pound, i.e. (figuratively) to inflict with (calamity)", "kjv": "smite."}, "G4142": {"greek": "πλοιάριον", "translit": "ploiárion", "pronunciation": "ploy-ar'-ee-on", "derivation": "neuter of a presumed derivative of (G4143);", "definition": "a boat", "kjv": "boat, little (small) ship."}, "G4143": {"greek": "πλοῖον", "translit": "ploîon", "pronunciation": "ploy'-on", "derivation": "from (G4126);", "definition": "a sailer, i.e. vessel", "kjv": "ship(-ing)."}, "G4144": {"greek": "πλόος", "translit": "plóos", "pronunciation": "plo'-os", "derivation": "from (G4126);", "definition": "a sail, i.e. navigation", "kjv": "course, sailing, voyage."}, "G4145": {"greek": "πλούσιος", "translit": "ploúsios", "pronunciation": "ploo'-see-os", "derivation": "from (G4149);", "definition": "wealthy; figuratively, abounding with", "kjv": "rich."}, "G4146": {"greek": "πλουσίως", "translit": "plousíōs", "pronunciation": "ploo-see'-oce", "derivation": "adverb from (G4145);", "definition": "copiously", "kjv": "abundantly, richly."}, "G4147": {"greek": "πλουτέω", "translit": "ploutéō", "pronunciation": "ploo-teh'-o", "derivation": "from (G4148);", "definition": "to be (or become) wealthy (literally or figuratively)", "kjv": "be increased with goods, (be made, wax) rich."}, "G4148": {"greek": "πλουτίζω", "translit": "ploutízō", "pronunciation": "ploo-tid'-zo", "derivation": "from (G4149);", "definition": "to make wealthy (figuratively)", "kjv": "en- (make) rich."}, "G4149": {"greek": "πλοῦτος", "translit": "ploûtos", "pronunciation": "ploo'-tos", "derivation": "from the base of (G4130);", "definition": "wealth (as fulness), i.e. (literally) money, possessions, or (figuratively) abundance, richness, (specially), valuable bestowment", "kjv": "riches."}, "G4150": {"greek": "πλύνω", "translit": "plýnō", "pronunciation": "ploo'-no", "derivation": "a prolonged form of an obsolete (to \"flow\");", "definition": "to \"plunge\", i.e. launder clothing", "kjv": "wash."}, "G4151": {"greek": "πνεῦμα", "translit": "pneûma", "pronunciation": "pnyoo'-mah", "derivation": "from (G4154);", "definition": "a current of air, i.e. breath (blast) or a breeze; by analogy or figuratively, a spirit, i.e. (human) the rational soul, (by implication) vital principle, mental disposition, etc., or (superhuman) an angel, demon, or (divine) God, Christ's spirit, the Holy Spirit", "kjv": "ghost, life, spirit(-ual, -ually), mind."}, "G4152": {"greek": "πνευματικός", "translit": "pneumatikós", "pronunciation": "pnyoo-mat-ik-os'", "derivation": "from (G4151);", "definition": "non-carnal, i.e. (humanly) ethereal (as opposed to gross), or (dæmoniacally) a spirit (concretely), or (divinely) supernatural, regenerate, religious", "kjv": "spiritual."}, "G4153": {"greek": "πνευματικῶς", "translit": "pneumatikōs", "pronunciation": "pnyoo-mat-ik-oce'", "derivation": "adverb from (G4152);", "definition": "non-physically, i.e. divinely, figuratively", "kjv": "spiritually."}, "G4154": {"greek": "πνέω", "translit": "pnéō", "pronunciation": "pneh'-o", "derivation": "a primary word;", "definition": "to breathe hard, i.e. breeze", "kjv": "blow."}, "G4155": {"greek": "πνίγω", "translit": "pnígō", "pronunciation": "pnee'-go", "derivation": "strengthened from (G4154);", "definition": "to wheeze, i.e. (causative, by implication) to throttle or strangle (drown)", "kjv": "choke, take by the throat."}, "G4156": {"greek": "πνικτός", "translit": "pniktós", "pronunciation": "pnik-tos'", "derivation": "from (G4155);", "definition": "throttled, i.e. (neuter concretely) an animal choked to death (not bled)", "kjv": "strangled."}, "G4157": {"greek": "πνοή", "translit": "pnoḗ", "pronunciation": "pno-ay'", "derivation": "from (G4154);", "definition": "respiration, a breeze", "kjv": "breath, wind."}, "G4158": {"greek": "ποδήρης", "translit": "podḗrēs", "pronunciation": "pod-ay'-race", "derivation": "from (G4228) and another element of uncertain affinity;", "definition": "a dress ((G2066) implied) reaching the ankles", "kjv": "garment down to the foot."}, "G4159": {"greek": "πόθεν", "translit": "póthen", "pronunciation": "poth'-en", "derivation": "from the base of (G4213) with enclitic adverb of origin;", "definition": "from which (as interrogative) or what (as relative) place, state, source or cause", "kjv": "whence."}, "G4160": {"greek": "ποιέω", "translit": "poiéō", "pronunciation": "poy-eh'-o", "derivation": "apparently a prolonged form of an obsolete primary;", "definition": "to make or do (in a very wide application, more or less direct)", "kjv": "abide, + agree, appoint, X avenge, + band together, be, bear, + bewray, bring (forth), cast out, cause, commit, + content, continue, deal, + without any delay, (would) do(-ing), execute, exercise, fulfil, gain, give, have, hold, X journeying, keep, + lay wait, + lighten the ship, make, X mean, + none of these things move me, observe, ordain, perform, provide, + have purged, purpose, put, + raising up, X secure, shew, X shoot out, spend, take, tarry, + transgress the law, work, yield."}, "G4161": {"greek": "ποίημα", "translit": "poíēma", "pronunciation": "poy'-ay-mah", "derivation": "from (G4160);", "definition": "a product, i.e. fabric (literally or figuratively)", "kjv": "thing that is made, workmanship."}, "G4163": {"greek": "ποιητής", "translit": "poiētḗs", "pronunciation": "poy-ay-tace'", "derivation": "from (G4160);", "definition": "a performer; specially, a \"poet\";", "kjv": "doer, poet."}, "G4164": {"greek": "ποικίλος", "translit": "poikílos", "pronunciation": "poy-kee'-los", "derivation": "of uncertain derivation;", "definition": "motley, i.e. various in character", "kjv": "divers, manifold."}, "G4165": {"greek": "ποιμαίνω", "translit": "poimaínō", "pronunciation": "poy-mah'-ee-no", "derivation": "from (G4166);", "definition": "to tend as a shepherd of (figuratively, superviser)", "kjv": "feed (cattle), rule."}, "G4166": {"greek": "ποιμήν", "translit": "poimḗn", "pronunciation": "poy-mane'", "derivation": "of uncertain affinity;", "definition": "a shepherd (literally or figuratively)", "kjv": "shepherd, pastor."}, "G4167": {"greek": "ποίμνη", "translit": "poímnē", "pronunciation": "poym'-nay", "derivation": "contraction from (G4165);", "definition": "a flock (literally or figuratively)", "kjv": "flock, fold."}, "G4168": {"greek": "ποίμνιον", "translit": "poímnion", "pronunciation": "poym'-nee-on", "derivation": "neuter of a presumed derivative of (G4167);", "definition": "a flock, i.e. (figuratively) group (of believers)", "kjv": "flock."}, "G4169": {"greek": "ποῖος", "translit": "poîos", "pronunciation": "poy'-os", "derivation": "from the base of (G4226) and (G3634);", "definition": "individualizing interrogative (of character) what sort of, or (of number) which one", "kjv": "what (manner of), which."}, "G4170": {"greek": "πολεμέω", "translit": "poleméō", "pronunciation": "pol-em-eh'-o", "derivation": "from (G4171);", "definition": "to be (engaged) in warfare, i.e. to battle (literally or figuratively)", "kjv": "fight, (make) war."}, "G4171": {"greek": "πόλεμος", "translit": "pólemos", "pronunciation": "pol'-em-os", "derivation": "from (to bustle);", "definition": "warfare (literally or figuratively; a single encounter or a series)", "kjv": "battle, fight, war."}, "G4172": {"greek": "πόλις", "translit": "pólis", "pronunciation": "pol'-is", "derivation": "probably from the same as (G4171), or perhaps from (G4183);", "definition": "a town (properly, with walls, of greater or less size)", "kjv": "city."}, "G4173": {"greek": "πολιτάρχης", "translit": "politárchēs", "pronunciation": "pol-it-ar'-khace", "derivation": "from (G4172) and (G757);", "definition": "a town-officer, i.e. magistrate", "kjv": "ruler of the city."}, "G4174": {"greek": "πολιτεία", "translit": "politeía", "pronunciation": "pol-ee-ti'-ah", "derivation": "from (G4177) (\"polity\");", "definition": "citizenship; concretely, a community", "kjv": "commonwealth, freedom."}, "G4175": {"greek": "πολίτευμα", "translit": "políteuma", "pronunciation": "pol-it'-yoo-mah", "derivation": "from (G4176);", "definition": "a community, i.e. (abstractly) citizenship (figuratively)", "kjv": "conversation."}, "G4176": {"greek": "πολιτεύομαι", "translit": "politeúomai", "pronunciation": "pol-it-yoo'-om-ahee", "derivation": "middle voice of a derivative of (G4177);", "definition": "to behave as a citizen (figuratively)", "kjv": "let conversation be, live."}, "G4177": {"greek": "πολίτης", "translit": "polítēs", "pronunciation": "pol-ee'-tace", "derivation": "from (G4172);", "definition": "a townsman", "kjv": "citizen."}, "G4178": {"greek": "πολλάκις", "translit": "pollákis", "pronunciation": "pol-lak'-is", "derivation": "multiplicative adverb from (G4183);", "definition": "many times, i.e. frequently", "kjv": "oft(-en, -entimes, -times)."}, "G4179": {"greek": "πολλαπλασίων", "translit": "pollaplasíōn", "pronunciation": "pol-lap-las-ee'-ohn", "derivation": "from (G4183) and probably a derivative of (G4120);", "definition": "manifold, i.e. (neuter as noun) very much more", "kjv": "manifold more."}, "G4180": {"greek": "πολυλογία", "translit": "polylogía", "pronunciation": "pol-oo-log-ee'-ah", "derivation": "from a compound of (G4183) and (G3056);", "definition": "loquacity, i.e. prolixity", "kjv": "much speaking."}, "G4181": {"greek": "πολυμερῶς", "translit": "polymerōs", "pronunciation": "pol-oo-mer'-oce", "derivation": "adverb from a compound of (G4183) and (G3313);", "definition": "in many portions, i.e. variously as to time and agency (piecemeal)", "kjv": "at sundry times."}, "G4182": {"greek": "πολυποίκιλος", "translit": "polypoíkilos", "pronunciation": "pol-oo-poy'-kil-os", "derivation": "from (G4183) and (G4164);", "definition": "much variegated, i.e. multifarious", "kjv": "manifold."}, "G4183": {"greek": "πολύς", "translit": "polýs", "pronunciation": "pol-oos'", "derivation": "including the forms from the alternate ;", "definition": "(singular) much (in any respect) or (plural) many; neuter (singular) as adverbial, largely; neuter (plural) as adverb or noun often, mostly, largely", "kjv": "abundant, + altogether, common, + far (passed, spent), (+ be of a) great (age, deal, -ly, while), long, many, much, oft(-en (-times)), plenteous, sore, straitly."}, "G4184": {"greek": "πολύσπλαγχνος", "translit": "polýsplanchnos", "pronunciation": "pol-oo'-splankh-nos", "derivation": "from (G4183) and (G4698) (figuratively);", "definition": "extremely compassionate", "kjv": "very pitiful."}, "G4185": {"greek": "πολυτελής", "translit": "polytelḗs", "pronunciation": "pol-oo-tel-ace'", "derivation": "from (G4183) and (G5056);", "definition": "extremely expensive", "kjv": "costly, very precious, of great price."}, "G4186": {"greek": "πολύτιμος", "translit": "polýtimos", "pronunciation": "pol-oot'-ee-mos", "derivation": "from (G4183) and (G5092);", "definition": "extremely valuable", "kjv": "very costly, of great price."}, "G4187": {"greek": "πολυτρόπως", "translit": "polytrópōs", "pronunciation": "pol-oot-rop'-oce", "derivation": "adverb from a compound of (G4183) and (G5158);", "definition": "in many ways, i.e. variously as to method or form", "kjv": "in divers manners."}, "G4188": {"greek": "πόμα", "translit": "póma", "pronunciation": "pom'-ah", "derivation": "from the alternate of (G4095);", "definition": "a beverage", "kjv": "drink."}, "G4189": {"greek": "πονηρία", "translit": "ponēría", "pronunciation": "pon-ay-ree'-ah", "derivation": "from (G4190);", "definition": "depravity, i.e. (specially), malice; plural (concretely) plots, sins", "kjv": "iniquity, wickedness."}, "G4190": {"greek": "πονηρός", "translit": "ponērós", "pronunciation": "pon-ay-ros'", "derivation": "from a derivative of (G4192);", "definition": "hurtful, i.e. evil (properly, in effect or influence, and thus differing from (G2556), which refers rather to essential character, as well as from (G4550), which indicates degeneracy from original virtue); figuratively, calamitous; also (passively) ill, i.e. diseased; but especially (morally) culpable, i.e. derelict, vicious, facinorous; neuter (singular) mischief, malice, or (plural) guilt; masculine (singular) the devil, or (plural) sinners", "kjv": "bad, evil, grievous, harm, lewd, malicious, wicked(-ness)."}, "G4192": {"greek": "πόνος", "translit": "pónos", "pronunciation": "pon'-os", "derivation": "from the base of (G3993);", "definition": "toil, i.e. (by implication) anguish", "kjv": "pain."}, "G4193": {"greek": "Ποντικός", "translit": "Pontikós", "pronunciation": "pon-tik-os'", "derivation": "from (G4195);", "definition": "a Pontican, i.e. native of Pontus", "kjv": "born in Pontus."}, "G4194": {"greek": "Πόντιος", "translit": "Póntios", "pronunciation": "pon'-tee-os", "derivation": "of Latin origin;", "definition": "apparently bridged; Pontius, a Roman", "kjv": "Pontius."}, "G4195": {"greek": "Πόντος", "translit": "Póntos", "pronunciation": "pon'-tos", "derivation": "of Latin origin;", "definition": "a sea; Pontus, a region of Asia Minor", "kjv": "Pontus."}, "G4196": {"greek": "Πόπλιος", "translit": "Póplios", "pronunciation": "pop'-lee-os", "derivation": "of Latin origin;", "definition": "apparently \"popular\"; Poplius (i.e. Publius), a Roman", "kjv": "Publius."}, "G4197": {"greek": "πορεία", "translit": "poreía", "pronunciation": "por-i'-ah", "derivation": "from (G4198);", "definition": "travel (by land); figuratively (plural) proceedings, i.e. career", "kjv": "journey(-ing), ways."}, "G4198": {"greek": "πορεύομαι", "translit": "poreúomai", "pronunciation": "por-yoo'-om-ahee", "derivation": "middle voice from a derivative of the same as (G3984);", "definition": "to traverse, i.e. travel (literally or figuratively; especially to remove (figuratively, die), live, etc.);", "kjv": "depart, go (away, forth, one's way, up), (make a, take a) journey, walk."}, "G4199": {"greek": "πορθέω", "translit": "porthéō", "pronunciation": "por-theh'-o", "derivation": "prolongation from (to sack);", "definition": "to ravage (figuratively)", "kjv": "destroy, waste."}, "G4200": {"greek": "πορισμός", "translit": "porismós", "pronunciation": "por-is-mos'", "derivation": "from a derivative of (a way, i.e. means);", "definition": "furnishing (procuring), i.e. (by implication) money-getting (acquisition)", "kjv": "gain."}, "G4201": {"greek": "Πόρκιος", "translit": "Pórkios", "pronunciation": "por'-kee-os", "derivation": "of Latin origin;", "definition": "apparently swinish; Porcius, a Roman", "kjv": "Porcius."}, "G4202": {"greek": "πορνεία", "translit": "porneía", "pronunciation": "por-ni'-ah", "derivation": "from (G4203);", "definition": "harlotry (including adultery and incest); figuratively, idolatry", "kjv": "fornication."}, "G4203": {"greek": "πορνεύω", "translit": "porneúō", "pronunciation": "porn-yoo'-o", "derivation": "from (G4204);", "definition": "to act the harlot, i.e. (literally) indulge unlawful lust (of either sex), or (figuratively) practise idolatry", "kjv": "commit (fornication)."}, "G4204": {"greek": "πόρνη", "translit": "pórnē", "pronunciation": "por'-nay", "derivation": "feminine of (G4205);", "definition": "a strumpet; figuratively, an idolater", "kjv": "harlot, whore."}, "G4205": {"greek": "πόρνος", "translit": "pórnos", "pronunciation": "por'-nos", "derivation": "from (to sell; akin to the base of (G4097));", "definition": "a (male) prostitute (as venal), i.e. (by analogy) a debauchee (libertine)", "kjv": "fornicator, whoremonger."}, "G4206": {"greek": "πόῤῥω", "translit": "pórrhō", "pronunciation": "por'-rho", "derivation": "adverb from (G4253);", "definition": "forwards, i.e. at a distance", "kjv": "far, a great way off."}, "G4207": {"greek": "πόῤῥωθεν", "translit": "pórrhōthen", "pronunciation": "por'-rho-then", "derivation": "from (G4206) with adverbial enclitic of source;", "definition": "from far, or (by implication) at a distance, i.e. distantly", "kjv": "afar off."}, "G4208": {"greek": "ποῤῥωτέρω", "translit": "porrhōtérō", "pronunciation": "por-rho-ter'-o", "derivation": "adverb comparative of (G4206);", "definition": "further, i.e. a greater distance", "kjv": "farther."}, "G4209": {"greek": "πορφύρα", "translit": "porphýra", "pronunciation": "por-foo'-rah", "derivation": "of Latin origin;", "definition": "the \"purple\" mussel, i.e. (by implication) the red-blue color itself, and finally a garment dyed with it", "kjv": "purple."}, "G4210": {"greek": "πορφυροῦς", "translit": "porphyroûs", "pronunciation": "por-foo-rooce'", "derivation": "from (G4209);", "definition": "purpureal, i.e. bluish red", "kjv": "purple."}, "G4211": {"greek": "πορφυρόπωλις", "translit": "porphyrópōlis", "pronunciation": "por-foo-rop'-o-lis", "derivation": "feminine of a compound of (G4209) and (G4453);", "definition": "a female trader in purple cloth", "kjv": "seller of purple."}, "G4212": {"greek": "ποσάκις", "translit": "posákis", "pronunciation": "pos-ak'-is", "derivation": "multiplicative from (G4214);", "definition": "how many times", "kjv": "how oft(-en)."}, "G4213": {"greek": "πόσις", "translit": "pósis", "pronunciation": "pos'-is", "derivation": "from the alternate of (G4095);", "definition": "a drinking (the act), i.e. (concretely) a draught", "kjv": "drink."}, "G4214": {"greek": "πόσος", "translit": "pósos", "pronunciation": "pos'-os", "derivation": "from an absolute (who, what) and (G3739);", "definition": "interrogative pronoun (of amount) how much (large, long or (plural) many)", "kjv": "how great (long, many), what."}, "G4215": {"greek": "ποταμός", "translit": "potamós", "pronunciation": "pot-am-os'", "derivation": "probably from a derivative of the alternate of (G4095) (compare (G4224));", "definition": "a current, brook or freshet (as drinkable), i.e. running water", "kjv": "flood, river, stream, water."}, "G4216": {"greek": "ποταμοφόρητος", "translit": "potamophórētos", "pronunciation": "pot-am-of-or'-ay-tos", "derivation": "from (G4215) and a derivative of (G5409);", "definition": "river-borne, i.e. overwhelmed by a stream", "kjv": "carried away of the flood."}, "G4217": {"greek": "ποταπός", "translit": "potapós", "pronunciation": "pot-ap-os'", "derivation": "apparently from (G4219) and the base of (G4226);", "definition": "interrogatively, whatever, i.e. of what possible sort", "kjv": "what (manner of)."}, "G4218": {"greek": "ποτέ", "translit": "poté", "pronunciation": "pot-eh'", "derivation": "from the base of (G4225) and (G5037);", "definition": "indefinite adverb, at some time, ever", "kjv": "afore-(any, some-)time(-s), at length (the last), (+ n- )ever, in the old time, in time past, once, when."}, "G4220": {"greek": "πότερον", "translit": "póteron", "pronunciation": "pot'-er-on", "derivation": "neuter of a comparative of the base of (G4226);", "definition": "interrogative as adverb, which (of two), i.e. is it this or that", "kjv": "whether."}, "G4221": {"greek": "ποτήριον", "translit": "potḗrion", "pronunciation": "pot-ay'-ree-on", "derivation": "neuter of a derivative of the alternate of (G4095);", "definition": "a drinking-vessel; by extension, the contents thereof, i.e. a cupful (draught); figuratively, a lot or fate", "kjv": "cup."}, "G4222": {"greek": "ποτίζω", "translit": "potízō", "pronunciation": "pot-id'-zo", "derivation": "from a derivative of the alternate of (G4095);", "definition": "to furnish drink, irrigate", "kjv": "give (make) to drink, feed, water."}, "G4223": {"greek": "Ποτίολοι", "translit": "Potíoloi", "pronunciation": "pot-ee'-ol-oy", "derivation": "of Latin origin;", "definition": "little wells, i.e. mineral springs; Potioli (i.e. Puteoli), a place in Italy", "kjv": "Puteoli."}, "G4224": {"greek": "πότος", "translit": "pótos", "pronunciation": "pot'-os", "derivation": "from the alternate of (G4095);", "definition": "a drinking-bout or carousal", "kjv": "banqueting."}, "G4225": {"greek": "πού", "translit": "poú", "pronunciation": "poo", "derivation": "genitive case of an indefinite pronoun (some) otherwise obsolete (compare (G4214));", "definition": "as adverb of place, somewhere, i.e. nearly", "kjv": "about, a certain place."}, "G4226": {"greek": "ποῦ", "translit": "poû", "pronunciation": "poo", "derivation": "genitive case of an interrogative pronoun (what) otherwise obsolete (perhaps the same as (G4225) used with the rising slide of inquiry);", "definition": "as adverb of place; at (by implication, to) what locality", "kjv": "where, whither."}, "G4227": {"greek": "Πούδης", "translit": "Poúdēs", "pronunciation": "poo'-dace", "derivation": "of Latin origin;", "definition": "modest; Pudes (i.e. Pudens), a Christian", "kjv": "Pudens."}, "G4228": {"greek": "πούς", "translit": "poús", "pronunciation": "pooce", "derivation": "a primary word;", "definition": "a \"foot\" (figuratively or literally)", "kjv": "foot(-stool)."}, "G4229": {"greek": "πρᾶγμα", "translit": "prâgma", "pronunciation": "prag'-mah", "derivation": "from (G4238);", "definition": "a deed; by implication, an affair; by extension, an object (material)", "kjv": "business, matter, thing, work."}, "G4230": {"greek": "πραγματεία", "translit": "pragmateía", "pronunciation": "prag-mat-i'-ah", "derivation": "from (G4231);", "definition": "a transaction, i.e. negotiation", "kjv": "affair."}, "G4231": {"greek": "πραγματεύομαι", "translit": "pragmateúomai", "pronunciation": "prag-mat-yoo'-om-ahee", "derivation": "from (G4229);", "definition": "to busy oneself with, i.e. to trade", "kjv": "occupy."}, "G4232": {"greek": "πραιτώριον", "translit": "praitṓrion", "pronunciation": "prahee-to'-ree-on", "derivation": "of Latin origin;", "definition": "the prætorium or governor's courtroom (sometimes including the whole edifice and camp)", "kjv": "(common, judgment) hall (of judgment), palace, prætorium."}, "G4233": {"greek": "πράκτωρ", "translit": "práktōr", "pronunciation": "prak'-tor", "derivation": "from a derivative of (G4238);", "definition": "a practiser, i.e. (specially), an official collector", "kjv": "officer."}, "G4234": {"greek": "πρᾶξις", "translit": "prâxis", "pronunciation": "prax'-is", "derivation": "from (G4238);", "definition": "practice, i.e. (concretely) an act; by extension, a function", "kjv": "deed, office, work."}, "G4236": {"greek": "πρᾳότης", "translit": "praiótēs", "pronunciation": "prah-ot'-ace", "derivation": "from (G4235);", "definition": "gentleness, by implication, humility", "kjv": "meekness."}, "G4237": {"greek": "πρασιά", "translit": "prasiá", "pronunciation": "pras-ee-ah'", "derivation": "perhaps from (a leek, and so an onion-patch);", "definition": "a garden plot, i.e. (by implication, of regular beds) a row (repeated in plural by Hebraism, to indicate an arrangement)", "kjv": "in ranks."}, "G4238": {"greek": "πράσσω", "translit": "prássō", "pronunciation": "pras'-so", "derivation": "a primary verb;", "definition": "to \"practise\", i.e. perform repeatedly or habitually (thus differing from (G4160), which properly refers to a single act); by implication, to execute, accomplish, etc.; specially, to collect (dues), fare (personally)", "kjv": "commit, deeds, do, exact, keep, require, use arts."}, "G4239": {"greek": "πραΰς", "translit": "praÿs", "pronunciation": "prah-ooce'", "derivation": "apparently a primary word;", "definition": "mild, i.e. (by implication) humble", "kjv": "meek."}, "G4240": {"greek": "πραΰτης", "translit": "praÿtēs", "pronunciation": "prah-oo'-tace", "derivation": "from (G4239);", "definition": "mildness, i.e. (by implication) humility", "kjv": "meekness."}, "G4241": {"greek": "πρέπω", "translit": "prépō", "pronunciation": "prep'-o", "derivation": "apparently a primary verb;", "definition": "to tower up (be conspicuous), i.e. (by implication) to be suitable or proper (third person singular present indicative, often used impersonally, it is fit or right)", "kjv": "become, comely."}, "G4242": {"greek": "πρεσβεία", "translit": "presbeía", "pronunciation": "pres-bi'-ah", "derivation": "from (G4243);", "definition": "seniority (eldership), i.e. (by implication) an embassy (concretely, ambassadors)", "kjv": "ambassage, message."}, "G4243": {"greek": "πρεσβεύω", "translit": "presbeúō", "pronunciation": "pres-byoo'-o", "derivation": "from the base of (G4245);", "definition": "to be a senior, i.e. (by implication) act as a representative (figuratively, preacher)", "kjv": "be an ambassador."}, "G4244": {"greek": "πρεσβυτέριον", "translit": "presbytérion", "pronunciation": "pres-boo-ter'-ee-on", "derivation": "neuter of a presumed derivative of (G4245);", "definition": "the order of elders, i.e. (specially), Israelite Sanhedrin or Christian \"presbytery\"", "kjv": "(estate of) elder(-s), presbytery."}, "G4245": {"greek": "πρεσβύτερος", "translit": "presbýteros", "pronunciation": "pres-boo'-ter-os", "derivation": "compound of (elderly);", "definition": "older; as noun, a senior; specially, an Israelite Sanhedrist (also figuratively, member of the celestial council) or Christian \"presbyter\"", "kjv": "elder(-est), old."}, "G4246": {"greek": "πρεσβύτης", "translit": "presbýtēs", "pronunciation": "pres-boo'-tace", "derivation": "from the same as (G4245);", "definition": "an old man", "kjv": "aged (man), old man."}, "G4247": {"greek": "πρεσβῦτις", "translit": "presbŷtis", "pronunciation": "pres-boo'-tis", "derivation": "feminine of (G4246);", "definition": "an old woman", "kjv": "aged woman."}, "G4248": {"greek": "πρηνής", "translit": "prēnḗs", "pronunciation": "pray-nace'", "derivation": "from (G4253);", "definition": "leaning (falling) forward (\"prone\"), i.e. head foremost", "kjv": "headlong."}, "G4249": {"greek": "πρίζω", "translit": "prízō", "pronunciation": "prid'-zo", "derivation": "a strengthened form of a primary prio (to saw);", "definition": "to saw in two", "kjv": "saw asunder."}, "G4250": {"greek": "πρίν", "translit": "prín", "pronunciation": "prin", "derivation": "adverb from (G4253);", "definition": "prior, sooner", "kjv": "before (that), ere."}, "G4251": {"greek": "Πρίσκα", "translit": "Príska", "pronunciation": "pris'-kah", "derivation": "of Latin origin;", "definition": "feminine of Priscus, ancient; Priska, a Christian woman", "kjv": "Prisca."}, "G4252": {"greek": "Πρίσκιλλα", "translit": "Prískilla", "pronunciation": "pris'-cil-lah", "derivation": "diminutive of (G4251);", "definition": "Priscilla (i.e. little Prisca), a Christian woman", "kjv": "Priscilla."}, "G4253": {"greek": "πρό", "translit": "pró", "pronunciation": "pro", "derivation": "a primary preposition;", "definition": "\"fore\", i.e. in front of, prior (figuratively, superior) to", "kjv": "above, ago, before, or ever."}, "G4254": {"greek": "προάγω", "translit": "proágō", "pronunciation": "pro-ag'-o", "derivation": "from (G4253) and (G71);", "definition": "to lead forward (magisterially); intransitively, to precede (in place or time [particle previous])", "kjv": "bring (forth, out), go before."}, "G4255": {"greek": "προαιρέομαι", "translit": "proairéomai", "pronunciation": "pro-ahee-reh'-om-ahee", "derivation": "from (G4253) and (G138);", "definition": "to choose for oneself before another thing (prefer), i.e. (by implication) to propose (intend)", "kjv": "purpose."}, "G4256": {"greek": "προαιτιάομαι", "translit": "proaitiáomai", "pronunciation": "pro-ahee-tee-ah'-om-ahee", "derivation": "from (G4253) and a derivative of (G156);", "definition": "to accuse already, i.e. previously charge", "kjv": "prove before."}, "G4257": {"greek": "προακούω", "translit": "proakoúō", "pronunciation": "pro-ak-oo'-o", "derivation": "from (G4253) and (G191);", "definition": "to hear already,i.e. anticipate", "kjv": "hear before."}, "G4258": {"greek": "προαμαρτάνω", "translit": "proamartánō", "pronunciation": "pro-am-ar-tan'-o", "derivation": "from (G4253) and (G264);", "definition": "to sin previously (to conversion)", "kjv": "sin already, heretofore sin."}, "G4259": {"greek": "προαύλιον", "translit": "proaúlion", "pronunciation": "pro-ow'-lee-on", "derivation": "neuter of a presumed compound of (G4253) and (G833);", "definition": "a forecourt, i.e. vestibule (alley-way)", "kjv": "porch."}, "G4260": {"greek": "προβαίνω", "translit": "probaínō", "pronunciation": "prob-ah'-ee-no", "derivation": "from (G4253) and the base of (G939);", "definition": "to walk forward, i.e. advance (literally, or in years)", "kjv": "+ be of a great age, go farther (on), be well stricken."}, "G4261": {"greek": "προβάλλω", "translit": "probállō", "pronunciation": "prob-al'-lo", "derivation": "from (G4253) and (G906);", "definition": "to throw forward, i.e. push to the front, germinate", "kjv": "put forward, shoot forth."}, "G4262": {"greek": "προβατικός", "translit": "probatikós", "pronunciation": "prob-at-ik-os'", "derivation": "from (G4263);", "definition": "relating to sheep, i.e. (a gate) through which they were led into Jerusalem", "kjv": "sheep (market)."}, "G4263": {"greek": "πρόβατον", "translit": "próbaton", "pronunciation": "prob'-at-on", "derivation": "probably neuter of a presumed derivative of (G4260);", "definition": "something that walks forward (a quadruped), i.e. (specially), a sheep (literally or figuratively)", "kjv": "sheep(-fold)."}, "G4264": {"greek": "προβιβάζω", "translit": "probibázō", "pronunciation": "prob-ib-ad'-zo", "derivation": "from (G4253) and a reduplicated form of (G971);", "definition": "to force forward, i.e. bring to the front, instigate", "kjv": "draw, before instruct."}, "G4265": {"greek": "προβλέπω", "translit": "problépō", "pronunciation": "prob-lep'-o", "derivation": "from (G4253) and (G991);", "definition": "to look out beforehand, i.e. furnish in advance", "kjv": "provide."}, "G4266": {"greek": "προγίνομαι", "translit": "progínomai", "pronunciation": "prog-in'-om-ahee", "derivation": "from (G4253) and (G1096);", "definition": "to be already, i.e. have previousy transpired", "kjv": "be past."}, "G4267": {"greek": "προγινώσκω", "translit": "proginṓskō", "pronunciation": "prog-in-oce'-ko", "derivation": "from (G4253) and (G1097);", "definition": "to know beforehand, i.e. foresee", "kjv": "foreknow (ordain), know (before)."}, "G4268": {"greek": "πρόγνωσις", "translit": "prógnōsis", "pronunciation": "prog'-no-sis", "derivation": "from (G4267);", "definition": "forethought", "kjv": "foreknowledge."}, "G4269": {"greek": "πρόγονος", "translit": "prógonos", "pronunciation": "prog'-on-os", "derivation": "from (G4266);", "definition": "an ancestor, (grand-)parent", "kjv": "forefather, parent."}, "G4270": {"greek": "προγράφω", "translit": "prográphō", "pronunciation": "prog-raf'-o", "derivation": "from (G4253) and (G1125);", "definition": "to write previously; figuratively, to announce, prescribe", "kjv": "before ordain, evidently set forth, write (afore, aforetime)."}, "G4271": {"greek": "πρόδηλος", "translit": "pródēlos", "pronunciation": "prod'-ay-los", "derivation": "from (G4253) and (G1212);", "definition": "plain before all men, i.e. obvious", "kjv": "evident, manifest (open) beforehand."}, "G4272": {"greek": "προδίδωμι", "translit": "prodídōmi", "pronunciation": "prod-id'-o-mee", "derivation": "from (G4253) and (G1325);", "definition": "to give before the other party has given", "kjv": "first give."}, "G4273": {"greek": "προδότης", "translit": "prodótēs", "pronunciation": "prod-ot'-ace", "derivation": "from (G4272) (in the sense of giving forward into another's (the enemy's) hands);", "definition": "a surrender", "kjv": "betrayer, traitor."}, "G4274": {"greek": "πρόδρομος", "translit": "pródromos", "pronunciation": "prod'-rom-os", "derivation": "from the alternate of (G4390);", "definition": "a runner ahead, i.e. scout (figuratively, precursor)", "kjv": "forerunner."}, "G4276": {"greek": "προελπίζω", "translit": "proelpízō", "pronunciation": "pro-el-pid'-zo", "derivation": "from (G4253) and (G1679);", "definition": "to hope in advance of other confirmation", "kjv": "first trust."}, "G4278": {"greek": "προενάρχομαι", "translit": "proenárchomai", "pronunciation": "pro-en-ar'-khom-ahee", "derivation": "from (G4253) and (G1728);", "definition": "to commence already", "kjv": "begin (before)."}, "G4279": {"greek": "προεπαγγέλλομαι", "translit": "proepangéllomai", "pronunciation": "pro-ep-ang-ghel'-lom-ahee", "derivation": "middle voice from (G4253) and (G1861);", "definition": "to promise of old", "kjv": "promise before."}, "G4280": {"greek": "προερέω", "translit": "proeréō", "pronunciation": "pro-er-eh'-o", "derivation": "from (G4253) and (G2046);", "definition": "used as alternate of (G4277); to say already, predict", "kjv": "foretell, say (speak, tell) before."}, "G4281": {"greek": "προέρχομαι", "translit": "proérchomai", "pronunciation": "pro-er'-khom-ahee", "derivation": "from (G4253) and (G2064) (including its alternate);", "definition": "to go onward, precede (in place or time)", "kjv": "go before (farther, forward), outgo, pass on."}, "G4282": {"greek": "προετοιμάζω", "translit": "proetoimázō", "pronunciation": "pro-et-oy-mad'-zo", "derivation": "from (G4253) and (G2090);", "definition": "to fit up in advance (literally or figuratively)", "kjv": "ordain before, prepare afore."}, "G4283": {"greek": "προευαγγελίζομαι", "translit": "proeuangelízomai", "pronunciation": "pro-yoo-ang-ghel-id'-zom-ahee", "derivation": "middle voice from (G4253) and (G2097);", "definition": "to announce glad news in advance", "kjv": "preach before the gospel."}, "G4284": {"greek": "προέχομαι", "translit": "proéchomai", "pronunciation": "pro-ekh-om-ahee", "derivation": "middle voice from (G4253) and (G2192);", "definition": "to hold oneself before others, i.e. (figuratively) to excel", "kjv": "be better."}, "G4285": {"greek": "προηγέομαι", "translit": "proēgéomai", "pronunciation": "pro-ay-geh'-om-ahee", "derivation": "from (G4253) and (G2233);", "definition": "to lead the way for others, i.e. show deference", "kjv": "prefer."}, "G4286": {"greek": "πρόθεσις", "translit": "próthesis", "pronunciation": "proth'-es-is", "derivation": "from (G4388);", "definition": "a setting forth, i.e. (figuratively) proposal (intention); specially, the show-bread (in the Temple) as exposed before God", "kjv": "purpose, shew(-bread)."}, "G4287": {"greek": "προθέσμιος", "translit": "prothésmios", "pronunciation": "proth-es'-mee-os", "derivation": "from (G4253) and a derivative of (G5087);", "definition": "fixed beforehand, i.e. (feminine with (G2250) implied) a designated day", "kjv": "time appointed."}, "G4288": {"greek": "προθυμία", "translit": "prothymía", "pronunciation": "proth-oo-mee'-ah", "derivation": "from (G4289);", "definition": "predisposition, i.e. alacrity", "kjv": "forwardness of mind, readiness (of mind), ready (willing) mind."}, "G4289": {"greek": "πρόθυμος", "translit": "próthymos", "pronunciation": "proth'-oo-mos", "derivation": "from (G4253) and (G2372);", "definition": "forward in spirit, i.e. predisposed; neuter (as noun) alacrity", "kjv": "ready, willing."}, "G4290": {"greek": "προθύμως", "translit": "prothýmōs", "pronunciation": "proth-oo'-moce", "derivation": "adverb from (G4289);", "definition": "with alacrity", "kjv": "willingly."}, "G4291": {"greek": "προΐστημι", "translit": "proḯstēmi", "pronunciation": "pro-is'-tay-mee", "derivation": "from (G4253) and (G2476);", "definition": "to stand before, i.e. (in rank) to preside, or (by implication) to practise", "kjv": "maintain, be over, rule."}, "G4292": {"greek": "προκαλέομαι", "translit": "prokaléomai", "pronunciation": "prok-al-eh'-om-ahee", "derivation": "middle voice from (G4253) and (G2564);", "definition": "to call forth to oneself (challenge), i.e. (by implication) to irritate", "kjv": "provoke."}, "G4293": {"greek": "προκαταγγέλλω", "translit": "prokatangéllō", "pronunciation": "prok-at-ang-ghel'-lo", "derivation": "from (G4253) and (G2605);", "definition": "to anounce beforehand, i.e. predict, promise", "kjv": "foretell, have notice, (shew) before."}, "G4294": {"greek": "προκαταρτίζω", "translit": "prokatartízō", "pronunciation": "prok-at-ar-tid'-zo", "derivation": "from (G4253) and (G2675);", "definition": "to prepare in advance", "kjv": "make up beforehand."}, "G4295": {"greek": "πρόκειμαι", "translit": "prókeimai", "pronunciation": "prok'-i-mahee", "derivation": "from (G4253) and (G2749);", "definition": "to lie before the view, i.e. (figuratively) to be present (to the mind), to stand forth (as an example or reward)", "kjv": "be first, set before (forth)."}, "G4296": {"greek": "προκηρύσσω", "translit": "prokērýssō", "pronunciation": "prok-ay-rooce'-so", "derivation": "from (G4253) and (G2784);", "definition": "to herald (i.e. proclaim) in advance", "kjv": "before (first) preach."}, "G4297": {"greek": "προκοπή", "translit": "prokopḗ", "pronunciation": "prok-op-ay'", "derivation": "from (G4298);", "definition": "progress, i.e. advancement (subjectively or objectively)", "kjv": "furtherance, profit."}, "G4298": {"greek": "προκόπτω", "translit": "prokóptō", "pronunciation": "prok-op'-to", "derivation": "from (G4253) and (G2875);", "definition": "to drive forward (as if by beating), i.e. (figuratively and intransitively) to advance (in amount, to grow; in time, to be well along)", "kjv": "increase, proceed, profit, be far spent, wax."}, "G4299": {"greek": "πρόκριμα", "translit": "prókrima", "pronunciation": "prok'-ree-mah", "derivation": "from a compound of (G4253) and (G2919);", "definition": "a prejudgment (prejudice), i.e. prepossession", "kjv": "prefer one before another."}, "G4300": {"greek": "προκυρόω", "translit": "prokyróō", "pronunciation": "prok-oo-ro'-o", "derivation": "from (G4253) and (G2964);", "definition": "to ratify previously", "kjv": "confirm before."}, "G4301": {"greek": "προλαμβάνω", "translit": "prolambánō", "pronunciation": "prol-am-ban'-o", "derivation": "from (G4253) and (G2983);", "definition": "to take in advance, i.e. (literally) eat before others have an opportunity; (figuratively) to anticipate, surprise", "kjv": "come aforehand, overtake, take before."}, "G4302": {"greek": "προλέγω", "translit": "prolégō", "pronunciation": "prol-eg'-o", "derivation": "from (G4253) and (G3004);", "definition": "to say beforehand, i.e. predict, forewarn", "kjv": "foretell, tell before."}, "G4303": {"greek": "προμαρτύρομαι", "translit": "promartýromai", "pronunciation": "prom-ar-too'-rom-ahee", "derivation": "from (G4253) and (G3143);", "definition": "to be a witness in advance i.e. predict", "kjv": "testify beforehand."}, "G4304": {"greek": "προμελετάω", "translit": "promeletáō", "pronunciation": "prom-el-et-ah'-o", "derivation": "from (G4253) and (G3191);", "definition": "to premeditate", "kjv": "meditate before."}, "G4305": {"greek": "προμεριμνάω", "translit": "promerimnáō", "pronunciation": "prom-er-im-nah'-o", "derivation": "from (G4253) and (G3309);", "definition": "to care (anxiously) in advance", "kjv": "take thought beforehand."}, "G4306": {"greek": "προνοέω", "translit": "pronoéō", "pronunciation": "pron-o-eh'-o", "derivation": "from (G4253) and (G3539);", "definition": "to consider in advance, i.e. look out for beforehand (actively, by way of maintenance for others; middle voice by way of circumspection for oneself)", "kjv": "provide (for)."}, "G4307": {"greek": "πρόνοια", "translit": "prónoia", "pronunciation": "pron'-oy-ah", "derivation": "from (G4306);", "definition": "forethought, i.e. provident care or supply", "kjv": "providence, provision."}, "G4308": {"greek": "προοράω", "translit": "prooráō", "pronunciation": "pro-or-ah'-o", "derivation": "from (G4253) and (G3708);", "definition": "to behold in advance, i.e. (actively) to notice (another) previously, or (middle voice) to keep in (one's own) view", "kjv": "foresee, see before."}, "G4309": {"greek": "προορίζω", "translit": "proorízō", "pronunciation": "pro-or-id'-zo", "derivation": "from (G4253) and (G3724);", "definition": "to limit in advance, i.e. (figuratively) predetermine", "kjv": "determine before, ordain, predestinate."}, "G4310": {"greek": "προπάσχω", "translit": "propáschō", "pronunciation": "prop-as'-kho", "derivation": "from (G4253) and (G3958);", "definition": "to undergo hardship previously", "kjv": "suffer before."}, "G4311": {"greek": "προπέμπω", "translit": "propémpō", "pronunciation": "prop-em'-po", "derivation": "from (G4253) and (G3992);", "definition": "to send forward, i.e. escort or aid in travel", "kjv": "accompany, bring (forward) on journey (way), conduct forth."}, "G4312": {"greek": "προπετής", "translit": "propetḗs", "pronunciation": "prop-et-ace'", "derivation": "from a compound of (G4253) and (G4098);", "definition": "falling forward, i.e. headlong (figuratively, precipitate)", "kjv": "heady, rash(-ly)."}, "G4313": {"greek": "προπορεύομαι", "translit": "proporeúomai", "pronunciation": "prop-or-yoo'-om-ahee", "derivation": "from (G4253) and (G4198);", "definition": "to precede (as guide or herald)", "kjv": "go before."}, "G4314": {"greek": "πρός", "translit": "prós", "pronunciation": "pros", "derivation": "a strengthened form of (G4253);", "definition": "a preposition of direction; forward to, i.e. toward (with the genitive case, the side of, i.e. pertaining to; with the dative case, by the side of, i.e. near to; usually with the accusative case, the place, time, occasion, or respect, which is the destination of the relation, i.e. whither or for which it is predicated)", "kjv": "about, according to , against, among, at, because of, before, between, (where-)by, for, X at thy house, in, for intent, nigh unto, of, which pertain to, that, to (the end that), X together, to (you) -ward, unto, with(-in)."}, "G4315": {"greek": "προσάββατον", "translit": "prosábbaton", "pronunciation": "pros-ab'-bat-on", "derivation": "from (G4253) and (G4521);", "definition": "a fore-sabbath, i.e. the Sabbath-eve", "kjv": "day before the sabbath."}, "G4316": {"greek": "προσαγορεύω", "translit": "prosagoreúō", "pronunciation": "pros-ag-or-yoo'-o", "derivation": "from (G4314) and a derivative of (G58) (mean to harangue);", "definition": "to address, i.e. salute by name", "kjv": "call."}, "G4317": {"greek": "προσάγω", "translit": "proságō", "pronunciation": "pros-ag'-o", "derivation": "from (G4314) and (G71);", "definition": "to lead towards, i.e. (transitively) to conduct near (summon, present), or (intransitively) to approach", "kjv": "bring, draw near."}, "G4318": {"greek": "προσαγωγή", "translit": "prosagōgḗ", "pronunciation": "pros-ag-ogue-ay'", "derivation": "from (G4317) (compare (G72));", "definition": "admission", "kjv": "access."}, "G4319": {"greek": "προσαιτέω", "translit": "prosaitéō", "pronunciation": "pros-ahee-teh'-o", "derivation": "from (G4314) and (G154);", "definition": "to ask repeatedly (importune), i.e. solicit", "kjv": "beg."}, "G4320": {"greek": "προσαναβαίνω", "translit": "prosanabaínō", "pronunciation": "pros-an-ab-ah'-ee-no", "derivation": "from (G4314) and (G305);", "definition": "to ascend farther, i.e. be promoted (take an upper (more honorable) seat)", "kjv": "go up."}, "G4321": {"greek": "προσαναλίσκω", "translit": "prosanalískō", "pronunciation": "pros-an-al-is'-ko", "derivation": "from (G4314) and (G355);", "definition": "to expend further", "kjv": "spend."}, "G4322": {"greek": "προσαναπληρόω", "translit": "prosanaplēróō", "pronunciation": "pros-an-ap-lay-ro'-o", "derivation": "from (G4314) and (G378);", "definition": "to fill up further, i.e. furnish fully", "kjv": "supply."}, "G4323": {"greek": "προσανατίθημι", "translit": "prosanatíthēmi", "pronunciation": "pros-an-at-ith'-ay-mee", "derivation": "from (G4314) and (G394);", "definition": "to lay up in addition, i.e. (middle voice and figuratively) to impart or (by implication) to consult", "kjv": "in conference add, confer."}, "G4324": {"greek": "προσαπειλέω", "translit": "prosapeiléō", "pronunciation": "pros-ap-i-leh'-o", "derivation": "from (G4314) and (G546);", "definition": "to menace additionally", "kjv": "i."}, "G4325": {"greek": "προσδαπανάω", "translit": "prosdapanáō", "pronunciation": "pros-dap-an-ah'-o", "derivation": "from (G4314) and (G1159);", "definition": "to expend additionally", "kjv": "spend more."}, "G4326": {"greek": "προσδέομαι", "translit": "prosdéomai", "pronunciation": "pros-deh'-om-ahee", "derivation": "from (G4314) and (G1189);", "definition": "to require additionally, i.e. want further", "kjv": "need."}, "G4327": {"greek": "προσδέχομαι", "translit": "prosdéchomai", "pronunciation": "pros-dekh'-om-ahee", "derivation": "from (G4314) and (G1209);", "definition": "to admit (to intercourse, hospitality, credence, or (figuratively) endurance); by implication, to await (with confidence or patience)", "kjv": "accept, allow, look (wait) for, take."}, "G4328": {"greek": "προσδοκάω", "translit": "prosdokáō", "pronunciation": "pros-dok-ah'-o", "derivation": "from (G4314) and dokeuo (to watch);", "definition": "to anticipate (in thought, hope or fear); by implication, to await", "kjv": "(be in) expect(-ation), look (for), when looked, tarry, wait for."}, "G4329": {"greek": "προσδοκία", "translit": "prosdokía", "pronunciation": "pros-dok-ee'-ah", "derivation": "from (G4328);", "definition": "apprehension (of evil); by implication, infliction anticipated", "kjv": "expectation, looking after."}, "G4330": {"greek": "προσεάω", "translit": "proseáō", "pronunciation": "pros-eh-ah'-o", "derivation": "from (G4314) and (G1439);", "definition": "to permit further progress", "kjv": "suffer."}, "G4332": {"greek": "προσεδρεύω", "translit": "prosedreúō", "pronunciation": "pros-ed-ryoo'-o", "derivation": "from a compound of (G4314) and the base of (G1476);", "definition": "to sit near, i.e. attend as a servant", "kjv": "wait at."}, "G4333": {"greek": "προσεργάζομαι", "translit": "prosergázomai", "pronunciation": "pros-er-gad'-zom-ahee", "derivation": "from (G4314) and (G2038);", "definition": "to work additionally, i.e. (by implication) acquire besides", "kjv": "gain."}, "G4334": {"greek": "προσέρχομαι", "translit": "prosérchomai", "pronunciation": "pros-er'-khom-ahee", "derivation": "from (G4314) and (G2064) (including its alternate);", "definition": "to approach, i.e. (literally) come near, visit, or (figuratively) worship, assent to", "kjv": "(as soon as he) come (unto), come thereunto, consent, draw near, go (near, to, unto)."}, "G4335": {"greek": "προσευχή", "translit": "proseuchḗ", "pronunciation": "pros-yoo-khay'", "derivation": "from (G4336);", "definition": "prayer (worship); by implication, an oratory (chapel)", "kjv": "X pray earnestly, prayer."}, "G4336": {"greek": "προσεύχομαι", "translit": "proseúchomai", "pronunciation": "pros-yoo'-khom-ahee", "derivation": "from (G4314) and (G2172);", "definition": "to pray to God, i.e. supplicate, worship", "kjv": "pray (X earnestly, for), make prayer."}, "G4337": {"greek": "προσέχω", "translit": "proséchō", "pronunciation": "pros-ekh'-o", "derivation": "from (G4314) and (G2192);", "definition": "(figuratively) to hold the mind (3563 implied) towards, i.e. pay attention to, be cautious about, apply oneself to, adhere to", "kjv": "(give) attend(-ance, -ance at, -ance to, unto), beware, be given to, give (take) heed (to unto); have regard."}, "G4338": {"greek": "προσηλόω", "translit": "prosēlóō", "pronunciation": "pros-ay-lo'-o", "derivation": "from (G4314) and a derivative of (G2247);", "definition": "to peg to, i.e. spike fast", "kjv": "nail to."}, "G4339": {"greek": "προσήλυτος", "translit": "prosḗlytos", "pronunciation": "pros-ay'-loo-tos", "derivation": "from the alternate of (G4334);", "definition": "an arriver from a foreign region, i.e. (specially), an acceder (convert) to Judaism (\"proselyte\")", "kjv": "proselyte."}, "G4340": {"greek": "πρόσκαιρος", "translit": "próskairos", "pronunciation": "pros'-kahee-ros", "derivation": "from (G4314) and (G2540);", "definition": "for the occasion only, i.e. temporary", "kjv": "dur-(eth) for awhile, endure for a time, for a season, temporal."}, "G4341": {"greek": "προσκαλέομαι", "translit": "proskaléomai", "pronunciation": "pros-kal-eh'-om-ahee", "derivation": "middle voice from (G4314) and (G2564);", "definition": "to call toward oneself, i.e. summon, invite", "kjv": "call (for, to, unto)."}, "G4342": {"greek": "προσκαρτερέω", "translit": "proskarteréō", "pronunciation": "pros-kar-ter-eh'-o", "derivation": "from (G4314) and (G2594);", "definition": "to be earnest towards, i.e. (to a thing) to persevere, be constantly diligent, or (in a place) to attend assiduously all the exercises, or (to a person) to adhere closely to (as a servitor)", "kjv": "attend (give self) continually (upon), continue (in, instant in, with), wait on (continually)."}, "G4343": {"greek": "προσκαρτέρησις", "translit": "proskartérēsis", "pronunciation": "pros-kar-ter'-ay-sis", "derivation": "from (G4342);", "definition": "persistancy", "kjv": "perseverance."}, "G4344": {"greek": "προσκεφάλαιον", "translit": "proskephálaion", "pronunciation": "pros-kef-al'-ahee-on", "derivation": "neuter of a presumed compound of (G4314) and (G2776);", "definition": "something for the head, i.e. a cushion", "kjv": "pillow."}, "G4345": {"greek": "προσκληρόω", "translit": "prosklēróō", "pronunciation": "pros-klay-ro'-o", "derivation": "from (G4314) and (G2820);", "definition": "to give a common lot to, i.e. (figuratively) to associate with", "kjv": "consort with."}, "G4346": {"greek": "πρόσκλισις", "translit": "prósklisis", "pronunciation": "pros'-klis-is", "derivation": "from a compound of (G4314) and (G2827);", "definition": "a leaning towards, i.e. (figuratively) proclivity (favoritism)", "kjv": "partiality."}, "G4347": {"greek": "προσκολλάω", "translit": "proskolláō", "pronunciation": "pros-kol-lah'-o", "derivation": "from (G4314) and (G2853);", "definition": "to glue to, i.e. (figuratively) to adhere", "kjv": "cleave, join (self)."}, "G4348": {"greek": "πρόσκομμα", "translit": "próskomma", "pronunciation": "pros'-kom-mah", "derivation": "from (G4350);", "definition": "a stub, i.e. (figuratively) occasion of apostasy", "kjv": "offence, stumbling(-block, (-stone))."}, "G4349": {"greek": "προσκοπή", "translit": "proskopḗ", "pronunciation": "pros-kop-ay'", "derivation": "from (G4350);", "definition": "a stumbling, i.e. (figuratively and concretely) occasion of sin", "kjv": "offence."}, "G4350": {"greek": "προσκόπτω", "translit": "proskóptō", "pronunciation": "pros-kop'-to", "derivation": "from (G4314) and (G2875);", "definition": "to strike at, i.e. surge against (as water); specially, to stub on, i.e. trip up (literally or figuratively)", "kjv": "beat upon, dash, stumble (at)."}, "G4351": {"greek": "προσκυλίω", "translit": "proskylíō", "pronunciation": "pros-koo-lee'-o", "derivation": "from (G4314) and (G2947);", "definition": "to roll towards, i.e. block against", "kjv": "roll (to)."}, "G4352": {"greek": "προσκυνέω", "translit": "proskynéō", "pronunciation": "pros-koo-neh'-o", "derivation": "from (G4314) and a probable derivative of (G2965) (meaning to kiss, like a dog licking his master's hand);", "definition": "to fawn or crouch to, i.e. (literally or figuratively) prostrate oneself in homage (do reverence to, adore)", "kjv": "worship."}, "G4353": {"greek": "προσκυνητής", "translit": "proskynētḗs", "pronunciation": "pros-koo-nay-tace'", "derivation": "from (G4352);", "definition": "an adorer", "kjv": "worshipper."}, "G4354": {"greek": "προσλαλέω", "translit": "proslaléō", "pronunciation": "pros-lal-eh'-o", "derivation": "from (G4314) and (G2980);", "definition": "to talk to, i.e. converse with", "kjv": "speak to (with)."}, "G4355": {"greek": "προσλαμβάνω", "translit": "proslambánō", "pronunciation": "pros-lam-ban'-o", "derivation": "from (G4314) and (G2983);", "definition": "to take to oneself, i.e. use (food), lead (aside), admit (to friendship or hospitality)", "kjv": "receive, take (unto)."}, "G4356": {"greek": "πρόσληψις", "translit": "próslēpsis", "pronunciation": "pros'-lape-sis", "derivation": "from (G4355);", "definition": "admission", "kjv": "receiving."}, "G4357": {"greek": "προσμένω", "translit": "prosménō", "pronunciation": "pros-men'-o", "derivation": "from (G4314) and (G3306);", "definition": "to stay further, i.e. remain in a place, with a person; figuratively, to adhere to, persevere in", "kjv": "abide still, be with, cleave unto, continue in (with)."}, "G4358": {"greek": "προσορμίζω", "translit": "prosormízō", "pronunciation": "pros-or-mid'-zo", "derivation": "from (G4314) and a derivative of the same as (G3730) (meaning to tie (anchor) or lull);", "definition": "to moor to, i.e. (by implication) land at", "kjv": "draw to the shore."}, "G4359": {"greek": "προσοφείλω", "translit": "prosopheílō", "pronunciation": "pros-of-i'-lo", "derivation": "from (G4314) and (G3784);", "definition": "to be indebted additionally", "kjv": "over besides."}, "G4360": {"greek": "προσοχθίζω", "translit": "prosochthízō", "pronunciation": "pros-okh-thid'-zo", "derivation": "from (G4314) and a form of (to be vexed with something irksome);", "definition": "to feel indignant at", "kjv": "be grieved at."}, "G4361": {"greek": "πρόσπεινος", "translit": "próspeinos", "pronunciation": "pros'-pi-nos", "derivation": "from (G4314) and the same as (G3983);", "definition": "hungering further, i.e. intensely hungry", "kjv": "very hungry."}, "G4362": {"greek": "προσπήγνυμι", "translit": "prospḗgnymi", "pronunciation": "pros-payg'-noo-mee", "derivation": "from (G4314) and (G4078);", "definition": "to fasten to, i.e. (specially), to impale (on a cross)", "kjv": "crucify."}, "G4363": {"greek": "προσπίπτω", "translit": "prospíptō", "pronunciation": "pros-pip'-to", "derivation": "from (G4314) and (G4098);", "definition": "to fall towards, i.e. (gently) prostrate oneself (in supplication or homage), or (violently) to rush upon (in storm)", "kjv": "beat upon, fall (down) at (before)."}, "G4364": {"greek": "προσποιέομαι", "translit": "prospoiéomai", "pronunciation": "pros-poy-eh'-om-ahee", "derivation": "middle voice from (G4314) and (G4160);", "definition": "to do forward for oneself, i.e. pretend (as if about to do a thing)", "kjv": "make as though."}, "G4365": {"greek": "προσπορεύομαι", "translit": "prosporeúomai", "pronunciation": "pros-por-yoo'-om-ahee", "derivation": "from (G4314) and (G4198);", "definition": "to journey towards, i.e. approach (not the same as (G4313))", "kjv": "go before."}, "G4366": {"greek": "προσρήγνυμι", "translit": "prosrḗgnymi", "pronunciation": "pros-rayg'-noo-mee", "derivation": "from (G4314) and (G4486);", "definition": "to tear towards, i.e. burst upon (as a tempest or flood)", "kjv": "beat vehemently against (upon)."}, "G4367": {"greek": "προστάσσω", "translit": "prostássō", "pronunciation": "pros-tas'-so", "derivation": "from (G4314) and (G5021);", "definition": "to arrange towards, i.e. (figuratively) enjoin", "kjv": "bid, command."}, "G4368": {"greek": "προστάτις", "translit": "prostátis", "pronunciation": "pros-tat'-is", "derivation": "feminine of a derivative of (G4291);", "definition": "a patroness, i.e. assistant", "kjv": "succourer."}, "G4369": {"greek": "προστίθημι", "translit": "prostíthēmi", "pronunciation": "pros-tith'-ay-mee", "derivation": "from (G4314) and (G5087);", "definition": "to place additionally, i.e. lay beside, annex, repeat", "kjv": "add, again, give more, increase, lay unto, proceed further, speak to any more."}, "G4370": {"greek": "προστρέχω", "translit": "prostréchō", "pronunciation": "pros-trekh'-o", "derivation": "from (G4314) and (G5143) (including its alternate);", "definition": "to run towards, i.e. hasten to meet or join", "kjv": "run (thither to, to)."}, "G4371": {"greek": "προσφάγιον", "translit": "prosphágion", "pronunciation": "pros-fag'-ee-on", "derivation": "neuter of a presumed derivative of a compound of (G4314) and (G5315);", "definition": "something eaten in addition to bread, i.e. a relish (specially, fish; compare (G3795))", "kjv": "meat."}, "G4372": {"greek": "πρόσφατος", "translit": "prósphatos", "pronunciation": "pros'-fat-os", "derivation": "from (G4253) and a derivative of (G4969);", "definition": "previously (recently) slain (fresh), i.e. (figuratively) lately made", "kjv": "new."}, "G4373": {"greek": "προσφάτως", "translit": "prosphátōs", "pronunciation": "pros-fat'-oce", "derivation": "adverb from (G4372);", "definition": "recently", "kjv": "lately."}, "G4374": {"greek": "προσφέρω", "translit": "prosphérō", "pronunciation": "pros-fer'-o", "derivation": "from (G4314) and (G5342) (including its alternate);", "definition": "to bear towards, i.e. lead to, tender (especially to God), treat", "kjv": "bring (to, unto), deal with, do, offer (unto, up), present unto, put to."}, "G4375": {"greek": "προσφιλής", "translit": "prosphilḗs", "pronunciation": "pros-fee-lace'", "derivation": "from a presumed compound of (G4314) and (G5368);", "definition": "friendly towards, i.e. acceptable", "kjv": "lovely."}, "G4376": {"greek": "προσφορά", "translit": "prosphorá", "pronunciation": "pros-for-ah'", "derivation": "from (G4374);", "definition": "presentation; concretely, an oblation (bloodless) or sacrifice", "kjv": "offering (up)."}, "G4377": {"greek": "προσφωνέω", "translit": "prosphōnéō", "pronunciation": "pros-fo-neh'-o", "derivation": "from (G4314) and (G5455);", "definition": "to sound towards, i.e. address, exclaim, summon", "kjv": "call unto, speak (un-)to."}, "G4378": {"greek": "πρόσχυσις", "translit": "próschysis", "pronunciation": "pros'-khoo-sis", "derivation": "from a comparative of (G4314) and (to pour);", "definition": "a shedding forth, i.e. affusion", "kjv": "sprinkling."}, "G4379": {"greek": "προσψαύω", "translit": "prospsaúō", "pronunciation": "pros-psow'-o", "derivation": "from (G4314) and (to touch);", "definition": "to impinge, i.e. lay a finger on (in order to relieve)", "kjv": "touch."}, "G4380": {"greek": "προσωποληπτέω", "translit": "prosōpolēptéō", "pronunciation": "pros-o-pol-ape-teh'-o", "derivation": "from (G4381);", "definition": "to favor an individual, i.e. show partiality", "kjv": "have respect to persons."}, "G4381": {"greek": "προσωπολήπτης", "translit": "prosōpolḗptēs", "pronunciation": "pros-o-pol-ape'-tace", "derivation": "from (G4383) and (G2983);", "definition": "an accepter of a face (individual), i.e. (specially), one exhibiting partiality", "kjv": "respecter of persons."}, "G4382": {"greek": "προσωποληψία", "translit": "prosōpolēpsía", "pronunciation": "pros-o-pol-ape-see'-ah", "derivation": "from (G4381);", "definition": "partiality, i.e. favoritism", "kjv": "respect of persons."}, "G4383": {"greek": "πρόσωπον", "translit": "prósōpon", "pronunciation": "pros'-o-pon", "derivation": "from (G4314) and (the visage, from (G3700));", "definition": "the front (as being towards view), i.e. the countenance, aspect, appearance, surface; by implication, presence, person", "kjv": "(outward) appearance, X before, countenance, face, fashion, (men's) person, presence."}, "G4385": {"greek": "προτείνω", "translit": "proteínō", "pronunciation": "prot-i'-no", "derivation": "from (G4253) and (to stretch);", "definition": "to protend, i.e. tie prostrate (for scourging)", "kjv": "bind."}, "G4387": {"greek": "πρότερος", "translit": "próteros", "pronunciation": "prot'-er-os", "derivation": "comparative of (G4253);", "definition": "prior or previous", "kjv": "former."}, "G4388": {"greek": "προτίθεμαι", "translit": "protíthemai", "pronunciation": "prot-ith'-em-ahee", "derivation": "middle voice from (G4253) and (G5087);", "definition": "to place before, i.e. (for oneself) to exhibit; (to oneself) to propose (determine)", "kjv": "purpose, set forth."}, "G4389": {"greek": "προτρέπομαι", "translit": "protrépomai", "pronunciation": "prot-rep'-om-ahee", "derivation": "middle voice from (G4253) and the base of (G5157);", "definition": "to turn forward for oneself, i.e. encourage", "kjv": "exhort."}, "G4390": {"greek": "προτρέχω", "translit": "protréchō", "pronunciation": "prot-rekh'-o", "derivation": "from (G4253) and (G5143) (including its alternate);", "definition": "to run forward, i.e. outstrip, precede", "kjv": "outrun, run before."}, "G4391": {"greek": "προϋπάρχω", "translit": "proÿpárchō", "pronunciation": "pro-oop-ar'-kho", "derivation": "from (G4253) and (G5225);", "definition": "to exist before, i.e. (adverbially) to be or do something previously", "kjv": "+ be before(-time)."}, "G4392": {"greek": "πρόφασις", "translit": "próphasis", "pronunciation": "prof'-as-is", "derivation": "from a compound of (G4253) and (G5316);", "definition": "an outward showing, i.e. pretext", "kjv": "cloke, colour, pretence, show."}, "G4393": {"greek": "προφέρω", "translit": "prophérō", "pronunciation": "prof-er'-o", "derivation": "from (G4253) and (G5342);", "definition": "to bear forward, i.e. produce", "kjv": "bring forth."}, "G4394": {"greek": "προφητεία", "translit": "prophēteía", "pronunciation": "prof-ay-ti'-ah", "derivation": "from (G4396) (\"prophecy\");", "definition": "prediction (scriptural or other)", "kjv": "prophecy, prophesying."}, "G4395": {"greek": "προφητεύω", "translit": "prophēteúō", "pronunciation": "prof-ate-yoo'-o", "derivation": "from (G4396);", "definition": "to foretell events, divine, speak under inspiration, exercise the prophetic office", "kjv": "prophesy."}, "G4396": {"greek": "προφήτης", "translit": "prophḗtēs", "pronunciation": "prof-ay'-tace", "derivation": "from a compound of (G4253) and (G5346);", "definition": "a foreteller (\"prophet\"); by analogy, an inspired speaker; by extension, a poet", "kjv": "prophet."}, "G4397": {"greek": "προφητικός", "translit": "prophētikós", "pronunciation": "prof-ay-tik-os'", "derivation": "from (G4396);", "definition": "pertaining to a foreteller (\"prophetic\")", "kjv": "of prophecy, of the prophets."}, "G4398": {"greek": "προφῆτις", "translit": "prophētis", "pronunciation": "prof-ay'-tis", "derivation": "feminine of (G4396);", "definition": "a female foreteller or an inspired woman", "kjv": "prophetess."}, "G4399": {"greek": "προφθάνω", "translit": "prophthánō", "pronunciation": "prof-than'-o", "derivation": "from (G4253) and (G5348);", "definition": "to get an earlier start of, i.e. anticipate", "kjv": "prevent."}, "G4400": {"greek": "προχειρίζομαι", "translit": "procheirízomai", "pronunciation": "prokh-i-rid'-zom-ahee", "derivation": "middle voice from (G4253) and a derivative of (G5495);", "definition": "to handle for oneself in advance, i.e. (figuratively) to purpose", "kjv": "choose, make."}, "G4401": {"greek": "προχειροτονέω", "translit": "procheirotonéō", "pronunciation": "prokh-i-rot-on-eh'-o", "derivation": "from (G4253) and (G5500);", "definition": "to elect in advance", "kjv": "choose before."}, "G4402": {"greek": "Πρόχορος", "translit": "Próchoros", "pronunciation": "prokh'-or-os", "derivation": "from (G4253) and (G5525);", "definition": "before the dance; Prochorus, a Christian", "kjv": "Prochorus."}, "G4403": {"greek": "πρύμνα", "translit": "prýmna", "pronunciation": "proom'-nah", "derivation": "feminine of (hindmost);", "definition": "the stern of a ship", "kjv": "hinder part, stern."}, "G4404": {"greek": "πρωΐ", "translit": "prōḯ", "pronunciation": "pro-ee'", "derivation": "adverb from (G4253);", "definition": "at dawn; by implication, the day-break watch", "kjv": "early (in the morning), (in the) morning."}, "G4405": {"greek": "πρωΐα", "translit": "prōḯa", "pronunciation": "pro-ee'-ah", "derivation": "feminine of a derivative of (G4404) as noun;", "definition": "day-dawn", "kjv": "early, morning."}, "G4406": {"greek": "πρώϊμος", "translit": "prṓïmos", "pronunciation": "pro'-ee-mos", "derivation": "from (G4404);", "definition": "dawning, i.e. (by analogy) autumnal (showering, the first of the rainy season)", "kjv": "early."}, "G4407": {"greek": "πρωϊνός", "translit": "prōïnós", "pronunciation": "pro-ee-nos'", "derivation": "from (G4404);", "definition": "pertaining to the dawn, i.e. matutinal", "kjv": "morning."}, "G4408": {"greek": "πρῶρα", "translit": "prōra", "pronunciation": "pro'-ra", "derivation": "feminine of a presumed derivative of (G4253) as noun;", "definition": "the prow, i.e. forward part of a vessel", "kjv": "forepart(-ship)."}, "G4409": {"greek": "πρωτεύω", "translit": "prōteúō", "pronunciation": "prote-yoo'-o", "derivation": "from (G4413);", "definition": "to be first (in rank or influence)", "kjv": "have the preeminence."}, "G4410": {"greek": "πρωτοκαθεδρία", "translit": "prōtokathedría", "pronunciation": "pro-tok-ath-ed-ree'-ah", "derivation": "from (G4413) and (G2515);", "definition": "a sitting first (in the front row), i.e. preeminence in council", "kjv": "chief (highest, uppermost) seat."}, "G4411": {"greek": "πρωτοκλισία", "translit": "prōtoklisía", "pronunciation": "pro-tok-lis-ee'-ah", "derivation": "from (G4413) and (G2828);", "definition": "a reclining first (in the place of honor) at the dinner-bed, i.e. preeminence at meals", "kjv": "chief (highest, uppermost) room."}, "G4412": {"greek": "πρῶτον", "translit": "prōton", "pronunciation": "pro'-ton", "derivation": "neuter of (G4413) as adverb (with or without (G3588));", "definition": "firstly (in time, place, order, or importance)", "kjv": "before, at the beginning, chiefly (at, at the) first (of all)."}, "G4413": {"greek": "πρῶτος", "translit": "prōtos", "pronunciation": "pro'-tos", "derivation": "contracted superlative of (G4253);", "definition": "foremost (in time, place, order or importance)", "kjv": "before, beginning, best, chief(-est), first (of all), former."}, "G4414": {"greek": "πρωτοστάτης", "translit": "prōtostátēs", "pronunciation": "pro-tos-tat'-ace", "derivation": "from (G4413) and (G2476);", "definition": "one standing first in the ranks, i.e. a captain (champion)", "kjv": "ringleader."}, "G4415": {"greek": "πρωτοτόκια", "translit": "prōtotókia", "pronunciation": "pro-tot-ok'-ee-ah", "derivation": "from (G4416);", "definition": "primogeniture (as a privilege)", "kjv": "birthright."}, "G4416": {"greek": "πρωτότοκος", "translit": "prōtótokos", "pronunciation": "pro-tot-ok'-os", "derivation": "from (G4413) and the alternate of (G5088);", "definition": "first-born (usually as noun, literally or figuratively)", "kjv": "firstbegotten(-born)."}, "G4417": {"greek": "πταίω", "translit": "ptaíō", "pronunciation": "ptah'-yo", "derivation": "a form of (G4098);", "definition": "to trip, i.e. (figuratively) to err, sin, fail (of salvation)", "kjv": "fall, offend, stumble."}, "G4418": {"greek": "πτέρνα", "translit": "ptérna", "pronunciation": "pter'-nah", "derivation": "of uncertain derivation;", "definition": "the heel (figuratively)", "kjv": "heel."}, "G4419": {"greek": "πτερύγιον", "translit": "pterýgion", "pronunciation": "pter-oog'-ee-on", "derivation": "neuter of a presumed derivative of (G4420);", "definition": "a winglet, i.e. (figuratively) extremity (top corner)", "kjv": "pinnacle."}, "G4420": {"greek": "πτέρυξ", "translit": "ptéryx", "pronunciation": "pter'-oox", "derivation": "from a derivative of (G4072) (meaning a feather);", "definition": "a wing", "kjv": "wing."}, "G4421": {"greek": "πτηνόν", "translit": "ptēnón", "pronunciation": "ptay-non'", "derivation": "contraction for (G4071);", "definition": "a bird", "kjv": "bird."}, "G4422": {"greek": "πτοέω", "translit": "ptoéō", "pronunciation": "pto-eh'-o", "derivation": "probably akin to the alternate of (G4098) (through the idea of causing to fall) or to (G4072) (through that of causing to fly away);", "definition": "to scare", "kjv": "frighten."}, "G4423": {"greek": "πτόησις", "translit": "ptóēsis", "pronunciation": "pto'-ay-sis", "derivation": "from (G4422);", "definition": "alarm", "kjv": "amazement."}, "G4424": {"greek": "Πτολεμαΐς", "translit": "Ptolemaḯs", "pronunciation": "ptol-em-ah-is'", "derivation": "from (Ptolemy, after whom it was named);", "definition": "Ptolemais, a place in Palestine", "kjv": "Ptolemais."}, "G4425": {"greek": "πτύον", "translit": "ptýon", "pronunciation": "ptoo'-on", "derivation": "from (G4429);", "definition": "a winnowing-fork (as scattering like spittle)", "kjv": "fan."}, "G4426": {"greek": "πτύρω", "translit": "ptýrō", "pronunciation": "ptoo'-ro", "derivation": "from a presumed derivative of (G4429) (and thus akin to (G4422));", "definition": "to frighten", "kjv": "terrify."}, "G4427": {"greek": "πτύσμα", "translit": "ptýsma", "pronunciation": "ptoos'-mah", "derivation": "from (G4429);", "definition": "saliva", "kjv": "spittle."}, "G4428": {"greek": "πτύσσω", "translit": "ptýssō", "pronunciation": "ptoos'-so", "derivation": "probably akin to (to spread;", "definition": "and thus apparently allied to (G4072) through the idea of expansion, and to 4429 through that of flattening; compare (G3961)); to fold, i.e. furl a scroll", "kjv": "close."}, "G4429": {"greek": "πτύω", "translit": "ptýō", "pronunciation": "ptoo'-o", "derivation": "a primary verb (compare (G4428));", "definition": "to spit", "kjv": "spit."}, "G4430": {"greek": "πτῶμα", "translit": "ptōma", "pronunciation": "pto'-mah", "derivation": "from the alternate of (G4098);", "definition": "a ruin, i.e. (specially), lifeless body (corpse, carrion)", "kjv": "dead body, carcase, corpse."}, "G4431": {"greek": "πτῶσις", "translit": "ptōsis", "pronunciation": "pto'-sis", "derivation": "from the alternate of (G4098);", "definition": "a crash, i.e. downfall (literally or figuratively)", "kjv": "fall."}, "G4432": {"greek": "πτωχεία", "translit": "ptōcheía", "pronunciation": "pto-khi'-ah", "derivation": "from (G4433);", "definition": "beggary, i.e. indigence (literally or figuratively)", "kjv": "poverty."}, "G4433": {"greek": "πτωχεύω", "translit": "ptōcheúō", "pronunciation": "pto-khyoo'-o", "derivation": "from (G4434);", "definition": "to be a beggar, i.e. (by implication) to become indigent (figuratively)", "kjv": "become poor."}, "G4434": {"greek": "πτωχός", "translit": "ptōchós", "pronunciation": "pto-khos'", "derivation": "from (to crouch);", "definition": "akin to (G4422) and the alternate of (G4098)); a beggar (as cringing), i.e. pauper (strictly denoting absolute or public mendicancy, although also used in a qualified or relative sense; whereas (G3993) properly means only straitened circumstances in private), literally (often as noun) or figuratively (distressed)", "kjv": "beggar(-ly), poor."}, "G4435": {"greek": "πυγμή", "translit": "pygmḗ", "pronunciation": "poog-may'", "derivation": "from a primary (the fist as a weapon);", "definition": "the clenched hand, i.e. (only in dative case as adverb) with the fist (hard scrubbing)", "kjv": "oft."}, "G4436": {"greek": "Πύθων", "translit": "Pýthōn", "pronunciation": "poo'-thone", "derivation": "from (the name of the region where Delphi, the seat of the famous oracle, was located);", "definition": "a Python, i.e. (by analogy, with the supposed diviner there) inspiration (soothsaying)", "kjv": "divination."}, "G4437": {"greek": "πυκνός", "translit": "pyknós", "pronunciation": "pook-nos'", "derivation": "from the same as (G4635);", "definition": "clasped (thick), i.e. (figuratively) frequent; neuter plural (as adverb) frequently", "kjv": "often(-er)."}, "G4438": {"greek": "πυκτέω", "translit": "pyktéō", "pronunciation": "pook-teh'-o", "derivation": "from a derivative of the same as (G4435);", "definition": "to box (with the fist), i.e. contend (as a boxer) at the games (figuratively)", "kjv": "fight."}, "G4439": {"greek": "πύλη", "translit": "pýlē", "pronunciation": "poo'-lay", "derivation": "apparently a primary word;", "definition": "a gate, i.e. the leaf or wing of a folding entrance (literally or figuratively)", "kjv": "gate."}, "G4440": {"greek": "πυλών", "translit": "pylṓn", "pronunciation": "poo-lone'", "derivation": "from (G4439);", "definition": "a gate-way, door-way of a building or city; by implication, a portal or vestibule", "kjv": "gate, porch."}, "G4441": {"greek": "πυνθάνομαι", "translit": "pynthánomai", "pronunciation": "poon-than'-om-ahee", "derivation": "middle voice prolonged from a primary (which occurs only as an alternate in certain tenses);", "definition": "to question, i.e. ascertain by inquiry (as a matter of information merely; and thus differing from (G2065), which properly means a request as a favor; and from (G154), which is strictly a demand for something due; as well as from (G2212), which implies a search for something hidden; and from (G1189), which involves the idea of urgent need); by implication, to learn (by casual intelligence)", "kjv": "ask, demand, enquire, understand."}, "G4442": {"greek": "πῦρ", "translit": "pŷr", "pronunciation": "poor", "derivation": "a primary word;", "definition": "\"fire\" (literally or figuratively, specially, lightning)", "kjv": "fiery, fire."}, "G4443": {"greek": "πυρά", "translit": "pyrá", "pronunciation": "poo-rah'", "derivation": "from (G4442);", "definition": "a fire (concretely)", "kjv": "fire."}, "G4444": {"greek": "πύργος", "translit": "pýrgos", "pronunciation": "poor'-gos", "derivation": "apparently a primary word (\"burgh\");", "definition": "a tower or castle", "kjv": "tower."}, "G4445": {"greek": "πυρέσσω", "translit": "pyréssō", "pronunciation": "poo-res'-so", "derivation": "from (G4443);", "definition": "to be on fire, i.e. (specially), to have a fever", "kjv": "be sick of a fever."}, "G4446": {"greek": "πυρετός", "translit": "pyretós", "pronunciation": "poo-ret-os'", "derivation": "from (G4445);", "definition": "inflamed, i.e. (by implication) feverish (as noun, fever)", "kjv": "fever."}, "G4447": {"greek": "πύρινος", "translit": "pýrinos", "pronunciation": "poo'-ree-nos", "derivation": "from (G4443);", "definition": "fiery, i.e. (by implication) flaming", "kjv": "of fire."}, "G4448": {"greek": "πυρόω", "translit": "pyróō", "pronunciation": "poo-ro'-o", "derivation": "from (G4442);", "definition": "to kindle, i.e. (passively) to be ignited, glow (literally), be refined (by implication), or (figuratively) to be inflamed (with anger, grief, lust)", "kjv": "burn, fiery, be on fire, try."}, "G4449": {"greek": "πυῤῥάζω", "translit": "pyrrházō", "pronunciation": "poor-hrad'-zo", "derivation": "from (G4450);", "definition": "to redden (intransitively)", "kjv": "be red."}, "G4450": {"greek": "πυῤῥός", "translit": "pyrrhós", "pronunciation": "poor-hros'", "derivation": "from (G4442);", "definition": "fire-like, i.e. (specially), flame- colored", "kjv": "red."}, "G4451": {"greek": "πύρωσις", "translit": "pýrōsis", "pronunciation": "poo'-ro-sis", "derivation": "from (G4448);", "definition": "ignition, i.e. (specially), smelting (figuratively, conflagration, calamity as a test)", "kjv": "burning, trial."}, "G4453": {"greek": "πωλέω", "translit": "pōléō", "pronunciation": "po-leh'-o", "derivation": "probably ultimately from (to be busy, to trade);", "definition": "to barter (as a pedlar), i.e. to sell", "kjv": "sell, whatever is sold."}, "G4454": {"greek": "πῶλος", "translit": "pōlos", "pronunciation": "po'-los", "derivation": "apparently a primary word;", "definition": "a \"foal\" or \"filly\", i.e. (specially), a young ass", "kjv": "colt."}, "G4455": {"greek": "πώποτε", "translit": "pṓpote", "pronunciation": "po'-pot-e", "derivation": "from (G4452) and (G4218);", "definition": "at any time, i.e. (with negative particle) at no time", "kjv": "at any time, + never (…to any man), + yet, never man."}, "G4456": {"greek": "πωρόω", "translit": "pōróō", "pronunciation": "po-ro'-o", "derivation": "apparently from (a kind of stone);", "definition": "to petrify, i.e. (figuratively) to indurate (render stupid or callous)", "kjv": "blind, harden."}, "G4457": {"greek": "πώρωσις", "translit": "pṓrōsis", "pronunciation": "po'-ro-sis", "derivation": "from (G4456);", "definition": "stupidity or callousness", "kjv": "blindness, hardness."}, "G4458": {"greek": "‐πώς", "translit": "-pṓs", "pronunciation": "poce", "derivation": "adverb from the base of (G4225);", "definition": "an enclitic particle of indefiniteness of manner; somehow or anyhow; used only in composition", "kjv": "haply, by any (some) means, perhaps."}, "G4459": {"greek": "πῶς", "translit": "pōs", "pronunciation": "poce", "derivation": "adverb from the base of (G4226);", "definition": "an interrogative particle of manner; in what way? (sometimes the question is indirect, how?); also as exclamation, how much!", "kjv": "how, after (by) what manner (means), that."}, "G4460": {"greek": "Ῥαάβ", "translit": "Rhaáb", "pronunciation": "hrah-ab'", "derivation": "of Hebrew origin ((G7343));", "definition": "Raab (i.e. Rachab), a Canaanitess", "kjv": "Rahab."}, "G4461": {"greek": "ῥαββί", "translit": "rhabbí", "pronunciation": "hrab-bee'", "derivation": "of Hebrew origin ((G7227) with pronominal suffix);", "definition": "my master, i.e Rabbi, as an official title of honor", "kjv": "Master, Rabbi."}, "G4462": {"greek": "ῥαββονί", "translit": "rhabboní", "pronunciation": "hrab-bon-ee'", "derivation": "of Chaldee origin;", "definition": "corresponding to (G4461)", "kjv": "Lord, Rabboni."}, "G4463": {"greek": "ῥαβδίζω", "translit": "rhabdízō", "pronunciation": "hrab-did'-zo", "derivation": "from (G4464);", "definition": "to strike with a stick, i.e. bastinado", "kjv": "beat (with rods)."}, "G4464": {"greek": "ῥάβδος", "translit": "rhábdos", "pronunciation": "hrab'-dos", "derivation": "from the base of (G4474);", "definition": "a stick or wand (as a cudgel, a cane or a baton of royalty)", "kjv": "rod, sceptre, staff."}, "G4465": {"greek": "ῥαβδοῦχος", "translit": "rhabdoûchos", "pronunciation": "hrab-doo'-khos", "derivation": "from (G4464) and (G2192);", "definition": "a rod- (the Latin fasces) holder, i.e. a Roman lictor (constable or executioner)", "kjv": "serjeant."}, "G4466": {"greek": "Ῥαγαῦ", "translit": "Rhagaû", "pronunciation": "hrag-ow'", "derivation": "of Hebrew origin ((G7466));", "definition": "Ragau (i.e. Reu), a patriarch", "kjv": "Ragau."}, "G4467": {"greek": "ῥᾳδιούργημα", "translit": "rhaidioúrgēma", "pronunciation": "hrad-ee-oorg'-ay-mah", "derivation": "from a compound of (easy, i.e. reckless) and (G2041);", "definition": "easy-going behavior, i.e. (by extension) a crime", "kjv": "lewdness."}, "G4468": {"greek": "ῥᾳδιουργία", "translit": "rhaidiourgía", "pronunciation": "hrad-ee-oorg-ee'-a", "derivation": "from the same as (G4467);", "definition": "recklessness, i.e. (by extension) malignity", "kjv": "mischief."}, "G4469": {"greek": "ῥακά", "translit": "rhaká", "pronunciation": "rhak-ah'", "derivation": "of Chaldee origin (compare (G7386));", "definition": "O empty one, i.e. thou worthless (as a term of utter vilification)", "kjv": "Raca."}, "G4470": {"greek": "ῥάκος", "translit": "rhákos", "pronunciation": "hrak'-os", "derivation": "from (G4486);", "definition": "a \"rag,\" i.e. piece of cloth", "kjv": "cloth."}, "G4471": {"greek": "Ῥαμᾶ", "translit": "Rhamâ", "pronunciation": "hram-ah'", "derivation": "of Hebrew origin ((G7414));", "definition": "Rama (i.e. Ramah), a place in Palestine", "kjv": "Rama."}, "G4472": {"greek": "ῥαντίζω", "translit": "rhantízō", "pronunciation": "hran-tid'-zo", "derivation": "from a derivative of (to sprinkle);", "definition": "to render besprinkled, i.e. asperse (ceremonially or figuratively)", "kjv": "sprinkle."}, "G4473": {"greek": "ῥαντισμός", "translit": "rhantismós", "pronunciation": "hran-tis-mos'", "derivation": "from (G4472);", "definition": "aspersion (ceremonially or figuratively)", "kjv": "sprinkling."}, "G4474": {"greek": "ῥαπίζω", "translit": "rhapízō", "pronunciation": "hrap-id'-zo", "derivation": "from a derivative of a primary (to let fall, \"rap\");", "definition": "to slap", "kjv": "smite (with the palm of the hand)."}, "G4475": {"greek": "ῥάπισμα", "translit": "rhápisma", "pronunciation": "hrap'-is-mah", "derivation": "from (G4474);", "definition": "a slap", "kjv": "(+ strike with the) palm of the hand, smite with the hand."}, "G4476": {"greek": "ῥαφίς", "translit": "rhaphís", "pronunciation": "hraf-ece'", "derivation": "from a primary (to sew; perhaps rather akin to the base of (G4474) through the idea of puncturing);", "definition": "a needle", "kjv": "needle."}, "G4477": {"greek": "Ῥαχάβ", "translit": "Rhacháb", "pronunciation": "hrakh-ab'", "derivation": "from the same as (G4460);", "definition": "Rachab, a Canaanitess", "kjv": "Rachab."}, "G4478": {"greek": "Ῥαχήλ", "translit": "Rhachḗl", "pronunciation": "hrakh-ale'", "derivation": "of Hebrew origin ((G7354));", "definition": "Rachel, the wife of Jacob", "kjv": "Rachel."}, "G4479": {"greek": "Ῥεβέκκα", "translit": "Rhebékka", "pronunciation": "hreb-bek'-kah", "derivation": "of Hebrew origin ((G7259));", "definition": "Rebecca (i.e. Ribkah), the wife of Isaac", "kjv": "Rebecca."}, "G4480": {"greek": "ῥέδα", "translit": "rhéda", "pronunciation": "hred'-ah", "derivation": "of Latin origin;", "definition": "a rheda, i.e. four-wheeled carriage (wagon for riding)", "kjv": "chariot."}, "G4481": {"greek": "Ῥεμφάν", "translit": "Rhemphán", "pronunciation": "hrem-fan'", "derivation": "by incorrect transliteration for a word of Hebrew origin ((G3594));", "definition": "Remphan (i.e. Kijun), an Egyptian idol", "kjv": "Remphan."}, "G4482": {"greek": "ῥέω", "translit": "rhéō", "pronunciation": "hreh'-o", "derivation": "a primary verb;", "definition": "for some tenses of which a prolonged form is used to flow (\"run\"; as water)", "kjv": "flow."}, "G4483": {"greek": "ῥέω", "translit": "rhéō", "pronunciation": "hreh'-o", "derivation": "perhaps akin (or identical) with (G4482) (through the idea of pouring forth);", "definition": "to utter, i.e. speak or say", "kjv": "command, make, say, speak (of)."}, "G4484": {"greek": "Ῥήγιον", "translit": "Rhḗgion", "pronunciation": "hrayg'-ee-on", "derivation": "of Latin origin;", "definition": "Rhegium, a place in Italy", "kjv": "Rhegium."}, "G4485": {"greek": "ῥῆγμα", "translit": "rhēgma", "pronunciation": "hrayg'-mah", "derivation": "from (G4486);", "definition": "something torn, i.e. a fragment (by implication and abstractly, a fall)", "kjv": "ruin."}, "G4486": {"greek": "ῥήγνυμι", "translit": "rhḗgnymi", "pronunciation": "hrayg'-noo-mee", "derivation": "both prolonged forms of (which appears only in certain forms, and is itself probably a strengthened form of (see in (G2608)));", "definition": "to \"break,\" \"wreck\" or \"crack\", i.e. (especially) to sunder (by separation of the parts; (G2608) being its intensive (with the preposition in composition), and (G2352) a shattering to minute fragments; but not a reduction to the constituent particles, like (G3089)) or disrupt, lacerate; by implication, to convulse (with spasms); figuratively, to give vent to joyful emotions", "kjv": "break (forth), burst, rend, tear."}, "G4487": {"greek": "ῥῆμα", "translit": "rhēma", "pronunciation": "hray'-mah", "derivation": "from (G4483);", "definition": "an utterance (individually, collectively or specially),; by implication, a matter or topic (especially of narration, command or dispute); with a negative naught whatever", "kjv": "+ evil, + nothing, saying, word."}, "G4488": {"greek": "Ῥησά", "translit": "Rhēsá", "pronunciation": "hray-sah'", "derivation": "probably of Hebrew origin (apparently for (G7509));", "definition": "Resa (i.e. Rephajah), an Israelite", "kjv": "Rhesa."}, "G4489": {"greek": "ῥήτωρ", "translit": "rhḗtōr", "pronunciation": "hray'-tore", "derivation": "from (G4483);", "definition": "a speaker, i.e. (by implication) a forensic advocate", "kjv": "orator."}, "G4490": {"greek": "ῥητῶς", "translit": "rhētōs", "pronunciation": "hray-toce'", "derivation": "adverb from a derivative of (G4483);", "definition": "out-spokenly, i.e. distinctly", "kjv": "expressly."}, "G4491": {"greek": "ῥίζα", "translit": "rhíza", "pronunciation": "hrid'-zah", "derivation": "apparently a primary word;", "definition": "a \"root\" (literally or figuratively)", "kjv": "root."}, "G4492": {"greek": "ῥιζόω", "translit": "rhizóō", "pronunciation": "hrid-zo'-o", "derivation": "from (G4491);", "definition": "to root (figuratively, become stable)", "kjv": "root."}, "G4493": {"greek": "ῥιπή", "translit": "rhipḗ", "pronunciation": "hree-pay'", "derivation": "from (G4496);", "definition": "a jerk (of the eye, i.e. (by analogy) an instant)", "kjv": "twinkling."}, "G4494": {"greek": "ῥιπίζω", "translit": "rhipízō", "pronunciation": "hrip-id'-zo", "derivation": "from a derivative of (G4496) (meaning a fan or bellows);", "definition": "to breeze up, i.e. (by analogy) to agitate (into waves)", "kjv": "toss."}, "G4496": {"greek": "ῥίπτω", "translit": "rhíptō", "pronunciation": "hrip'-to", "derivation": "a primary verb (perhaps rather akin to the base of (G4474), through the idea of sudden motion);", "definition": "to fling (properly, with a quick toss, thus differing from (G906), which denotes a deliberate hurl; and from (see in (G1614)), which indicates an extended projection); by qualification, to deposit (as if a load); by extension, to disperse", "kjv": "cast (down, out), scatter abroad, throw."}, "G4497": {"greek": "Ῥοβοάμ", "translit": "Rhoboám", "pronunciation": "hrob-o-am'", "derivation": "of Hebrew origin ((G7346));", "definition": "Roboam (i.e. Rechobam), an Israelite", "kjv": "Roboam."}, "G4498": {"greek": "Ῥόδη", "translit": "Rhódē", "pronunciation": "hrod'-ay", "derivation": "probably for rhode (a rose);", "definition": "Rode, a servant girl", "kjv": "Rhoda."}, "G4499": {"greek": "Ῥόδος", "translit": "Rhódos", "pronunciation": "hrod'-os", "derivation": "probably from (a rose);", "definition": "Rhodus, an island of the Mediterranean", "kjv": "Rhodes."}, "G4500": {"greek": "ῥοιζηδόν", "translit": "rhoizēdón", "pronunciation": "hroyd-zay-don'", "derivation": "adverb from a derivative of (a whir);", "definition": "whizzingly, i.e. with a crash", "kjv": "with a great noise."}, "G4501": {"greek": "ῥομφαία", "translit": "rhomphaía", "pronunciation": "hrom-fah'-yah", "derivation": "probably of foreign origin;", "definition": "a sabre, i.e. a long and broad cutlass (any weapon of the kind, literally or figuratively)", "kjv": "sword."}, "G4502": {"greek": "Ῥουβήν", "translit": "Rhoubḗn", "pronunciation": "hroo-bane'", "derivation": "of Hebrew origin ((G7205));", "definition": "Ruben (i.e. Reuben), an Israelite", "kjv": "Reuben."}, "G4503": {"greek": "Ῥούθ", "translit": "Rhoúth", "pronunciation": "hrooth", "derivation": "of Hebrew origin ((G7327));", "definition": "Ruth, a Moabitess", "kjv": "Ruth."}, "G4504": {"greek": "Ῥοῦφος", "translit": "Rhoûphos", "pronunciation": "hroo'-fos", "derivation": "of Latin origin;", "definition": "red; Rufus, a Christian", "kjv": "Rufus."}, "G4505": {"greek": "ῥύμη", "translit": "rhýmē", "pronunciation": "hroo'-may", "derivation": "prolongation from (G4506) in its original sense;", "definition": "an alley or avenue (as crowded)", "kjv": "lane, street."}, "G4506": {"greek": "ῥύομαι", "translit": "rhýomai", "pronunciation": "rhoo'-om-ahee", "derivation": "middle voice of an obsolete verb, akin to (G4482) (through the idea of a current;", "definition": "compare (G4511)); to rush or draw (for oneself), i.e. rescue", "kjv": "deliver(-er)."}, "G4507": {"greek": "ῥυπαρία", "translit": "rhyparía", "pronunciation": "hroo-par-ee'-ah", "derivation": "from (G4508);", "definition": "dirtiness (morally)", "kjv": "turpitude."}, "G4508": {"greek": "ῥυπαρός", "translit": "rhyparós", "pronunciation": "rhoo-par-os'", "derivation": "from (G4509);", "definition": "dirty, i.e. (relatively) cheap or shabby; morally, wicked", "kjv": "vile."}, "G4509": {"greek": "ῥύπος", "translit": "rhýpos", "pronunciation": "hroo'-pos", "derivation": "of uncertain affinity;", "definition": "dirt, i.e. (morally) depravity", "kjv": "filth."}, "G4510": {"greek": "ῥυπόω", "translit": "rhypóō", "pronunciation": "rhoo-po'-o", "derivation": "from (G4509);", "definition": "to soil, i.e. (intransitively) to become dirty (morally)", "kjv": "be filthy."}, "G4511": {"greek": "ῥύσις", "translit": "rhýsis", "pronunciation": "hroo'-sis", "derivation": "from (G4506) in the sense of its congener (G4482);", "definition": "a flux (of blood)", "kjv": "issue."}, "G4512": {"greek": "ῥυτίς", "translit": "rhytís", "pronunciation": "hroo-tece'", "derivation": "from (G4506);", "definition": "a fold (as drawing together), i.e. a wrinkle (especially on the face)", "kjv": "wrinkle."}, "G4514": {"greek": "Ῥωμαῖος", "translit": "Rhōmaîos", "pronunciation": "hro-mah'-yos", "derivation": "from (G4516);", "definition": "Romæan, i.e. Roman (as noun)", "kjv": "Roman, of Rome."}, "G4515": {"greek": "Ῥωμαϊστί", "translit": "Rhōmaïstí", "pronunciation": "hro-mah-is-tee'", "derivation": "adverb from a presumed derivative of (G4516);", "definition": "Romaistically, i.e. in the Latin language", "kjv": "Latin."}, "G4516": {"greek": "Ῥώμη", "translit": "Rhṓmē", "pronunciation": "hro'-may", "derivation": "from the base of (G4517);", "definition": "strength; Roma, the capital of Italy", "kjv": "Rome."}, "G4517": {"greek": "ῥώννυμι", "translit": "rhṓnnymi", "pronunciation": "hrone'-noo-mee", "derivation": "prolongation from (to dart;", "definition": "probably akin to (G4506)); to strengthen, i.e. (impersonal passive) have health (as a parting exclamation, good-bye)", "kjv": "farewell."}, "G4518": {"greek": "σαβαχθάνι", "translit": "sabachtháni", "pronunciation": "sab-akh-than-ee'", "derivation": "of Chaldee or ((G7662) with pronominal suffix);", "definition": "thou hast left me; sabachthani (i.e. shebakthani), a cry of distress", "kjv": "sabachthani."}, "G4519": {"greek": "σαβαώθ", "translit": "sabaṓth", "pronunciation": "sab-ah-owth'", "derivation": "of Hebrew origin ((G6635) in feminine plural);", "definition": "armies; sabaoth (i.e. tsebaoth), a military epithet of God", "kjv": "sabaoth."}, "G4520": {"greek": "σαββατισμός", "translit": "sabbatismós", "pronunciation": "sab-bat-is-mos'", "derivation": "from a derivative of (G4521);", "definition": "a \"sabbatism\", i.e. (figuratively) the repose of Christianity (as a type of heaven)", "kjv": "rest."}, "G4521": {"greek": "σάββατον", "translit": "sábbaton", "pronunciation": "sab'-bat-on", "derivation": "of Hebrew origin ((G7676));", "definition": "the Sabbath (i.e. Shabbath), or day of weekly repose from secular avocations (also the observance or institution itself); by extension, a se'nnight, i.e. the interval between two Sabbaths; likewise the plural in all the above applications", "kjv": "sabbath (day), week."}, "G4522": {"greek": "σαγήνη", "translit": "sagḗnē", "pronunciation": "sag-ay'-nay", "derivation": "from a derivative of (to equip) meaning furniture, especially a pack-saddle (which in the East is merely a bag of netted rope);", "definition": "a \"seine\" for fishing", "kjv": "net."}, "G4523": {"greek": "Σαδδουκαῖος", "translit": "Saddoukaîos", "pronunciation": "sad-doo-kah'-yos", "derivation": "probably from (G4524);", "definition": "a Sadducæan (i.e. Tsadokian), or follower of a certain heretical Israelite", "kjv": "Sadducee."}, "G4524": {"greek": "Σαδώκ", "translit": "Sadṓk", "pronunciation": "sad-oke'", "derivation": "of Hebrew origin ((G6659));", "definition": "Sadoc (i.e. Tsadok), an Israelite", "kjv": "Sadoc."}, "G4525": {"greek": "σαίνω", "translit": "saínō", "pronunciation": "sah'-ee-no", "derivation": "akin to (G4579);", "definition": "to wag (as a dog its tail fawningly), i.e. (generally) to shake (figuratively, disturb)", "kjv": "move."}, "G4526": {"greek": "σάκκος", "translit": "sákkos", "pronunciation": "sak'-kos", "derivation": "of Hebrew origin ((G8242));", "definition": "\"sack\"-cloth, i.e. mohair (the material or garments made of it, worn as a sign of grief)", "kjv": "sackcloth."}, "G4527": {"greek": "Σαλά", "translit": "Salá", "pronunciation": "sal-ah'", "derivation": "of Hebrew origin ((G7974));", "definition": "Sala (i.e. Shelach), a patriarch", "kjv": "Sala."}, "G4528": {"greek": "Σαλαθιήλ", "translit": "Salathiḗl", "pronunciation": "sal-ath-ee-ale'", "derivation": "of Hebrew origin ((G7597));", "definition": "Salathiel (i.e. Shealtiel), an Israelite", "kjv": "Salathiel."}, "G4529": {"greek": "Σαλαμίς", "translit": "Salamís", "pronunciation": "sal-am-ece'", "derivation": "probably from (G4535) (from the surge on the shore);", "definition": "Salamis, a place in Cyprus", "kjv": "Salamis."}, "G4530": {"greek": "Σαλείμ", "translit": "Saleím", "pronunciation": "sal-ime'", "derivation": "probably from the same as (G4531);", "definition": "Salim, a place in Palestine", "kjv": "Salim."}, "G4531": {"greek": "σαλεύω", "translit": "saleúō", "pronunciation": "sal-yoo'-o", "derivation": "from (G4535);", "definition": "to waver, i.e. agitate, rock, topple or (by implication) destroy; figuratively, to disturb, incite", "kjv": "move, shake (together), which can(-not) be shaken, stir up."}, "G4532": {"greek": "Σαλήμ", "translit": "Salḗm", "pronunciation": "sal-ame'", "derivation": "of Hebrew origin ((G8004));", "definition": "Salem (i.e. Shalem), a place in Palestine", "kjv": "Salem."}, "G4533": {"greek": "Σαλμών", "translit": "Salmṓn", "pronunciation": "sal-mone'", "derivation": "of Hebrew origin ((G8012));", "definition": "Salmon, an Israelite", "kjv": "Salmon."}, "G4534": {"greek": "Σαλμώνη", "translit": "Salmṓnē", "pronunciation": "sal-mo'-nay", "derivation": "perhaps of similar origin to (G4529);", "definition": "Salmone, a place in Crete", "kjv": "Salmone."}, "G4535": {"greek": "σάλος", "translit": "sálos", "pronunciation": "sal'-os", "derivation": "probably from the base of (G4525);", "definition": "a vibration, i.e. (specially), billow", "kjv": "wave."}, "G4536": {"greek": "σάλπιγξ", "translit": "sálpinx", "pronunciation": "sal'-pinx", "derivation": "perhaps from (G4535) (through the idea of quavering or reverberation);", "definition": "a trumpet", "kjv": "trump(-et)."}, "G4537": {"greek": "σαλπίζω", "translit": "salpízō", "pronunciation": "sal-pid'-zo", "derivation": "from (G4536);", "definition": "to trumpet, i.e. sound a blast (literally or figuratively)", "kjv": "(which are yet to) sound (a trumpet)."}, "G4538": {"greek": "σαλπιστής", "translit": "salpistḗs", "pronunciation": "sal-pis-tace'", "derivation": "from (G4537);", "definition": "a trumpeter", "kjv": "trumpeter."}, "G4539": {"greek": "Σαλώμη", "translit": "Salṓmē", "pronunciation": "sal-o'-may", "derivation": "probably of Hebrew origin (feminine from (G7965));", "definition": "Salome (i.e. Shelomah), an Israelitess", "kjv": "Salome."}, "G4540": {"greek": "Σαμάρεια", "translit": "Samáreia", "pronunciation": "sam-ar'-i-ah", "derivation": "of Hebrew origin ((G8111));", "definition": "Samaria (i.e. Shomeron), a city and region of Palestine", "kjv": "Samaria."}, "G4541": {"greek": "Σαμαρείτης", "translit": "Samareítēs", "pronunciation": "sam-ar-i'-tace", "derivation": "from (G4540);", "definition": "a Samarite, i.e. inhabitant of Samaria", "kjv": "Samaritan."}, "G4542": {"greek": "Σαμαρεῖτις", "translit": "Samareîtis", "pronunciation": "sam-ar-i'-tis", "derivation": "feminine of (G4541);", "definition": "a Samaritess, i.e. woman of Samaria", "kjv": "of Samaria."}, "G4543": {"greek": "Σαμοθρᾴκη", "translit": "Samothráikē", "pronunciation": "sam-oth-rak'-ay", "derivation": "from (G4544) and (Thrace);", "definition": "Samo-thrace (Samos of Thrace), an island in the Mediterranean", "kjv": "Samothracia."}, "G4544": {"greek": "Σάμος", "translit": "Sámos", "pronunciation": "sam'-os", "derivation": "of uncertain affinity;", "definition": "Samus, an island of the Mediterranean", "kjv": "Samos."}, "G4545": {"greek": "Σαμουήλ", "translit": "Samouḗl", "pronunciation": "sam-oo-ale'", "derivation": "of Hebrew origin ((G8050));", "definition": "Samuel (i.e. Shemuel), an Israelite", "kjv": "Samuel."}, "G4546": {"greek": "Σαμψών", "translit": "Sampsṓn", "pronunciation": "samp-sone'", "derivation": "of Hebrew origin ((G8123));", "definition": "Sampson (i.e. Shimshon), an Israelite", "kjv": "Samson."}, "G4547": {"greek": "σανδάλιον", "translit": "sandálion", "pronunciation": "san-dal'-ee-on", "derivation": "neuter of a derivative of (a \"sandal\"; of uncertain origin);", "definition": "a slipper or sole-pad", "kjv": "sandal."}, "G4548": {"greek": "σανίς", "translit": "sanís", "pronunciation": "san-ece'", "derivation": "of uncertain affinity;", "definition": "a plank", "kjv": "board."}, "G4549": {"greek": "Σαούλ", "translit": "Saoúl", "pronunciation": "sah-ool'", "derivation": "of Hebrew origin ((G7586));", "definition": "Saul (i.e. Shaul), the Jewish name of Paul", "kjv": "Saul."}, "G4550": {"greek": "σαπρός", "translit": "saprós", "pronunciation": "sap-ros'", "derivation": "from (G4595);", "definition": "rotten, i.e. worthless (literally or morally)", "kjv": "bad, corrupt."}, "G4551": {"greek": "Σαπφείρη", "translit": "Sappheírē", "pronunciation": "sap-fi'-ray", "derivation": "feminine of (G4552);", "definition": "Sapphire, an Israelitess", "kjv": "Sapphira."}, "G4552": {"greek": "σάπφειρος", "translit": "sáppheiros", "pronunciation": "sap'-fi-ros", "derivation": "of Hebrew origin ((G5601));", "definition": "a \"sapphire\" or lapis-lazuli gem", "kjv": "sapphire."}, "G4553": {"greek": "σαργάνη", "translit": "sargánē", "pronunciation": "sar-gan'-ay", "derivation": "apparently of Hebrew origin ((G8276));", "definition": "a basket (as interwoven or wicker-work", "kjv": "basket."}, "G4554": {"greek": "Σάρδεις", "translit": "Sárdeis", "pronunciation": "sar'-dice", "derivation": "plural of uncertain derivation;", "definition": "Sardis, a place in Asia Minor", "kjv": "Sardis."}, "G4555": {"greek": "σάρδινος", "translit": "sárdinos", "pronunciation": "sar'-dee-nos", "derivation": "from the same as (G4556);", "definition": "sardine ((G3037) being implied), i.e. a gem, so called", "kjv": "sardine."}, "G4557": {"greek": "σαρδόνυξ", "translit": "sardónyx", "pronunciation": "sar-don'-oox", "derivation": "from the base of (G4556) and (the nail of a finger; hence the \"onyx\" stone);", "definition": "a \"sardonyx\", i.e. the gem so called", "kjv": "sardonyx."}, "G4558": {"greek": "Σάρεπτα", "translit": "Sárepta", "pronunciation": "sar'-ep-tah", "derivation": "of Hebrew origin ((G6886));", "definition": "Sarepta (i.e. Tsarephath), a place in Palestine", "kjv": "Sarepta."}, "G4559": {"greek": "σαρκικός", "translit": "sarkikós", "pronunciation": "sar-kee-kos'", "derivation": "from (G4561);", "definition": "pertaining to flesh, i.e. (by extension) bodily, temporal, or (by implication) animal, unregenerate", "kjv": "carnal, fleshly."}, "G4560": {"greek": "σάρκινος", "translit": "sárkinos", "pronunciation": "sar'-kee-nos", "derivation": "from (G4561);", "definition": "similar to flesh, i.e. (by analogy) soft", "kjv": "fleshly."}, "G4561": {"greek": "σάρξ", "translit": "sárx", "pronunciation": "sarx", "derivation": "probably from the base of (G4563);", "definition": "flesh (as stripped of the skin), i.e. (strictly) the meat of an animal (as food), or (by extension) the body (as opposed to the soul (or spirit), or as the symbol of what is external, or as the means of kindred), or (by implication) human nature (with its frailties (physically or morally) and passions), or (specially), a human being (as such)", "kjv": "carnal(-ly, + -ly minded), flesh(-ly)."}, "G4562": {"greek": "Σαρούχ", "translit": "Saroúch", "pronunciation": "sar-ooch'", "derivation": "of Hebrew origin ((G8286));", "definition": "Saruch (i.e. Serug), a patriarch", "kjv": "Saruch."}, "G4563": {"greek": "σαρόω", "translit": "saróō", "pronunciation": "sar-o'-o", "derivation": "from a derivative of (to brush off; akin to (G4951));", "definition": "meaning a broom; to sweep", "kjv": "sweep."}, "G4564": {"greek": "Σάῤῥα", "translit": "Sárrha", "pronunciation": "sar'-hrah", "derivation": "of Hebrew origin ((G8283));", "definition": "Sarra (i.e. Sarah), the wife of Abraham", "kjv": "Sara, Sarah."}, "G4565": {"greek": "Σάρων", "translit": "Sárōn", "pronunciation": "sar'-one", "derivation": "of Hebrew origin ((G8289));", "definition": "Saron (i.e. Sharon), a district of Palestine", "kjv": "Saron."}, "G4567": {"greek": "Σατανᾶς", "translit": "Satanâs", "pronunciation": "sat-an-as'", "derivation": "of Chaldee origin corresponding to (G4566) (with the definite affix);", "definition": "the accuser, i.e. the devil", "kjv": "Satan."}, "G4568": {"greek": "σάτον", "translit": "sáton", "pronunciation": "sat'-on", "derivation": "of Hebrew origin ((G5429));", "definition": "a certain measure for things dry", "kjv": "measure."}, "G4569": {"greek": "Σαῦλος", "translit": "Saûlos", "pronunciation": "sow'-los", "derivation": "of Hebrew origin, the same as (G4549);", "definition": "Saulus (i.e. Shaul), the Jewish name of Paul", "kjv": "Saul."}, "G4570": {"greek": "σβέννυμι", "translit": "sbénnymi", "pronunciation": "sben'-noo-mee", "derivation": "a prolonged form of an apparently primary verb;", "definition": "to extinguish (literally or figuratively)", "kjv": "go out, quench."}, "G4571": {"greek": "σέ", "translit": "sé", "pronunciation": "seh", "derivation": "accusative case singular of (G4771);", "definition": "thee", "kjv": "thee, thou, X thy house."}, "G4572": {"greek": "σεαυτοῦ", "translit": "seautoû", "pronunciation": "seh-ow-too'", "derivation": "genitive case from (G4571) and (G846), also dative case of the same, , and accusative case , likewise contracted , , and , respectively;", "definition": "of (with, to) thyself", "kjv": "thee, thine own self, (thou) thy(-self)."}, "G4573": {"greek": "σεβάζομαι", "translit": "sebázomai", "pronunciation": "seb-ad'-zom-ahee", "derivation": "middle voice from a derivative of (G4576);", "definition": "to venerate, i.e. adore", "kjv": "worship."}, "G4574": {"greek": "σέβασμα", "translit": "sébasma", "pronunciation": "seb'-as-mah", "derivation": "from (G4573);", "definition": "something adored, i.e. an object of worship (god, altar, etc)", "kjv": "devotion, that is worshipped."}, "G4575": {"greek": "σεβαστός", "translit": "sebastós", "pronunciation": "seb-as-tos'", "derivation": "from (G4573);", "definition": "venerable (august), i.e. (as noun) a title of the Roman Emperor, or (as adjective) imperial", "kjv": "Augustus(-')."}, "G4576": {"greek": "σέβομαι", "translit": "sébomai", "pronunciation": "seb'-om-ahee", "derivation": "middle voice of an apparently primary verb;", "definition": "to revere, i.e. adore", "kjv": "devout, religious, worship."}, "G4577": {"greek": "σειρά", "translit": "seirá", "pronunciation": "si-rah'", "derivation": "probably from (G4951) through its congener (to fasten; akin to (G138));", "definition": "a chain (as binding or drawing)", "kjv": "chain."}, "G4578": {"greek": "σεισμός", "translit": "seismós", "pronunciation": "sice-mos'", "derivation": "from (G4579);", "definition": "a commotion, i.e. (of the air) a gale, (of the ground) an earthquake", "kjv": "earthquake, tempest."}, "G4579": {"greek": "σείω", "translit": "seíō", "pronunciation": "si'-o", "derivation": "apparently a primary verb;", "definition": "to rock (vibrate, properly, sideways or to and fro), i.e. (generally) to agitate (in any direction; cause to tremble); figuratively, to throw into a tremor (of fear or concern)", "kjv": "move, quake, shake."}, "G4580": {"greek": "Σεκοῦνδος", "translit": "Sekoûndos", "pronunciation": "sek-oon'-dos", "derivation": "of Latin origin;", "definition": "\"second\"; Secundus, a Christian", "kjv": "Secundus."}, "G4581": {"greek": "Σελεύκεια", "translit": "Seleúkeia", "pronunciation": "sel-yook'-i-ah", "derivation": "from (Seleucus, a Syrian king);", "definition": "Seleuceia, a place in Syria", "kjv": "Seleucia."}, "G4582": {"greek": "σελήνη", "translit": "selḗnē", "pronunciation": "sel-ay'-nay", "derivation": "from (brilliancy; probably akin to the alternate of (G138), through the idea of attractiveness);", "definition": "the moon", "kjv": "moon."}, "G4583": {"greek": "σεληνιάζομαι", "translit": "selēniázomai", "pronunciation": "sel-ay-nee-ad'-zom-ahee", "derivation": "middle voice or passive from a presumed derivative of (G4582);", "definition": "to be moon-struck, i.e. crazy", "kjv": "be a lunatic."}, "G4584": {"greek": "Σεμεΐ", "translit": "Semeḯ", "pronunciation": "sem-eh-ee'", "derivation": "of Hebrew origin ((G8096));", "definition": "Semei (i.e. Shimi), an Israelite", "kjv": "Semei."}, "G4585": {"greek": "σεμίδαλις", "translit": "semídalis", "pronunciation": "sem-id'-al-is", "derivation": "probably of foreign origin;", "definition": "fine wheaten flour", "kjv": "fine flour."}, "G4586": {"greek": "σεμνός", "translit": "semnós", "pronunciation": "sem-nos'", "derivation": "from (G4576);", "definition": "venerable, i.e. honorable", "kjv": "grave, honest."}, "G4587": {"greek": "σεμνότης", "translit": "semnótēs", "pronunciation": "sem-not'-ace", "derivation": "from (G4586);", "definition": "venerableness, i.e. probity", "kjv": "gravity, honesty."}, "G4588": {"greek": "Σέργιος", "translit": "Sérgios", "pronunciation": "serg'-ee-os", "derivation": "of Latin origin;", "definition": "Sergius, a Roman", "kjv": "Sergius."}, "G4589": {"greek": "Σήθ", "translit": "Sḗth", "pronunciation": "sayth", "derivation": "of Hebrew origin ((G8352));", "definition": "Seth (i.e. Sheth), a patriarch", "kjv": "Seth."}, "G4590": {"greek": "Σήμ", "translit": "Sḗm", "pronunciation": "same", "derivation": "of Hebrew origin ((G8035));", "definition": "Sem (i.e. Shem), a patriarch", "kjv": "Sem."}, "G4591": {"greek": "σημαίνω", "translit": "sēmaínō", "pronunciation": "say-mah'-ee-no", "derivation": "from (a mark; of uncertain derivation);", "definition": "to indicate", "kjv": "signify."}, "G4592": {"greek": "σημεῖον", "translit": "sēmeîon", "pronunciation": "say-mi'-on", "derivation": "neuter of a presumed derivative of the base of (G4591);", "definition": "an indication, especially ceremonially or supernaturally", "kjv": "miracle, sign, token, wonder."}, "G4593": {"greek": "σημειόω", "translit": "sēmeióō", "pronunciation": "say-mi-o'-o", "derivation": "from (G4592);", "definition": "to distinguish, i.e. mark (for avoidance)", "kjv": "note."}, "G4594": {"greek": "σήμερον", "translit": "sḗmeron", "pronunciation": "say'-mer-on", "derivation": "neuter (as adverb) of a presumed compound of the article (G3588) (t changed to s) and (G2250);", "definition": "on the (i.e. this) day (or night current or just passed); generally, now (i.e. at present, hitherto)", "kjv": "this (to-)day."}, "G4595": {"greek": "σήπω", "translit": "sḗpō", "pronunciation": "say'-po", "derivation": "apparently a primary verb;", "definition": "to putrefy, i.e. (figuratively) perish", "kjv": "be corrupted."}, "G4596": {"greek": "σηρικός", "translit": "sērikós", "pronunciation": "say-ree-kos'", "derivation": "from (an Indian tribe from whom silk was procured; hence the name of the silk-worm);", "definition": "Seric, i.e. silken (neuter as noun, a silky fabric)", "kjv": "silk."}, "G4597": {"greek": "σής", "translit": "sḗs", "pronunciation": "sace", "derivation": "apparently of Hebrew origin ((G5580));", "definition": "a moth", "kjv": "moth."}, "G4598": {"greek": "σητόβρωτος", "translit": "sētóbrōtos", "pronunciation": "say-tob'-ro-tos", "derivation": "from (G4597) and a derivative of (G977);", "definition": "moth-eaten", "kjv": "motheaten."}, "G4599": {"greek": "σθενόω", "translit": "sthenóō", "pronunciation": "sthen-o'-o", "derivation": "from (bodily vigor; probably akin to the base of (G2476));", "definition": "to strengthen, i.e. (figuratively) confirm (in spiritual knowledge and power)", "kjv": "strengthen."}, "G4600": {"greek": "σιαγών", "translit": "siagṓn", "pronunciation": "see-ag-one'", "derivation": "of uncertain derivation;", "definition": "the jaw-bone, i.e. (by implication) the cheek or side of the face", "kjv": "cheek."}, "G4601": {"greek": "σιγάω", "translit": "sigáō", "pronunciation": "see-gah'-o", "derivation": "from (G4602);", "definition": "to keep silent (transitively or intransitively)", "kjv": "keep close (secret, silence), hold peace."}, "G4602": {"greek": "σιγή", "translit": "sigḗ", "pronunciation": "see-gay'", "derivation": "apparently from (to hiss, i.e. hist or hush);", "definition": "silence", "kjv": "silence."}, "G4603": {"greek": "σιδήρεος", "translit": "sidḗreos", "pronunciation": "sid-ay'-reh-os", "derivation": "from (G4604);", "definition": "made of iron", "kjv": "(of) iron."}, "G4604": {"greek": "σίδηρος", "translit": "sídēros", "pronunciation": "sid'-ay-ros", "derivation": "of uncertain derivation;", "definition": "iron", "kjv": "iron."}, "G4605": {"greek": "Σιδών", "translit": "Sidṓn", "pronunciation": "sid-one'", "derivation": "of Hebrew origin ((G6721));", "definition": "Sidon (i.e. Tsidon), a place in Palestine", "kjv": "Sidon."}, "G4606": {"greek": "Σιδώνιος", "translit": "Sidṓnios", "pronunciation": "sid-o'-nee-os", "derivation": "from (G4605);", "definition": "a Sidonian, i.e. inhabitant of Sidon", "kjv": "of Sidon."}, "G4607": {"greek": "σικάριος", "translit": "sikários", "pronunciation": "sik-ar'-ee-os", "derivation": "of Latin origin;", "definition": "a dagger-man or assassin; a freebooter (Jewish fanatic outlawed by the Romans)", "kjv": "murderer."}, "G4608": {"greek": "σίκερα", "translit": "síkera", "pronunciation": "sik'-er-ah", "derivation": "of Hebrew origin ((G7941));", "definition": "an intoxicant, i.e. intensely fermented liquor", "kjv": "strong drink."}, "G4609": {"greek": "Σίλας", "translit": "Sílas", "pronunciation": "see'-las", "derivation": "contraction for (G4610);", "definition": "Silas, a Christian", "kjv": "Silas."}, "G4610": {"greek": "Σιλουανός", "translit": "Silouanós", "pronunciation": "sil-oo-an-os'", "derivation": "of Latin origin;", "definition": "\"silvan\"; Silvanus, a Christian", "kjv": "Silvanus."}, "G4611": {"greek": "Σιλωάμ", "translit": "Silōám", "pronunciation": "sil-o-am'", "derivation": "of Hebrew origin ((G7975));", "definition": "Siloam (i.e. Shiloach), a pool of Jerusalem", "kjv": "Siloam."}, "G4612": {"greek": "σιμικίνθιον", "translit": "simikínthion", "pronunciation": "sim-ee-kin'-thee-on", "derivation": "of Latin origin;", "definition": "a semicinctium or half-girding, i.e. narrow covering (apron)", "kjv": "apron."}, "G4613": {"greek": "Σίμων", "translit": "Símōn", "pronunciation": "see'-mone", "derivation": "of Hebrew origin ((G8095));", "definition": "Simon (i.e. Shimon), the name of nine Israelites", "kjv": "Simon."}, "G4614": {"greek": "Σινᾶ", "translit": "Sinâ", "pronunciation": "see-nah'", "derivation": "of Hebrew origin ((G5514));", "definition": "Sina (i.e. Sinai), a mountain in Arabia", "kjv": "Sina."}, "G4615": {"greek": "σίναπι", "translit": "sínapi", "pronunciation": "sin'-ap-ee", "derivation": "perhaps from (to hurt, i.e. sting);", "definition": "mustard (the plant)", "kjv": "mustard."}, "G4616": {"greek": "σινδών", "translit": "sindṓn", "pronunciation": "sin-done'", "derivation": "of uncertain (perhaps foreign) origin;", "definition": "byssos, i.e. bleached linen (the cloth or a garment of it)", "kjv": "(fine) linen (cloth)."}, "G4617": {"greek": "σινιάζω", "translit": "siniázō", "pronunciation": "sin-ee-ad'-zo", "derivation": "from (a sieve);", "definition": "to riddle (figuratively)", "kjv": "sift."}, "G4618": {"greek": "σιτευτός", "translit": "siteutós", "pronunciation": "sit-yoo-ros'", "derivation": "from a derivative of (G4621);", "definition": "grain-fed, i.e. fattened", "kjv": "fatted."}, "G4619": {"greek": "σιτιστός", "translit": "sitistós", "pronunciation": "sit-is-tos'", "derivation": "from a derivative of (G4621);", "definition": "grained, i.e. fatted", "kjv": "fatling."}, "G4620": {"greek": "σιτόμετρον", "translit": "sitómetron", "pronunciation": "sit-om'-et-ron", "derivation": "from (G4621) and (G3358);", "definition": "a grain-measure, i.e. (by implication) ration (allowance of food)", "kjv": "portion of meat."}, "G4621": {"greek": "σῖτος", "translit": "sîtos", "pronunciation": "see'-tos", "derivation": "of uncertain derivation;", "definition": "grain, especially wheat", "kjv": "corn, wheat."}, "G4622": {"greek": "Σιών", "translit": "Siṓn", "pronunciation": "see-own'", "derivation": "of Hebrew origin ((G6726));", "definition": "Sion (i.e. Tsijon), a hill of Jerusalem; figuratively, the Church (militant or triumphant)", "kjv": "Sion."}, "G4623": {"greek": "σιωπάω", "translit": "siōpáō", "pronunciation": "see-o-pah'-o", "derivation": "from (silence, i.e. a hush; properly, muteness, i.e. involuntary stillness, or inability to speak; and thus differing from (G4602), which is rather a voluntary refusal or indisposition to speak, although the terms are often used synonymously);", "definition": "to be dumb (but not deaf also, like 2974 properly); figuratively, to be calm (as quiet water)", "kjv": "dumb, (hold) peace."}, "G4624": {"greek": "σκανδαλίζω", "translit": "skandalízō", "pronunciation": "skan-dal-id'-zo", "derivation": "from (G4625);", "definition": "to entrap, i.e. trip up (figuratively, stumble (transitively) or entice to sin, apostasy or displeasure)", "kjv": "(make to) offend."}, "G4625": {"greek": "σκάνδαλον", "translit": "skándalon", "pronunciation": "skan'-dal-on", "derivation": "(\"scandal\"); probably from a derivative of (G2578);", "definition": "a trap-stick (bent sapling), i.e. snare (figuratively, cause of displeasure or sin)", "kjv": "occasion to fall (of stumbling), offence, thing that offends, stumblingblock."}, "G4626": {"greek": "σκάπτω", "translit": "skáptō", "pronunciation": "skap'-to", "derivation": "apparently a primary verb;", "definition": "to dig", "kjv": "dig."}, "G4627": {"greek": "σκάφη", "translit": "skáphē", "pronunciation": "skaf'-ay", "derivation": "", "definition": "a \"skiff\" (as if dug out), or yawl (carried aboard a large vessel for landing)", "kjv": "boat."}, "G4628": {"greek": "σκέλος", "translit": "skélos", "pronunciation": "skel'-os", "derivation": "apparently from (to parch;", "definition": "through the idea of leanness); the leg (as lank)", "kjv": "leg."}, "G4629": {"greek": "σκέπασμα", "translit": "sképasma", "pronunciation": "skep'-as-mah", "derivation": "from a derivative of (a covering; perhaps akin to the base of (G4649) through the idea of noticeableness);", "definition": "clothing", "kjv": "raiment."}, "G4630": {"greek": "Σκευᾶς", "translit": "Skeuâs", "pronunciation": "skyoo-as'", "derivation": "apparently of Latin origin;", "definition": "left-handed; Scevas (i.e. Scævus), an Israelite", "kjv": "Sceva."}, "G4631": {"greek": "σκευή", "translit": "skeuḗ", "pronunciation": "skyoo-ay'", "derivation": "from (G4632);", "definition": "furniture, i.e. spare tackle", "kjv": "tackling."}, "G4632": {"greek": "σκεῦος", "translit": "skeûos", "pronunciation": "skyoo'-os", "derivation": "of uncertain affinity;", "definition": "a vessel, implement, equipment or apparatus (literally or figuratively [specially, a wife as contributing to the usefulness of the husband])", "kjv": "goods, sail, stuff, vessel."}, "G4633": {"greek": "σκηνή", "translit": "skēnḗ", "pronunciation": "skay-nay'", "derivation": "apparently akin to (G4632) and (G4639);", "definition": "a tent or cloth hut (literally or figuratively)", "kjv": "habitation, tabernacle."}, "G4634": {"greek": "σκηνοπηγία", "translit": "skēnopēgía", "pronunciation": "skay-nop-ayg-ee'-ah", "derivation": "from (G4636) and (G4078);", "definition": "the Festival of Tabernacles (so called from the custom of erecting booths for temporary homes)", "kjv": "tabernacles."}, "G4635": {"greek": "σκηνοποιός", "translit": "skēnopoiós", "pronunciation": "skay-nop-oy-os'", "derivation": "from (G4633) and (G4160);", "definition": "a manufacturer of tents", "kjv": "tent-maker."}, "G4636": {"greek": "σκῆνος", "translit": "skēnos", "pronunciation": "skay'-nos", "derivation": "from (G4633);", "definition": "a hut or temporary residence, i.e. (figuratively) the human body (as the abode of the spirit)", "kjv": "tabernacle."}, "G4637": {"greek": "σκηνόω", "translit": "skēnóō", "pronunciation": "skay-no'-o", "derivation": "from (G4636);", "definition": "to tent or encamp, i.e. (figuratively) to occupy (as a mansion) or (specially), to reside (as God did in the Tabernacle of old, a symbol of protection and communion)", "kjv": "dwell."}, "G4638": {"greek": "σκήνωμα", "translit": "skḗnōma", "pronunciation": "skay'-no-mah", "derivation": "from (G4637);", "definition": "an encampment, i.e. (figuratively) the Temple (as God's residence), the body (as a tenement for the soul)", "kjv": "tabernacle."}, "G4639": {"greek": "σκιά", "translit": "skiá", "pronunciation": "skee'-ah", "derivation": "apparently a primary word;", "definition": "\"shade\" or a shadow (literally or figuratively (darkness of error or an adumbration))", "kjv": "shadow."}, "G4640": {"greek": "σκιρτάω", "translit": "skirtáō", "pronunciation": "skeer-tah'-o", "derivation": "akin to (to skip);", "definition": "to jump, i.e. sympathetically move (as the quickening of a fetus)", "kjv": "leap (for joy)."}, "G4641": {"greek": "σκληροκαρδία", "translit": "sklērokardía", "pronunciation": "sklay-rok-ar-dee'-ah", "derivation": "feminine of a compound of (G4642) and (G2588);", "definition": "hard-heartedness, i.e. (specially), destitution of (spiritual) perception", "kjv": "hardness of heart."}, "G4642": {"greek": "σκληρός", "translit": "sklērós", "pronunciation": "sklay-ros'", "derivation": "from the base of (G4628);", "definition": "dry, i.e. hard or tough (figuratively, harsh, severe)", "kjv": "fierce, hard."}, "G4643": {"greek": "σκληρότης", "translit": "sklērótēs", "pronunciation": "sklay-rot'-ace", "derivation": "from (G4642);", "definition": "callousness, i.e. (figuratively) stubbornness", "kjv": "hardness."}, "G4644": {"greek": "σκληροτράχηλος", "translit": "sklērotráchēlos", "pronunciation": "sklay-rot-rakh'-ay-los", "derivation": "from (G4642) and (G5137);", "definition": "hardnaped, i.e. (figuratively) obstinate", "kjv": "stiffnecked."}, "G4645": {"greek": "σκληρύνω", "translit": "sklērýnō", "pronunciation": "sklay-roo'-no", "derivation": "from (G4642);", "definition": "to indurate, i.e. (figuratively) render stubborn", "kjv": "harden."}, "G4646": {"greek": "σκολιός", "translit": "skoliós", "pronunciation": "skol-ee-os'", "derivation": "from the base of (G4628);", "definition": "warped, i.e. winding; figuratively, perverse", "kjv": "crooked, froward, untoward."}, "G4647": {"greek": "σκόλοψ", "translit": "skólops", "pronunciation": "skol'-ops", "derivation": "perhaps from the base of (G4628) and (G3700);", "definition": "withered at the front, i.e. a point or prickle (figuratively, a bodily annoyance or disability)", "kjv": "thorn."}, "G4648": {"greek": "σκοπέω", "translit": "skopéō", "pronunciation": "skop-eh'-o", "derivation": "from (G4649);", "definition": "to take aim at (spy), i.e. (figuratively) regard", "kjv": "consider, take heed, look at (on), mark."}, "G4649": {"greek": "σκοπός", "translit": "skopós", "pronunciation": "skop-os'", "derivation": "from (to peer about (\"skeptic\"); perhaps akin to (G4626) through the idea of concealment; compare (G4629));", "definition": "a watch (sentry or scout), i.e. (by implication) a goal", "kjv": "mark."}, "G4650": {"greek": "σκορπίζω", "translit": "skorpízō", "pronunciation": "skor-pid'-zo", "derivation": "apparently from the same as (G4651) (through the idea of penetrating);", "definition": "to dissipate, i.e. (figuratively) put to flight, waste, be liberal", "kjv": "disperse abroad, scatter (abroad)."}, "G4651": {"greek": "σκορπίος", "translit": "skorpíos", "pronunciation": "skor-pee'-os", "derivation": "probably from an obsolete (perhaps strengthened from the base of (G4649) and meaning to pierce);", "definition": "a \"scorpion\" (from its sting)", "kjv": "scorpion."}, "G4652": {"greek": "σκοτεινός", "translit": "skoteinós", "pronunciation": "skot-i-nos'", "derivation": "from (G4655);", "definition": "opaque, i.e. (figuratively) benighted", "kjv": "dark, full of darkness."}, "G4653": {"greek": "σκοτία", "translit": "skotía", "pronunciation": "skot-ee'-ah", "derivation": "from (G4655);", "definition": "dimness, obscurity (literally or figuratively)", "kjv": "dark(-ness)."}, "G4654": {"greek": "σκοτίζω", "translit": "skotízō", "pronunciation": "skot-id-zo", "derivation": "from (G4655);", "definition": "to obscure (literally or figuratively)", "kjv": "darken."}, "G4655": {"greek": "σκότος", "translit": "skótos", "pronunciation": "skot'-os", "derivation": "from the base of (G4639);", "definition": "shadiness, i.e. obscurity (literally or figuratively)", "kjv": "darkness."}, "G4656": {"greek": "σκοτόω", "translit": "skotóō", "pronunciation": "skot-o'-o", "derivation": "from (G4655);", "definition": "to obscure or blind (literally or figuratively)", "kjv": "be full of darkness."}, "G4657": {"greek": "σκύβαλον", "translit": "skýbalon", "pronunciation": "skoo'-bal-on", "derivation": "neuter of a presumed derivative of (G1519) and (G2965) and (G906);", "definition": "what is thrown to the dogs, i.e. refuse (ordure)", "kjv": "dung."}, "G4658": {"greek": "Σκύθης", "translit": "Skýthēs", "pronunciation": "skoo'-thace", "derivation": "probably of foreign origin;", "definition": "a Scythene or Scythian, i.e. (by implication) a savage", "kjv": "Scythian."}, "G4659": {"greek": "σκυθρωπός", "translit": "skythrōpós", "pronunciation": "skoo-thro-pos'", "derivation": "from (sullen) and a derivative of (G3700);", "definition": "angry-visaged, i.e. gloomy or affecting a mournful appearance", "kjv": "of a sad countenance."}, "G4660": {"greek": "σκύλλω", "translit": "skýllō", "pronunciation": "skool'-lo", "derivation": "apparently a primary verb;", "definition": "to flay, i.e. (figuratively) to harass", "kjv": "trouble(self)."}, "G4661": {"greek": "σκῦλον", "translit": "skŷlon", "pronunciation": "skoo'-lon", "derivation": "neuter from (G4660);", "definition": "something stripped (as a hide), i.e. booty", "kjv": "spoil."}, "G4662": {"greek": "σκωληκόβρωτος", "translit": "skōlēkóbrōtos", "pronunciation": "sko-lay-kob'-ro-tos", "derivation": "from (G4663) and a derivative of (G977);", "definition": "worm-eaten, i.e. diseased with maggots", "kjv": "eaten of worms."}, "G4663": {"greek": "σκώληξ", "translit": "skṓlēx", "pronunciation": "sko'-lakes", "derivation": "of uncertain derivation;", "definition": "a grub, maggot or earth-worm", "kjv": "worm."}, "G4664": {"greek": "σμαράγδινος", "translit": "smarágdinos", "pronunciation": "smar-ag'-dee-nos", "derivation": "from (G4665);", "definition": "consisting of emerald", "kjv": "emerald."}, "G4665": {"greek": "σμάραγδος", "translit": "smáragdos", "pronunciation": "smar'-ag-dos", "derivation": "of uncertain derivation;", "definition": "the emerald or green gem so called", "kjv": "emerald."}, "G4666": {"greek": "σμύρνα", "translit": "smýrna", "pronunciation": "smoor'-nah", "derivation": "apparently strengthened for (G3464);", "definition": "myrrh", "kjv": "myrrh."}, "G4667": {"greek": "Σμύρνα", "translit": "Smýrna", "pronunciation": "smoor'-nah", "derivation": "the same as (G4666);", "definition": "Smyrna, a place in Asia Minor", "kjv": "Smyrna."}, "G4669": {"greek": "σμυρνίζω", "translit": "smyrnízō", "pronunciation": "smoor-nid'-zo", "derivation": "from (G4667);", "definition": "to tincture with myrrh, i.e. embitter (as a narcotic)", "kjv": "mingle with myrrh."}, "G4670": {"greek": "Σόδομα", "translit": "Sódoma", "pronunciation": "sod'-om-ah", "derivation": "plural of Hebrew origin ((G5467));", "definition": "Sodoma (i.e. Sedom), a place in Palestine", "kjv": "Sodom."}, "G4671": {"greek": "σοί", "translit": "soí", "pronunciation": "soy", "derivation": "dative case of (G4771);", "definition": "to thee", "kjv": "thee, thine own, thou, thy."}, "G4672": {"greek": "Σολομών", "translit": "Solomṓn", "pronunciation": "sol-om-one'", "derivation": "of Hebrew origin ((G8010));", "definition": "Solomon (i.e. Shelomoh), the son of David", "kjv": "Solomon."}, "G4673": {"greek": "σορός", "translit": "sorós", "pronunciation": "sor-os'", "derivation": "probably akin to the base of (G4987);", "definition": "a funereal receptacle (urn, coffin), i.e. (by analogy) a bier", "kjv": "bier."}, "G4674": {"greek": "σός", "translit": "sós", "pronunciation": "sos", "derivation": "from (G4771);", "definition": "thine", "kjv": "thine (own), thy (friend)."}, "G4675": {"greek": "σοῦ", "translit": "soû", "pronunciation": "soo", "derivation": "genitive case of (G4771);", "definition": "of thee, thy", "kjv": "X home, thee, thine (own), thou, thy."}, "G4676": {"greek": "σουδάριον", "translit": "soudárion", "pronunciation": "soo-dar'-ee-on", "derivation": "of Latin origin;", "definition": "a sudarium (sweat-cloth), i.e. towel (for wiping the perspiration from the face, or binding the face of a corpse)", "kjv": "handkerchief, napkin."}, "G4677": {"greek": "Σουσάννα", "translit": "Sousánna", "pronunciation": "soo-san'-nah", "derivation": "of Hebrew origin ((G7799) feminine);", "definition": "lily; Susannah (i.e. Shoshannah), an Israelitess", "kjv": "Susanna."}, "G4678": {"greek": "σοφία", "translit": "sophía", "pronunciation": "sof-ee'-ah", "derivation": "from (G4680);", "definition": "wisdom (higher or lower, worldly or spiritual)", "kjv": "wisdom."}, "G4679": {"greek": "σοφίζω", "translit": "sophízō", "pronunciation": "sof-id'-zo", "derivation": "from (G4680);", "definition": "to render wise; in a sinister acceptation, to form \"sophisms\", i.e. continue plausible error", "kjv": "cunningly devised, make wise."}, "G4680": {"greek": "σοφός", "translit": "sophós", "pronunciation": "sof-os'", "derivation": "akin to (clear);", "definition": "wise (in a most general application)", "kjv": "wise."}, "G4681": {"greek": "Σπανία", "translit": "Spanía", "pronunciation": "span-ee'-ah", "derivation": "probably of foreign origin;", "definition": "Spania, a region of Europe", "kjv": "Spain."}, "G4682": {"greek": "σπαράσσω", "translit": "sparássō", "pronunciation": "spar-as'-so", "derivation": "prolongation from (to grasp;", "definition": "apparently strengthened from (G4685) through the idea of spasmodic contraction); to mangle, i.e. convluse with epilepsy", "kjv": "rend, tear."}, "G4683": {"greek": "σπαργανόω", "translit": "sparganóō", "pronunciation": "spar-gan-o'-o", "derivation": "from (a strip; from a derivative of the base of (G4682) meaning to strap or wrap with strips);", "definition": "to swathe (an infant after the Oriental custom)", "kjv": "wrap in swaddling clothes."}, "G4684": {"greek": "σπαταλάω", "translit": "spataláō", "pronunciation": "spat-al-ah'-o", "derivation": "from (luxury);", "definition": "to be voluptuous", "kjv": "live in pleasure, be wanton."}, "G4685": {"greek": "σπάω", "translit": "spáō", "pronunciation": "spah'-o", "derivation": "a primary verb;", "definition": "to draw", "kjv": "draw (out)."}, "G4686": {"greek": "σπεῖρα", "translit": "speîra", "pronunciation": "spi'-rah", "derivation": "of immediate Latin origin, but ultimately a derivative of (G138) in the sense of its cognate (G1507);", "definition": "a coil (spira, \"spire\"), i.e. (figuratively) a mass of men (a Roman military cohort; also (by analogy) a squad of Levitical janitors)", "kjv": "band."}, "G4687": {"greek": "σπείρω", "translit": "speírō", "pronunciation": "spi'-ro", "derivation": "probably strengthened from (G4685) (through the idea of extending);", "definition": "to scatter, i.e. sow (literally or figuratively)", "kjv": "sow(- er), receive seed."}, "G4688": {"greek": "σπεκουλάτωρ", "translit": "spekoulátōr", "pronunciation": "spek-oo-lat'-ore", "derivation": "of Latin origin;", "definition": "a speculator, i.e. military scout (spy or (by extension) life-guardsman)", "kjv": "executioner."}, "G4689": {"greek": "σπένδω", "translit": "spéndō", "pronunciation": "spen'-do", "derivation": "apparently a primary verb;", "definition": "to pour out as a libation, i.e. (figuratively) to devote (one's life or blood, as a sacrifice) (\"spend\")", "kjv": "(be ready to) be offered."}, "G4690": {"greek": "σπέρμα", "translit": "spérma", "pronunciation": "sper'-mah", "derivation": "from (G4687);", "definition": "something sown, i.e. seed (including the male \"sperm\"); by implication, offspring; specially, a remnant (figuratively, as if kept over for planting)", "kjv": "issue, seed."}, "G4691": {"greek": "σπερμολόγος", "translit": "spermológos", "pronunciation": "sper-mol-og'-os", "derivation": "from (G4690) and (G3004);", "definition": "a seed-picker (as the crow), i.e. (figuratively) a sponger, loafer (specially, a gossip or trifler in talk)", "kjv": "babbler."}, "G4692": {"greek": "σπεύδω", "translit": "speúdō", "pronunciation": "spyoo'-do", "derivation": "probably strengthened from (G4228);", "definition": "to \"speed\" (\"study\"), i.e. urge on (diligently or earnestly); by implication, to await eagerly", "kjv": "(make, with) haste unto."}, "G4693": {"greek": "σπήλαιον", "translit": "spḗlaion", "pronunciation": "spay'-lah-yon", "derivation": "neuter of a presumed derivative of (a grotto);", "definition": "a cavern; by implication, a hiding-place or resort", "kjv": "cave, den."}, "G4694": {"greek": "σπιλάς", "translit": "spilás", "pronunciation": "spee-las'", "derivation": "of uncertain derivation;", "definition": "a ledge or reef of rock in the sea", "kjv": "spot (by confusion with (G4696))."}, "G4695": {"greek": "σπιλόω", "translit": "spilóō", "pronunciation": "spee-lo'-o", "derivation": "from (G4696);", "definition": "to stain or soil (literally or figuratively)", "kjv": "defile, spot."}, "G4696": {"greek": "σπίλος", "translit": "spílos", "pronunciation": "spee'-los", "derivation": "of uncertain derivation;", "definition": "a stain or blemish, i.e. (figuratively) defect, disgrace", "kjv": "spot."}, "G4697": {"greek": "σπλαγχνίζομαι", "translit": "splanchnízomai", "pronunciation": "splangkh-nid'-zom-ahee", "derivation": "middle voice from (G4698);", "definition": "to have the bowels yearn, i.e. (figuratively) feel sympathy, to pity", "kjv": "have (be moved with) compassion."}, "G4698": {"greek": "σπλάγχνον", "translit": "splánchnon", "pronunciation": "splangkh'-non", "derivation": "probably strengthened from (the \"spleen\");", "definition": "an intestine (plural); figuratively, pity or sympathy", "kjv": "bowels, inward affection, + tender mercy."}, "G4699": {"greek": "σπόγγος", "translit": "spóngos", "pronunciation": "spong'-gos", "derivation": "perhaps of foreign origin;", "definition": "a \"sponge\"", "kjv": "spunge."}, "G4700": {"greek": "σποδός", "translit": "spodós", "pronunciation": "spod-os'", "derivation": "of uncertain derivation;", "definition": "ashes", "kjv": "ashes."}, "G4701": {"greek": "σπορά", "translit": "sporá", "pronunciation": "spor-ah'", "derivation": "from (G4687);", "definition": "a sowing, i.e. (by implication) parentage", "kjv": "seed."}, "G4702": {"greek": "σπόριμος", "translit": "spórimos", "pronunciation": "spor'-ee-mos", "derivation": "from (G4703);", "definition": "sown, i.e. (neuter plural) a planted field", "kjv": "corn(-field)."}, "G4703": {"greek": "σπόρος", "translit": "spóros", "pronunciation": "spro'-os", "derivation": "from (G4687);", "definition": "a scattering (of seed), i.e. (concretely) seed (as sown)", "kjv": "seed (X sown)."}, "G4704": {"greek": "σπουδάζω", "translit": "spoudázō", "pronunciation": "spoo-dad'-zo", "derivation": "from (G4710);", "definition": "to use speed, i.e. to make effort, be prompt or earnest", "kjv": "do (give) diligence, be diligent (forward), endeavour, labour, study."}, "G4705": {"greek": "σπουδαῖος", "translit": "spoudaîos", "pronunciation": "spoo-dah'-yos", "derivation": "from (G4710);", "definition": "prompt, energetic, earnest", "kjv": "diligent."}, "G4709": {"greek": "σπουδαίως", "translit": "spoudaíōs", "pronunciation": "spoo-dah'-yoce", "derivation": "adverb from (G4705);", "definition": "earnestly, promptly", "kjv": "diligently, instantly."}, "G4710": {"greek": "σπουδή", "translit": "spoudḗ", "pronunciation": "spoo-day'", "derivation": "from (G4692);", "definition": "\"speed\", i.e. (by implication) despatch, eagerness, earnestness", "kjv": "business, (earnest) care(-fulness), diligence, forwardness, haste."}, "G4711": {"greek": "σπυρίς", "translit": "spyrís", "pronunciation": "spoo-rece'", "derivation": "from (G4687) (as woven);", "definition": "a hamper or lunch-receptacle", "kjv": "basket."}, "G4712": {"greek": "στάδιον", "translit": "stádion", "pronunciation": "stad'-ee-on", "derivation": "from the base of (G2476) (as fixed);", "definition": "a stade or certain measure of distance; by implication, a stadium or race-course", "kjv": "furlong, race."}, "G4713": {"greek": "στάμνος", "translit": "stámnos", "pronunciation": "stam'-nos", "derivation": "from the base of (G2476) (as stationary);", "definition": "a jar or earthen tank", "kjv": "pot."}, "G4714": {"greek": "στάσις", "translit": "stásis", "pronunciation": "stas'-is", "derivation": "from the base of (G2476);", "definition": "a standing (properly, the act), i.e. (by analogy) position (existence); by implication, a popular uprising; figuratively, controversy", "kjv": "dissension, insurrection, X standing, uproar."}, "G4715": {"greek": "στατήρ", "translit": "statḗr", "pronunciation": "stat-air'", "derivation": "from the base of (G2746);", "definition": "a stander (standard of value), i.e. (specially), a stater or certain coin", "kjv": "piece of money."}, "G4716": {"greek": "σταυρός", "translit": "staurós", "pronunciation": "stow-ros'", "derivation": "from the base of (G2476);", "definition": "a stake or post (as set upright), i.e. (specially), a pole or cross (as an instrument of capital punishment); figuratively, exposure to death, i.e. self-denial; by implication, the atonement of Christ", "kjv": "cross."}, "G4717": {"greek": "σταυρόω", "translit": "stauróō", "pronunciation": "stow-ro'-o", "derivation": "from (G4716);", "definition": "to impale on the cross; figuratively, to extinguish (subdue) passion or selfishness", "kjv": "crucify."}, "G4718": {"greek": "σταφυλή", "translit": "staphylḗ", "pronunciation": "staf-oo-lay'", "derivation": "probably from the base of (G4735);", "definition": "a cluster of grapes (as if intertwined)", "kjv": "grapes."}, "G4719": {"greek": "στάχυς", "translit": "stáchys", "pronunciation": "stakh'-oos", "derivation": "from the base of (G2476);", "definition": "a head of grain (as standing out from the stalk)", "kjv": "ear (of corn)."}, "G4720": {"greek": "Στάχυς", "translit": "Stáchys", "pronunciation": "stakh'-oos", "derivation": "the same as (G4719);", "definition": "Stachys, a Christian", "kjv": "Stachys."}, "G4721": {"greek": "στέγη", "translit": "stégē", "pronunciation": "steg'-ay", "derivation": "strengthened from a primary (a \"thatch\" or \"deck\" of a building);", "definition": "a roof", "kjv": "roof."}, "G4722": {"greek": "στέγω", "translit": "stégō", "pronunciation": "steg'-o", "derivation": "from (G4721);", "definition": "to roof over, i.e. (figuratively) to cover with silence (endure patiently)", "kjv": "(for-)bear, suffer."}, "G4723": {"greek": "στείρος", "translit": "steíros", "pronunciation": "sti'-ros", "derivation": "a contraction from (G4731) (as stiff and unnatural);", "definition": "\"sterile\"", "kjv": "barren."}, "G4724": {"greek": "στέλλω", "translit": "stéllō", "pronunciation": "stel'-lo", "derivation": "probably strengthened from the base of (G2476);", "definition": "properly, to set fast (\"stall\"), i.e. (figuratively) to repress (reflexively, abstain from associating with)", "kjv": "avoid, withdraw self."}, "G4725": {"greek": "στέμμα", "translit": "stémma", "pronunciation": "stem'-mah", "derivation": "from the base of (G4735);", "definition": "a wreath for show", "kjv": "garland."}, "G4726": {"greek": "στεναγμός", "translit": "stenagmós", "pronunciation": "sten-ag-mos'", "derivation": "from (G4727);", "definition": "a sigh", "kjv": "groaning."}, "G4727": {"greek": "στενάζω", "translit": "stenázō", "pronunciation": "sten-ad'-zo", "derivation": "from (G4728);", "definition": "to make (intransitively, be) in straits, i.e. (by implication) to sigh, murmur, pray inaudibly", "kjv": "with grief, groan, grudge, sigh."}, "G4728": {"greek": "στενός", "translit": "stenós", "pronunciation": "sten-os'", "derivation": "probably from the base of (G2476);", "definition": "narrow (from obstacles standing close about)", "kjv": "strait."}, "G4729": {"greek": "στενοχωρέω", "translit": "stenochōréō", "pronunciation": "sten-okh-o-reh'-o", "derivation": "from the same as (G4730);", "definition": "to hem in closely, i.e. (figuratively) cramp", "kjv": "distress, straiten."}, "G4730": {"greek": "στενοχωρία", "translit": "stenochōría", "pronunciation": "sten-okh-o-ree'-ah", "derivation": "from a compound of (G4728) and (G5561);", "definition": "narrowness of room, i.e. (figuratively) calamity", "kjv": "anguish, distress."}, "G4731": {"greek": "στερεός", "translit": "stereós", "pronunciation": "ster-eh-os'", "derivation": "from (G2476);", "definition": "stiff, i.e. solid, stable (literally or figuratively)", "kjv": "stedfast, strong, sure."}, "G4732": {"greek": "στερεόω", "translit": "stereóō", "pronunciation": "ster-eh-o'-o", "derivation": "from (G4731);", "definition": "to solidify, i.e. confirm (literally or figuratively)", "kjv": "establish, receive strength, make strong."}, "G4733": {"greek": "στερέωμα", "translit": "steréōma", "pronunciation": "ster-eh'-o-mah", "derivation": "from (G4732);", "definition": "something established, i.e. (abstractly) confirmation (stability)", "kjv": "stedfastness."}, "G4734": {"greek": "Στεφανᾶς", "translit": "Stephanâs", "pronunciation": "stef-an-as'", "derivation": "probably contraction for (crowned; from (G4737));", "definition": "Stephanas, a Christian", "kjv": "Stephanas."}, "G4735": {"greek": "στέφανος", "translit": "stéphanos", "pronunciation": "stef'-an-os", "derivation": "from an apparently primary (to twine or wreathe);", "definition": "a chaplet (as a badge of royalty, a prize in the public games or a symbol of honor generally; but more conspicuous and elaborate than the simple fillet, (G1238)), literally or figuratively", "kjv": "crown."}, "G4737": {"greek": "στεφανόω", "translit": "stephanóō", "pronunciation": "stef-an-o'-o", "derivation": "from (G4735);", "definition": "to adorn with an honorary wreath (literally or figuratively)", "kjv": "crown."}, "G4738": {"greek": "στῆθος", "translit": "stēthos", "pronunciation": "stay'-thos", "derivation": "from (G2476) (as standing prominently);", "definition": "the (entire external) bosom, i.e. chest", "kjv": "breast."}, "G4739": {"greek": "στήκω", "translit": "stḗkō", "pronunciation": "stay'-ko", "derivation": "from the perfect tense of (G2476);", "definition": "to be stationary, i.e. (figuratively) to persevere", "kjv": "stand (fast)."}, "G4740": {"greek": "στηριγμός", "translit": "stērigmós", "pronunciation": "stay-rig-mos'", "derivation": "from (G4741);", "definition": "stability (figuratively)", "kjv": "stedfastness."}, "G4741": {"greek": "στηρίζω", "translit": "stērízō", "pronunciation": "stay-rid'-zo", "derivation": "from a presumed derivative of (G2476) (like (G4731));", "definition": "to set fast, i.e. (literally) to turn resolutely in a certain direction, or (figuratively) to confirm", "kjv": "fix, (e-)stablish, stedfastly set, strengthen."}, "G4742": {"greek": "στίγμα", "translit": "stígma", "pronunciation": "stig'-mah", "derivation": "from a primary (to \"stick\", i.e. prick);", "definition": "a mark incised or punched (for recognition of ownership), i.e. (figuratively) scar of service", "kjv": "mark."}, "G4743": {"greek": "στιγμή", "translit": "stigmḗ", "pronunciation": "stig-may'", "derivation": "feminine of (G4742);", "definition": "a point of time, i.e. an instant", "kjv": "moment."}, "G4744": {"greek": "στίλβω", "translit": "stílbō", "pronunciation": "stil'-bo", "derivation": "apparently a primary verb;", "definition": "to gleam, i.e. flash intensely", "kjv": "shining."}, "G4745": {"greek": "στοά", "translit": "stoá", "pronunciation": "sto-ah'", "derivation": "probably from (G2476);", "definition": "a colonnade or interior piazza", "kjv": "porch."}, "G4746": {"greek": "στοιβάς", "translit": "stoibás", "pronunciation": "stoy-bas'", "derivation": "from a primary (to \"step\" or \"stamp\");", "definition": "a spread (as if tramped flat) of loose materials for a couch, i.e. (by implication) a bough of a tree so employed", "kjv": "branch."}, "G4747": {"greek": "στοιχεῖον", "translit": "stoicheîon", "pronunciation": "stoy-khi'-on", "derivation": "neuter of a presumed derivative of the base of (G4748);", "definition": "something orderly in arrangement, i.e. (by implication) a serial (basal, fundamental, initial) constituent (literally), proposition (figuratively)", "kjv": "element, principle, rudiment."}, "G4748": {"greek": "στοιχέω", "translit": "stoichéō", "pronunciation": "stoy-kheh'-o", "derivation": "from a derivative of (to range in regular line);", "definition": "to march in (military) rank (keep step), i.e. (figuratively) to conform to virtue and piety", "kjv": "walk (orderly)."}, "G4749": {"greek": "στολή", "translit": "stolḗ", "pronunciation": "stol-ay'", "derivation": "from (G4724);", "definition": "equipment, i.e. (specially), a \"stole\" or long-fitting gown (as a mark of dignity)", "kjv": "long clothing (garment), (long) robe."}, "G4750": {"greek": "στόμα", "translit": "stóma", "pronunciation": "stom'-a", "derivation": "probably strengthened from a presumed derivative of the base of (G5114);", "definition": "the mouth (as if a gash in the face); by implication, language (and its relations); figuratively, an opening (in the earth); specially, the front or edge (of a weapon)", "kjv": "edge, face, mouth."}, "G4751": {"greek": "στόμαχος", "translit": "stómachos", "pronunciation": "stom'-akh-os", "derivation": "from (G4750);", "definition": "an orifice (the gullet), i.e. (specially), the \"stomach\"", "kjv": "stomach."}, "G4752": {"greek": "στρατεία", "translit": "strateía", "pronunciation": "strat-i'-ah", "derivation": "from (G4754);", "definition": "military service, i.e. (figuratively) the apostolic career (as one of hardship and danger)", "kjv": "warfare."}, "G4753": {"greek": "στράτευμα", "translit": "stráteuma", "pronunciation": "strat'-yoo-mah", "derivation": "from (G4754);", "definition": "an armament, i.e. (by implication) a body of troops (more or less extensive or systematic)", "kjv": "army, soldier, man of war."}, "G4754": {"greek": "στρατεύομαι", "translit": "strateúomai", "pronunciation": "strat-yoo'-om-ahee", "derivation": "middle voice from the base of (G4756);", "definition": "to serve in a military campaign; figuratively, to execute the apostolate (with its arduous duties and functions), to contend with carnal inclinations", "kjv": "soldier, (go to) war(-fare)."}, "G4755": {"greek": "στρατηγός", "translit": "stratēgós", "pronunciation": "strat-ay-gos'", "derivation": "from the base of (G4756) and (G71) or (G2233);", "definition": "a general, i.e. (by implication or analogy) a (military) governor (prætor), the chief (præfect) of the (Levitical) temple-wardens", "kjv": "captain, magistrate."}, "G4756": {"greek": "στρατιά", "translit": "stratiá", "pronunciation": "strat-ee'-ah", "derivation": "feminine of a derivative of (an army;", "definition": "from the base of (G4766), as encamped); camp-likeness, i.e. an army, i.e. (figuratively) the angels, the celestial luminaries", "kjv": "host."}, "G4757": {"greek": "στρατιώτης", "translit": "stratiṓtēs", "pronunciation": "strat-ee-o'-tace", "derivation": "from a presumed derivative of the same as (G4756);", "definition": "a camper-out, i.e. a (common) warrior (literally or figuratively)", "kjv": "soldier."}, "G4758": {"greek": "στρατολογέω", "translit": "stratologéō", "pronunciation": "strat-ol-og-eh'-o", "derivation": "from a compound of the base of (G4756) and (G3004) (in its original sense);", "definition": "to gather (or select) as a warrior, i.e. enlist in the army", "kjv": "choose to be a soldier."}, "G4760": {"greek": "στρατόπεδον", "translit": "stratópedon", "pronunciation": "strat-op'-ed-on", "derivation": "from the base of (G4756) and the same as (G3977);", "definition": "a camping-ground, i.e. (by implication) a body of troops", "kjv": "army."}, "G4761": {"greek": "στρεβλόω", "translit": "streblóō", "pronunciation": "streb-lo'-o", "derivation": "from a derivative of (G4762);", "definition": "to wrench, i.e. (specially), to torture (by the rack), but only figuratively, to pervert", "kjv": "wrest."}, "G4762": {"greek": "στρέφω", "translit": "stréphō", "pronunciation": "stref'-o", "derivation": "strengthened from the base of (G5157);", "definition": "to twist, i.e. turn quite around or reverse (literally or figuratively)", "kjv": "convert, turn (again, back again, self, self about)."}, "G4763": {"greek": "στρηνιάω", "translit": "strēniáō", "pronunciation": "stray-nee-ah'-o", "derivation": "from a presumed derivative of (G4764);", "definition": "to be luxurious", "kjv": "live deliciously."}, "G4764": {"greek": "στρῆνος", "translit": "strēnos", "pronunciation": "stray'-nos", "derivation": "akin to (G4731);", "definition": "a \"straining\", \"strenuousness\" or \"strength\", i.e. (figuratively) luxury (voluptuousness)", "kjv": "delicacy."}, "G4765": {"greek": "στρουθίον", "translit": "strouthíon", "pronunciation": "stroo-thee'-on", "derivation": "diminutive of (a sparrow);", "definition": "a little sparrow", "kjv": "sparrow."}, "G4766": {"greek": "στρώννυμι", "translit": "strṓnnymi", "pronunciation": "strone'-noo-mee", "derivation": "prolongation from a still simpler , (used only as an alternate in certain tenses) (probably akin to (G4731) through the idea of positing);", "definition": "to \"strew,\" i.e. spread (as a carpet or couch)", "kjv": "make bed, furnish, spread, strew."}, "G4767": {"greek": "στυγνητός", "translit": "stygnētós", "pronunciation": "stoog-nay-tos'", "derivation": "from a derivative of an obsolete apparently primary (to hate);", "definition": "hated, i.e. odious", "kjv": "hateful."}, "G4768": {"greek": "στυγνάζω", "translit": "stygnázō", "pronunciation": "stoog-nad'-zo", "derivation": "from the same as (G4767);", "definition": "to render gloomy, i.e. (by implication) glower (be overcast with clouds, or sombreness of speech)", "kjv": "lower, be sad."}, "G4769": {"greek": "στῦλος", "translit": "stŷlos", "pronunciation": "stoo'-los", "derivation": "from (to stiffen; properly akin to the base of (G2476));", "definition": "a post (\"style\"), i.e. (figuratively) support", "kjv": "pillar."}, "G4770": {"greek": "Στωϊκός", "translit": "Stōïkós", "pronunciation": "sto-ik-os'", "derivation": "from (G4745);", "definition": "a \"Stoic\" (as occupying a particular porch in Athens), i.e. adherent of a certin philosophy", "kjv": "Stoick."}, "G4771": {"greek": "σύ", "translit": "sý", "pronunciation": "soo", "derivation": "the personal pronoun of the second person singular;", "definition": "thou", "kjv": "thou."}, "G4772": {"greek": "συγγένεια", "translit": "syngéneia", "pronunciation": "soong-ghen'-i-ah", "derivation": "from (G4773);", "definition": "relationship, i.e. (concretely) relatives", "kjv": "kindred."}, "G4773": {"greek": "συγγενής", "translit": "syngenḗs", "pronunciation": "soong-ghen-ace'", "derivation": "from (G4862) and (G1085);", "definition": "a relative (by blood); by extension, a fellow countryman", "kjv": "cousin, kin(-sfolk, -sman)."}, "G4774": {"greek": "συγγνώμη", "translit": "syngnṓmē", "pronunciation": "soong-gno'-may", "derivation": "from a compound of (G4862) and (G1097);", "definition": "fellow knowledge, i.e. concession", "kjv": "permission."}, "G4775": {"greek": "συγκάθημαι", "translit": "synkáthēmai", "pronunciation": "soong-kath'-ay-mahee", "derivation": "from (G4862) and (G2521);", "definition": "to seat oneself in company with", "kjv": "sit with."}, "G4776": {"greek": "συγκαθίζω", "translit": "synkathízō", "pronunciation": "soong-kath-id'-zo", "derivation": "from (G4862) and (G2523);", "definition": "to give (or take) a seat in company with", "kjv": "(make) sit (down) together."}, "G4777": {"greek": "συγκακοπαθέω", "translit": "synkakopathéō", "pronunciation": "soong-kak-op-ath-eh'-o", "derivation": "from (G4862) and (G2553);", "definition": "to suffer hardship in company with", "kjv": "be partaker of afflictions."}, "G4778": {"greek": "συγκακουχέω", "translit": "synkakouchéō", "pronunciation": "soong-kak-oo-kheh'-o", "derivation": "from (G4862) and (G2558);", "definition": "to maltreat in company with, i.e. (passively) endure persecution together", "kjv": "suffer affliction with."}, "G4779": {"greek": "συγκαλέω", "translit": "synkaléō", "pronunciation": "soong-kal-eh'-o", "derivation": "from (G4862) and (G2564);", "definition": "to convoke", "kjv": "call together."}, "G4780": {"greek": "συγκαλύπτω", "translit": "synkalýptō", "pronunciation": "soong-kal-oop'-to", "derivation": "from (G4862) and (G2572);", "definition": "to conceal altogether", "kjv": "cover."}, "G4781": {"greek": "συγκάμπτω", "translit": "synkámptō", "pronunciation": "soong-kamp'-to", "derivation": "from (G4862) and (G2578);", "definition": "to bend together, i.e. (figuratively) to afflict", "kjv": "bow down."}, "G4782": {"greek": "συγκαταβαίνω", "translit": "synkatabaínō", "pronunciation": "soong-kat-ab-ah'-ee-no", "derivation": "from (G4862) and (G2597);", "definition": "to descend in company with", "kjv": "go down with."}, "G4783": {"greek": "συγκατάθεσις", "translit": "synkatáthesis", "pronunciation": "soong-kat-ath'-es-is", "derivation": "from (G4784);", "definition": "a deposition (of sentiment) in company with, i.e. (figuratively) accord with", "kjv": "agreement."}, "G4784": {"greek": "συγκατατίθεμαι", "translit": "synkatatíthemai", "pronunciation": "soong-kat-at-ith'-em-ahee", "derivation": "middle from (G4862) and (G2698);", "definition": "to deposit (one's vote or opinion) in company with, i.e. (figuratively) to accord with", "kjv": "consent."}, "G4785": {"greek": "συγκαταψηφίζω", "translit": "synkatapsēphízō", "pronunciation": "soong-kat-aps-ay-fid'-zo", "derivation": "from (G4862) and a compound of (G2596) and (G5585);", "definition": "to count down in company with, i.e. enroll among", "kjv": "number with."}, "G4786": {"greek": "συγκεράννυμι", "translit": "synkeránnymi", "pronunciation": "soong-ker-an'-noo-mee", "derivation": "from (G4862) and (G2767);", "definition": "to commingle, i.e. (figuratively) to combine or assimilate", "kjv": "mix with, temper together."}, "G4787": {"greek": "συγκινέω", "translit": "synkinéō", "pronunciation": "soong-kin-eh'-o", "derivation": "from (G4682) and (G2795);", "definition": "to move together, i.e. (specially), to excite as a mass (to sedition)", "kjv": "stir up."}, "G4788": {"greek": "συγκλείω", "translit": "synkleíō", "pronunciation": "soong-kli'-o", "derivation": "from (G4862) and (G2808);", "definition": "to shut together, i.e. include or (figuratively) embrace in a common subjection to", "kjv": "conclude, inclose, shut up."}, "G4789": {"greek": "συγκληρονόμος", "translit": "synklēronómos", "pronunciation": "soong-klay-ron-om'-os", "derivation": "from (G4862) and (G2818);", "definition": "a co-heir, i.e. (by analogy) participant in common", "kjv": "fellow (joint)-heir, heir together, heir with."}, "G4790": {"greek": "συγκοινωνέω", "translit": "synkoinōnéō", "pronunciation": "soong-koy-no-neh'-o", "derivation": "from (G4862) and (G2841);", "definition": "to share in company with, i.e. co-participate in", "kjv": "communicate (have fellowship) with, be partaker of."}, "G4791": {"greek": "συγκοινωνός", "translit": "synkoinōnós", "pronunciation": "soong-koy-no-nos'", "derivation": "from (G4862) and (G2844);", "definition": "a co-participant", "kjv": "companion, partake(-r, -r with)."}, "G4792": {"greek": "συγκομίζω", "translit": "synkomízō", "pronunciation": "soong-kom-id'-zo", "derivation": "from (G4862) and (G2865);", "definition": "to convey together, i.e. collect or bear away in company with others", "kjv": "carry."}, "G4793": {"greek": "συγκρίνω", "translit": "synkrínō", "pronunciation": "soong-kree'-no", "derivation": "from (G4862) and (G2919);", "definition": "to judge of one thing in connection with another, i.e. combine (spiritual ideas with appropriate expressions) or collate (one person with another by way of contrast or resemblance)", "kjv": "compare among (with)."}, "G4794": {"greek": "συγκύπτω", "translit": "synkýptō", "pronunciation": "soong-koop'-to", "derivation": "from (G4862) and (G2955);", "definition": "to stoop altogether, i.e. be completely overcome by", "kjv": "bow together."}, "G4795": {"greek": "συγκυρία", "translit": "synkyría", "pronunciation": "soong-koo-ree'-ah", "derivation": "from a compound of (G4862) and (to light or happen; from the base of (G2962));", "definition": "concurrence, i.e. accident", "kjv": "chance."}, "G4796": {"greek": "συγχαίρω", "translit": "synchaírō", "pronunciation": "soong-khah'-ee-ro", "derivation": "from (G4862) and (G5463);", "definition": "to sympathize in gladness, congratulate", "kjv": "rejoice in (with)."}, "G4797": {"greek": "συγχέω", "translit": "synchéō", "pronunciation": "soong-kheh'-o", "derivation": "from (G4862) and (to pour) or its alternate;", "definition": "to commingle promiscuously, i.e. (figuratively) to throw (an assembly) into disorder, to perplex (the mind)", "kjv": "confound, confuse, stir up, be in an uproar."}, "G4798": {"greek": "συγχράομαι", "translit": "synchráomai", "pronunciation": "soong-khrah'-om-ahee", "derivation": "from (G4862) and (G5530);", "definition": "to use jointly, i.e. (by implication) to hold intercourse in common", "kjv": "have dealings with."}, "G4799": {"greek": "σύγχυσις", "translit": "sýnchysis", "pronunciation": "soong'-khoo-sis", "derivation": "from (G4797);", "definition": "commixture, i.e. (figuratively) riotous disturbance", "kjv": "confusion."}, "G4800": {"greek": "συζάω", "translit": "syzáō", "pronunciation": "sood-zah'-o", "derivation": "from (G4862) and (G2198);", "definition": "to continue to live in common with, i.e. co-survive (literally or figuratively)", "kjv": "live with."}, "G4801": {"greek": "συζεύγνυμι", "translit": "syzeúgnymi", "pronunciation": "sood-zyoog'-noo-mee", "derivation": "from (G4862) and the base of (G2201);", "definition": "to yoke together, i.e. (figuratively) conjoin (in marriage)", "kjv": "join together."}, "G4802": {"greek": "συζητέω", "translit": "syzētéō", "pronunciation": "sood-zay-teh'-o", "derivation": "from (G4862) and (G2212);", "definition": "to investigate jointly, i.e. discuss, controvert, cavil", "kjv": "dispute (with), enquire, question (with), reason (together)."}, "G4804": {"greek": "συζητητής", "translit": "syzētētḗs", "pronunciation": "sood-zay-tay-tace'", "derivation": "from (G4802);", "definition": "a disputant, i.e. sophist", "kjv": "disputer."}, "G4805": {"greek": "σύζυγος", "translit": "sýzygos", "pronunciation": "sood'-zoo-gos", "derivation": "from (G4801);", "definition": "co-yoked, i.e. (figuratively) as noun, a colleague; probably rather as a proper name; Syzygus, a Christian", "kjv": "yokefellow."}, "G4806": {"greek": "συζωοποιέω", "translit": "syzōopoiéō", "pronunciation": "sood-zo-op-oy-eh'-o", "derivation": "from (G4862) and (G2227);", "definition": "to reanimate conjointly with (figuratively)", "kjv": "quicken together with."}, "G4807": {"greek": "συκάμινος", "translit": "sykáminos", "pronunciation": "soo-kam'-ee-nos", "derivation": "of Hebrew origin ((G8256)) in imitation of (G4809);", "definition": "a sycamore-fig tree", "kjv": "sycamine tree."}, "G4808": {"greek": "συκῆ", "translit": "sykē", "pronunciation": "soo-kay'", "derivation": "from (G4810);", "definition": "a fig-tree", "kjv": "fig tree."}, "G4809": {"greek": "συκομωραία", "translit": "sykomōraía", "pronunciation": "soo-kom-o-rah'-yah", "derivation": "from (G4810) and (the mulberry);", "definition": "the \"sycamore\"-fig tree", "kjv": "sycamore tree."}, "G4810": {"greek": "σῦκον", "translit": "sŷkon", "pronunciation": "soo'-kon", "derivation": "apparently a primary word;", "definition": "a fig", "kjv": "fig."}, "G4811": {"greek": "συκοφαντέω", "translit": "sykophantéō", "pronunciation": "soo-kof-an-teh'-o", "derivation": "from a compound of (G4810) and a derivative of (G5316);", "definition": "to be a fig-informer (reporter of the law forbidding the exportation of figs from Greece), \"sycophant\", i.e. (genitive and by extension) to defraud (exact unlawfully, extort)", "kjv": "accuse falsely, take by false accusation."}, "G4812": {"greek": "συλαγωγέω", "translit": "sylagōgéō", "pronunciation": "soo-lag-ogue-eh'-o", "derivation": "from the base of (G4813) and (the reduplicated form of) (G71);", "definition": "to lead away as booty, i.e. (figuratively) seduce", "kjv": "spoil."}, "G4813": {"greek": "συλάω", "translit": "syláō", "pronunciation": "soo-lah'-o", "derivation": "from a derivative of (to strip; probably akin to (G138); compare (G4661));", "definition": "to despoil", "kjv": "rob."}, "G4814": {"greek": "συλλαλέω", "translit": "syllaléō", "pronunciation": "sool-lal-eh'-o", "derivation": "from (G4862) and (G2980);", "definition": "to talk together, i.e. converse", "kjv": "commune (confer, talk) with, speak among."}, "G4815": {"greek": "συλλαμβάνω", "translit": "syllambánō", "pronunciation": "sool-lam-ban'-o", "derivation": "from (G4862) and (G2983);", "definition": "to clasp, i.e. seize (arrest, capture); specially, to conceive (literally or figuratively); by implication, to aid", "kjv": "catch, conceive, help, take."}, "G4816": {"greek": "συλλέγω", "translit": "syllégō", "pronunciation": "sool-leg'-o", "derivation": "from (G4862) and (G3004) in its original sense;", "definition": "to collect", "kjv": "gather (together, up)."}, "G4817": {"greek": "συλλογίζομαι", "translit": "syllogízomai", "pronunciation": "sool-log-id'-zom-ahee", "derivation": "from (G4862) and (G3049);", "definition": "to reckon together (with oneself), i.e. deliberate", "kjv": "reason with."}, "G4818": {"greek": "συλλυπέω", "translit": "syllypéō", "pronunciation": "sool-loop-eh'-o", "derivation": "from (G4862) and (G3076);", "definition": "to afflict jointly, i.e. (passive) sorrow at (on account of) someone", "kjv": "be grieved."}, "G4819": {"greek": "συμβαίνω", "translit": "symbaínō", "pronunciation": "soom-bah'-ee-no", "derivation": "from (G4862) and the base of (G939);", "definition": "to walk (figuratively, transpire) together, i.e. concur (take place)", "kjv": "be(-fall), happen (unto)."}, "G4820": {"greek": "συμβάλλω", "translit": "symbállō", "pronunciation": "soom-bal'-lo", "derivation": "from (G4862) and (G906);", "definition": "to combine, i.e. (in speaking) to converse, consult, dispute, (mentally) to consider, (by implication) to aid, (personally) to join, attack", "kjv": "confer, encounter, help, make, meet with, ponder."}, "G4821": {"greek": "συμβασιλεύω", "translit": "symbasileúō", "pronunciation": "soom-bas-il-yoo'-o", "derivation": "from (G4862) and (G936);", "definition": "to be co-regent (figuratively)", "kjv": "reign with."}, "G4822": {"greek": "συμβιβάζω", "translit": "symbibázō", "pronunciation": "soom-bib-ad'-zo", "derivation": "from (G4862) and (to force;", "definition": "causative (by reduplication) of the base of (G939)); to drive together, i.e. unite (in association or affection), (mentally) to infer, show, teach", "kjv": "compact, assuredly gather, intrust, knit together, prove."}, "G4823": {"greek": "συμβουλεύω", "translit": "symbouleúō", "pronunciation": "soom-bool-yoo'-o", "derivation": "from (G4862) and (G1011);", "definition": "to give (or take) advice jointly, i.e. recommend, deliberate or determine", "kjv": "consult, (give, take) counsel (together)."}, "G4824": {"greek": "συμβούλιον", "translit": "symboúlion", "pronunciation": "soom-boo'-lee-on", "derivation": "neuter of a presumed derivative of (G4825);", "definition": "advisement; specially, a deliberative body, i.e. the provincial assessors or lay-court", "kjv": "consultation, counsel, council."}, "G4825": {"greek": "σύμβουλος", "translit": "sýmboulos", "pronunciation": "soom'-boo-los", "derivation": "from (G4862) and (G1012);", "definition": "a consultor, i.e. adviser", "kjv": "counsellor."}, "G4826": {"greek": "Συμεών", "translit": "Symeṓn", "pronunciation": "soom-eh-one'", "derivation": "from the same as (G4613);", "definition": "Symeon (i.e. Shimon), the name of five Israelites", "kjv": "Simeon, Simon."}, "G4827": {"greek": "συμμαθητής", "translit": "symmathētḗs", "pronunciation": "soom-math-ay-tace'", "derivation": "from a compound of (G4862) and (G3129);", "definition": "a co-learner (of Christianity)", "kjv": "fellow disciple."}, "G4828": {"greek": "συμμαρτυρέω", "translit": "symmartyréō", "pronunciation": "soom-mar-too-reh'-o", "derivation": "from (G4862) and (G3140);", "definition": "to testify jointly, i.e. corroborate by (concurrent) evidence", "kjv": "testify unto, (also) bear witness (with)."}, "G4829": {"greek": "συμμερίζομαι", "translit": "symmerízomai", "pronunciation": "soom-mer-id'-zom-ahee", "derivation": "middle voice from (G4862) and (G3307);", "definition": "to share jointly, i.e. participate in", "kjv": "be partaker with."}, "G4830": {"greek": "συμμέτοχος", "translit": "symmétochos", "pronunciation": "soom-met'-okh-os", "derivation": "from (G4862) and (G3353);", "definition": "a co-participant", "kjv": "partaker."}, "G4831": {"greek": "συμμιμητής", "translit": "symmimētḗs", "pronunciation": "soom-mim-ay-tace'", "derivation": "from a presumed compound of (G4862) and (G3401);", "definition": "a co-imitator, i.e. fellow votary", "kjv": "follower together."}, "G4832": {"greek": "σύμμορφος", "translit": "sýmmorphos", "pronunciation": "soom-mor-fos'", "derivation": "from (G4862) and (G3444);", "definition": "jointly formed, i.e. (figuratively) similar", "kjv": "conformed to, fashioned like unto."}, "G4833": {"greek": "συμμορφόω", "translit": "symmorphóō", "pronunciation": "soom-mor-fo'-o", "derivation": "from (G4832);", "definition": "to render like, i.e. (figuratively) to assimilate", "kjv": "make conformable unto."}, "G4834": {"greek": "συμπαθέω", "translit": "sympathéō", "pronunciation": "soom-path-eh'-o", "derivation": "from (G4835);", "definition": "to feel \"sympathy\" with, i.e. (by implication) to commiserate", "kjv": "have compassion, be touched with a feeling of."}, "G4835": {"greek": "συμπαθής", "translit": "sympathḗs", "pronunciation": "soom-path-ace'", "derivation": "from (G4841);", "definition": "having a fellow-feeling (\"sympathetic\"), i.e. (by implication) mutually commiserative", "kjv": "having compassion one of another."}, "G4836": {"greek": "συμπαραγίνομαι", "translit": "symparagínomai", "pronunciation": "soom-par-ag-in'-om-ahee", "derivation": "from (G4862) and (G3854);", "definition": "to be present together, i.e. to convene; by implication, to appear in aid", "kjv": "come together, stand with."}, "G4837": {"greek": "συμπαρακαλέω", "translit": "symparakaléō", "pronunciation": "soom-par-ak-al-eh'-o", "derivation": "from (G4862) and (G3870);", "definition": "to console jointly", "kjv": "comfort together."}, "G4838": {"greek": "συμπαραλαμβάνω", "translit": "symparalambánō", "pronunciation": "soom-par-al-am-ban'-o", "derivation": "from (G4862) and (G3880);", "definition": "to take along in company", "kjv": "take with."}, "G4840": {"greek": "συμπάρειμι", "translit": "sympáreimi", "pronunciation": "soom-par'-i-mee", "derivation": "from (G4862) and (G3918);", "definition": "to be at hand together, i.e. now present", "kjv": "be here present with."}, "G4841": {"greek": "συμπάσχω", "translit": "sympáschō", "pronunciation": "soom-pas'-kho", "derivation": "from (G4862) and (G3958) (including its alternate);", "definition": "to experience pain jointly or of the same kind (specially, persecution; to \"sympathize\")", "kjv": "suffer with."}, "G4842": {"greek": "συμπέμπω", "translit": "sympémpō", "pronunciation": "soom-pem'-po", "derivation": "from (G4862) and (G3992);", "definition": "to despatch in company", "kjv": "send with."}, "G4843": {"greek": "συμπεριλαμβάνω", "translit": "symperilambánō", "pronunciation": "soom-per-ee-lam-ban'-o", "derivation": "from (G4862) and a compound of (G4012) and (G2983);", "definition": "to take by enclosing altogether, i.e. earnestly throw the arms about one", "kjv": "embrace."}, "G4844": {"greek": "συμπίνω", "translit": "sympínō", "pronunciation": "soom-pee'-no", "derivation": "from (G4862) and (G4095);", "definition": "to partake a beverage in company", "kjv": "drink with."}, "G4845": {"greek": "συμπληρόω", "translit": "symplēróō", "pronunciation": "soom-play-ro'-o", "derivation": "from (G4862) and (G4137);", "definition": "to implenish completely, i.e. (of space) to swamp (a boat), or (of time) to accomplish (passive, be complete)", "kjv": "(fully) come, fill up."}, "G4846": {"greek": "συμπνίγω", "translit": "sympnígō", "pronunciation": "soom-pnee'-go", "derivation": "from (G4862) and (G4155);", "definition": "to strangle completely, i.e. (literally) to drown, or (figuratively) to crowd", "kjv": "choke, throng."}, "G4847": {"greek": "συμπολίτης", "translit": "sympolítēs", "pronunciation": "soom-pol-ee'-tace", "derivation": "from (G4862) and (G4177);", "definition": "a native of the same town, i.e. (figuratively) co-religionist (fellow-Christian)", "kjv": "fellow- citizen."}, "G4848": {"greek": "συμπορεύομαι", "translit": "symporeúomai", "pronunciation": "soom-por-yoo'-om-ahee", "derivation": "from (G4862) and (G4198);", "definition": "to journey together; by implication, to assemble", "kjv": "go with, resort."}, "G4849": {"greek": "συμπόσιον", "translit": "sympósion", "pronunciation": "soom-pos'-ee-on", "derivation": "neuter of a derivative of the alternate of (G4844);", "definition": "a drinking-party (\"symposium\"), i.e. (by extension) a room of guests", "kjv": "company."}, "G4850": {"greek": "συμπρεσβύτερος", "translit": "sympresbýteros", "pronunciation": "soom-pres-boo'-ter-os", "derivation": "from (G4862) and (G4245);", "definition": "a co-presbyter", "kjv": "presbyter, also an elder."}, "G4851": {"greek": "συμφέρω", "translit": "symphérō", "pronunciation": "soom-fer'-o", "derivation": "from (G4862) and (G5342) (including its alternate);", "definition": "to bear together (contribute), i.e. (literally) to collect, or (figuratively) to conduce; especially (neuter participle as a noun) advantage", "kjv": "be better for, bring together, be expedient (for), be good, (be) profit(-able for)."}, "G4852": {"greek": "σύμφημι", "translit": "sýmphēmi", "pronunciation": "soom'-fay-mee", "derivation": "from (G4862) and (G5346);", "definition": "to say jointly, i.e. assent to", "kjv": "consent unto."}, "G4853": {"greek": "συμφυλέτης", "translit": "symphylétēs", "pronunciation": "soom-foo-let'-ace", "derivation": "from (G4862) and a derivative of (G5443);", "definition": "a co-tribesman, i.e. native of the same country", "kjv": "countryman."}, "G4854": {"greek": "σύμφυτος", "translit": "sýmphytos", "pronunciation": "soom'-foo-tos", "derivation": "from (G4862) and a derivative of (G5453);", "definition": "grown along with (connate), i.e. (figuratively) closely united to", "kjv": "planted together."}, "G4855": {"greek": "συμφύω", "translit": "symphýō", "pronunciation": "soom-foo'-o", "derivation": "from (G4862) and (G5453);", "definition": "passive, to grow jointly", "kjv": "spring up with."}, "G4856": {"greek": "συμφωνέω", "translit": "symphōnéō", "pronunciation": "soom-fo-neh'-o", "derivation": "from (G4859);", "definition": "to be harmonious, i.e. (figuratively) to accord (be suitable, concur) or stipulate (by compact)", "kjv": "agree (together, with)."}, "G4857": {"greek": "συμφώνησις", "translit": "symphṓnēsis", "pronunciation": "soom-fo'-nay-sis", "derivation": "from (G4856);", "definition": "accordance", "kjv": "concord."}, "G4858": {"greek": "συμφωνία", "translit": "symphōnía", "pronunciation": "soom-fo-nee'-ah", "derivation": "from (G4859);", "definition": "unison of sound (\"symphony\"), i.e. a concert of instruments (harmonious note)", "kjv": "music."}, "G4859": {"greek": "σύμφωνος", "translit": "sýmphōnos", "pronunciation": "soom'-fo-nos", "derivation": "from (G4862) and (G5456);", "definition": "sounding together (alike), i.e. (figuratively) accordant (neuter as noun, agreement)", "kjv": "consent."}, "G4860": {"greek": "συμψηφίζω", "translit": "sympsēphízō", "pronunciation": "soom-psay-fid'-zo", "derivation": "from (G4862) and (G5585);", "definition": "to compute jointly", "kjv": "reckon."}, "G4861": {"greek": "σύμψυχος", "translit": "sýmpsychos", "pronunciation": "soom'-psoo-khos", "derivation": "from (G4862) and (G5590);", "definition": "co-spirited, i.e. similar in sentiment", "kjv": "like-minded."}, "G4862": {"greek": "σύν", "translit": "sýn", "pronunciation": "soon", "derivation": "a primary preposition denoting union;", "definition": "with or together (but much closer than (G3326) or (G3844)), i.e. by association, companionship, process, resemblance, possession, instrumentality, addition, etc.", "kjv": "beside, with."}, "G4863": {"greek": "συνάγω", "translit": "synágō", "pronunciation": "soon-ag'-o", "derivation": "from (G4862) and (G71);", "definition": "to lead together, i.e. collect or convene; specially, to entertain (hospitably)", "kjv": "+ accompany, assemble (selves, together), bestow, come together, gather (selves together, up, together), lead into, resort, take in."}, "G4864": {"greek": "συναγωγή", "translit": "synagōgḗ", "pronunciation": "soon-ag-o-gay'", "derivation": "from (the reduplicated form of) (G4863);", "definition": "an assemblage of persons; specially, a Jewish \"synagogue\" (the meeting or the place); by analogy, a Christian church", "kjv": "assembly, congregation, synagogue."}, "G4865": {"greek": "συναγωνίζομαι", "translit": "synagōnízomai", "pronunciation": "soon-ag-o-nid'-zom-ahee", "derivation": "from (G4862) and (G75);", "definition": "to struggle in company with, i.e. (figuratively) to be a partner (assistant)", "kjv": "strive together with."}, "G4866": {"greek": "συναθλέω", "translit": "synathléō", "pronunciation": "soon-ath-leh'-o", "derivation": "from (G4862) and (G118);", "definition": "to wrestle in company with, i.e. (figuratively) to seek jointly", "kjv": "labour with, strive together for."}, "G4867": {"greek": "συναθροίζω", "translit": "synathroízō", "pronunciation": "soon-ath-royd'-zo", "derivation": "from (G4862) and (to hoard);", "definition": "to convene", "kjv": "call (gather) together."}, "G4868": {"greek": "συναίρω", "translit": "synaírō", "pronunciation": "soon-ah'-ee-ro", "derivation": "from (G4862) and (G142);", "definition": "to make up together, i.e. (figuratively) to compute (an account)", "kjv": "reckon, take."}, "G4869": {"greek": "συναιχμάλωτος", "translit": "synaichmálōtos", "pronunciation": "soon-aheekh-mal'-o-tos", "derivation": "from (G4862) and (G164);", "definition": "a co-captive", "kjv": "fellowprisoner."}, "G4870": {"greek": "συνακολουθέω", "translit": "synakolouthéō", "pronunciation": "soon-ak-ol-oo-theh'-o", "derivation": "from (G4862) and (G190);", "definition": "to accompany", "kjv": "follow."}, "G4871": {"greek": "συναλίζω", "translit": "synalízō", "pronunciation": "soon-al-id'-zo", "derivation": "from (G4862) and (to throng);", "definition": "to accumulate, i.e. convene", "kjv": "assemble together."}, "G4872": {"greek": "συναναβαίνω", "translit": "synanabaínō", "pronunciation": "soon-an-ab-ah'-ee-no", "derivation": "from (G4862) and (G305);", "definition": "to ascend in company with", "kjv": "come up with."}, "G4873": {"greek": "συνανάκειμαι", "translit": "synanákeimai", "pronunciation": "soon-an-ak'-i-mahee", "derivation": "from (G4862) and (G345);", "definition": "to recline in company with (at a meal)", "kjv": "sit (down, at the table, together) with (at meat)."}, "G4874": {"greek": "συναναμίγνυμι", "translit": "synanamígnymi", "pronunciation": "soon-an-am-ig'-noo-mee", "derivation": "from (G4862) and a compound of (G303) and (G3396);", "definition": "to mix up together, i.e. (figurative) associate with", "kjv": "(have, keep) company (with)."}, "G4875": {"greek": "συναναπαύομαι", "translit": "synanapaúomai", "pronunciation": "soon-an-ap-ow'-om-ahee", "derivation": "middle from (G4862) and (G373);", "definition": "to recruit oneself in company with", "kjv": "refresh with."}, "G4876": {"greek": "συναντάω", "translit": "synantáō", "pronunciation": "soon-an-tah'-o", "derivation": "from (G4862) and a derivative of (G473);", "definition": "to meet with; figuratively, to occur", "kjv": "befall, meet."}, "G4878": {"greek": "συναντιλαμβάνομαι", "translit": "synantilambánomai", "pronunciation": "soon-an-tee-lam-ban'-om-ahee", "derivation": "from (G4862) and (G482);", "definition": "to take hold of opposite together, i.e. co-operate (assist)", "kjv": "help."}, "G4879": {"greek": "συναπάγω", "translit": "synapágō", "pronunciation": "soon-ap-ag'-o", "derivation": "from (G4862) and (G520);", "definition": "to take off together, i.e. transport with (seduce, passively, yield)", "kjv": "carry (lead) away with, condescend."}, "G4880": {"greek": "συναποθνήσκω", "translit": "synapothnḗskō", "pronunciation": "soon-ap-oth-nace'-ko", "derivation": "from (G4862) and (G599);", "definition": "to decease (literally) in company with, or (figuratively), similarly to", "kjv": "be dead (die) with."}, "G4881": {"greek": "συναπόλλυμι", "translit": "synapóllymi", "pronunciation": "soon-ap-ol'-loo-mee", "derivation": "from (G4862) and (G622);", "definition": "to destroy (middle voice or passively, be slain) in company with", "kjv": "perish with."}, "G4882": {"greek": "συναποστέλλω", "translit": "synapostéllō", "pronunciation": "soon-ap-os-tel'-lo", "derivation": "from (G4862) and (G649);", "definition": "to despatch (on an errand) in company with", "kjv": "send with."}, "G4883": {"greek": "συναρμολογέω", "translit": "synarmologéō", "pronunciation": "soon-ar-mol-og-eh'-o", "derivation": "from (G4862) and a derivative of a compound of (G719) and (G3004) (in its original sense of laying);", "definition": "to render close-jointed together, i.e. organize compactly", "kjv": "be fitly framed (joined) together."}, "G4884": {"greek": "συναρπάζω", "translit": "synarpázō", "pronunciation": "soon-ar-pad'-zo", "derivation": "from (G4862) and (G726);", "definition": "to snatch together, i.e. seize", "kjv": "catch."}, "G4885": {"greek": "συναυξάνω", "translit": "synauxánō", "pronunciation": "soon-owx-an'-o", "derivation": "from (G4862) and (G837);", "definition": "to increase (grow up) together", "kjv": "grow together."}, "G4886": {"greek": "σύνδεσμος", "translit": "sýndesmos", "pronunciation": "soon'-des-mos", "derivation": "from (G4862) and (G1199);", "definition": "a joint tie, i.e. ligament, (figuratively) uniting principle, control", "kjv": "band, bond."}, "G4887": {"greek": "συνδέω", "translit": "syndéō", "pronunciation": "soon-deh'-o", "derivation": "from (G4862) and (G1210);", "definition": "to bind with, i.e. (passively) be a fellow-prisoner (figuratively)", "kjv": "be bound with."}, "G4888": {"greek": "συνδοξάζω", "translit": "syndoxázō", "pronunciation": "soon-dox-ad'-zo", "derivation": "from (G4862) and (G1392);", "definition": "to exalt to dignity in company (i.e. similarly) with", "kjv": "glorify together."}, "G4889": {"greek": "σύνδουλος", "translit": "sýndoulos", "pronunciation": "soon'-doo-los", "derivation": "from (G4862) and (G1401);", "definition": "a co-slave, i.e. servitor or ministrant of the same master (human or divine)", "kjv": "fellowservant."}, "G4890": {"greek": "συνδρομή", "translit": "syndromḗ", "pronunciation": "soon-drom-ay'", "derivation": "from (the alternate of) (G4936);", "definition": "a running together, i.e. (riotous) concourse", "kjv": "run together."}, "G4891": {"greek": "συνεγείρω", "translit": "synegeírō", "pronunciation": "soon-eg-i'-ro", "derivation": "from (G4862) and (G1453);", "definition": "to rouse (from death) in company with, i.e. (figuratively) to revivify (spirtually) in resemblance to", "kjv": "raise up together, rise with."}, "G4892": {"greek": "συνέδριον", "translit": "synédrion", "pronunciation": "soon-ed'-ree-on", "derivation": "neuter of a presumed derivative of a compound of (G4862) and the base of (G1476);", "definition": "a joint session, i.e. (specially), the Jewish Sanhedrin; by analogy, a subordinate tribunal", "kjv": "council."}, "G4893": {"greek": "συνείδησις", "translit": "syneídēsis", "pronunciation": "soon-i'-day-sis", "derivation": "from a prolonged form of (G4894);", "definition": "co-perception, i.e. moral consciousness", "kjv": "conscience."}, "G4894": {"greek": "συνείδω", "translit": "syneídō", "pronunciation": "soon-i'-do", "derivation": "from (G4862) and (G1492);", "definition": "to see completely; used (like its primary) only in two past tenses, respectively meaning to understand or become aware, and to be conscious or (clandestinely) informed of", "kjv": "consider, know, be privy, be ware of."}, "G4895": {"greek": "σύνειμι", "translit": "sýneimi", "pronunciation": "soon'-i-mee", "derivation": "from (G4862) and (G1510) (including its various inflections);", "definition": "to be in company with, i.e. present at the time", "kjv": "be with."}, "G4897": {"greek": "συνεισέρχομαι", "translit": "syneisérchomai", "pronunciation": "soon-ice-er'-khom-ahee", "derivation": "from (G4862) and (G1525);", "definition": "to enter in company with", "kjv": "go in with, go with into."}, "G4898": {"greek": "συνέκδημος", "translit": "synékdēmos", "pronunciation": "soon-ek'-day-mos", "derivation": "from (G4862) and the base of (G1553);", "definition": "a co-absentee from home, i.e. fellow-traveller", "kjv": "companion in travel, travel with."}, "G4899": {"greek": "συνεκλεκτός", "translit": "syneklektós", "pronunciation": "soon-ek-lek-tos'", "derivation": "from a compound of (G4862) and (G1586);", "definition": "chosen in company with, i.e. co-elect (fellow Christian)", "kjv": "elected together with."}, "G4900": {"greek": "συνελαύνω", "translit": "synelaúnō", "pronunciation": "soon-el-ow'-no", "derivation": "from (G4862) and (G1643);", "definition": "to drive together, i.e. (figuratively) exhort (to reconciliation)", "kjv": "+ set at one again."}, "G4901": {"greek": "συνεπιμαρτυρέω", "translit": "synepimartyréō", "pronunciation": "soon-ep-ee-mar-too-reh'-o", "derivation": "from (G4862) and (G1957);", "definition": "to testify further jointly, i.e. unite in adding evidence", "kjv": "also bear witness."}, "G4902": {"greek": "συνέπομαι", "translit": "synépomai", "pronunciation": "soon-ep'-om-ahee", "derivation": "middle voice from (G4862) and a primary (to follow);", "definition": "to attend (travel) in company with", "kjv": "accompany."}, "G4903": {"greek": "συνεργέω", "translit": "synergéō", "pronunciation": "soon-erg-eh'-o", "derivation": "from (G4904);", "definition": "to be a fellow-worker, i.e. co-operate", "kjv": "help (work) with, work(-er) together."}, "G4904": {"greek": "συνεργός", "translit": "synergós", "pronunciation": "soon-er-gos'", "derivation": "from a presumed compound of (G4862) and the base of (G2041);", "definition": "a co-laborer, i.e. coadjutor", "kjv": "companion in labour, (fellow-)helper(-labourer, -worker), labourer together with, workfellow."}, "G4905": {"greek": "συνέρχομαι", "translit": "synérchomai", "pronunciation": "soon-er'-khom-ahee", "derivation": "from (G4862) and (G2064);", "definition": "to convene, depart in company with, associate with, or (specially), cohabit (conjugally)", "kjv": "accompany, assemble (with), come (together), come (company, go) with, resort."}, "G4906": {"greek": "συνεσθίω", "translit": "synesthíō", "pronunciation": "soon-es-thee'-o", "derivation": "from (G4862) and (G2068) (including its alternate);", "definition": "to take food in company with", "kjv": "eat with."}, "G4907": {"greek": "σύνεσις", "translit": "sýnesis", "pronunciation": "soon'-es-is", "derivation": "from (G4920);", "definition": "a mental putting together, i.e. intelligence or (concretely) the intellect", "kjv": "knowledge, understanding."}, "G4908": {"greek": "συνετός", "translit": "synetós", "pronunciation": "soon-et'-os", "derivation": "from (G4920);", "definition": "mentally put (or putting) together, i.e. sagacious", "kjv": "prudent."}, "G4909": {"greek": "συνευδοκέω", "translit": "syneudokéō", "pronunciation": "soon-yoo-dok-eh'-o", "derivation": "from (G4862) and (G2106);", "definition": "to think well of in common, i.e. assent to, feel gratified with", "kjv": "allow, assent, be pleased, have pleasure."}, "G4910": {"greek": "συνευωχέω", "translit": "syneuōchéō", "pronunciation": "soon-yoo-o-kheh'-o", "derivation": "from (G4862) and a derivative of a presumed compound of (G2095) and a derivative of (G2192) (meaning to be in good condition, i.e. (by implication) to fare well, or feast);", "definition": "to entertain sumptuously in company with, i.e. (middle voice or passive) to revel together", "kjv": "feast with."}, "G4911": {"greek": "συνεφίστημι", "translit": "synephístēmi", "pronunciation": "soon-ef-is'-tay-mee", "derivation": "from (G4862) and (G2186);", "definition": "to stand up together, i.e. to resist (or assault) jointly", "kjv": "rise up together."}, "G4912": {"greek": "συνέχω", "translit": "synéchō", "pronunciation": "soon-ekh'-o", "derivation": "from (G4862) and (G2192);", "definition": "to hold together, i.e. to compress (the ears, with a crowd or siege) or arrest (a prisoner); figuratively, to compel, perplex, afflict, preoccupy", "kjv": "constrain, hold, keep in, press, lie sick of, stop, be in a strait, straiten, be taken with, throng."}, "G4913": {"greek": "συνήδομαι", "translit": "synḗdomai", "pronunciation": "soon-ay'-dom-ahee", "derivation": "middle voice from (G4862) and the base of (G2237);", "definition": "to rejoice in with oneself, i.e. feel satisfaction concerning", "kjv": "delight."}, "G4914": {"greek": "συνήθεια", "translit": "synḗtheia", "pronunciation": "soon-ay'-thi-ah", "derivation": "from a compound of (G4862) and (G2239);", "definition": "mutual habituation, i.e. usage", "kjv": "custom."}, "G4915": {"greek": "συνηλικιώτης", "translit": "synēlikiṓtēs", "pronunciation": "soon-ay-lik-ee-o'-tace", "derivation": "from (G4862) and a derivative of (G2244);", "definition": "a co-aged person, i.e. alike in years", "kjv": "equal."}, "G4916": {"greek": "συνθάπτω", "translit": "syntháptō", "pronunciation": "soon-thap'-to", "derivation": "from (G4862) and (G2290);", "definition": "to inter in company with, i.e. (figuratively) to assimilate spiritually (to Christ by a sepulture as to sin)", "kjv": "bury with."}, "G4917": {"greek": "συνθλάω", "translit": "synthláō", "pronunciation": "soon-thlah'-o", "derivation": "from (G4862) and thlao (to crush);", "definition": "to dash together, i.e. shatter", "kjv": "break."}, "G4918": {"greek": "συνθλίβω", "translit": "synthlíbō", "pronunciation": "soon-thlee'-bo", "derivation": "from (G4862) and (G2346);", "definition": "to compress, i.e. crowd on all sides", "kjv": "throng."}, "G4919": {"greek": "συνθρύπτω", "translit": "synthrýptō", "pronunciation": "soon-throop'-to", "derivation": "from (G4862) and (to crumble);", "definition": "to crush together, i.e. (figuratively) to dispirit", "kjv": "break."}, "G4920": {"greek": "συνίημι", "translit": "syníēmi", "pronunciation": "soon-ee'-ay-mee", "derivation": "from (G4862) and (to send);", "definition": "to put together, i.e. (mentally) to comprehend; by implication, to act piously", "kjv": "consider, understand, be wise."}, "G4921": {"greek": "συνιστάω", "translit": "synistáō", "pronunciation": "soon-is-tah'-o", "derivation": "from (G4862) and (G2476) (including its collateral forms);", "definition": "to set together, i.e. (by implication) to introduce (favorably), or (figuratively) to exhibit; intransitively, to stand near, or (figuratively) to constitute", "kjv": "approve, commend, consist, make, stand (with)."}, "G4922": {"greek": "συνοδεύω", "translit": "synodeúō", "pronunciation": "soon-od-yoo'-o", "derivation": "from (G4862) and (G3593);", "definition": "to travel in company with", "kjv": "journey with."}, "G4923": {"greek": "συνοδία", "translit": "synodía", "pronunciation": "soon-od-ee'-ah", "derivation": "from a compound of (G4862) and (G3598) (\"synod\");", "definition": "companionship on a journey, i.e. (by implication), a caravan", "kjv": "company."}, "G4924": {"greek": "συνοικέω", "translit": "synoikéō", "pronunciation": "soon-oy-keh'-o", "derivation": "from (G4862) and (G3611);", "definition": "to reside together (as a family)", "kjv": "dwell together."}, "G4925": {"greek": "συνοικοδομέω", "translit": "synoikodoméō", "pronunciation": "soon-oy-kod-om-eh'-o", "derivation": "from (G4862) and (G3618);", "definition": "to construct, i.e. (passively) to compose (in company with other Christians, figuratively)", "kjv": "build together."}, "G4926": {"greek": "συνομιλέω", "translit": "synomiléō", "pronunciation": "soon-om-il-eh'-o", "derivation": "from (G4862) and (G3656);", "definition": "to converse mutually", "kjv": "talk with."}, "G4927": {"greek": "συνομορέω", "translit": "synomoréō", "pronunciation": "soon-om-or-eh'-o", "derivation": "from (G4862) and a derivative of a compound of the base of 3674 and the base of (G3725);", "definition": "to border together, i.e. adjoin", "kjv": "join hard."}, "G4928": {"greek": "συνοχή", "translit": "synochḗ", "pronunciation": "soon-okh-ay'", "derivation": "from (G4912);", "definition": "restraint, i.e. (figuratively) anxiety", "kjv": "anguish, distress."}, "G4929": {"greek": "συντάσσω", "translit": "syntássō", "pronunciation": "soon-tas-so", "derivation": "from (G4862) and (G5021);", "definition": "to arrange jointly, i.e. (figuratively) to direct", "kjv": "appoint."}, "G4930": {"greek": "συντέλεια", "translit": "syntéleia", "pronunciation": "soon-tel'-i-ah", "derivation": "from (G4931);", "definition": "entire completion, i.e. consummation (of a dispensation)", "kjv": "end."}, "G4931": {"greek": "συντελέω", "translit": "synteléō", "pronunciation": "soon-tel-eh'-o", "derivation": "from (G4862) and (G5055);", "definition": "to complete entirely; generally, to execute (literally or figuratively)", "kjv": "end, finish, fulfil, make."}, "G4932": {"greek": "συντέμνω", "translit": "syntémnō", "pronunciation": "soon-tem'-no", "derivation": "from (G4862) and the base of (G5114);", "definition": "to contract by cutting, i.e. (figuratively) do concisely (speedily)", "kjv": "(cut) short."}, "G4933": {"greek": "συντηρέω", "translit": "syntēréō", "pronunciation": "soon-tay-reh'-o", "derivation": "from (G4862) and (G5083);", "definition": "to keep closely together, i.e. (by implication) to conserve (from ruin); mentally, to remember (and obey)", "kjv": "keep, observe, preserve."}, "G4934": {"greek": "συντίθεμαι", "translit": "syntíthemai", "pronunciation": "soon-tith'-em-ahee", "derivation": "middle voice from (G4862) and (G5087);", "definition": "to place jointly, i.e. (figuratively) to consent (bargain, stipulate), concur", "kjv": "agree, assent, covenant."}, "G4935": {"greek": "συντόμως", "translit": "syntómōs", "pronunciation": "soon-tom'-oce", "derivation": "adverb from a derivative of (G4932);", "definition": "concisely (briefly)", "kjv": "a few words."}, "G4936": {"greek": "συντρέχω", "translit": "syntréchō", "pronunciation": "soon-trekh'-o", "derivation": "from (G4862) and (G5143) (including its alternate);", "definition": "to rush together (hastily assemble) or headlong (figuratively)", "kjv": "run (together, with)."}, "G4937": {"greek": "συντρίβω", "translit": "syntríbō", "pronunciation": "soon-tree'-bo", "derivation": "from (G4862) and the base of (G5147);", "definition": "to crush completely, i.e. to shatter (literally or figuratively)", "kjv": "break (in pieces), broken to shivers (+ -hearted), bruise."}, "G4938": {"greek": "σύντριμμα", "translit": "sýntrimma", "pronunciation": "soon-trim'-mah", "derivation": "from (G4937);", "definition": "concussion or utter fracture (properly, concretely), i.e. complete ruin", "kjv": "destruction."}, "G4939": {"greek": "σύντροφος", "translit": "sýntrophos", "pronunciation": "soon'-trof-os", "derivation": "from (G4862) and (G5162) (in a passive sense);", "definition": "a fellow-nursling, i.e. comrade", "kjv": "brought up with."}, "G4940": {"greek": "συντυγχάνω", "translit": "syntynchánō", "pronunciation": "soon-toong-khan'-o", "derivation": "from (G4862) and (G5177);", "definition": "to chance together, i.e. meet with (reach)", "kjv": "come at."}, "G4941": {"greek": "Συντύχη", "translit": "Syntýchē", "pronunciation": "soon-too'-khay", "derivation": "from (G4940);", "definition": "an accident; Syntyche, a Christian female", "kjv": "Syntyche."}, "G4942": {"greek": "συνυποκρίνομαι", "translit": "synypokrínomai", "pronunciation": "soon-oo-pok-rin'-om-ahee", "derivation": "from (G4862) and (G5271);", "definition": "to act hypocritically in concert with", "kjv": "dissemble with."}, "G4943": {"greek": "συνυπουργέω", "translit": "synypourgéō", "pronunciation": "soon-oop-oorg-eh'-o", "derivation": "from (G4862) and a derivative of a compound of (G5259) and the base of (G2041);", "definition": "to be a co-auxiliary, i.e. assist", "kjv": "help together."}, "G4944": {"greek": "συνωδίνω", "translit": "synōdínō", "pronunciation": "soon-o-dee'-no", "derivation": "from (G4862) and (G5605);", "definition": "to have (parturition) pangs in company (concert, simultaneously) with, i.e. (figuratively) to sympathize (in expectation of relief from suffering)", "kjv": "travail in pain together."}, "G4945": {"greek": "συνωμοσία", "translit": "synōmosía", "pronunciation": "soon-o-mos-ee'-ah", "derivation": "from a compound of (G4862) and (G3660);", "definition": "a swearing together, i.e. (by implication) a plot", "kjv": "comspiracy."}, "G4946": {"greek": "Συράκουσαι", "translit": "Syrákousai", "pronunciation": "soo-rak'-oo-sahee", "derivation": "plural of uncertain derivation;", "definition": "Syracuse, the capital of Sicily", "kjv": "Syracuse."}, "G4947": {"greek": "Συρία", "translit": "Syría", "pronunciation": "soo-ree'-ah", "derivation": "probably of Hebrew origin ((G6865));", "definition": "Syria (i.e. Tsyria or Tyre), a region of Asia", "kjv": "Syria."}, "G4948": {"greek": "Σύρος", "translit": "Sýros", "pronunciation": "soo'-ros", "derivation": "from the same as (G4947);", "definition": "a Syran (i.e. probably Tyrian), a native of Syria", "kjv": "Syrian."}, "G4949": {"greek": "Συροφοίνισσα", "translit": "Syrophoínissa", "pronunciation": "soo-rof-oy'-nis-sah", "derivation": "feminine of a compound of (G4948) and the same as (G5403);", "definition": "a Syro-phœnician woman, i.e. a female native of Phœnicia in Syria", "kjv": "Syrophenician."}, "G4950": {"greek": "σύρτις", "translit": "sýrtis", "pronunciation": "soor'-tis", "derivation": "from (G4951);", "definition": "a shoal (from the sand drawn thither by the waves), i.e. the Syrtis Major or great bay on the north coast of Africa", "kjv": "quicksands."}, "G4951": {"greek": "σύρω", "translit": "sýrō", "pronunciation": "soo'-ro", "derivation": "probably akin to (G138);", "definition": "to trail", "kjv": "drag, draw, hale."}, "G4952": {"greek": "συσπαράσσω", "translit": "sysparássō", "pronunciation": "soos-par-as'-so", "derivation": "from (G4862) and (G4682);", "definition": "to rend completely, i.e. (by analogy) to convulse violently", "kjv": "throw down."}, "G4953": {"greek": "σύσσημον", "translit": "sýssēmon", "pronunciation": "soos'-say-mon", "derivation": "neuter of a compound of (G4862) and the base of (G4591);", "definition": "a sign in common, i.e. preconcerted signal", "kjv": "token."}, "G4954": {"greek": "σύσσωμος", "translit": "sýssōmos", "pronunciation": "soos'-so-mos", "derivation": "from (G4862) and (G4983);", "definition": "of a joint body, i.e. (figuratively) a fellow-member of the Christian community", "kjv": "of the same body."}, "G4955": {"greek": "συστασιαστής", "translit": "systasiastḗs", "pronunciation": "soos-tas-ee-as-tace'", "derivation": "from a compound of (G4862) and a derivative of (G4714);", "definition": "a fellow-insurgent", "kjv": "make insurrection with."}, "G4956": {"greek": "συστατικός", "translit": "systatikós", "pronunciation": "soos-tat-ee-kos'", "derivation": "from a derivative of (G4921);", "definition": "introductory, i.e. recommendatory", "kjv": "of commendation."}, "G4957": {"greek": "συσταυρόω", "translit": "systauróō", "pronunciation": "soos-tow-ro'-o", "derivation": "from (G4862) and (G4717);", "definition": "to impale in company with (literally or figuratively)", "kjv": "crucify with."}, "G4958": {"greek": "συστέλλω", "translit": "systéllō", "pronunciation": "soos-tel'-lo", "derivation": "from (G4862) and (G4724);", "definition": "to send (draw) together, i.e. enwrap (enshroud a corpse for burial), contract (an interval)", "kjv": "short, wind up."}, "G4959": {"greek": "συστενάζω", "translit": "systenázō", "pronunciation": "soos-ten-ad'-zo", "derivation": "from (G4862) and (G4727);", "definition": "to moan jointly, i.e. (figuratively) experience a common calamity", "kjv": "groan together."}, "G4960": {"greek": "συστοιχέω", "translit": "systoichéō", "pronunciation": "soos-toy-kheh'-o", "derivation": "from (G4862) and (G4748);", "definition": "to file together (as soldiers in ranks), i.e. (figuratively) to correspond to", "kjv": "answer to."}, "G4961": {"greek": "συστρατιώτης", "translit": "systratiṓtēs", "pronunciation": "soos-trat-ee-o'-tace", "derivation": "from (G4862) and (G4757);", "definition": "a co-campaigner, i.e. (figuratively) an associate in Christian toil", "kjv": "fellowsoldier."}, "G4962": {"greek": "συστρέφω", "translit": "systréphō", "pronunciation": "soos-tref'-o", "derivation": "from (G4862) and (G4762);", "definition": "to twist together, i.e. collect (a bundle, a crowd)", "kjv": "gather."}, "G4963": {"greek": "συστροφή", "translit": "systrophḗ", "pronunciation": "soos-trof-ay'", "derivation": "from (G4962);", "definition": "a twisting together, i.e. (figuratively) a secret coalition, riotous crowd", "kjv": "+ band together, concourse."}, "G4964": {"greek": "συσχηματίζω", "translit": "syschēmatízō", "pronunciation": "soos-khay-mat-id'-zo", "derivation": "from (G4862) and a derivative of (G4976);", "definition": "to fashion alike, i.e. conform to the same pattern (figuratively)", "kjv": "conform to, fashion self according to."}, "G4965": {"greek": "Συχάρ", "translit": "Sychár", "pronunciation": "soo-khar'", "derivation": "of Hebrew origin ((G7941));", "definition": "Sychar (i.e. Shekar), a place in Palestine", "kjv": "Sychar."}, "G4966": {"greek": "Συχέμ", "translit": "Sychém", "pronunciation": "soo-khem'", "derivation": "of Hebrew origin ((G7927));", "definition": "Sychem (i.e. Shekem), the name of a Canaanite and of a place in Palestine", "kjv": "Sychem."}, "G4967": {"greek": "σφαγή", "translit": "sphagḗ", "pronunciation": "sfag-ay'", "derivation": "from (G4969);", "definition": "butchery (of animals for food or sacrifice, or (figuratively) of men (destruction))", "kjv": "slaughter."}, "G4968": {"greek": "σφάγιον", "translit": "sphágion", "pronunciation": "sfag'-ee-on", "derivation": "neuter of a derivative of (G4967);", "definition": "a victim (in sacrifice)", "kjv": "slain beast."}, "G4969": {"greek": "σφάζω", "translit": "spházō", "pronunciation": "sfad'-zo", "derivation": "a primary verb;", "definition": "to butcher (especially an animal for food or in sacrifice) or (generally) to slaughter, or (specially), to maim (violently)", "kjv": "kill, slay, wound."}, "G4970": {"greek": "σφόδρα", "translit": "sphódra", "pronunciation": "sfod'-rah", "derivation": "neuter plural of (violent;", "definition": "of uncertain derivation) as adverb; vehemently, i.e. in a high degree, much", "kjv": "exceeding(-ly), greatly, sore, very."}, "G4971": {"greek": "σφοδρῶς", "translit": "sphodrōs", "pronunciation": "sfod-roce'", "derivation": "adverb from the same as (G4970);", "definition": "very much", "kjv": "exceedingly."}, "G4972": {"greek": "σφραγίζω", "translit": "sphragízō", "pronunciation": "sfrag-id'-zo", "derivation": "from (G4973);", "definition": "to stamp (with a signet or private mark) for security or preservation (literally or figuratively); by implication, to keep secret, to attest", "kjv": "(set a, set to) seal up, stop."}, "G4973": {"greek": "σφραγίς", "translit": "sphragís", "pronunciation": "sfrag-ece'", "derivation": "probably strengthened from (G5420);", "definition": "a signet (as fencing in or protecting from misappropriation); by implication, the stamp impressed (as a mark of privacy, or genuineness), literally or figuratively", "kjv": "seal."}, "G4974": {"greek": "σφυρόν", "translit": "sphyrón", "pronunciation": "sfoo-ron'", "derivation": "neuter of a presumed derivative probably of the same as (a ball, \"sphere\"; compare the feminine , a hammer);", "definition": "the ankle (as globular)", "kjv": "ancle bone."}, "G4975": {"greek": "σχεδόν", "translit": "schedón", "pronunciation": "skhed-on'", "derivation": "neuter of a presumed derivative of the alternate of (G2192) as adverb;", "definition": "nigh, i.e. nearly", "kjv": "almost."}, "G4976": {"greek": "σχῆμα", "translit": "schēma", "pronunciation": "skhay'-mah", "derivation": "from the alternate of (G2192);", "definition": "a figure (as a mode or circumstance), i.e. (by implication) external condition", "kjv": "fashion."}, "G4977": {"greek": "σχίζω", "translit": "schízō", "pronunciation": "skhid'-zo", "derivation": "apparently a primary verb;", "definition": "to split or sever (literally or figuratively)", "kjv": "break, divide, open, rend, make a rent."}, "G4978": {"greek": "σχίσμα", "translit": "schísma", "pronunciation": "skhis'-mah", "derivation": "from (G4977);", "definition": "a split or gap (\"schism\"), literally or figuratively", "kjv": "division, rent, schism."}, "G4979": {"greek": "σχοινίον", "translit": "schoiníon", "pronunciation": "skhoy-nee'-on", "derivation": "diminutive of (a rush or flag-plant;", "definition": "of uncertain derivation); a rushlet, i.e. grass-withe or tie (generally)", "kjv": "small cord, rope."}, "G4980": {"greek": "σχολάζω", "translit": "scholázō", "pronunciation": "skhol-ad'-zo", "derivation": "from (G4981);", "definition": "to take a holiday, i.e. be at leisure for (by implication, devote oneself wholly to); figuratively, to be vacant (of a house)", "kjv": "empty, give self."}, "G4981": {"greek": "σχολή", "translit": "scholḗ", "pronunciation": "skhol-ay'", "derivation": "probably feminine of a presumed derivative of the alternate of (G2192);", "definition": "properly, loitering (as a withholding of oneself from work) or leisure, i.e. (by implication) a \"school\" (as vacation from physical employment)", "kjv": "school."}, "G4982": {"greek": "σώζω", "translit": "sṓzō", "pronunciation": "sode'-zo", "derivation": "from a primary (contraction for obsolete , \"safe\");", "definition": "to save, i.e. deliver or protect (literally or figuratively)", "kjv": "heal, preserve, save (self), do well, be (make) whole."}, "G4983": {"greek": "σῶμα", "translit": "sōma", "pronunciation": "so'-mah", "derivation": "from (G4982);", "definition": "the body (as a sound whole), used in a very wide application, literally or figuratively", "kjv": "bodily, body, slave."}, "G4984": {"greek": "σωματικός", "translit": "sōmatikós", "pronunciation": "so-mat-ee-kos'", "derivation": "from (G4983);", "definition": "corporeal or physical", "kjv": "bodily."}, "G4985": {"greek": "σωματικῶς", "translit": "sōmatikōs", "pronunciation": "so-mat-ee-koce'", "derivation": "adverb from (G4984);", "definition": "corporeally or physically", "kjv": "bodily."}, "G4986": {"greek": "Σώπατρος", "translit": "Sṓpatros", "pronunciation": "so'-pat-ros", "derivation": "from the base of (G4982) and (G3962);", "definition": "of a safe father; Sopatrus, a Christian", "kjv": "Sopater."}, "G4987": {"greek": "σωρεύω", "translit": "sōreúō", "pronunciation": "sore-yoo'-o", "derivation": "from another form of (G4673);", "definition": "to pile up (literally or figuratively)", "kjv": "heap, load."}, "G4988": {"greek": "Σωσθένης", "translit": "Sōsthénēs", "pronunciation": "soce-then'-ace", "derivation": "from the base of (G4982) and that of (G4599);", "definition": "of safe strength; Sosthenes, a Christian", "kjv": "Sosthenes."}, "G4989": {"greek": "Σωσίπατρος", "translit": "Sōsípatros", "pronunciation": "so-sip'-at-ros", "derivation": "prolongation for (G4986);", "definition": "Sosipatrus, a Christian", "kjv": "Sosipater."}, "G4990": {"greek": "σωτήρ", "translit": "sōtḗr", "pronunciation": "so-tare'", "derivation": "from (G4982);", "definition": "a deliverer, i.e. God or Christ", "kjv": "saviour."}, "G4991": {"greek": "σωτηρία", "translit": "sōtēría", "pronunciation": "so-tay-ree'-ah", "derivation": "feminine of a derivative of (G4990) as (properly, abstract) noun;", "definition": "rescue or safety (physically or morally)", "kjv": "deliver, health, salvation, save, saving."}, "G4992": {"greek": "σωτήριον", "translit": "sōtḗrion", "pronunciation": "so-tay'-ree-on", "derivation": "neuter of the same as (G4991) as (properly, concretely) noun;", "definition": "defender or (by implication) defence", "kjv": "salvation."}, "G4993": {"greek": "σωφρονέω", "translit": "sōphronéō", "pronunciation": "so-fron-eh'-o", "derivation": "from (G4998);", "definition": "to be of sound mind, i.e. sane, (figuratively) moderate", "kjv": "be in right mind, be sober (minded), soberly."}, "G4994": {"greek": "σωφρονίζω", "translit": "sōphronízō", "pronunciation": "so-fron-id'-zo", "derivation": "from (G4998);", "definition": "to make of sound mind, i.e. (figuratively) to discipline or correct", "kjv": "teach to be sober."}, "G4995": {"greek": "σωφρονισμός", "translit": "sōphronismós", "pronunciation": "so-fron-is-mos'", "derivation": "from (G4994);", "definition": "discipline, i.e. self-control", "kjv": "sound mind."}, "G4996": {"greek": "σωφρόνως", "translit": "sōphrónōs", "pronunciation": "so-fron'-oce", "derivation": "adverb from (G4998);", "definition": "with sound mind, i.e. moderately", "kjv": "soberly."}, "G4997": {"greek": "σωφροσύνη", "translit": "sōphrosýnē", "pronunciation": "so-fros-oo'-nay", "derivation": "from (G4998);", "definition": "soundness of mind, i.e. (literally) sanity or (figuratively) self-control", "kjv": "soberness, sobriety."}, "G4998": {"greek": "σώφρων", "translit": "sṓphrōn", "pronunciation": "so'-frone", "derivation": "from the base of (G4982) and that of (G5424);", "definition": "safe (sound) in mind, i.e. self-controlled (moderate as to opinion or passion)", "kjv": "discreet, sober, temperate."}, "G4999": {"greek": "Ταβέρναι", "translit": "Tabérnai", "pronunciation": "tab-er'-nahee", "derivation": "plural of Latin origin;", "definition": "huts or wooden-walled buildings; Tabernæ", "kjv": "taverns."}, "G5000": {"greek": "Ταβιθά", "translit": "Tabithá", "pronunciation": "tab-ee-thah'", "derivation": "of Chaldee origin (compare (G6646));", "definition": "the gazelle; Tabitha (i.e. Tabjetha), a Christian female", "kjv": "Tabitha."}, "G5001": {"greek": "τάγμα", "translit": "tágma", "pronunciation": "tag'-mah", "derivation": "from (G5021);", "definition": "something orderly in arrangement (a troop), i.e. (figuratively) a series or succession", "kjv": "order."}, "G5002": {"greek": "τακτός", "translit": "taktós", "pronunciation": "tak-tos'", "derivation": "from (G5021);", "definition": "arranged, i.e. appointed or stated", "kjv": "set."}, "G5003": {"greek": "ταλαιπωρέω", "translit": "talaipōréō", "pronunciation": "tal-ahee-po-reh'-o", "derivation": "from (G5005);", "definition": "to be wretched, i.e. realize one's own misery", "kjv": "be afflicted."}, "G5004": {"greek": "ταλαιπωρία", "translit": "talaipōría", "pronunciation": "tal-ahee-po-ree'-ah", "derivation": "from (G5005);", "definition": "wretchedness, i.e. calamity", "kjv": "misery."}, "G5005": {"greek": "ταλαίπωρος", "translit": "talaípōros", "pronunciation": "tal-ah'-ee-po-ros", "derivation": "from the base of (G5007) and a derivative of the base of (G3984);", "definition": "enduring trial, i.e. miserable", "kjv": "wretched."}, "G5006": {"greek": "ταλαντιαῖος", "translit": "talantiaîos", "pronunciation": "tal-an-tee-ah'-yos", "derivation": "from (G5007);", "definition": "talent-like in weight", "kjv": "weight of a talent."}, "G5007": {"greek": "τάλαντον", "translit": "tálanton", "pronunciation": "tal'-an-ton", "derivation": "neuter of a presumed derivative of the original form of (to bear; equivalent to (G5342));", "definition": "a balance (as supporting weights), i.e. (by implication) a certain weight (and thence a coin or rather sum of money) or \"talent\"", "kjv": "talent."}, "G5008": {"greek": "ταλιθά", "translit": "talithá", "pronunciation": "tal-ee-thah'", "derivation": "of Chaldee origin (compare (G2924));", "definition": "the fresh, i.e. young girl; talitha (O maiden)", "kjv": "talitha."}, "G5009": {"greek": "ταμεῖον", "translit": "tameîon", "pronunciation": "tam-i'-on", "derivation": "neuter contraction of a presumed derivative of (a dispenser or distributor; akin to , to cut);", "definition": "a dispensary or magazine, i.e. a chamber on the ground-floor or interior of an Oriental house (generally used for storage or privacy, a spot for retirement)", "kjv": "secret chamber, closet, storehouse."}, "G5010": {"greek": "τάξις", "translit": "táxis", "pronunciation": "tax'-is", "derivation": "from (G5021);", "definition": "regular arrangement, i.e. (in time) fixed succession (of rank or character), official dignity", "kjv": "order."}, "G5011": {"greek": "ταπεινός", "translit": "tapeinós", "pronunciation": "tap-i-nos'", "derivation": "of uncertain derivation;", "definition": "depressed, i.e. (figuratively) humiliated (in circumstances or disposition)", "kjv": "base, cast down, humble, of low degree (estate), lowly."}, "G5012": {"greek": "ταπεινοφροσύνη", "translit": "tapeinophrosýnē", "pronunciation": "tap-i-nof-ros-oo'-nay", "derivation": "from a compound of (G5011) and the base of (G5424);", "definition": "humiliation of mind, i.e. modesty", "kjv": "humbleness of mind, humility (of mind, loneliness (of mind)."}, "G5013": {"greek": "ταπεινόω", "translit": "tapeinóō", "pronunciation": "tap-i-no'-o", "derivation": "from (G5011);", "definition": "to depress; figuratively, to humiliate (in condition or heart)", "kjv": "abase, bring low, humble (self)."}, "G5014": {"greek": "ταπείνωσις", "translit": "tapeínōsis", "pronunciation": "tap-i'-no-sis", "derivation": "from (G5013);", "definition": "depression (in rank or feeling)", "kjv": "humiliation, be made low, low estate, vile."}, "G5015": {"greek": "ταράσσω", "translit": "tarássō", "pronunciation": "tar-as'-so", "derivation": "of uncertain affinity;", "definition": "to stir or agitate (roil water)", "kjv": "trouble."}, "G5017": {"greek": "τάραχος", "translit": "tárachos", "pronunciation": "tar'-akh-os", "derivation": "masculine from (G5015);", "definition": "a disturbance, i.e. (popular) tumult", "kjv": "stir."}, "G5018": {"greek": "Ταρσεύς", "translit": "Tarseús", "pronunciation": "tar-syoos'", "derivation": "from (G5019);", "definition": "a Tarsean, i.e. native of Tarsus", "kjv": "of Tarsus."}, "G5019": {"greek": "Ταρσός", "translit": "Tarsós", "pronunciation": "tar-sos'", "derivation": "perhaps the same as (a flat basket);", "definition": "Tarsus, a place in Asia Minor", "kjv": "Tarsus."}, "G5020": {"greek": "ταρταρόω", "translit": "tartaróō", "pronunciation": "tar-tar-o'-o", "derivation": "from (the deepest abyss of Hades);", "definition": "to incarcerate in eternal torment", "kjv": "cast down to hell."}, "G5021": {"greek": "τάσσω", "translit": "tássō", "pronunciation": "tas'-so", "derivation": "a prolonged form of a primary verb (which latter appears only in certain tenses);", "definition": "to arrange in an orderly manner, i.e. assign or dispose (to a certain position or lot)", "kjv": "addict, appoint, determine, ordain, set."}, "G5022": {"greek": "ταῦρος", "translit": "taûros", "pronunciation": "tow'-ros", "derivation": "apparently a primary word (compare (G8450), \"steer\");", "definition": "a bullock", "kjv": "bull, ox."}, "G5023": {"greek": "ταῦτα", "translit": "taûta", "pronunciation": "tow'-tah", "derivation": "nominative or accusative case neuter plural of (G3778);", "definition": "these things", "kjv": "+ afterward, follow, + hereafter, X him, the same, so, such, that, then, these, they, this, those, thus."}, "G5027": {"greek": "ταφή", "translit": "taphḗ", "pronunciation": "taf-ay'", "derivation": "feminine from (G2290);", "definition": "burial (the act)", "kjv": "X bury."}, "G5028": {"greek": "τάφος", "translit": "táphos", "pronunciation": "taf'-os", "derivation": "masculine from (G2290);", "definition": "a grave (the place of interment)", "kjv": "sepulchre, tomb."}, "G5029": {"greek": "τάχα", "translit": "tácha", "pronunciation": "takh'-ah", "derivation": "as if neuter plural of (G5036) (adverbially);", "definition": "shortly, i.e. (figuratively) possibly", "kjv": "peradventure(-haps)."}, "G5030": {"greek": "ταχέως", "translit": "tachéōs", "pronunciation": "takh-eh'-oce", "derivation": "adverb from (G5036);", "definition": "briefly, i.e. (in time) speedily, or (in manner) rapidly", "kjv": "hastily, quickly, shortly, soon, suddenly."}, "G5031": {"greek": "ταχινός", "translit": "tachinós", "pronunciation": "takh-ee-nos'", "derivation": "from (G5034);", "definition": "curt, i.e. impending", "kjv": "shortly, swift."}, "G5032": {"greek": "τάχιον", "translit": "táchion", "pronunciation": "takh'-ee-on", "derivation": "neuter singular of the comparative of (G5036) (as adverb);", "definition": "more swiftly, i.e. (in manner) more rapidly, or (in time) more speedily", "kjv": "out (run), quickly, shortly, sooner."}, "G5034": {"greek": "τάχος", "translit": "táchos", "pronunciation": "takh'-os", "derivation": "from the same as (G5036);", "definition": "a brief space (of time), i.e. (with (G1722) prefixed) in haste", "kjv": "+ quickly, + shortly, + speedily."}, "G5035": {"greek": "ταχύ", "translit": "tachý", "pronunciation": "takh-oo'", "derivation": "neuter singular of (G5036) (as adverb);", "definition": "shortly, i.e. without delay, soon, or (by surprise) suddenly, or (by implication, of ease) readily", "kjv": "lightly, quickly."}, "G5036": {"greek": "ταχύς", "translit": "tachýs", "pronunciation": "takh-oos'", "derivation": "of uncertain affinity;", "definition": "fleet, i.e. (figuratively) prompt or ready", "kjv": "swift."}, "G5037": {"greek": "τέ", "translit": "té", "pronunciation": "teh", "derivation": "a primary particle (enclitic) of connection or addition;", "definition": "both or also (properly, as correlation of (G2532))", "kjv": "also, and, both, even, then, whether."}, "G5038": {"greek": "τεῖχος", "translit": "teîchos", "pronunciation": "ti'-khos", "derivation": "akin to the base of (G5088);", "definition": "a wall (as formative of a house)", "kjv": "wall."}, "G5039": {"greek": "τεκμήριον", "translit": "tekmḗrion", "pronunciation": "tek-may'-ree-on", "derivation": "neuter of a presumed derivative of (a goal or fixed limit);", "definition": "a token (as defining a fact), i.e. criterion of certainty", "kjv": "infallible proof."}, "G5040": {"greek": "τεκνίον", "translit": "tekníon", "pronunciation": "tek-nee'-on", "derivation": "diminutive of (G5043);", "definition": "an infant, i.e. (plural figuratively) darlings (Christian converts)", "kjv": "little children."}, "G5041": {"greek": "τεκνογονέω", "translit": "teknogonéō", "pronunciation": "tek-nog-on-eh'-o", "derivation": "from a compound of (G5043) and the base of (G1096);", "definition": "to be a child-bearer, i.e. parent (mother)", "kjv": "bear children."}, "G5042": {"greek": "τεκνογονία", "translit": "teknogonía", "pronunciation": "tek-nog-on-ee'-ah", "derivation": "from the same as (G5041);", "definition": "childbirth (parentage), i.e. (by implication) maternity (the performance of maternal duties)", "kjv": "childbearing."}, "G5043": {"greek": "τέκνον", "translit": "téknon", "pronunciation": "tek'-non", "derivation": "from the base of (G5088);", "definition": "a child (as produced)", "kjv": "child, daughter, son."}, "G5044": {"greek": "τεκνοτροφέω", "translit": "teknotrophéō", "pronunciation": "tek-not-rof-eh'-o", "derivation": "from a compound of (G5043) and (G5142);", "definition": "to be a childrearer, i.e. fulfil the duties of a female parent", "kjv": "bring up children."}, "G5045": {"greek": "τέκτων", "translit": "téktōn", "pronunciation": "tek'-tone", "derivation": "from the base of (G5098);", "definition": "an artificer (as producer of fabrics), i.e. (specially), a craftsman in wood", "kjv": "carpenter."}, "G5046": {"greek": "τέλειος", "translit": "téleios", "pronunciation": "tel'-i-os", "derivation": "from (G5056);", "definition": "complete (in various applications of labor, growth, mental and moral character, etc.); neuter (as noun, with (G3588)) completeness", "kjv": "of full age, man, perfect."}, "G5047": {"greek": "τελειότης", "translit": "teleiótēs", "pronunciation": "tel-i-ot'-ace", "derivation": "from (G5046);", "definition": "(the state) completeness (mentally or morally)", "kjv": "perfection(-ness)."}, "G5048": {"greek": "τελειόω", "translit": "teleióō", "pronunciation": "tel-i-o'-o", "derivation": "from (G5046);", "definition": "to complete, i.e. (literally) accomplish, or (figuratively) consummate (in character)", "kjv": "consecrate, finish, fulfil, make) perfect."}, "G5049": {"greek": "τελείως", "translit": "teleíōs", "pronunciation": "tel-i'-oce", "derivation": "adverb from (G5046);", "definition": "completely, i.e. (of hope) without wavering", "kjv": "to the end."}, "G5050": {"greek": "τελείωσις", "translit": "teleíōsis", "pronunciation": "tel-i'-o-sis", "derivation": "from (G5448);", "definition": "(the act) completion, i.e. (of prophecy) verification, or (of expiation) absolution", "kjv": "perfection, performance."}, "G5051": {"greek": "τελειωτής", "translit": "teleiōtḗs", "pronunciation": "tel-i-o-tace'", "derivation": "from (G5048);", "definition": "a completer, i.e. consummater", "kjv": "finisher."}, "G5052": {"greek": "τελεσφορέω", "translit": "telesphoréō", "pronunciation": "tel-es-for-eh'-o", "derivation": "from a compound of (G5056) and (G5342);", "definition": "to be a bearer to completion (maturity), i.e. to ripen fruit (figuratively)", "kjv": "bring fruit to perfection."}, "G5053": {"greek": "τελευτάω", "translit": "teleutáō", "pronunciation": "tel-yoo-tah'-o", "derivation": "from a presumed derivative of (G5055);", "definition": "to finish life (by implication, of (G979)), i.e. expire (demise)", "kjv": "be dead, decease, die."}, "G5054": {"greek": "τελευτή", "translit": "teleutḗ", "pronunciation": "tel-yoo-tay'", "derivation": "from (G5053);", "definition": "decease", "kjv": "death."}, "G5055": {"greek": "τελέω", "translit": "teléō", "pronunciation": "tel-eh'-o", "derivation": "from (G5056);", "definition": "to end, i.e. complete, execute, conclude, discharge (a debt)", "kjv": "accomplish, make an end, expire, fill up, finish, go over, pay, perform."}, "G5056": {"greek": "τέλος", "translit": "télos", "pronunciation": "tel'-os", "derivation": "from a primary (to set out for a definite point or goal);", "definition": "properly, the point aimed at as a limit, i.e. (by implication) the conclusion of an act or state (termination (literally, figuratively or indefinitely), result (immediate, ultimate or prophetic), purpose); specially, an impost or levy (as paid)", "kjv": "+ continual, custom, end(-ing), finally, uttermost."}, "G5057": {"greek": "τελώνης", "translit": "telṓnēs", "pronunciation": "tel-o'-nace", "derivation": "from (G5056) and (G5608);", "definition": "a tax-farmer, i.e. collector of public revenue", "kjv": "publican."}, "G5058": {"greek": "τελώνιον", "translit": "telṓnion", "pronunciation": "tel-o'-nee-on", "derivation": "neuter of a presumed derivative of (G5057);", "definition": "a tax-gatherer's place of business", "kjv": "receipt of custom."}, "G5059": {"greek": "τέρας", "translit": "téras", "pronunciation": "ter'-as", "derivation": "of uncertain affinity;", "definition": "a prodigy or omen", "kjv": "wonder."}, "G5060": {"greek": "Τέρτιος", "translit": "Tértios", "pronunciation": "ter'-tee-os", "derivation": "of Latin origin;", "definition": "third; Tertius, a Christian", "kjv": "Tertius."}, "G5061": {"greek": "Τέρτυλλος", "translit": "Tértyllos", "pronunciation": "ter'-tool-los", "derivation": "of uncertain derivation;", "definition": "Tertullus, a Roman", "kjv": "Tertullus."}, "G5062": {"greek": "τεσσαράκοντα", "translit": "tessarákonta", "pronunciation": "tes-sar-ak'-on-tah", "derivation": "the decade of (G5064);", "definition": "forty", "kjv": "forty."}, "G5063": {"greek": "τεσσαρακονταετής", "translit": "tessarakontaetḗs", "pronunciation": "tes-sar-ak-on-tah-et-ace'", "derivation": "from (G5062) and (G2094);", "definition": "of forty years of age", "kjv": "(+ full, of) forty years (old)."}, "G5064": {"greek": "τέσσαρες", "translit": "téssares", "pronunciation": "tes'-sar-es", "derivation": "a plural number;", "definition": "four", "kjv": "four."}, "G5065": {"greek": "τεσσαρεσκαιδέκατος", "translit": "tessareskaidékatos", "pronunciation": "tes-sar-es-kahee-dek'-at-os", "derivation": "from (G5064) and (G2532) and (G1182);", "definition": "fourteenth", "kjv": "fourteenth."}, "G5066": {"greek": "τεταρταῖος", "translit": "tetartaîos", "pronunciation": "tet-ar-tah'-yos", "derivation": "from (G5064);", "definition": "pertaining to the fourth day", "kjv": "four days."}, "G5067": {"greek": "τέταρτος", "translit": "tétartos", "pronunciation": "tet'-ar-tos", "derivation": "ordinal from (G5064);", "definition": "fourth", "kjv": "four(-th)."}, "G5068": {"greek": "τετράγωνος", "translit": "tetrágōnos", "pronunciation": "tet-rag'-o-nos", "derivation": "from (G5064) and (G1137);", "definition": "four-cornered, i.e. square", "kjv": "foursquare."}, "G5069": {"greek": "τετράδιον", "translit": "tetrádion", "pronunciation": "tet-rad'-ee-on", "derivation": "neuter of a presumed derivative of (a tetrad; from (G5064));", "definition": "a quaternion or squad (picket) of four Roman soldiers", "kjv": "quaternion."}, "G5070": {"greek": "τετρακισχίλιοι", "translit": "tetrakischílioi", "pronunciation": "tet-rak-is-khil'-ee-oy", "derivation": "from the multiplicative adverb of (G5064) and (G5507);", "definition": "four times a thousand", "kjv": "four thousand."}, "G5071": {"greek": "τετρακόσιοι", "translit": "tetrakósioi", "pronunciation": "tet-rak-os'-ee-oy", "derivation": "plural from (G5064) and (G1540);", "definition": "four hundred", "kjv": "four hundred."}, "G5072": {"greek": "τετράμηνον", "translit": "tetrámēnon", "pronunciation": "tet-ram'-ay-non", "derivation": "neuter of a compound of (G5064) and (G3376);", "definition": "a four months' space", "kjv": "four months."}, "G5073": {"greek": "τετραπλόος", "translit": "tetraplóos", "pronunciation": "tet-rap-lo'-os", "derivation": "from (G5064) and a derivative of the base of (G4118);", "definition": "quadruple", "kjv": "fourfold."}, "G5074": {"greek": "τετράπους", "translit": "tetrápous", "pronunciation": "tet-rap'-ooce", "derivation": "from (G5064) and (G4228);", "definition": "a quadruped", "kjv": "fourfooted beast."}, "G5075": {"greek": "τετραρχέω", "translit": "tetrarchéō", "pronunciation": "tet-rar-kheh'-o", "derivation": "from (G5076);", "definition": "to be a tetrarch", "kjv": "(be) tetrarch."}, "G5076": {"greek": "τετράρχης", "translit": "tetrárchēs", "pronunciation": "tet-rar'-khace", "derivation": "from (G5064) and (G757);", "definition": "the ruler of a fourth part of a country (\"tetrarch\")", "kjv": "tetrarch."}, "G5077": {"greek": "τεφρόω", "translit": "tephróō", "pronunciation": "tef-ro'-o", "derivation": "from (ashes);", "definition": "to incinerate, i.e. consume", "kjv": "turn to ashes."}, "G5078": {"greek": "τέχνη", "translit": "téchnē", "pronunciation": "tekh'-nay", "derivation": "from the base of (G5088);", "definition": "art (as productive), i.e. (specially), a trade, or (generally) skill", "kjv": "art, craft, occupation."}, "G5079": {"greek": "τεχνίτης", "translit": "technítēs", "pronunciation": "tekh-nee'-tace", "derivation": "from (G5078);", "definition": "an artisan; figuratively, a founder (Creator)", "kjv": "builder, craftsman."}, "G5080": {"greek": "τήκω", "translit": "tḗkō", "pronunciation": "tay'-ko", "derivation": "apparently a primary verb;", "definition": "to liquefy", "kjv": "melt."}, "G5081": {"greek": "τηλαυγῶς", "translit": "tēlaugōs", "pronunciation": "tay-low-goce'", "derivation": "adverb from a compound of a derivative of (G5056) and (G827);", "definition": "in a far-shining manner, i.e. plainly", "kjv": "clearly."}, "G5082": {"greek": "τηλικοῦτος", "translit": "tēlikoûtos", "pronunciation": "tay-lik-oo'-tos", "derivation": "from a compound of (G3588) with (G2245) and (G3778);", "definition": "such as this, i.e. (in (figurative) magnitude) so vast", "kjv": "so great, so mighty."}, "G5083": {"greek": "τηρέω", "translit": "tēréō", "pronunciation": "tay-reh'-o", "derivation": "from (a watch; perhaps akin to (G2334));", "definition": "to guard (from loss or injury, properly, by keeping the eye upon; and thus differing from (G5442), which is properly to prevent escaping; and from (G2892), which implies a fortress or full military lines of apparatus), i.e. to note (a prophecy; figuratively, to fulfil a command); by implication, to detain (in custody; figuratively, to maintain); by extension, to withhold (for personal ends; figuratively, to keep unmarried); by extension, to withhold (for personal ends; figuratively, to keep unmarried)", "kjv": "hold fast, keep(- er), (pre-, re-)serve, watch."}, "G5084": {"greek": "τήρησις", "translit": "tḗrēsis", "pronunciation": "tay'-ray-sis", "derivation": "from (G5083);", "definition": "a watching, i.e. (figuratively) observance, or (concretely) a prison", "kjv": "hold."}, "G5085": {"greek": "Τιβεριάς", "translit": "Tiberiás", "pronunciation": "tib-er-ee-as'", "derivation": "from (G5086);", "definition": "Tiberias, the name of a town and a lake in Palestine", "kjv": "Tiberias."}, "G5086": {"greek": "Τιβέριος", "translit": "Tibérios", "pronunciation": "tib-er'-ee-os", "derivation": "of Latin origin;", "definition": "probably pertaining to the river Tiberis or Tiber; Tiberius, a Roman emperor", "kjv": "Tiberius."}, "G5087": {"greek": "τίθημι", "translit": "títhēmi", "pronunciation": "tith'-ay-mee", "derivation": "a prolonged form of a primary (which is used only as alternate in certain tenses);", "definition": "to place (in the widest application, literally and figuratively; properly, in a passive or horizontal posture, and thus different from (G2476), which properly denotes an upright and active position, while (G2749) is properly reflexive and utterly prostrate)", "kjv": "+ advise, appoint, bow, commit, conceive, give, X kneel down, lay (aside, down, up), make, ordain, purpose, put, set (forth), settle, sink down."}, "G5088": {"greek": "τίκτω", "translit": "tíktō", "pronunciation": "tik'-to", "derivation": "a strengthened form of a primary (which is used only as alternate in certain tenses);", "definition": "to produce (from seed, as a mother, a plant, the earth, etc.), literally or figuratively", "kjv": "bear, be born, bring forth, be delivered, be in travail."}, "G5089": {"greek": "τίλλω", "translit": "tíllō", "pronunciation": "til'-lo", "derivation": "perhaps akin to the alternate of (G138), and thus to (G4951);", "definition": "to pull off", "kjv": "pluck."}, "G5090": {"greek": "Τιμαῖος", "translit": "Timaîos", "pronunciation": "tim'-ah-yos", "derivation": "probably of Chaldee origin (compare (G2931));", "definition": "Timæus (i.e. Timay), an Israelite", "kjv": "Timæus."}, "G5091": {"greek": "τιμάω", "translit": "timáō", "pronunciation": "tim-ah'-o", "derivation": "from (G5093);", "definition": "to prize, i.e. fix a valuation upon; by implication, to revere", "kjv": "honour, value."}, "G5092": {"greek": "τιμή", "translit": "timḗ", "pronunciation": "tee-may'", "derivation": "from (G5099);", "definition": "a value, i.e. money paid, or (concretely and collectively) valuables; by analogy, esteem (especially of the highest degree), or the dignity itself", "kjv": "honour, precious, price, some."}, "G5093": {"greek": "τίμιος", "translit": "tímios", "pronunciation": "tim'-ee-os", "derivation": "from (G5092);", "definition": "valuable, i.e. (objectively) costly, or (subjectively) honored, esteemed, or (figuratively) beloved", "kjv": "dear, honourable, (more, most) precious, had in reputation."}, "G5094": {"greek": "τιμιότης", "translit": "timiótēs", "pronunciation": "tim-ee-ot'-ace", "derivation": "from (G5093);", "definition": "expensiveness, i.e. (by implication) magnificence", "kjv": "costliness."}, "G5095": {"greek": "Τιμόθεος", "translit": "Timótheos", "pronunciation": "tee-moth'-eh-os", "derivation": "from (G5092) and (G2316);", "definition": "dear to God; Timotheus, a Christian", "kjv": "Timotheus, Timothy."}, "G5096": {"greek": "Τίμων", "translit": "Tímōn", "pronunciation": "tee'-mone", "derivation": "from (G5092);", "definition": "valuable; Timon, a Christian", "kjv": "Timon."}, "G5097": {"greek": "τιμωρέω", "translit": "timōréō", "pronunciation": "tim-o-reh'-o", "derivation": "from a compound of (G5092) and ouros (a guard);", "definition": "properly, to protect one's honor, i.e. to avenge (inflict a penalty)", "kjv": "punish."}, "G5098": {"greek": "τιμωρία", "translit": "timōría", "pronunciation": "tee-mo-ree'-ah", "derivation": "from (G5097);", "definition": "vindication, i.e. (by implication) a penalty", "kjv": "punishment."}, "G5099": {"greek": "τίνω", "translit": "tínō", "pronunciation": "tee'-no", "derivation": "strengthened for a primary (which is only used as an alternate in certain tenses);", "definition": "to pay a price, i.e. as a penalty", "kjv": "be punished with."}, "G5100": {"greek": "τὶς", "translit": "tìs", "pronunciation": "tis", "derivation": "an enclitic indefinite pronoun;", "definition": "some or any person or object", "kjv": "a (kind of), any (man, thing, thing at all), certain (thing), divers, he (every) man, one (X thing), ought, + partly, some (man, -body, - thing, -what), (+ that no-)thing, what(-soever), X wherewith, whom(-soever), whose(-soever)."}, "G5101": {"greek": "τίς", "translit": "tís", "pronunciation": "tis", "derivation": "probably emphatic of (G5100);", "definition": "an interrogative pronoun, who, which or what (in direct or indirect questions)", "kjv": "every man, how (much), + no(-ne, thing), what (manner, thing), where (-by, -fore, -of, -unto, - with, -withal), whether, which, who(-m, -se), why."}, "G5102": {"greek": "τίτλος", "translit": "títlos", "pronunciation": "tit'-los", "derivation": "of Latin origin;", "definition": "a titulus or \"title\" (placard)", "kjv": "title."}, "G5103": {"greek": "Τίτος", "translit": "Títos", "pronunciation": "tee'-tos", "derivation": "of Latin origin but uncertain significance;", "definition": "Titus, a Christian", "kjv": "Titus."}, "G5105": {"greek": "τοιγαροῦν", "translit": "toigaroûn", "pronunciation": "toy-gar-oon'", "derivation": "from (G5104) and (G1063) and (G3767);", "definition": "truly for then, i.e. consequently", "kjv": "there-(where-)fore."}, "G5106": {"greek": "τοίνυν", "translit": "toínyn", "pronunciation": "toy'-noon", "derivation": "from (G5104) and (G3568);", "definition": "truly now, i.e. accordingly", "kjv": "then, therefore."}, "G5107": {"greek": "τοιόσδε", "translit": "toiósde", "pronunciation": "toy-os'-deh", "derivation": "(including the other inflections); from a derivative of 5104 and (G1161);", "definition": "such-like then, i.e. so great", "kjv": "such."}, "G5108": {"greek": "τοιοῦτος", "translit": "toioûtos", "pronunciation": "toy-oo'-tos", "derivation": "(including the other inflections); from (G5104) and (G3778);", "definition": "truly this, i.e. of this sort (to denote character or individuality)", "kjv": "like, such (an one)."}, "G5109": {"greek": "τοῖχος", "translit": "toîchos", "pronunciation": "toy'-khos", "derivation": "another form of (G5038);", "definition": "a wall", "kjv": "wall."}, "G5110": {"greek": "τόκος", "translit": "tókos", "pronunciation": "tok'-os", "derivation": "from the base of (G5088);", "definition": "interest on money loaned (as a produce)", "kjv": "usury."}, "G5111": {"greek": "τολμάω", "translit": "tolmáō", "pronunciation": "tol-mah'-o", "derivation": "from (boldness; probably itself from the base of (G5056) through the idea of extreme conduct);", "definition": "to venture (objectively or in act; while (G2292) is rather subjective or in feeling); by implication, to be courageous", "kjv": "be bold, boldly, dare, durst."}, "G5112": {"greek": "τολμηρότερον", "translit": "tolmēróteron", "pronunciation": "tol-may-rot'-er-on", "derivation": "neuter of the compound of a derivative of the base of 5111 (as adverb);", "definition": "more daringly, i.e. with greater confidence than otherwise", "kjv": "the more boldly."}, "G5113": {"greek": "τολμητής", "translit": "tolmētḗs", "pronunciation": "tol-may-tace'", "derivation": "from (G5111);", "definition": "a daring (audacious) man", "kjv": "presumptuous."}, "G5114": {"greek": "τομώτερος", "translit": "tomṓteros", "pronunciation": "tom-o'-ter-os", "derivation": "comparative of a derivative of the primary (to cut; more comprehensive or decisive than (G2875), as if by a single stroke; whereas that implies repeated blows, like hacking);", "definition": "more keen", "kjv": "sharper."}, "G5115": {"greek": "τόξον", "translit": "tóxon", "pronunciation": "tox'-on", "derivation": "from the base of (G5088);", "definition": "a bow (apparently as the simplest fabric)", "kjv": "bow."}, "G5116": {"greek": "τοπάζιον", "translit": "topázion", "pronunciation": "top-ad'-zee-on", "derivation": "neuter of a presumed derivative (alternately) of (a \"topaz\"; of uncertain origin);", "definition": "a gem, probably the chrysolite", "kjv": "topaz."}, "G5117": {"greek": "τόπος", "translit": "tópos", "pronunciation": "top'-os", "derivation": "apparently a primary word;", "definition": "a spot (generally in space, but limited by occupancy; whereas (G5561) is a large but particular locality), i.e. location (as a position, home, tract, etc.); figuratively, condition, opportunity; specially, a scabbard", "kjv": "coast, licence, place, X plain, quarter, + rock, room, where."}, "G5118": {"greek": "τοσοῦτος", "translit": "tosoûtos", "pronunciation": "tos-oo'-tos", "derivation": "from (so much;", "definition": "apparently from (G3588) and (G3739)) and (G3778) (including its variations); so vast as this, i.e. such (in quantity, amount, number of space)", "kjv": "as large, so great (long, many, much), these many."}, "G5119": {"greek": "τότε", "translit": "tóte", "pronunciation": "tot'-eh", "derivation": "from (the neuter of) (G3588) and (G3753);", "definition": "the when, i.e. at the time that (of the past or future, also in consecution)", "kjv": "that time, then."}, "G5121": {"greek": "τοὐναντίον", "translit": "tounantíon", "pronunciation": "too-nan-tee'-on", "derivation": "contraction for the neuter of (G3588) and (G1726);", "definition": "on the contrary", "kjv": "contrariwise."}, "G5122": {"greek": "τοὔνομα", "translit": "toúnoma", "pronunciation": "too'-no-mah", "derivation": "contraction for the neuter of (G3588) and (G3686);", "definition": "the name (is)", "kjv": "named."}, "G5124": {"greek": "τοῦτο", "translit": "toûto", "pronunciation": "too'-to", "derivation": "neuter singular nominative or accusative case of (G3778);", "definition": "that thing", "kjv": "here (-unto), it, partly, self(-same), so, that (intent), the same, there(-fore, -unto), this, thus, where(-fore)."}, "G5125": {"greek": "τούτοις", "translit": "toútois", "pronunciation": "too'-toice", "derivation": "dative case plural masculine or neuter of (G3778);", "definition": "to (for, in, with or by) these (persons or things)", "kjv": "such, them, there(-in, -with), these, this, those."}, "G5126": {"greek": "τοῦτον", "translit": "toûton", "pronunciation": "too'-ton", "derivation": "accusative case singular masculine of (G3778);", "definition": "this (person, as objective of verb or preposition)", "kjv": "him, the same, that, this."}, "G5127": {"greek": "τούτου", "translit": "toútou", "pronunciation": "too'-too", "derivation": "genitive case singular masculine or neuter of (G3778);", "definition": "of (from or concerning) this (person or thing)", "kjv": "here(-by), him, it, + such manner of, that, thence(-forth), thereabout, this, thus."}, "G5128": {"greek": "τούτους", "translit": "toútous", "pronunciation": "too'-tooce", "derivation": "accusative case plural masculine of (G3778);", "definition": "these (persons, as objective of verb or preposition)", "kjv": "such, them, these, this."}, "G5129": {"greek": "τούτῳ", "translit": "toútōi", "pronunciation": "too'-to", "derivation": "dative case singular masculine or neuter of (G3778);", "definition": "to (in, with or by) this (person or thing)", "kjv": "here(-by, -in), him, one, the same, there(-in), this."}, "G5130": {"greek": "τούτων", "translit": "toútōn", "pronunciation": "too'-tone", "derivation": "genitive case plural masculine or neuter of (G3778);", "definition": "of (from or concerning) these (persons or things)", "kjv": "such, their, these (things), they, this sort, those."}, "G5131": {"greek": "τράγος", "translit": "trágos", "pronunciation": "trag'-os", "derivation": "from the base of (G5176);", "definition": "a he-goat (as a gnawer)", "kjv": "goat."}, "G5132": {"greek": "τράπεζα", "translit": "trápeza", "pronunciation": "trap'-ed-zah", "derivation": "probably contracted from (G5064) and (G3979);", "definition": "a table or stool (as being four-legged), usually for food (figuratively, a meal); also a counter for money (figuratively, a broker's office for loans at interest)", "kjv": "bank, meat, table."}, "G5133": {"greek": "τραπεζίτης", "translit": "trapezítēs", "pronunciation": "trap-ed-zee'-tace", "derivation": "from (G5132);", "definition": "a money-broker or banker", "kjv": "exchanger."}, "G5134": {"greek": "τραῦμα", "translit": "traûma", "pronunciation": "trow'-mah", "derivation": "from the base of (to wound; akin to the base of (G2352), (G5147), (G5149), etc.);", "definition": "a wound", "kjv": "wound."}, "G5135": {"greek": "τραυματίζω", "translit": "traumatízō", "pronunciation": "trow-mat-id'-zo", "derivation": "from (G5134);", "definition": "to inflict a wound", "kjv": "wound."}, "G5136": {"greek": "τραχηλίζω", "translit": "trachēlízō", "pronunciation": "trakh-ay-lid'-zo", "derivation": "from (G5137);", "definition": "to seize by the throat or neck, i.e. to expose the gullet of a victim for killing (generally, to lay bare)", "kjv": "opened."}, "G5137": {"greek": "τράχηλος", "translit": "tráchēlos", "pronunciation": "trakh'-ay-los", "derivation": "probably from (G5143) (through the idea of mobility);", "definition": "the throat (neck), i.e. (figuratively) life", "kjv": "neck."}, "G5138": {"greek": "τραχύς", "translit": "trachýs", "pronunciation": "trakh-oos'", "derivation": "perhaps strengthened from the base of (G4486) (as if jagged by rents);", "definition": "uneven, rocky (reefy)", "kjv": "rock, rough."}, "G5139": {"greek": "Τραχωνῖτις", "translit": "Trachōnîtis", "pronunciation": "trakh-o-nee'-tis", "derivation": "from a derivative of (G5138);", "definition": "rough district; Trachonitis, a region of Syria", "kjv": "Trachonitis."}, "G5140": {"greek": "τρεῖς", "translit": "treîs", "pronunciation": "trice", "derivation": "a primary (plural) number;", "definition": "\"three\"", "kjv": "three."}, "G5141": {"greek": "τρέμω", "translit": "trémō", "pronunciation": "trem'-o", "derivation": "strengthened from a primary (to \"dread\", \"terrify\");", "definition": "to \"tremble\" or fear", "kjv": "be afraid, trembling."}, "G5142": {"greek": "τρέφω", "translit": "tréphō", "pronunciation": "tref'-o", "derivation": "a primary verb (properly, ;", "definition": "but perhaps strengthened from the base of (G5157) through the idea of convolution); properly, to stiffen, i.e. fatten (by implication, to cherish (with food, etc.), pamper, rear)", "kjv": "bring up, feed, nourish."}, "G5143": {"greek": "τρέχω", "translit": "tréchō", "pronunciation": "trekh'-o", "derivation": "apparently a primary verb (properly, ; compare (G2359));", "definition": "which uses (the base of (G1408)) as alternate in certain tenses; to run or walk hastily (literally or figuratively)", "kjv": "have course, run."}, "G5144": {"greek": "τριάκοντα", "translit": "triákonta", "pronunciation": "tree-ak'-on-tah", "derivation": "the decade of (G5140);", "definition": "thirty", "kjv": "thirty."}, "G5145": {"greek": "τριακόσιοι", "translit": "triakósioi", "pronunciation": "tree-ak-os'-ee-oy", "derivation": "plural from (G5140) and (G1540);", "definition": "three hundred", "kjv": "three hundred."}, "G5146": {"greek": "τρίβολος", "translit": "tríbolos", "pronunciation": "trib'-ol-os", "derivation": "from (G5140) and (G956);", "definition": "properly, a crow-foot (three-pronged obstruction in war), i.e. (by analogy) a thorny plant (caltrop)", "kjv": "brier, thistle."}, "G5147": {"greek": "τρίβος", "translit": "tríbos", "pronunciation": "tree'-bos", "derivation": "from (to \"rub\"; akin to , , and the base of (G5131), (G5134));", "definition": "a rut or worn track", "kjv": "path."}, "G5148": {"greek": "τριετία", "translit": "trietía", "pronunciation": "tree-et-ee'-ah", "derivation": "from a compound of (G5140) and (G2094);", "definition": "a three years' period (triennium)", "kjv": "space of three years."}, "G5149": {"greek": "τρίζω", "translit": "trízō", "pronunciation": "trid'-zo", "derivation": "apparently a primary verb;", "definition": "to creak (squeak), i.e. (by analogy) to grate the teeth (in frenzy)", "kjv": "gnash."}, "G5150": {"greek": "τρίμηνον", "translit": "trímēnon", "pronunciation": "trim'-ay-non", "derivation": "neuter of a compound of (G5140) and (G3376) as noun;", "definition": "a three months' space", "kjv": "three months."}, "G5151": {"greek": "τρίς", "translit": "trís", "pronunciation": "trece", "derivation": "adverb from (G5140);", "definition": "three times", "kjv": "three times, thrice."}, "G5152": {"greek": "τρίστεγον", "translit": "trístegon", "pronunciation": "tris'-teg-on", "derivation": "neuter of a compound of (G5140) and (G4721) as noun;", "definition": "a third roof (story)", "kjv": "third loft."}, "G5153": {"greek": "τρισχίλιοι", "translit": "trischílioi", "pronunciation": "tris-khil'-ee-oy", "derivation": "from (G5151) and (G5507);", "definition": "three times a thousand", "kjv": "three thousand."}, "G5154": {"greek": "τρίτος", "translit": "trítos", "pronunciation": "tree'-tos", "derivation": "ordinal from (G5140);", "definition": "third; neuter (as noun) a third part, or (as adverb) a (or the) third time, thirdly", "kjv": "third(-ly)."}, "G5155": {"greek": "τρίχινος", "translit": "tríchinos", "pronunciation": "trikh'-ee-nos", "derivation": "from (G2359);", "definition": "hairy, i.e. made of hair (mohair)", "kjv": "of hair."}, "G5156": {"greek": "τρόμος", "translit": "trómos", "pronunciation": "trom'-os", "derivation": "from (G5141);", "definition": "a \"trembling\", i.e. quaking with fear", "kjv": "+ tremble(-ing)."}, "G5157": {"greek": "τροπή", "translit": "tropḗ", "pronunciation": "trop-ay'", "derivation": "from an apparently primary to turn;", "definition": "a turn (\"trope\"), i.e. revolution (figuratively, variation)", "kjv": "turning."}, "G5158": {"greek": "τρόπος", "translit": "trópos", "pronunciation": "trop'-os", "derivation": "from the same as (G5157);", "definition": "a turn, i.e. (by implication) mode or style (especially with preposition or relative prefix as adverb, like); figuratively, deportment or character", "kjv": "(even) as, conversation, (+ like) manner, (+ by any) means, way."}, "G5159": {"greek": "τροποφορέω", "translit": "tropophoréō", "pronunciation": "trop-of-or-eh'-o", "derivation": "from (G5158) and (G5409);", "definition": "to endure one's habits", "kjv": "suffer the manners."}, "G5160": {"greek": "τροφή", "translit": "trophḗ", "pronunciation": "trof-ay'", "derivation": "from (G5142);", "definition": "nourishment (literally or figuratively); by implication, rations (wages)", "kjv": "food, meat."}, "G5161": {"greek": "Τρόφιμος", "translit": "Tróphimos", "pronunciation": "trof'-ee-mos", "derivation": "from (G5160);", "definition": "nutritive; Trophimus, a Christian", "kjv": "Trophimus."}, "G5162": {"greek": "τροφός", "translit": "trophós", "pronunciation": "trof-os'", "derivation": "from (G5142);", "definition": "a nourisher, i.e. nurse", "kjv": "nurse."}, "G5163": {"greek": "τροχιά", "translit": "trochiá", "pronunciation": "trokh-ee-ah'", "derivation": "from (G5164);", "definition": "a track (as a wheel-rut), i.e. (figuratively) a course of conduct", "kjv": "path."}, "G5164": {"greek": "τροχός", "translit": "trochós", "pronunciation": "trokh-os'", "derivation": "from (G5143);", "definition": "a wheel (as a runner), i.e. (figuratively) a circuit of physical effects", "kjv": "course."}, "G5165": {"greek": "τρύβλιον", "translit": "trýblion", "pronunciation": "troob'-lee-on", "derivation": "neuter of a presumed derivative of uncertain affinity;", "definition": "a bowl", "kjv": "dish."}, "G5166": {"greek": "τρυγάω", "translit": "trygáō", "pronunciation": "troo-gah'-o", "derivation": "from a derivative of (to dry) meaning ripe fruit (as if dry);", "definition": "to collect the vintage", "kjv": "gather."}, "G5167": {"greek": "τρυγών", "translit": "trygṓn", "pronunciation": "troo-gone'", "derivation": "from (to murmur; akin to (G5149), but denoting a duller sound);", "definition": "a turtle-dove (as cooing)", "kjv": "turtle-dove."}, "G5168": {"greek": "τρυμαλιά", "translit": "trymaliá", "pronunciation": "troo-mal-ee-ah'", "derivation": "from a derivative of (to wear away; akin to the base of (G5134), (G5147) and (G5176));", "definition": "an orifice, i.e. needle's eye", "kjv": "eye."}, "G5169": {"greek": "τρύπημα", "translit": "trýpēma", "pronunciation": "troo'-pay-mah", "derivation": "from a derivative of the base of (G5168);", "definition": "an aperture, i.e. a needle's eye", "kjv": "eye."}, "G5170": {"greek": "Τρύφαινα", "translit": "Trýphaina", "pronunciation": "troo'-fahee-nah", "derivation": "from (G5172);", "definition": "luxurious; Tryphæna, a Christian woman", "kjv": "Tryphena."}, "G5171": {"greek": "τρυφάω", "translit": "trypháō", "pronunciation": "troo-fah'-o", "derivation": "from (G5172);", "definition": "to indulge in luxury", "kjv": "live in pleasure."}, "G5172": {"greek": "τρυφή", "translit": "tryphḗ", "pronunciation": "troo-fay'", "derivation": "from (to break up or (figuratively) enfeeble, especially the mind and body by indulgence);", "definition": "effeminacy, i.e. luxury or debauchery", "kjv": "delicately, riot."}, "G5173": {"greek": "Τρυφῶσα", "translit": "Tryphōsa", "pronunciation": "troo-fo'-sah", "derivation": "from (G5172);", "definition": "luxuriating; Tryphosa, a Christian female", "kjv": "Tryphosa."}, "G5174": {"greek": "Τρωάς", "translit": "Trōás", "pronunciation": "tro-as'", "derivation": "from (a Trojan);", "definition": "the Troad (or plain of Troy), i.e. Troas, a place in Asia Minor", "kjv": "Troas."}, "G5176": {"greek": "τρώγω", "translit": "trṓgō", "pronunciation": "tro'-go", "derivation": "probably strengthened from a collateral form of the base of (G5134) and (G5147) through the idea of corrosion or wear;", "definition": "or perhaps rather of a base of (G5167) and (G5149) through the idea of a craunching sound; to gnaw or chew, i.e. (generally) to eat", "kjv": "eat."}, "G5177": {"greek": "τυγχάνω", "translit": "tynchánō", "pronunciation": "toong-khan'-o", "derivation": "probably for an obsolete (for which the middle voice of another alternate (to make ready or bring to pass) is used in certain tenses;", "definition": "akin to the base of (G5088) through the idea of effecting; properly, to affect; or (specially), to hit or light upon (as a mark to be reached), i.e. (transitively) to attain or secure an object or end, or (intransitively) to happen (as if meeting with); but in the latter application only impersonal (with (G1487)), i.e. perchance; or (present participle) as adjective, usual (as if commonly met with, with (G3756), extraordinary), neuter (as adverb) perhaps; or (with another verb) as adverb, by accident (as it were)", "kjv": "be, chance, enjoy, little, obtain, X refresh…self, + special."}, "G5178": {"greek": "τυμπανίζω", "translit": "tympanízō", "pronunciation": "toom-pan-id'-zo", "derivation": "from a derivative of (G5180) (meaning a drum, \"tympanum\");", "definition": "to stretch on an instrument of torture resembling a drum, and thus beat to death", "kjv": "torture."}, "G5179": {"greek": "τύπος", "translit": "týpos", "pronunciation": "too'-pos", "derivation": "from (G5180);", "definition": "a die (as struck), i.e. (by implication) a stamp or scar; by analogy, a shape, i.e. a statue, (figuratively) style or resemblance; specially, a sampler (\"type\"), i.e. a model (for imitation) or instance (for warning)", "kjv": "en-(ex-)ample, fashion, figure, form, manner, pattern, print."}, "G5180": {"greek": "τύπτω", "translit": "týptō", "pronunciation": "toop'-to", "derivation": "a primary verb (in a strengthened form);", "definition": "to \"thump\", i.e. cudgel or pummel (properly, with a stick or bastinado), but in any case by repeated blows; thus differing from (G3817) and (G3960), which denote a (usually single) blow with the hand or any instrument, or (G4141) with the fist (or a hammer), or (G4474) with the palm; as well as from (G5177), an accidental collision); by implication, to punish; figuratively, to offend (the conscience)", "kjv": "beat, smite, strike, wound."}, "G5181": {"greek": "Τύραννος", "translit": "Týrannos", "pronunciation": "too'-ran-nos", "derivation": "a provincial form of the derivative of the base of (G2962);", "definition": "a \"tyrant\"; Tyrannus, an Ephesian", "kjv": "Tyrannus."}, "G5183": {"greek": "Τύριος", "translit": "Týrios", "pronunciation": "too'-ree-os", "derivation": "from (G5184);", "definition": "a Tyrian, i.e. inhabitant of Tyrus", "kjv": "of Tyre."}, "G5184": {"greek": "Τύρος", "translit": "Týros", "pronunciation": "too'-ros", "derivation": "of Hebrew origin ((G6865)): Tyrus (i.e. Tsor), a place in Palestine", "definition": "", "kjv": "Tyre."}, "G5185": {"greek": "τυφλός", "translit": "typhlós", "pronunciation": "toof-los'", "derivation": "from, (G5187);", "definition": "opaque (as if smoky), i.e. (by analogy) blind (physically or mentally)", "kjv": "blind."}, "G5186": {"greek": "τυφλόω", "translit": "typhlóō", "pronunciation": "toof-lo'-o", "derivation": "from (G5185);", "definition": "to make blind, i.e. (figuratively) to obscure", "kjv": "blind."}, "G5187": {"greek": "τυφόω", "translit": "typhóō", "pronunciation": "toof-o'-o", "derivation": "from a derivative of (G5188);", "definition": "to envelop with smoke, i.e. (figuratively) to inflate with self-conceit", "kjv": "high-minded, be lifted up with pride, be proud."}, "G5188": {"greek": "τύφω", "translit": "týphō", "pronunciation": "too'-fo", "derivation": "apparently a primary verb;", "definition": "to make a smoke, i.e. slowly consume without flame", "kjv": "smoke."}, "G5189": {"greek": "τυφωνικός", "translit": "typhōnikós", "pronunciation": "too-fo-nee-kos'", "derivation": "from a derivative of (G5188);", "definition": "stormy (as if smoky)", "kjv": "tempestuous."}, "G5190": {"greek": "Τυχικός", "translit": "Tychikós", "pronunciation": "too-khee-kos'", "derivation": "from a derivative of (G5177);", "definition": "fortuitous, i.e. fortunate; Tychicus, a Christian", "kjv": "Tychicus."}, "G5191": {"greek": "ὑακίνθινος", "translit": "hyakínthinos", "pronunciation": "hoo-ak-in'-thee-nos", "derivation": "from (G5192);", "definition": "\"hyacinthine\" or \"jacinthine\", i.e. deep blue", "kjv": "jacinth."}, "G5192": {"greek": "ὑάκινθος", "translit": "hyákinthos", "pronunciation": "hoo-ak'-in-thos", "derivation": "of uncertain derivation;", "definition": "the \"hyacinth\" or \"jacinth\", i.e. some gem of a deep blue color, probably the zirkon", "kjv": "jacinth."}, "G5193": {"greek": "ὑάλινος", "translit": "hyálinos", "pronunciation": "hoo-al'-ee-nos", "derivation": "from (G5194);", "definition": "glassy, i.e. transparent", "kjv": "of glass."}, "G5194": {"greek": "ὕαλος", "translit": "hýalos", "pronunciation": "hoo'-al-os", "derivation": "perhaps from the same as (G5205) (as being transparent like rain);", "definition": "glass", "kjv": "glass."}, "G5195": {"greek": "ὑβρίζω", "translit": "hybrízō", "pronunciation": "hoo-brid'-zo", "derivation": "from (G5196);", "definition": "to exercise violence, i.e. abuse", "kjv": "use despitefully, reproach, entreat shamefully (spitefully)."}, "G5196": {"greek": "ὕβρις", "translit": "hýbris", "pronunciation": "hoo'-bris", "derivation": "from (G5228);", "definition": "insolence (as over-bearing), i.e. insult, injury", "kjv": "harm, hurt, reproach."}, "G5197": {"greek": "ὑβριστής", "translit": "hybristḗs", "pronunciation": "hoo-bris-tace'", "derivation": "from (G5195);", "definition": "an insulter, i.e. maltreater", "kjv": "despiteful, injurious."}, "G5198": {"greek": "ὑγιαίνω", "translit": "hygiaínō", "pronunciation": "hoog-ee-ah'-ee-no", "derivation": "from (G5199);", "definition": "to have sound health, i.e. be well (in body); figuratively, to be uncorrupt (true in doctrine)", "kjv": "be in health, (be safe and) sound, (be) whole(-some)."}, "G5199": {"greek": "ὑγιής", "translit": "hygiḗs", "pronunciation": "hoog-ee-ace'", "derivation": "from the base of (G837);", "definition": "healthy, i.e. well (in body); figuratively, true (in doctrine)", "kjv": "sound, whole."}, "G5200": {"greek": "ὑγρός", "translit": "hygrós", "pronunciation": "hoo-gros'", "derivation": "from the base of (G5205);", "definition": "wet (as if with rain), i.e. (by implication) sappy (fresh)", "kjv": "green."}, "G5201": {"greek": "ὑδρία", "translit": "hydría", "pronunciation": "hoo-dree-ah'", "derivation": "from (G5204);", "definition": "a water-jar, i.e. receptacle for family supply", "kjv": "water-pot."}, "G5202": {"greek": "ὑδροποτέω", "translit": "hydropotéō", "pronunciation": "hoo-drop-ot-eh'-o", "derivation": "from a compound of (G5204) and a derivative of (G4095);", "definition": "to be a water-drinker, i.e. to abstain from vinous beverages", "kjv": "drink water."}, "G5203": {"greek": "ὑδρωπικός", "translit": "hydrōpikós", "pronunciation": "hoo-dro-pik-os'", "derivation": "from a compound of (G5204) and a derivative of (G3700) (as if looking watery);", "definition": "to be \"dropsical\"", "kjv": "have the dropsy."}, "G5204": {"greek": "ὕδωρ", "translit": "hýdōr", "pronunciation": "hoo'-dore", "derivation": "from the base of (G5205);", "definition": "water (as if rainy) literally or figuratively", "kjv": "water."}, "G5205": {"greek": "ὑετός", "translit": "hyetós", "pronunciation": "hoo-et-os'", "derivation": "from a primary (to rain);", "definition": "rain, especially a shower", "kjv": "rain."}, "G5206": {"greek": "υἱοθεσία", "translit": "huiothesía", "pronunciation": "hwee-oth-es-ee'-ah", "derivation": "from a presumed compound of (G5207) and a derivative of (G5087);", "definition": "the placing as a son, i.e. adoption (figuratively, Christian sonship in respect to God)", "kjv": "adoption (of children, of sons)."}, "G5207": {"greek": "υἱός", "translit": "huiós", "pronunciation": "hwee-os'", "derivation": "apparently a primary word;", "definition": "a \"son\" (sometimes of animals), used very widely of immediate, remote or figuratively, kinship", "kjv": "child, foal, son."}, "G5208": {"greek": "ὕλη", "translit": "hýlē", "pronunciation": "hoo-lay'", "derivation": "perhaps akin to (G3586);", "definition": "a forest, i.e. (by implication) fuel", "kjv": "matter."}, "G5209": {"greek": "ὑμᾶς", "translit": "hymâs", "pronunciation": "hoo-mas'", "derivation": "accusative case of (G5210);", "definition": "you (as the objective of a verb or preposition)", "kjv": "ye, you (+ -ward), your (+ own)."}, "G5210": {"greek": "ὑμεῖς", "translit": "hymeîs", "pronunciation": "hoo-mice'", "derivation": "irregular plural of (G4771);", "definition": "you (as subjective of verb)", "kjv": "ye (yourselves), you."}, "G5211": {"greek": "Ὑμεναῖος", "translit": "Hymenaîos", "pronunciation": "hoo-men-ah'-yos", "derivation": "from (the god of weddings);", "definition": "\"hymenæal\"; Hymenæus, an opponent of Christianity", "kjv": "Hymenæus."}, "G5212": {"greek": "ὑμέτερος", "translit": "hyméteros", "pronunciation": "hoo-met'-er-os", "derivation": "from (G5210);", "definition": "yours, i.e. pertaining to you", "kjv": "your (own)."}, "G5213": {"greek": "ὑμῖν", "translit": "hymîn", "pronunciation": "hoo-min'", "derivation": "irregular dative case of (G5210);", "definition": "to (with or by) you", "kjv": "ye, you, your(-selves)."}, "G5214": {"greek": "ὑμνέω", "translit": "hymnéō", "pronunciation": "hoom-neh'-o", "derivation": "from (G5215);", "definition": "to hymn, i.e. sing a religious ode; by implication, to celebrate (God) in song", "kjv": "sing a hymn (praise unto)."}, "G5215": {"greek": "ὕμνος", "translit": "hýmnos", "pronunciation": "hoom'-nos", "derivation": "apparently from a simpler (obsolete) form of (to celebrate; probably akin to (G103); compare (G5667));", "definition": "a \"hymn\" or religious ode (one of the Psalms)", "kjv": "hymn."}, "G5216": {"greek": "ὑμῶν", "translit": "hymōn", "pronunciation": "hoo-mone'", "derivation": "genitive case of (G5210);", "definition": "of (from or concerning) you", "kjv": "ye, you, your (own, -selves)."}, "G5217": {"greek": "ὑπάγω", "translit": "hypágō", "pronunciation": "hoop-ag'-o", "derivation": "from (G5259) and (G71);", "definition": "to lead (oneself) under, i.e. withdraw or retire (as if sinking out of sight), literally or figuratively", "kjv": "depart, get hence, go (a-)way."}, "G5218": {"greek": "ὑπακοή", "translit": "hypakoḗ", "pronunciation": "hoop-ak-o-ay'", "derivation": "from (G5219);", "definition": "attentive hearkening, i.e. (by implication) compliance or submission", "kjv": "obedience, (make) obedient, obey(-ing)."}, "G5219": {"greek": "ὑπακούω", "translit": "hypakoúō", "pronunciation": "hoop-ak-oo'-o", "derivation": "from (G5259) and (G191);", "definition": "to hear under (as a subordinate), i.e. to listen attentively; by implication, to heed or conform to a command or authority", "kjv": "hearken, be obedient to, obey."}, "G5220": {"greek": "ὕπανδρος", "translit": "hýpandros", "pronunciation": "hoop'-an-dros", "derivation": "from (G5259) and (G435);", "definition": "in subjection under a man, i.e. a married woman", "kjv": "which hath an husband."}, "G5221": {"greek": "ὑπαντάω", "translit": "hypantáō", "pronunciation": "hoop-an-tah'-o", "derivation": "from (G5259) and a derivative of (G473);", "definition": "to go opposite (meet) under (quietly), i.e. to encounter, fall in with", "kjv": "(go to) meet."}, "G5222": {"greek": "ὑπάντησις", "translit": "hypántēsis", "pronunciation": "hoop-an'-tay-sis", "derivation": "from (G5221);", "definition": "an encounter or concurrence (with (G1519) for infinitive, in order to fall in with)", "kjv": "meeting."}, "G5223": {"greek": "ὕπαρξις", "translit": "hýparxis", "pronunciation": "hoop'-arx-is", "derivation": "from (G5225);", "definition": "existency or proprietorship, i.e. (concretely) property, wealth", "kjv": "goods, substance."}, "G5225": {"greek": "ὑπάρχω", "translit": "hypárchō", "pronunciation": "hoop-ar'-kho", "derivation": "from (G5259) and (G756);", "definition": "to begin under (quietly), i.e. come into existence (be present or at hand); expletively, to exist (as copula or subordinate to an adjective, participle, adverb or preposition, or as an auxiliary to a principal (verb)", "kjv": "after, behave, live."}, "G5226": {"greek": "ὑπείκω", "translit": "hypeíkō", "pronunciation": "hoop-i'-ko", "derivation": "from (G5259) and (to yield, be \"weak\");", "definition": "to surrender", "kjv": "submit self."}, "G5227": {"greek": "ὑπεναντίος", "translit": "hypenantíos", "pronunciation": "hoop-en-an-tee'-os", "derivation": "from (G5259) and (G1727);", "definition": "under (covertly) contrary to, i.e. opposed or (as noun) an opponent", "kjv": "adversary, against."}, "G5228": {"greek": "ὑπέρ", "translit": "hypér", "pronunciation": "hoop-er'", "derivation": "a primary preposition;", "definition": "\"over\", i.e. (with the genitive case) of place, above, beyond, across, or causal, for the sake of, instead, regarding; with the accusative case superior to, more than", "kjv": "(+ exceeding, abundantly) above, in (on) behalf of, beyond, by, + very chiefest, concerning, exceeding (above, -ly), for, + very highly, more (than), of, over, on the part of, for sake of, in stead, than, to(-ward), very."}, "G5229": {"greek": "ὑπεραίρομαι", "translit": "hyperaíromai", "pronunciation": "hoop-er-ah'-ee-rom-ahee", "derivation": "middle voice from (G5228) and (G142);", "definition": "to raise oneself over, i.e. (figuratively) to become haughty", "kjv": "exalt self, be exalted above measure."}, "G5230": {"greek": "ὑπέρακμος", "translit": "hypérakmos", "pronunciation": "hoop-er'-ak-mos", "derivation": "from (G5228) and the base of (G188);", "definition": "beyond the \"acme\", i.e. figuratively (of a daughter) past the bloom (prime) of youth", "kjv": "+ pass the flower of (her) age."}, "G5231": {"greek": "ὑπεράνω", "translit": "hyperánō", "pronunciation": "hoop-er-an'-o", "derivation": "from (G5228) and (G507);", "definition": "above upward, i.e. greatly higher (in place or rank)", "kjv": "far above, over."}, "G5232": {"greek": "ὑπεραυξάνω", "translit": "hyperauxánō", "pronunciation": "hoop-er-owx-an'-o", "derivation": "from (G5228) and (G837);", "definition": "to increase above ordinary degree", "kjv": "grow exceedingly."}, "G5233": {"greek": "ὑπερβαίνω", "translit": "hyperbaínō", "pronunciation": "hoop-er-bah'-ee-no", "derivation": "from (G5228) and the base of (G939);", "definition": "to transcend, i.e. (figuratively) to overreach", "kjv": "go beyond."}, "G5234": {"greek": "ὑπερβαλλόντως", "translit": "hyperballóntōs", "pronunciation": "hoop-er-bal-lon'-toce", "derivation": "adverb from present participle active of (G5235);", "definition": "excessively", "kjv": "beyond measure."}, "G5235": {"greek": "ὑπερβάλλω", "translit": "hyperbállō", "pronunciation": "hoop-er-bal'-lo", "derivation": "from (G5228) and (G906);", "definition": "to throw beyod the usual mark, i.e. (figuratively) to surpass (only active participle supereminent)", "kjv": "exceeding, excel, pass."}, "G5236": {"greek": "ὑπερβολή", "translit": "hyperbolḗ", "pronunciation": "hoop-er-bol-ay'", "derivation": "from (G5235);", "definition": "a throwing beyond others, i.e. (figuratively) supereminence; adverbially (with (G1519) or (G2596)) pre- eminently", "kjv": "abundance, (far more) exceeding, excellency, more excellent, beyond (out of) measure."}, "G5237": {"greek": "ὑπερείδω", "translit": "hypereídō", "pronunciation": "hoop-er-i'-do", "derivation": "from (G5228) and (G1492);", "definition": "to overlook, i.e. not punish", "kjv": "wink at."}, "G5238": {"greek": "ὑπερέκεινα", "translit": "hyperékeina", "pronunciation": "hoop-er-ek'-i-nah", "derivation": "from (G5228) and the neuter plural of (G1565);", "definition": "above those parts, i.e. still farther", "kjv": "beyond."}, "G5239": {"greek": "ὑπερεκτείνω", "translit": "hyperekteínō", "pronunciation": "hoop-er-ek-ti'-no", "derivation": "from (G5228) and (G1614);", "definition": "to extend inordinately", "kjv": "stretch beyond."}, "G5240": {"greek": "ὑπερεκχύνω", "translit": "hyperekchýnō", "pronunciation": "hoop-er-ek-khoo'-no", "derivation": "from (G5228) and the alternate form of (G1632);", "definition": "to pour out over, i.e. (passively) to overflow", "kjv": "run over."}, "G5241": {"greek": "ὑπερεντυγχάνω", "translit": "hyperentynchánō", "pronunciation": "hoop-er-en-toong-khan'-o", "derivation": "from (G5228) and (G1793);", "definition": "to intercede in behalf of", "kjv": "make intercession for."}, "G5242": {"greek": "ὑπερέχω", "translit": "hyperéchō", "pronunciation": "hoop-er-ekh'-o", "derivation": "from (G5228) and (G2192);", "definition": "to hold oneself above, i.e. (figuratively) to excel; participle (as adjective, or neuter as noun) superior, superiority", "kjv": "better, excellency, higher, pass, supreme."}, "G5243": {"greek": "ὑπερηφανία", "translit": "hyperēphanía", "pronunciation": "hoop-er-ay-fan-ee'-ah", "derivation": "from (G5244);", "definition": "haughtiness", "kjv": "pride."}, "G5244": {"greek": "ὑπερήφανος", "translit": "hyperḗphanos", "pronunciation": "hoop-er-ay'-fan-os", "derivation": "from (G5228) and (G5316);", "definition": "appearing above others (conspicuous), i.e. (figuratively) haughty", "kjv": "proud."}, "G5245": {"greek": "ὑπερνικάω", "translit": "hypernikáō", "pronunciation": "hoop-er-nik-ah'-o", "derivation": "from (G5228) and (G3528);", "definition": "to vanquish beyond, i.e. gain a decisive victory", "kjv": "more than conquer."}, "G5246": {"greek": "ὑπέρογκος", "translit": "hypéronkos", "pronunciation": "hoop-er'-ong-kos", "derivation": "from (G5228) and (G3591);", "definition": "bulging over, i.e. (figuratively) insolent", "kjv": "great swelling."}, "G5247": {"greek": "ὑπεροχή", "translit": "hyperochḗ", "pronunciation": "hoop-er-okh-ay'", "derivation": "from (G5242);", "definition": "prominence, i.e. (figuratively) superiority (in rank or character)", "kjv": "authority, excellency."}, "G5248": {"greek": "ὑπερπερισσεύω", "translit": "hyperperisseúō", "pronunciation": "hoop-er-per-is-syoo'-o", "derivation": "from (G5228) and (G4052);", "definition": "to super-abound", "kjv": "abound much more, exceeding."}, "G5249": {"greek": "ὑπερπερισσῶς", "translit": "hyperperissōs", "pronunciation": "hoop-er-per-is-soce'", "derivation": "from (G5228) and (G4057);", "definition": "superabundantly, i.e. exceedingly", "kjv": "beyond measure."}, "G5250": {"greek": "ὑπερπλεονάζω", "translit": "hyperpleonázō", "pronunciation": "hoop-er-pleh-on-ad'-zo", "derivation": "from (G5228) and (G4121);", "definition": "to superabound", "kjv": "be exceeding abundant."}, "G5251": {"greek": "ὑπερυψόω", "translit": "hyperypsóō", "pronunciation": "hoop-er-oop-so'-o", "derivation": "from (G5228) and (G5312);", "definition": "to elevate above others, i.e. raise to the highest position", "kjv": "highly exalt."}, "G5252": {"greek": "ὑπερφρονέω", "translit": "hyperphronéō", "pronunciation": "hoop-er-fron-eh'-o", "derivation": "from (G5228) and (G5426);", "definition": "to esteem oneself overmuch, i.e. be vain or arrogant", "kjv": "think more highly."}, "G5253": {"greek": "ὑπερῷον", "translit": "hyperōion", "pronunciation": "hoop-er-o'-on", "derivation": "neuter of a derivative of (G5228);", "definition": "a higher part of the house, i.e. apartment in the third story", "kjv": "upper chamber (room)."}, "G5254": {"greek": "ὑπέχω", "translit": "hypéchō", "pronunciation": "hoop-ekh'-o", "derivation": "from (G5259) and (G2192);", "definition": "to hold oneself under, i.e. endure with patience", "kjv": "suffer."}, "G5255": {"greek": "ὑπήκοος", "translit": "hypḗkoos", "pronunciation": "hoop-ay'-ko-os", "derivation": "from (G5219);", "definition": "attentively listening, i.e. (by implication) submissive", "kjv": "obedient."}, "G5256": {"greek": "ὑπηρετέω", "translit": "hypēretéō", "pronunciation": "hoop-ay-ret-eh'-o", "derivation": "from (G5257);", "definition": "to be a subordinate, i.e. (by implication) subserve", "kjv": "minister (unto), serve."}, "G5257": {"greek": "ὑπηρέτης", "translit": "hypērétēs", "pronunciation": "hoop-ay-ret'-ace", "derivation": "from (G5259) and a derivative of (to row);", "definition": "an under-oarsman, i.e. (generally) subordinate (assistant, sexton, constable)", "kjv": "minister, officer, servant."}, "G5258": {"greek": "ὕπνος", "translit": "hýpnos", "pronunciation": "hoop'-nos", "derivation": "from an obsolete primary (perhaps akin to (G5259) through the idea of subsilience);", "definition": "sleep, i.e. (figuratively) spiritual torpor", "kjv": "sleep."}, "G5259": {"greek": "ὑπό", "translit": "hypó", "pronunciation": "hoop-o'", "derivation": "a primary preposition;", "definition": "under, i.e. (with the genitive case) of place (beneath), or with verbs (the agency or means, through); (with the accusative case) of place (whither (underneath) or where (below) or time (when (at))", "kjv": "among, by, from, in, of, under, with."}, "G5260": {"greek": "ὑποβάλλω", "translit": "hypobállō", "pronunciation": "hoop-ob-al'-lo", "derivation": "from (G5259) and (G906);", "definition": "to throw in stealthily, i.e. introduce by collusion", "kjv": "suborn."}, "G5261": {"greek": "ὑπογραμμός", "translit": "hypogrammós", "pronunciation": "hoop-og-ram-mos'", "derivation": "from a compound of (G5259) and (G1125);", "definition": "an underwriting, i.e. copy for imitation (figuratively)", "kjv": "example."}, "G5262": {"greek": "ὑπόδειγμα", "translit": "hypódeigma", "pronunciation": "hoop-od'-igue-mah", "derivation": "from (G5263);", "definition": "an exhibit for imitation or warning (figuratively, specimen, adumbration)", "kjv": "en-(ex-)ample, pattern."}, "G5263": {"greek": "ὑποδείκνυμι", "translit": "hypodeíknymi", "pronunciation": "hoop-od-ike'-noo-mee", "derivation": "from (G5259) and (G1166);", "definition": "to exhibit under the eyes, i.e. (figuratively) to exemplify (instruct, admonish)", "kjv": "show, (fore-)warn."}, "G5264": {"greek": "ὑποδέχομαι", "translit": "hypodéchomai", "pronunciation": "hoop-od-ekh'-om-ahee", "derivation": "from (G5259) and (G1209);", "definition": "to admit under one's roof, i.e. entertain hospitably", "kjv": "receive."}, "G5265": {"greek": "ὑποδέω", "translit": "hypodéō", "pronunciation": "hoop-od-eh'-o", "derivation": "from (G5259) and (G1210);", "definition": "to bind under one's feet, i.e. put on shoes or sandals", "kjv": "bind on, (be) shod."}, "G5266": {"greek": "ὑπόδημα", "translit": "hypódēma", "pronunciation": "hoop-od'-ay-mah", "derivation": "from (G5265);", "definition": "something bound under the feet, i.e. a shoe or sandal", "kjv": "shoe."}, "G5267": {"greek": "ὑπόδικος", "translit": "hypódikos", "pronunciation": "hoop-od'-ee-kos", "derivation": "from (G5259) and (G1349);", "definition": "under sentence, i.e. (by implication) condemned", "kjv": "guilty."}, "G5268": {"greek": "ὑποζύγιον", "translit": "hypozýgion", "pronunciation": "hoop-od-zoog'-ee-on", "derivation": "neuter of a compound of (G5259) and (G2218);", "definition": "an animal under the yoke (draught-beast), i.e. (specially), a donkey", "kjv": "ass."}, "G5269": {"greek": "ὑποζώννυμι", "translit": "hypozṓnnymi", "pronunciation": "hoop-od-zone'-noo-mee", "derivation": "from (G5259) and (G2224);", "definition": "to gird under, i.e. frap (a vessel with cables across the keel, sides and deck)", "kjv": "undergirt."}, "G5270": {"greek": "ὑποκάτω", "translit": "hypokátō", "pronunciation": "hoop-ok-at'-o", "derivation": "from (G5259) and (G2736);", "definition": "down under, i.e. beneath", "kjv": "under."}, "G5271": {"greek": "ὑποκρίνομαι", "translit": "hypokrínomai", "pronunciation": "hoop-ok-rin'-om-ahee", "derivation": "middle voice from (G5259) and (G2919);", "definition": "to decide (speak or act) under a false part, i.e. (figuratively) dissemble (pretend)", "kjv": "feign."}, "G5272": {"greek": "ὑπόκρισις", "translit": "hypókrisis", "pronunciation": "hoop-ok'-ree-sis", "derivation": "from (G5271);", "definition": "acting under a feigned part, i.e. (figuratively) deceit (\"hypocrisy\")", "kjv": "condemnation, dissimulation, hypocrisy."}, "G5273": {"greek": "ὑποκριτής", "translit": "hypokritḗs", "pronunciation": "hoop-ok-ree-tace'", "derivation": "from (G5271);", "definition": "an actor under an assumed character (stage-player), i.e. (figuratively) a dissembler (\"hypocrite\"", "kjv": "hypocrite."}, "G5274": {"greek": "ὑπολαμβάνω", "translit": "hypolambánō", "pronunciation": "hoop-ol-am-ban'-o", "derivation": "from (G5259) and (G2983);", "definition": "to take from below, i.e. carry upward; figuratively, to take up, i.e. continue a discourse or topic; mentally, to assume (presume)", "kjv": "answer, receive, suppose."}, "G5275": {"greek": "ὑπολείπω", "translit": "hypoleípō", "pronunciation": "hoop-ol-i'-po", "derivation": "from (G5295) and (G3007);", "definition": "to leave under (behind), i.e. (passively) to remain (survive)", "kjv": "be left."}, "G5276": {"greek": "ὑπολήνιον", "translit": "hypolḗnion", "pronunciation": "hoop-ol-ay'-nee-on", "derivation": "neuter of a presumed compound of (G5259) and (G3025);", "definition": "vessel or receptacle under the press, i.e. lower wine-vat", "kjv": "winefat."}, "G5277": {"greek": "ὑπολιμπάνω", "translit": "hypolimpánō", "pronunciation": "hoop-ol-im-pan'-o", "derivation": "a prolonged form for (G5275);", "definition": "to leave behind, i.e. bequeath", "kjv": "leave."}, "G5278": {"greek": "ὑπομένω", "translit": "hypoménō", "pronunciation": "hoop-om-en'-o", "derivation": "from (G5259) and (G3306);", "definition": "to stay under (behind), i.e. remain; figuratively, to undergo, i.e. bear (trials), have fortitude, persevere", "kjv": "abide, endure, (take) patient(-ly), suffer, tarry behind."}, "G5279": {"greek": "ὑπομιμνήσκω", "translit": "hypomimnḗskō", "pronunciation": "hoop-om-im-nace'-ko", "derivation": "from (G5259) and (G3403);", "definition": "to remind quietly, i.e. suggest to the (middle voice, one's own) memory", "kjv": "put in mind, remember, bring to (put in) remembrance."}, "G5280": {"greek": "ὑπόμνησις", "translit": "hypómnēsis", "pronunciation": "hoop-om'-nay-sis", "derivation": "from (G5279);", "definition": "a reminding or (reflexively) recollection", "kjv": "remembrance."}, "G5281": {"greek": "ὑπομονή", "translit": "hypomonḗ", "pronunciation": "hoop-om-on-ay'", "derivation": "from (G5278);", "definition": "cheerful (or hopeful) endurance, constancy", "kjv": "enduring, patience, patient continuance (waiting)."}, "G5282": {"greek": "ὑπονοέω", "translit": "hyponoéō", "pronunciation": "hoop-on-o-eh'-o", "derivation": "from (G5259) and (G3539);", "definition": "to think under (privately), i.e. to surmise or conjecture", "kjv": "think, suppose, deem."}, "G5283": {"greek": "ὑπόνοια", "translit": "hypónoia", "pronunciation": "hoop-on'-oy-ah", "derivation": "from (G5282);", "definition": "suspicion", "kjv": "surmising."}, "G5284": {"greek": "ὑποπλέω", "translit": "hypopléō", "pronunciation": "hoop-op-leh'-o", "derivation": "from (G5259) and (G4126);", "definition": "to sail under the lee of", "kjv": "sail under."}, "G5285": {"greek": "ὑποπνέω", "translit": "hypopnéō", "pronunciation": "hoop-op-neh'-o", "derivation": "from (G5259) and (G4154);", "definition": "to breathe gently, i.e. breeze", "kjv": "blow softly."}, "G5286": {"greek": "ὑποπόδιον", "translit": "hypopódion", "pronunciation": "hoop-op-od'-ee-on", "derivation": "neuter of a compound of (G5259) and (G4228);", "definition": "something under the feet, i.e. a foot-rest (figuratively)", "kjv": "footstool."}, "G5287": {"greek": "ὑπόστασις", "translit": "hypóstasis", "pronunciation": "hoop-os'-tas-is", "derivation": "from a compound of (G5259) and (G2476);", "definition": "a setting under (support), i.e. (figuratively) concretely, essence, or abstractly, assurance (objectively or subjectively)", "kjv": "confidence, confident, person, substance."}, "G5288": {"greek": "ὑποστέλλω", "translit": "hypostéllō", "pronunciation": "hoop-os-tel'-lo", "derivation": "from (G5259) and (G4724);", "definition": "to withhold under (out of sight), i.e. (reflexively) to cower or shrink, (figuratively) to conceal (reserve)", "kjv": "draw (keep) back, shun, withdraw."}, "G5289": {"greek": "ὑποστολή", "translit": "hypostolḗ", "pronunciation": "hoop-os-tol-ay'", "derivation": "from (G5288);", "definition": "shrinkage (timidity), i.e. (by implication) apostasy", "kjv": "draw back."}, "G5290": {"greek": "ὑποστρέφω", "translit": "hypostréphō", "pronunciation": "hoop-os-tref'-o", "derivation": "from (G5259) and (G4762);", "definition": "to turn under (behind), i.e. to return (literally or figuratively)", "kjv": "come again, return (again, back again), turn back (again)."}, "G5291": {"greek": "ὑποστρώννυμι", "translit": "hypostrṓnnymi", "pronunciation": "hoop-os-trone'-noo-mee", "derivation": "from (G5259) and (G4766);", "definition": "to strew underneath (the feet as a carpet)", "kjv": "spread."}, "G5293": {"greek": "ὑποτάσσω", "translit": "hypotássō", "pronunciation": "hoop-ot-as'-so", "derivation": "from (G5259) and (G5021);", "definition": "to subordinate; reflexively, to obey", "kjv": "be under obedience (obedient), put under, subdue unto, (be, make) subject (to, unto), be (put) in subjection (to, under), submit self unto."}, "G5294": {"greek": "ὑποτίθημι", "translit": "hypotíthēmi", "pronunciation": "hoop-ot-ith'-ay-mee", "derivation": "from (G5259) and (G5087);", "definition": "to place underneath, i.e. (figuratively) to hazard, (reflexively) to suggest", "kjv": "lay down, put in remembrance."}, "G5295": {"greek": "ὑποτρέχω", "translit": "hypotréchō", "pronunciation": "hoop-ot-rekh'-o", "derivation": "from (G5259) and (G5143) (including its alternate);", "definition": "to run under, i.e. (specially), to sail past", "kjv": "run under."}, "G5296": {"greek": "ὑποτύπωσις", "translit": "hypotýpōsis", "pronunciation": "hoop-ot-oop'-o-sis", "derivation": "from a compound of (G5259) and a derivative of (G5179);", "definition": "typification under (after), i.e. (concretely) a sketch (figuratively) for imitation", "kjv": "form, pattern."}, "G5297": {"greek": "ὑποφέρω", "translit": "hypophérō", "pronunciation": "hoop-of-er'-o", "derivation": "from (G5259) and (G5342);", "definition": "to bear from underneath, i.e. (figuratively) to undergo hardship", "kjv": "bear, endure."}, "G5298": {"greek": "ὑποχωρέω", "translit": "hypochōréō", "pronunciation": "hoop-okh-o-reh'-o", "derivation": "from (G5259) and (G5562);", "definition": "to vacate down, i.e. retire quietly", "kjv": "go aside, withdraw self."}, "G5299": {"greek": "ὑπωπιάζω", "translit": "hypōpiázō", "pronunciation": "hoop-o-pee-ad'-zo", "derivation": "from a compound of (G5259) and a derivative of (G3700);", "definition": "to hit under the eye (buffet or disable an antagonist as a pugilist), i.e. (figuratively) to tease or annoy (into compliance), subdue (one's passions)", "kjv": "keep under, weary."}, "G5300": {"greek": "ὗς", "translit": "hŷs", "pronunciation": "hoos", "derivation": "apparently a primary word;", "definition": "a hog (\"swine\")", "kjv": "sow."}, "G5301": {"greek": "ὕσσωπος", "translit": "hýssōpos", "pronunciation": "hoos'-so-pos", "derivation": "of foreign origin ((G231));", "definition": "\"hyssop\"", "kjv": "hyssop."}, "G5302": {"greek": "ὑστερέω", "translit": "hysteréō", "pronunciation": "hoos-ter-eh'-o", "derivation": "from (G5306);", "definition": "to be later, i.e. (by implication) to be inferior; generally, to fall short (be deficient)", "kjv": "come behind (short), be destitute, fail, lack, suffer need, (be in) want, be the worse."}, "G5303": {"greek": "ὑστέρημα", "translit": "hystérēma", "pronunciation": "hoos-ter'-ay-mah", "derivation": "from (G5302);", "definition": "a deficit; specially, poverty", "kjv": "that which is behind, (that which was) lack(-ing), penury, want."}, "G5304": {"greek": "ὑστέρησις", "translit": "hystérēsis", "pronunciation": "hoos-ter'-ay-sis", "derivation": "from (G5302);", "definition": "a falling short, i.e. (specially), penury", "kjv": "want."}, "G5305": {"greek": "ὕστερον", "translit": "hýsteron", "pronunciation": "hoos'-ter-on", "derivation": "neuter of (G5306) as adverb;", "definition": "more lately, i.e. eventually", "kjv": "afterward, (at the) last (of all)."}, "G5306": {"greek": "ὕστερος", "translit": "hýsteros", "pronunciation": "hoos'-ter-os", "derivation": "comparative from (G5259) (in the sense of behind);", "definition": "later", "kjv": "latter."}, "G5307": {"greek": "ὑφαντός", "translit": "hyphantós", "pronunciation": "hoo-fan-tos'", "derivation": "from to weave;", "definition": "woven, i.e. (perhaps) knitted", "kjv": "woven."}, "G5308": {"greek": "ὑψηλός", "translit": "hypsēlós", "pronunciation": "hoop-say-los'", "derivation": "from (G5311);", "definition": "lofty (in place or character)", "kjv": "high(-er, -ly) (esteemed)."}, "G5309": {"greek": "ὑψηλοφρονέω", "translit": "hypsēlophronéō", "pronunciation": "hoop-say-lo-fron-eh'-o", "derivation": "from a compound of (G5308) and (G5424);", "definition": "to be lofty in mind, i.e. arrogant", "kjv": "be highminded."}, "G5310": {"greek": "ὕψιστος", "translit": "hýpsistos", "pronunciation": "hoop'-sis-tos", "derivation": "superlative from the base of (G5311);", "definition": "highest, i.e. (masculine singular) the Supreme (God), or (neuter plural) the heavens", "kjv": "most high, highest."}, "G5311": {"greek": "ὕψος", "translit": "hýpsos", "pronunciation": "hoop'-sos", "derivation": "from a derivative of (G5228);", "definition": "elevation, i.e. (abstractly) altitude, (specially), the sky, or (figuratively) dignity", "kjv": "be exalted, height, (on) high."}, "G5312": {"greek": "ὑψόω", "translit": "hypsóō", "pronunciation": "hoop-so'-o", "derivation": "from (G5311);", "definition": "to elevate (literally or figuratively)", "kjv": "exalt, lift up."}, "G5313": {"greek": "ὕψωμα", "translit": "hýpsōma", "pronunciation": "hoop'-so-mah", "derivation": "from (G5312);", "definition": "an elevated place or thing, i.e. (abstractly) altitude, or (by implication) a barrier (figuratively)", "kjv": "height, high thing."}, "G5314": {"greek": "φάγος", "translit": "phágos", "pronunciation": "fag'-os", "derivation": "from (G5315);", "definition": "a glutton", "kjv": "gluttonous."}, "G5315": {"greek": "φάγω", "translit": "phágō", "pronunciation": "fag'-o", "derivation": "a primary verb (used as an alternate of (G2068) in certain tenses);", "definition": "to eat (literally or figuratively)", "kjv": "eat, meat."}, "G5316": {"greek": "φαίνω", "translit": "phaínō", "pronunciation": "fah'-ee-no", "derivation": "prolongation for the base of (G5457);", "definition": "to lighten (shine), i.e. show (transitive or intransitive, literal or figurative)", "kjv": "appear, seem, be seen, shine, X think."}, "G5317": {"greek": "Φάλεκ", "translit": "Phálek", "pronunciation": "fal'-ek", "derivation": "of Hebrew origin ((G6389));", "definition": "Phalek (i.e. Peleg), a patriarch", "kjv": "Phalec."}, "G5318": {"greek": "φανερός", "translit": "phanerós", "pronunciation": "fan-er-os'", "derivation": "from (G5316);", "definition": "shining, i.e. apparent (literally or figuratively); neuter (as adverb) publicly, externally", "kjv": "abroad, + appear, known, manifest, open (+ -ly), outward (+ -ly)."}, "G5319": {"greek": "φανερόω", "translit": "phaneróō", "pronunciation": "fan-er-o'-o", "derivation": "from (G5318);", "definition": "to render apparent (literally or figuratively)", "kjv": "appear, manifestly declare, (make) manifest (forth), shew (self)."}, "G5320": {"greek": "φανερῶς", "translit": "phanerōs", "pronunciation": "fan-er-oce'", "derivation": "adverb from (G5318);", "definition": "plainly, i.e. clearly or publicly", "kjv": "evidently, openly."}, "G5321": {"greek": "φανέρωσις", "translit": "phanérōsis", "pronunciation": "fan-er'-o-sis", "derivation": "from (G5319);", "definition": "exhibition, i.e. (figuratively) expression, (by extension) a bestowment", "kjv": "manifestation."}, "G5322": {"greek": "φανός", "translit": "phanós", "pronunciation": "fan-os'", "derivation": "from (G5316);", "definition": "a lightener, i.e. light; lantern", "kjv": "lantern."}, "G5323": {"greek": "Φανουήλ", "translit": "Phanouḗl", "pronunciation": "fan-oo-ale'", "derivation": "of Hebrew origin ((G6439));", "definition": "Phanuel (i.e. Penuel), an Israelite", "kjv": "Phanuel."}, "G5324": {"greek": "φαντάζω", "translit": "phantázō", "pronunciation": "fan-tad'-zo", "derivation": "from a derivative of (G5316);", "definition": "to make apparent, i.e. (passively) to appear (neuter participle as noun, a spectacle)", "kjv": "sight."}, "G5325": {"greek": "φαντασία", "translit": "phantasía", "pronunciation": "fan-tas-ee'-ah", "derivation": "from a derivative of (G5324);", "definition": "(properly abstract) a (vain) show (\"fantasy\")", "kjv": "pomp."}, "G5326": {"greek": "φάντασμα", "translit": "phántasma", "pronunciation": "fan'-tas-mah", "derivation": "from (G5324);", "definition": "(properly concrete) a (mere) show (\"phantasm\"), i.e. spectre", "kjv": "spirit."}, "G5327": {"greek": "φάραγξ", "translit": "pháranx", "pronunciation": "far'-anx", "derivation": "properly, strengthened from the base of (G4008) or rather of (G4486);", "definition": "a gap or chasm, i.e. ravine (winter-torrent)", "kjv": "valley."}, "G5328": {"greek": "Φαραώ", "translit": "Pharaṓ", "pronunciation": "far-ah-o'", "derivation": "of foreign origin ((G6547));", "definition": "Pharao (i.e. Pharoh), an Egyptian king", "kjv": "Pharaoh."}, "G5329": {"greek": "Φάρες", "translit": "Pháres", "pronunciation": "far-es'", "derivation": "of Hebrew origin ((G6557));", "definition": "Phares (i.e. Perets), an Israelite", "kjv": "Phares."}, "G5330": {"greek": "Φαρισαῖος", "translit": "Pharisaîos", "pronunciation": "far-is-ah'-yos", "derivation": "of Hebrew origin (compare (G6567));", "definition": "a separatist, i.e. exclusively religious; a Pharisean, i.e. Jewish sectary", "kjv": "Pharisee."}, "G5331": {"greek": "φαρμακεία", "translit": "pharmakeía", "pronunciation": "far-mak-i'-ah", "derivation": "from (G5332);", "definition": "medication (\"pharmacy\"), i.e. (by extension) magic (literally or figuratively)", "kjv": "sorcery, witchcraft."}, "G5333": {"greek": "φάρμακος", "translit": "phármakos", "pronunciation": "far-mak-os'", "derivation": "the same as 5332", "definition": "", "kjv": "sorcerer."}, "G5334": {"greek": "φάσις", "translit": "phásis", "pronunciation": "fas'-is", "derivation": "from (G5346) (not the same as \"phase\", which is from (G5316));", "definition": "a saying, i.e. report", "kjv": "tidings."}, "G5335": {"greek": "φάσκω", "translit": "pháskō", "pronunciation": "fas'-ko", "derivation": "prolongation from the same as (G5346);", "definition": "to assert", "kjv": "affirm, profess, say."}, "G5336": {"greek": "φάτνη", "translit": "phátnē", "pronunciation": "fat'-nay", "derivation": "from (to eat);", "definition": "a crib (for fodder)", "kjv": "manager, stall."}, "G5337": {"greek": "φαῦλος", "translit": "phaûlos", "pronunciation": "fow'-los", "derivation": "apparently a primary word;", "definition": "\"foul\" or \"flawy\", i.e. (figuratively) wicked", "kjv": "evil."}, "G5338": {"greek": "φέγγος", "translit": "phéngos", "pronunciation": "feng'-gos", "derivation": "probably akin to the base of (G5457) (compare (G5350));", "definition": "brilliancy", "kjv": "light."}, "G5339": {"greek": "φείδομαι", "translit": "pheídomai", "pronunciation": "fi'-dom-ahee", "derivation": "of uncertain affinity;", "definition": "to be chary of, i.e. (subjectively) to abstain or (objectively) to treat leniently", "kjv": "forbear, spare."}, "G5340": {"greek": "φειδομένως", "translit": "pheidoménōs", "pronunciation": "fi-dom-en'-oce", "derivation": "adverb from participle of (G5339);", "definition": "abstemiously, i.e. stingily", "kjv": "sparingly."}, "G5341": {"greek": "φελόνης", "translit": "phelónēs", "pronunciation": "fel-on'-ace", "derivation": "by transposition for a derivative probably of (G5316) (as showing outside the other garments);", "definition": "a mantle (surtout)", "kjv": "cloke."}, "G5342": {"greek": "φέρω", "translit": "phérō", "pronunciation": "fer'-o", "derivation": "a primary verb (for which other, and apparently not cognate ones are used in certain tenses only; namely, ; and ;", "definition": "to \"bear\" or carry (in a very wide application, literally and figuratively, as follows)", "kjv": "be, bear, bring (forth), carry, come, + let her drive, be driven, endure, go on, lay, lead, move, reach, rushing, uphold."}, "G5343": {"greek": "φεύγω", "translit": "pheúgō", "pronunciation": "fyoo'-go", "derivation": "apparently a primary verb;", "definition": "to run away (literally or figuratively); by implication, to shun; by analogy, to vanish", "kjv": "escape, flee (away)."}, "G5344": {"greek": "Φῆλιξ", "translit": "Phēlix", "pronunciation": "fay'-lix", "derivation": "of Latin origin;", "definition": "happy; Phelix (i.e. Felix), a Roman", "kjv": "Felix."}, "G5345": {"greek": "φήμη", "translit": "phḗmē", "pronunciation": "fay'-may", "derivation": "from (G5346);", "definition": "a saying, i.e. rumor (\"fame\")", "kjv": "fame."}, "G5346": {"greek": "φημί", "translit": "phēmí", "pronunciation": "fay-mee'", "derivation": "properly, the same as the base of (G5457) and (G5316);", "definition": "to show or make known one's thoughts, i.e. speak or say", "kjv": "affirm, say."}, "G5347": {"greek": "Φῆστος", "translit": "Phēstos", "pronunciation": "face'-tos", "derivation": "of Latin derivation;", "definition": "festal; Phestus (i.e. Festus), a Roman", "kjv": "Festus."}, "G5348": {"greek": "φθάνω", "translit": "phthánō", "pronunciation": "fthan'-o", "derivation": "apparently a primary verb;", "definition": "to be beforehand, i.e. anticipate or precede; by extension, to have arrived at", "kjv": "(already) attain, come, prevent."}, "G5349": {"greek": "φθαρτός", "translit": "phthartós", "pronunciation": "fthar-tos'", "derivation": "from (G5351);", "definition": "decayed, i.e. (by implication) perishable", "kjv": "corruptible."}, "G5350": {"greek": "φθέγγομαι", "translit": "phthéngomai", "pronunciation": "ftheng'-gom-ahee", "derivation": "probably akin to (G5338) and thus to (G5346);", "definition": "to utter a clear sound, i.e. (generally) to proclaim", "kjv": "speak."}, "G5351": {"greek": "φθείρω", "translit": "phtheírō", "pronunciation": "fthi'-ro", "derivation": "probably strengthened from (to pine or waste);", "definition": "properly, to shrivel or wither, i.e. to spoil (by any process) or (generally) to ruin (especially figuratively, by moral influences, to deprave)", "kjv": "corrupt (self), defile, destroy."}, "G5352": {"greek": "φθινοπωρινός", "translit": "phthinopōrinós", "pronunciation": "fthin-op-o-ree-nos'", "derivation": "from derivative of (to wane; akin to the base of (G5351))", "definition": "and (G3703) (meaning late autumn); autumnal (as stripped of leaves)", "kjv": "whose fruit withereth."}, "G5353": {"greek": "φθόγγος", "translit": "phthóngos", "pronunciation": "ftong'-gos", "derivation": "from (G5350);", "definition": "utterance, i.e. a musical note (vocal or instrumental)", "kjv": "sound."}, "G5354": {"greek": "φθονέω", "translit": "phthonéō", "pronunciation": "fthon-eh'-o", "derivation": "from (G5355);", "definition": "to be jealous of", "kjv": "envy."}, "G5355": {"greek": "φθόνος", "translit": "phthónos", "pronunciation": "fthon'-os", "derivation": "probably akin to the base of (G5351);", "definition": "ill-will (as detraction), i.e. jealousy (spite)", "kjv": "envy."}, "G5356": {"greek": "φθορά", "translit": "phthorá", "pronunciation": "fthor-ah'", "derivation": "from (G5351);", "definition": "decay, i.e. ruin (spontaneous or inflicted, literally or figuratively)", "kjv": "corruption, destroy, perish."}, "G5357": {"greek": "φιάλη", "translit": "phiálē", "pronunciation": "fee-al'-ay", "derivation": "of uncertain affinity;", "definition": "a broad shallow cup (\"phial\")", "kjv": "vial."}, "G5358": {"greek": "φιλάγαθος", "translit": "philágathos", "pronunciation": "fil-ag'-ath-os", "derivation": "from (G5384) and (G18);", "definition": "fond to good, i.e. a promoter of virtue", "kjv": "love of good men."}, "G5359": {"greek": "Φιλαδέλφεια", "translit": "Philadélpheia", "pronunciation": "fil-ad-el'-fee-ah", "derivation": "from (the same as (G5361)), a king of Pergamos;", "definition": "Philadelphia, a place in Asia Minor", "kjv": "Philadelphia."}, "G5360": {"greek": "φιλαδελφία", "translit": "philadelphía", "pronunciation": "fil-ad-el-fee'-ah", "derivation": "from (G5361);", "definition": "fraternal affection", "kjv": "brotherly love (kindness), love of the brethren."}, "G5361": {"greek": "φιλάδελφος", "translit": "philádelphos", "pronunciation": "fil-ad'-el-fos", "derivation": "from (G5384) and (G80);", "definition": "fond of brethren, i.e. fraternal", "kjv": "love as brethren."}, "G5362": {"greek": "φίλανδρος", "translit": "phílandros", "pronunciation": "fil'-an-dros", "derivation": "from (G5384) and (G435);", "definition": "fond of man, i.e. affectionate as a wife", "kjv": "love their husbands."}, "G5363": {"greek": "φιλανθρωπία", "translit": "philanthrōpía", "pronunciation": "fil-an-thro-pee'-ah", "derivation": "from the same as (G5364);", "definition": "fondness of mankind, i.e. benevolence (\"philanthropy\")", "kjv": "kindness, love towards man."}, "G5364": {"greek": "φιλανθρώπως", "translit": "philanthrṓpōs", "pronunciation": "fil-an-thro'-poce", "derivation": "adverb from a compound of (G5384) and (G444);", "definition": "fondly to man (\"philanthropically\"), i.e. humanely", "kjv": "courteously."}, "G5365": {"greek": "φιλαργυρία", "translit": "philargyría", "pronunciation": "fil-ar-goo-ree'-ah", "derivation": "from (G5366);", "definition": "avarice", "kjv": "love of money."}, "G5366": {"greek": "φιλάργυρος", "translit": "philárgyros", "pronunciation": "fil-ar'-goo-ros", "derivation": "from (G5384) and (G696);", "definition": "fond of silver (money), i.e. avaricious", "kjv": "covetous."}, "G5367": {"greek": "φίλαυτος", "translit": "phílautos", "pronunciation": "fil'-ow-tos", "derivation": "from (G5384) and (G846);", "definition": "fond of self, i.e. selfish", "kjv": "lover of own self."}, "G5368": {"greek": "φιλέω", "translit": "philéō", "pronunciation": "fil-eh'-o", "derivation": "from (G5384);", "definition": "to be a friend to (fond of (an individual or an object)), i.e. have affection for (denoting personal attachment, as a matter of sentiment or feeling; while (G25) is wider, embracing especially the judgment and the deliberate assent of the will as a matter of principle, duty and propriety: the two thus stand related very much as (G2309) and (G1014), or as (G2372) and (G3563) respectively; the former being chiefly of the heart and the latter of the head); specially, to kiss (as a mark of tenderness)", "kjv": "kiss, love."}, "G5369": {"greek": "φιλήδονος", "translit": "philḗdonos", "pronunciation": "fil-ay'-don-os", "derivation": "from (G5384) and (G2237);", "definition": "fond of pleasure, i.e. voluptuous", "kjv": "lover of pleasure."}, "G5370": {"greek": "φίλημα", "translit": "phílēma", "pronunciation": "fil'-ay-mah", "derivation": "from (G5368);", "definition": "a kiss", "kjv": "kiss."}, "G5371": {"greek": "Φιλήμων", "translit": "Philḗmōn", "pronunciation": "fil-ay'-mone", "derivation": "from (G5368);", "definition": "friendly; Philemon, a Christian", "kjv": "Philemon."}, "G5372": {"greek": "Φίλητος", "translit": "Phílētos", "pronunciation": "fil-ay-tos'", "derivation": "from (G5368);", "definition": "amiable; Philetus, an opposer of Christianity", "kjv": "Philetus."}, "G5373": {"greek": "φιλία", "translit": "philía", "pronunciation": "fil-ee'-ah", "derivation": "from (G5384);", "definition": "fondness", "kjv": "friendship."}, "G5374": {"greek": "Φιλιππήσιος", "translit": "Philippḗsios", "pronunciation": "fil-ip-pay'-see-os", "derivation": "from (G5375);", "definition": "a Philippesian (Philippian), i.e. native of Philippi", "kjv": "Philippian."}, "G5375": {"greek": "Φίλιπποι", "translit": "Phílippoi", "pronunciation": "fil'-ip-poy", "derivation": "plural of (G5376);", "definition": "Philippi, a place in Macedonia", "kjv": "Philippi."}, "G5376": {"greek": "Φίλιππος", "translit": "Phílippos", "pronunciation": "fil'-ip-pos", "derivation": "from (G5384) and (G2462);", "definition": "fond of horses; Philippus, the name of four Israelites", "kjv": "Philip."}, "G5377": {"greek": "φιλόθεος", "translit": "philótheos", "pronunciation": "fil-oth'-eh-os", "derivation": "from (G5384) and (G2316);", "definition": "fond of God, i.e. pious", "kjv": "lover of God."}, "G5378": {"greek": "Φιλόλογος", "translit": "Philólogos", "pronunciation": "fil-ol'-og-os", "derivation": "from (G5384) and (G3056);", "definition": "fond of words, i.e. talkative (argumentative, learned, \"philological\"); Philologus, a Christian", "kjv": "Philologus."}, "G5379": {"greek": "φιλονεικία", "translit": "philoneikía", "pronunciation": "fil-on-i-kee'-ah", "derivation": "from (G5380);", "definition": "quarrelsomeness, i.e. a dispute", "kjv": "strife."}, "G5380": {"greek": "φιλόνεικος", "translit": "philóneikos", "pronunciation": "fil-on'-i-kos", "derivation": "from (G5384) and (a quarrel; probably akin to (G3534));", "definition": "fond of strife, i.e. disputatious", "kjv": "contentious."}, "G5381": {"greek": "φιλονεξία", "translit": "philonexía", "pronunciation": "fil-on-ex-ee'-ah", "derivation": "from (G5382);", "definition": "hospitableness", "kjv": "entertain stranger, hospitality."}, "G5382": {"greek": "φιλόξενος", "translit": "philóxenos", "pronunciation": "fil-ox'-en-os", "derivation": "from (G5384) and (G3581);", "definition": "fond of guests, i.e. hospitable", "kjv": "given to (lover of, use) hospitality."}, "G5383": {"greek": "φιλοπρωτεύω", "translit": "philoprōteúō", "pronunciation": "fil-op-rote-yoo'-o", "derivation": "from a compound of (G5384) and (G4413);", "definition": "to be fond of being first, i.e. ambitious of distinction", "kjv": "love to have the preeminence."}, "G5384": {"greek": "φίλος", "translit": "phílos", "pronunciation": "fee'-los", "derivation": "properly, dear, i.e. a friend;", "definition": "actively, fond, i.e. friendly (still as a noun, an associate, neighbor, etc.)", "kjv": "friend."}, "G5385": {"greek": "φιλοσοφία", "translit": "philosophía", "pronunciation": "fil-os-of-ee'-ah", "derivation": "from (G5386);", "definition": "\"philosophy\", i.e. (specially), Jewish sophistry", "kjv": "philosophy."}, "G5386": {"greek": "φιλόσοφος", "translit": "philósophos", "pronunciation": "fil-os'-of-os", "derivation": "from (G5384) and (G4680);", "definition": "fond of wise things, i.e. a \"philosopher\"", "kjv": "philosopher."}, "G5387": {"greek": "φιλόστοργος", "translit": "philóstorgos", "pronunciation": "fil-os'-tor-gos", "derivation": "from (G5384) and (cherishing one's kindred, especially parents or children);", "definition": "fond of natural relatives, i.e. fraternal towards fellow Christian", "kjv": "kindly affectioned."}, "G5388": {"greek": "φιλότεκνος", "translit": "philóteknos", "pronunciation": "fil-ot'-ek-nos", "derivation": "from (G5384) and (G5043);", "definition": "fond of one's children, i.e. maternal", "kjv": "love their children."}, "G5389": {"greek": "φιλοτιμέομαι", "translit": "philotiméomai", "pronunciation": "fil-ot-im-eh'-om-ahee", "derivation": "middle voice from a compound of (G5384) and (G5092);", "definition": "to be fond of honor, i.e. emulous (eager or earnest to do something)", "kjv": "labour, strive, study."}, "G5390": {"greek": "φιλοφρόνως", "translit": "philophrónōs", "pronunciation": "fil-of-ron'-oce", "derivation": "adverb from (G5391);", "definition": "with friendliness of mind, i.e. kindly", "kjv": "courteously."}, "G5392": {"greek": "φιμόω", "translit": "phimóō", "pronunciation": "fee-mo'-o", "derivation": "from (a muzzle);", "definition": "to muzzle", "kjv": "muzzle."}, "G5393": {"greek": "Φλέγων", "translit": "Phlégōn", "pronunciation": "fleg'-one", "derivation": "active participle of the base of (G5395);", "definition": "blazing; Phlegon, a Christian", "kjv": "Phlegon."}, "G5394": {"greek": "φλογίζω", "translit": "phlogízō", "pronunciation": "flog-id'-zo", "derivation": "from (G5395);", "definition": "to cause a blaze, i.e. ignite (figuratively, to inflame with passion)", "kjv": "set on fire."}, "G5395": {"greek": "φλόξ", "translit": "phlóx", "pronunciation": "flox", "derivation": "from a primary (to \"flash\" or \"flame\");", "definition": "a blaze", "kjv": "flame(-ing)."}, "G5396": {"greek": "φλυαρέω", "translit": "phlyaréō", "pronunciation": "floo-ar-eh'-o", "derivation": "from (G5397);", "definition": "to be a babbler or trifler, i.e. (by implication) to berate idly or mischievously", "kjv": "prate against."}, "G5397": {"greek": "φλύαρος", "translit": "phlýaros", "pronunciation": "floo'-ar-os", "derivation": "from (to bubble);", "definition": "a garrulous person, i.e. prater", "kjv": "tattler."}, "G5398": {"greek": "φοβερός", "translit": "phoberós", "pronunciation": "fob-er-os'", "derivation": "from (G5401);", "definition": "frightful, i.e. (objectively) formidable", "kjv": "fearful, terrible."}, "G5399": {"greek": "φοβέω", "translit": "phobéō", "pronunciation": "fob-eh'-o", "derivation": "from (G5401);", "definition": "to frighten, i.e. (passively) to be alarmed; by analogy, to be in awe of, i.e. revere", "kjv": "be (+ sore) afraid, fear (exceedingly), reverence."}, "G5400": {"greek": "φόβητρον", "translit": "phóbētron", "pronunciation": "fob'-ay-tron", "derivation": "neuter of a derivative of (G5399);", "definition": "a frightening thing, i.e. terrific portent", "kjv": "fearful sight."}, "G5401": {"greek": "φόβος", "translit": "phóbos", "pronunciation": "fob'-os", "derivation": "from a primary (to be put in fear);", "definition": "alarm or fright", "kjv": "be afraid, + exceedingly, fear, terror."}, "G5402": {"greek": "Φοίβη", "translit": "Phoíbē", "pronunciation": "foy'-bay", "derivation": "feminine of (bright;", "definition": "probably akin to the base of (G5457)); Phœbe, a Christian woman", "kjv": "Phebe."}, "G5403": {"greek": "Φοινίκη", "translit": "Phoiníkē", "pronunciation": "foy-nee'-kay", "derivation": "from (G5404);", "definition": "palm-country; Phœnice (or Phœnicia), a region of Palestine", "kjv": "Phenice, Phenicia."}, "G5404": {"greek": "φοῖνιξ", "translit": "phoînix", "pronunciation": "foy'-nix", "derivation": "of uncertain derivation;", "definition": "a palm-tree", "kjv": "palm (tree)."}, "G5406": {"greek": "φονεύς", "translit": "phoneús", "pronunciation": "fon-yooce'", "derivation": "from (G5408);", "definition": "a murderer (always of criminal (or at least intentional) homicide; which (G443) does not necessarily imply; while (G4607) is a special term for a public bandit)", "kjv": "murderer."}, "G5407": {"greek": "φονεύω", "translit": "phoneúō", "pronunciation": "fon-yoo'-o", "derivation": "from (G5406);", "definition": "to be a murderer (of)", "kjv": "kill, do murder, slay."}, "G5408": {"greek": "φόνος", "translit": "phónos", "pronunciation": "fon'-os", "derivation": "from an obsolete primary (to slay);", "definition": "murder", "kjv": "murder, + be slain with, slaughter."}, "G5409": {"greek": "φορέω", "translit": "phoréō", "pronunciation": "for-eh'-o", "derivation": "from (G5411);", "definition": "to have a burden, i.e. (by analogy) to wear as clothing or a constant accompaniment", "kjv": "bear, wear."}, "G5410": {"greek": "Φόρον", "translit": "Phóron", "pronunciation": "for'-on", "derivation": "of Latin origin;", "definition": "a forum or market-place; only in compound with (G675); a station on the Appian road", "kjv": "forum."}, "G5411": {"greek": "φόρος", "translit": "phóros", "pronunciation": "for'-os", "derivation": "from (G5342);", "definition": "a load (as borne), i.e. (figuratively) a tax (properly, an individual assessment on persons or property; whereas (G5056) is usually a general toll on goods or travel)", "kjv": "tribute."}, "G5412": {"greek": "φορτίζω", "translit": "phortízō", "pronunciation": "for-tid'-zo", "derivation": "from (G5414);", "definition": "to load up (properly, as a vessel or animal), i.e. (figuratively) to overburden with ceremony (or spiritual anxiety)", "kjv": "lade, by heavy laden."}, "G5413": {"greek": "φορτίον", "translit": "phortíon", "pronunciation": "for-tee'-on", "derivation": "diminutive of (G5414);", "definition": "an invoice (as part of freight), i.e. (figuratively) a task or service", "kjv": "burden."}, "G5415": {"greek": "Φορτουνᾶτος", "translit": "Phortounâtos", "pronunciation": "for-too-nat'-os", "derivation": "of Latin origin;", "definition": "\"fortunate\"; Fortunatus, a Christian", "kjv": "Fortunatus."}, "G5416": {"greek": "φραγέλλιον", "translit": "phragéllion", "pronunciation": "frag-el'-le-on", "derivation": "neuter of a derivative from the base of (G5417);", "definition": "a whip, i.e. Roman lash as a public punishment", "kjv": "scourge."}, "G5417": {"greek": "φραγελλόω", "translit": "phragellóō", "pronunciation": "frag-el-lo'-o", "derivation": "from a presumed equivalent of the Latin flagellum;", "definition": "to whip, i.e. lash as a public punishment", "kjv": "scourge."}, "G5418": {"greek": "φραγμός", "translit": "phragmós", "pronunciation": "frag-mos'", "derivation": "from (G5420);", "definition": "a fence, or inclosing barrier (literally or figuratively)", "kjv": "hedge (+ round about), partition."}, "G5419": {"greek": "φράζω", "translit": "phrázō", "pronunciation": "frad'-zo", "derivation": "probably akin to (G5420) through the idea of defining;", "definition": "to indicate (by word or act), i.e. (specially), to expound", "kjv": "declare."}, "G5420": {"greek": "φράσσω", "translit": "phrássō", "pronunciation": "fras'-so", "derivation": "apparently a strengthening form of the base of (G5424);", "definition": "to fence or inclose, i.e. (specially), to block up (figuratively, to silence)", "kjv": "stop."}, "G5421": {"greek": "φρέαρ", "translit": "phréar", "pronunciation": "freh'-ar", "derivation": "of uncertain derivation;", "definition": "a hole in the ground (dug for obtaining or holding water or other purposes), i.e. a cistern or well; figuratively, an abyss (as a prison)", "kjv": "well, pit."}, "G5422": {"greek": "φρεναπατάω", "translit": "phrenapatáō", "pronunciation": "fren-ap-at-ah'-o", "derivation": "from (G5423);", "definition": "to be a mind-misleader, i.e. delude", "kjv": "deceive."}, "G5423": {"greek": "φρεναπάτης", "translit": "phrenapátēs", "pronunciation": "fren-ap-at'-ace", "derivation": "from (G5424) and (G539);", "definition": "a mind-misleader, i.e. seducer", "kjv": "deceiver."}, "G5424": {"greek": "φρήν", "translit": "phrḗn", "pronunciation": "frane", "derivation": "probably from an obsolete (to rein in or curb; compare (G5420));", "definition": "the midrif (as a partition of the body), i.e. (figuratively and by implication, of sympathy) the feelings (or sensitive nature; by extension (also in the plural) the mind or cognitive faculties)", "kjv": "understanding."}, "G5425": {"greek": "φρίσσω", "translit": "phríssō", "pronunciation": "fris'-so", "derivation": "apparently a primary verb;", "definition": "to \"bristle\" or chill, i.e. shudder (fear)", "kjv": "tremble."}, "G5426": {"greek": "φρονέω", "translit": "phronéō", "pronunciation": "fron-eh'-o", "derivation": "from (G5424);", "definition": "to exercise the mind, i.e. entertain or have a sentiment or opinion; by implication, to be (mentally) disposed (more or less earnestly in a certain direction); intensively, to interest oneself in (with concern or obedience)", "kjv": "set the affection on, (be) care(-ful), (be like-, + be of one, + be of the same, + let this) mind(-ed), regard, savour, think."}, "G5427": {"greek": "φρόνημα", "translit": "phrónēma", "pronunciation": "fron'-ay-mah", "derivation": "from (G5426);", "definition": "(mental) inclination or purpose", "kjv": "(be, + be carnally, + be spiritually) mind(-ed)."}, "G5428": {"greek": "φρόνησις", "translit": "phrónēsis", "pronunciation": "fron'-ay-sis", "derivation": "from (G5426);", "definition": "mental action or activity, i.e. intellectual or moral insight", "kjv": "prudence, wisdom."}, "G5429": {"greek": "φρόνιμος", "translit": "phrónimos", "pronunciation": "fron'-ee-mos", "derivation": "from (G5424);", "definition": "thoughtful, i.e. sagacious or discreet (implying a cautious character; while (G4680) denotes practical skill or acumen; and (G4908) indicates rather intelligence or mental acquirement); in a bad sense conceited (also in the comparative)", "kjv": "wise(-r)."}, "G5430": {"greek": "φρονίμως", "translit": "phronímōs", "pronunciation": "fron-im'-oce", "derivation": "adverb from (G5429);", "definition": "prudently", "kjv": "wisely."}, "G5431": {"greek": "φροντίζω", "translit": "phrontízō", "pronunciation": "fron-tid'-zo", "derivation": "from a derivative of (G5424);", "definition": "to exercise thought, i.e. be anxious", "kjv": "be careful."}, "G5432": {"greek": "φρουρέω", "translit": "phrouréō", "pronunciation": "froo-reh'-o", "derivation": "from a compound of (G4253) and (G3708);", "definition": "to be a watcher in advance, i.e. to mount guard as a sentinel (post spies at gates); figuratively, to hem in, protect", "kjv": "keep (with a garrison)."}, "G5433": {"greek": "φρυάσσω", "translit": "phryássō", "pronunciation": "froo-as'-so", "derivation": "akin to (G1032), (G1031);", "definition": "to snort (as a spirited horse), i.e. (figuratively) to make a tumult", "kjv": "rage."}, "G5434": {"greek": "φρύγανον", "translit": "phrýganon", "pronunciation": "froo'-gan-on", "derivation": "neuter of a presumed derivative of (to roast or parch; akin to the base of (G5395));", "definition": "something desiccated, i.e. a dry twig", "kjv": "stick."}, "G5435": {"greek": "Φρυγία", "translit": "Phrygía", "pronunciation": "froog-ee'-ah", "derivation": "probably of foreign origin;", "definition": "Phrygia, a region of Asia Minor", "kjv": "Phrygia."}, "G5436": {"greek": "Φύγελλος", "translit": "Phýgellos", "pronunciation": "foog'-el-los", "derivation": "probably from (G5343);", "definition": "fugitive; Phygellus, an apostate Christian", "kjv": "Phygellus."}, "G5437": {"greek": "φυγή", "translit": "phygḗ", "pronunciation": "foog-ay'", "derivation": "from (G5343);", "definition": "a fleeing, i.e. escape", "kjv": "flight."}, "G5438": {"greek": "φυλακή", "translit": "phylakḗ", "pronunciation": "foo-lak-ay'", "derivation": "from (G5442);", "definition": "a guarding or (concretely, guard), the act, the person; figuratively, the place, the condition, or (specially), the time (as a division of day or night), literally or figuratively", "kjv": "cage, hold, (im-)prison(-ment), ward, watch."}, "G5439": {"greek": "φυλακίζω", "translit": "phylakízō", "pronunciation": "foo-lak-id'-zo", "derivation": "from (G5441);", "definition": "to incarcerate", "kjv": "imprison."}, "G5440": {"greek": "φυλακτήριον", "translit": "phylaktḗrion", "pronunciation": "foo-lak-tay'-ree-on", "derivation": "neuter of a derivative of (G5442);", "definition": "a guard-case, i.e. \"phylactery\" for wearing slips of Scripture texts", "kjv": "phylactery."}, "G5441": {"greek": "φύλαξ", "translit": "phýlax", "pronunciation": "foo'-lax", "derivation": "from (G5442);", "definition": "a watcher or sentry", "kjv": "keeper."}, "G5442": {"greek": "φυλάσσω", "translit": "phylássō", "pronunciation": "foo-las'-so", "derivation": "probably from (G5443) through the idea of isolation;", "definition": "to watch, i.e. be on guard (literally of figuratively); by implication, to preserve, obey, avoid", "kjv": "beward, keep (self), observe, save."}, "G5443": {"greek": "φυλή", "translit": "phylḗ", "pronunciation": "foo-lay'", "derivation": "from (G5453) (compare (G5444));", "definition": "an offshoot, i.e. race or clan", "kjv": "kindred, tribe."}, "G5444": {"greek": "φύλλον", "translit": "phýllon", "pronunciation": "fool'-lon", "derivation": "from the same as (G5443);", "definition": "a sprout, i.e. leaf", "kjv": "leaf."}, "G5445": {"greek": "φύραμα", "translit": "phýrama", "pronunciation": "foo'-ram-ah", "derivation": "from a prolonged form of (to mix a liquid with a solid;", "definition": "perhaps akin to (G5453) through the idea of swelling in bulk), mean to knead; a mass of dough", "kjv": "lump."}, "G5446": {"greek": "φυσικός", "translit": "physikós", "pronunciation": "foo-see-kos'", "derivation": "from (G5449);", "definition": "\"physical\", i.e. (by implication) instinctive", "kjv": "natural."}, "G5447": {"greek": "φυσικῶς", "translit": "physikōs", "pronunciation": "foo-see-koce'", "derivation": "adverb from (G5446);", "definition": "\"physically\", i.e. (by implication) instinctively", "kjv": "naturally."}, "G5448": {"greek": "φυσιόω", "translit": "physióō", "pronunciation": "foo-see-o'-o", "derivation": "from (G5449) in the primary sense of blowing;", "definition": "to inflate, i.e. (figuratively) make proud (haughty)", "kjv": "puff up."}, "G5449": {"greek": "φύσις", "translit": "phýsis", "pronunciation": "foo'-sis", "derivation": "from (G5453);", "definition": "growth (by germination or expansion), i.e. (by implication) natural production (lineal descent); by extension, a genus or sort; figuratively, native disposition, constitution or usage", "kjv": "(man-)kind, nature(-al)."}, "G5450": {"greek": "φυσίωσις", "translit": "physíōsis", "pronunciation": "foo-see'-o-sis", "derivation": "from (G5448);", "definition": "inflation, i.e. (figuratively) haughtiness", "kjv": "swelling."}, "G5451": {"greek": "φυτεία", "translit": "phyteía", "pronunciation": "foo-ti'-ah", "derivation": "from (G5452);", "definition": "trans-planting, i.e. (concretely) a shrub or vegetable", "kjv": "plant."}, "G5452": {"greek": "φυτεύω", "translit": "phyteúō", "pronunciation": "foot-yoo'-o", "derivation": "from a derivative of (G5453);", "definition": "to set out in the earth, i.e. implant; figuratively, to instil doctrine", "kjv": "plant."}, "G5453": {"greek": "φύω", "translit": "phýō", "pronunciation": "foo'-o", "derivation": "a primary verb;", "definition": "probably originally, to \"puff\" or blow, i.e. to swell up; but only used in the implied sense, to germinate or grow (sprout, produce), literally or figuratively", "kjv": "spring (up)."}, "G5454": {"greek": "φωλεός", "translit": "phōleós", "pronunciation": "fo-leh-os'", "derivation": "of uncertain derivative;", "definition": "a burrow or lurking-place", "kjv": "hole."}, "G5455": {"greek": "φωνέω", "translit": "phōnéō", "pronunciation": "fo-neh'-o", "derivation": "from (G5456);", "definition": "to emit a sound (animal, human or instrumental); by implication, to address in words or by name, also in imitation", "kjv": "call (for), crow, cry."}, "G5456": {"greek": "φωνή", "translit": "phōnḗ", "pronunciation": "fo-nay'", "derivation": "probably akin to (G5316) through the idea of disclosure;", "definition": "a tone (articulate, bestial or artificial); by implication, an address (for any purpose), saying or language", "kjv": "noise, sound, voice."}, "G5457": {"greek": "φῶς", "translit": "phōs", "pronunciation": "foce", "derivation": "from an obsolete (to shine or make manifest, especially by rays; compare (G5316), (G5346));", "definition": "luminousness (in the widest application, natural or artificial, abstract or concrete, literal or figurative)", "kjv": "fire, light."}, "G5458": {"greek": "φωστήρ", "translit": "phōstḗr", "pronunciation": "foce-tare'", "derivation": "from (G5457);", "definition": "an illuminator, i.e. (concretely) a luminary, or (abstractly) brilliancy", "kjv": "light."}, "G5459": {"greek": "φωσφόρος", "translit": "phōsphóros", "pronunciation": "foce-for'-os", "derivation": "from (G5457) and (G5342);", "definition": "light-bearing (\"phosphorus\"), i.e. (specially), the morning-star (figuratively)", "kjv": "day star."}, "G5460": {"greek": "φωτεινός", "translit": "phōteinós", "pronunciation": "fo-ti-nos'", "derivation": "from (G5457);", "definition": "lustrous, i.e. transparent or well-illuminated (figuratively)", "kjv": "bright, full of light."}, "G5461": {"greek": "φωτίζω", "translit": "phōtízō", "pronunciation": "fo-tid'-zo", "derivation": "from (G5457);", "definition": "to shed rays, i.e. to shine or (transitively) to brighten up (literally or figuratively)", "kjv": "enlighten, illuminate, (bring to, give) light, make to see."}, "G5462": {"greek": "φωτισμός", "translit": "phōtismós", "pronunciation": "fo-tis-mos'", "derivation": "from (G5461);", "definition": "illumination (figuratively)", "kjv": "light."}, "G5463": {"greek": "χαίρω", "translit": "chaírō", "pronunciation": "khah'-ee-ro", "derivation": "a primary verb;", "definition": "to be \"cheer\"ful, i.e. calmly happy or well-off; impersonally, especially as salutation (on meeting or parting), be well", "kjv": "farewell, be glad, God speed, greeting, hall, joy(- fully), rejoice."}, "G5464": {"greek": "χάλαζα", "translit": "chálaza", "pronunciation": "khal'-ad-zah", "derivation": "probably from (G5465);", "definition": "hail", "kjv": "hail."}, "G5465": {"greek": "χαλάω", "translit": "chaláō", "pronunciation": "khal-ah'-o", "derivation": "from the base of (G5490);", "definition": "to lower (as into a void)", "kjv": "let down, strike."}, "G5466": {"greek": "Χαλδαῖος", "translit": "Chaldaîos", "pronunciation": "khal-dah'-yos", "derivation": "probably of Hebrew or ((G3778));", "definition": "a Chaldæan (i.e. Kasdi), or native or the region of the lower Euphrates", "kjv": "Chaldæan."}, "G5467": {"greek": "χαλεπός", "translit": "chalepós", "pronunciation": "khal-ep-os'", "derivation": "perhaps from (G5465) through the idea of reducing the strength;", "definition": "difficult, i.e. dangerous, or (by implication) furious", "kjv": "fierce, perilous."}, "G5468": {"greek": "χαλιναγωγέω", "translit": "chalinagōgéō", "pronunciation": "khal-in-ag-ogue-eh'-o", "derivation": "from a compound of (G5469) and the reduplicated form of (G71);", "definition": "to be a bit-leader, i.e. to curb (figuratively)", "kjv": "bridle."}, "G5469": {"greek": "χαλινός", "translit": "chalinós", "pronunciation": "khal-ee-nos'", "derivation": "from (G5465);", "definition": "a curb or head-stall (as curbing the spirit)", "kjv": "bit, bridle."}, "G5470": {"greek": "χάλκεος", "translit": "chálkeos", "pronunciation": "khal'-keh-os", "derivation": "from (G5475);", "definition": "coppery", "kjv": "brass."}, "G5471": {"greek": "χαλκεύς", "translit": "chalkeús", "pronunciation": "khalk-yooce'", "derivation": "from (G5475);", "definition": "a copper-worker or brazier", "kjv": "coppersmith."}, "G5472": {"greek": "χαλκηδών", "translit": "chalkēdṓn", "pronunciation": "khal-kay-dohn'", "derivation": "from (G5475) and perhaps (G1491);", "definition": "copper-like, i.e. \"chalcedony\"", "kjv": "chalcedony."}, "G5473": {"greek": "χαλκίον", "translit": "chalkíon", "pronunciation": "khal-kee'-on", "derivation": "diminutive from (G5475);", "definition": "a copper dish", "kjv": "brazen vessel."}, "G5474": {"greek": "χαλκολίβανον", "translit": "chalkolíbanon", "pronunciation": "khal-kol-ib'-an-on", "derivation": "neuter of a compound of (G5475) and (G3030) (in the implied mean of whiteness or brilliancy);", "definition": "burnished copper, an alloy of copper (or gold) and silver having a brilliant lustre", "kjv": "fine brass."}, "G5475": {"greek": "χαλκός", "translit": "chalkós", "pronunciation": "khal-kos'", "derivation": "perhaps from (G5465) through the idea of hollowing out as a vessel (this metal being chiefly used for that purpose);", "definition": "copper (the substance, or some implement or coin made of it)", "kjv": "brass, money."}, "G5476": {"greek": "χαμαί", "translit": "chamaí", "pronunciation": "kham-ah'-ee", "derivation": "adverb perhaps from the base of (G5490) through the idea of a fissure in the soil;", "definition": "earthward, i.e. prostrate", "kjv": "on (to) the ground."}, "G5477": {"greek": "Χαναάν", "translit": "Chanaán", "pronunciation": "khan-ah-an'", "derivation": "of Hebrew origin ((G3667));", "definition": "Chanaan (i.e. Kenaan), the early name of Palestine", "kjv": "Chanaan."}, "G5478": {"greek": "Χανααναῖος", "translit": "Chanaanaîos", "pronunciation": "khan-ah-an-ah'-yos", "derivation": "from (G5477);", "definition": "a Chanaanæan (i.e. Kenaanite), or native of gentile Palestine", "kjv": "of Canaan."}, "G5479": {"greek": "χαρά", "translit": "chará", "pronunciation": "khar-ah'", "derivation": "from (G5463);", "definition": "cheerfulness, i.e. calm delight", "kjv": "gladness, X greatly, (X be exceeding) joy(-ful, -fully, -fulness, -ous)."}, "G5480": {"greek": "χάραγμα", "translit": "cháragma", "pronunciation": "khar'-ag-mah", "derivation": "from the same as (G5482);", "definition": "a scratch or etching, i.e. stamp (as a badge of servitude), or sculptured figure (statue)", "kjv": "graven, mark."}, "G5481": {"greek": "χαρακτήρ", "translit": "charaktḗr", "pronunciation": "khar-ak-tare'", "derivation": "from the same as (G5482);", "definition": "a graver (the tool or the person), i.e. (by implication) engraving ((\"character\"), the figure stamped, i.e. an exact copy or (figuratively) representation)", "kjv": "express image."}, "G5482": {"greek": "χάραξ", "translit": "chárax", "pronunciation": "khar'-ax", "derivation": "from (to sharpen to a point; akin to (G1125) through the idea of scratching);", "definition": "a stake, i.e. (by implication) a palisade or rampart (military mound for circumvallation in a siege)", "kjv": "trench."}, "G5483": {"greek": "χαρίζομαι", "translit": "charízomai", "pronunciation": "khar-id'-zom-ahee", "derivation": "middle voice from (G5485);", "definition": "to grant as a favor, i.e. gratuitously, in kindness, pardon or rescue", "kjv": "deliver, (frankly) forgive, (freely) give, grant."}, "G5485": {"greek": "χάρις", "translit": "cháris", "pronunciation": "khar'-ece", "derivation": "from (G5463);", "definition": "graciousness (as gratifying), of manner or act (abstract or concrete; literal, figurative or spiritual; especially the divine influence upon the heart, and its reflection in the life; including gratitude)", "kjv": "acceptable, benefit, favour, gift, grace(- ious), joy, liberality, pleasure, thank(-s, -worthy)."}, "G5486": {"greek": "χάρισμα", "translit": "chárisma", "pronunciation": "khar'-is-mah", "derivation": "from (G5483);", "definition": "a (divine) gratuity, i.e. deliverance (from danger or passion); (specially), a (spiritual) endowment, i.e. (subjectively) religious qualification, or (objectively) miraculous faculty", "kjv": "(free) gift."}, "G5487": {"greek": "χαριτόω", "translit": "charitóō", "pronunciation": "khar-ee-to'-o", "derivation": "from (G5485);", "definition": "to grace, i.e. indue with special honor", "kjv": "make accepted, be highly favoured."}, "G5488": {"greek": "Χαῤῥάν", "translit": "Charrhán", "pronunciation": "khar-hran'", "derivation": "of Hebrew origin ((G2771));", "definition": "Charrhan (i.e. Charan), a place in Mesopotamia", "kjv": "Charran."}, "G5489": {"greek": "χάρτης", "translit": "chártēs", "pronunciation": "khar'-tace", "derivation": "from the same as (G5482);", "definition": "a sheet (\"chart\") of writing-material (as to be scribbled over)", "kjv": "paper."}, "G5490": {"greek": "χάσμα", "translit": "chásma", "pronunciation": "khas'-mah", "derivation": "from a form of an obsolete primary (to \"gape\" or \"yawn\");", "definition": "a \"chasm\" or vacancy (impassable interval)", "kjv": "gulf."}, "G5491": {"greek": "χεῖλος", "translit": "cheîlos", "pronunciation": "khi'-los", "derivation": "from a form of the same as (G5490);", "definition": "a lip (as a pouring place); figuratively, a margin (of water)", "kjv": "lip, shore."}, "G5492": {"greek": "χειμάζω", "translit": "cheimázō", "pronunciation": "khi-mad'-zo", "derivation": "from the same as (G5494);", "definition": "to storm, i.e. (passively) to labor under a gale", "kjv": "be tossed with tempest."}, "G5493": {"greek": "χείμαῤῥος", "translit": "cheímarrhos", "pronunciation": "khi'-mar-hros", "derivation": "from the base of (G5494) and (G4482);", "definition": "a storm-runlet, i.e. winter-torrent", "kjv": "brook."}, "G5494": {"greek": "χειμών", "translit": "cheimṓn", "pronunciation": "khi-mone'", "derivation": "from a derivative of (to pour;", "definition": "akin to the base of 5490 through the idea of a channel), meaning a storm (as pouring rain); by implication, the rainy season, i.e. winter", "kjv": "tempest, foul weather, winter."}, "G5495": {"greek": "χείρ", "translit": "cheír", "pronunciation": "khire", "derivation": "perhaps from the base of (G5494) in the sense of its congener the base of (G5490) (through the idea of hollowness for grasping);", "definition": "the hand (literally or figuratively (power); especially (by Hebraism) a means or instrument)", "kjv": "hand."}, "G5496": {"greek": "χειραγωγέω", "translit": "cheiragōgéō", "pronunciation": "khi-rag-ogue-eh'-o", "derivation": "from (G5497);", "definition": "to be a hand-leader, i.e. to guide (a blind person)", "kjv": "lead by the hand."}, "G5497": {"greek": "χειραγωγός", "translit": "cheiragōgós", "pronunciation": "khi-rag-o-gos'", "derivation": "from (G5495) and a reduplicated form of (G71);", "definition": "a hand-leader, i.e. personal conductor (of a blind person)", "kjv": "some to lead by the hand."}, "G5498": {"greek": "χειρόγραφον", "translit": "cheirógraphon", "pronunciation": "khi-rog'-raf-on", "derivation": "neuter of a compound of (G5495) and (G1125);", "definition": "something hand-written (\"chirograph\"), i.e. a manuscript (specially, a legal document or bond (figuratively))", "kjv": "handwriting."}, "G5499": {"greek": "χειροποίητος", "translit": "cheiropoíētos", "pronunciation": "khi-rop-oy'-ay-tos", "derivation": "from (G5495) and a derivative of (G4160);", "definition": "manufactured, i.e. of human construction", "kjv": "made by (make with) hands."}, "G5500": {"greek": "χειροτονέω", "translit": "cheirotonéō", "pronunciation": "khi-rot-on-eh'-o", "derivation": "from a compound of (G5495) and (to stretch);", "definition": "to be a hand-reacher or voter (by raising the hand), i.e. (generally) to select or appoint", "kjv": "choose, ordain."}, "G5501": {"greek": "χείρων", "translit": "cheírōn", "pronunciation": "khi'-rone", "derivation": "irregular comparative of (G2556);", "definition": "from an obsolete equivalent (of uncertain derivation); more evil or aggravated (physically, mentally or morally)", "kjv": "sorer, worse."}, "G5502": {"greek": "χερουβίμ", "translit": "cheroubím", "pronunciation": "kher-oo-beem'", "derivation": "plural of Hebrew origin ((G3742));", "definition": "\"cherubim\" (i.e. cherubs or kerubim)", "kjv": "cherubims."}, "G5503": {"greek": "χήρα", "translit": "chḗra", "pronunciation": "khay'-rah", "derivation": "feminine of a presumed derivative apparently from the base of (G5490) through the idea of deficiency;", "definition": "a widow (as lacking a husband), literally or figuratively", "kjv": "widow."}, "G5504": {"greek": "χθές", "translit": "chthés", "pronunciation": "khthes", "derivation": "of uncertain derivation;", "definition": "\"yesterday\"; by extension, in time past or hitherto", "kjv": "yesterday."}, "G5505": {"greek": "χιλιάς", "translit": "chiliás", "pronunciation": "khil-ee-as'", "derivation": "from (G5507);", "definition": "one thousand (\"chiliad\")", "kjv": "thousand."}, "G5506": {"greek": "χιλίαρχος", "translit": "chilíarchos", "pronunciation": "khil-ee'-ar-khos", "derivation": "from (G5507) and (G757);", "definition": "the commander of a thousand soldiers (\"chiliarch\"; i.e. colonel", "kjv": "(chief, high) captain."}, "G5507": {"greek": "χίλιοι", "translit": "chílioi", "pronunciation": "khil'-ee-oy", "derivation": "plural of uncertain affinity;", "definition": "a thousand", "kjv": "thousand."}, "G5508": {"greek": "Χίος", "translit": "Chíos", "pronunciation": "khee'-os", "derivation": "of uncertain derivation;", "definition": "Chios, an island in the Mediterranean", "kjv": "Chios."}, "G5509": {"greek": "χιτών", "translit": "chitṓn", "pronunciation": "khee-tone'", "derivation": "of foreign origin ((G3801));", "definition": "a tunic or shirt", "kjv": "clothes, coat, garment."}, "G5510": {"greek": "χιών", "translit": "chiṓn", "pronunciation": "khee-one'", "derivation": "perhaps akin to the base of (G5490) ((G5465)) or (G5494) (as descending or empty);", "definition": "snow", "kjv": "snow."}, "G5511": {"greek": "χλαμύς", "translit": "chlamýs", "pronunciation": "khlam-ooce'", "derivation": "of uncertain derivation;", "definition": "a military cloak", "kjv": "robe."}, "G5512": {"greek": "χλευάζω", "translit": "chleuázō", "pronunciation": "khlyoo-ad'-zo", "derivation": "from a derivative probably of (G5491);", "definition": "to throw out the lip, i.e. jeer at", "kjv": "mock."}, "G5513": {"greek": "χλιαρός", "translit": "chliarós", "pronunciation": "khlee-ar-os'", "derivation": "from (to warm);", "definition": "tepid", "kjv": "lukewarm."}, "G5514": {"greek": "Χλόη", "translit": "Chlóē", "pronunciation": "khlo'-ay", "derivation": "feminine of apparently a primary word;", "definition": "\"green\"; Chloë, a Christian female", "kjv": "Chloe."}, "G5515": {"greek": "χλωρός", "translit": "chlōrós", "pronunciation": "khlo-ros'", "derivation": "from the same as (G5514);", "definition": "greenish, i.e. verdant, dun-colored", "kjv": "green, pale."}, "G5517": {"greek": "χοϊκός", "translit": "choïkós", "pronunciation": "kho-ik-os'", "derivation": "from (G5522);", "definition": "dusty or dirty (soil-like), i.e. (by implication) terrene", "kjv": "earthy."}, "G5518": {"greek": "χοῖνιξ", "translit": "choînix", "pronunciation": "khoy'-nix", "derivation": "of uncertain derivation;", "definition": "a chœnix or certain dry measure", "kjv": "measure."}, "G5519": {"greek": "χοῖρος", "translit": "choîros", "pronunciation": "khoy'-ros", "derivation": "of uncertain derivation;", "definition": "a hog", "kjv": "swine."}, "G5520": {"greek": "χολάω", "translit": "choláō", "pronunciation": "khol-ah'-o", "derivation": "from (G5521);", "definition": "to be bilious, i.e. (by implication) irritable (enraged, \"choleric\")", "kjv": "be angry."}, "G5521": {"greek": "χολή", "translit": "cholḗ", "pronunciation": "khol-ay'", "derivation": "feminine of an equivalent perhaps akin to the same as (G5514) (from the greenish hue);", "definition": "\"gall\" or bile, i.e. (by analogy) poison or an anodyne (wormwood, poppy, etc.)", "kjv": "gall."}, "G5522": {"greek": "χόος", "translit": "chóos", "pronunciation": "kho'-os", "derivation": "from the base of (G5494);", "definition": "a heap (as poured out), i.e. rubbish; loose dirt", "kjv": "dust."}, "G5523": {"greek": "Χοραζίν", "translit": "Chorazín", "pronunciation": "khor-ad-zin'", "derivation": "of uncertain derivation;", "definition": "Chorazin, a place in Palestine", "kjv": "Chorazin."}, "G5524": {"greek": "χορηγέω", "translit": "chorēgéō", "pronunciation": "khor-ayg-eh'-o", "derivation": "from a compound of (G5525) and (G71);", "definition": "to be a dance-leader, i.e. (generally) to furnish", "kjv": "give, minister."}, "G5525": {"greek": "χορός", "translit": "chorós", "pronunciation": "khor-os'", "derivation": "of uncertain derivation;", "definition": "a ring, i.e. round dance (\"choir\"", "kjv": "dancing."}, "G5526": {"greek": "χορτάζω", "translit": "chortázō", "pronunciation": "khor-tad'-zo", "derivation": "from (G5528);", "definition": "to fodder, i.e. (generally) to gorge (supply food in abundance)", "kjv": "feed, fill, satisfy."}, "G5527": {"greek": "χόρτασμα", "translit": "chórtasma", "pronunciation": "khor'-tas-mah", "derivation": "from (G5526);", "definition": "forage, i.e. food", "kjv": "sustenance."}, "G5528": {"greek": "χόρτος", "translit": "chórtos", "pronunciation": "khor'-tos", "derivation": "apparently a primary word;", "definition": "a \"court\" or \"garden\", i.e. (by implication, of pasture) herbage or vegetation", "kjv": "blade, grass, hay."}, "G5529": {"greek": "Χουζᾶς", "translit": "Chouzâs", "pronunciation": "khood-zas'", "derivation": "of uncertain origin;", "definition": "Chuzas, an officer of Herod", "kjv": "Chuza."}, "G5530": {"greek": "χράομαι", "translit": "chráomai", "pronunciation": "khrah'-om-ahee", "derivation": "middle voice of a primary verb (perhaps rather from (G5495), to handle);", "definition": "to furnish what is needed; (give an oracle, \"graze\" (touch slightly), light upon, etc.), i.e. (by implication) to employ or (by extension) to act towards one in a given manner", "kjv": "entreat, use."}, "G5531": {"greek": "χράω", "translit": "chráō", "pronunciation": "khrah'-o", "derivation": "probably the same as the base of (G5530);", "definition": "to loan", "kjv": "lend."}, "G5532": {"greek": "χρεία", "translit": "chreía", "pronunciation": "khri'-ah", "derivation": "from the base of (G5530) or (G5534);", "definition": "employment, i.e. an affair; also (by implication) occasion, demand, requirement or destitution", "kjv": "business, lack, necessary(-ity), need(-ful), use, want."}, "G5533": {"greek": "χρεωφειλέτης", "translit": "chreōpheilétēs", "pronunciation": "khreh-o-fi-let'-ace", "derivation": "from a derivative of (G5531) and (G3781);", "definition": "a loan-ower, i.e. indebted person", "kjv": "debtor."}, "G5534": {"greek": "χρή", "translit": "chrḗ", "pronunciation": "khray", "derivation": "third person singular of the same as (G5530) or (G5531) used impersonally;", "definition": "it needs (must or should) be", "kjv": "ought."}, "G5535": {"greek": "χρῄζω", "translit": "chrḗizō", "pronunciation": "khrade'-zo", "derivation": "from (G5532);", "definition": "to make (i.e. have) necessity, i.e. be in want of", "kjv": "(have) need."}, "G5536": {"greek": "χρῆμα", "translit": "chrēma", "pronunciation": "khray'-mah", "derivation": "", "definition": "something useful or needed, i.e. wealth, price", "kjv": "money, riches."}, "G5537": {"greek": "χρηματίζω", "translit": "chrēmatízō", "pronunciation": "khray-mat-id'-zo", "derivation": "from (G5536);", "definition": "to utter an oracle (compare the original sense of (G5530)), i.e. divinely intimate; by implication, (compare the secular sense of (G5532)) to constitute a firm for business, i.e. (generally) bear as a title", "kjv": "be called, be admonished (warned) of God, reveal, speak."}, "G5538": {"greek": "χρηματισμός", "translit": "chrēmatismós", "pronunciation": "khray-mat-is-mos'", "derivation": "from (G5537);", "definition": "a divine response or revelation", "kjv": "answer of God."}, "G5539": {"greek": "χρήσιμος", "translit": "chrḗsimos", "pronunciation": "khray'-see-mos", "derivation": "from (G5540);", "definition": "serviceable", "kjv": "profit."}, "G5540": {"greek": "χρῆσις", "translit": "chrēsis", "pronunciation": "khray'-sis", "derivation": "from (G5530);", "definition": "employment, i.e. (specially), sexual intercourse (as an occupation of the body)", "kjv": "use."}, "G5541": {"greek": "χρηστεύομαι", "translit": "chrēsteúomai", "pronunciation": "khraste-yoo'-om-ahee", "derivation": "middle voice from (G5543);", "definition": "to show oneself useful, i.e. act benevolently", "kjv": "be kind."}, "G5542": {"greek": "χρηστολογία", "translit": "chrēstología", "pronunciation": "khrase-tol-og-ee'-ah", "derivation": "from a compound of (G5543) and (G3004);", "definition": "fair speech, i.e. plausibility", "kjv": "good words."}, "G5543": {"greek": "χρηστός", "translit": "chrēstós", "pronunciation": "khrase-tos'", "derivation": "from (G5530);", "definition": "employed, i.e. (by implication) useful (in manner or morals)", "kjv": "better, easy, good(-ness), gracious, kind."}, "G5544": {"greek": "χρηστότης", "translit": "chrēstótēs", "pronunciation": "khray-stot'-ace", "derivation": "from (G5543);", "definition": "usefulness, i.e. morally, excellence (in character or demeanor)", "kjv": "gentleness, good(-ness), kindness."}, "G5545": {"greek": "χρῖσμα", "translit": "chrîsma", "pronunciation": "khris'-mah", "derivation": "from (G5548);", "definition": "an unguent or smearing, i.e. (figuratively) the special endowment (\"chrism\") of the Holy Spirit", "kjv": "anointing, unction."}, "G5546": {"greek": "Χριστιανός", "translit": "Christianós", "pronunciation": "khris-tee-an-os'", "derivation": "from (G5547);", "definition": "a Christian, i.e. follower of Christ", "kjv": "Christian."}, "G5547": {"greek": "Χριστός", "translit": "Christós", "pronunciation": "khris-tos'", "derivation": "from (G5548);", "definition": "anointed, i.e. the Messiah, an epithet of Jesus", "kjv": "Christ."}, "G5548": {"greek": "χρίω", "translit": "chríō", "pronunciation": "khree'-o", "derivation": "probably akin to (G5530) through the idea of contact;", "definition": "to smear or rub with oil, i.e. (by implication) to consecrate to an office or religious service", "kjv": "anoint."}, "G5549": {"greek": "χρονίζω", "translit": "chronízō", "pronunciation": "khron-id'-zo", "derivation": "from (G5550);", "definition": "to take time, i.e. linger", "kjv": "delay, tarry."}, "G5550": {"greek": "χρόνος", "translit": "chrónos", "pronunciation": "khron'-os", "derivation": "of uncertain derivation;", "definition": "a space of time (in general, and thus properly distinguished from (G2540), which designates a fixed or special occasion; and from (G165), which denotes a particular period) or interval; by extension, an individual opportunity; by implication, delay", "kjv": "+ years old, season, space, (X often-)time(-s), (a) while."}, "G5551": {"greek": "χρονοτριβέω", "translit": "chronotribéō", "pronunciation": "khron-ot-rib-eh'-o", "derivation": "from a presumed compound of (G5550) and the base of (G5147);", "definition": "to be a time-wearer, i.e. to procrastinate (linger)", "kjv": "spend time."}, "G5552": {"greek": "χρύσεος", "translit": "chrýseos", "pronunciation": "khroo'-seh-os", "derivation": "from (G5557);", "definition": "made of gold", "kjv": "of gold, golden."}, "G5553": {"greek": "χρυσίον", "translit": "chrysíon", "pronunciation": "khroo-see'-on", "derivation": "diminutive of (G5557);", "definition": "a golden article, i.e. gold plating, ornament, or coin", "kjv": "gold."}, "G5554": {"greek": "χρυσοδακτύλιος", "translit": "chrysodaktýlios", "pronunciation": "khroo-sod-ak-too'-lee-os", "derivation": "from (G5557) and (G1146);", "definition": "gold-ringed, i.e. wearing a golden finger-ring or similar jewelry", "kjv": "with a gold ring."}, "G5555": {"greek": "χρυσόλιθος", "translit": "chrysólithos", "pronunciation": "khroo-sol'-ee-thos", "derivation": "from (G5557) and (G3037);", "definition": "gold-stone, i.e. a yellow gem (\"chrysolite\")", "kjv": "chrysolite."}, "G5556": {"greek": "χρυσόπρασος", "translit": "chrysóprasos", "pronunciation": "khroo-sop'-ras-os", "derivation": "from (G5557) and (a leek);", "definition": "a greenish-yellow gem (\"chrysoprase\")", "kjv": "chrysoprase."}, "G5557": {"greek": "χρυσός", "translit": "chrysós", "pronunciation": "khroo-sos'", "derivation": "perhaps from the base of (G5530) (through the idea of the utility of the metal);", "definition": "gold; by extension, a golden article, as an ornament or coin", "kjv": "gold."}, "G5558": {"greek": "χρυσόω", "translit": "chrysóō", "pronunciation": "khroo-so'-o", "derivation": "from (G5557);", "definition": "to gild, i.e. bespangle with golden ornaments", "kjv": "deck."}, "G5559": {"greek": "χρώς", "translit": "chrṓs", "pronunciation": "khroce", "derivation": "probably akin to the base of (G5530) through the idea of handling;", "definition": "the body (properly, its surface or skin)", "kjv": "body."}, "G5560": {"greek": "χωλός", "translit": "chōlós", "pronunciation": "kho-los'", "derivation": "apparently a primary word;", "definition": "\"halt\", i.e. limping", "kjv": "cripple, halt, lame."}, "G5561": {"greek": "χώρα", "translit": "chṓra", "pronunciation": "kho'-rah", "derivation": "feminine of a derivative of the base of (G5490) through the idea of empty expanse;", "definition": "room, i.e. a space of territory (more or less extensive; often including its inhabitants)", "kjv": "coast, county, fields, ground, land, region."}, "G5562": {"greek": "χωρέω", "translit": "chōréō", "pronunciation": "kho-reh'-o", "derivation": "from (G5561);", "definition": "to be in (give) space, i.e. (intransitively) to pass, enter, or (transitively) to hold, admit (literally or figuratively)", "kjv": "come, contain, go, have place, (can, be room to) receive."}, "G5563": {"greek": "χωρίζω", "translit": "chōrízō", "pronunciation": "kho-rid'-zo", "derivation": "from (G5561);", "definition": "to place room between, i.e. part; reflexively, to go away", "kjv": "depart, put asunder, separate."}, "G5564": {"greek": "χωρίον", "translit": "chōríon", "pronunciation": "kho-ree'-on", "derivation": "diminutive of (G5561);", "definition": "a spot or plot of ground", "kjv": "field, land, parcel of ground, place, possession."}, "G5565": {"greek": "χωρίς", "translit": "chōrís", "pronunciation": "kho-rece'", "derivation": "adverb from (G5561);", "definition": "at a space, i.e. separately or apart from (often as preposition)", "kjv": "beside, by itself, without."}, "G5566": {"greek": "χῶρος", "translit": "chōros", "pronunciation": "kho'-ros", "derivation": "of Latin origin;", "definition": "the north-west wind", "kjv": "north west."}, "G5567": {"greek": "ψάλλω", "translit": "psállō", "pronunciation": "psal'-lo", "derivation": "probably strengthened from (to rub or touch the surface; compare (G5597));", "definition": "to twitch or twang, i.e. to play on a stringed instrument (celebrate the divine worship with music and accompanying odes)", "kjv": "make melody, sing (psalms)."}, "G5568": {"greek": "ψαλμός", "translit": "psalmós", "pronunciation": "psal-mos'", "derivation": "from (G5567);", "definition": "a set piece of music, i.e. a sacred ode (accompanied with the voice, harp or other instrument; a \"psalm\"); collectively, the book of the Psalms", "kjv": "psalm."}, "G5569": {"greek": "ψευδάδελφος", "translit": "pseudádelphos", "pronunciation": "psyoo-dad'-el-fos", "derivation": "from (G5571) and (G80);", "definition": "a spurious brother, i.e. pretended associate", "kjv": "false brethren."}, "G5570": {"greek": "ψευδαπόστολος", "translit": "pseudapóstolos", "pronunciation": "psyoo-dap-os'-tol-os", "derivation": "from (G5571) and (G652);", "definition": "a spurious apostle, i.e. pretended pracher", "kjv": "false teacher."}, "G5571": {"greek": "ψευδής", "translit": "pseudḗs", "pronunciation": "psyoo-dace'", "derivation": "from (G5574);", "definition": "untrue, i.e. erroneous, deceitful, wicked", "kjv": "false, liar."}, "G5572": {"greek": "ψευδοδιδάσκαλος", "translit": "pseudodidáskalos", "pronunciation": "psyoo-dod-id-as'-kal-os", "derivation": "from (G5571) and (G1320);", "definition": "a spurious teacher, i.e. propagator of erroneous Christian doctrine", "kjv": "false teacher."}, "G5573": {"greek": "ψευδολόγος", "translit": "pseudológos", "pronunciation": "psyoo-dol-og'-os", "derivation": "from (G5571) and (G3004);", "definition": "mendacious, i.e. promulgating erroneous Christian doctrine", "kjv": "speaking lies."}, "G5574": {"greek": "ψεύδομαι", "translit": "pseúdomai", "pronunciation": "psyoo'-dom-ahee", "derivation": "middle voice of an apparently primary verb;", "definition": "to utter an untruth or attempt to deceive by falsehood", "kjv": "falsely, lie."}, "G5575": {"greek": "ψευδομάρτυρ", "translit": "pseudomártyr", "pronunciation": "psyoo-dom-ar'-toor", "derivation": "from (G5571) and a kindred form of (G3144);", "definition": "a spurious witness, i.e. bearer of untrue testimony", "kjv": "false witness."}, "G5576": {"greek": "ψευδομαρτυρέω", "translit": "pseudomartyréō", "pronunciation": "psyoo-dom-ar-too-reh'-o", "derivation": "from (G5575);", "definition": "to be an untrue testifier, i.e. offer falsehood in evidence", "kjv": "be a false witness."}, "G5577": {"greek": "ψευδομαρτυρία", "translit": "pseudomartyría", "pronunciation": "psyoo-dom-ar-too-ree'-ah", "derivation": "from (G5575);", "definition": "untrue testimony", "kjv": "false witness."}, "G5578": {"greek": "ψευδοπροφήτης", "translit": "pseudoprophḗtēs", "pronunciation": "psyoo-dop-rof-ay'-tace", "derivation": "from (G5571) and (G4396);", "definition": "a spurious prophet, i.e. pretended foreteller or religious impostor", "kjv": "false prophet."}, "G5579": {"greek": "ψεῦδος", "translit": "pseûdos", "pronunciation": "psyoo'-dos", "derivation": "from (G5574);", "definition": "a falsehood", "kjv": "lie, lying."}, "G5580": {"greek": "ψευδόχριστος", "translit": "pseudóchristos", "pronunciation": "psyoo-dokh'-ris-tos", "derivation": "from (G5571) and (G5547);", "definition": "a spurious Messiah", "kjv": "false Christ."}, "G5581": {"greek": "ψευδώνυμος", "translit": "pseudṓnymos", "pronunciation": "psyoo-do'-noo-mos", "derivation": "from (G5571) and (G3686);", "definition": "untruly named", "kjv": "falsely so called."}, "G5582": {"greek": "ψεῦσμα", "translit": "pseûsma", "pronunciation": "psyoos'-mah", "derivation": "from (G5574);", "definition": "a fabrication, i.e. falsehood", "kjv": "lie."}, "G5583": {"greek": "ψεύστης", "translit": "pseústēs", "pronunciation": "psyoos-tace'", "derivation": "from (G5574);", "definition": "a falsifier", "kjv": "liar."}, "G5584": {"greek": "ψηλαφάω", "translit": "psēlapháō", "pronunciation": "psay-laf-ah'-o", "derivation": "from the base of (G5567) (compare (G5586));", "definition": "to manipulate, i.e. verify by contact; figuratively, to search for", "kjv": "feel after, handle, touch."}, "G5585": {"greek": "ψηφίζω", "translit": "psēphízō", "pronunciation": "psay-fid'-zo", "derivation": "from (G5586);", "definition": "to use pebbles in enumeration, i.e. (generally) to compute", "kjv": "count."}, "G5586": {"greek": "ψῆφος", "translit": "psēphos", "pronunciation": "psay'-fos", "derivation": "from the same as (G5584);", "definition": "a pebble (as worn smooth by handling), i.e. (by implication, of use as a counter or ballot) a verdict (of acquittal) or ticket (of admission); a vote", "kjv": "stone, voice."}, "G5587": {"greek": "ψιθυρισμός", "translit": "psithyrismós", "pronunciation": "psith-oo-ris-mos'", "derivation": "from a derivative of (a whisper; by implication, a slander; probably akin to (G5574));", "definition": "whispering, i.e. secret detraction", "kjv": "whispering."}, "G5588": {"greek": "ψιθυριστής", "translit": "psithyristḗs", "pronunciation": "psith-oo-ris-tace'", "derivation": "from the same as (G5587);", "definition": "a secret calumniator", "kjv": "whisperer."}, "G5589": {"greek": "ψιχίον", "translit": "psichíon", "pronunciation": "psikh-ee'-on", "derivation": "diminutive from a derivative of the base of (G5567) (meaning a crumb);", "definition": "a little bit or morsel", "kjv": "crumb."}, "G5590": {"greek": "ψυχή", "translit": "psychḗ", "pronunciation": "psoo-khay'", "derivation": "from (G5594);", "definition": "breath, i.e. (by implication) spirit, abstractly or concretely (the animal sentient principle only; thus distinguished on the one hand from (G4151), which is the rational and immortal soul; and on the other from (G2222), which is mere vitality, even of plants: these terms thus exactly correspond respectively to the Hebrew (G5315), (G7307) and (G2416))", "kjv": "heart (+ -ily), life, mind, soul, + us, + you."}, "G5591": {"greek": "ψυχικός", "translit": "psychikós", "pronunciation": "psoo-khee-kos'", "derivation": "from (G5590);", "definition": "sensitive, i.e. animate (in distinction on the one hand from (G4152), which is the higher or renovated nature; and on the other from (G5446), which is the lower or bestial nature)", "kjv": "natural, sensual."}, "G5592": {"greek": "ψύχος", "translit": "psýchos", "pronunciation": "psoo'-khos", "derivation": "from (G5594);", "definition": "coolness", "kjv": "cold."}, "G5593": {"greek": "ψυχρός", "translit": "psychrós", "pronunciation": "psoo-chros'", "derivation": "from (G5592);", "definition": "chilly (literally or figuratively)", "kjv": "cold."}, "G5594": {"greek": "ψύχω", "translit": "psýchō", "pronunciation": "psoo'-kho", "derivation": "a primary verb;", "definition": "to breathe (voluntarily but gently, thus differing on the one hand from (G4154), which denotes properly a forcible respiration; and on the other from the base of (G109), which refers properly to an inanimate breeze), i.e. (by implication, of reduction of temperature by evaporation) to chill (figuratively)", "kjv": "wax cold."}, "G5595": {"greek": "ψωμίζω", "translit": "psōmízō", "pronunciation": "pso-mid'-zo", "derivation": "from the base of (G5596);", "definition": "to supply with bits, i.e. (generally) to nourish", "kjv": "(bestow to) feed."}, "G5596": {"greek": "ψωμίον", "translit": "psōmíon", "pronunciation": "pso-mee'-on", "derivation": "diminutive from a derivative of the base of (G5597);", "definition": "a crumb or morsel (as if rubbed off), i.e. a mouthful", "kjv": "sop."}, "G5597": {"greek": "ψώχω", "translit": "psṓchō", "pronunciation": "pso'-kho", "derivation": "prolongation from the same base as (G5567);", "definition": "to triturate, i.e. (by analogy) to rub out (kernels from husks with the fingers or hand)", "kjv": "rub."}, "G5599": {"greek": "ὦ", "translit": "ō", "pronunciation": "o", "derivation": "a primary interjection;", "definition": "as a sign of the vocative case, O; as a note of exclamation, oh", "kjv": "O."}, "G5601": {"greek": "Ὠβήδ", "translit": "Ōbḗd", "pronunciation": "o-bade'", "derivation": "of Hebrew origin ((G5744));", "definition": "Obed, an Israelite", "kjv": "Obed."}, "G5602": {"greek": "ὧδε", "translit": "hōde", "pronunciation": "ho'-deh", "derivation": "from an adverb form of (G3592);", "definition": "in this same spot, i.e. here or hither", "kjv": "here, hither, (in) this place, there."}, "G5603": {"greek": "ᾠδή", "translit": "ōidḗ", "pronunciation": "o-day'", "derivation": "from (G103);", "definition": "a chant or \"ode\" (the general term for any words sung; while (G5215) denotes especially a religious metrical composition, and (G5568) still more specially, a Hebrew cantillation)", "kjv": "song."}, "G5604": {"greek": "ὠδίν", "translit": "ōdín", "pronunciation": "o-deen'", "derivation": "akin to (G3601);", "definition": "a pang or throe, especially of childbirth", "kjv": "pain, sorrow, travail."}, "G5605": {"greek": "ὠδίνω", "translit": "ōdínō", "pronunciation": "o-dee'-no", "derivation": "from (G5604);", "definition": "to experience the pains of parturition (literally or figuratively)", "kjv": "travail in (birth)."}, "G5606": {"greek": "ὦμος", "translit": "ōmos", "pronunciation": "o'-mos", "derivation": "perhaps from the alternate of (G5342);", "definition": "the shoulder (as that on which burdens are borne)", "kjv": "shoulder."}, "G5608": {"greek": "ὠνέομαι", "translit": "ōnéomai", "pronunciation": "o-neh'-om-ahee", "derivation": "middle voice from an apparently primary (a sum or price);", "definition": "to purchase (synonymous with the earlier (G4092))", "kjv": "buy."}, "G5609": {"greek": "ὠόν", "translit": "ōón", "pronunciation": "o-on'", "derivation": "apparently a primary word;", "definition": "an \"egg\"", "kjv": "egg."}, "G5610": {"greek": "ὥρα", "translit": "hṓra", "pronunciation": "ho'-rah", "derivation": "apparently a primary word;", "definition": "an \"hour\" (literally or figuratively)", "kjv": "day, hour, instant, season, X short, (even-)tide, (high) time."}, "G5611": {"greek": "ὡραῖος", "translit": "hōraîos", "pronunciation": "ho-rah'-yos", "derivation": "from (G5610);", "definition": "belonging to the right hour or season (timely), i.e. (by implication) flourishing (beauteous (figuratively))", "kjv": "beautiful."}, "G5612": {"greek": "ὠρύομαι", "translit": "ōrýomai", "pronunciation": "o-roo'-om-ahee", "derivation": "middle voice of an apparently primary verb;", "definition": "to \"roar\"", "kjv": "roar."}, "G5613": {"greek": "ὡς", "translit": "hōs", "pronunciation": "hoce", "derivation": "probably adverb of comparative from (G3739);", "definition": "which how, i.e. in that manner (very variously used, as follows)", "kjv": "about, after (that), (according) as (it had been, it were), as soon (as), even as (like), for, how (greatly), like (as, unto), since, so (that), that, to wit, unto, when(-soever), while, X with all speed."}, "G5614": {"greek": "ὡσαννά", "translit": "hōsanná", "pronunciation": "ho-san-nah'", "derivation": "of Hebrew origin ((G3467) and (G4994));", "definition": "oh save!; hosanna (i.e. hoshia-na), an exclamation of adoration", "kjv": "hosanna."}, "G5615": {"greek": "ὡσαύτως", "translit": "hōsaútōs", "pronunciation": "ho-sow'-toce", "derivation": "from (G5613) and an adverb from (G846);", "definition": "as thus, i.e. in the same way", "kjv": "even so, likewise, after the same (in like) manner."}, "G5616": {"greek": "ὡσεί", "translit": "hōseí", "pronunciation": "ho-si'", "derivation": "from (G5613) and (G1487);", "definition": "as if", "kjv": "about, as (it had been, it were), like (as)."}, "G5617": {"greek": "Ὡσηέ", "translit": "Hōsēé", "pronunciation": "ho-say-eh'", "derivation": "of Hebrew origin ((G1954));", "definition": "Hosee (i.e. Hoshea), an Israelite", "kjv": "Osee."}, "G5618": {"greek": "ὥσπερ", "translit": "hṓsper", "pronunciation": "hoce'-per", "derivation": "from (G5613) and (G4007);", "definition": "just as, i.e. exactly like", "kjv": "(even, like) as."}, "G5619": {"greek": "ὡσπερεί", "translit": "hōspereí", "pronunciation": "hoce-per-i'", "derivation": "from (G5618) and (G1487);", "definition": "just as if, i.e. as it were", "kjv": "as."}, "G5620": {"greek": "ὥστε", "translit": "hṓste", "pronunciation": "hoce'-teh", "derivation": "from (G5613) and (G5037);", "definition": "so too, i.e. thus therefore (in various relations of consecution, as follow)", "kjv": "(insomuch) as, so that (then), (insomuch) that, therefore, to, wherefore."}, "G5621": {"greek": "ὠτίον", "translit": "ōtíon", "pronunciation": "o-tee'-on", "derivation": "diminutive of (G3775);", "definition": "an earlet, i.e. one of the ears, or perhaps the lobe of the ear", "kjv": "ear."}, "G5622": {"greek": "ὠφέλεια", "translit": "ōphéleia", "pronunciation": "o-fel'-i-ah", "derivation": "from a derivative of the base of (G5624);", "definition": "usefulness, i.e. benefit", "kjv": "advantage, profit."}, "G5623": {"greek": "ὠφελέω", "translit": "ōpheléō", "pronunciation": "o-fel-eh'-o", "derivation": "from the same as (G5622);", "definition": "to be useful, i.e. to benefit", "kjv": "advantage, better, prevail, profit."}, "G5624": {"greek": "ὠφέλιμος", "translit": "ōphélimos", "pronunciation": "o-fel'-ee-mos", "derivation": "from a form of (G3786);", "definition": "helpful or serviceable, i.e. advantageous", "kjv": "profit(-able)."}, "G3376": {"greek": "μήν", "translit": "mḗn", "pronunciation": "mane", "derivation": "a primary word;", "definition": "a month", "kjv": "month."}, "G2057": {"greek": "Ἑρμᾶς", "translit": "Hermâs", "pronunciation": "her-mas'", "derivation": "probably from (G2060);", "definition": "Hermas, the name of a Christian", "kjv": "Hermas."}};
